-- AGRIS Seed Data

INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af41', 'Manure, Soil Organic Matter and Soil Fertility', 'Petkova, Zdravka', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Higher content of soil organic matter can greatly reduce the difficulties of a good crop production system. Content of organic matter in the majority of Bulgarian soils is very low which is evident from the results of soil survey and the data from mass chemical soil tests – nearly 60% of studied soils are with humus content lower than 2.5%. The organic fertilization has direct effect on supplying humic substances in soil. On the basis of some Bulgarian soil types, it is shown the inclusion of organic fertilizers into the fraction of humic acids. A pot experiment and a small field study with Haplic Chernozems show an increase into the fraction of free humic acids and those bound with monovalent cations and mobile R2O3 oxides.', 'https://zenodo.org/record/2579182', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af42', 'Method for Evaluation of Soil Conditions Suitable for Growing Emmer and Einkorn Wheat', 'Krasteva, Veneta; Pankov, Veselin; Mitreva, Zornitsa', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Method is developed for the field rating of main soil characteristics that define the suitability for growing emmer and einkorn wheat. Soil texture of the fallow land, depth of the humus horizon, depth of the soil profile, texture differentiation of the soil profile, soil reaction, humus content and groundwater level have been evaluated. The method is harmonized with the officially accepted in Bulgaria parametric methods of the system of field ratings and the categorization of the agricultural lands. The end result is an evaluation of the soil conditions and a soil rating.', 'https://zenodo.org/record/2581111', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af44', 'Horizon Differences in Micronutrient Contents of Soils of the Coastal Plain Sands in Imo State, South-East Nigeria, Micronutrient Contents of Pedons formed under Coastal Plain Sands', 'Osujieke, Donald; Ndukwu, Bernardine; Ahukaemere, Chioma', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Horizon differences in soils influence ability of crops to obtain nutrients and indeed support other uses. The study aimed at investigating the micronutrient (Cu, Mn, Fe, Zn) contents of horizons of two different pedons which lies on similar parent material (Coastal plain sand) in Imo State. Random survey technique guided by the geologic map of the area was used in siting one profile pits on each of the locations. The profile pits were described; and identification and delineation of horizon boundaries were accomplished using FAO guidelines before actual sample collection for laboratory analyses. Soil data were subjected to coefficient of variation (CV) analysis. The results of the micronutrients indicated range values of 0.02- 0.36 mg kg-1 for Mn, 36.6-108 mg kg-1 for Fe, 0.091-0.256 mg kg-1 for Cu and 0.205-0.774 mg kg-1 for Zn in pedon 1. In pedon 2, the ranges were 0.13-1.09 mg kg-1 for Mn, 19-50.6 mg kg-1for Fe, 0.143-0.613 mg kg-1 for Cu and 0.22- 0.962 mg kg-1 for Zn respectivel', 'https://zenodo.org/record/2585990', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af49', 'Genesis of Soils with Anthropogenic Influences and their Classification', 'Teoharov, Metodi; Kirilov, Ivaylo', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'The genesis of anthropogenic soils is widely studied. Soil changes or the formation of new soil types due to human activities are a basic and major factor about anthropogenic soils. A genetic-diagnostic characteristics of anthropogenic influences and the current processes, which influence the formation of specific by composition, properties and structure soils, has been performed. Generally human activities and the consequent running processes are of a different nature and the reflection of these activities on soil cover is durable and visible. All that provides grounds for anthropogenic soils to be grouped and systemized as a separate soil type with subtypes and to be correlated according to according to FAO diagnostics and classification (2014) and the accredited criteria for soil assessment in the world referential base.', 'https://zenodo.org/record/4886402', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af46', 'Test of the Biological Module of CERES-Maize Model in Lysimeters on Chromic Luvisols', 'Gabrielle, Benoit; Popova, Zornitsa; Kercheva, Milena; Leviel, Bruno', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'This paper reports on CERES-maize model stepwise calibration, modification and validation using independent data from specific experiments carried out in a chromic luvisol (Chelopechene), Sofia field,1997-1999. Laboratory based water conductivity curve WCC (eq.1) and water retention curve WRC (eq.2) are calibrated (step i) and adjusted to data measured in field (step ii) (Fig.1; Table 3). Field observations of water dynamics under maize hybrid Kn 509 relative to optimal nitrogen supply N200 (kg ha-1 ) and variable water stress (irrigated A1 plots/lysimeters №1 and №2) are used to modify the function of Root Water Absorption (eq.3) (step iii). The ability of calibrated biological module of CERES-NC-Maize model to make predictions without any further adjustments of parameters is tested against independent three-year dataset (1997-1999) collected in the same field (Chelopechene) but in lysimeter №1 (step iv). Observed water contents in the 1.30 m root zone PESW and soil layers SW (Figs.3a', 'https://zenodo.org/record/3865420', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af4c', 'Erosion Processes Due to Sprinkler Irrigation', 'Petrova, Rossitza; Bozhkov, Snejan; Kancheva, Viktoriya; Gadjalska, Nelly', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'The study and analyses of erosion have shown that the main factors determiningerosion processes under equal soil and climatic conditions are the intensity and structure ofartificial rain and the ground slope. The main factor, artificial rain intensity, depends mainlyon the soil infiltration rate. In sprinkle irrigation, the soil infiltration is preceded by interactionbetween the soil and the rainfall drops. Failure to observe this interaction has often causedirrigation erosion problems due to the impact drops on the soil. It has been proved that thebigger are rainfall drops and their intensity, the bigger are the damages to soil structure. Themost important factors on which depends the degree of erosion are erosion resistance and slopeof the soil surface. Bulgarian soils are classified in a seven-degree scale, based on Qcritical -erosion-safety discharge.This paper deals with the feasibility to choose irrigation equipment suitable foragricultural crops and having appropriate characteri', 'https://zenodo.org/record/4887457', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af45', 'Natural Radionuclides in Soils from Selected Regions in Bulgaria Affected by Natural and Anthropogenic Processes', 'Staneva, Donka; Yordanova, Ivanka; Lazarova, Radoslava', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'The content of natural radionuclides 40K, 235U, 238U, 232Th and 226Ra in soils from two regions of past uranium mining in Bulgaria were determined and analyzed and results of radiation monitoring summarized. Soil samples from three other regions in the country: North Bulgaria - plane region (around “Kozloduy” Nuclear Power Plant and the Danube River) – 40 samples; semi-mountainous - (Sofia field) – 5 samples and South Bulgaria – mountainous (Rhodope massif) – 25 samples, were analyzed for comparison. Evaluation of possible radiation hazard to the population in the respective regions was made by calculatingthe average radium equivalent activity (Raeq) and the external hazard index (Hex). It was found that content of natural radionuclides in the studied soils, both plain and mountainous, is within normal background levels and is not hazardous to the population.', 'https://zenodo.org/record/2585984', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af4d', 'Influence of the Red Wood Ant Formica lugubris Zetterstedt (Hymenoptera: Formicidae) on the Surrounding Forest Soil Influence of the Red Wood Ant on the Forest Soil', 'Tsikas, Angelos; Orfanoudakis, Michail; Karanikola, Paraskevi', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Red wood ants build their nests as above-ground mounds by collecting organicmaterials from the forest floor. The effects of ant nest to the soil carbon and nitrogen alongwith the soil pH, were measured. There was an increase in pH with distance from the nestswhile there was a decrease in C and N concentration with the distance from the nestincreases. The carbon content at the mound and nests center was differ, with carbonpercentage more than double at the nests mound than in the center of the nest. In contrast thenitrogen percentage was higher at the nest center but with no significant difference. The pHwas increased at the nests center while the soil was more acidic at greater ratio. Red woodants’ mounds do not significantly alter the C and N concentrations in the forest ecosystem,but they increase spatial heterogeneity of the forest floor by storing organic matter andnutrients.', 'https://zenodo.org/record/4886610', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af43', 'Soil Science – Science of Past, Present and Future', 'Teoharov, Metodi', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'The present study includes a detailed analysis on the past, present and future of the soil science in the Bulgaria and over the world. Soil science entered in the cycle of scientific discipline serving practice when in 1883 the famous Russian scientist V.V.Dokuchaev established regularities of soil formation. Since then it has emerged as an important branch of biological science and it has become a science of undoubtedly great for public importance. There are different periods how it was developed in Bulgaria and it the rest of the world. In third period is examined Vernadski"s concept of the Noosphere and relationship with soil science and how „"the thoughtful layer of the planet” can repairs the consequences of the Technosphere and Anthropocentris.', 'https://zenodo.org/record/2585613', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af47', 'Roles of Leucaena leucocephala (Lam.) on Sandy Loam Soil pH, Organic Matter, Bulk Density, Water-Holding Capacity and Carbon Stock Under Humid Lowland Tropical Climatic Conditions', 'Michael, Patrick S.', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Leucaena (Leucaena leucocephala Lam.) trees planted in alley cropping or establishedon fallowed farms by natural means contribute significantly to soil health and productivity byinfluencing various soil properties. In this study, the effects of L. leucocephala (Lam.) onsandy loam soil pH, organic matter content, bulk density, water-holding capacity and carbonstock were investigated under humid lowland tropical climatic conditions in Papua NewGuinea (PNG). Soil samples were collected from 60 cm deep piths dug out from 1 m and 2 maway from the base of the legume trees. The control soil samples were collected fromadjacent grassland dominated by Imperata cylindrica (L.), 10 m away from the legume trees.In all the piths, soil samples were collected from the 0-20, 20-40 and 40-60 cm profiles. Theresults showed presence of the legume trees acidifies the soil (lowers pH), lowers surface soilorganic carbon, improves the water holding capacity within the surface soils and helpsimprove bulk densi', 'https://zenodo.org/record/3250845', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af48', 'The Effects of Chicken Manure Digestates on the Removal of Diesel Range Organics from Petroleum Products Polluted Soils', 'Ukpebor, J. E.; Oghoje, S. U.; Ukpebor, E. E.', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'This study was designed to investigate the efficiency of using locally producedchicken manure digestates (CMD) as nutrient supplement for the removal of diesel rangeorganics (DRO) from petroleum products polluted soils by land farming process. Soilssamples spiked with hydrocarbon mixture (HCM), 5 % and 10 %) were treated with threerates of the CMD (0, 10 or 20 %) for a 336 days period. Soil samples were collected at day 1,14, 28, 56, 84, 168 and 336 time interval and the samples were extracted using standardmethods. The concentrations of DRO at various sampling periods were determined using agas chromatography equipped with a flame ionization detector (GC – FID). The percentageremoval of the DRO and the significance differences of the different treatments wereevaluated using statistical tools.Results obtained showed that the use of 10 and 20 % CMD led to the removal of about50 and 58 % of the DRO respectively from the 5 % HCM polluted soils and about 41 and 35% respectively for the 10 ', 'https://zenodo.org/record/4887779', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af4a', 'Influence of Agro-Technical Treatments on Some Physical and Agrochemical Parameters of Haplic Vertisols', 'Lozanova, Vanya; Dimitrov, Ivan', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'By assessing basic agro-technical factors, optimal decisions can be made for goodagricultural practice on soils with heavy soil texture, such as the Haplic Vertisols. The aim ofthe study is to identify the changes in the physical and agrochemical status of HaplicVertisols that occur under the influence of applied agro-technical measures.For the achievement of the purpose in the period 2016 -2019, field experiments, basedon the block method in the Sofia Region on a Haplic Vertisols were carried out.The study found out that soil moisture was a major limiting factor for cropdevelopment. The soil moisture content is influenced by the type of soil tillage, although thedensity of the weeds is also less affected by the parameter. The bulk density of the HaplicVertisols is inversely correlated with the soil moisture content. In the case of deep looseningof maize, its values are reduced compared to those with plowing. Lower values were foundfor the parameter after plowing as a pre-sowing treatm', 'https://zenodo.org/record/4887333', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af4b', 'Ionic Mobility of Cations as Affected by Redox Status of Two Different Soil Textures', 'Dayo-Olagbende, G.O.; Ewulo, B.S', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Movement of ions within the soil plays a key role in nutrient availability as well assoil management. Various reactions in the soil contribute to soil ionic mobility andconsequently nutrient availability, one of which is the oxidation-reduction reaction. Hence,this study sets out to evaluate the effect of redox status of the soil on ionic mobility of cations.A 3x2x2 factorial experiment was set up on two different soil types (clay loam and sandy clayloam), arranged in a Randomzed complete Block design (RCBD) with three replicates. Thetreatment combination involved three levels of poultry manure (0 tha-1, 6 tha-1 and 8 tha-1),two levels of NPK 15-15-15 (0 gha-1, 200 kgha-1) and two water regimes (field capacity andwaterlogging). Twelve treatments were obtained giving rise to different redox potential.Redox potential was measured using a redox meter, electrical conductivity using aconductivity meter; Ionic mobility was calculated using the mobility equation.Results from this study show t', 'https://zenodo.org/record/4887052', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64747057425ec3c088f1af4e', 'Influence of Forest Vegetation on Organic Matter Composition after Restoration of Mining Spoils in the Town of Pernik', 'Kachova, Vania', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Three tree species are studied: coniferous plantation of black pine / Pinus nigra Arn./and deciduous: birch / Betulla alba L./ and ash / Fraxinus pennsylvanica Marsh/, on theterritory of Baikusheva neighborhood in Pernik, near the mine "M. Tolbuhin ”, afterperformed 45 years ago reclamation. The accumulation of organic matter in the mining spoiland humus composition are analysed. High amounts of org.C are found under all three typesof woody plants (tC% = 3.65 ÷ 9.50 in top layers 0-20cm). This is also due to the presence oflarge amounts of coal carbon particles in the substrate. Humus accumulation is morepronounced under deciduous species and especially under the newly studied species ofFraxinus pennsylvanica Marsh (Humus% = 11.42 ÷ 16.38). But here the process ofhumification takes place to a lesser extent (~ 10 ÷ 16%). On the contrary, under the coniferousplantation of Pinus nigra Arn. is accumulated less org. C (tC% = 1.34 ÷ 3.65), but thehumification processes are going in the highe', 'https://zenodo.org/record/4887198', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e030', 'A ÁGUA EM DEBATE: RELATO DE EXPERIÊNCIA EM ESCOLAS NO MEIO URBANO, RURAL E INDÍGENA, NO CENTRO-OESTE DO BRASIL, MICRORREGIÃO DE TANGARÁ DA SERRA', 'De Queiroz, Tadeu; Ferreira, Jheiny Raiany; De Oliveira, Jessica', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O presente artigo tem como objetivo relatar as experiências vivenciadas durante atividades de extensão do Programa “BB Água Limpa”. Foram realizadas dinâmicas de grupo relacionadas à importância da água, usos e preservação, contaminação microbiológica, doenças e formas alternativas de tratamento. O público-alvo foi constituído de crianças e adolescentes de escolas no meio urbano, rural e indígena nos municípios de Barra do Bugres-MT e Tangará da Serra-MT. Utilizou-se de apresentação visual, roda de conversas, brincadeiras e representação ilustrativa de patógenos causadores de doenças de veiculação hídrica. As atividades atingiram um total de 956 alunos, sendo que os resultados foram satisfatórios, pois possibilitaram que conhecimentos fossem disseminados, de forma a contribuir para a conscientização sobre a importância da qualidade da água para o consumo humano, além de possibilitar a interação entre a comunidade e universidade para buscar alternativas que contribuam para uma melhoria ', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e030', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e032', 'BIOMASSA: CONHECER PARA TRANSFORMAR', 'Silva, Geisa; Santos, Maria do Socorro; Carmo, Jéssica; Batistote, Margareth', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A produção de biocombustíveis a partir de biomassa tem despertado o interesse industrial por ser uma fonte alternativa renovável em relação aos combustíveis fósseis. Em função da grande extensão territorial e a qualidade das terras, o estado de Mato Grosso do Sul responde a uma parcela considerável da produção agrícola nacional. Neste sentido, este estudo visa apresentar as principais biomassas e seus processos de transformação aos alunos da rede pública de ensino de Dourados-MS. Para o desenvolvimento da ação extensionista, foram elaborados palestras e experimentos, os quais foram trabalhados em sala de aula. Para a avaliação, foi aplicado um questionário contendo questões objetivas e subjetivas. A ação extensionista oportunizou um diferencial na formação acadêmica, uma vez que a vivência com a comunidade escolar proporcionou habilidades de tolerância, observação, planejamento e execução de trabalho em grupo, condições que são requisitos fundamentais para o exercício profissional.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e032', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e034', 'CONHECENDO A SAÚDE NUTRICIONAL DE IDOSOS ATENDIDOS EM UMA ORGANIZAÇÃO NÃO GOVERNAMENTAL, BENEVIDES / PA', 'Miranda, Rozineia; Serrão, Fernanda; Carvalho, Elenilce; Amorim, Yane; Dos Santos, Kelly', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este artigo teve como objetivo descrever o perfil socioeconômico, antropométrico, dietético e identificar a prevalência de doenças crônicas em idosos. Foi um estudo transversal, descritivo realizado com idosos atendidos pelo Projeto de Extensão "Nutrição e Saúde na 3ª idade", Faculdade de Nutrição/UFPA em uma Organização Não Governamental. Foram coletadas através de um questionário semiestruturado variáveis socioeconômicas e de estilo de vida, presença ou não de doenças crônicas, varáveis antropométricas e consumo alimentar. 185 idosos foram avaliados, predomínio do sexo feminino na faixa etária de 60 a 69 anos. Detectou-se em sua maioria a presença acentuada de sedentarismo e de um estado nutricional de sobrepeso/obesidade, segundo o índice de massa corpórea; as outras medidas compartimentadas apresentaram eutrofia, prevalência de hipertensão arterial e diabetes mellitus e grande ingestão de carboidratos simples e baixo consumo de alimentos protetores. Assim, todos esses dados direcio', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e034', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e036', 'EL EXTENSIONISMO A PARTIR DE LA GESTIÓN DE LA INNOVACIÓN EN ÁREAS DE ALTA MARGINACIÓN DE MÉXICO', 'Rodriguez-Hernández, Rafael; Fernández-González, Isidro; Camas-Gómez,, Robertotony; Espinosa-Paz, Nestor; Cadena-Iñiguez, Jorge; Martínez-Sánchez, Jesus; Cadena-Iñiguez, Pedro', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Desde 2009-2013 se desarrolló un proyecto en dos etapas donde se intervino en ocho municipios del sureste de México, región considerada como de alta marginación, trabajando en forma coordinada seis instituciones y 23 investigadores con 480 familias. Se implementó un modelo cuyo principal objetivo fue gestionar la innovación a partir del potencial del contexto donde trabajan los productores, el cual consta de tres puntos: Los resultados indican que se puede detonar el desarrollo de esas áreas marginadas, ser competitivo hasta lograr ser altamente productivo y realizar agro negocios con lo producido y la capacitación ofrecida por el sistema de extensionismo. Los impactos ambiental, económico, social, indican un avance entre los grupos organizados, dado que se lograron conformar siete agroindustrias a partir de las fortalezas productivas detectadas en un primer diagnóstico.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e036', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e039', 'BACIA HIDROGRÁFICA DO RIO NEGRO-RS: CONHECER PARA GERENCIAR - DOI: 10.5212/Rev.Conexao.v.12.i3.0010', 'Schafer, Alexandro; Branco, Vivian', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este artigo apresenta o projeto de extensão universitária intitulado “Bacia hidrográfica do Rio Negro: conhecer para gerenciar”, seus principais aspectos e os resultados alcançados até o momento. O projeto tem como objetivo principal promover ações que resultem em conhecimentossobre aspectos físicos, sociais e ambientais da bacia hidrográfica do Rio Negro-RS. A metodologia utilizada para o desenvolvimento desse projeto constitui-se de: a) estudo do problema; b) definição de ações de extensão;c) planejamento das ações; d) realização das ações planejadas e f) avaliação das ações realizadas. Após três anos de execução desse projeto, é possível afirmar que tem contribuído para a conscientização da população que habita a bacia hidrográfica do Rio Negro a respeito de sua importância no contexto local e internacional etambém sobre a preservação dos recursos hídricos localizados no interior da bacia hidrográfica.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e039', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e03b', 'IMPACTOS DA INSERÇÃO DE ATIVIDADES DE EDUCAÇÃO AMBIENTAL EM UMA ESCOLA MUNICIPAL DE LAVRAS, MG', 'Silva, Sabrina; Silva, Gabriela Francine de', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Em vista da crescente ocorrência de problemas ambientais, alunos e professores do Departamento de Administração e Economia da Universidade Federal de Lavras elaboraram um projeto de extensão com o objetivo de levar atividades de educação ambiental nas escolas municipais de Lavras, MG. Este projeto ficou conhecido como Projeto Planeta Azul. O presente estudo objetivou, portanto, analisar os impactos da adição destas atividades realizadas neste Projeto. Para tanto, foi feito um estudo qualitativo e quantitativo. A coleta de dados se deu por meio da aplicação de questionário com os alunos participantes do projeto. Perceberam-se mudanças de comportamentos e atitudes de todos os envolvidos no Projeto e, com isso, viabiliza-se o desenvolvimento da consciência crítica e a obtenção de valores e ações que visam um ambiente mais equilibrado, bem como a formação cidadã.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e03b', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e03f', 'INCUBADORA TECNOSSOCIAL DE COOPERATIVAS EEMPREENDIMENTOS ECONÔMICOS SOLIDÁRIOS COMO ARTICULADORA DA EDUCAÇÃO AMBIENTAL EM CERRO LARGO POR MEIO DA EXTENSÃO UNIVERSITÁRIA', 'Scherer, Luciana; Botelho, Louise; Franqui, Luis', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'As Incubadoras Tecnológicas de Cooperativas Populares (ITCPs) têm o objetivo de promover desenvolvimento sustentável através de atividades de extensãopara empreendimentos de economia solidária. A Incubadora Tecnossocial de Cooperativas e Empreendimentos Econômicos Solidários (ITCEES) é um laboratório multidisciplinar da UFFSque atua por intermédio da incubação de empreendimentos e uma das áreas de atuação é a Educação Ambiental. Em 2016, a ITCEES criou o Fórum de Gestão Social, que busca, através da discussão coletiva de vários atores sociais, a resolução para um problema que assola o município de Cerro Largo (RS): a questão dos resíduos sólidos urbanos (RSU). Este artigo tem como metodologia a abordagem qualitativa de pesquisa. Como resultados, destacam-se a implantação de projeto de educação ambiental em escolas municipais, a elaboração de folder sobre a coleta seletiva, a retomada do projeto de reciclagem de gordura saturada, a fundação de cooperativa de catadores, a aquisição de eq', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e03f', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e040', 'IMPLEMENTAÇÃO DE AÇÕES GESTIONÁRIAS EM UMA ASSOCIAÇÃO DE CATADORES DE MATERIAIS RECICLÁVEIS', 'Maria, Robert; Silva, Anelisa; Andrade, Yã; Marcelino, Daniele; Chagas, Tays; Barbosa, Lucas', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O artigo apresenta as ações e os resultados de um projeto de extensão intitulado “Implementação de Ações Gestionárias em uma Associação de Catadores de Materiais Recicláveis”. Promoveram-se capacitações e intervenções físicas na associação, as quais contribuíram para o seu desenvolvimento e perpetuação. A associação, que é a única fonte de renda dos catadores, foi fundada em 2006 pela Prefeitura de Ouro Preto-MG para retirá-los das condições precárias de trabalho no lixão do município. A metodologia utilizada foi de caráter qualitativo, com observação direta, entrevistas semiestruturadas e princípios da andragogia, a qual proporcionou maior interação entre pesquisadores e catadores, facilitando a troca de saberes e a apropriação das técnicas utilizadas. Como resultado, têm-se melhorias na divulgação, na periodicidade e nas rotas da coleta seletiva; na organização do trabalho, nos aspectos ergonômicos, no aumento do volume coletado e na geração de renda.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e040', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e041', 'EXTENSÃO UNIVERSITÁRIA: UMA ANÁLISE DA CONSTRUÇÃO DE UM PROJETO DE EXTENSÃO COM AS MULHERES RURAIS DO BAIRRO PEROBA DE ITAJUBÁ - MG', 'Oliveira, Pâmela; Andrade, Vitor; Pereira, Samanta; Pereira, Miguel; Pereira, Viviane; Battiston, Kalahan; Lima, Ednilson; Santos, Gabriela; Brito, Tayrine', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A extensão universitária é o instrumento mantenedor do diálogo da Universidade com a sociedade. A Política Nacional de Extensão Universitária (PNEU) fornece direcionamentos, nos quais os projetos de extensão devem se fundamentar e guiar suas ações. Partindo desse princípio, o objetivo deste trabalho é analisar os caminhos percorridos pelo Núcleo Travessia na execução do projeto de extensão “Economia Solidária na Peroba – Itajubá-MG: geração de renda e emancipação social das mulheres rurais”. Para a análise, foram realizadas comparações entre os procedimentos adotados pelo Núcleo Travessia e as diretrizes descritas na PNEU. Os resultados apontaram para a importância da Interação Dialógica desde a aproximação com a comunidade e sua relevância no estabelecimento da relação de respeito e confiança. A melhoria na autoestima e a conquista dos primeiros rendimentos mostraram o potencial de Transformação Social em projetos dessa dimensão, fazendo com que a Universidade cumpra com a sua missão ', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e041', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e04a', 'PESQUISA-AÇÃO PARA O RECONHECIMENTO DA REGIÃO “SERRAS DA IBITIPOCA” COMO PRODUTORA DE QUEIJO MINAS ARTESANAL', 'Assis, Thiago; Pereira, Maria Dalva', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A valorização de produtos tradicionais pode representar uma estratégia de desenvolvimento rural sustentável. O objetivo deste trabalho, desenvolvido no mestrado profissional em Desenvolvimento Sustentável e Extensão da Universidade Federal de Lavras (UFLA), foi contribuir com o reconhecimento da região “Serras da Ibitipoca” como produtora do Queijo Minas Artesanal (QMA). Realizou-se pesquisa ação que buscou identificar elementos na região que justificassem o seu reconhecimento, e sistematizar e analisar o processo de articulação e organização empreendido. Foram realizados estudos bibliográficos, 3 entrevistas e 50 questionários, em 12 municípios. Realizaram-se, ainda, reuniões, observação e análise documental. Verificou-se que a região possui histórico de produção de queijos que remonta ao século XVIII, meio físico favorável à produção e um grupo de interesse. Esses elementos justificam o reconhecimento da região “Serras da Ibitipoca” como produtora de QMA. Sistematizar esse processo p', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e04a', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e04d', 'PROJETO DE EXTENSÃO “ORQUESTRANDO A RECICLAGEM”', 'Zanutto, Adriane; Duarte, Elis; Ishida, Sabrina', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo apresentar o projeto de extensão “Orquestrando a Reciclagem”, desenvolvido pelo Grupo PET de Engenharia Química da Universidade Tecnológica Federal do Paraná, Campus Ponta Grossa, em parceria com o Instituto Reviver. Esta ação foi promovida para contribuir com a conscientização sobre reciclagem, sendo dividida em apresentação de conteúdo teórico, mesa redonda, jogo e oficina sobre instrumentos musicais a partir de material reciclado. Pode-se observar que a maioria das crianças não tinham conhecimento dos conceitos abordados e não faziam a reciclagem. Concluise que a utilização de brincadeiras e oficinas práticas auxiliou no processo de aprendizagem, além de enfatizar a importância de ações extensionistas que proponham soluções viáveis para problemas que afetam a comunidade externa à universidade.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e04d', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35311e', 'RESULTADOS OBTENIDOS CON LA IMPLEMENTACIÓN DEL PROGRAMA DE EXTENSIÓN UNIVERSITARIA DISEÑADO EN LA UNIVERSIDAD LA LAS TUNAS', 'Ríos, Dagneris Batista de los', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'RESUMENEn el constante perfeccionamiento de la Educación Superior cubana, el desarrollo de la extensión universitaria ha determinado un redimensionamiento de su contenido, concretándose su esencia en la promoción de la cultura en su expresión más amplia, que se desarrolla en la comunidad universitaria y en su interacción con la sociedad. La Universalización de la Educación Superior manifiesta la concreción del ideal extensionista en la Nueva Universidad donde la integración es esencial y la vía más propicia para revelar las necesidades socioculturales más sentidas del entorno y contribuir a transformarlas. El Programa Nacional de Extensión Universitaria se desarrolla a partir de estas transformaciones conceptuales para dar respuesta a las nuevas exigencias de la sociedad, el Centro Universitario de Las Tunas comienza a instrumentarlo en el curso escolar 2004-2005. En función de este programa, la Dirección de Extensión Universitaria diseño e implementó su propio programa, teniendo en cu', 'https://revistas.uepg.br/index.php/conexao/article/view/3671', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
