INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35313e', 'APRESENTAÇÃO DIDÁTICA DO PROJETO “EDUCAÇÃO PARA O CONSUMO RESPONSÁVEL”', 'Saleh, Pascoalina Bailon de Oliveira; Saleh, Abdala Mohamed', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/3735', NULL, 'English', 'published', false, false, 'open', 'pdf')
