INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35313f', 'EDUCAÇÃO PARA A SENSIBILIZAÇÃO AMBIENTAL: UMA CONSTRUÇÃO DE TODA A SOCIEDADE', 'Vieira, Daniele Mariz; Rodrigues, Vanessa Maria Silva; Souza, Anna Carla Feitosa Ferreira de; Teixeira, Simone Ferreira; Lins, Mariana Lopes Accioly; Costa, Cristiane Maria Queiroz da; Leão, Victor do', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O PROSA – Projeto de Sensibilização Ambiental, da Universidade de Pernambuco, foi formado com o objetivo de aliar a educação ambiental com o papel da extensão universitária, junto à comunidade na qual está inserida, com o intuito de contribuir para a sensibilização e uma nova consciência ecológica. Este artigo visa relatar as experiências e ações do PROSA, que possuem um caráter interdisciplinar e interinstitucional, promovendo discussões sobre a degradação planetária e formas de contribuir para a minimização dos impactos negativos. As ações são compostas por palestras e exposições fotográficas; atividades lúdicas e/ou artísticas e oficinas com materiais recicláveis; participação em eventos culturais, temáticos e científicos; movimentos em alusão ao Dia Mundial de Limpeza dos Rios e Praias. Os resultados alcançados até o presente momento vêm contribuindo para a formação de discentes comprometidos com sua missão social e ambiental, além de despertar na comunidade um olhar crítico acerca', 'https://revistas.uepg.br/index.php/conexao/article/view/3737', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353145', 'APLICAÇÃO DA METODOLOGIA MEXPAR PARA IMPLANTAÇÃO DA COOPERATIVA DOS APICULTORES E MELIPONICULTORES CAMINHOS DO TIBAGI', 'Staron, Enelise Aparecida; Bannach, Franklin; Almeida, Mareci Mendes de; Tomachewski, Fabiane; Quast, Leda Battestin', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A Universidade Estadual de Ponta Grossa atua em um projeto de extensão vinculado ao Programa Universidade sem Fronteiras cujo objetivo é auxiliar na implantação da Cooperativa de Apicultores “Caminhos do Tibagi”. A metodologia Mexpar foi aplicada com sucesso para a realização deste projeto. Foram realizadas ações referentes a parte administrativa e tecnológica possibilitando dessa forma a obtenção do serviço de inspeção municipal (SIM) que permite o beneficiamento e comercialização do mel no município de Telêmaco Borba. A Cooperativa foi inaugurada em fevereiro de 2010 e já conta com a comercialização do produto por meio de processo de doação simultânea junto a CONAB.', 'https://revistas.uepg.br/index.php/conexao/article/view/3749', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35314e', 'INGLÊS NA TERCEIRA IDADE: UM SONHO TORNANDO-SE  REALIDADE', 'Machado, Hayat Boulos; Chaves, Maria Inês; Oliveira, Rita de Cássia da Silva', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Acreditando na capacidade de aprender, do idoso, o projeto extensionista “Universidade Aberta para a Terceira Idade”, da Universidade Estadual de Ponta Grossa, inseriu, em 2005, a disciplina de Língua Inglesa, como parte das atividades ofertadas ao grupo da terceira idade, da cidade de Ponta Grossa, Paraná. O objetivo deste artigo é demonstrar que a iniciativa atingiu resultados positivos. Em 2005, a primeira turma iniciou com 15 alunos. Em 2009, houve 40 alunos inscritos, que foram divididos em três turmas, de nível lingüístico diferenciado. A metodologia adotada nas aulas segue os preceitos da abordagem comunicativa; sendo que os conteúdos lingüísticos são adequados a tópicos de interesse dos alunos. A avaliação da aprendizagem é realizada formal e informalmente, sendo que indicam que é grande a capacidade do idoso, para em aprender uma língua estrangeira, uma vez respeitado o ritmo individual de cada um. O resultado positivo, obtido durante os quase cinco anos de atividade, permite ', 'https://revistas.uepg.br/index.php/conexao/article/view/3774', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35314f', 'NÚCLEO DE ESTUDOS E DEFESA DOS DIREITOS DA INFÂNCIA E JUVENTUDE – NEDIJ ÁREA TEMÁTICA: DIREITOS HUMANOS E JUSTIÇA', 'Siqueira, Samanta Rodrigues; Van Kan, Fernanda; Levandowski, Scheila Aparecida; Brandão, Rosângela Fátima Penteado; Silva, Janaína Adamshuk; Miranda, João Irineu de Resende; Quadros, Débora; Bueno, Ri', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O Núcleo de Estudos e Defesa de Direitos da Infância e da Juventude é um Projeto de extensão das Universidades Estaduais do Paraná. Instituído por convênio entre o Ministério Público e o Governo do Estado do Paraná, por intermédio das Secretarias de Estado da Ciência, Tecnologia e Ensino Superior, da Justiça e do Trabalho e Ação Social, o Instituto de Ação Social do Paraná e o Conselho Estadual dos Direitos da Criança e do Adolescente do Estado do Paraná, Integra o programa Universidade Sem Fronteiras, Subprograma Incubadora dos Direitos Sociais. Seu principal objetivo é proteger os interesses das crianças e dos adolescentes, através da inserção em família substituta, pela guarda, pela tutela ou pela adoção, ou proporcionando defesa técnica para adolescentes infratores, sem condições financeiras para constituir advogado. Ademais, possui uma função consultiva acerca dos direitos e dos deveres das crianças / adolescentes ou dos genitores, além do acesso ao Poder Judiciário e das possívei', 'https://revistas.uepg.br/index.php/conexao/article/view/3777', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353154', 'INCLUSÃO DIGITAL COM A LIBERDADE DO SOFTWARE LIVRE', 'Brumatti, Dayane Valentina; Goulart, Carlos de Castro; Cotta, Júlio Cpesar Bueno', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta o trabalho que vem sendo desenvolvido, no Laboratório de Inclusão Digital (LID), da Universidade Federal de Viçosa, desde setembro de 2004. O principal objetivo do projeto é oferecer cursos introdutórios, de informática, para pessoas de baixa renda. Todos os cursos são baseados em programas de software livre, caracterizado por sua licença de uso, que dá liberdade total ao usuário, sendo possível copiar e redistribuir os programas, sem nenhuma restrição. Desta forma, procura-se difundir, entre os alunos dos cursos, o espírito colaborativo e de ajuda mútua que está por detrás da filosofia do software livre. Nos cursos, é dada uma visão geral do ambiente gráfico do sistema operacional Linux e dos principais aplicativos (editor de textos, planilha eletrônica, etc.), para que o aluno esteja apto a usar o computador, para solucionar alguns de seus problemas do dia a dia. Ao final de cada curso, é aplicado um questionário de avaliação. Os resultados do projeto têm sido b', 'https://revistas.uepg.br/index.php/conexao/article/view/3785', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353158', 'AS AÇÕES DO NÚCLEO DE MONITORAMENTO DE PENAS ALTERNATIVAS NO MUNICÍPIO DE LONDRINA', 'Vergara, Alcides J. S.; Frieling, Allisson D. M.; Pacca, Deisy C. S.; Freitas, Renata M.; Furlanetto, Camila F.; da Silva, Elisângela; Sacramento, Cibéle H.; Nadalim, Elizabeth; Jesus, Valdeir R.; Mor', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente artigo tem, por objetivo, apresentar o Núcleo de Monitoramento de Penas Alternativas de Londrina, cuja proposta é oferecer um trabalho multidisciplinar de atenção e de acompanhamento do processo de cumprimento da pena, aos usuários de drogas, sancionados nos termos do artigo 28, da Lei 11.343/06. Tendo isso em vista, o texto traz algumas considerações sobre as penas alternativas, a nova Lei de Drogas e analisa temáticas diretamente associadas ao campo específico de ação da Equipe do Projeto. Fazemos ainda uma apresentação do Núcleo e do trabalho desenvolvido, apresentando a importância e a validade de iniciativas congêneres, para a concretizar o potencial reinseridor das penas alternativas, para dar continuidade aos avanços empreendidos pela lei e ainda, para atender, de modo eficaz, aos usuários de drogas, sancionados.', 'https://revistas.uepg.br/index.php/conexao/article/view/3794', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35315d', 'QUALIDADE DO MEL NO MUNICÍPIO DE PRUDENTÓPOLIS', 'Macohon, Edson Roberto; Klosowski, Ana Léa Macohon; Opuchkevich, Maria Helena', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O mel é um produto natural, elaborado pelas abelhas, a partir do néctar das flores. É um alimento nutritivo e energético, sendo muito apreciado por suas propriedades terapêuticas. É composto de açúcares e de água, em maior porcentagem; em outras pequenas quantidades, encontra-se vitaminas e sais minerais. Para o mel manter as características e as propriedades, são necessários cuidados na hora de manejar e manipular, para o mel não sofrer transformações químicas que prejudiquem sua qualidade final. Para verificar a pureza e a alteração na qualidade do mel, realizaram-se análises físico-químicas para controlar a qualidade final e conhecer melhor o produto.', 'https://revistas.uepg.br/index.php/conexao/article/view/3803', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353168', 'A ALEGRIA DO OBRIGATÓRIO', 'Machado, Cristina Donasolo; Marques, Luana Maira Bittencourt; Tozetto, Henriqueta Kubiak', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho, fruto de atividades realizadas no projeto extensionista “Construindo Saberes na Diversidade”, aprovado pela Resolução nº 103, de 30 de agosto de 2005, em atuação semanal direta em Escola Municipal, tem por objetivo apontar os desafios enfrentados pelo professor de Educação Musical no mundo globalizado e a preocupação diante da obrigatoriedade do ensino de Música no currículo da Educação Básica. A metodologia utilizada envolveu a participação de acadêmicas do 3º ano do curso de Licenciatura em Música – UEPG e das professoras das turmas onde se aplica o projeto. As metodologias utilizadas no ensino da Música são específicas, tais como o Método Martenot, Método Dalcroze e Método Kodaly, que propiciam uma aprendizagem rítmico-sonora eficaz. Apontamos para o posicionamento ainda tecnicista de professores do Ensino Fundamental com relação ao ensino da Música, diante da insuficiência desses conhecimentos na sua formação, o que o torna não habilitado para o ensino na área musica', 'https://revistas.uepg.br/index.php/conexao/article/view/3823', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353169', 'ACESSIBILIDADE NA UNIVERSIDADE: REPENSANDO OS PROCESSOS INCLUSIVOS', 'Valdivia, Freddy Alberto; Lichacovski, Jussara Carmencita Gomes; Krüger, José Adelino; Machado, Érico Ribas; Machado, Rosana Ribas; Silva, Márcia Barbosa da; Uczak, Rodrigo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta as características, ações e discussões do projeto de extensão “Acessibilidade na Universidade”, que tem por finalidade propiciar o aprendizado de como se pode trabalhar a questão dos processos inclusivos na universidade, tendo como perspectiva a identidade/diferença dos sujeitos e a necessidade de adaptação dos espaços físicos. O projeto utiliza estratégias de vivências, informações, grupo de estudos sobre os processos de inclusão e desenvolve projetos na área de Engenharia Civil para reestruturar os espaços físicos da Universidade Estadual de Ponta Grossa. Desde 2006 o projeto já atingiu um público de aproximadamente três mil pessoas, entre funcionários, acadêmicos e professores. Desta forma, os participantes têm promovido discussões, visando aprofundar conhecimentos sobre o desenvolvimento dos múltiplos sujeitos nas práticas sociais inclusivas e proporcionar o acesso e a permanência dos mesmos nos espaços universitários.', 'https://revistas.uepg.br/index.php/conexao/article/view/3826', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35316d', 'EMAGRECENDO COM SAÚDE: UMA PROPOSTA DE MUDANÇA DE COMPORTAMENTO EM INDIVÍDUOS OBESOS', 'Rech, Cassiano Ricardo; Kalinowski, Flavio Guimarães; Junior, André Geraldo Brauer; Araújo, Eliane Denise da Silveira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente projeto tem como objetivo proporcionar orientações sobre atividade física e mudanças comportamentais que possam refletir sobre uma melhora na qualidade de vida de indivíduos obesos da cidade de Ponta Grossa, Paraná. O projeto “Emagrecendo com Saúde”, é uma parceria entre a UEPG e a Associação Obesos Alerta. As atividades realizadas consistem de caminhada orientada realizada três vezes por semana com duração de 60 minutos e de atividades aquáticas (natação e hidroginástica) realizadas duas vezes por semana. Fazem parte do projeto 15 acadêmicos que iniciaram as atividades em agosto de 2006. Nesse mesmo ano atendemos 50 indivíduos obesos, com idades entre 20 e 50 anos, sendo 45 mulheres e cinco homens. Após quatro meses de atividades, os indivíduos apresentaram uma redução em média de 10% do peso corporal e de 8% no índice de massa corporal (IMC). Houve também um aumento na capacidade cardiorespiratória (14%), bem como melhoras nos aspectos psicossociais (auto-estima, aumento d', 'https://revistas.uepg.br/index.php/conexao/article/view/3830', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353175', 'UTILIZAÇÃO DE PLANTAS MEDICINAIS E AROMATERAPIA COMO FERRAMENTA NO ENSINO FUNDAMENTAL DAS CIÊNCIAS', 'Costa, Raylan Golinski; Farago, Paulo Vitor; Machado, William Moreira; Moreira, Eline Eilen Magno; Serenato, Tânia; Silva, Rozi Zanoni da; Volpato, Ana Márcia; Navarro, Dionezine de Fátima; Marcondes,', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente projeto é resultado de uma parceria entre a Universidade Estadual de Ponta Grossa e a Escola Estadual Medalha Milagrosa – Ponta Grossa – PR, o qual utilizou Plantas Medicinais e Aromaterapia como ferramenta no ensino Fundamental das Ciências. A metodologia empregada baseou-se no cultivo, coleta e dessecação de plantas medicinais dentro de parâmetros preconizados. Foram envolvidos acadêmicos do curso de Farmácia e educandos da 6ª série da referida escola. Como estratégia de ensino, proporcionou- se a estes alunos, estudos morfo-anatômicos e conceitos de Botânica com espécies medicinais. Também foram realizadas visitas ao horto medicinal e aos laboratórios da UEPG onde os envolvidos acompanharam a extração e caracterização de óleos essenciais, obtidos de espécies vegetais. Como resultados, observou-se significativo envolvimento no processo ensino-aprendizagem, com vivências experimentais na área de Fitoterapia, proporcionando aos acadêmicos a valorização dos seus conhecimentos', 'https://revistas.uepg.br/index.php/conexao/article/view/3840', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353178', 'ACOMPANHAMENTO FARMACÊUTICO DE PACIENTES INSUFICIENTES RENAIS QUE REALIZAM HEMODIÁLISE NA NEFROMED', 'Ribas, João Luiz Coelho; Holk, Ingrid Helen; Miyoshi, Edmar; Filho, Nelson José Rodrigues; Madalozzo, Josiane Cristine Bachmann', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A doença renal crônica é uma condição clínica, resultante de múltiplos processos patológicos que levam a alterações das funções renais. Os portadores necessitam de tratamento medicamentoso regular, o que justifica a inclusão do profissional Farmacêutico na equipe de assistência à saúde. O projeto tem por objetivos, promover a inserção de acadêmicos de Farmácia no seguimento de pacientes insuficientes renais em processo dialítico, visando detectar e solucionar problemas relacionados aos medicamentos, além de promover o intercâmbio técnico-científico com os profissionais da NEFROMED. Para tanto, os acadêmicos, devidamente capacitados, realizam o acompanhamento dos pacientes cadastrados, utilizando o Programa Dáder de Atenção Farmacêutica. O desenvolvimento da proposta permite aos envolvidos, a aplicação dos conhecimentos exigidos para a prática da Atenção Farmacêutica, através de sua intervenção junto aos pacientes hemodialisados, contribuindo, desta forma, na formação de um profissional', 'https://revistas.uepg.br/index.php/conexao/article/view/3849', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35317a', 'DE 1993 A 2006: A TRAJETÓRIA DE UM PROJETO DE EXTENSÃO', 'Perez, Marlene; Ribas, João Luiz Domingues; Bachmann, Gina Maria; Camargo, Joseli Almeida; Meza, Elisangela dos Santos; Borsato, José Carlos; Van Kan, Marli Terezinha; Campiteli, Heliana Cioccia; Trob', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Cada vez mais a comunidade matemática tem discutido a ação pedagógica do professor atuante nessa área do conhecimento. Como resultado desta reflexão, surgem várias formas de pensar a prática pedagógica do professor que, além do domínio do conhecimento dos conteúdos específicos da Matemática, tem a necessidade de compreender a relevância de ensinar Matemática significativamente, levando a um olhar mais atento em relação à formação do educador matemático. A necessidade de discussão em torno destas e de outras questões deram origem ao NIEM - Núcleo Integrado de Educação Matemática, projeto de extensão interdepartamental, proposto pela primeira vez em 1993. A proposta é nortear a integração permanente entre professores do curso de Licenciatura em Matemática por meio do assessoramento à comunidade atuante na escola básica. Estando na 9ª edição, este projeto tem proporcionado estudos, discussões e reflexões para o grupo de professores por ele responsável, bem como à comunidade envolvida.', 'https://revistas.uepg.br/index.php/conexao/article/view/3851', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35317d', 'PROGRAMA ALFASOL – O DIÁLOGO ENTRE A UNIVERSIDADE E A ALFABETIZAÇÃO DE ADULTOS', 'Saveli, Esméria de Lourdes', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente texto tem por objetivo relatar uma experiência extensionista vivenciada por acadêmicos (as) do 3º e do 4º ano do Curso de Pedagogia, que se inscreveram no Projeto de Alfabetização Solidária, para desenvolverem as ações de formação inicial e acompanhamento dos alfabetizadores de adultos em quatro municípios do Estado da Bahia. A referida ação extensionista foi executada em duas etapas distintas: formação dos formadores em que se desenvolviam atividades teórico-práticas com os/as acadêmicos (as) sobre o tema alfabetização de adultos, ocorrendo no espaço da universidade, e a outra etapa, denominada ecologia de saberes em que se promoveram diálogos entre o saber científico que a universidade produz e os outros saberes, provenientes de diferentes culturas e experiências vindas dos alfabetizadores e acadêmicos (as).', 'https://revistas.uepg.br/index.php/conexao/article/view/3860', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35317e', 'PROJETO RONDON E SUA FUNÇÃO POLÍTICO SOCIAL', 'Saveli, Esméria de Lourdes; Paula, Ercilia Maria Angeli Teixeira de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta as características e as contribuições do Projeto Rondon Operação Amazônia- 2006. Este Projeto é organizado pelo Ministério da Defesa, em parceria com o Ministério da Educação. A Universidade Estadual de Ponta Grossa, através do Programa de Extensão Universitária, participou deste trabalho com o intuito de cumprir sua função político social. O Projeto Rondon possibilitou às professoras e aos acadêmicos o conhecimento da realidade do Norte do país, e oportunizou aos integrantes da equipe assumir atitudes de compromisso e de responsabilidade com os problemas sociais do Brasil. A metodologia da pesquisa etnográfica possibilitou a escuta das vozes dos diferentes atores sociais da cidade de Caracaraí – Roraima, e a construção de ações coletivas com a população, nas quais foram traçadas Políticas Públicas para a cidade. O Projeto Rondon caracterizou-se como efetivo exercício de cidadania para todos os seus participantes.', 'https://revistas.uepg.br/index.php/conexao/article/view/3861', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353187', 'PRESERVAÇÃO E REVITALIZAÇÃO DO SISTEMA FAXINAL NA REGIÃO DA MATA DE ARAUCÁRIA DO PARANÁ: UM PROJETO EXTENSIONISTA', 'Sahr, Cicilian Luiza Löwen', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O “Sistema Faxinal” é encontrado, desde o começo do século XVIII, no âmbito da Floresta de Araucária, na região Centro- Sul do Paraná. Trata-se de pequenos povoados rurais com atividade silvo-pastoril em áreas comuns, além de uma policultura de subsistência. As áreas de criar e de plantar são separadas através de valos e cercas. O Sistema foi implantado inicialmente no contexto cultural dos caboclos, tendo sido também absorvido por imigrantes. Esta forma de uso do solo, pela sua adaptação ecológica e interação social, parece cumprir critérios de sustentabilidade. Em 1994, existiam 121 Faxinais remanescentes. Um levantamento recente demonstra que ainda subsistem 44. Os Faxinais vêm sofrendo pressão pela modernização do campo. Recentemente, observa-se um reavivar da agricultura familiar, na qual este Sistema pode vir novamente a encontrar espaço político. Em contato com a população faxinalense e com instituições governamentais e não-governamentais neles atuantes, delineiam-se diretrizes ', 'https://revistas.uepg.br/index.php/conexao/article/view/3888', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353188', 'PROGRAMA ALFABETIZAÇÃO SOLIDÁRIA E AS DOENÇAS PARASITÁRIAS', 'Kovaliczn, Rosilda Aparecida', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Trata-se de uma vivência sobre a importância da prevenção das doenças parasitárias junto à comunidade em geral, num esforço conjunto entre professores alfabetizadores, provenientes da região Nordeste e participantes do programa Alfabetização Solidária, do Ministério da Educação, em parceria com a Universidade Estadual de Ponta Grossa – PR. No decorrer do tema “Biologia” durante as aulas de capacitação, o alfabetizador foi incentivado a disseminar conhecimentos sobre doenças parasitárias da sua realidade, principalmente junto às populações mais isoladas.', 'https://revistas.uepg.br/index.php/conexao/article/view/3890', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531a9', 'O PAPEL SOCIAL DA VOZ PARA COMUNICADORES: UMA EXPERIÊNCIA EXTENSIONISTA EM RÁDIO E TV', 'Silva Lins Cajazeira, Paulo Eduardo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A Universidade Federal do Ceará (UFC) desenvolveu o Projeto de Extensão “Locução e técnica vocal para comunicadores”, por meio do Curso de Jornalismo do Campus Cariri, em Juazeiro do Norte, Sul do Ceará. Esta foi uma proposta de trabalho envolvendo profissionais e estudantes da área de Comunicação Social, na Habilitação em Jornalismo. O trabalho objetivou o desenvolvimento de ações educativas voltadas às necessidades básicas de informação, educação e saúde vocal para jovens comunicadores. Para tanto, um professor coordenador do projeto e um bolsista de extensão do Curso de Jornalismo ficaram responsáveis por planejar e executar as atividades durante a vigência do projeto. A equipe desenvolveu e elaborou a programação, a seleção, a divulgação de datas e horários dos diversos encontros semanais, além de convidar a equipe de profissionais para atuarem, de forma voluntária, como palestrantes e instrutores da ação extensionista. Isto proporcionou aos realizadores a oportunidade da reflexão ', 'https://revistas.uepg.br/index.php/conexao/article/view/4781', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ad', 'RÁDIO UNIVERSITÁRIA “CONEXÃO UFRA”: A IMPORTÂNCIA DA COMUNICAÇÃO NO MEIO RURAL', 'Martins, Caick Rosa; Cardoso, Cíntia Maria; Pires, Najla Castro; Sousa, Lais Victória Ferreira de; Almeida, Ruth Helena Cristo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo tem como propósito apresentar a experiência do projeto de extensão universitária denominado “Rádio Universitária-Conexão UFRA”. Ressalta-se no mesmo a importância da rádio como ferramenta comunicacional e fundamental para compreensão dos processos comunicativos nos quais a sociedade se insere e como podem ser transformados em massa crítica. O projeto desenvolveu-se por meio da aplicação de questionário, pesquisas bibliográficas e documentais, de conversas informais e formais com atores sociais do meio rural. Os resultados auxiliaram na elaboração dos programas radiofônicos apresentados à comunidade. Com o apoio do Projeto Carroceiro da UFRA, elaborou-se os quadros da primeira edição: Radionovela, Conversa com o pesquisador e Extensão Universitária. Foi possível constatar que a rádio é um meio de comunicação de massa e que tem um alcance surpreendente.', 'https://revistas.uepg.br/index.php/conexao/article/view/4994', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b2', 'APRIMORAMENTO DA ESCRITA NA TERCEIRA IDADE: AÇÕES DO PROJETO MINHA MEMÓRIA, MINHA HISTÓRIA', 'Schardong, Rosangela', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Minha Memória, Minha História é uma projeto de extensão da Universidade Estadual de Ponta Grossa (UEPG) que atende um grupo da Melhor Idade do município. O projeto tem como principais objetivos valorizar a terceira idade, resgatar a memória, aprimorar as habilidades de leitura e escrita a partir da exploração de textos literários. Este artigo pretende descrever brevemente as expectativas do grupo de idosos a respeito do desenvolvimento da escrita; seus temores; as atividades propostas, a partir da heterogênea escolaridade dos participantes; as dificuldades encontradas e os caminhos trilhados para superá-las. Neste artigo espera-se reunir e analisar dados acerca da produção escrita no período de março a outubro de 2011. A observação dos dados será a partir de ensaios de Antonio Candido e Luis Percival Leme Britto, obras de Paulo Freire e Ecléa Bosi.', 'https://revistas.uepg.br/index.php/conexao/article/view/5046', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b3', 'RELATO DE EXPERIÊNCIA - GRUPO DE ESTUDOS EM DIREITOS HUMANOS DA UFG', 'Santos, Kamilly Cordeiro dos; Vieira, Marisa Damas; Leal, Germana da Silva; Camilo, Christiane de Holanda; Martins, Raquel Maria Gonçalves; Santana, Danielly Aparecida de Souza Carvalho; Nascimento de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O artigo relata as experiências do Grupo de Estudos em Direitos Humanos, um dos projetos de extensão do Núcleo de Estudos e Pesquisas em Direitos Humanos da Universidade Federal de Goiás (NDH-UFG). Iniciado em setembro de 2011, o Grupo tem como principais características o caráter interdisciplinar e o livre acesso à participação de qualquer interessado nas discussões sobre as várias temáticas dos Direitos Humanos e os seus desdobramentos. Alunos e funcionários da UFG, estagiários do NDH e pessoas da comunidade externa à UFG, com diferentes motivações e formações diversas, o integram. Os encontros acontecem quinzenalmente e contam com dinâmicas que envolvem a participação de todos os seus integrantes, seja através da leitura, apresentação e debate sobre os textos selecionados, seja através das palestras com pesquisadores convidados. Neste relato, o leitor conhecerá melhor as ações, as temáticas discutidas, os palestrantes já recebidos, os desafios e os projetos do Grupo de Estudos em Di', 'https://revistas.uepg.br/index.php/conexao/article/view/5191', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531bb', 'A EXTENSÃO UNIVERSITÁRIA EM DOCUMENTOS DA UNEMAT: UM CONCEITO A SER CONTRUÍDO', 'Machado, Verônica Moreno', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo é um recorte de uma pesquisa realizada na Universidade do Estado de Mato Grosso, tem como objetivo verificar as concepções de extensão universitária manifestas em alguns documentos da UNEMAT. Embasa-se na pesquisa qualitativa através de um estudo de caso e utiliza-se a análise documental. A pesquisa investiga as diferentes concepções de extensão presentes na história da universidade brasileira e em algumas legislações nacionais, bem como em resoluções da UNEMAT e nos 43 projetos de extensão que estiveram em vigência no ano de 2011, no Campus Universitário Jane Vanini de Cáceres e na Sede Administrativa. Revela-se que estes documentos estão em consonância com o Plano Nacional de Extensão Universitária. Porém, a UNEMAT, nos documentos analisados, ainda não explicitou um conceito particular de extensão, o que pode gerar contradições em seu desenvolvimento.', 'https://revistas.uepg.br/index.php/conexao/article/view/5306', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c0', 'CONSTRUÇÃO DO MARCO LEGAL PARA A PRODUÇÃO DE AÇAÍ DE JUÇARA: CONTRIBUIÇÕES DA “OFICINA INTERESTADUAL SOBRE LEGISLAÇÃO, COMERCIALIZAÇÃO E MARKETING PARA EXPLORAÇÃO DE FRUTOS DA PALMEIRA JUÇARA”.', 'Chaimsohn, Francisco Paulo; Chiquetto, Nelci Catarina', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O corte ilegal da palmeira juçara (Euterpe edulis Mart.) para a extração do palmito gera perdas ambientais. A exploração sustentável de frutos para a produção de suco similar ao açaí (E. oleracea Mart.) pode contribuir para a conservação da espécie, a manutenção da biodiversidade da Mata Atlântica e a geração de renda em comunidades inseridas em áreas de preservação permanente ou em seu entorno. Alternativas para o desenvolvimento da exploração sustentável através da construção de um marco legal apropriado à atividade, considerando-se a potencialidade do produto e a questão socioambiental, foram debatidas em grupos de trabalho envolvendo técnicos, pesquisadores, professores, membros da policia ambiental, agricultores, gestores e estudantes de ciências agrárias e ambientais Concluiu-se que a legislação deve motivar o cultivo das palmeiras, principalmente em sistemas agroflorestais; que há necessidade de regulamento técnico para fixação dos padrões de identidade e qualidade da polpa; e q', 'https://revistas.uepg.br/index.php/conexao/article/view/5416', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c1', 'EDUCAÇÃO, CULTURA E MOVIMENTO: UMA ABORDAGEM INTERDISCIPLINAR EM EXTENSÃO NO VALE DO SÃO FRANCISCO', 'de Maio, Marcelo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este estudo relata a estrutura, procedimentos metodológicos e resultados da disciplina com caráter de extensão chamada por Núcleo Temático, a qual é oferecida sob o título de “Educação, Cultura e Movimento-ECM”. O ECM possui 120 horas/aula, é interdisciplinar e está ligado ao curso de Educação Física da Universidade Federal do Vale do São Francisco (UNIVASF/Petrolina-PE). O ECM é composto por professores das áreas da Educação Física, Artes Visuais, Biologia, Medicina, Farmácia e Psicologia. Suas atividades são estruturadas a partir de quatro linhas de estudo relacionadas às áreas da cultura, história e sociedade; corpo, movimento, expressão e criatividade; corpo, saúde e qualidade de vida; e esporte, lazer e meio ambiente. Os procedimentos “extensionistas” do ECM serão ilustrados a partir de dois projetos, escolhidos entre oito desenvolvidos em sua primeira versão em 2011, são eles: “Resgatando tradições orais no Vale do São Francisco, comunidade indígena Truká, Sobradinho-BA” e “Fotog', 'https://revistas.uepg.br/index.php/conexao/article/view/5501', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c8', 'A LEITURA LITERÁRIA COMO REVIVÊNCIA E RESSIGNIFICAÇÃO SUBJETIVA DE UM ALUNO-DETENTO', 'Melo, Henrique Furtado de; Oliveira Lima, Sheila', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto “As marcas dos momentos de entrada no mundo da leitura nas construções textuais-discursivas de alunos detentos: vestígios de infâncias encarceradas” surge a partir da demanda observada nos atendimentos a detentos participantes do projeto “Remição pela leitura”, promovido pela Secretaria de Estado de Justiça, Cidadania e Direitos Humanos. Durante o processo de orientação de um dos alunos-detentos, foram observados elementos de sua subjetividade evocados a partir da convivência com a leitura literária. Amparados em estudos sobre a função do texto literário, na psicanálise freudiana e em pesquisas sobre o potencial transformador da leitura em situações de crise, foi possível estabelecer uma reflexão sobre a relevância da leitura literária como meio de revisão da narrativa pessoal do detento e da consequente reorientação de sua relação com o mundo e consigo mesmo.', 'https://revistas.uepg.br/index.php/conexao/article/view/5549', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531cb', 'O YOGA COMO ESTRATÉGIA PARA PROMOVER A QUALIDADE DE VIDA NO TRABALHO', 'Villa, Eliana Aparecida; Valadares, Victor Mourthé; Vieira, Jackeline Soares; Oliveira, Bárbara Kellen Souza; Spagnol, Carla Aparecida; Candian, Érica Santana; Freitas, Maria Édila Abreu; Silveira, An', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Esse artigo relata a experiência da adoção do yoga como estratégia de promoção da qualidade de vida no trabalho (QVT) para a equipe de enfermagem de um Hospital Escola. Aplicamos um questionário para traçar o perfil da equipe, apreender suas percepções sobre as condições de trabalho e sobre a qualidade de vida na organização. Posteriormente, implementamos o yoga em dois turnos e, ao final, aplicamos outro questionário para avaliar a adesão à atividade proposta. Os trabalhadores aderiram à prática adotada e pretendem participar de outras estratégias. Esperamos incentivar os trabalhadores a desenvolver o autocuidado e criar ambientes confortáveis/produtivos para uma assistência de qualidade.', 'https://revistas.uepg.br/index.php/conexao/article/view/5727', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d5', 'ATENDIMENTO AMBULATORIAL DE CRIANÇAS EM CENTRO DE RECUPERAÇÃO NUTRICIONAL', 'Brecailo, Marcela Komechen; Saldan, Paula Chuproski', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo desse artigo é relatar a experiência de um Projeto de Extensão em Nutrição Materno Infantil desenvolvido em um Centro de Recuperação Nutricional em Guarapuava-PR. O projeto foi desenvolvido na forma de atendimento ambulatorial nutricional às crianças e suas mães por acadêmicas de Nutrição, supervisionadas por docentes nutricionistas. As mães recebiam orientações sobre o estado nutricional e a alimentação da criança com base nos hábitos alimentares e condição social da família. Foram realizados 338 atendimentos. Verificou-se que 47,0% das crianças apresentaram melhora do estado nutricional entre o primeiro e o segundo atendimento, 29,1% delas não retornaram para o segundo atendimento, 17,9% não tinham necessidade de um novo atendimento e 6,0% apresentaram piora do estado nutricional. Com a realização do projeto crianças e mães receberam atendimento nutricional específico para melhora do estado nutricional da criança e as acadêmicas puderam vivenciar a prática profissional ali', 'https://revistas.uepg.br/index.php/conexao/article/view/6279', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d6', 'EXTENSÃO UNIVERSITÁRIA, EDUCAÇÃO AMBIENTAL E LUDICIDADE NA PRESERVAÇÃO DE ANIMAIS SILVESTRES', 'Islas, Camila Alvez; Behling, Greici Maia', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O NURFS/CETAS-UFPEL realiza atendimento e destinação de animais silvestres oriundos de ações de fiscalização ambiental ou entrega voluntária, além de atividades de ensino, pesquisa e extensão. A extensão universitária deve garantir a aprendizagem recíproca da comunidade acadêmica e da sociedade e estimular a comunidade universitária à realização de ações sociais, políticas e profissionais. Assim, o Programa de Educação Ambiental do NURFS/CETAS realiza atividades de sensibilização e formação de consciência crítica dos indivíduos com relação à preservação da fauna silvestre. O objetivo deste trabalho é descrever duas das experiências desenvolvidas: a elaboração de um jogo de tabuleiro e a apresentação de um teatro de fantoches sobre animais silvestres/cativeiro ilegal buscando, pela ludicidade, despertar a preocupação em preservar a fauna silvestre. Conclui-se que atividades lúdicas podem ser usadas, desde que acompanhadas de ações educativas paralelas, na busca pela conscientização para', 'https://revistas.uepg.br/index.php/conexao/article/view/6290', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d8', 'CULTURA E LAZER COMO PROPOSTA PEDAGÓGICA ARTICULADA À EDUCAÇÃO INTEGRAL PARA ALUNOS MATRICULADOS NA ESCOLA REITOR ÁLVARO AUGUSTO CUNHA ROCHA, DO CAIC/UEPG', 'Santos, Sonia Aparecida Gomes do; Campos, Joselaine Aparecida; Cruz, Gilmar de Carvalho; Souza, Audrey Pietrobelli de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'No presente estudo, relata-se uma experiência pedagógica vivenciada no âmbito CAIC - Escola Álvaro Augusto Cunha Rocha direcionado aos filhos de servidores da UEPG, regularmente matriculado na referida escola. As práticas foram configuradas por: atividades relacionadas ao lazer (jogos e atividades extra-ambiente com visitas técnicas que agregam conhecimento), esporte (variedades esportivas com o ludicidade) e cultura (oficinas de leitura e artes). O referido projeto insere-se no âmbito da Educação Integral e tem como objetivo: atender, pedagogicamente, a demanda de alunos que ficam na escola após o encerramento das aulas, no período das 16h às 17h30min. É parte da demanda que resultou em problemática na escola, ou seja, após o encerramento das aulas os alunos ficavam ociosos e, sem acompanhamento pedagógico não raro envolviam-se em incidentes. Diante desse problema houve a necessidade de, junto a PRORH (Pró–Reitoria de Recursos Humanos), o CAIC e CDR (Centro de Desporto e Recreação), p', 'https://revistas.uepg.br/index.php/conexao/article/view/6324', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531e2', 'IMPLANTAÇÃO DO PROGRAMA DE REABILITAÇÃO PULMONAR EM UM HOSPITAL ESCOLA DE NIVEL TERCIÁRIO NA CIDADE DE FORTALEZA/CE: EXPERIÊNCIA DA FISIOTERAPIA', 'Vasconcelos, Renata dos Santos; Sales, Raquel Pinto; Magalhães, Clarissa Bentes de Araujo; de Vasconcelos, Thiago Brasileiro; Macena, Raimunda Hermelinda Maia; Viana, Soraya Maria do Nascimento Rebouç', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Doença Pulmonar Obstrutiva Crônica (DPOC) é uma enfermidade respiratória prevenível e tratável, caracterizada pela presença de obstrução crônica do fluxo aéreo. A Reabilitação Pulmonar é um programa de cuidados inter/ multidisciplinares, com ações assistenciais planejadas que possibilitam ao usuário a otimização da autonomia para atividades da vida diária, com melhora da qualidade de vida através da ampliação do desempenho físico e social. Dessa forma, objetivamos descrever o processo de implantação de um programa de extensão universitária de reabilitação pulmonar em um hospital escola de nível terciário na cidade de Fortaleza/CE. Para tanto, realizamos um relato de caso de prática extensionista, qualitativo e interpretativo. Foi organizada parceria com o Programa de Residência Multiprofissional de Fisioterapia do Hospital Universitário Walter Cantídio, criada uma agenda de atendimentos e selecionado o protocolo a ser utilizado. As etapas de implantação incluíam avaliação do usuário (m', 'https://revistas.uepg.br/index.php/conexao/article/view/6745', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531e3', 'INVESTIGAÇÃO SOBRE A INSERÇÃO DA TEMÁTICA AMBIENTAL NO ENSINO FUNDAMENTAL EM DUAS ESCOLAS DE GUARAPUAVA – PR', 'Suriani-Affonso, Ana Lúcia; Plavak, Tatieli; Kataoka, Adriana Massaê', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente estudo teve por objetivo investigar a inserção da temática ambiental no ensino fundamental, e as representações sociais de meio ambiente e Educação Ambiental de professores de duas escolas de Guarapuava - PR. Buscou-se os fundamentos da pesquisa qualitativa, utilizando a entrevista como instrumento para a coleta de dados. Os resultados revelaram que as representações dos professores sobre estes temas são muito genéricas, descontextualizadas e até mesmo ingênuas, as quais podem estar associadas à deficiência na própria formação e uma forte influência da mídia. Diversas iniciativas já acontecem nas escolas, tanto de forma disciplinar quanto interdisciplinar, embora os assuntos ainda sejam abordados pontualmente. Apesar dos problemas apontados, os professores demonstraram uma grande disposição em estarem abordando a temática. Essa investigação trouxe resultados importantes no sentido de subsidiar um projeto de Educação Ambiental nas referidas escolas que parta do diagnóstico ap', 'https://revistas.uepg.br/index.php/conexao/article/view/6748', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531e4', 'ABORDAGEM CONCEITUAL TEÓRICA E EXPERIMENTAL SOBRE ASSUNTOS DE HIDROSTÁTICA', 'Santos, Silvia Helena Fonseca; Silva, Vania Cristina Rutz da; Silva, Silvio Luiz Rutz da; Moletta, Larissa Fernanda Yassugui; Silva, Jeremias Borges da; Drabeski, Regiane Gordia; Brinatti, André Maurí', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A contextualização do ensino é fortemente recomendada em documentos oficiais, como os Parâmetros Curriculares Nacionais. O cotidiano oferece possibilidades de explorar a Física na sala de aula. O objetivo deste trabalho foi desenvolver uma atividade construtivista abordando o tema Hidrostática. Os assuntos apresentados foram Lei de Stevin, Princípios de Pascal e de Arquimedes. A atividade consistia em uma revisão dos assuntos, para uma turma do 2º ano do Ensino Médio e uma turma do 1º ano do curso profissionalizante de Técnico em Química, realizada pelos acadêmicos do projeto extensionista – Iniciação à Docência para a Licenciatura em Física da Universidade Estadual de Ponta Grossa. A revisão foi feita utilizando experimentos demonstrativos, uma demonstração para cada assunto. No decorrer da explanação, foram explorados alguns exemplos do cotidiano e, por fim, realizado um questionário para avaliar qualitativamente se houve a ancoragem de novo conhecimento.', 'https://revistas.uepg.br/index.php/conexao/article/view/6752', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cfa32da1a94b3531e5', 'A CONTRIBUIÇÃO DO PROJETO “GESTORES DE CADEIAS PRODUTIVAS RURAIS” NO PROGRAMA DE DESENVOLVIMENTO REGIONAL SUSTENTÁVEL - DRS DO BANCO DO BRASIL: UM ESTUDO DE CASO NO MUNICÍPIO DE CATANDUVAS, TERRITÓRIO', 'Zonin, Wilson João; Corbari, Fábio; Gregolin, Marcos Roberto Pires; Zonin, Valdecir José; Gregolin, Graciela Caroline', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este estudo destaca o trabalho de sensibilização e aplicação da matriz FOFA na cadeia produtiva do leite em Catanduvas - PR, ação integrante do projeto de extensão financiado pela Fundação Banco do Brasil, que utilizou a metodologia proposta pela Universidade Corporativa do Banco do Brasil e pelo Instituto Interamericano de Cooperação para a Agricultura - IICA. O trabalho aconteceu em 12 estados brasileiros e proporcionou apoio técnico para a estruturação das cadeias produtivas interligadas ao DRS do BB. Metodologicamente, pode-se destacar a fase de sensibilização regional, seguida de aplicação de um diagnóstico participativo, finalizando com a elaboração de um plano de negócios, vinculado a estratégias de desenvolvimento rural sustentável. Conclui-se que há necessidade de desenvolver ações estruturantes entre os agricultores familiares e fomento ao cooperativismo, porém percebe-se que estas ações têm mais chance de serem desempenhadas quando elas surgem de um processo participativo de', 'https://revistas.uepg.br/index.php/conexao/article/view/6758', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cfa32da1a94b3531e7', 'A INFLUÊNCIA DO GÊNERO NA PARTICIPAÇÃO DA MODALIDADE FUTEBOL NO PROJETO ESCOLA DA BOLA', 'Gabriel, Bruno José; de Freitas Jr., Miguel Archanjo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto Escola da Bola (UEPG) atendia, em 2011, a 260 escolares residentes no entorno do Campus Universitário. Ofertava várias práticas físicas e esportivas, como o basquetebol, a dança, o futebol, o futsal, as lutas, a natação e o voleibol. Posteriormente ao encerramento do período de inscrição, observou-se a inexistência de meninas matriculadas na modalidade futebol. Desta forma, objetiva-se analisar e discutir a influência do gênero na não participação desta modalidade no referido projeto. Para tanto, optou-se pela aplicação de um questionário conformado por duas questões fechadas, para as meninas matriculadas nas outras modalidades. Das vinte e seis respondentes (26), 15,38% gostam de futebol, mas nunca tiveram oportunidade de praticar, 34,62% não gostam devido à falta de afinidade, 7,69% não gostam devido à inabilidade, 19,23% não gostam devido à violência e 23,08% não gostam devido ao preconceito de gênero. Concluiu-se que essas são as implicações atuais dos habitus sexistas hi', 'https://revistas.uepg.br/index.php/conexao/article/view/6762', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cfa32da1a94b3531ef', 'A IMPORTÂNCIA DA ORGANIZAÇÃO ADMINISTRATIVA NA GESTÃO PÚBLICA MUNICIPAL: UM ESTUDO DE CASO', 'Lauxen, Verner Augusto; Botelho, Louise de Lira Roedel', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Os gestores públicos municipais são pressionados a responder as demandas de seus stakeholders de maneira satisfatória e, para que isso seja possível, eles devem ter sua organização de trabalho bem definida e estruturada, visando atender seus objetivos. Este trabalho objetiva analisar a estrutura administrativa de um órgão de Administração Pública Direta Municipal e relacionar sua importância nos processos gerenciais daquela organização. Para tanto, realizou-se uma pesquisa qualitativa com consulta aos documentos oficiais e usuais da municipalidade, bem como, da observação participante, realizada entre os meses de Novembro de 2013 a Julho de 2014, sendo parte integrante de um projeto de extensão universitária com a temática da aprendizagem gerencial. Com esse estudo notou-se que não há estrutura administrativa oficial e isso acarreta em problemas gerenciais para a organização, como fluxos confusos de trabalho e servidores em desvio de função. Desta forma, conclui-se que a organização ne', 'https://revistas.uepg.br/index.php/conexao/article/view/6954', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d1a32da1a94b3532b4', 'ANÁLISE DOS FATORES MOTIVACIONAIS DOS ESTUDANTES UNIVERSITÁRIOS QUE ADEREM UM PROGRAMA DE EXERCÍCIO FÍSICO', 'Levandoski, Gustavo; Mourão, Alexsandra Belido; Gama, Daniel Traina', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste estudo é analisar os fatores motivacionais que levaram os universitários a aderirem ao projeto de extensão “Programa de Treinamento Físico TIME UFGD”. O presente estudo tem caráter descritivo/quantitativo e também denominado como pesquisa de campo. Participaram do estudo 101 universitários do sexo masculino, com faixa etária de 18 a 24 anos. A pesquisa foi realizada mediante questionário desenvolvido por Chagas &amp; Samulski, o mesmo contém 26 questões adaptado pelos autores. Os fatores motivacionais mais expressivos para a aderência ao treinamento físico foram: melhorar a qualidade de vida, melhorar ou manter o estado de saúde, aumentar o bem-estar corporal, aumentar a disposição geral. A motivação predominante para a participação dos acadêmicos foi 95,0% melhorar a qualidade de vida.', 'https://revistas.uepg.br/index.php/conexao/article/view/13382', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353349', 'PROJETO DE EXTENSÃO INTERINSTITUCIONAL INTERSABERES: PROTAGONISMO ESTUDANTIL À DECOLONIALIDADE DOS SABERES', 'Loro, Alexandre Paulo; de Almeida Freitas , Maria Inah; Nitiele da Silva Anacleto  , Bruna; ribeiro, silvana', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este estudo propõe-se a descrever as contribuições da extensão universitária para a Pós-Graduação, especificamente a experiência do Projeto de Extensão Interinstitucional InterSaberes, que se configura como uma proposta coordenada pelos estudantes do Programa de Pós-Graduação Interdisciplinar em Ciências Humanas da Universidade Federal da Fronteira Sul e da Universidade Estadual do Amazonas. Metodologicamente, o estudo caracteriza-se como de natureza qualitativa e bibliográfica. Durante o contexto da Pandemia de COVID-19, os acadêmicos protagonizaram ações que possibilitaram a troca de saberes sobre as pesquisas, sendo que muitas delas apresentavam uma ligação direta com as pautas da extensão universitária, como a decolonialidade e a educação para a liberdade. Conclui-se que o compartilhamento metodológico da construção do próprio projeto, que partiu das concepções da pesquisa-ação, além de possibilitar o entrelaçamento da pesquisa com a extensão, contribui para o fortalecimento do pro', 'https://revistas.uepg.br/index.php/conexao/article/view/20125', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35334a', 'EXPERIÊNCIA DA EXTENSÃO CURRICULARIZADA INSTITUCIONAL EM 2021 DA UNIVERSIDADE POSITIVO: UNIDADE CURRICULAR PROJETO EMPREENDEDOR', 'Bueno Wandscheer, Clarissa', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A extensão universitária passou por grande transformação. Inicialmente percebida pela realização de eventos e atividades assistencialistas passou a construir de forma dialógica com a sociedade soluções para seus problemas. O objetivo desse artigo é compartilhar a vivência de um dos projetos da extensão institucional curricularizada da Universidade Positivo, com a utilização de instrumentos remotos para o desenvolvimento das atividades. As atividades foram desenvolvidas no segundo semestre de 2021, no projeto Empreender em Peabiru da unidade curricular de extensão Projeto Empreendedor. Caracteriza-se por uma pesquisa em extensão com uma abordagem qualitativa, com objetivos descritivos, procedimento documental e pesquisa participante. Como resultado percebe-se que os meios remotos não constituíram um obstáculo para a realização da extensão, a relação dialógica contribuiu para o engajamento dos discentes no projeto, os materiais entregues ao final atenderam às expectativas. Contudo, ainda', 'https://revistas.uepg.br/index.php/conexao/article/view/20151', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
