INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35335e', 'ASPECTOS DE HIGIENE NA INFÂNCIA DURANTE A PANDEMIA DA COVID-19: RELATO DE EXTENSÃO UNIVERSITÁRIA', 'Fonseca, Álvaro Micael Duarte; Souza, Aryane Bastos de; Silva Júnior, José Antonio da; Nascimento, Ellany Gurgel Cosme do', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este estudo objetiva relatar vivências e desafios do projeto Ensinando às Crianças Aspectos de Higiene durante a pandemia da COVID-19. Trata-se de um estudo descritivo, tipo relato de experiência, que teve o desenvolvimento e a adaptação de ações educativas no ambiente online. Este novo espaço possibilitou a reunião e a comunicação dos extensionistas, cumprindo assim o papel social, de ensino, pesquisa e extensão, alcançando a comunidade mesmo durante a pandemia. Foram confeccionados vídeos educativos, por meio de teatros, canções e ebooks infantis, de autoria. Esses materiais levaram a um maior alcance do projeto à sociedade, bem como tornou possível um feedback positivo. A experiência evidenciou a necessidade de adaptações como essa, com o intuito de divulgar o projeto em ambientes extraescolar e universitário, permitindo que as crianças, profissionais de saúde e de educação tenham conhecimento e acesso ao projeto e as suas atividades, abrangendo assim a sociedade como um todo.', 'https://revistas.uepg.br/index.php/conexao/article/view/21388', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
