INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b35338d', 'EDUCAÇÃO EM SAÚDE COM CRIANÇAS E ADOLESCENTES EM SITUAÇÃO DE VULNERABILIDADE SOCIAL: RELATO DE AÇÕES EXTENSIONISTAS', 'Saraiva , Ana Laura Alves; Vernes, Victória Braseiro; Balk, Rodrigo de Souza; Da Costa e Silva, Tatiane Motta; Nunes, Geovana dos Santos; da Rosa, Mylena Francini', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O estudo tem o objetivo de relatar a implementação e o desenvolvimento de ações extensionistas realizadas junto ao Centro de Referência Especializado de Assistência Social (CREAS), como estratégia de educação em saúde e diminuição de desigualdades sociais para crianças e adolescentes socialmente assistidos. Trata-se de um estudo do tipo relato de experiência. As ações foram desenvolvidas pelo Programa de Educação Tutorial Práticas Integradas em Saúde Coletiva (PET PISC), em parceria com um CREAS de um município da Fronteira Oeste do Rio Grande do Sul, sendo realizadas entre os meses de junho de 2021 e janeiro de 2023. Foram abordados temas como prevenção ao bullying, direitos humanos e cultura da paz, desenvolvimento motor e combate ao assédio sexual. As atividades oportunizaram momentos de discussão e reflexão junto aos participantes, além de agregarem ao futuro profissional dos discentes envolvidos, contemplando conhecimentos extracurriculares e possibilitando vivências multiprofissi', 'https://revistas.uepg.br/index.php/conexao/article/view/22438', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
