INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353391', 'DIAGNÓSTICO DE LESÕES ORAIS E ANÁLISE DEMOGRÁFICA EM CAMPANHAS DE PREVENÇÃO DO CÂNCER BUCAL: IMPACTO DE AÇÕES EXTENSIONISTAS REALIZADAS EM UMA POPULAÇÃO DO NORDESTE BRASILEIRO', 'Belo Faria, Caroline Augusta; da Silva Barros, Caio César; Vieira Pedrosa, Bruna Rafaele; Fonseca da Silveira, Márcia Maria; Fernandes Azevedo, Ana Beatriz; Veras Sobral, Ana Paula', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Campanhas de prevenção do câncer de boca têm atuado como importantes ferramentas na detecção precoce de lesões orais. Nesse sentido, o objetivo deste artigo foi relatar o impacto de ações extensionistas, realizadas pela Liga Acadêmica de EstomatoPatologia em uma população do nordeste brasileiro, através da análise de fichas clínicas de campanhas de prevenção do câncer bucal. Dos 355 participantes que foram submetidos a exame clínico, 57,8% dos que foram diagnosticados com lesões eram do sexo feminino. As lesões infecciosas foram as mais prevalentes (42,8%), seguidas das desordens orais potencialmente malignas (16,7%), lesões reativas/inflamatórias (15,5%) e defeitos de desenvolvimento (9,5%). Torna-se evidente a relevância do projeto e o impacto positivo gerado na sociedade, uma vez que permite a expansão do conhecimento acerca da população examinada e traz benefícios para os participantes, por meio da ampliação do acesso ao cirurgião-dentista e maior conscientização da importância do ', 'https://revistas.uepg.br/index.php/conexao/article/view/22484', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353392', 'EDUCAR PARA A SUSTENTABILIDADE NO CONTEXTO DE SABERES TRADICIONAIS: AÇÕES COMUNITÁRIAS PARA SENSIBILIZAÇÃO AMBIENTAL E VALORIZAÇÃO DA CULTURA LOCAL', 'Silva, Natanael Charles da; Cavignac, Julie Antoinette; Araújo, Magnólia Fernandes Florêncio de; Nascimento, Aline Gadelha do', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente relato objetivou apresentar as ações comunitárias desenvolvidas por um projeto de extensão que integrou saberes tradicionais e Educação para a Sustentabilidade em localidades do estado do Rio Grande do Norte (RN). O projeto intitulado “Saberes tradicionais e educação para a sustentabilidade: um projeto de extensão realizado na Vila de Ponta Negra (Natal) e Pium (Nísia Floresta e Parnamirim), RN” ocorreu entre dezembro de 2021 e julho de 2023, abrangendo atividades diversas, como: reuniões, visitação, promoção e participação em eventos, oficinas, produção de material audiovisual, oferta de formações, produção acadêmica (dissertações e teses) e produção de material didático. Os dados evidenciam que o projeto obteve resultados satisfatórios ao apontar o alcance das duas metas inicialmente traçadas (1- Sensibilização para uma educação sustentável; e 2 - Valorização da cultura local). Além disso, o projeto contribuiu para a formação científica e cidadã dos envolvidos, ao nortear ', 'https://revistas.uepg.br/index.php/conexao/article/view/22491', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353393', 'A EXTENSÃO UNIVERSITÁRIA NA CAPACITAÇÃO EM PRIMEIROS SOCORROS DE CRIANÇAS E ADOLESCENTES', 'Silva Souza, Débora Aparecida; Vilela de Oliveira, Janaína; Souza de Almeida, Camila; Ribeiro Soares, Geovanna; da Cruz Pereira, Mislaine; de Souza Rocha Ferreira, Stéfanie', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/22502', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353398', 'O ENSINO DA HISTÓRIA DO HOLOCAUSTO SOB AS LENTES DAS RESISTÊNCIAS', 'Kosicki Bellotti, Karina; Muhlstedet Carrico, Gustavo; Gaiofatto Gonçalves, Nadia; Silva Vidal, Calebe', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'No ano de 2021, as atividades do projeto de extensão Ensino de História: diálogos e possibilidades abrangeram a construção de proposições didáticas que envolvem o ensino de História ligado ao tema do Holocausto. Uma das questões trabalhadas se relaciona às resistências naquele contexto. A importância do ensino deste tema reflete na formação de um elemento ético em sala de aula, trabalhando a consciência histórica dos educandos e educandas de modo que se responsabilizem por seu mundo observando o passado, que é constituinte do presente e, por sua vez, condiciona o futuro. Neste artigo, serão apresentados dois roteiros didáticos desenvolvidos sobre esta temática. Eles envolvem atividades e fontes sobre o nazifascismo e o Holocausto, em consonância com discussões sobre formas de resistências e sua importância para a constituição da realidade. Busca-se articular o global e o local, por meio de fontes como as referentes à narrativa de Marian Grynbaum, que participou da resistência armada ao', 'https://revistas.uepg.br/index.php/conexao/article/view/22528', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b35339b', 'QUEIJO COLONIAL ARTESANAL: DIAGNÓSTICO E CAPACITAÇÃO PARA AGRICULTORES FAMILIARES DA REGIÃO DE LARANJEIRAS DO SUL', 'Picinin de Castro Cislaghi, Fabiane; de Souza Vigolo, Joelcio; Quast, Ernesto; Ragazzon, Daniela; Battestin Quast, Leda', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi apresentar um diagnóstico geral sobre a produção de queijo Colonial artesanal, informações técnicas e bibliográficas sobre os assuntos abordados na capacitação feita para produtores de queijo Colonial artesanal e os resultados das atividades realizadas durante a formação dos agricultores. O Curso de Queijo Artesanal teve oito módulos, oferecido aos produtores de queijo e profissionais da área, promovido pelo IDR-Paraná em parceria com Universidades, SEAB e suas empresas vinculadas. As palestras abordaram sobre saúde e sanidade do rebanho, obtenção higiênica do leite e boas práticas de fabricação de queijo, legislação brasileira do queijo artesanal, gestão da qualidade e financeira da agroindústria, turismo rural e tecnologia de fabricação para o queijo Colonial. Constatou-se que na região de Laranjeiras do Sul há carência de informações sobre produção de queijo Colonial e há a necessidade de promover eventos voltados à atividade para que o queijo tenha qualid', 'https://revistas.uepg.br/index.php/conexao/article/view/22642', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
