INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67bc99d9e27dfa1251894da1', 'AÇÕES EXTENSIONISTAS PARA O DESENVOLVIMENTO DE ESTRATÉGIAS DE IDENTIFICAÇÃO DE ÁREAS DE OCORRÊNCIA POTENCIAL DO MOSQUITO AEDES AEGYPTI NO MUNICÍPIO DE BANDEIRANTES (PR)', 'Ferri Menegheli, Breno Henrique; Oliveira Motta, Ana Beatriz; Marcos Sgarbi , Ederson; de Souza Lemes, Gabriel; Rolim de Oliveira Ferreira, Paulo Guilherme; Batista de Oliveira, Rone', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A dengue é uma das principais arboviroses transmitidas pelo Aedes aegypti. O projeto "Estratégias para Prevenção e Combate à Dengue com o Uso de Aeronaves Remotamente Pilotáveis (ARP)", realizado em Bandeirantes, PR, pelo Programa de Extensão Universidade sem Fronteiras, visa capacitar agentes de combate às endemias e mapear áreas de risco com ARP. É fundamental que os agentes participem de processos institucionalizados, gerando qualificação e legitimando seus saberes. Os agentes se mostraram qualificados na aprendizagem de novas ferramentas e uma maior valorização e reconhecimento de seu trabalho. As áreas mapeadas permitiram o georreferenciamento de 779 terrenos. Os maiores índices de imóveis não fiscalizados foram registrados na Vila São José e Vila Paraíso. Os principais problemas identificados foram obstruções em calhas, acúmulo de materiais de construção e caixas de cimento. A extensão universitária promove a interação entre a universidade e a sociedade e, portanto, é essencial p', 'https://revistas.uepg.br/index.php/conexao/article/view/23150', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67bc99d9e27dfa1251894da8', 'ESTADO DE CONHECIMENTO DA CURRICULARIZAÇÃO DA EXTENSÃO UNIVERSITÁRIA: BIBLIOTECA DIGITAL BRASILEIRA DE TESES E DISSERTAÇÕES (BDTD) 2019-2023', 'Picollo de Oliveira, Amauri; Cláudio Del Pino, José', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/23388', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67bc99d9e27dfa1251894dab', 'PERCEPÇÕES SOBRE A PRODUÇÃO ARTESANAL DE KEFIR EM UM GRUPO FOCAL', 'da Silva, Lilian de Fátima Ferreira; Salazar, Marcela Mendes; Ströher, Jeferson Aloísio; Lehn,  Daniel Neutzling Lehn; Flôres, Simone Hickmann; Malheiros, Patrícia da Silva Malheiros', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O interesse crescente por hábitos alimentares saudáveis impulsiona a procura por alimentos funcionais, com destaque para o kefir, rico em microrganismos. No entanto, a produção artesanal de kefir no Brasil enfrenta desafios de padronização para a industrialização em larga escala. A doação de grãos de kefir é a principal forma de obtenção, mas a falta de familiaridade com técnicas de manipulação pode resultar em variações na composição e na qualidade microbiológica. Este estudo apresenta resultados de oficinas extensionistas, nas quais 19 participantes foram envolvidos, destacando a necessidade de educação e pesquisa para estabelecer padrões e tornar o kefir mais acessível. A falta de conhecimento sobre o kefir ressalta a importância da educação e do investimento em pesquisa para definir padrões, tornando-o mais acessível a um amplo público. Isso promove uma cultura alimentar saudável e sustentável, preparando-o para a comercialização em larga escala.
Palavras-chave: Alimentos funcionai', 'https://revistas.uepg.br/index.php/conexao/article/view/23499', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
