VALUES ('6943cb2df2f3b972440792ed', 'ADOLESCÊNCIA E SEXUALIDADE: RELATO DE EXPERIÊNCIA DA REALIZAÇÃO DE GRUPOS OPERATIVOS EM UMA ESCOLA', 'Silva Souza, Debora Aparecida; Souza de Almeida, Camila; Lobo Michel, Julia; Andrade Faria Vaz, Ana Clara; Cardoso Ferreira, Filipe Gabriel', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/24982', NULL, 'English', 'published', false, false, 'open', 'pdf')
