INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792ef', 'ENTRE ALGORITMOS E EMOÇÕES: A FORMAÇÃO DE PROFESSORES ATRAVÉS DE UM CURSO ON-LINE ABERTO E MASSIVO COMO EXTENSÃO UNIVERSITÁRIA', 'da Cruz Fraga, Cristiano; Decarli, Cecilia; Inês Boll, Cíntia', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O artigo apresenta um relato de experiência do curso on-line aberto e massivo (MOOC), intitulado “Inteligência Emocional e Inteligência Artificial: um debate para o futuro da educação”, ofertado ao grande público interessado na temática no âmbito da educação, abrangendo, assim, professores e estudantes de licenciatura. O estudo tem por objetivo apresentar o curso e analisar dados coletados pelos cursistas por meio de análises multivariadas, a fim de verificar expectativas e possibilidades da integração entre Inteligência Artificial e Inteligência Emocional. A metodologia consiste em relato de experiência e análise textual de respostas de fóruns no período de julho de 2024 a abril de 2025. O curso segue disponível, e novas interações podem ocorrer após a publicação deste estudo. Os resultados apresentam os temas abordados pelo curso e as conexões estabelecidas pelos cursistas. O MOOC produzido e o material gerado em virtude dele serão úteis na disseminação do conceito de Amorismo em tem', 'https://revistas.uepg.br/index.php/conexao/article/view/25037', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792f1', 'O ACESSO AO ENSINO SUPERIOR DE MIGRANTES NO BRASIL COMO ESTRATÉGIA DE PROMOÇÃO DE INCLUSÃO SOCIAL: UM RELATO DE EXPERIÊNCIA DO PROJETO DE EXTENSÃO MIGRANTES DAS FACULDADES PEQUENO PRÍNCIPE.', 'Carrer Fassbender Teixeira, Mariah; Negri Kreutzer, Mariana; Furtado Viana, Maria Isabella; Bogus, Ana Luiza; Bitdinger Cobalchini, Cláudia Cibele', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Diante do crescimento da migração para o Brasil, diversas dificuldades têm sido enfrentadas por pessoas migrantes, especialmente no que se refere ao acesso à saúde, à informação e à educação. Barreiras linguísticas, preconceito, exclusão social e ausência de políticas públicas adequadas tornam esse grupo ainda mais vulnerável. Dentre os fatores promotores de inclusão está o acesso à educação e à qualificação para o trabalho. Este artigo descreve as intervenções desenvolvidas pelas estudantes participantes do projeto de extensão “Migrantes”, promovido pelas Faculdades Pequeno Príncipe, que oferece apoio a migrantes em Curitiba e região metropolitana. Por meio de visitas a alguns locais, estudos teóricos e atividades práticas, as estudantes identificaram a necessidade de ampliar o acesso a informações sobre o ensino superior brasileiro para migrantes. A partir dessa demanda, foram desenvolvidas ações educativas com o objetivo de contribuir para a inclusão social dessa população. A experi', 'https://revistas.uepg.br/index.php/conexao/article/view/25361', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792f2', 'ALIMENTO SEGURO E SAÚDE PÚBLICA: EXTENSÃO UNIVERSITÁRIA EM ESCOLA DE REALEZA-PR', 'Barros de Araújo, Laiana; Kawka, Maria Eduarda; Pereira Gomes, Giordanna; Ramirez Starikoff, Karina; Amaral Ojeda, Breno; Borges Hall, Ana Julia', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A “Gincana do Alimento Seguro” foi desenvolvida pelos projetos de extensão “Semeando sustentabilidade: fortalecimento das agroindústrias da agricultura familiar” e “Condições higiênico-sanitárias de estabelecimentos de produtos de origem animal”. O objetivo foi promover e divulgar a conscientização sobre alimento seguro para estudantes do ensino médio em Realeza, PR. Inicialmente, foi aplicado um questionário a todos os alunos para avaliar o nível de familiaridade com o tema. Na sequência, foram realizadas quatro atividades: 1. identificar erros em ambientes de manipulação de alimentos; 2. verificar a ocorrência de contaminação durante o preparo de refeições; 3. analisar os rótulos de produtos de origem animal; e, 4. visualizar a contaminação cruzada e a manipulação inadequada de alimentos. A gincana foi aplicada a 115 alunos, distribuídos em quatro turmas. A experiência mostrou o potencial das metodologias ativas para o envolvimento do público estudantil, contribuindo para a formação ', 'https://revistas.uepg.br/index.php/conexao/article/view/25364', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792f5', 'ENERGIAS RENOVÁVEIS: UMA ABORDAGEM NO APROVEITAMENTO DE RESÍDUOS AGRÍCOLAS NA PRODUÇÃO DE BIOGÁS', 'Cláudia Rodrigues, Rosane; Oliveira Pereira , Lis Lanni; Sousa Brito, Lucas; dos Santos Araújo, Jocélio; Veras, Alexandre; dos Santos Cabral , Ismael', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto de extensão Energia renováveis: uma abordagem no aproveitamento de resíduos agrícolas na produção de biogás teve como objetivo difundir conhecimentos científicos e práticos sobre biodigestores, promovendo sua aplicação como alternativa sustentável no meio rural. As ações foram desenvolvidas por meio de metodologia extensionista, envolvendo estudantes do ensino médio, técnico, tecnológico e de graduação em minicursos, oficinas e ações formativas. Também foram realizadas exposições educativas, feiras de ciências e atividades lúdicas para ampliar o diálogo com escolas técnicas e agricultores familiares. Os experimentos práticos utilizaram esterco bovino e resíduos ruminais, possibilitando avaliar o potencial de produção de biogás e do digestato como biofertilizante. Como produto, elaborou-se uma cartilha didática destinada à difusão junto a agricultores. A extensão universitária desempenha papel estratégico na popularização da ciência, fortalecendo a sustentabilidade energética ', 'https://revistas.uepg.br/index.php/conexao/article/view/25574', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('69033490b901ffe5ca64ccd0', 'A IMPORTÂNCIA DO CIRURGIÃO DENTISTA NA REABILITAÇÃO ESTÉTICA E SOCIAL DE PACIENTE COM MUTILAÇÃO FACIAL: UM RELATO DE EXPERIÊNCIA DE UM PROJETO DE EXTENSÃO:', 'Nunes Godoi Moreira, Mariana; Foresti Vieira Munhoz, Maira; Filié Haddad, Marcela', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/24834', NULL, 'English', 'published', false, false, 'open', 'pdf')
