INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f792600a', 'PROTAGONISMO ESTUDANTIL: O POTENCIAL DE UMA COMUNIDADE FRENTE AOS ESPAÇOS SILENCIADOS NO ENSINO SUPERIOR', 'Maria Ramos, Wilsa; de Resende Lombardi, Anne; Yann Costa Rodrigues, Wyder; Nunes Melo, Yasmin; Montalvão Marques, Meire Kamile; Louzada Guedes Carneiro da Fontoura, Beatriz', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O artigo relata a experiência do projeto de extensão universitária Comunidade Virtual de Aprendizagem e Práticas da Psicologia do Instituto de Psicologia da Universidade de Brasília, destacando sua contribuição para a formação acadêmica e o desenvolvimento interpessoal dos estudantes. A comunidade é composta por discentes de graduação, uma professora coordenadora e ex-alunas voluntárias. As atividades incentivam a construção coletiva de conhecimentos, redes de pertencimento e acolhimento de discentes, docentes e técnicos, configurando-se como espaço dialógico de luta e resistência diante de exclusões e desigualdades sociais nos microespaços silenciados na universidade. Em cinco anos, mais de 1200 pessoas foram beneficiadas pelas oficinas, minicursos e rodas de conversa, além de conteúdos multimídia produzidos pelos estudantes. Os resultados apontam que a autogestão compartilhada da comunidade amplia as possibilidades de emergência do protagonismo estudantil e favorece o engajamento e o', 'https://revistas.uepg.br/index.php/conexao/article/view/24947', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f792600b', 'CONHECIMENTO DE DOCENTE SOBRE EXTENSÃO UNIVERSITÁRIA E REVISTAS DE EXTENSÃO', 'Custodio Jovasque, Luizi; Porto Schneider Rudnicki, Carlise', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente artigo apresenta como objetivo analisar as percepções de pesquisadores extensionistas a respeito da extensão universitária, bem como do fazer extensão nas revistas científicas brasileiras. Metodologicamente, é composto por pesquisa bibliográfica, análise documental e pesquisa descritiva, finalizando com a aplicação de uma pesquisa Survey. O público-alvo é composto por diferentes docentes da Universidade Federal de Santa Maria (UFSM). Quanto às revistas consideradas neste estudo, foram listadas 17 revistas brasileiras com Qualis Capes dentro das faixas de classificação A ou B. Como resultados, mostramos o que os respondentes do questionário aplicado compreendem por extensão e projetos de extensão e seu conhecimento sobre a legislação relacionada ao assunto e as revistas científicas nacionais extensionistas.
Palavras-chaves: extensão universitária; revistas científicas de extensão; comunicação científica.', 'https://revistas.uepg.br/index.php/conexao/article/view/24979', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f792600c', 'FOTOEDUCAÇÃO NO ESPORTE: RELATO DE EXPERIÊNCIA NA ZONA OESTE DO RIO DE JANEIRO', 'Collazo Pontes, Carlos Eduardo; Henriques Maffra Lessa, Telles; da Silva e Souza Lorca, Bárbara', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/24980', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f792600d', 'EXTENSÃO UNIVERSITÁRIA NO CÁRCERE: EXPERIÊNCIA INTERDISCIPLINAR EM GESTÃO SOCIAL, AGROECOLOGIA E SEGURANÇA ALIMENTAR E NUTRICIONAL:', 'do Nascimento Rabelo, Diego José; Tres, Guilherme Smaniotto; Souza, Washington José de; Torres, Romoaldo Marroque', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Ações no contexto penal precisam considerar oportunidades de melhoria nas condições prisionais, de ocupação e de ressocialização de pessoas privadas de liberdade. Assim, descrevemos experiência de extensão universitária no sistema penal brasileiro, desenvolvida sob metodologia e princípios da gestão social, com exposições dialogadas, atividades práticas e reflexões em grupo em torno de conceitos e práticas de economia solidária, segurança e soberania alimentar e agroecologia. Obtivemos, como resultados, instalação de uma horta, de um minhocário, avanços entre os apenados na compreensão dos valores de atos cooperativos, de práticas de alimentação saudável e da conscientização em torno de efeitos socioambientais dos sistemas de produção e consumo. A experiência gerou contribuição pela inserção da extensão universitária no sistema penal, alicerçada em princípios teórico-práticos que têm potencial para viabilizar o acesso de apenados a conhecimentos sobre segurança alimentar e nutricional,', 'https://revistas.uepg.br/index.php/conexao/article/view/25062', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926012', 'LABORATÓRIO INTERDISCIPLINAR DE JOGOS COLABORATIVOS: EXTENSÃO UNIVERSITÁRIA, LUDICIDADE E MEDIAÇÃO DE SABERES', 'Antunes, Jeferson; Fernandes da Silva, Abigayl; Clarice Bezerra de Araujo Silva, Ana; Nunes de Souza, Maria Eduarda', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Envolver metodologias educacionais e extensão universitária remete a uma práxis ligada a educação. Com a participação de instituições educacionais em múltiplos níveis, de forma positiva e propositiva, a pesquisa e desenvolvimento de produtos específicos para a educação pode ser um caminho que orienta essas práxis afim de desenvolver mais que produtos, estabelecendo relações e vínculos entre pessoas e instituições. O presente estudo apresenta considerações iniciais que deram origem ao Laboratório Interdisciplinar de Jogos colaborativos (LIJC), bem como estudos e análises sobre seu primeiro jogo implementado, a CRIATIVA. Seguimos um percurso teórico que demonstra os aspectos norteadores, bem como nosso conceito de extensão universitária, em seguida apresentamos o jogo criado, para então expor os resultados da aplicação desse jogo a partir de um relato de experiência.
Palavras-Chave: Jogos cooperativos; Educação; Extensão universitária.', 'https://revistas.uepg.br/index.php/conexao/article/view/25148', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926013', 'EDUCAÇÃO AMBIENTAL EM ESPAÇOS URBANOS: UMA EXPERIÊNCIA EXTENSIONISTA COM USO DE QR CODES NA ARBORIZAÇÃO PÚBLICA', 'Santos Alves, Naize; Costa Souza, Argel; Roque Lima, Michael Douglas; Morais Oliveira, Railton; Alves da Silva, Bruna; Raabe, Joabel', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente trabalho de extensão universitária teve como objetivo disponibilizar informações à comunidade sobre as espécies arbóreas presentes na Praça União do município de Imperatriz – MA, por meio da instalação de placas com QR Codes, como estratégia de promoção da educação ambiental e também para levantar a quantidade de espécies presentes na praça. As placas fornecem dados como nome científico, origem, morfologia e curiosidades, aproximando a população da biodiversidade local. Foram catalogados 83 indivíduos pertencentes a 24 espécies, distribuídas em 17 famílias botânicas, sendo 58,3% nativas. As análises dendrométricas incluíram altura, circunferência e área de sombreamento, que cobrem 4.253,63 m², correspondendo a 75% da praça. O índice de Shannon-Weaver revelou diversidade moderada (H’ = 2,53) e a equabilidade de Pielou indicou distribuição relativamente homogênea das espécies florísticas (J = 0,79). A iniciativa integrou tecnologia e sustentabilidade, promovendo sensibilização', 'https://revistas.uepg.br/index.php/conexao/article/view/25173', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926014', 'PROGRAMA DE DESENVOLVIMENTO PARA O ENSINO EM UM CURSINHO UNIVERSITÁRIO POPULAR', 'Nunes de Souza, João Pedro; Steil, Leonardo José', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A Escola Preparatória da Universidade Federal do ABC é um programa permanente de extensão que pode ser caracterizado como um Cursinho Universitário Popular (CUP) que oferece um curso gratuito para estudantes de escolas públicas. O preparo dos instrutores, que ministram as aulas, é realizado através de um Programa de Desenvolvimento para o Ensino (PDE). O presente estudo descreve as atividades e fundamentos teóricos dos encontros formativos do PDE a partir de um relato de experiência. A principal potencialidade do PDE é oferecer subsídios elementares de um conhecimento pedagógico geral para instrumentalizar uma prática crítica e reflexiva de instrutores não vinculados aos cursos de licenciatura. O principal desafio é a diversidade de objetivos, experiências e repertório do público de instrutores. Em suma, iniciativas semelhantes são necessárias para qualificar a prática docente em um CUP que representa uma oportunidade singular para promoção da equidade de acesso e permanência no ensino', 'https://revistas.uepg.br/index.php/conexao/article/view/25219', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926016', 'TECENDO SABERES: UMA EXPERIÊNCIA EXTENSIONISTA COM UMA ASSOCIAÇÃO DE SENHORAS ARTESÃS EM OURO PRETO (MG)', 'Almeida Rocha, Bernardo; Grossi Andrade, Yã; Pereira Bonilho, Julia; Torres Ribeiro das Chagas, Tays', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo relata uma experiência extensionista desenvolvida junto à Associação das Senhoras Artesãs (ASA) de Ouro Preto (MG), por meio do projeto de extensão “Mulheres de ASAs: artesanato empreendedor com mulheres rurais”, vinculado à Pró-Reitoria de Extensão da Universidade Federal de Ouro Preto. O projeto teve como foco o fortalecimento do empreendedorismo feminino, valorizando o bordado como patrimônio cultural e promovendo a capacitação técnica e organizacional das artesãs. Por meio de oficinas, assessoramento e apoio à participação em editais, as mulheres ampliaram suas habilidades, autonomia e geração de renda, além de promoverem a inovação em produtos ligados à tradição local. A atividade também contribuiu para a formação prática e crítica dos discentes, aproximando-os da realidade social e fortalecendo o diálogo entre universidade e comunidade. Como resultado, observou-se o fortalecimento da associação, a valorização dos saberes artesanais e o impacto positivo na economia loc', 'https://revistas.uepg.br/index.php/conexao/article/view/25437', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
