INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353123', 'UTILIZAÇÃO DO LÚDICO COMO COADJUVANTE DO CUIDADO PRESTADO PELA ENFERMAGEM NA PEDIATRIA', 'Pivetta, Adrieli; Argenta, Carla; Zanatta, Elisangela Argenta', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Relato de um Projeto de Prática Assistencial de Enfermagem, proposto pela disciplina de Trabalho de Conclusão do Curso de Enfermagem da Universidade Regional Integrada do Alto Uruguai e das Missões – Campus Frederico Westphalen. As ações do projeto foram implantadas no primeiro semestre de 2009, na Unidade Pediátrica de um hospital da Região Norte do RS. Teve como objetivo proporcionar o cuidar, essência da profissão Enfermagem, através de momentos de recreação, diversão e lazer para as crianças que se encontravam hospitalizadas, permitindo que desenvolvessem as atividades próprias da idade, que a hospitalização ou a própria patologia acabaram limitando ou impossibilitando. Participaram do projeto quinze crianças, na faixa etária de dois a nove anos. As ações traduziramse em: pinturas, desenhos, confecções de cartões, dobraduras e histórias. As ações possibilitaram aos pequenos pacientes atividades que vão além das impostas no ambiente hospitalar, permitindo à equipe de enfermagem ofer', 'https://revistas.uepg.br/index.php/conexao/article/view/3684', NULL, 'English', 'published', false, false, 'open', 'pdf')
