VALUES ('674852cca32da1a94b35313b', 'CONTRIBUTOS DA EXTENSÃO UNIVERSITÁRIA BRASILEIRA À FORMAÇÃO ACADÊMICA DOCENTE E DISCENTE NO SÉCULO XXI: UM DEBATE NECESSÁRIO', 'Santos, Marcos Pereira dos', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/3731', NULL, 'English', 'published', false, false, 'open', 'pdf')
