INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35313c', 'ORIENTACIÓN EDUCATIVA EN LA UNIVERSIDAD ACTUAL DESDE LA DIMENSIÓN EXTENSIONISTA', 'los Ríos, Dagneris Batista de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'La credibilidad y pertinencia de la Universidad del siglo XXI Se harán evidentes en la medida en que forjen profesionales cuya formación humanista y su alta capacitación científico –técnica sean fuentes constantes para la búsqueda se soluciones. El tríptico misional de la Universidad: formación, investigación y extensión, debe satisfacer y dar respuesta a las necesidades de la sociedad así como a ella misma. La universidad debe nutrirse de la sociedad para su desarrollo y poder aportarle a la misma. Esta relación es lo que permite el autodesarrollo y la transformación de la universidad y la sociedad, vista como un sistema de procesos conscientes, holisticos y dialécticos que revelan regularidades y relaciones que explican y predicen el comportamiento de los procesos que la construyen. En este trabajo se plasma como se logra establecer una interrelación directa entre los procesos extensionistas y la orientación educativa en la comunidad universitaria, ajustándose a los nuevos enfoques y', 'https://revistas.uepg.br/index.php/conexao/article/view/3732', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35313d', 'AS INTERAÇÕES ENTRE O ENSINO DE PUBLICIDADE E PROPAGANDA E A COMUNIDADE', 'Marques, Darciele Paula; Lisbôa Filho, Flavi Ferreira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/3734', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353140', 'AÇÃO EXTENSIONISTA FORTALECENDO A REDE DE EDUCAÇÃO AMBIENTAL DO PARANÁ', 'Hinsching, Maria Aparecida de Oliveira; Silva, Adriane Ribeiro; Dzulinski, Tatiana Constantino; Luz, Fernanda Baggio; Morales, Angélica Góis Müller', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A educação ambiental é um processo que visa construir conhecimentos socioambientais por meio do diálogo de saberes o que permite a discussão e a reflexão para a busca de melhorias e prática cidadãs para a sustentabilidade. Assim, as redes oportunizam o intercâmbio de informações, participação interativa, intermediação, relacionamento entre os integrantes da rede. Esse artigo apresenta a dinâmica da Rede de Educação Ambiental do Paraná (REA-PR), como uma ação extensionista em desenvolvimento e tem como objetivo fortalecer a REA-PR para melhor articulação entre indivíduos e instituições, a fim de somar esforços para se construir elos representativos de todos segmentos da sociedade, criando sinergia e diálogo de saberes entre os atores envolvidos em ações, programas e projetos de Educação Ambiental. Com uma metodologia participativa, os resultados alcançados refletem o fortalecimento da rede por meio de ferramentas informacionais virtuais que contribuíram no mapeamento das atividades dos ', 'https://revistas.uepg.br/index.php/conexao/article/view/3744', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353141', 'AS CONTRIBUIÇÕES SÓCIOECONÔMICAS E AMBIENTAIS DA COCAP NO MUNICÍPIO DE APUCARANA – PR', 'Oliveira, Emerson Dias de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Nosso País passa por muitos problemas a serem administrados atualmente, e a disposição incorreta do lixo é uma dura realidade sem uma solução definida. Neste contexto a questão do desenvolvimento sustentável, preservação do meio ambiente e ainda a inclusão social serão destacados neste trabalho, buscando conhecê-los mais profundamente através de seus atuais conceitos juntamente com seus diversos vetores. Objetivando enfocar a importância que têm os trabalhos realizados pelas cooperativas recicladoras, em particular pela COCAP – Apucarana, uma instituição organizada que disponibiliza novas oportunidades em inúmeros aspectos sociais aos seus associados e colaboradores, maior distribuição de renda, operacionalizando na prática a inclusão social em uma nação que possui enorme parcela da população abaixo da linha da pobreza. Aborda-se ainda, a questão ambiental, formando um perfeito ciclo sustentável nas comunidades inseridas. Espera-se contribuir para a reflexão do assunto, deixando assim,', 'https://revistas.uepg.br/index.php/conexao/article/view/3745', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353143', 'TECNOLOGIAS ALTERNATIVAS DE PRODUÇÃO VEGETAL EM TELHADOS VERDES EM ÁREAS DE INTERESSE SOCIAL', 'Silva, Luciene Pimentel da; Arruda, Juliana; Soares, Yasmin Xavier; Mary, Wellington; Garcia, Bruno Antônio Scatolin Rossafa; Pinto, Gabriel Barros', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo é resultado do projeto de extensão apoiado pelo Programa de Bolsas Institucionais de Extensão (BIEXT) da Univeridade Federal Rural do Rio de Janeiro - UFRuralRJ, ocorrido entre junho de 2009 à janeiro de 2010 em duas áreas do Rio de Janeiro, a Vila Cascatinha, em Jacarepaguá e o Mutirão Coqueiral, em Seropédica. O objetivo foi transferir tecnologia de cultivo alternativo para produção vegetal em áreas de interesse social da Baixada de Jacarepaguá e Baixada Fluminense, visando à melhoria da qualidade de vida. A metodologia foi orientada por uma abordagem pesquisa-ação, integrando ensino, pesquisa e extensão (THIOLLENT, 2000; BARBIER, 2002). Como resultado pôde-se concluir que a adoção dos sistemas de produção vegetal em áreas urbanas, utilizandose embalagens descartáveis e a tecnologia de telhados verdes, pode se tornar um veículo para a identificação do conhecimento intrínseco dos membros da comunidade, que permite a consolidação e o aproveitamento deste em atividades produ', 'https://revistas.uepg.br/index.php/conexao/article/view/3747', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353144', 'RELATO DE EXPERIÊNCIA NO NOROESTE PARANAENSE : O PROCESSO DE CONSTITUIÇÃO DA COOPERATIVA BIOLEITE', 'Gomes, Eder Pereira; Galuch, Mariana Vieira; Alves, Maria Aparecida; Takahashi, Cintia Natacha', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O trabalho tem como proposta analisar a iniciativa de organização coletiva de agricultores familiares e sua trajetória na busca por melhorias no processo de comercialização do leite em sua região. O grupo em questão, a Cooperativa de Produtores de Leite do Arenito Caiuá - BIOLEITE, iniciou o processo por meio da assessoria da Incubadora de Empreendimentos Solidários (IEES), da Universidade Estadual de Maringá (UEM), Campus Avançado de Umuarama (CAU), no noroeste do Paraná. Através da sua organização e na busca por novos mercados, conhecimento e articulação com políticas públicas de Economia Solidária, conseguiram melhores preços e qualidade do leite, permitindo a valorização do trabalho do produtor e permitindo uma melhor renda e qualidade de vida. Nesse momento, o trabalho tem como objetivo divulgar o trabalho dos produtores, a metodologia de incubação e levar essa experiência para outras localidades que enfrentam dificuldades com a comercialização do leite.', 'https://revistas.uepg.br/index.php/conexao/article/view/3748', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353148', 'A NECESSIDADE DE CAPACITAR A FAMÍLIA PARA CUIDAR EM SEU AMBIENTE DOMICILIAR: UM RELATO DE EXPERIÊNCIA', 'Silva, Luzia Wilma Santana da; Lima, Alice Almeida; Santos, Flávia Farias; Araujo, Taise Carneiro; Oliveira, Jackeline Aparecida Leite', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste estudo é compartilhar experiências de acompanhamento familiar dos discentes/docente da disciplina Saúde da Família no contexto de ações cuidativas numa comunidade, a partir do Projeto Núcleo Interdisciplinar de Estudos e Extensão em Cuidados à Saúde da Família em Convibilidade com Doenças Crônicas – NIEFAM, da Universidade Estadual do Sudoeste da Bahia, campus de Jequié. Trata-se de um relato de experiência desenvolvido em 2009 por docente e graduandos do Curso de Enfermagem. A experiência possibilitou conhecer o sistema familiar e visualizar cada membro enquanto ser humano-subsistema de um sistema maior que é a família na interação com o meio dinâmico-social para sua capacidade de resiliência no enfrentamento das adversidades vivenciadas cotidianamente no processo de viver humano. O acompanhamento domiciliar prestado às famílias foi uma mais-valia na construção do conhecimento acerca da dinâmica familiar no processo de viver-adoecer-morrer contributivos para o alcance', 'https://revistas.uepg.br/index.php/conexao/article/view/3753', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35314a', 'O CAP VAI À ESCOLA: UMA EXPERIÊNCIA COM PROJETOS INTEGRADOS', 'Almeida, Roseane Soares; Melo, Marcelo Soares Tavares de; Rosa, Adriana Letícia Torres; Ximenes, Lavínia de Melo Silva', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Consolidar atividades desenvolvidas pelo Projeto de Extensão e Pesquisa “O CAp vai à escola”, a partir de ações interdisciplinares, tendo, como objetivo, contribuir com outras escolas e com experiências educacionais, das comunidades do entorno da Universidade Federal de Pernambuco, é nosso propósito. A proposta se desenvolveu a partir das ações de Projetos Integrados, com perspectiva de investigar as problemáticas da organização do trabalho pedagógico da escola e de outros espaços educativos; de trocar experiências do trato do conhecimento e das questões social e cultural que envolvem a ação educativa; de sistematizar ações crítico-superadoras dos problemas da sala de aula e da escola; sendo que as atividades de ensino, de pesquisa e de extensão foram desenvolvidas por uma equipe multidisciplinar, do Colégio de Aplicação e por licenciandos, de diversas áreas de conhecimento, da Universidade Federal de Pernambuco (UFPE). A experiência com Projetos integrados apontou possibilidades do tr', 'https://revistas.uepg.br/index.php/conexao/article/view/3766', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35314b', 'CONTRIBUIÇÕES DA DANÇA NO PROCESSO DE ENSINO APRENDIZAGEM DE JOVENS E ADULTOS', 'Romarco, Evanize Kelli Siviero; Rocha, Priscilla Alvarenga; Almeida, Tatiana de Oliveira; Cavalcanti, Clara Amorim', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este estudo surgiu de um projeto de extensão, realizado nos anos 2007 e 2008, juntamente com uma pesquisa de campo, com aplicações de aulas de Dança, a uma população de 35 alunos, entre jovens e adultos, frequentadores do NEAD – Núcleo de Educação de Jovens e Adultos, do Departamento de Educação, da Universidade Federal de Viçosa, Mina Gerais. A fim de revelar a importância da dança, na Educação dos Jovens e Adultos, propôs-se refletir sobre as contribuições que essa linguagem pode oferecer ao processo de aprendizagem dessa população. Ao término do projeto, verificou-se que, para os alunos participantes desse estudo, tiveram esclarecimentos e ampliação do conhecimento de uma linguagem que vai além do ato de dançar, fornecendo elementos que contribuem para a aprendizagem, em relação ao processo de alfabetização e ao de auto-afirmação dessa população.', 'https://revistas.uepg.br/index.php/conexao/article/view/3767', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35314c', 'EXTENSÃO UNIVERSITÁRIA E ARTICULAÇÃO DE SABERES: A PROPOSTA DO LALUPE – LABORATÓRIO LÚDICO PEDAGÓGICO', 'Pisacco, Nelba Maria Teixeira; Foltran, Elenice Parise; Júnior, Dierone César Foltran', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste artigo é apresentar algumas reflexões sobre o papel da extensão no ambiente universitário, pois os projetos de extensão constituem-se como espaço ideal, para desenvolver ações que articulem o papel da Universidade e o seu compromisso social. Objetivando estabelecer essa relação, está sendo desenvolvido o Projeto LALUPE: Laboratório Lúdico Pedagógico:espaço para a formação de professores. Este artigo apresenta o referido Projeto de Extensão que tem, por objetivo, formar professores, capazes de utilizarem o pensamento conceitual diante da realidade, permitindo intervenções sólidas e consistentes na comunidade. A metodologia de trabalho se apresenta como proposta inovadora, possuindo, como aporte teórico, a pesquisa-ação, na perspectiva de Engel (2000); ensino pela pesquisa, de Berger (2004); e a complexidade como princípio, Demo (2002). Os resultados iniciais são expressos pelo entusiasmo e pela participação dos corpos discente e docente, da Universidade Estadual de Pont', 'https://revistas.uepg.br/index.php/conexao/article/view/3768', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353153', 'O DESIGN NA ESCOLA PÚBLICA: INFORMAÇÕES SOBRE A PROFISSÃO', 'Monteiro, Milena Anunciada; Silva, Paulo Roberto; Santos, Gabriele Maria Silva dos; Araújo, Hélder Magno Figueira de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo pretende mostrar os resultados de uma experiência de extensão, e as reflexões sobre uma ação de treinamento de formação de jovens, realizadas em 3 escolas públicas,de distritos municipais, Gravatá, Pesqueira e Arcoverde, estado de Pernambuco; a prática pedagógica da teoria e prática, à luz de Paulo Freire. 45 jovens participaram da demanda de mão de obra das marcenarias e de suas peças de artesanato de móveis, que usam, em seus processos produtivos, madeira, tijolos. O objetivo do projeto é divulgar o curso de Design, da Universidade Federal de Pernambuco (UFPE), e o programa BIA (Bolsa de Incentivo Acadêmico) o projeto que incentiva financeiramente jovens estudantes que ingressam na universidade, demonstrando a importância de divulgar as características do curso e da profissão de designer, na escolha do jovem, ao se inscrever para o teste, para ingressar na universidade.', 'https://revistas.uepg.br/index.php/conexao/article/view/3784', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353156', 'PROJETO LOGOS: O CONHECIMENTO COMO  PREVENÇÃO ÀS DSTS E À GRAVIDEZ PRECOCE', 'Carpiné, Anelise; Dresch, Ana Cristina; Ribeiro, Mayara Capucho; Cintra, Fernanda Hernandes; Oliveira, João Victor Campos de; Pompeu, Camille Bresolin; Silva, Ibraim Flávio; Schreiner, Carlos Augusto;', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O crescente número de adolescentes grávidas involuntária e precocemente indica falta de conhecimento e despreparo no uso e na escolha do método contraceptivo adequado. Somando-se a isso, as doenças sexualmente transmissíveis são grandes problemas de saúde pública, atingindo grande parcela de indivíduos entre 13-18 anos. Segundo o Ministério da Saúde, acredita-se que 12 milhões de novos casos de doenças, sexualmente transmissíveis, ao ano, ocorram no Brasil, sendo 10%, entre os adolescentes. Considerando o crescente índice de DST e também de gravidez, na adolescência, desenvolvemos um programa, buscando informar aos alunos do Ensino Médio, da cidade de Cascavel, as atitudes de risco que favorecem o contágio com uma tou as informações errôneas expõem o adolescente a um comportamento de risco; assim, através desta atividade, pretendemos levar tais informações a, aproximadamente, 1100 adolescentes.', 'https://revistas.uepg.br/index.php/conexao/article/view/3787', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35315a', 'APOIO FAMILIAR AOS ADOLESCENTES EGRESSOS DO SISTEMA SÓCIO-EDUCATIVO DA REGIÃO DE PONTA GROSSA – PR', 'Moreira, Dircéia; Ribeiro, Marisa Marques; Lavoratti, Cleide; Schulz, Elisa Stroberg; Pacheco, Mauricio; Budny, Giovana; Bach, Fabiani Ramos; Angreves, Maiara Barbosa de; Krainski, Luiza Bittencourt; ', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta a experiência desenvolvida pelo Projeto de Extensão Universitária: Apoio familiar aos adolescentes egressos do sistema sócio-educativo da região de Ponta Grossa – PR, que integra o Programa Universidade Sem Fronteiras da Secretaria de Estado da Ciência, Tecnologia e Ensino Superior/SETI. Tem, por objetivos principais, promover a inclusão social dos adolescentes egressos, através da mobilização dos gestores das políticas públicas e da sociedade, a fim de propiciar condições para serem acolhidos e mantidos estes jovens no convívio familiar e no comunitário. Também visa resgatar e fortalecer os vínculos familiares, a partir de trabalho interdisciplinar e intersetorial que prima pelo atendimento em rede, por uma metodologia que, além do atendimento direto a adolescentes e a suas famílias, desenvolve um sistema de informação que identifica as políticas sociais municipais e os fatores de risco às condutas infracionais de adolescentes.', 'https://revistas.uepg.br/index.php/conexao/article/view/3799', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35315f', 'ALFABETIZACAO E LETRAMENTO - UMA POSSIBILIDADE DE INTERVENCAO', 'Mendes, Marjorie B. E.; Marinho, Hermínia R. B.; Antunes, Wladimir G. R.; Pinto, Camila Augusto; Dallarosa, Andréia Rodrigues Zoelner; Santos, Livair A. dos; Bonnet, Ketlin de C.; Sozim, Mirian Martin', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O Projeto Alfabetização e Letramento: uma proposta de intervenção nas séries iniciais, do Ensino Fundamental, vinculado ao Programa Universidade sem Fronteiras – SETI/PR e UEPG, constitui-se numa intervenção interdisciplinar, entre as áreas de Letras, de Pedagogia e de Educação Física, oferecendo subsídios teórico-metodológicos para a ação docente, envolvendo a participação de cinco acadêmicos, um egresso e três Professoras dos referidos cursos. A falta de compreensão e de entendimento das questões da língua em aspectos relacionados com oralidade e com escrita reflete-se na linguagem e interfere nela. O projeto propõe metodologia voltada para formar professores – oficinas temáticas como: organização e planejamento do espaço e tempo pedagógico; práticas avaliativas em ensino-aprendizagem; ludicidade: jogos didáticos, cooperativos, lúdicos e vivenciais; oralidade e escrita; produção textual; fatos fonéticos e fonológicos; variação lingüística. Pretende-se levantar dados em relação à prod', 'https://revistas.uepg.br/index.php/conexao/article/view/3807', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353160', 'FORMAÇÃO DE PROFESSORES: UMA EXPERIÊNCIA DE ENSINO E PESQUISA A PARTIR DA EXTENSÃO UNIVERSITÁRIA', 'Carvalho, Silvana Maura Batista de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Há urgência de investimentos na formação inicial e continuada de Professores, para construir um consistente suporte teórico-metodológico, baseado na unidade teoria-prática. Nesse sentido, nos cursos de licenciatura em História e em Geografia, na UEPG, as áreas de Prática de Ensino/Estágio Supervisionado, desenvolvem um projeto de extensão/pesquisa - FORMAÇÃO de professores e cidadania social: um trabalho pedagógico junto ao patrimônio histórico, aprovado pelo Programa Universidade Sem fronteiras, subprograma- “Apoio às licenciaturas” - SETI – PR ( jul/2007), articulando extensão - ação na educação básica com Ensino Superior e, nessa relação a pesquisa para sistematizar o conhecimento construído pelos sujeitos protagonistas do projeto, visando uma atuação na perspectiva de uma educação patrimonial, a partir da análise das realidades patrimoniais de cada região e sua aplicabilidade na educação básica, contribuindo para formar uma consciência preservacionista, referencial de identidade cu', 'https://revistas.uepg.br/index.php/conexao/article/view/3808', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353161', 'FILOSOFIA, PEDAGOGIA E SOCIOLOGIA A SERVIÇO DA CIDADANIA', 'de Campos, Névio; Vitkowski, José Rogério; Rodrigues, Marli de Fátima', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo visa apresentar à comunidade acadêmica o projeto “Filosofia, Pedagogia e Sociologia a Serviço da Cidadania”, inserido no Programa Universidade Sem Fronteiras e no Subprograma Apoio às Licenciaturas, da Secretaria de Estado da Ciência, Tecnologia e Ensino Superior. Este projeto objetiva estabelecer uma interlocução entre a comunidade acadêmica da Universidade Estadual de Ponta Grossa e a comunidade escolar do Colégio Estadual Francisco Neves Filho (localizado na zona urbana), e do Colégio Estadual Professor Argemiro L. de Lima (situado na zona rural), do Município de São João do Triunfo. Conta com a participação dos professores do Departamento de Educação, bem como de uma egressa e de acadêmicas do Curso de Pedagogia, do Campus Avançado de Palmeira, e ainda de um acadêmico do Curso de Licenciatura em Artes. O diálogo estabelecer-se-á sob a luz das áreas da Filosofia, da Pedagogia e da Sociologia, visando discutir o problema da cidadania, no século XXI, sob o prisma das quest', 'https://revistas.uepg.br/index.php/conexao/article/view/3809', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353163', 'PROJETO CRIAÇÃO CLUBES DE CIÊNCIAS', 'Brinatti, André Mauricio; Silva, Silvio Luiz Rutz da; Silva, Jeremias Borges da; Colman, Jordana; Passoni, Sabrina', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Recentemente o desenvolvimento da ciência e da tecnologia tem provocado mudanças drásticas na sociedade. Além disso, é crescente a preocupação com a falta de professores e com o baixo número de formandos nas áreas de Ciências. Este projeto se propõe a criar Clubes de Ciências a partir de escolas públicas de educação básica, nas cidades de Ipiranga, Teixeira Soares e Imbituva, Paraná. Os clubes funcionarão em contraturno, como ambiente não formal de ensino e aprendizagem em ciências. As atividades do Clube desenvolvemse com participação de alunos do ensino básico, orientados por acadêmicos de Licenciatura da UEPG, coordenados por professores do Departamento de Física. O primeiro está em implantação em Ipiranga, atingindo 10% dos alunos do turno matutino. Observa-se que o projeto vem preencher lacunas na formação de estudantes e de acadêmicos, além de atender aos anseios de suas curiosidades e provendo um acréscimo em seus saberes científicos.', 'https://revistas.uepg.br/index.php/conexao/article/view/3811', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353164', 'ECONOMIA SOLIDÁRIA NO CONTEXTO DA REFORMA AGRÁRIA: ESTUDOS SOBRE ASSENTAMENTOS', 'Novatski, Greice Kelly; Camargo, Daniel de Oliveira; Ribeiro Junior, Constantino; Miranda, Robson Rodrigo; dos Santos, Andrea Paula; Bordignon, Valdecir; Peyerl, Drielli; Soares, Isis Schmidt; Cunha, ', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto tem, como características e propósitos, trabalhar com dois Assentamentos Estrela e Iraci Salete Strozake, sitos no município de Ortigueira – Paraná. Pretende proporcionar, após diagnósticos, estudos e pesquisas, alternativos para resolver os problemas que os assentados enfrentam. O trabalho é desenvolvido em três linhas temáticas: administração e ciranda infantil no Assentamento Estrela e plantas medicinais em ambos os assentamentos. Oferece formações, oficinas e acompanhamento, no intuito de aprimorar a educação básica, a organização administrativa, a saúde e o trabalho dos envolvidos. Objetiva-se também garantir melhores perspectivas de qualidade de vida e de renda. Os resultados alcançados, até o momento, são positivos, ocorrendo aumento de renda e de oportunidade de trabalho e aperfeiçoamento na educação. Assim, a equipe trabalha para todas as propostas e soluções se concretizarem e beneficiarem os aspectos socioeconômicos dos Assentamentos.', 'https://revistas.uepg.br/index.php/conexao/article/view/3815', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353167', 'AVALIAÇÃO DAS CONDIÇÕES HIGIÊNICO-SANITÁRIAS EM ESTABELECIMENTOS DA AGRICULTURA FAMILIAR ENVOLVIDOS NA PECUÁRIA LEITEIRA DOS MUNICÍPIOS DE CASCAVEL E GUARANIAÇU/PR', 'Bulhões, Ronaldo; Iark, Amanda Karina; Torres, Eliziane Fregolin; Tavares, Juliana Almeida; Falconi, Fabiana André; Corrêa, Juliana Moço; Sosa, David Esteban Fariña; Fariña, Luciana Oliveira de; Tessa', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O mercado pecuarista está se tornando mais exigente com relação à qualidade do leite. A fase de ordenha constitui um dos pontos críticos e uma séria ameaça à qualidade do produto. A produção de leite, no Brasil, ocorre sob condições rudimentares por pequenos produtores, os quais, normalmente, não são assistidos por programas de práticas de higiene e de melhorias de produção. Nosso objetivo foi avaliar as condições higiênicosanitárias, em estabelecimentos da agricultura familiar, envolvidos na pecuária leiteira dos municípios de Cascavel e de Guaraniaçu – PR. Entre os meses de março e abril de 2008, foram aplicados check-lists relacionados à ordenha, à higienização, a sanidade do rebanho, entre outras. Os resultados mostraram a carência de informações relacionadas à produção de leite com qualidade. Isso mostra a necessidade e a aplicabilidade deste trabalho no sentido de melhorar as condições de trabalho dos agricultores familiares.', 'https://revistas.uepg.br/index.php/conexao/article/view/3818', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35316a', 'BENZEDURA: FAMÍLIA FERREIRA E A ARTE DE CURAR PELA FÉ', 'Menegotto, Carla Adriana; Carneiro, Cirlei Francisca Gomes', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'As atividades extensionistas realizadas através do projeto “Doença e cura” (CARNEIRO, 2000) permitiram presenciar as práticas de rituais de uma família de descendência africana, loca-lizada em Ponta Grossa, Castro e Piraí do Sul. As formas de curar junto à população foram observadas a partir do diálogo com as fontes escritas, orais e fotográficas. Ao final do século XX, vê-se ainda presente nos Campos Gerais do Paraná, a assistência terapêutica não especializada, cujas artes de cura estão fundamentadas nos ritos da espiritualidade. Em pleno Século XXI, na qualidade de “esculápios”, a família Ferreira é portadora do domínio de “curas milagrosas”: Joaquim é conhecido como benzedor e trata com ervas as mazelas das famílias; Zenilda cura enfermidades provocadas por “feitiçarias”; Maria Zeni, como vidente, direciona os seus pacientes. Assim, a partir de rituais afro-brasileiros, a família Ferreira trata do doente e, numa relação “sócio-religiosa”, cura o paciente pela fé.', 'https://revistas.uepg.br/index.php/conexao/article/view/3827', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35316b', 'BRINQUEDOTECA HOSPITALAR: DIREITO DAS CRIANÇAS E ADOLESCENTES HOSPITALIZADOS', 'Foltran, Elenice Parise; Paula, Ercília Maria Angeli Teixeira de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Quando uma criança sofre uma internação hospitalar existe uma série de alterações que são realizadas na sua rotina. Para assisti-la, é necessária uma atuação para diminuir os efeitos da doença e tratamento. Este artigo apresenta um Projeto de Extensão realizado na brinquedoteca de um hospital em Ponta Grossa/PR. O objetivo é humanizar a saúde e promover o lúdico. A metodologia do trabalho compreende atividades lúdicas, artísticas e de literatura infantil que são realizadas quatro vezes por semana no hospital e reuniões de planejamento e avaliação. A clientela atendida corresponde a idades variando de 0 a 14 anos de diferentes cidades do Paraná. Os resultados são expressos na modificação dos comportamentos, na preservação do acervo de brinquedos para que os mesmos sejam socializados para outros pacientes. Estes fatos demonstram que a brinquedoteca hospitalar tem sido um espaço de valorização da saúde, do brincar, da socialização e também da cidadania.', 'https://revistas.uepg.br/index.php/conexao/article/view/3828', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35316c', 'EDUCAÇÃO NÃO-FORMAL E ALFABETIZAÇÃO DE ADULTOS: UM RELATO DE EXPERIÊNCIA', 'Schafranski, Márcia Derbli', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente texto relata uma experiência educativa que vem sendo desenvolvida numa Organização Não Governamental da cidade de Ponta Grossa, estado do Paraná, que presta assistência a pessoas com neoplasia. Considerando que algumas dessas pessoas não tiveram condições de acesso ou de permanência no sistema regular de ensino, as ações extensionistas visam oportunizar-lhes a possibilidade de serem alfabetizadas, contribuindo, conseqüentemente, para a sua maior autonomia. O trabalho desenvolvido visa também propiciar aos acadêmicos do curso de Pedagogia a atuação na educação não-formal, tendo em vista a ampliação de sua formação profissional.', 'https://revistas.uepg.br/index.php/conexao/article/view/3829', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35316e', 'EXTENSÃO UNIVERSITÁRIA: PROMOVENDO A INTERAÇÃO DOS CURSOS DE ENGENHARIA DA UEPG COM O ENSINO MÉDIO', 'Modesto, Flávia Andrea; Ielo, Frederico Guilherme de Paula Ferreira; Krüger, José Adelino; Chinelatto, Adriana Scoton Antonio; Almeida, Mareci Mendes de; Vaz, Maria Salete Marcon Gomes; Foltran Junior', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo descreve as atividades de extensão universitária que serão desenvolvidas para promover a Interação dos Cursos de Engenharia da Universidade Estadual de Ponta Grossa com o Ensino Médio. O objetivo principal é despertar o interesse dos alunos do ensino médio em cursar Engenharia. As atividades estão agrupadas em duas etapas. Na primeira, a Universidade se apresenta aos professores e alunos do ensino médio, visando a motivação dos mesmos. E na segunda, os professores (do ensino médio e universitário) e alunos compartilham os conhecimentos dentro do ambiente universitário, estreitando o relacionamento entre as partes.', 'https://revistas.uepg.br/index.php/conexao/article/view/3831', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35316f', 'FORMAÇÃO CONTINUADA NO ENSINO MÉDIO', 'Baretta, Alcebiades Antonio; Gueretz, Juliano Santos; Polon, Sandra Aparecida Machado', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O artigo destaca resultados e perspectivas do curso de extensão realizado nos meses de junho a dezembro de 2006, no Colégio Estadual Agrícola Augusto Ribas - CAAR. O estudo abordou o mundo do trabalho, bem como a LDB. A metodologia consistiu em: seleção de textos, debates e produção de novos textos. Dos debates realizados, percebeu-se a necessidade da formação continuada, a importância do trabalho interdisciplinar e, também espaços e horários para efetivar esses estudos, visto que o curso ofertado realizou-se aos sábados. Concluiu-se que o curso contribuiu para aprofundar o entendimento sobre formação profissional, necessidade da continuidade dos estudos, uma melhor seleção de textos, que propiciem mais espaços para debate e propostas. A oferta do curso de extensão atendeu a uma das necessidades da formação de professores, bem como, contemplou além das questões destacadas, um dos objetivos da Universidade no que se refere à difusão de conhecimentos.', 'https://revistas.uepg.br/index.php/conexao/article/view/3832', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353170', 'FORMAÇÃO INICIAL E CONTINUADA DE PROFESSORES NAS ÁREAS DE LÍNGUA PORTUGUESA E LITERATURA INFANTIL: DESAFIOS DE UM PROJETO EXTENSIONISTA', 'Chagas, Róbison Benedito; Leal, Sandra do Rocio Ferreira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo tem por objetivo apresentar as ações desenvolvidas no projeto de extensão Construindo Saberes na Diversidade, no segundo semestre de 2005, e durante o ano letivo de 2006, nas áreas de Língua Portuguesa e Literatura Infantil, nas séries iniciais do Ensino Fundamental da Escola Municipal Agenoridas Stadler, em Ponta Grossa – PR. Esse projeto integrou professores e acadêmicos dos cursos de Letras, Pedagogia e Artes. Num primeiro momento, lançamos um olhar mais criterioso sobre a formação continuada dos professores que atuam na referida escola, oferecendo-lhes, a partir das necessidades externadas em uma sondagem inicial, um ciclo de estudos em serviço e nas dependências da UEPG. Num segundo momento, a atenção recaiu sobre as crianças da classe de 8 anos, do período da tarde, e sobre as crianças da classe de 8 e 9 anos, do período da manhã. Os resultados foram bastante significativos. Acadêmicos de Letras, partícipes do projeto, vivenciaram experiências teórico-práticas que con', 'https://revistas.uepg.br/index.php/conexao/article/view/3834', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353171', 'LEITURA: UMA FORMA DE ENRIQUECER A VIDA DE PORTADORES DE DEFORMIDADES FACIAIS', 'França, Nilcéia Albuquerque; Ferreira, Daniele Glaba; Silva, Kamila Batista da', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este projeto, único na região dos Campos Gerais, objetivou desenvolver a habilidade de ler e de interpretar textos verbais e não verbais e, principalmente desenvolver a habilidade da fala, das crianças e adolescentes, portadores de deformidades faciais, alunos de uma associação de voluntários, Associação Pontagrossense de Portadores de Deformidades Faciais (APPDF), Ponta Grossa. Constou de aulas de reforço de Língua Portuguesa aos alunos da associação, estudantes de 5ª a 8ª séries, ministradas, no contraturno, por acadêmicas do Curso de Letras da Universidade Estadual de Ponta Grossa, como estágio voluntário. Foi relevante, pois oportunizou aos alunos, desenvolvimento pleno, não só pessoal, como social, instrumentalizando- os no que tange às suas capacidades comunicativas e melhorando sua qualidade de vida. Destacamos também a importância de oportunizarmos aos acadêmicos, conhecer nossa realidade sócio-cultural-educacional, propiciando-lhes experiência pessoal e profissional, como alun', 'https://revistas.uepg.br/index.php/conexao/article/view/3835', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353179', 'CONHECIMENTO DO INDIVÍDUO OSTOMIZADO EM RELAÇÃO AO AUTOCUIDADO', 'Tosato, Sonia Ramos; Zimmermann, Marlene H.', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente artigo tem como objetivo divulgar resultados da pesquisa realizada no Pronto Socorro Municipal de Ponta Grossa - Paraná (Setor de Órteses e Próteses), que averiguou o conhecimento do individuo ostomizado em relação aos cuidados após alta hospitalar e as incidências de complicações relacionadas ao estoma. Trata-se de uma pesquisa qualitativa exploratória e de campo com contribuição de dados quantitativos, onde foi utilizada como técnica de coleta de dados a entrevista semi-estruturada. Participaram da pesquisa dez portadores de ostomia (colostomia/ileostomia) intestinal e os resultados mostraram que a maior parte dos pacientes teve dificuldades com o auto-cuidado por falta de orientação apropriada e/ou ajuda de um profissional capacitado para esta fase do tratamento.', 'https://revistas.uepg.br/index.php/conexao/article/view/3850', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35317f', 'QUALIDADE DA ÁGUA UTILIZADA PARA CONSUMO HUMANO NAS COMUNIDADES RURAIS DO DISTRITO DE ITAIACOCA – PR', 'Esmerino, Luis Antônio; Silva, Nelci Catarina Chiqueto; Kulchetscki, Luiz; Pereira, Lara Tschopoko Pedroso', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O distrito de Itaiacoca está situado nas proximidades de Ponta Grossa – Paraná - e apresenta características peculiares em relação ao abastecimento de água. Nascentes superficiais são abundantes, e a geografia da região permite a captação direta. Esta facilidade alia-se ao pouco conhecimento da população sobre as implicações do consumo de água sem tratamento. A avaliação da qualidade da água, para consumo humano, foi realizada por análises bacteriológicas e as informações sobre as condições gerais de saneamento na região do Estado foram obtidas por meio de entrevistas. Os resultados demonstraram a precariedade das condições de saneamento básico sendo que, na maioria dos domicílios avaliados, a água não atende aos padrões de potabilidade, preconizados pela legislação brasileira.', 'https://revistas.uepg.br/index.php/conexao/article/view/3862', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353182', 'AMPLIANDO A LEITURA E O CONHECIMENTO DE MUNDO COM A COMUNIDADE ESCOLAR: UM RELATO DE EXPERIÊNCIA', 'Camargo, Elizabet Tramontin Silveira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente projeto iniciou-se em 2004, no CAIC Reitor Álvaro Augusto Cunha Rocha, da Universidade Estadual de Ponta Grossa; surgindo da necessidade da efetivação da prática de leitura na escola. O projeto envolve toda a comunidade escolar: pais, professores, alunos e funcionários; é uma experiência que ultrapassa os muros da escola e as práticas tradicionais de sala de aula. O desenvolvimento desse projeto tem proporcionado atividades diversificadas: momento da biblioteca, clube de leitura, correio da amizade, painéis, o jornal “O Repórter na Escola”, leitura direcionada a pais e funcionários, roda de leitura de professores e roda de leitura de alunos. O mesmo objetiva proporcionar momentos de leitura, mobilizando toda a comunidade escolar, ampliando a leitura de mundo e os estimulando a serem leitoresprodutores de textos. Acredita-se que o leitor só pode constituirse mediante prática constante de leitura, a partir de um trabalho que se organize em torno da diversidade de textos que ci', 'https://revistas.uepg.br/index.php/conexao/article/view/3882', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353183', 'DESCRIÇÃO DE UMA EXPERIÊNCIA EM ECONOMIA FAMILIAR', 'Santos, Sônia; Monteiro, Rodrigo Marques; Saleh, Pascoalina Bailon de Oliveira; Saleh, Abdala Mohamed', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Neste artigo apresentamos uma descrição do desenvolvimento do projeto de Economia Familiar para os servidores da Universidade Estadual de Ponta Grossa (UEPG-PR). Este projeto visa auxiliar as famílias do ponto de vista financeiro, levando em conta conhecimentos matemático-financeiros, fatores pedagógicos e psico-sociais relacionados à família. Esta abordagem abrangente é possível ao se considerar alguns elementos fornecidos pela Terapia Familiar Breve e pela Gerência Financeira.', 'https://revistas.uepg.br/index.php/conexao/article/view/3883', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353184', 'DIFERENTES CONCEPÇÕES SOBRE A VELHICE E A VISÃO OTIMISTA DA UNIVERSIDADE ESTADUAL DE PONTA GROSSA', 'Oliveira, Flávia da Silva; Oliveira, Rita de Cássia da Silva', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente artigo apresenta reflexões sobre as diferentes concepções da velhice na sociedade e a necessidade de um redimensionamento do espaço social da terceira idade, tendo como principio norteador a Educação Permanente. Dessa maneira criou-se o projeto de extensão da Universidade Aberta para a Terceira Idade na Universidade Estadual de Ponta Grossa, visando a integração de gerações, atualização e aquisição de conhecimentos, possibilitando o resgate da dignidade, participação, exercício da cidadania e elevação da auto-estima dos idosos, contribuindo para a melhoria da qualidade de vida dessa faixa etária.', 'https://revistas.uepg.br/index.php/conexao/article/view/3884', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353186', 'FORMAÇÃO CONTÍNUA DE RECURSOS HUMANOS NA EDUCAÇÃO: UMA PROPOSTA COLETIVA NO CAIC REITOR ALVARO AUGUSTO CUNHA ROCHA', 'Brandalise, Mary Ângela Teixeira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto de extensão “Formação Contínua de Recursos Humanos na Educação: uma proposta coletiva no CAIC Reitor Alvaro Augusto Cunha Rocha”, é desenvolvido no CAIC/ UEPG. Seu maior objetivo é promover a integração entre os profissionais atuantes neste espaço educacional, redimensionando as propostas de formação e ao mesmo tempo pensando concretamente a gestão educacional através de seus sujeitos. O Projeto atende a quatro grupos distintos de profissionais da educação: professores de Educação Infantil e Ensino Fundamental (séries iniciais), com encontros semanais; professores do Ensino Fundamental (5.ª a 8.ª séries), com encontros mensais; grupo gestor, formado por pedagogas, por chefes de seção e por direção, com encontros quinzenais; e funcionários, com periodicidade variada. Este artigo apresenta os resultados obtidos no desenvolvimento do projeto no âmbito escolar, tanto para a formação contínua de recursos humanos na educação, como para as contribuições na melhoria da qualidade do p', 'https://revistas.uepg.br/index.php/conexao/article/view/3887', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353189', 'RESGATANDO AS BRINCADEIRAS INFANTIS NA ESCOLA', 'Favoreto, Iomara', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta um relato parcial do projeto de extensão “Resgatando as Brincadeiras Infantis na Escola”, desenvolvido no CAIC Reitor Álvaro Augusto Cunha Rocha em 2004, com alunos de quatro a dez anos de idade. Este projeto objetiva resgatar as brincadeiras infantis na escola, através de diferentes ações, tais como construção de brinquedos com sucatas, realização de teatro com fantoches, cantigas de roda, contação de histórias, entre outras. Nas atividades propostas com brinquedos, são significativas as contribuições para o desenvolvimento da criatividade, da afetividade, da desenvoltura e da interação social nas crianças, bem como o prazer e a alegria de brincar na escola.', 'https://revistas.uepg.br/index.php/conexao/article/view/3892', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ac', 'ESPANHOL NO CURSINHO POPULAR: CIDADANIA E FORMAÇÃO DE PROFESSORES', 'de Assis, Joziane Ferraz; da Silva, Everalda Ribeiro', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto “Espanhol no cursinho popular: cidadania e formação de professores” foi criado para suprir a lacuna encontrada no Cursinho Popular Paula Cândido (CPPC) que, até 2011, não oferecia aulas da disciplina Língua Espanhola. O CPPC surgiu em 2010 e, desde sua criação, oferece aulas semanais aos sábados na Escola Municipal Antônio Faustino Duarte em Paula Cândido/MG. O projeto teve por objetivos implantar o ensino de Língua Espanhola no CPPC e preparar os alunos para realizar o Exame Nacional do Ensino Médio e outros exames de seleção para ingresso no ensino superior. As aulas de Espanhol se baseiam em leitura e compreensão de textos, já que este é o modelo de avaliação do ENEM e, de acordo com a matriz de referência do Exame, o aluno deve utilizar a Língua Estrangeira como acesso a informações sobre outros grupos sociais.', 'https://revistas.uepg.br/index.php/conexao/article/view/4988', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531af', 'FLORICULTURA: A PRODUÇÃO DE FLORES COMO UMA NOVA ALTERNATIVA DE EMPREGO E RENDA PARA A COMUNIDADE DE BAGÉ-RS', 'Terra, Simone Braga; Züge, Deise Patrícia Portela de Oliveira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto de extensão universitária em questão propôs a realização de um curso teórico-prático na área de produção de flores e plantas ornamentais para a comunidade moradora do município de Bagé-RS, situada na Região da Campanha do Rio Grande do Sul, com o objetivo de evidenciar novas alternativas de emprego e renda na área de floricultura. O trabalho realizado serviu de base para evidenciar que o cultivo de flores e plantas ornamentais pode ser uma alternativa promissora de geração de renda para a comunidade que se sente excluída por não exercer as atividades tradicionais da Região da Campanha, como a pecuária de corte e a produção de arroz irrigado.', 'https://revistas.uepg.br/index.php/conexao/article/view/5014', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b1', 'PROJETO CONSULTA PUERPERAL DE ENFERMAGEM: AVALIANDO O APRENDIZADO ADQUIRIDO DE PUÉRPERAS SOBRE O PÓS-PARTO', 'Ravelli, Ana Paula Xavier; Madalozo, Fernanda', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Trata-se de pesquisa quantitativa, retrospectiva onde o objetivo do estudo foi identificar o aprendizado adquirido das mulheres sobre o pós-parto atendidas pelo projeto Consulta Puerperal de Enfermagem nos anos de 2009 e 2010 e caracterizar o perfil demográfico e obstétrico das mulheres atendidas pelo Projeto Consulta Puerperal de Enfermagem. Utilizou-se de questionário estruturado com 7 (sete) questões de verdadeiro ou falso, com questões arraigadas ao tema período pós-parto com 177 mulheres e a amostra foi não probabilística intencional onde a análise dos dados se deu em percentual de acertos, mediante frequência simples. Sendo assim, o estudo identificou o aprendizado de puérperas sobre o período pósparto, média de 87% de respostas certas, evidenciando a importância da educação em saúde no pósparto, visando a autonomia no cuidado materno e com o bebê.', 'https://revistas.uepg.br/index.php/conexao/article/view/5031', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b6', 'INTERVENÇÃO FISIOTERAPÊUTICA ASSOCIADA À PSICOMOTRICIDADE EM PORTADORES DE LESÃO MEDULAR', 'Santino, Thayla Amorin; Moreira, Cláudia Holanda; Tito, Thâmmara Lariane Henriques; Sousa, Hellen Louise Lino de; Barbosa, Valéria Ribeiro Nogueira; Melo, Emanuelle Silva de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A lesão medular (LM) é caracterizada por perda da função motora associada a alterações biopsicossociais. Portadores de LM necessitam de programas de reabilitação bem coordenado e especializado, envolvendo diversos profissionais da saúde, que forneçam as ferramentas necessárias para o desenvolvimento de um modo de vida com qualidade. Portanto, o profissional fisioterapeuta deve desenvolver habilidades específicas para atuar de forma ampla e eficaz sob o ponto de vista da saúde integral do paciente. Este estudo tem por objetivo relatar experiências vividas no Projeto de Extensão Psicomotricidade Aplicada a Lesados Medulares, realizado na Clínica Escola de Fisioterapia da Universidade Estadual da Paraíba. A intervenção é realizada através de recursos fisioterapêuticos aliados ao conceito de Psicomotricidade, observando os aspectos motores, afetivos e cognitivos, associados à musicoterapia e à dançaterapia, com o objetivo de reestabelecer a autoestima, promovendo bem estar e qualidade de v', 'https://revistas.uepg.br/index.php/conexao/article/view/5287', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b7', 'FRINGTUR: LÍNGUA INGLESA PARA PROFISSIONAIS DE TURISMO DA CIDADE DE NOVA FRIBURGO/RJ', 'Barroso Azevedo, Suzana de Carvalho; Nogueira, Mariana Rodrigues; Aquino, Wagner de Carvalho; Ramos, Isabelle; Spallanzani, Alessandra Mitie; Mouza, Kamila', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente artigo tem por objetivo detalhar a descrição de um projeto de extensão desenvolvido no CEFET/RJ – Campus Nova Friburgo. Esse projeto terá como propósito a capacitação em língua inglesa de profissionais ligados a diferentes setores do turismo na cidade de Nova Friburgo. Para tanto, serão apresentadas três subdivisões dispostas em fases. Inicialmente, empreenderemos uma pesquisa realizada por meio de entrevistas semiestruturadas sobre as necessidades dos profissionais supracitados ao interagirem, em inglês, com turistas estrangeiros. Baseados na análise dessas entrevistas, iniciaremos a segunda fase do projeto que compreenderá a elaboração de materiais didáticos específicos para cada grupo de profissionais entrevistados. A terceira fase consistirá na oferta de cursos de extensão gratuitos para cada grupo, com apoio do respectivo material didático. Pretendemos colaborar para a qualificação da mão de obra local, bem como estimular, nos profissionais beneficiados, o interesse em ', 'https://revistas.uepg.br/index.php/conexao/article/view/5289', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b9', 'GRUPO DE ESTUDOS DA TERCEIRA IDADE - GETI: UMA PROPOSTA DE INTEGRAÇÃO ENTRE EXTENSÃO, ENSINO E PESQUISA VOLTADOS À PESSOA IDOSA', 'Virtuoso, Janeisa Franck; Krug, Rodrigo de Rosso; Sandreschi, Paula Fabricio; Nepomuceno, Alice Sousa Noronha; Mazo, Giovana Zarpellon; Medeiros, Paulo Adão de; Naman, Maíra; Streit, Inês Amanda', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente estudo caracteriza-se por ser um relato de experiência que aborda o Grupo de Estudos de Terceira Idade – GETI – da Universidade do Estado de Santa Catarina – UDESC. O GETI desenvolve suas ações de extensão, ensino e pesquisa voltados ao idoso. O objetivo deste estudo é descrever as ações de promoção de saúde do GETI nas áreas de ensino, pesquisa e extensão e caracterizar o perfil dos idosos. O Grupo desenvolve, na extensão, projetos voltados às atividades educacionais, culturais, artísticas, de atividade física, de avaliação fisioterápica e apoio psicológico. No ensino, são realizados cursos de capacitação e orientação no trabalho gerontológico. Na pesquisa, o Laboratório de Gerontologia – LAGER – desenvolve estudos na área da atividade física, saúde, qualidade de vida e reabilitação. O GETI representa a UDESC em conselhos, fóruns e eventos acadêmico-científicos; integra a extensão ao ensino e à pesquisa, transformando projetos independentes em um programa interdisciplinar.', 'https://revistas.uepg.br/index.php/conexao/article/view/5291', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531be', 'AQUARELA DO CONHECIMENTO: AS AÇÕES DO CAMPUS UNIVERSITÁRIO DE CÁCERES-MT NAS ESCOLAS PÚBLICAS E PRIVADAS DO MUNICIPIO', 'Constantino, Graciela', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Neste artigo trata-se de uma ação inovadora e pioneira da primeira Gestão de Extensão do Campus Universitário de Cáceres-MT, proporcionando conhecimentos específicos aos integrantes da Escola, mediante metodologia qualitativa, utilizando-se o instrumento de Palestras e oficinas educativas de acordo com um levantamento de dados prévios realizados junto às visitas nas dezessete Escolas públicas e privadas do ensino fundamental e médio do município de Cáceres-MT. Objetivou a institucionalização da ação da Gestão de Extensão do Campus de Cáceres e obteve-se como resultados: o atendimento à demanda de promoção de conhecimento nas Escolas do Ensino Fundamental e Médio Público e Privado do município de Cáceres-MT, quanto às suas prioridades temáticas no ano letivo de 2012; a otimização de políticas estratégicas de promoção da UNEMAT de aproximação e parcerias com as escolas; supriu-se, por meio de temáticas especificas das áreas dos Cursos de Graduação da UNEMAT/ Campus de Cáceres-MT, as nece', 'https://revistas.uepg.br/index.php/conexao/article/view/5350', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c5', 'REPENSANDO VALORES NA FORMAÇÃO PROFISSIONAL: ALTERIDADE E ESTRATÉGIA EM UM PROJETO DE EXTENSÃO UNIVERSITÁRIA QUE ENVOLVE SEXUALIDADE NA JUVENTUDE E NA ADOLESCÊNCIA', 'Holzmann, Liza; Barreto, Adriano Albuquerque', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O trabalho que segue é uma reflexão em torno da atuação dos acadêmicos do curso de Serviço Social da Universidade Estadual de Ponta Grossa em um projeto de extensão chamado Plugados na Prevenção. O projeto Plugados na Prevenção tem por objetivo discutir sobre sexualidade na juventude e adolescência, buscando informar sobre prevenção, transmissão, tratamentos, sinais e sintomas das DST/AIDS. Busca ainda desenvolver atividades educativas sobre sexualidade humana tendo por objetivo estimular a reflexão dos jovens e dos adolescentes sobre as relações sociais que envolvem a sexualidade, especificamente as relações familiares, relações com amigos, relações com as mídias e demais instituições sociais. A problemática exposta neste artigo procura aproximar o leitor dos impasses enfrentados pelos acadêmicos, futuros profissionais que precisam ponderar sobre valores pessoais e atuação profissional. Veremos como a atividade extensionista proporciona um bom espaço de mediação entre contexto de vivê', 'https://revistas.uepg.br/index.php/conexao/article/view/5541', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c9', 'PROJETO DE EXTENSÃO CRESCER SORRINDO: INTEGRANDO ENSINO, PESQUISA E EXTENSÃO EM ODONTOLOGIA POR 12 ANOS', 'Santos, Ana Paula Pires dos; Pentagna, Marialice Barroso; Oliveira, Branca Heloísa; Barja-Fidalgo, Fernanda; de Marsillac, Mirian de Waele Souchois', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A saúde das crianças pode ser afetada por diversos problemas bucais, tais como cárie dentária, oclusopatias e traumatismos dentários. Esses problemas podem ter efeito negativo sobre as suas vidas e sobre as de suas famílias Esse relato descreve o projeto “Crescer Sorrindo”, que é desenvolvido pela Faculdade de Odontologia da UERJ (FOUERJ), na Policlínica Piquet Carneiro (PPC), desde 2001. O projeto objetiva promover a saúde bucal de crianças de até 12 anos de idade incompletos através de ações de caráter educativo, preventivo e curativo e tem ênfase nos cuidados odontológicos a pré-escolares. Além do atendimento à população, o projeto promove a formação e a atualização profissional na área de Odontopediatria e desenvolve pesquisas científicas no campo da saúde bucal infantil. Assim, o projeto “Crescer Sorrindo” tem promovido, ao longo de 12 anos, a integração entre o ensino, a pesquisa e a extensão em prol da melhoria da saúde bucal infantil.', 'https://revistas.uepg.br/index.php/conexao/article/view/5621', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531cf', 'FORMAÇÃO INICIAL E CONTINUADA DO PROFESSOR PEDAGOGO: UMA EXPERIÊNCIA EXTENSIONISTA DA UNIVERSIDADE ESTADUAL DE LONDRINA', 'Delgado Paschoal, Jaqueline; Furlan de Oliveira, Marta Regina; Lupion Moreno, Gilmara', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho tem o propósito de relatar as ações desenvolvidas na primeira etapa do Projeto de Ensino e Extensão intitulado “Formação inicial e continuada do professor de educação infantil: a contribuição da Universidade Estadual de Londrina”. O objetivo foi demonstrar a importância dos conteúdos relacionados à educação na primeira infância, na formação inicial dos acadêmicos do Curso de Pedagogia da UEL, e promover a nossa capacitação como professoras formadoras do curso em questão. A metodologia desenvolveu-se por meio de grupo de estudos e aplicação de questionário aos alunos, a fim de conhecer o que estes pensam sobre a organização do trabalho pedagógico da educação infantil na formação inicial. Os resultados da pesquisa apontam que há o reconhecimento por parte dos alunos sobre a importância da educação infantil na formação inicial. Enquanto formadoras, tivemos a oportunidade de reavaliar nossa própria atuação, no sentido de confirmar a teoria e a prática como elementos indissoci', 'https://revistas.uepg.br/index.php/conexao/article/view/6235', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d0', 'EDUCAÇÃO EM MOVIMENTO: ESCOLA E UNIVERSIDADE INTEGRADAS PELA QUALIDADE DA EDUCAÇÃO BÁSICA NO CENTRO-SUL DO PARANÁ', 'Crisostimo, Ana Lucia; Vilas Boas Gomes, Marquiana de Freitas; Queiroga, Marcos Roberto', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo analisa o projeto multidisciplinar “Educação em Movimento: Escola e Universidade Integradas pela qualidade da Educação Básica no Centro-Sul do Paraná”, realizado no período 2011 e 2012 na Universidade Estadual do Centro-Oeste do Paraná, Unicentro. A proposta objetivou criar espaços de diálogo entre a universidade e a Educação Básica, no sentido de promover a produção do conhecimento científico a partir de formação inicial e continuada de professores, bem como desenvolver atividades que impulsionassem a valorização da criatividade, senso crítico, comprometimento social e ambiental. Os registros do processo formativo estão organizados no formato de livros, cartilhas e relatórios sistematizados pelos participantes do projeto. Os resultados destas ações implicaram na implementação de novas metodologias de ensino, construção do conhecimento e, sobretudo, buscou a autonomia do professor da Educação Básica. O projeto foi articulado em três cursos de Graduação que coordenaram as aç', 'https://revistas.uepg.br/index.php/conexao/article/view/6237', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d1', 'O PAPEL DA LIGA ACADÊMICA DE URGÊNCIAS E EMERGÊNCIAS CIRÚRGICAS NA FORMAÇÃO MÉDICA', 'Camargo, Carlos Henrique Ferreira; Przybycien, Michella; Trentini, Conrado Auer; de Freitas Júnior, Joâo Remi Remí', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Há uma significativa dificuldade no atendimento de urgências e emergências nos hospitais públicos, devido à desorganização do sistema de atendimento e ao despreparo dos profissionais recém-formados. Buscando divergir dessa realidade, foi idealizada a Liga de Urgências e Emergências Cirúrgicas da Universidade Estadual de Ponta Grossa. Os benefícios acadêmicos de tal projeto, como visualizar a aplicabilidade do conhecimento teórico, fortalecer os aspectos éticos da relação médico–paciente, exercitar o raciocínio clínico, adquirir habilidades clínico-cirúrgicas, desenvolver um espírito crítico, são relevantes para a formação médica. Os acadêmicos de medicina realizam plantões em duplas que duram entre sete e dez horas,no acompanhamento da equipe de cirurgia geral do HMAP, e são orientados na realização de cirurgia ambulatorial. No centro cirúrgico eles têm a possibilidade de se paramentar, instrumentar e  auxiliar em cirurgias. Considerando a experiência adquirida pelos acadêmicos e a red', 'https://revistas.uepg.br/index.php/conexao/article/view/6240', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d2', 'CURSO DE EXTENSÃO: POSSIBILIDADES DE FORMAÇÃO DE PROFESSORES NA CONTEMPORANEIDADE', 'Ferreira, Ingride de Carvalho; Silva, Patrícia Freire; Ferreira, Lúcia Gracia; Nascimento Ferraz, Rita de Cássia Souza; Mares de Souza, Francine Alves', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Atualmente, vimos emergir uma nova era - a contemporaneidade. Nela, percebemos inconsistências e mudanças muito rápidas. Nessa perspectiva, foi realizado na Universidade Estadual do Sudoeste da Bahia/ Campus de Itapetinga, um projeto de extensão, em formato de curso, buscando discutir estas questões. Assim, o curso foi realizado com duração de seis meses e buscou possibilitar debates, discussões e reflexões sobre a formação de professores frente ao desafio da contemporaneidade. Ao final do curso, foi solicitado que os cursistas respondessem ao questionário que foram devolvidos por 52 participantes. Essa avaliação mostrou que o curso possibilitou mudanças no modo de pensar e agir dos participantes, sendo avaliado como positivo; que as histórias de aprendiz, escrita e oral, promoveu um efeito formador. Ainda que a formação docente deva ser repensada para atender as demandas de uma sociedade contemporânea que reflete as incertezas da modernidade.', 'https://revistas.uepg.br/index.php/conexao/article/view/6242', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d4', 'PROJETO FORMA ENGENHARIA: VIVENCIANDO ENGENHARIA QUIMICA', 'Rodrigues, Sabrina Avila; Duarte, Elis Regina; Mendes, Daiane', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho tem como objetivo apresentar o projeto “Forma Engenharia: Vivenciando Engenharia Química”, realizado na Universidade Tecnológica Federal do Paraná,Campus Ponta Grossa (UTFPR), no período de dezembro de 2012 a fevereiro de 2014. Esta vivencia buscou estimular os alunos envolvidos a conhecerem e desenvolverem atividades na área de engenharia na prática. Como recursos inovadores, foram inseridas dinâmicas, estudo de caso, ensaios laboratoriais, maquetes, simulações e visita técnica.  Desta forma, os alunos do curso Técnico em Agroindústria puderam conhecer o curso de Engenharia Química e interagir com alunos de graduação. Para fechamento do projeto e divulgação entre os dois cursos envolvidos foi realizada uma exposição oral e uma gincana. Conclui-se que os alunos possuíam uma visão equivocada sobre o Curso de Engenharia Química e após as atividades do projeto alguns até se sentiram motivados a cursar. Além disto, como foram abordadas várias formas de aprendizagem, o conheci', 'https://revistas.uepg.br/index.php/conexao/article/view/6274', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d7', 'A ORGANIZAÇÃO E A PRODUÇÃO AGROINDUSTRIAL EXTRATIVISTA NA FRONTEIRA BRASIL–BOLÍVIA, NA REGIÃO SUDOESTE DE MATO GROSSO', 'Mendes, Maurício Ferreira; Silva, Marcela de Almeida; Neves, Sandra Mara Alves da Silva; Neves, Ronaldo José; Seabra Junior, Santino', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo teve como escopo apresentar a organização e a produção agroindustrial gerada pelos grupos sociais Amigas do Cerrado, Amigas da Fronteira e As Margaridas, situados nos municípios de Cáceres e Mirassol D’Oeste, na região sudoeste mato-grossense, fronteira Brasil – Bolívia, na perspectiva de contribuir no estabelecimento de estratégias nas outras comunidades dos demais 20 municípios que integram a região contemplada pelo projeto de extensão, favorecendo assim a segurança alimentar e geração de renda. O delineamento utilizado para a realização deste trabalho foi o estudo de caso, com método descritivo, operacionalizado através de: pesquisa bibliográfica, trabalhos de campo com realização de entrevista semiestruturada, sistematização das informações, aplicação de estatística descritiva, análise e discussão pautada na literatura, redação de texto informativo, para serem distribuídos nos encontros com as comunidades dos assentamentos localizados na região sudoeste mato-grossense. ', 'https://revistas.uepg.br/index.php/conexao/article/view/6321', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531dc', 'LABORATORIO CULTURAL – UNA EXPERIENCIA CRÍTICA EN LA FRONTERA', 'Amato, Laura Janaina Dias; Acuña, Catalina Isabel Britez', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Laboratorio Cultural tuvo como objetivo principal trabajar diversos temas relacionados al contexto social actual de las personas, como: educación, medios de comunicación y noción de desarrollo. Estos temas son abordados a través de dos metodologías específicas: la OSDE – Open Spaces for Dialogue and Enquiry (Espacios Abiertos para el Diálogo y Cuestionamiento) y TOE- Trough Other Eyes (Ver el mundo a través de otros ojos), de manera a que con la aplicación de estas metodologías se pueda trabajar con acciones que permitan obtener un abordaje y una mirada más crítica frente a las situaciones a lo “nuevo” y/o “diferente”.', 'https://revistas.uepg.br/index.php/conexao/article/view/6716', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531e1', 'AÇÃO EXTENSIONISTA PARA FORTALECER A IMPORTÂNCIA ALIMENTAR E AMBIENTAL DOS FRUTOS DO CERRADO EM RIO PARANAÍBA (MG)', 'Fernandes, Regiane Victória de Barros; Botrel, Diego Alvarenga; Arruda, Henrique Silvano; Almeida, Martha Elisa Ferreira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Várias espécies frutíferas do cerrado constituem fontes potenciais de exploração alimentar (ricos em nutrientes benéficos à saúde), mas ainda são pouco conhecidas ou apreciadas. Além disso, a reduzida extensão protegida pela lei, acrescida dos avanços da fronteira agrícola torna este bioma o mais ameaçado no país. Assim, este estudo propôs o desenvolvimento de ações em educação nutricional e ambiental, visando formar cidadãos esclarecidos com relação aos benefícios de uma alimentação saudável e utilização sustentável dos recursos presentes no cerrado. Neste contexto, atuamos como educadores, expondo temas relevantes em saúde e meio ambiente, através de palestras que atingiram elevado grau de aproveitamento pelos alunos. Desta forma, acreditamos que o conhecimento adquirido pelas crianças será disseminado para outras crianças, familiares e outros de seu convívio, contribuindo para a formação de uma sociedade mais consciente acerca da situação do meio ambiente onde estão inseridos e dos ', 'https://revistas.uepg.br/index.php/conexao/article/view/6744', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d0a32da1a94b353263', 'FORMAÇÃO DOCENTE PARA AS FEIRAS DE MATEMÁTICA: ATIVIDADES DE UM PROJETO DE EXTENSÃO', 'Siewert, Katia Hardt; Guttschow, Gisele Gutstein; de Melo, Marilândes Mól Ribeiro', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/10355', NULL, 'English', 'published', false, false, 'open', 'pdf')
