INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d0a32da1a94b353275', 'FISSURA LÁBIO-PALATINA: ALIANDO A EXTENSÃO, O ENSINO E A PESQUISA', 'Freitas, Jordana da Silva; Barbosa, Lisiane De Rosa; Pacheco, Raiane de Moraes; Trindade, Jennifer Alvares; Aguiar, Pamela Pacheco; Mazzotti, Karina; Prates, Renata Pereira; Menzen, Liliane; Maahs, Ma', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/10996', NULL, 'English', 'published', false, false, 'open', 'pdf')
