INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d1a32da1a94b3532bd', 'TECNOLOGIAS E CONHECIMENTOS - PESSOAS E PROTAGONISMOS: UMA PROPOSTA DE PROJETO DE EXTENSÃO', 'Carbonera, Silvana Maria; Jesus, Andreia de; Kutzke, Alexander Robert; Ferreira, Izabel do Rocio Costa', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste artigo é descrever a proposta do projeto de extensão universitária “Construindo Saberes com o Uso de Tecnologia”, do Setor de Educação Profissional e Tecnológica, da Universidade Federal do Paraná. Sua finalidade principal é promover o uso da tecnologia em processos educativos, no ambiente escolar, para enfrentamento e supervisão de vulnerabilidades. A metodologia se apresenta nos seguintes passos: 1) Divulgação das atividades do projeto; 2) Formação dos Acadêmicos (bolsistas/voluntários); 3) Execução das atividades na escola; 4) Análise das avaliações das atividades e sistematização de materiais; 5) Eventos. Espera-se atingir a Inclusão Sociodigital dos atores sociais da escola pública da região de Curitiba, pois, não basta apenas ter acesso às tecnologias digitais e ser alfabetizado digitalmente, é preciso também desenvolver habilidades e competências com relação ao uso dessas tecnologias e conhecimento para utilizá-las com segurança, ética e autonomia, tornando-se a', 'https://revistas.uepg.br/index.php/conexao/article/view/13580', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d1a32da1a94b3532bf', 'PROJETO HORTA NO PROGRAMA UNIVERSIDADE ABERTA PARA A TERCEIRA IDADE DA UNIVERSIDADE ESTADUAL DE PONTA GROSSA', 'da Silva Oliveira, Rita de Cássia; Scortegagna, Paola Andressa; Scortegagna, Pâmela Vanessa', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O aumento da população idosa reflete numa maior preocupação em relação às perspectivas e condições de vida destes sujeitos. Esta pesquisa qualitativa objetivou: conhecer os hábitos dos idosos do consumo de plantas medicinais e temperos; identificar a fonte dos conhecimentos acerca das propriedades das plantas mais utilizadas pelo grupo; refletir sobre a melhoria na qualidade de vida do idoso por meio do cultivo de uma horta. Realizou-se aplicação de dois questionários, em momentos distintos, para 33 alunos da UATI – UEPG. Parte dos alunos relataram ter uma vida saudável, consumindo alimentos e remédios naturais. Os alunos relataram conhecer as atividades do projeto e o consideraram importante para a comunidade. O desenvolvimento de uma horta com o idoso contribui com sua interação social e possibilita a diversificação de atividades.É necessário o aperfeiçoamento do projeto, bem como a conscientização e inclusão do idoso nas atividades, visando contribuir com sua qualidade de vida.', 'https://revistas.uepg.br/index.php/conexao/article/view/13639', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d1a32da1a94b3532c3', 'PLANEJAMENTO REPRODUTIVO: UM RELATO DE EXPERIÊNCIA MULTIDISCIPLINAR', 'Carlotto, Kharen; Gutmann, Victoria Leslyê Rocha; dos Santos, Daniela; da Fonseca, Tania Maria de Morais Vieira; Kerber, Nalú Pereira da Costa', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Objetiva-se descrever o trabalho multidisciplinar desenvolvido no serviço de Planejamento Reprodutivo do Hospital Universitário Dr. Miguel Riet Corrêa Jr., que busca auxiliar as mulheres na escolha de um método anticoncepcional. Trata-se de um relato de experiência constituído das seguintes etapas: grupo de planejamento familiar, atendimento com as assistentes sociais, consulta médica e procedimentos ambulatoriais ou cirúrgicos, envolvendo uma equipe multiprofissional (docentes, discentes e profissionais da saúde) composta por integrantes da enfermagem, medicina, assistência social e técnicos administrativos. Em todas essas etapas, a educação e a promoção da saúde se fazem presentes, de modo a instigar a reflexão e empoderar as pessoas assistidas por meio da informação para a escolha de um método anticoncepcional.', 'https://revistas.uepg.br/index.php/conexao/article/view/13676', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d1a32da1a94b3532f3', 'INFÂNCIA E EDUCAÇÃO AMBIENTAL: CONSTRUINDO AS TRILHAS DO BRINCAR CONSCIENTE', 'Queiroz Furtado, Valéria; Furlan de Oliveira, Marta Regina', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/16814', NULL, 'English', 'published', false, false, 'open', 'pdf')
