INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353347', 'CIDADANIA E EDUCAÇÃO: AÇÕES EXTENSIONISTAS NA DEFESA À POPULAÇÃO MIGRANTE E REFUGIADA', 'Kruger, Daniele Marcondes; Machado, Paula Rodrigues; Manosso, Alline Caroline; Souza, Bruna Suellen de Camargo de; Krainski, Luiza Bittencourt', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Resumo:&nbsp;&nbsp;O presente artigo é fruto das reflexões e práticas realizadas junto ao projeto de extensão Internacionalização, Cidadania e Direitos Humanos: do intercâmbio às migrações internacionais contemporâneas – InterMig. O trabalho contempla reflexões sobre as atividades desenvolvidas com os acadêmicos em mobilidade, migrantes e a comunidade externa. Em um panorama onde emergem questões relacionadas às migrações contemporâneas, sentiu-se necessária a atuação do projeto com um conjunto de ações que pudessem atender as demandas trazidas inicialmente pelos alunos na área socioassistencial e jurídica e, com migrantes e refugiados em conjunto com a rede de atendimento do Município. O estudo de natureza exploratória e descritiva tem a finalidade integrar conhecimentos teóricos e práticos, apresentando as ações desenvolvidas pelo projeto. Apesar dos avanços presentes nas legislações e direitos aos migrantes, há muito a avançar na estruturação da rede de acolhimento e em ações educat', 'https://revistas.uepg.br/index.php/conexao/article/view/20093', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35334b', 'AS CONTRIBUIÇÕES DA EXTENSÃO UNIVERSITÁRIA NA FORMAÇÃO DO BACHAREL EM ADMINISTRAÇÃO: UMA VISÃO A PARTIR DO ECOSSISTEMA EMPREENDEDOR', 'Martins, Steicy Lopes; Borba Vefago, Yuri; Francisco, Thiago Henrique Almino; Laurindo, Kevin Antunes', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A extensão universitária é um tema emergente no campo da pesquisa em gestão universitária, que vêm a superfície sobretudo a partir das contribuições do Plano Nacional da Educação. Neste contexto, este artigo objetiva analisar as contribuições da extensão universitária para o desenvolvimento de ações integradas entre estudantes de um curso de Administração e o ecossistema empreendedor. Em relação às contribuições teóricas, o artigo apresenta uma visão da literatura a respeito da extensão universitária, da relação entre a universidade-empresa e da identidade docente no ensino superior. Por meio de uma pesquisa de base qualitativa, desenvolvida a partir de uma entrevista semiestruturada com 20 participantes do projeto, os resultados demonstram que a extensão universitária aprimora competências aplicadas ao processo formativo e proporciona, entre outros aspectos, relações virtuosas entre a universidade e a sociedade. As conclusões destacam a contribuição da extensão e oportunidades teórico', 'https://revistas.uepg.br/index.php/conexao/article/view/20285', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35334e', 'USO DO INSTAGRAM PELO PROJETO  DE EXTENSÃO UNIVERSIDADE DA  CRIATIVA IDADE', 'Lisboa Sohn, Ana Paula; Ardigo, Carlos Marcelo; Soares Peixe, Thaynara', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/20307', NULL, 'English', 'published', false, false, 'open', 'pdf')
