INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353351', 'ESCOLAS DO CAMPO E COMUNIDADES DO LITORAL DO PARANÁ: PRIMEIRAS APROXIMAÇÕES', 'Meira de Moraes, Herika; Dias de Miranda Junior , Claudenir; Cristina Correia Alves, Michelle; Costa da Silva Ferreira, Vitória; de Souza Corrêa, João Guilherme; Carla Bernardo, Luana Carla Bernardo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/20631', NULL, 'English', 'published', false, false, 'open', 'pdf')
