INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353352', 'CORPOS QUE FALAM: COMUNICAÇÃO NÃO VERBAL EM CRIANÇAS PARTICIPANTES DE OFICINAS DE CIRCO', 'Kronbauer, Gláucia Andreza; Tyszka, Saara', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Objetivou-se descrever e analisar estratégias de comunicação não verbal de crianças participantes de oficinas de práticas corporais circenses, bem como discutir suas implicações relacionadas ao contexto educacional. Realizou-se através de entrevistas com roteiro semiestruturado e levantamento bibliográfico. A pesquisa contou com 6 participantes, os quais relataram suas experiências como monitores no projeto de extensão Circo em Contextos (UNICENTRO-PR), em seguida foi realizada a discussão com a literatura da área. Constatou-se que os corpos das crianças participantes se comunicam de maneira expressiva, são fortemente impactados e atravessados pela prática, seja pela característica provocadora, pelo corpo livre, pelo lúdico ou pela ação potencializadora da expressividade. Através do corpo expressam diversos signos da infância, descobrindo um mundo de possibilidades através do brincar circense. Além disso, evidenciou-se relações sociais democráticas dentro de um espaço de aprendizagem, ', 'https://revistas.uepg.br/index.php/conexao/article/view/20632', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353353', 'AÇÕES EXTENSIONISTAS REALIZADAS PELOS ALUNOS DO CURSO DE FISIOTERAPIA NO ATENDIMENTO E PROMOÇÃO DE SAÚDE AOS PACIENTES NEUROLÓGICOS E SEUS CUIDADORES DURANTE A PANDEMIA DE COVID-19', 'Pellizzari, Camila Costa de Araujo; Lucio, Maria Clara Fagundes; Valenciano, Paola Janeiro; da Silva, Joyce Karla Machado; Sambe, Angélica Yumi', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Objetivo: descrever a experiência da realização de ações extensionistas na reabilitação neurológica, prevenção de comorbidades e orientação ao paciente e cuidador/ familiar, durante a pandemia. Métodos: relato de experiência de um projeto de extensão de abril de 2020 à setembro de 2021, com a participação de pacientes atendido no SUS, pelo convênio CISNORPI/UENP, abrangendo 22 municípios vizinhos de Jacarezinho-PR e aproximadamente 14 discente e 4 docentes do curso de fisioterapia da UENP. Resultados: 145 publicações nas redes sociais do FisioLar, 349 seguidores no Instagram e 451 curtidas no facebook. Houve 18 pacientes atendidos no teleatendimento, totalizando 35 cartilhas e 20 sessões online, com 2 a 3 sessões por paciente e 4 pacientes no presencial. Conclusão: possibilitou assistência aos pacientes neurológicos da clínica de Fisioterapia da UENP, no teleatendimento, redes sociais e atendimento presencial, mantendo o quadro clínico geral, e possibilitando capacitação dos discentes ', 'https://revistas.uepg.br/index.php/conexao/article/view/20643', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
