VALUES ('674852d3a32da1a94b353355', 'TERRITÓRIOS, SABERES E PESQUISA: A INTERCONEXÃO COMUNIDADE-UNIVERSIDADE POR MEIO DA CURRICULARIZAÇÃO DA EXTENSÃO', 'Lupatini, Priscila Gonçalves; Chiapinoto, Mayara Luza; Vaniel, Ana Paula Härter; Favreto , Giovana; Lauxen, Ademar Antonio', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/20871', NULL, 'English', 'published', false, false, 'open', 'pdf')
