INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353357', 'PROMOVENDO EFICIÊNCIA NA SECAGEM DE GRÃOS DE MILHO: UMA ABORDAGEM EXTENSIONISTA PARA ANÁLISE DE CUSTOS NOS ESTADOS UNIDOS DA AMÉRICA E BRASIL', 'Zuin, Rafaela Maria Crivellari; Tocha, Brenda Gross; Beardmore, John; Gebieluca, Thauana; Garcia, Luiz Cláudio; Rickli, Jacob; Moraes, Daniela Mariana', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Dentre as atividades de extensão que a Universidade Estadual de Ponta Grossa (UEPG) oferece aos acadêmicos está o The Ohio Program, que dá suporte aos alunos que buscam a experiência internacional. No que se refere ao curso de Agronomia da instituição, na interação com agricultores de diferentes países, os extensionistas são desafiados na mais das vezes a sistematizar informações comparando o manejo de culturas em distintas regiões. Como consequência das atividades extensionistas, os agricultores elegeram como objetivo dos acadêmicos comparar o custo de secagem de grãos de milho (Zea mays) nos EUA e no Brasil. Para análise do sistema de secagem do milho nos Estados Unidos da América (EUA) escolheu-se a propriedade Frahm Farmland Inc., localizada na Cidade de Colby no estado do Kansas, (39°20’13.58”N 101° 8’20.00”O e altitude de 1.000 metros do nível do mar). Os dados de referência do Brasil foram baseados no valor médio investido na programação da unidade armazenadora da propriedade Fa', 'https://revistas.uepg.br/index.php/conexao/article/view/21053', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353358', 'ATENÇÃO E CUIDADO PARA MULHERES MÃES ACOMPANHANTES DE BEBÊS PREMATUROS: A ATUAÇÃO DO PROJETO DE EXTENSÃO “HUMANIZAÇÃO”', 'Thomazini Cardoso, Vanessa; Guisantes de Salvo Toni, Caroline; Dalcarobo Antochevicz, Mariana; Freitas Vieira, Cauynê; Ide Fujinaga, Cristina; Dos Santos Silva, Josiane', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21059', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35335b', 'PROGRAMAÇÃO COMPETITIVA EM UM PROJETO DE EXTENSÃO PARA O ENSINO TÉCNICO EM INFORMÁTICA', 'Piekarski, Ana Elisa Tozetto; Silva, João Vitor Pieczarka da; Militão, Eric Patrick; Rocha Junior, Alexandro Luis da; Miazaki, Mauro', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho descreve os treinamentos em programação de computadores para os alunos do curso Técnico em Informática, como atividades de extensão, realizadas no período de 2016 a 2022. Os treinamentos, destinados à preparação para a Olimpíada Brasileira de Informática (OBI), são oferecidos no âmbito do projeto “Treinamento em Lógica e Programação de Computadores para o Ensino Técnico” (TL&amp;PC), vinculado ao Departamento de Ciência da Computação (Decomp) da Universidade Estadual do Centro-Oeste (Unicentro), destinados aos alunos do Curso Técnico em Informática do Colégio Estadual Francisco Carneiro Martins (CEFCM), em Guarapuava, PR. O artigo apresenta um histórico das ações realizadas, os conceitos de programação competitiva, competições de programação e os ambientes de treinamento, descreve as atividades realizadas e apresenta os principais resultados desses sete anos de parceria.', 'https://revistas.uepg.br/index.php/conexao/article/view/21239', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35335c', 'RELATO DE EXPERIÊNCIA SOBRE A  ELABORAÇÃO DE UMA COLETÂNEA DE  LIVROS ORGANIZADA DURANTE O PERÍODO  DA PANDEMIA DE COVID-19 POR MEIO  DE UMA AÇÃO DE EXTENSÃO', 'Cortes Lacerda, Caroline; Frescura Flores, Laiane; Santos da Silva, Anelise; Rejane Trindade de Lima, Marta; Carneiro Disconci, Renilza', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho aborda uma ação promovida pelo Instituto Federal Farroupilha e tem o objetivo de relatar o desenvolvimento de um projeto de extensão que originou uma coletânea de livros acerca das experiências de ensino, pesquisa e extensão realizadas durante a pandemia, assim como mostrar a importância da extensão universitária e sua função articuladora com a comunidade. O enfoque registra os recursos utilizados para a realização da ação, as flexibilizações feitas pela Instituição durante o período e o resultado alcançado. Foram recebidos 54 textos, sendo 42 selecionados para publicação. Devido ao expressivo número de escritos, a versão final da coletânea foi composta por três volumes que retratam as experiências, adaptações e desafios enfrentados durante o período pandêmico em diversas instituições do País. O processo de divulgação, organização e publicação possibilitou reafirmar a importância da extensão universitária como um dos pilares fundamentais do conhecimento acadêmico e da fun', 'https://revistas.uepg.br/index.php/conexao/article/view/21297', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
