VALUES ('674852d3a32da1a94b353367', 'MANIFESTAÇÕES CULTURAIS DOS  ESTUDANTES GUINEENSES NA UNILAB: ANÁLISE DO PROJETO DE EXTENSÃO  ‘KABAZ DI TERRA’  DANÇAS E RITMOS  TRADICIONAIS DA GUINÉ-BISSAU', 'Delfino da Silva, Antonio Gislailson; Ocuni C´´a, Lourenço', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21710', NULL, 'English', 'published', false, false, 'open', 'pdf')
