VALUES ('674852d3a32da1a94b353371', 'FUTEBOL DE MULHERES E SAÚDE: PÉS QUE DEFENDEM E RESISTEM AOS IMPACTOS DA TRANSPOSIÇÃO DO SÃO FRANCISCO', 'Marques, Clarissa; Emilia de Barros Santos, Suely; Pereira Farias, Renata', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21887', NULL, 'English', 'published', false, false, 'open', 'pdf')
