INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353377', 'HISTOLOGIA INTERATIVA: UMA FERRAMENTA PARA O APRENDIZADO', 'Nascimento Guimarães Mattar, Victoria; Carvalho da Costa, Manuella; Cerruti, Raquel', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21991', NULL, 'English', 'published', false, false, 'open', 'pdf')
