INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353378', 'IMPORTÂNCIA DA EDUCAÇÃO ECONÔMICA PARA O FUTURO DAS CRIANÇAS E JOVENS', 'Vargas, Marcelo; Souza da Silva, Jéssica Letícia; Henrique, Franciele; Santos Rufato, Fernanda', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O conhecimento de economia deve fazer parte da cultura de uma sociedade bem informada. Através do projeto de extensão “A Economia Traduzida (TECA)” realizou-se um curso para os alunos do ensino fundamental II e médio. O objetivo do artigo foi analisar a importância do conhecimento de economia na vida dos discentes. Para isso, fez-se uma pesquisa bibliográfica referente a extensão universitária e educação econômica e um estudo de campo que procurou captar a característica da população investigada e a percepção dos alunos sobre educação econômica. As informações analisadas mostraram que 18,72% dos discentes estão inseridos no mercado de trabalho, 57,48% participam no planejamento financeiro familiar, 75,43% consideram fundamental aprender economia na escola e 73,39% acreditam que ter conhecimento de economia influenciará sua vida. Observa-se que seria relevante haver novos projetos de extensão que levem a educação econômica para as crianças e jovens, ou ainda, poderia inseri-la na grade ', 'https://revistas.uepg.br/index.php/conexao/article/view/21994', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b35337a', 'PAIETS: CAMINHOS DE UM PROGRAMA DE EXTENSÃO', 'Costa Claro, Lisiane; Avila Pereira, Roberta', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo do presente texto é registrar a trajetória do programa de extensão intitulado “Programa de Auxílio ao Ingressos nos Ensinos Técnico e Superior – PAIETS”, da Universidade Federal do Rio Grande – FURG. Utiliza-se a contribuição da abordagem hermenêutica como metodologia de análise do fenômeno destacado. O PAIETS atuou em cinco frentes: 1) Na promoção de cursos Pré-Universitários Populares (PUP) e preparatórios para Pós-Graduação; 2) No fortalecimento da Educação Básica para Jovens e Adultos, em comunidades tradicionais de pesca artesanal e na comunidade LGBT+; 3) Por meio do apoio à permanência de estudantes quilombolas e indígenas no ambiente acadêmico; 4) Na formação docente da rede pública para atender às necessidades da Educação de Jovens e Adultos (EJA); e 5) No diálogo intercultural com os imigrantes senegaleses no Rio Grande/RS. Reconhece-se a importância do Programa na luta por uma universidade mais justa e democrática e na construção de uma sociedade mais humana e igu', 'https://revistas.uepg.br/index.php/conexao/article/view/22051', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
