INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353395', 'O USO DO INSTAGRAM PARA A DEMOCRATIZAÇÃO DO ACESSO AO PATRIMÔNIO CULTURAL DA FACULDADE DE DIREITO DO RECIFE', 'Almeida, Maria Isabel Chicó de; Piraua, Isabela Cabral de Melo Dantas; Pereira, Andreina Aguiar; Carneiro Filho, Humberto João; Mesquita, Fábio Albert', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Neste artigo, objetivamos analisar o impacto da rede social Instagram nas ações de democratização do acesso ao patrimônio cultural desenvolvidas pelo Projeto Memória Acadêmica da Faculdade de Direito do Recife, ação de extensão vinculada à Universidade Federal de Pernambuco (UFPE). Por meio de um estudo de caso e da análise dos tipos de publicação realizadas na conta do projeto na rede social, procuramos averiguar em que medida o uso do Instagram auxilia as atividades do projeto no que diz respeito à promoção da interação dialógica com outros setores da sociedade. Como resultados, verificamos que, apesar de não substituir o papel central das interações presenciais, a rede social vem sendo uma importante ferramenta no cumprimento do objetivo central do projeto de contribuir com a política de preservação e acesso ao patrimônio cultural da Faculdade de Direito do Recife.
Palavras-chave: Rede social; Interação dialógica; Extensão universitária.', 'https://revistas.uepg.br/index.php/conexao/article/view/22513', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
