VALUES ('674852d4a32da1a94b3533a0', 'CONSTRUIR OU TRANSMITIR CONHECIMENTOS: UMA ANÁLISE DOS RELATOS DE EXTENSÃO UNIVERSITÁRIA A PARTIR DAS PUBLICAÇÕES EM PERIÓDICOS', 'de Mello Júnior, Wílson', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/23040', NULL, 'English', 'published', false, false, 'open', 'pdf')
