INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b3533aa', 'O CORPO FEMININO EM ADÉLIA PRADO: A PRODUÇÃO AUDIOVISUAL COMO ESTRATÉGIA PARA INCENTIVAR A LEITURA', 'Samuel Sanchotene, Carlos Renan', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O trabalho busca representar o caminho que o eu-lírico presente nas poesias de Adélia Prado segue para conseguir realizar-se por meio dos corpos femininos. A interface entre literatura e audiovisual ajuda a desvelar os dois caminhos propostos entre o divino e o profano, o sagrado e o devasso, frequentemente encontrados nos poemas da escritora mineira. Trata-se de um trabalho que é resultado do projeto de extensão “O corpo feminino nos poemas de Adélia Prado”, realizado em 2023, na Universidade do Estado de Minas Gerais – Divinópolis. Assim, produziu-se uma série de três produções audiovisuais para o Youtube. A metodologia compreende a produção de roteiros audiovisuais (Rodrigues, 2010), a partir de três poemas do livro Terra de Santa Cruz (Prado, 2006), sendo eles: Casamento, Festa do corpo de Deus e Sagração. Acredita-se que o audiovisual aliado à literatura é um instrumento que potencializa e incentiva o ato da leitura.
Palavras-chave:  Corpo feminino; Audiovisual; Literatura; Youtub', 'https://revistas.uepg.br/index.php/conexao/article/view/23377', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
