INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926010', 'O EMPREGO DAS MÍDIAS DIGITAIS NA DIVULGAÇÃO CIENTÍFICA DO NÚCLEO DE PESQUISA EM EDUCAÇÃO E CIBERCULTURA DO INSTITUTO FEDERAL DO PARÁ, CAMPUS BELÉM.', 'de Oliveira Alencar, Breno Rodrigo; Nonato de Souza, Abimael', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/25093', NULL, 'English', 'published', false, false, 'open', 'pdf')
