INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926011', 'CLUBES DE CIÊNCIAS COMO ESTRATÉGIA DE EXTENSÃO UNIVERSITÁRIA: O QUE NOS MOSTRAM OS ARTIGOS BRASILEIROS?', 'Lopes Romero, Adriano', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Os clubes de ciências revelam-se como estratégias potentes para o desenvolvimento da extensão universitária, especialmente por sua capacidade de integrar ensino, pesquisa e divulgação científica em espaços educacionais não formais. Nesse contexto, objetivou-se realizar, no presente artigo, uma revisão sistemática da literatura com o intuito de responder à seguinte pergunta: O que nos mostram os artigos produzidos no contexto brasileiro sobre clubes de ciências como estratégia de extensão universitária? Para tanto, analisaram-se 18 artigos científicos produzidos no contexto brasileiro, coletados no Portal de Periódicos da CAPES. A análise do corpus textual resultou em sete categorias emergentes: 1. Contexto institucional e parcerias; 2. Metodologia pedagógica e abordagem didática; 3. Objetivos educacionais e finalidades sociais; 4. Participantes e público-alvo; 5. Espaço-tempo e formato das atividades; 6. Avaliação e impactos da ação extensionista; 7. Desafios e perspectivas futuras. Co', 'https://revistas.uepg.br/index.php/conexao/article/view/25100', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('691dacbe49e41686f7926015', 'EDUCAÇÃO AMBIENTAL E AGROECOLOGIA NA EDUCAÇÃO BÁSICA: PERCEPÇÕES DE ESTUDANTES DO 7º ANO EM RIO VERDE (GO)', 'Batista Teixeira, Marconi; Santos Felis, Grazielly; Aparecida Josefi da Silva, Elizabeth; Oliveira Souza, Amanda; Alves Morais , Wilker; Campos Pimentel, Fernando', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta resultados de um projeto de extensão vinculado ao curso de Doutorado em Ciências Agrárias, que investigou o uso de minidocumentários como prática pedagógica para promover a Educação Ambiental e a Agroecologia em turmas do 7º ano de uma escola pública de Rio Verde – GO. A pesquisa qualitativa articulou exibição de vídeos, rodas de conversa e análise do Documento Curricular do Estado de Goiás, visando relacionar os conteúdos à realidade local. Os resultados apontam que os recursos audiovisuais ampliaram o interesse dos estudantes por temas como sustentabilidade, preservação ambiental e práticas agrícolas mais responsáveis. Contudo, identificaram-se desafios, como a carência de formação continuada para professores e de materiais didáticos adequados. Conclui-se que a integração entre ensino, extensão e metodologias ativas favorece o protagonismo discente, fortalece o currículo e contribui para a formação de cidadãos críticos e comprometidos com o meio ambiente.
Palavr', 'https://revistas.uepg.br/index.php/conexao/article/view/25287', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792ee', 'POPULARIZAÇÃO DA CIÊNCIA NO SEMIÁRIDO: A EXPERIÊNCIA DA NOITE INTERNACIONAL DE OBSERVAÇÃO DA LUA EM MUNICÍPIOS DO INTERIOR DO RIO GRANDE DO NORTE E DO CEARÁ', 'de Amorim Oliveira, Marcelo; de Medeiros, Subênia Karine; de Oliveira Gurgel Rebouças, Gustavo; da Costa e Silva, Jusciane', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/25036', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792f0', 'AVALIAÇÃO DA EXTENSÃO UNIVERSITÁRIA CURRICULARIZADA: CONSTRUÇÃO DE INSTRUMENTO DE CONFORMIDADE COM BASE EM DIRETRIZES NORMATIVAS E INSTITUCIONAIS', 'Carvalho Silva, Márcia Gabriele; Bolwerk, Aloísio', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A curricularização da extensão, regulamentada pela Resolução CNE/CES nº 7/2018, consolida a concepção da extensão universitária como função pontencializadora na formação dos estudantes e na capacidade de intervir em benefício da sociedade. Contudo, para que o propósito de transformação social seja efetivamente alcançado, as atividades extensionistas devem ser orientadas pelos princípios e diretrizes estabelecidos na referida resolução. Neste contexto, este trabalho apresenta um breve histórico normativo da avaliação da extensão no Brasil, destacando os marcos instituídos pelo FORPROEX e pela Política Nacional de Extensão. A partir da análise documental de marcos legais e institucionais, especialmente no contexto da Universidade Federal do Tocantins (UFT), o estudo propõe uma matriz avaliativa de aderência dos projetos de extensão às diretrizes estabelecidas pela Resolução CNE/CES nº 7/2018 e pelos documentos normativos da Universidade. Conclui-se que a institucionalização da avaliação ', 'https://revistas.uepg.br/index.php/conexao/article/view/25286', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acdcbd789e57df2cb1ab', 'ENTRE PESQUISA E EXTENSÃO: A COMPREENSÃO DA GEOGRAFIA HISTÓRICA NO DESENVOLVIMENTO DO VALE DO RIBEIRA PARANAENSE', 'Ornat, Marcio Jose; Gmach, Andriéli', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/25144', NULL, 'English', 'published', false, false, 'open', 'pdf')
