INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e02b', 'A EXTENSÃO NA CONCEPÇÃO DOS DOCENTES DA ÁREA RURAL DA UFPEL: CONTRIBUIÇÕES DE UMA ANÁLISE', 'Rodrigues, Marcio; Caldas, Nádia; Wociechoski, Darlan', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O objetivo deste estudo foi analisar as concepções de extensão dos professores da Universidade Federal de Pelotas (UFPel) ligados à área rural, tomando como apoio as categorias funcional (ou tradicional), processual e crítica, descritas por Silva (2001). Buscou-se também discutir a necessidade de um reposicionamento epistemológico nas práticas universitárias para efetivação da concepção crítica. Assim, foi realizado um estudo qualitativo in loco que contou com coleta de dados por meio de entrevistas semiestruturadas com onze professores da UFPel, as quais foram submetidas à análise interpretativo-descritiva. Os resultados indicam uma prevalência da concepção processual de extensão na UFPel. Ao final, enaltecemos a necessidade de promoção de metodologias dialógico-participativas para efetivação do comprometimento das atividades de ensino e pesquisa com a realidade social comunitária, a fim de promover uma identidade universitária nacional.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e02b', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e02d', 'A REPRODUÇÃO SOCIAL DE AGRICULTORES FAMILIARES NO SUDOESTE DO PARANÁ: UMA ANÁLISE DAS CARACTERÍSTICAS SOCIOECONÔMICAS', 'Schervinski Villwock, Ana Paula; Dos Santos Roncato, Patricia Eveline; Verardi Fialho, Marco Antonio', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A crescente orientação das práticas sociais para o mercado fez com que a reprodução social dos agricultores familiares fosse alterada. Sabendo que na agricultura moderna a reprodução social da agricultura familiar se consolida pela capacidade de adaptação aos novos contextos sociais, questiona-se sobre quais seriam as características socioeconômicas dos agricultores familiares do Sudoeste do Paraná? Para tanto, procurou-se analisar as estratégias de reprodução social baseada em três indicadores: terra, capital e trabalho. Como resultado, identificou-se que as unidades produtivas possuem como principais estratégias de produção o leite com manejo de pastagens e a produção de soja, e que os mesmos são eficientes para reprodução social das famílias em termos de renda, mas que precisam de força de trabalho, área de terra e investimento em tecnologias.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e02d', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e02e', 'A INCUBADORA TECNOLÓGICA DE COOPERATIVAS POPULARES DA UNIVERSIDADE DO PLANALTO CATARINENSE E A INCUBAÇÃO DA COOPERATIVA DE TRABALHO DOS CATADORES DE MATERIAIS RECICLÁVEIS DO MUNICÍPIO DE LAGES, SC', 'Farias, Sueli; Melo, João Eduardo; Locks, Geraldo', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O objetivo deste texto é refletir sobre a Incubadora Tecnológica de Cooperativas Populares da Universidade do Planalto Catarinense (ITCP UNIPLAC) e o processo de incubação da Cooperativa de Trabalho de Catadores de Materiais Recicláveis do Município de Lages, SC (COOPERLAGES). Descreve-se o contexto de emergência do movimento social da economia solidária, a institucionalização da incubadora, enfatizando sua aproximação com o universo dos catadores por meio de ações de incubação da cooperativa e o enfrentamento de desafios na gestão interna e na coleta seletiva. Neste processo pedagógico, são destacadas a formação dos catadores, organização, constituição da cooperativa e assinatura do primeiro contrato de prestação de serviço da coleta seletiva de materiais recicláveis entre a cooperativa e a Prefeitura Municipal de Lages, para o período de março de 2015 a março de 2016. A reflexão evidencia o papel da Incubadora no processo de incubação da cooperativa, orientada por princípios e valore', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e02e', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e02f', 'A SEMANA DE ENSINO, EXTENSÃO, PESQUISA E INOVAÇÃO: CAMINHOS PARA A DIVULGAÇÃO CIENTÍFICA NA PERSPECTIVA DO DESENVOLVIMENTO TERRITORIAL SUSTENTÁVEL', 'Signorelli, Marcos; Covolan, Nadia; Carvalho, Evelyn', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A Semana de Ensino, Extensão, Pesquisa e Inovação - SEME²PI do Instituto Federal do Paraná (IFPR), campus Paranaguá, é um evento expressivo de divulgação científica regional. Investiga-se aqui como a divulgação científica reflete os pressupostos do Desenvolvimento Territorial Sustentável (DTS), mediante os trabalhos de origem extensionista apresentados neste evento em 2015. Trata-se de uma pesquisa em base de dados que utilizou a metodologia de análise de conteúdo. Os resultados apontaram para o desenvolvimento local voltado para o fortalecimento da cultura endógena, saberes populares, empoderamento feminino e de comunidades tradicionais. Conclui-se que o IFPR vem desenvolvendo a divulgação científica através da SEME²PI, cujos destaques referem-se às ações extensionistas articuladas com o DTS. Argumenta-se, todavia, sobre limites para a ampliação, implementação e permanência dessas junto às comunidades envolvidas.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e02f', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e033', 'ATENDIMENTO NUTRICIONAL AMBULATORIAL: AVALIAÇÃO ANTROPOMÉTRICA E DO CONSUMO ALIMENTAR DE UNIVERSITÁRIOS', 'Nunes, Ludmila; Bresan, Deise; Melo, Fernanda; Sanches, Priscila; Del Ré, Patricia', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O objetivo do estudo foi traçar o perfil antropométrico e do consumo alimentar de universitários. Trata-se de um estudo transversal a partir da coleta de dados secundários de prontuários entre 2014-2016, do projeto de extensão “Atendimento Nutricional Ambulatorial” de uma universidade pública, que visa a assistência nutricional de estudantes de graduação e pós-graduação. A avaliação antropométrica foi realizada por meio do índice de massa corporal, circunferência da cintura e gordura corporal. Para a avaliação do consumo alimentar, foi utilizado recordatório de 24 horas e análise de energia e nutrientes segundo as DRIs. Foram avaliados 145 prontuários, sendo 69,0% do sexo feminino, com média de idade em ambos os sexos de 22,5±4,4anos. Foram observadas inadequações na composição corporal e no consumo alimentar dos universitários. Dessa forma, intervenções no ambiente universitário com ações educativas e de estímulo às práticas alimentares saudáveis são fundamentais para a prevenção de d', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e033', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e035', 'DO NEDET À INCUBAÇÃO: TRAJETÓRIA DAS AÇÕES DE EXTENSÃO UNIVERSITÁRIA NO ÂMBITO DA ABORDAGEM TERRITORIAL DO DESENVOLVIMENTO', 'Fröehlich, José Marcos; David Vieira, Lucas; Zarnott, Alisson; Hübner, Jeniffer; Facco, Hector', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este trabalho objetiva efetuar um balanço crítico da trajetória de atuação extensionista do Núcleo de Extensão em Desenvolvimento Territorial Centro Serra (NEDET CS), no período 2014-2017. Os NEDETs foram criados através da Chamada Pública CNPq/MDA/SPM-PR Nº 11/2014 com o objetivo de estruturar equipes de assessoramento aos Colegiados de Desenvolvimento Territorial (CODETERs). Na Universidade Federal de Santa Maria, foi constituído o NEDET CS para atuação no Território Centro Serra do Rio Grande do Sul. Entre 2014 e 2017, foram desenvolvidas atividades voltadas à gestão social e inclusão produtiva. A análise das ações realizadas aponta que o NEDET deu organicidade e promoveu a participação social no CODETER, realizou 115 atividades e mobilizou a execução de 2,6 milhões de reais. Conclui-se, assim, que o NEDET teve um papel positivo na articulação e no desenvolvimento do Território CS, além de ser um espaço privilegiado de formação acadêmica através das ações de pesquisa e extensão dese', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e035', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e037', 'EDUCAÇÃO DE JOVENS E ADULTOS: ESCOLARIZAÇÃO EM ÁREAS DE REFORMA AGRÁRIA DO PARANÁ (ANOS INICIAIS) – RELATO DA EXPERIÊNCIA DE EXTENSÃO DA UNIOESTE', 'Ritter, Janete', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este artigo é o relato de experiência da Universidade Estadual do Oeste do Paraná, que, por meio de um projeto de extensão, intencionalizou levar escolarização em áreas da reforma agrária no estado do Paraná. O projeto objetivou organizar 60 turmas dos anos iniciais, do ensino fundamental, com o mínimo de 20 alunos cada, num total de 1.200 alunos, certificando aqueles que lograssem êxito e, concomitantemente a isto, realizar a formação da equipe pedagógica. A carga horária de ensino foi de 1.600 horas, distribuídas ao longo de dois anos e houve a movimentação de cerca de 3 milhões de reais. A matriz curricular adotada foi as áreas do conhecimento. Como resultado, podemos apontar a certificação de 370 jovens e adultos analfabetos, e de mais de outros 400 que aprenderam a ler e escrever.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e037', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e038', 'DOCE CUIDADO: SERVIÇO DE ATENDIMENTO FARMACÊUTICO E NUTRICIONAL A PACIENTES DIABÉTICOS EM UMA FARMÁCIA UNIVERSITÁRIA', 'Bittencourt, Flavio; Siqueira, Nadielle; Rascado, Ricardo; Siqueira, Caroline; Da Silva, Rosangela; Dias, Ana Carolina', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O Diabetes Mellitus (DM) está associado a danos em diversos órgãos, que comprometem a produtividade, qualidade de vida e a sobrevida. Falhas na farmacoterapia podem ser atribuídas a utilização inadequada dos medicamentos e aos fatores nutricionais. Parte de um programa de extensão vinculado ao Centro de Farmacovigilância, o objetivo deste estudo foi avaliar a farmacoterapia e os aspectos nutricionais de 23 pacientes, entre 50-89 anos, atendidos pelo serviço de atenção farmacêutica. Observamos que 39,13% apresentaram problemas relacionados à utilização dos medicamentos, sendo 31,81% não adesão medicamentosa, 4,54% medicamentos desnecessários e 4,54% dose inadequada. Encontramos excesso de peso em 56,52% dos pacientes acompanhados, com média de IMC de 27,5 ± 3,6 Kg/m². Após orientação nutricional, observamos melhora nos níveis glicêmicos de 52,17% pacientes. Este estudo evidencia a importância do acompanhamento farmacêutico/nutricional para o paciente diabético e que o simples fornecimen', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e038', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e03a', 'HISTÓRIA DO CAFÉ AGROFLORESTAL: RELATOS DO CEJA BATURITÉ', 'Rufino, Maria do Socorro; Ribeiro, Sofia Regina', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O presente trabalho tem como objetivo apresentar o relato de experiência do Projeto “LeiturAção” CEJA Donaninha Arruda, em Baturité - Ceará, em parceria com o Mestrado Acadêmico em Sociobiodiversidade e Tecnologias Sustentáveis (MASTS), vinculado à Universidade da Integração Internacional da Lusofonia Afro-Brasileira, com o intuito de realizar oficinas temáticas com o corpo discente da EJA, contemplando o contexto histórico da cultura cafeeira com foco na educação ambiental. A atividade de extensão abrange o recorte temporal que compreende os meses de outubro e novembro de 2015. O arcabouço teórico que balizou as informações se respalda no estudo de vários autores, dentre eles: Freire, Girão, Martins, Gadotti. As atividades pedagógicas tiveram como base o tripé pesquisa, estudo e produção textual. Conclui-se que a iniciativa levou o educando a refletir sobre a relevância da cafeicultura para a região, bem como a necessidade de preservar o meio ambiente e desenvolver a ética ambiental.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e03a', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e03d', 'IMPACTO DE ACOMPANHAMENTO NUTRICIONAL NO ESTADO NUTRICIONAL DE CRIANÇAS DE UM CENTRO ESPECIALIZADO DE GUARAPUAVA - PR', 'Cavagnari, Mariana; Zanelatto, Carla; Melhem, Angélica; Saldan, Paula; Taques, Nilciane; Lacerda, Pâmela', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar se houve melhora no estado nutricional de crianças atendidas em um Centro Especializado de Guarapuava - PR após acompanhamento nutricional. O projeto foi conduzido com 35 crianças (idade média = 19,74 meses) frequentadoras do referido centro entre os anos de 2015 e 2017. Para avaliar o estado nutricional e antropométrico dessas crianças, foram analisadas as medidas de peso e estatura conforme preconiza o Ministério da Saúde. Para crianças com necessidades especiais, utilizaram-se curvas específicas. Foi possível observar que, nas consultas nutricionais de retorno, houve evolução de todos os quesitos avaliados, com destaque para a melhora do estado nutricional (77,14%) e do consumo alimentar (65,71%) no primeiro retorno. Evidencia-se, assim, a importância do acompanhamento nutricional na infância, sendo este um meio de intervenção precoce que favorece a qualidade de vida e a prevenção de novos problemas alimentares, com impacto sobre o bem-estar fís', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e03d', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e042', 'IMPACTOS DA MUDANÇA NO CÓDIGO FLORESTAL BRASILEIRO NO CONTEXTO DA AGRICULTURA DE BASE FAMILIAR', 'Rocha, Carlos; Okuyama, Kassio; Ribeiro, Diógenes; Weirich Neto, Pedro; Almeida, Dayana', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A assistência técnica e os serviços de extensão rural devem basear-se em iniciativas de desenvolvimento sustentável e, em teoria, a legislação ambiental deve ser o ponto de referência para o início da sustentabilidade agrícola._Nesse sentido, o Código Florestal de 1965 definiu parâmetros para a conservação da vegetação em propriedades rurais. De importância científica, esses valores foram significativamente reduzidos pela Lei 12.551 / 2012, que revogou o Código Florestal. Com o objetivo de subsidiar o Programa de Extensão para Desenvolvimento Rural Sustentável, desenvolvido pelo Laboratório de Mecanização Agrícola da UEPG, a mudança na legislação ambiental brasileira foi analisada através de pesquisas de 304 propriedades rurais familiares em dez municípios do estado do Paraná. Em nove municípios, a área de reserva legal excedeu a exigida pelo Código Floresstal. Por outro lado, a nova legislação tornou desnecessário a recuperação de 86,76 ha de áreas de preservação permanente exigidas p', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e042', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e043', 'MANEJO DA AGRICULTURA IRRIGADA: ORIENTAÇÕES TÉCNICAS AOS HORTICULTORES-FEIRANTES', 'Abreu, Laura; Santos, Gilmar; Cabral, Railaine; Carvalho, Regina; Thiesen, Amanda Cristina; Déa, Tayná Karine; Diniz, Raisa', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Na área da agricultura irrigada, há muitas pesquisas e informações disponíveis, porém muito frequentemente não chegam até os usuários da água, principalmente os de pequeno porte. Portanto, este projeto teve como finalidade prestar orientações técnicas aos horticultores-feirantes, no bairro Morada do Sol, no município de Rio Verde, Goiás, sobre o manejo da agricultura irrigada e qualificar os acadêmicos das Faculdades de Engenharia Ambiental e Agronomia e prepará-los para o mercado de trabalho. A partir das técnicas de manejo orientadas pelos acadêmicos, os horticultores conseguiram reduzir o consumo de água e energia elétrica, melhorar a eficiência de molhamento, aumentar a produtividade, prolongar a vida útil do sistema de irrigação e direcionar o uso da água com qualidade específica para a cultura indicada, o que justifica a relevância social e ambiental do projeto, além dos benefícios a sociedade e o ganho de conhecimento e interação entre os acadêmicos.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e043', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e049', 'POTENCIALIDADES E FRAGILIDADES DO PROGRAMA NACIONAL DE ALIMENTAÇÃO ESCOLAR − PNAE NO TERRITÓRIO CANTUQUIRIGUAÇU (PR)', 'Dos Santos, Cristina; Christoffoli, Pedro; Felippini, Marcia; Gregolin, Marcos; Ferrari Mateus, Milena', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este estudo registra o acompanhamento do "Núcleo de Extensão em Desenvolvimento Territorial – NEDET" ao Programa Nacional de Alimentação Escolar – PNAE no Território Cantuquiriguaçu, PR. Com o objetivo de elucidar a operacionalização do Programa, foram realizadas pesquisas em fontes oficiais do governo federal, coleta de dados quantitativos e qualitativos junto às secretarias municipais de educação do Território e entrevistas com atores-chaves (agricultores, nutricionistas, merendeiras, secretários municipais). Identificaram-se, em alguns municípios, dificuldades para se adquirir os 30% de produtos oriundos da Agricultura Familiar; contudo, em uma análise histórica, nota-se o aprimoramento gradativo na operacionalização desta compra. Conclui-se que a aceitação dos produtos da agricultura familiar é um ponto importante, porém, a falta de treinamento às merendeiras e de assistência técnica produtiva prejudicam a efetividade do Programa. Também se conclui que o pequeno número de agriculto', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e049', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e04c', 'OS CARBOIDRATOS NO COTIDIANO: TEORIA E PRÁTICA NO ENSINO DA BIOQUÍMICA PARA ALUNOS DO 9º ANO EM ESCOLAS DA REGIÃO DO BAIXO TOCANTINS-PA', 'Santos, Lourivaldo; Borges, Fábio; Santos, Natalino', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Vinculado ao projeto Atividades didático‐pedagógicas para a Bioquímica para o Ensino Fundamental, o presente artigo apresenta os resultados de uma ação extensionista, a fim de levar aulas práticas de bioquímica (ramo da ciência que estuda, especialmente, estruturas e funções das biomoléculas dos compostos orgânicos celulares) para o espaço das salas de aula do 9º Ano, de quatro escolas ribeirinhas da região do baixo Tocantins, no município de Cametá-PA. As aulas, que contaram com um público de 85 alunos, abordaram temas como a importância dos carboidratos e a identificação de biomoléculas em alimentos, por meio de uma metodologia que parte do uso de materiais alternativos presentes no dia a dia das comunidades, estabelecendo a relação entre teoria e prática, de forma a contribuir positivamente para o aprendizado dos alunos.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e04c', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e02c', 'ALFABETIZAÇÃO EM UMA ASSOCIAÇÃO DE RECICLADORES EM PONTA GROSSA: LIMITES E POSSIBILIDADES A PARTIR DA TRAJETÓRIA EDUCACIONAL DOS ASSOCIADOS', 'De Moura, Reidy; Sopko, Camila', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este trabalho tem como objetivo apresentar os dados sobre a experiência de alfabetização que aconteceu na Associação dos Recicladores Rei do “Pet” (ARREP), através da intervenção do programa de extensão “Incubadora de Empreendimentos Solidários” (IESol), da Universidade Estadual de Ponta Grossa (UEPG), que vem atuando junto ao grupo desde 2010. Os dados que serão apresentados resultaram de um Trabalho de Conclusão de Curso (TCC) da graduação em Serviço Social. Para este artigo, fez-se o recorte da trajetória educacional dos associados e a importância da alfabetização em suas vidas. Os dados foram obtidos a partir de entrevistas semiestruturadas com os participantes do programa de alfabetização viabilizado pela IESol. Os resultados mostraram diversas dificuldades que os(as) trabalhadores(as) tiveram em completar seus estudos. Dentre tantas, as que podemos enfatizar foram as questões de gênero que continuam permeando como limitadoras especialmente às mulheres associadas. Também ficou cla', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e02c', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e031', 'ASPECTOS SANITÁRIOS NA PRODUÇÃO DE CAPRINOS E OVINOS DE PRODUTORES FAMILIARES NO SEMIÁRIDO PARAIBANO', 'Santos, Daiane; Cruz, George; Lima, Aécio; Silva, André; Barros, José', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O objetivo deste estudo, através da atividade de extensão de discentes do programa de pós-graduação e graduação em Agroecologia da UFPB/CCHSA, foi caracterizar o perfil sanitário de rebanhos caprinos e ovinos de produtores familiares em regiões de clima semiárido do Estado da Paraíba. A avaliação dos aspectos sanitários foi realizado em 402 propriedades rurais, localizadas nos municípios de Serra Branca, Sumé, Amparo e São José dos Cordeiros. Foram utilizadas metodologias participativas, tais como questionário semiestruturado, entrevista com os proprietários rurais e caminhadas nos locais de criação dos animais. Foram verificadas propriedades em que a verminose, clostridiose e diarreia são as principais enfermidades que acometem os rebanhos, sendo 57,67, 25,13, 15,87%, respectivamente. A vermifugação é a prática mais utilizada no manejo. O manejo sanitário é realizado com pouca inovação tecnológica e técnicas deficientes, necessitando de assistência técnica e extensão rural para a ampl', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e031', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e03c', 'ESTUDO DAS ALTERNATIVAS PARA A MELHORIA DO EMPREENDIMENTO FEMININO: DOCES E CONSERVAS FRUTOS DO VALE - DOI: 10.5212/Rev.Conexao.v.12.i2.0009', 'Souza, Pércia; França, Raimundo; Seabra Júnior, Santino; Sanini, Cristina; Queiroz, Tadeu; Lima, Aparecida de Fátima; Butnariu, Alessandra; Carvalho, Amanda', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'O estudo buscou identificar as dificuldades enfrentadas nas etapas do agro-processamento e comercialização dos produtos do empreendimento feminino Doces e Conservas Frutos do Vale, da Comunidade Vale do Sol II, em Tangará da Serra-MT, e desta forma, propor alternativas passíveis de aplicação à realidade local. O papel da mulher na agricultura familiar vem ganhando destaque, devido à criação de grupos femininos que desempenham atividades alternativas, com o intuito de aumentar a renda familiar. Mas, observa-se ainda inúmeras dificuldades que envolvem o preconceito de gênero, acesso à infraestrutura adequada e inserção dos produtos ao mercado. Diante desse contexto, foi possível sugerir alternativas aplicáveis em curto prazo para auxiliar as integrantes do empreendimento, como a criação de um cardápio sazonal, inserção de novas linhas produtivas, reaproveitamento de resíduos das matérias-primas, acondicionamento dos produtos, ferramentas de comercialização e controle financeiro.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e03c', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e03e', 'JARDIM ECOLÓGICO: O PAISAGISMO COMO ESTRATÉGIA DE SENSIBILIZAÇÃO AMBIENTAL', 'Da Silveira Júnior, Júlio; Ruppenthal, Raquel; Coutinho, Cadidja', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A gestão sustentável dos resíduos constitui um dos princípios da Educação Ambiental, pautada na formação de atitudes e comportamentos ecologicamente orientados. Nesta perspectiva, o presente trabalho, vinculado ao projeto “Mobilização Universitária, Todos contra o Aedes e à Favor do Meio Ambiente”, de uma universidade de Santiago/RS, propôs a utilização de Jardins Ecológicos como ferramenta multiplicadora de informações sobre sustentabilidade, com o intuito de sensibilizar e estimular a participação da comunidade escolar na proteção ao meio ambiente e na redução dos focos para o desenvolvimento do Aedes aegypti no município. A metodologia consistiu em propiciar aos alunos do ensino fundamental (5º ao 9º ano) de escolas públicas municipais uma capacitação acerca das questões ambientais, através de oficinas teóricas/práticas, com a elaboração de jardins com materiais destinados ao descarte. Durante a realização da atividade, observou-se o interesse dos alunos e do corpo docente, e o cará', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e03e', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e044', 'MULHERES QUILOMBOLAS E SUAS EXPERIÊNCIAS DE ORGANIZAÇÃO - SÍTIO SANTANA, LAMARÃO/BA', 'Batista Dias, Acácia; Ferreira de Oliveira, Ildes; Carmo dos Santos, Vitoria', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Este artigo versa sobre as experiências de organização de mulheres pertencentes a uma comunidade quilombola, no município de Lamarão/BA, e está vinculado ao projeto de extensão “Ser Tão Forte: Desenvolvimento Territorial Sustentável”, na formação de Núcleos de Extensão em Desenvolvimento Territorial (NEDET), desenvolvido na Universidade Estadual de Feira de Santana/BA. A análise contempla questões referentes às relações de gênero, meio rural e raça/etnia, através de estudo qualitativo, o qual utilizou entrevistas semiestruturadas e visita técnica para outro município, com o intuito de promover a troca de saberes na produção do artesanato. As entrevistadas fazem parte da Associação Comunitária de Artesãs da Comunidade Remanescente de Quilombos do Sítio Santana, na qual produzem utensílios em cerâmicas. O artesanato constitui uma prática antiga na comunidade, transmitida por gerações e com predomínio feminino na atividade. Representa, assim, a manutenção da tradição/cultura, da identidad', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e044', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e045', 'MODELO DE PROGRAMA DE CONTROL DE PARASITOSIS INTESTINALES Y NUTRICIÓN EN ESCOLARES DE ARGENTINA: INTEGRANDO DOCENCIA, EXTENSIÓN E INVESTIGACIÓN', 'Pezzani, Betina; Rosa, Diana; Larrain, Marina; Ciarmela, Maria; Anabitarte, Josefina; Orden, Alicia; Mariñelarena, Alejandro; Minvielle, Marta', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Presentamos un modelo de Programa que integra actividades de docencia, extensión e investigación, desarrollado en la Facultad de Ciencias Médicas de la Universidad Nacional de La Plata, Argentina denominado PROCOPIN (Programa de Control de las Parasitosis Intestinales y Nutrición). Este modelo de programa refleja la unión entre la institución universitaria, los profesionales de la salud pública regional y los directivos de establecimientos escolares para lograr el control de las infecciones parasitarias intestinales y mejorar las condiciones nutricionales de niños en condiciones de vulnerabilidad social. Con un significativo valor formativo para los estudiantes de nuestra facultad, integrando contextos y contenidos curriculares, articulando lógicas institucionales diversas, incentivando el trabajo en equipo y adquiriendo una mirada crítica sobre problemáticas socio-sanitarias.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e045', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e046', 'LEVANTAMENTO NA ÁREA RURAL DOS CAMPOS GERAIS (PR) SOBRE O IMPACTO DO MANEJO OUTONO/INVERNO NA PROLIFERAÇÃO DA DOENÇA DE PLANTAS MOFO-BRANCO', 'Miranda, Eduardo; Calderari, Natali; Gomes, Jaime; Neves, Gabriela; Garcia, Luiz; Charnobay, Aghata; Farias, Anderson; Melo, Maghnom; Mendes, Jefferson; Bernardi, Wania', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'No plantio direto pode-se optar por deixar a área em pousio no outono/inverno ou realizar controle dos organismos indesejados. O objetivo foi mensurar o impacto do manejo outono/inverno sobre a proliferação da doença fúngica de plantas mofo-branco (Sclerotinia sclerotiorum), em conjunto com agricultores da região dos Campos Gerais (PR). Os dados foram obtidos por meio de ação desenvolvida junto ao Programa de Extensão Laboratório de Mecanização Agrícola (LAMA) da Universidade Estadual de Ponta Grossa (UEPG), que implementa na região dos Campos Gerais (PR) atividades extensionistas, permitindo a interação entre agricultores da região e a UEPG. O delineamento experimental utilizado foi em blocos aleatorizados, com 2 tratamentos e 16 repetições. Os tratamentos consistiram em áreas sem e com manejo outono/inverno, avaliando-se o número de plantas de nabo-bravo (Raphanus raphanistrum), escleródios e apotécios por metro quadrado. Escolheu-se o nabo-bravo por ser a principal planta hospedeira', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e046', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e047', 'PERFIL EPIDEMIOLÓGICO DAS PARASITOSES INTESTINAIS E AVALIAÇÃO DOS FATORES DE RISCO EM INDIVÍDUOS RESIDENTES EM UM ASSENTAMENTO RURAL DO NORDESTE BRASILEIRO – DOI: 10.5212/Rev.Conexao.v.12.i1.0002', 'Amorim, Ana Clara; Trindade, Reginaldo; Souza, Aline; Cruz, Marília; Borges, Edésio; Alves, Fernanda; Guimarães, Hildeanna; Melo, Ana Carolina; Santos, Bárbara', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'Enteroparasitosis commonly affect individuals under poor conditions of housing and sanitation. This study aimed at describing the epidemiological profile of enteroparasitosis in residents of a rural settlement, evaluating their risk factors. The study is part of the outreach project “Multidisciplinary University Action for Sustainable Development of the Cajueiro settlement in the city of Parnaíba/PI”. Parasitological analyses were performed in 49 fecal samples from individual above 13 years old. The prevalence of parasites was 73%, being 58% for monoparasitism and 83% of protozoa. In cases of biparasitism (33%), helminths corresponded to 57% and associations protozoa/helminths to 53%. The prevalence of parasitosis increased as age increased. Although not statistically associated, risk factors such as consuming food from streetmarket and reports of diarrhea showed some influence on the prevalence. It was possible to conclude that there is a high prevalence of enteroparasitoses affecting', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e047', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e048', 'PROJETO DE ENSINO DA CONSTRUÇÃO DE UMA MINICISTERNA COM MATERIAIS REUTILIZÁVEIS', 'Castro, Evanize; Boso, Ana Cláudia; Gabriel, Camila; Gabriel Filho, Luis Roberto; Batista, Cristina; Ferrari, Jéssica Maiara', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A necessidade hídrica vem aumentando com o passar dos anos, influenciada pelo aumento demográfico e econômico, poluição e o uso irregular dos recursos hídricos. Uma solução eficiente para minimizar esse desequilíbrio socioambiental é o uso da cisterna pelo fato de manter estrutura simples, facilidade no acesso e o aproveitamento dos recursos pluviais. Desta forma, o objetivo deste trabalho foi elaborar, construir e ensinar a comunidade local sobre a construção e instalação de uma minicisterna para fins não potáveis, produzida com materiais recicláveis, proposta por discentes do projeto de extensão Laboratório de Avaliação e Construção de Equipamentos com Materiais Reutilizáveis (LAMAR). O projeto alcançou satisfação dos participantes nos quesitos avaliados, em que foi considerada possível a construção da minicisterna.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e048', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b3d96fdec8b71b6e04b', 'SIMPÓSIO DE INTERCULTURALIDADE E A DIVERSIDADE CULTURAL INDÍGENA: CONTRIBUINDO COM AS AÇÕES AFIRMATIVAS', 'Sebastiani, Renata; Bozzini, Isabela; Calzolari Neto, Anselmo', 'FAO/AGRIS', 'Agriculture', 'Agriculture', 'A necessidade de reconhecer a diversidade da comunidade estudantil e de ações para a acolhida e permanência dos estudantes indígenas na Universidade Federal de São Carlos culminou no I Simpósio de Interculturalidade, atividade de extensão realizada em maio de 2015. Os objetivos a serem alcançados com a descrição desta atividade foram compartilhar as experiências do evento, destacar a atuação dos estudantes indígenas e não indígenas durante sua organização e relatar seus desdobramentos para a comunidade universitária. Como principais resultados, destacam-se a divulgação sobre o tema escolhido, a relação da universidade com a sociedade, a integração entre os estudantes indígenas e não indígenas, o estabelecimento de um Núcleo de Estudos Indígenas e o início do Ciclo de Ações e Luta Indígena. O evento fortaleceu as atuais ações de Políticas de Ações Afirmativas da UFSCar enquanto instrumento de promoção da diversidade no ambiente universitário.', 'https://agris.fao.org/search/en/records/64745b3d96fdec8b71b6e04b', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353130', 'DANÇA NA EDUCAÇÃO INFANTIL: DESVELANDO A ARTE E A LUDICIDADE NO CORPO', 'Teixeira, Guilherme Fraga da Rocha; Oliveira, Leticia T.; Bastos, Fernanda R. N.; Vieira, Alba Pedreira; Fialho, Aline D.; Vieira, Nara C.', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/3715', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353142', 'A ALFABETIZAÇÃO CIENTÍFICA E TECNOLÓGICA E O APROVEITAMENTO DA ENERGIA SOLAR: MEIO AMBIENTE, SOCIEDADE E SUSTENTABILIDADE', 'Jacobs, Andresa Liriane; Facin, Paulo Cesar', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O curso de extensão teve como meta contribuir para uma concepção alternativa à exploração industrial dos recursos naturais. Partiu-se de uma visão ampliada de alfabetização científica e tecnológica (ACT) e de uma concepção de sustentabilidade planetária que considere não somente a economia de energia elétrica, mas também a necessidade de mudanças no modelo hegemônico de produção e consumo. Foram desenvolvidas oficinas pedagógicas sobre a física da energia solar e modelos de produção e consumo; a construção e instalação de um aquecedor solar de baixo custo (ASBC) no Asilo Lar Paulo de Tarso; a construção de um protótipo didático para demonstrar o funcionamento do ASBC em sala de aula, além de algumas visitas ao dispositivo já instalado. O curso demonstrou que, além da necessidade de conhecimentos científicos, é necessário o domínio de conhecimentos tradicionais, de cunho prático, para que o cidadão tenha autonomia suficiente para a busca da sustentabilidade planetária.', 'https://revistas.uepg.br/index.php/conexao/article/view/3746', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353146', 'ASSESSORIA FONOAUDIOLÓGICA NA EDUCAÇÃO INFANTIL', 'Zaboroski, Ana Paula; Bougo, Graziela Chamarelli; Oliveira, Rudahyra Taisa Osswald de; Oliveira, Jáima Pinheiro de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente trabalho teve por objetivo indicar possibilidades de atuação da fonoaudiologia em ambiente escolar, com foco para a Educação Infantil. A ação extensionista foi desenvolvida em três centros de educação infantil da cidade de Irati/PR. Na presente análise foram considerados dados de 114 alunos e de 30 professores. Foram aplicados questionários e mini-cursos com os professores. Com as crianças, foi elaborado um perfil e atividades com foco para assuntos fonoaudiológicos. A ação extensionista confirmou-se como um importante aliado do desenvolvimento de competências acadêmicas e da comunidade escolar.', 'https://revistas.uepg.br/index.php/conexao/article/view/3750', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353147', 'ESTRATÉGIAS MULTIDISCIPLINARES DE PROMOÇÃO DE SAÚDE EM PORTADORES DE NEOPLASIAS BUCAIS MALIGNAS DESENVOLVIDAS POR PROJETOS DE EXTENSÃO DA UNIVERSIDADE ESTADUAL DE MARINGÁ', 'Pieralisi, Neli; Chicarelli, Mariliani; Takeshita, Wilton Mitsunari; Ferreira, Gustavo Zanna; Iwaki, Lilian Cristina Vessoni', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O câncer de boca é uma doença com alta prevalência no Brasil e no Mundo, sendo considerada como um problema de saúde pública. É uma lesão muito mutiladora para o ser humano. Um fato importante relacionado ao câncer bucal são as sequelas do tratamento, como as alterações estéticas e funcionais. A partir desta realidade, empenhados em proporcionar uma melhor qualidade de vida a esses pacientes e formar profissionais qualificados e conscientes dessa realidade, foram criados os projetos LEBU e VIDA no Departamento de Odontologia da Universidade Estadual de Maringá. Por isso a metodologia deste trabalho inclui uma análise das práticas de promoção da saúde bucal nos projetos. Os projetos LEBU e VIDA visam melhorar a qualidade de vida dos pacientes, oferecer um meio de resolutividade para sua problemática bucal, assim como formar profissionais comprometidos com seus deveres sociais e de cidadãos.', 'https://revistas.uepg.br/index.php/conexao/article/view/3751', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353149', 'AS POTENCIALIDADES DA EDUCAÇÃO EM SAÚDE NA PREVENÇÃO DE DOENÇAS CRÔNICAS', 'Teixeira, Eliane Tavares Natividade; Rossi, Bárbara Cristina Filgueiras', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo discute a relevância das Representações Sociais e da linguagem dos sujeitos nas práticas educativas no campo da saúde. Baseia-se nos resultados de pesquisa de campo no âmbito do projeto de extensão “Educação em Saúde em Doenças Crônicas: desvendando o processo saúde-doença” implantado na Policlínica Piquet Carneiro/UERJ. Ao se utilizar as representações e vivências dos próprios sujeitos espera-se contribuir para a inovação da linguagem na prevenção em saúde. As ações são desenvolvidas em dois eixos complementares: o vinculado à extensão, ao ensino e à pesquisa, que oferta aos acadêmicos uma proposta didática diferenciada, com recursos teórico-metodológicos como oficinas temáticas, grupos de estudo e oficinas de vivências, contribuindo para uma formação de profissionais com maiores qualificações em Serviço Social e saúde; o eixo da assistência, que mantém espaços permanentes para atendimentos individuais e coletivos para os usuários que buscam a Policlínica.', 'https://revistas.uepg.br/index.php/conexao/article/view/3754', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35314d', 'A DRAMATIZAÇÃO COMO FORMA DE RESGATAR A AUTOESTIMA DO DEFICIENTE VISUAL', 'França, Nilcéia Allbuquerque; França, Marília Rodrigues', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente texto é um estudo reflexivo sobre a pesquisa ação, como pesquisa interpretativa do trabalho docente, na área da Educação Especial. De acordo com a especificidade do estudo, trata-se de uma análise com os professores da APADEVI (Associação de Pais e Amigos dos Deficientes Visuais de Ponta Grossa), com o intuito de avaliar o programa de Educação Especial, com crianças e adultos, como objeto de trabalho, mostrando como é a visão dos profissionais da APADEVI que procuram melhorar seus métodos pedagógicos diante do desafio das diferenças, abordando contextos diferenciados ao trabalho docente. Como finalização, ainda que parcial, parece indicar que estudar e evoluir constantemente, na área, configuram- se como ações necessárias, para formar o docente eficaz em sua carreira, estando ainda, o profissional, sempre aberto (a) a questionamentos dos outros colegas professores e entre si, podendo tornar-se, deste modo, ser(es) crítico(s) e pesquisador(es).', 'https://revistas.uepg.br/index.php/conexao/article/view/3769', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353150', 'AÇÃO EXTENSIONISTA EM DEFESA DO DIREITO FUNDAMENTAL DE CRIANÇAS E DE ADOLESCENTES, “À LIBERDADE AO RESPEITO E A DIGNIDADE”', 'Bidarra, Zelimar Soares; Sasson, Susana Karen Hans', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O trabalho ora apresentado consiste num relato de experiência sobre uma das ações de extensão universitária que tem sido desenvolvida pelas equipes do “PAPS” (“Programa de Apoio as Políticas Sociais”) e do “Ponto”(“Ponto de Apoio aos Conselhos de Políticas Sociais), integrados por docentes e acadêmicas do Curso de Serviço Social da Universidade Estadual do Oeste do Paraná – UNIOESTE. Objetiva apresentar a atividade de extensão “Oficinas de Prevenção à Violência Sexual contra a Criança e o Adolescente, espaços para defender o “Direito à Liberdade ao Respeito e a Dignidade” (ECA, 1990). As Oficinas destinam-se a crianças, de 05 a 10 anos, consistindo em trabalho educativo e preventivo, tomando aspectos das violências contra crianças e contra adolescentes, em especial, da violência sexual, como foco central. Através de diálogo direto com o público alvo, mediado por recursos lúdicos, busca-se construir possibilidades de evitar a vitimização e a revitimização, decorrentes das práticas e das', 'https://revistas.uepg.br/index.php/conexao/article/view/3781', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353151', 'EXTENSÃO UNIVERSITÁRIA: CONSTRUINDO E PERMUTANDO SABERES EDUCOMIDIÁTICOS', 'Assumpção, Zeneida Alves de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo demonstra a construção e a permuta de conhecimentos educomidiáticos entre professores e alunos do Colégio Estadual Professor Meneleu de Almeida Torres e acadêmicos de Jornalismo, da Universidade Estadual de Ponta Grossa (UEPG), Paraná, mediante a leitura crítica e as produções midiáticas com a Radioescola, com as rádios tradicionais hertzianas e com a rádio web. Ao trabalhar com a Radioescola, o educando poderá se preparar para exercer a cidadania, a responsabilidade, a compreensão da realidade e a crítica social. Optou-se, pois, pelo método pesquisa-ação. Em 2007, os professores participaram de mini-cursos, de palestras, de debates, de discussões e de oficinas; e então, fizeram (gravaram e editaram) programas-pilotos. Em 2008, os alunos receberam o mesmo conteudo e a mesma prática. Demonstraram o domínio da locução e dos saberes sobre a linguagem, sobre o discurso radiofônico e sobre as rotinas produtivas. Gravaram e editaram debates, notícias, reportagens, dramaturgia sob', 'https://revistas.uepg.br/index.php/conexao/article/view/3782', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353152', 'PRÁTICA LABORATORIAL E ENSINO PELAS ATIVIDADES DE EXTENSÃO NA AGÊNCIA DE JORNALISMO DA UEPG', 'Gadini, Sérgio Luiz', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Entre os desafios, contradições e limites da esfera de ação da Universidade Pública Brasileira, as práticas de extensão figuram como tentativas para auxiliar a formar o acadêmico-profissional e, ao mesmo tempo, atender a demandas sociais de que o Estado não dá conta. O trabalho da Agência de Jornalismo, da UEPG, a partir de sua área de abrangência (Campos Gerais do Paraná), busca aproximar a Universidade da comunidade, visando conciliar as práticas de ensino, de pesquisa e de extensão. Sem pagamento, os estudantes que participam do trabalho e dos serviços de mídia que têm sido dados a instituições que precisam desse trabalho, o projeto tem sido um espaço de intervenção técnica de produção editorial, seja para realizar atividades jornalísticas, em mídia impressa, seja eletrônica ou digital, tais como a produção de jornais, folder, vinheta ou documentário televisivo, sites, dentre outros formatos em suportes variados, a partir de solicitações da comunidade. A Agência também cumpre com um', 'https://revistas.uepg.br/index.php/conexao/article/view/3783', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353155', 'TECNOLOGIA DESMISTIFICADA COMO BASE DE EXTENSÃO RURAL', 'Weirich Neto, Pedro Henrique; Looddi, Maria Marta; Santos, Nadine Woruby; Rocha, Carlos Hugo', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente trabalho de extensão rural é realizado com pequenos produtores de leite, no Assentamento Coletivo Estrela, localizado em Ortigueira. Município com um dos menores IDH da região sul do Brasil, tem na cadeia do leite um dos maiores potenciais para agregação de renda para a agricultura de base familiar. O objetivo é, através de tecnologias simplificadas, adaptadas à realidade local e de baixo custo, melhorar quantitativa e qualitativamente a produção de leite no assentamento e construir referencial técnico para outros assentamentos e para agricultura de base familiar. Essas ações baseiam-se em correções nos manejos da ordenha e alimentação, adequando a propriedade e racionalizando mão de obra e investimentos. Foram priorizadas as seguintes ações: identificação de animais, mudanças nos procedimentos de ordenha, produção de forragem e concentrado, registros de eventos do rebanho para iniciar o melhoramento genético. Rápidos avanços puderam ser obtidos com as práticas relativas à a', 'https://revistas.uepg.br/index.php/conexao/article/view/3786', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353157', 'FÍSICA – DA UNIVERSIDADE À COMUNIDADE', 'Silva, Silvio Luiz Rutz da; Camargo, Antônio José; Bernardes, Luiz Antonio Bastos; Pereira, Luis Américo Alves', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto de extensão “Física - da Universidade à Comunidade”, desde sua primeira execução, em 1999, tem como objetivo, estabelecer uma ligação direta entre a comunidade e o Departamento de Física, da UEPG. As atividades oferecidas por este projeto são: cursos de nivelamento e cursos sobre temas para complementar a formação dos acadêmicos dos cursos de Física e de áreas afins; cursos, oficinas e palestras para professores dos Ensinos Fundamental e Médio (EFM); monitorias, iniciação científica e participação no projeto “Cidadão do Futuro”, para alunos do EFM; montagem de laboratórios e divulgação dos cursos de Física, da UEPG, nas escolas da rede básica de ensino; realização de experimentos de Física em lugares públicos, em várias cidades do Estado do Paraná.', 'https://revistas.uepg.br/index.php/conexao/article/view/3788', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353159', 'A ATUAÇÃO DO PSICÓLOGO NO ACOMPANHAMENTO DAS PENAS ALTERNATIVAS', 'Silva, Maria Carolina Soares e; Gutzlaff, Tássia; Kazmierczac, Luiz Fernando', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta temas ligados à importância dos serviços prestados pela área de Psicologia, para acompanhar e para monitorar os apenados na prestação de serviço à comunidade, bem como para propiciar a essas pessoas a oportunidade de se ressocializarem, deixando de ser rotuladas.', 'https://revistas.uepg.br/index.php/conexao/article/view/3795', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35315b', 'PROGRAMA DE PREVENÇÃO AO USO DE DROGAS NO  CONTEXTO ESCOLAR', 'Pietrobon, Sandra Regina Gardacho; Batista, Ana Priscila; Ballão, Cléa Maria', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo tem como objetivo, apresentar as etapas para elaboração de um programa para prevenir o uso de drogas, no contexto escolar, para alunos de 5ª a 8ª séries; configurando-se como projeto de extensão, fazendo parte do Programa Universidade Sem Fronteiras do Governo do Estado do Paraná. Sua constituição subsidiou-se em pesquisa bibliográfica, para conhecer o efeito de drogas lícitas e ilícitas em diversos âmbitos. Com base nisso e, nas características da população alvo, foram criadas tecnologias para um trabalho de prevenção às drogas.', 'https://revistas.uepg.br/index.php/conexao/article/view/3800', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35315c', 'FORMAÇÃO DE ORGANIZAÇÃO POPULAR, E OS DESAFIOS DA PRÁTICA', 'Fleig, Daniel Gustavo; Barcelos, Simone Nunes; Zamperin, Nataly Cavalcanti; Leal, Rosemara Martins; Silva, Cristiane Rocha; Nogueira, Keite de Cássia; Pires, Sandra Pereira; Murata, Marilia Ferreira P', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O texto busca relatar a experiência de um grupo de mulheres do município de Matinhos, sito no litoral paranaense, em formar organização popular, o artigo busca ressaltar os medos e as expectativas das mulheres bem como os desafios para a auto-gestão, para o protagonismo do grupo, ao organizar e operacionalizar as atividades. A metodologia pauta-se na pesquisa-ação, utilizando falas e os registros, no decorrer das reuniões, na definição das regras internas, nas formas de comunicação das informações do artesanato e nos registros da pesquisadora no decorrer da vivência no projeto e nos diálogos informais. Até o momento, é possível observar que o grupo se fortaleceu devido ao vínculo de confiança entre os proponentes e principalmente devido ao respeito às diferenças. O espaço livre para falarem e para se envolverem, nas decisões, levou-as a valorizarem o saber individual e a se comprometerem. Ao sentirem-se valorizadas, a demanda sobre seu saber, levou-os ao compartilharem o que sabem e a ', 'https://revistas.uepg.br/index.php/conexao/article/view/3802', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35315e', 'LEITURA EM AÇÃO: INSERÇÃO SOCIAL & PRÁTICAS DO DISCURSO', 'Pinc, Amanda Maria Alves; Valente, Thiago Alves', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Compreendendo as lacunas de sua atuação, enquanto instituição formadora, a escola enfrenta problemas de ordem diversa, entre eles, a falta de capacitação docente, resultado de uma conjuntura histórico-social que envolve, como tal, muitos elementos, entre eles, a relação do ensino básico com o superior. À Universidade, portanto, cabe o importante papel de construir um espaço, para se refletir sobre os objetivos educacionais, o que certamente, implicará propostas metodológicas relevantes principalmente, no que tange às alterações das atuais condições de formação de leitores. Este projeto foi, pois concebido para refletir e para encaminhar procedimentos no âmbito das constatações da efetivação de práticas de leitura por parte dos estudantes da Escola Estadual João XXIII, no município de São Jerônimo da Serra.', 'https://revistas.uepg.br/index.php/conexao/article/view/3805', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353162', 'PENSANDO NAS RUAS: COMO ENSINAR A FILOSOFIA?', 'Bueno, André', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A proposta do Projeto “Pensando nas Ruas” é levar aos alunos da rede pública de Ensino Básico, conhecimento introdutório sobre Filosofia, privilegiando o trabalho ético, para construir uma cidadania consciente, através de reflexões sobre sociedade, cultura, vida e humanismo, presentes na tradição filosófica. Visa, assim, desenvolver atividades de ensino de Filosofia, assessorar os professores da rede pública e realizar a divulgação de temas filosóficos atuais.', 'https://revistas.uepg.br/index.php/conexao/article/view/3810', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353165', 'ESTRATÉGIA DE DESENVOLVIMENTO REGIONAL E SUSTENTÁVEL: ANÁLISE DO TERRITÓRIO CENTRO-SUL DO PARANÁ', 'Barreiros, Reginaldo Ferreira; Rox, Wanessa; Chrestani, Carlos Geovanni; Baniski, Andréia Mabel; Simon, Lucas', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo objetiva contribuir com o debate sobre o Território Centro- Sul do Paraná com respeito à estratégia de negócio do Banco do Brasil – “Desenvolvimento Regional Sustentável” (DRS) – e sua escolha: auxiliar o desenvolvimento da produção de leite no território. Esclarecemos que para haver o pleno desenvolvimento, algumas medidas (assistência técnica, auxílio financeiro e harmonização entre indústria e produtor) devem ser tomadas como requisitos básicos, prevalecendo sempre em consonância com os recursos naturais e a realidade dos pequenos produtores. Nossa presença na região deve-se ao projeto “Apoio à Concepção de Planos de Desenvolvimento Regional Sustentável no Território Centro Sul do Paraná”, do programa Universidade Sem Fronteiras da SETI-PR.', 'https://revistas.uepg.br/index.php/conexao/article/view/3816', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353166', 'APOIO TÉCNICO AOS PEQUENOS PRODUTORES DE LEITE DO MUNICÍPIO DE TEIXEIRA SOARES: DIAGNÓSTICO', 'Carlos, Laura Emília; Koop, Lais; Franquitto, Márcia Karine; Penteado, Rosângela de Fátima Stankowitz; de Moraes, Solange; Tedrus, Guilherme Almeida Souza; Barros, Angela; Domingues, Flávia', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente trabalho trata da produção de leite do município de Teixeira Soares-PR, desenvolvido no período de novembro de 2007 a outubro de 2008, através do Programa UNIVERSIDADE SEM FRONTEIRAS/SETI. O projeto tem por objetivo verificar os problemas inerentes à atividade. Tratase de um estudo de natureza extensiva e exploratória, ocorrido em três etapas: contato com as autoridades municipais e entidades envolvidas na atividade, em seguida foi realizado o cadastramento dos produtores e por último, diagnóstico das propriedades através de questionários técnicos e análises do leite, visando verificar sua qualidade. Constataram-se elevados índices de mastite no rebanho, precárias condições de higiene devido à falta de estrutura, de gestão financeira e carência de conhecimento sobre serviços sócio-assistenciais. Concluiu-se que as propriedades estudadas necessitam de maior apoio técnico e orientação, bem como implantação de ações para melhorias na produção, na renda e conseqüentemente na qua', 'https://revistas.uepg.br/index.php/conexao/article/view/3817', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353172', 'PEDAGOGIA HOSPITALAR: A PRÁTICA DO PEDAGOGO EM INSTITUIÇÃO NÃO-ESCOLAR', 'Wolf, Rosangela Abreu do Prado', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O artigo trata da diversidade atual no campo de atuação do pedagogo, que além de atuar em instituições escolares, também, vem atuando em instituições não-escolares. Apresenta o projeto de extensão do curso de Pedagogia da UNICENTRO, campus de Guarapuava-PR, que é desenvolvido na ala de Pediatria do Hospital de Caridade São Vicente de Paulo, cujo objetivo é propiciar ao acadêmico de Pedagogia durante sua formação a oportunidade de desenvolver práticas e adquirir conhecimentos sobre a atuação do Pedagogo em instituições não-escolares como a hospitalar, através da escolarização hospitalar para a continuidade dos estudos das crianças hospitalizadas. A metodologia utilizada é de cunho qualitativo-interpretativo (ERICKSON, 1988; VASCONCELOS, 2002). Os resultados obtidos indicaram a melhora do quadro sintomático da criança hospitalizada, pois a mediação do acadêmico possibilitou a adaptação, a motivação, e a ocupação sadia do tempo ocioso através de atividades diversas de leitura, além de gar', 'https://revistas.uepg.br/index.php/conexao/article/view/3836', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353173', 'PERFIL DOS USUÁRIOS DEPENDENTES DE DROGAS DO PROGRAMA PRÓ-EGRESSO (PPE) DE PONTA GROSSA', 'Cordeiro, Marilice Soelem; Krainski, Luiza Bittencourt; Quimelli, Gisele Alves de Sá', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O Programa Pró-Egresso (PPE) de Ponta Grossa é um programa de extensão universitária que faz acompanhamento social e jurídico ao egresso do sistema penitenciário e àqueles beneficiados com penas alternativas. A partir dos atendimentos realizados notouse grande incidência do artigo 28 da Lei n°. 11.343/2006 (uso e porte de drogas). O encaminhamento dos usuários/dependentes químicos às instituições conveniadas para a prestação de serviço à comunidade geralmente é difícil. Frente a essa dificuldade foi estabelecido o projeto de intervenção “Parceiros pela Vida” visando proporcionar aos usuários/dependentes químicos, um processo reflexivo, levando-os a compreender sua doença, e fazendo com que aceitem, de forma voluntária e consciente, o tratamento adequado a sua dependência. Para melhor conhecermos estes usuários/dependentes químicos foi necessário fazermos um levantamento do perfil sócio-econômico dos mesmos, visando qualificar as estagiárias de Serviço Social para o atendimento e os ser', 'https://revistas.uepg.br/index.php/conexao/article/view/3837', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353176', 'A GUAÇATONGA (Casearia sylvestris Sw.) E SEU USO POTENCIAL COMO FITOTERÁPICO: UM RESULTADO PRÁTICO DE TRABALHO EXTENSIONISTA NO DISTRITO DE ITAIACOCA', 'Quaquarelli, César Augusto; Lima, Pedro Ribeiro; Kulchetscki, Luiz', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho é resultado de atividades extensionistas iniciadas em maio de 2003 vinculadas ao projeto “Meio Ambiente sustentável para o Distrito de Itaiacoca - Ponta Grossa – Paraná - Brasil” com o objetivo de buscar soluções práticas para a população do meio rural baseadas em recursos existentes em seu próprio meio ambiente. Entre as várias inserções realizadas, apresentamos o resultado no tratamento de neoplasia em animal doméstico com folhas novas de Casearia sylvestris, conhecida como guaçatonga, pau-lagarto ou cafezeirode- bugre, cujo tratamento em pouco mais de dois meses de aplicação, promoveu a recuperação e cicatrização de tecidos da pata de um cão doméstico, sugerindo a necessidade de aprofundamento de estudos com esta planta. O resultado deste trabalho serve de subsídio para futuros testes curativos e de desinfecção aplicada em saúde animal, oportunizando a pesquisa e a valorização de plantas medicinais.', 'https://revistas.uepg.br/index.php/conexao/article/view/3847', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353177', 'A RELAÇÃO DO SURDO COM O MERCADO DE TRABALHO', 'Graeff, Talita Diane', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho é uma reflexão sobre a condição profissional do surdo, inserido em algumas empresas da cidade de Ponta Grossa- PR.. Foram pesquisadas doze empresas que contém em seu quadro funcional sujeitos surdos ocupando as mais diversas atividades. Nosso objetivo foi verificar qual é a relação desses surdos com o contexto de trabalho através da visão dos seus respectivos coordenadores que nos forneceram material para que pudéssemos compreender os lugares ocupados pelos surdos dentro das empresas, o seu desempenho e sobre a existência das condições necessárias exigidas pela singularidade da relação surdo/ouvinte.', 'https://revistas.uepg.br/index.php/conexao/article/view/3848', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35317b', 'EDUCAÇÃO PARA A CIDADANIA E SUA RELAÇÃO COM A EXTENSÃO UNIVERSITÁRIA', 'Quimelli, Gisele Alves de Sá', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente artigo discute a possibilidade de desenvolver uma educação crítica, para a cidadania, via extensão universitária. O Plano Nacional de Extensão Universitária é entendido como proposta de racionalidade crítica, de educação para a cidadania, e embasa os demais conceitos desenvolvidos no artigo. Concepções distintas de cidadania, como Civil Republicana, Liberal e Crítica são apresentadas. Diferentes racionalidades na educação para a cidadania são enfocadas com o intuito de esclarecer, como três diferentes práticas podem ser desenvolvidas por coordenadores de extensão com os seus alunos.', 'https://revistas.uepg.br/index.php/conexao/article/view/3855', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b35317c', 'INCUBADORA DE EMPREENDIMENTOS SOLIDÁRIOS: UMA NOVA PERSPECTIVA INTERDISCIPLINAR', 'Silva, Bethyan Kelly Roesler da; Maravieski, Andressa; Pedrozo, Elcio Fernando de Avila; Dambrós, Marcos Paulo; Christiano, Shana Eloisa; Monteiro, Marina Rodrigues; Ferreira, Vera Cristiane; Brasil, ', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A construção deste artigo teve por objetivo a apresentação da IESOL (Incubadora de Empreendimentos Solidários) enquanto um Programa de Extensão da Universidade Estadual de Ponta Grossa – Paraná, para a comunidade em geral. Em seu desenvolvimento, este artigo contém breve consideração sobre a questão da precarização do Trabalho e suas implicações sócio-econômicas como o desemprego, a exploração da mão-de-obra e a ausência de direitos trabalhistas. Neste contexto, a Economia Solidária surge como alternativa de questionamento e de enfrentamento destas relações, como perspectiva que visa à geração de trabalho e de renda que tem por valores: a democracia, a igualdade e a emancipação. Abordaremos o trabalho realizado pela IESOL através de sua metodologia de ação, que tem por fases: pré-incubagem, incubagem e desincubagem, relatando as experiências com os empreendimentos com os quais realizamos os primeiros contatos. Posteriormente iremos considerar as ações da Incubadora, salientando a impor', 'https://revistas.uepg.br/index.php/conexao/article/view/3858', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cca32da1a94b353180', 'TRIBUNAL DO JÚRI: UMA ANÁLISE À LUZ DA CONSTITUIÇÃO FEDERAL DE 1988', 'Mongruel, Ângela de Quadros', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente trabalho é parte integrante do projeto de pesquisa intitulado “Tribunal do Júri na Balança”, o qual teve por objetivo a verificação da existência ou não de igualdade material entre réus e jurados. Para tanto se fez uma análise doutrinária e uma pesquisa de campo sobre a forma de escolha dos integrantes da lista de jurados na cidade de Ponta Grossa, Paraná. Os resultados mostram que a opinião da doutrina é espelhada na práxis forense. Este relatório faz uma análise constitucional do tema, priorizando a noção de isonomia. A CF/88 afirma que todos são iguais perante a lei, mas sabe-se que este princípio não é parte da realidade brasileira. Os resultados do estudo mostram que a doutrina reconhece o caráter democrático do Júri, sendo este considerado uma conseqüência da soberania popular, a maneira de o povo participar diretamente da atividade do Judiciário. Entretanto, o Tribunal Popular é um instituto desigual, pois os jurados são, na maioria, funcionários públicos (recrutados ', 'https://revistas.uepg.br/index.php/conexao/article/view/3866', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353181', 'A PRÁTICA DO TRABALHO COM FAMÍLIAS: UMA PROPOSTA DE ATENÇÃO ODONTOLÓGI', 'Fadel, Cristina Berger', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O Programa Saúde da Família (PSF), enquanto modelo primário de atenção em saúde, deve evidenciar a família como núcleo básico de atuação, considerando a sua realidade socioeconômica e cultural, em todos os momentos do planejamento. Buscando implementar esta prática de saúde pública para o campo da Odontologia, desenvolvemos, em parceria com o Instituto Filhas e Filhos do Coração Imaculado de Maria, o projeto de extensão intitulado: “Experiências Extra- Muros em Odontologia Social”, voltado aos formandos de Odontologia da UEPG-PR. As atividades contemplam ações amplas de seleção, de cadastramento e de reconhecimento das famílias e ações específicas, preventivas, educativas e curativas em saúde bucal. Para tanto, nos valemos das visitas com atendimento domiciliar, da atenção em consultório odontológico dentro da própria comunidade e do sistema de referência para a atenção complexa. Apesar de sua pouca duração, sem dúvida, este projeto tem propiciado um aprendizado bilateral (equipe/ comu', 'https://revistas.uepg.br/index.php/conexao/article/view/3881', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b353185', '“O COMPANHEIRO” – JORNAL COMUNITÁRIO PRODUZIDO A PARTIR DA PARCERIA ENTRE O CURSO DE JORNALISMO DA UEPG E A FUNDAÇÃO MUNICIPAL DE PROMOÇÃO AO IDOSO DE PONTA GROSSA', 'Woitowicz, Karina Janz', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A partir de uma parceria firmada entre o Departamento de Comunicação/Curso de Jornalismo da UEPG e a Fundação Municipal de Promoção ao Idoso (FAPI) de Ponta Grossa, o projeto “O Companheiro” compreende a publicação bimestral de um jornal comunitário, direcionado à terceira idade no município. Trata-se de uma proposta de criação de um meio de interação com a comunidade local, que utiliza a comunicação como espaço a serviço da defesa e/ou conquista da cidadania. Ao criar um veículo para discutir aspectos relacionados à saúde, à inclusão social, aos direitos e aos serviços oferecidos pela FAPI, os idosos reconhecem demandas e dificuldades comuns, e mantém maior relação de pertença à comunidade. Através desse trabalho, pretende-se impulsionar a participação da terceira idade na produção e na recepção de informações e conteúdos voltados às suas necessidades, fortalecendo o caráter informativo e conscientizador do jornal “O Companheiro”.', 'https://revistas.uepg.br/index.php/conexao/article/view/3885', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b35318a', 'SE OS PAIS NÃO VÃO À ESCOLA, A ESCOLA VAI ATÉ OS PAIS', 'Jacob, Josélia Madalosso Vieira; Silva, Rosiane Machado da; Nascimento, Maria Luiza; Barbosa, Sueli Bertol', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta um relato parcial do projeto de extensão “Se os pais não vão à escola, a escola vai até os pais”, em desenvolvimento no CAIC/UEPG, no ano de 2005. O Centro de Atenção Integral à Criança e ao Adolescente Reitor Álvaro Augusto Cunha Rocha é um espaço educacional comprometido com a formação do educando e com a integração da família à escola. Esse projeto surgiu como uma alternativa para a viabilização dessa integração, oportunizando aos pais o acesso a diversas informações referentes à educação dos filhos, através de encontros, palestras e leituras domiciliares.', 'https://revistas.uepg.br/index.php/conexao/article/view/3893', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531aa', 'RELAÇÕES SOCIAIS EM ACAMPAMENTO DO MST: RELATO DE EXPERIÊNCIA INTERDISCIPLINAR', 'Kaminagakura, Fabrício Golono; Veber, Ana Paula; Uriarte, Sarah Zewe; Rech, Patrícia; Zdebskyi, Janaina de Fátima; Padilha, Liara Rotta; da Rosa, Sabrina da', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente trabalho visa expor as atividades de extensão desenvolvidas e as relações estabelecidas durante ações da Operação Capim Dourado, do Projeto Rondon, em especial no Acampamento Sebastião Bezerra da Silva, Porto Nacional (TO). Este acampamento foi inicialmente formado por representantes do Movimento dos Trabalhadores Rurais Sem Terra (MST) e Movimento dos Atingidos por Barragem (MAB). A organização de sociedade de ambos os grupos proporcionou a integração social e a formação de um espaço com grande riqueza empírica. A abordagem utilizada no presente projeto foi qualitativa, por meio da observação do cotidiano do acampamento, ações nas áreas ambiental, de saúde e recreação, da análise documental e de relatórios de pesquisa. Foi possível observar a relação direta do acesso à informação e à cidadania. Dentre os resultados, destacam-se a receptividade da comunidade e a experiência vivenciada pelos acadêmicos na integração com a mesma.', 'https://revistas.uepg.br/index.php/conexao/article/view/4816', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ab', 'O RETRATO DA EXTENSÃO UNIVERSITÁRIA PELOS DOCENTES', 'Porto Alegre, Laíze Marcia; Viviurka, Angela Bernert', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo refere-se a uma pesquisa realizada para uma dissertação de Mestrado, que procurou diagnosticar qual a percepção de extensão universitária dos docentes de uma universidade federal do Estado do Paraná. Para a realização da pesquisa foram utilizadas as abordagens metodológicas qualitativa, por meio de entrevistas com os gestores da Instituição e quantitativa, onde foram enviados questionários a todos os docentes da Universidade. Verificou-se que a extensão não é considerada uma atividade menor em relação ao ensino e à pesquisa na Instituição; que os docentes não têm clareza a respeito do conceito e das funções da extensão universitária e que há necessidade de esclarecimentos sobre a identidade da Universidade. Foram sugeridos o registro e a divulgação das ações extensionistas e a flexibilização da carga horária docente.', 'https://revistas.uepg.br/index.php/conexao/article/view/4947', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ae', 'COLETIVO EDUCADOR PARA O TERRITÓRIO PORTAL DA AMAZÔNIA: CONSTITUIÇÃO E DESENVOLVIMENTO DA EDUCAÇÃO AMBIENTAL', 'Tiso, Marcos Roberto; Camhlutti, Marília; Ribeiro, Luiz Fernando Cladeira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A Educação Ambiental deve ser permanente, participativa e continuada. Para que isso ocorra se faz necessária a união de instituições públicas e privadas na formação de educadores ambientais populares. O Programa Coletivo Educador consiste no fortalecimento desse processo através das atividades socioambientais de caráter pedagógico. Na metodologia do Programa foram adotadas três metas, sendo elas: a realização de articulação, seleção e implantação de quatro núcleos; formação inicial de 160 educandos através de módulos e intervenções educacionais e por último o fortalecimento e novas parcerias para o processo de formação continuada de educadores ambientais. Após três anos de projetos foram constituídos 4 microterritórios, formados 107 coletivos educadores ambientais e a implementação de 38 projetos de intervenção ambiental. A Educação ambiental no Portal da Amazônia teve suas bases lançadas e deve continuar sua construção de forma dinâmica e continuada buscando a conscientização e transf', 'https://revistas.uepg.br/index.php/conexao/article/view/5013', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b0', 'FORMAÇÃO DE JOVENS PARA O MUNDO DO TRABALHO E CIDADANIA: EXPERIÊNCIA TEÓRICA E PRÁTICA POR MEIO DE PROJETO EXTENSIONISTA', 'Perez, Deivis', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo apresenta o projeto de extensão universitária nomeado Programa Formação de Jovens para o Mundo do Trabalho e Cidadania. Trata-se de atividade psicossocial e educacional dedicada ao atendimento de jovens empobrecidos, com idade entre 14 e 19 anos, de Assis-SP e região. O objetivo é contribuir com o processo de desenvolvimento cognitivo, afetivo e social dos participantes. A atividade extensionista tem favorecido, também, a formação de graduandos de Psicologia para a mediação do desenvolvimento humano realizada no âmbito da educação não formal. O referencial teórico-metodológico é a Psicologia Histórico-Cultural de Vigotski. O Programa apresenta como resultados o estabelecimento de parcerias entre a universidade e organizações públicas estaduais e municipais; a incorporação de temáticas inovadoras ao currículo de Psicologia da UNESPcâmpus Assis, a realização de pesquisa acadêmico-científica sobre experiência de trabalho socioeducacional de psicólogos e, por fim, registrou-se ', 'https://revistas.uepg.br/index.php/conexao/article/view/5016', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b4', 'INTERAÇÃO DA FISIOTERAPIA JUNTO A IDOSAS INSTITUCIONALIZADAS: RELATO DE CASO EM IDOSA COM FRATURA UMERAL NÃO CONSOLIDADA', 'Fogaça, Cristiane do Amarante; Dorneles, Camila Christo; Rossi, Stefani Samai de Souza; Ilha, Jocemar; Medeiros, Paulo Adão de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'As quedas, frequentes na população idosa, tem se mostrado um fator de alta morbimortalidade, na qual as fraturas são a principal consequência que acarretam comprometimento funcional. A fisioterapia busca auxiliar na prevenção de novas quedas, melhorar o desempenho funcional e qualidade de vida do idoso. Este relato tem por objetivo descrever a evolução do tratamento fisioterapêutico realizado em paciente idosa com fratura de úmero não consolidada, atendida em programa de extensão universitária voltado a idosas institucionalizadas. Paciente de 84 anos foi submetida a um protocolo de cinesioterapia global e orientações. O tratamento proposto não foi suficiente para trazer uma evolução significativa à situação da paciente, o que pode estar relacionado ao severo quadro clínico, às progressivas alterações da idade e as dificuldades de manejo no contexto institucional. Conclui-se que a fisioterapia tenha retardado um maior declínio funcional e o tratamento proposto poderá servir de parâmetro', 'https://revistas.uepg.br/index.php/conexao/article/view/5276', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b5', 'APORTES METODOLÓGICOS PARA UNA LÍNEA SOBRE PRÁCTICA Y RESIDENCIA COMO SERVICIO DE EXTENSIÓN UNIVERSITARIA', 'Lópes, Marcelo Luis', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'El presente trabajo deriva de una investigación que tuvo como objeto la demanda en la extensión universitaria originada en la cátedra de Residencia del Profesorado en Ciencias de la Educación de la Universidad Nacional de Jujuy, Argentina. El problema de investigación es qué tratamiento tiene la demanda en materia de Extensión en distintos ámbitos de la Universidad, y cuál es el rol de la teoría al respecto con el objetivo de avanzar en la comprensión del alcance que tiene la demanda social en la promoción de la actividad extensionista vinculando procesos y resultados. Las conclusiones arribaron a que la demanda social abordada a través de acciones extensionistas, incluyendo la Residencia, esta condicionada por cuatro factores. En este artículo se exponen conclusiones con ex-residentes, profundizando la significación que le dan estos a la relación teoría práctica. La metodología utilizada fue la teoría fundamentada en los datos a partir de entrevistas semiestructuradas.', 'https://revistas.uepg.br/index.php/conexao/article/view/5286', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531b8', 'CULTURA E EXTENSÃO: A INCLUSÃO DE PORTADORES DE DEFICIÊNCIA VISUAL POR MEIO DAS ARTES CÊNICAS', 'Paz, Wilton Correia; Pereira, Heloísa Frehse; Baum, Jéssica; Gonçalves, Andréa Fermino; Guimarães, Cláudio Jorge', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'As atividades artísticas podem propiciar a inclusão sociocultural para diversos portadores de necessidades especiais. O presente artigo tem como objetivo avaliar de que maneira o projeto de extensão “O teatro como espaço de reflexão e inserção sociocultural para portadores de deficiência visual” vem contribuindo para a inclusão dos membros da UNIDEV. Desde março de 2012, o grupo busca o aperfeiçoamento de técnicas teatrais e leva as artes cênicas a espaços alternativos. Com o projeto, a Universidade Estadual de Ponta Grossa contribui para a circulação teatral, levando montagens a públicos que cotidianamente não poderiam frequentar o teatro, estendendo os objetivos de seu Festival Nacional de Teatro - FENATA, de democratizar o acesso à arte. Por meio de avaliação qualitativa, percebe-se a sensibilização do público que assiste aos espetáculos, bem como os benefícios que a formação e as apresentações vêm propiciando aos atores no que diz respeito ao desenvolvimento sensorial e melhora da ', 'https://revistas.uepg.br/index.php/conexao/article/view/5290', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ba', 'DIA DE CAMPO E DIFUSÃO DE TECNOLOGIAS PARA A AGRICULTURA FAMILIAR', 'Weirich Neto, Pedro Henrique; Eurich, Joelcio; Okuyama, Kássio Kiyoteru; Moura, Ivan César Furmann; Modena, Raquel Márcia; Ribeiro, Diogenes Raphael Soares; Rocha, Carlos Hugo; Vriesman, Alice Karine;', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A introdução das tecnologias associadas à revolução verde no Brasil promoveu um processo de transformação dos sistemas de produção agrícola o qual precedeu enorme impacto social, êxodo rural e concentração fundiária. Como contraponto a universidade deve ter papel fundamental no desenvolvimento da agricultura familiar, ao identificar, testar, validar e difundir tecnologias adequadas a esta realidade. Com base nestas premissas, em parceria com o Assentamento Guanabara, localizado no município de Imbaú – PR, a equipe do Laboratório de Mecanização Agrícola da UEPG, desenvolveu ações de Extensão Rural que culminaram com o dia de campo “Alternativas para a Agricultura Familiar”, com o objetivo de difundir alternativas tecnológicas testadas e validadas pelo assentamento. Discute-se neste trabalho o dia de campo realizado em parceria com os assentados, inseridos em sistema de produção com condições similares às do público alvo, como referencial para a difusão de tecnologias para agricultores f', 'https://revistas.uepg.br/index.php/conexao/article/view/5292', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531bc', 'PROJETO DE EXTENSÃO - FORMAÇÃO DE EDUCADORES AMBIENTAIS', 'Nunes, Lúcia Helena Oliveira; Cunha, Itana Nunes; Cunha, Ananda Helena Nunes', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A educação ambiental é um componente essencial e permanente da educação nacional, devendo estar presente, em todos os níveis e modalidades do processo educativo. Entretanto, não temos ainda referências concretas para avaliar a validade dos processos de educação ambiental. Há dúvidas se as experiências realmente mudam os comportamentos e as atitudes das crianças, jovens e adultos que passam por ela. O projeto de extensão ‘Formação de Educadores Ambientais’ foi desenvolvido com o objetivo de formar docentes para disseminação da Educação Ambiental; formar sujeitos ecológicos aptos a trabalharem com propostas educacionais enfocando a preservação do meio ambiente; formar indivíduos críticos para a visão do meio ambiente; desconstruir comportamentos e construir novas atitudes; e estruturar o indivíduo com consciência planetária. A iniciativa foi da Universidade Estadual de Goiás, juntamente com a Secretaria de Educação da Prefeitura Municipal de Anápolis-GO. Desta forma, a referência metodol', 'https://revistas.uepg.br/index.php/conexao/article/view/5310', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531bd', 'IMPACTO DO LABORATÓRIO DIDÁTICO NA MELHORIA DO ENSINO DE CIÊNCIAS E BIOLOGIA EM UMA ESCOLA PÚBLICA DE CAMPOS DOS GOYTACAZES/R', 'Viana, Adaisa Paes Paes; Oliveira, Antônia Elenir Amâncio; Pinto, Vinicius Ferreira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Os experimentos têm papel central na qualidade do ensino de ciências na visão dos professores, estudos mostram sua importância e também a visão distorcida de alguns profissionais sobre o método. O presente trabalho descreve os resultados de um projeto em que um laboratório de ciências foi montado em uma instituição pública de ensino básico no município de Campos dos Goytacazes/RJ. Os principais resultados são: o aumento das notas e da frequencia dos alunos na disciplina de ciências e biologia e indiretamente o laboratório pode ainda ter contribuido para um aumento de 46% do IDEB da instituição.', 'https://revistas.uepg.br/index.php/conexao/article/view/5315', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531bf', 'MANGALÔ: RESGATE E DIVULGAÇÃO DA CULTURA REGIONAL MINEIRA', 'Araújo, André Luiz Ribeiro; Gediel, Ana Luiza Borba', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo objetiva apresentar o projeto de extensão Procultura/UFV, que visa difundir a cultura popular a partir da interação com os “cantadores de folia”, principalmente, através da circulação musical e literária, visando a interação entre a comunidade da região do Vale do Mucuri e a Universidade Federal de Viçosa e a cidade de Viçosa, MG. Primeiramente, foi realizada a formação de gestores e produtores culturais, em uma ação participativa, envolvendo acadêmicos de graduação da UFV, em interação com o movimento de divulgação da cultura regional. Posteriormente, ocorreram shows, cursos e roda de conversas através de oficinas, com o intuito de divulgar e proporcionar a reflexão das pessoas envolvidas acerca da singularidade regional. Essa iniciativa, também, buscou o desenvolvimento profissional da banda Mangalô. Entende-se como resultados, que tais aspectos ressignificaram as próprias referências em uma perspectiva diferenciada da atual, mercantilização dos bens culturais no Brasil; ', 'https://revistas.uepg.br/index.php/conexao/article/view/5364', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c2', 'MICROBIOLOGIA PARA O ENSINO MÉDIO E TÉCNICO: CONTRIBUIÇÃO DA EXTENSÃO AO ENSINO E APLICAÇÃO DA CIÊNCIA', 'Bodmar, Carolina Giovana; Tatibana, Berenice Tomoko; Nakazato, Gerson; Gazal, Luis Eduardo de Souza; Koga, Vanessa Lumi; de Souza, Patricia Canteri; Scandorieiro, Sara; Sarmiento, Juan Josue Puno; Med', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O estudo analisa e discute as modificações dos conhecimentos dos participantes do Projeto de Extensão “Praticando Microbiologia e Parasitologia no Ensino Básico e Profissionalizante” desenvolvido na Universidade Estadual de Londrina. Por meio de atividades teórico-práticas, a microbiologia é abordada de forma aplicada ao cotidiano do aluno. Este trabalho teve como objetivo estender o acesso às tecnologias educacionais para além do âmbito universitário. Para coleta dos dados, os participantes responderam ao mesmo questionário, antes do início das aulas e após o término das aulas. A análise dos questionários mostrou que o conteúdo apresentado contribuiu para a formação dos participantes e facilitou a compreensão de que os micro-organismos estão presentes em vários ambientes e podem ser benéficos tanto na natureza quanto em diversos setores importantes para a vida humana. Este trabalho promoveu estímulo à curiosidade sobre os micro-organismos e o interesse pelo conhecimento científico.', 'https://revistas.uepg.br/index.php/conexao/article/view/5516', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c3', 'A CONTRIBUIÇÃO DE PROJETOS DE EXTENSÃO NA FORMAÇÃO PROFISSIONAL DE GRADUANDOS DE LICENCIATURAS', 'Manchur, Josiane; Affonso Suriani, Ana Lucia; Cunha, Marcia Cristina da', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo pretende apresentar uma reflexão teórica sobre importância de projetos extensionistas desenvolvidos no período da graduação nas universidades. Neste contexto abordamos especificamente um projeto de extensão desenvolvido pela Universidade Estadual do Centro Oeste do Paraná (UNICENTRO) em Guarapuava – PR, o qual visa aproximar os acadêmicos de diferentes cursos de licenciatura e a comunidade por meio de um Curso Pré-Vestibular. Portanto, a participação dos graduandos em projetos como esse contribui para uma formação docente contextualizada e amplia as suas experiências no âmbito escolar.', 'https://revistas.uepg.br/index.php/conexao/article/view/5522', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c4', 'NÚCLEO DE PRÁTICAS COMPLEMENTARES AO ENSINO REGULAR (NUPRAC): O TRABALHO COM ADULTOS POUCO ESCOLARIZADOS', 'Caldeira, Jeane dos Santos', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente estudo decorre de um Programa de Extensão intitulado Ação interdisciplinar a Carroceiros e Charreteiros na periferia de Pelotas/RS. Neste, compartilham-se alguns encaminhamentos da pesquisa que tem como objetivo investigar as histórias de educação de moradores de uma comunidade em situação de vulnerabilidade social, constituída em grande parte por carroceiros, charreteiros e catadores de lixo e que está localizada no espaço urbano da cidade de Pelotas/RS. Os principais colaboradores deste estudo, são adultos pouco escolarizados, que trabalham na informalidade com a coleta de resíduos sólidos e que usam técnicas de casqueamento e ferrageamento de equinos para os cuidados dos cavalos utilizados por estes.', 'https://revistas.uepg.br/index.php/conexao/article/view/5536', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c6', 'GRUPOS COM IDOSOS: ESTRATÉGIA PARA (RE)ORIENTAR O CUIDADO EM SAÚDE.', 'Soares, Marilu Correa; Gonçalves, Kamila Dias; Bielemann, Valquíria Machado', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Envelhecer é um processo biológico, dinâmico, progressivo e inevitável que sofre influências dos aspectos socioculturais, políticos e econômicos. O trabalho com grupos proporciona autonomia e desenvolvimento do nível de saúde e condições de vida do idoso. Objetiva-se apresentar o projeto de extensão “Assistência de enfermagem ao idoso da vila Municipal: valorizando a terceira idade”, por meio do relato de experiência das vivências no projeto de extensão.  O projeto teve início no ano de 1989, sob coordenação de docentes da Faculdade de Enfermagem da Universidade Federal de Pelotas em pareceria com a Associação Beneficente Luterana de Pelotas. São realizadas oficinas de educação em saúde, leituras reflexivas, atividades artesanais e recreativas, musicoterapia, técnica de relaxamento e dinâmicas interativas. O propósito do grupo vai ao encontro da promoção do envelhecimento ativo, preservando a capacidade e o potencial do indivíduo, desenvolvendo ações voltadas ao fortalecimento da auton', 'https://revistas.uepg.br/index.php/conexao/article/view/5544', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531c7', 'A LOCALIZAÇÃO DA QUEIXA FAMILIAR EM UM PACIENTE IDENTIFICADO', 'de Souza, Bruna Maria; Bonafé Sei, Maíra', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A família é um grupo permeado por diferentes relações, sentimentos e pensamentos, que podem ou não ser elaborados ao longo da relação familiar. Assim, é comum a dificuldade de elaboração e simbolização de elementos que perpassam tal relação. Como uma alternativa para lidar com tais dificuldades, o grupo familiar pode eleger um paciente identificado, o qual será responsabilizado por todas as dificuldades enfrentadas pela família. A partir desta visão, objetivou-se, por meio deste estudo, de caráter clínico qualitativo, analisar as triagens de famílias para o atendimento psicológico familiar, feitas em um serviço-escola de Psicologia. O foco desta análise foi refletir sobre a dinâmica de se eleger familiares como pacientes identificados, responsabilizando-os, já desde a triagem, pelas problemáticas por todos enfrentadas. Entende-se que tal compreensão favorece a ampliação do olhar dos profissionais ligados ao atendimento de famílias acerca das questões apresentadas por estes grupos, fome', 'https://revistas.uepg.br/index.php/conexao/article/view/5546', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ca', 'LA CONSTRUCCIÓN DE LAS RELACIONES EDUCATIVAS EN LA ENSEÑANZA MEDIA. REFLEXIONES A PARTIR DE UN PROCESO DE EXTENSIÓN UNIVERSITARIA JUNTO A UN LICEO DE MONTEVIDEO (URUGUAY)', 'Valle Lisboa, Laura; Cabo, María; Cano, Agustín', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'En el presente artículo se presentan los resultados de un proceso de extensión universitaria realizado en una institución de Enseñanza Media de Montevideo (Uruguay), en el cual se trabajó con la metodología de mapeo participativo de problemas junto a profesores y alumnos de dicha institución. Tal intervención fue realizada por un equipo docente del Programa Integral Metropolitano de la Universidad de la República (PIM), en un liceo de la zona Este de la ciudad de Montevideo, durante el primer semestre del año 2012. El artículo comienza con una breve descripción del PIM en tanto programa integral universitario de base territorial, así como del liceo y las características sociales y demográficas de su zona de referencia. Luego se describen los objetivos de la intervención y la metodología utilizada, y en los capítulos siguientes se sintetizan los principales resultados alcanzados según las perspectivas de profesores y alumnos del liceo.', 'https://revistas.uepg.br/index.php/conexao/article/view/5677', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531cd', 'FISIOLOGIA NA EDUCAÇÃO DE JOVENS PARA A CIDADANIA', 'Schaedler, Fernanda Gabriela Leandro; Silva Nascimento, Verônica; Brandão Carvalho, Laisa; Caliman Filadelfi, Ana Maria', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O projeto visou ampliar a formação cidadã de jovens e consistiu no planejamento, aplicação e avaliação de dez temas de aulas (ex., puberdade e uso de drogas), estimulando o conhecimento e autocuidado com o corpo. As atividades foram ministradas no Centro Alvorecer Ação Social e Educacional (CAASE), que objetiva facilitar o acesso de jovens carentes ao mercado de trabalho, através de um Programa de Aprendizagem. Nosso projeto visou contribuir na formação dos jovens e ampliar a das acadêmicas da Universidade Federal do Paraná (UFPR), que participaram de todas as etapas do projeto. Objetivou-se também fornecer materiais didáticos aos educadores do CAASE, que poderão manter as atividades sem a participação da UFPR. Finalmente, dados foram obtidos sobre a avaliação do projeto pelos adolescentes, bem como sobre sua situação de empregabilidade; a coleta de informações sobre as condições gerais de sua saúde e seus vizinhos somaram-se ao artigo ampliando a compreensão do alcance desta ação.', 'https://revistas.uepg.br/index.php/conexao/article/view/6223', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531ce', 'PROJETO DE EXTENSÃO PREVEST/UVA', 'Medeiros, João Wellington Silva de; Martins, Nicolle Caroline Brasil; Falcão, José Sobrinho', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A existência de um cursinho pré-vestibular gratuito é almejada por muitos, mas poucos têm a iniciativa, que incentive as classes populares ingressarem no ensino superior. O PREVEST-UVA (Universidade Estadual Vale do Acaraú) tem suma importância para a população mais carente do Município de Sobral, Ceará. Pois, ajuda na transformação de um sonho: ingressar no ensino superior. O PREVEST UVA é uma vertente do Programa Universidade, Educação e Desenvolvimento Social, de responsabilidade da PROEX da UVA que objetiva ampliar as atividades voltadas à comunidade por meio de ações de extensão a serem desenvolvidas com a participação do corpo discente e docente da UVA e outros segmentos da comunidade (pessoa física, associações, ONGs e outras) de caráter voluntário, na área de ensino. O Projeto PREVEST UVA atende a comunidade externa em geral, focando alunos da escola pública que estejam cursando o 3° ano do ensino médio ou que já tenham concluído o ensino básico. Além do mais, o Projeto objetiv', 'https://revistas.uepg.br/index.php/conexao/article/view/6224', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531d3', 'TÊNIS DE MESA PARALÍMPICO: UMA PROPOSTA ESPORTIVA PARA PESSOAS COM DEFICIÊNCIA', 'Frank, Robson; Borella, Douglas Roberto', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Tendo em vista que o esporte está se transformando em uma ferramenta de êxito no que tange à inclusão social e educacional da pessoa com deficiência, o Programa UNIAFA – Atividade Física Adaptada na UNIOESTE – oferece propostas de atividades físicas às pessoas com deficiência. Deste modo, o presente estudo tem como objetivo abordar acerca da relevância da atividade tênis de mesa junto à essa população, relatando experiências e expondo os benefícios proporcionados aos mesmos.  As atividades são desenvolvidas no Campus de Marechal Cândido Rondon/PR, ocorrendo semanalmente. A população envolvida consta de sete (7) pessoas com deficiência física. Com esta iniciativa, além da possibilidade de proporcionar atividades físicas e esportivas para esta parcela da população, espera-se contribuir no que se refere ao incentivo ao esporte e qualidade de vida dessas pessoas, além de oportunizar a formação e qualificação de acadêmicos envolvidos enquanto monitores de tal projeto.', 'https://revistas.uepg.br/index.php/conexao/article/view/6270', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531dd', 'CONTRIBUIÇÃO DA EXTENSÃO AO ENSINO: LÂMINAS HISTOLÓGICAS DE ESPÉCIES MEDICINAIS COMO APOIO PEDAGÓGICO EM AULAS PRÁTICAS NA EDUCAÇÃO DA REDE PÚBLICA DO MUNICÍPIO DE ALTA FLORESTA/MT', 'Larroca, Diene Gonçalves; Alves, Sylvana Kety; Araújo, Cleonete Ferreira de; Dardengo, Juliana de Freitas Encinas; Ribeiro Junior, Norberto Gomes; Rossi, Ana Aparecida Bandini; Pessoa, Marcos José Gom', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Esse trabalho faz parte do projeto de extensão “Por dentro das Plantas do Portal da Amazônia” realizado entre 2011 e 2013 com unidocentes e docentes de Ciências e Biologia da rede pública do município de Alta Floresta/MT, com o objetivo de produzir lâminas semipermanentes de plantas medicinais ocorrentes no município como forma alternativa de ensino para ser aplicada em aulas práticas. Propôs também levantar características anatômicas, montar pranchas ilustrativas e entregar Kit para as escolas. O trabalho constou de cinco fases: contato com a secretaria de educação e com as escolas; entrevista com os docentes; escolha das espécies a serem estudadas; cursos de capacitação; entrega de kit. Observou-se grande carência de material histológico vegetal nas escolas para as aulas práticas e que os microscópios, apesar de presentes na maioria das escolas, não eram utilizados por falta de capacitação dos operadores. A partir do desenvolvimento das atividades propostas foram alcançados resultado', 'https://revistas.uepg.br/index.php/conexao/article/view/6724', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531de', 'PROJETO EXTENSIONISTA “ALIMENTAÇÃO SAUDÁVEL NAS ESCOLAS”: ELABORAÇÃO E ANÁLISE DE PRODUTOS COM ADIÇÃO DE PREBIÓTICO', 'Novello, Daiana; Lachman, Cauana; Silva, Érica Caroline da; Zanini, Celina Ducat; Santos, Elisvânia Freitas dos; Manhani, Maria Raquel', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Objetivou-se verificar a aceitabilidade sensorial de formulações de sorvete de banana adicionadas de inulina e determinar a composição físico-química do produto tradicional e daquele contendo inulina com aceitação sensorial semelhante a padrão. Foram desenvolvidas 5 formulações de sorvete de banana, sendo: F1 - padrão (0%) e as demais adicionadas de 6% (F2), 12% (F3), 18% (F4) e 24% (F5) de inulina. Participaram 58 provadores não treinados, sendo crianças de ambos os gêneros, com idade de 7 a 10 anos. Não houve diferença significativa entre as formulações, demonstrando boa aceitação sensorial. F5 apresentou maiores teores de umidade e fibra alimentar e menores de calorias comparada a F1. A elaboração dos produtos permitiu comprovar que um nível de adição de até 24% de inulina (redução de 100% do açúcar) em sorvete de banana foi bem aceito pelos provadores infantis, obtendo-se aceitação sensorial semelhante ao produto padrão e com boas perspectivas de comercialização.', 'https://revistas.uepg.br/index.php/conexao/article/view/6735', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531df', 'EXERCÍCIOS FÍSICOS PARA MULHERES EM TRATAMENTO DO CÂNCER DE MAMA', 'Rentz Keil, Patricia Morgana; Crocetta, Tania Brusque; Arab, Claudia; Andrade, Alexandro', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O presente estudo descreve o projeto “Exercício Físico no Tratamento do Câncer de Mama”, com ações destinadas a mulheres em tratamento do câncer de mama, e objetiva proporcionar melhor preparação física e psicológica a estas pacientes para o enfrentamento da doença e tratamento. Este projeto está vinculado Programa de Extensão “Psicologia do Esporte e do Exercício Aplicado à Saúde” do Laboratório de Psicologia do Esporte e do Exercício da Universidade do Estado de Santa Catarina. O projeto é composto por protocolo estruturado de exercício físico resistido (musculação) e aeróbico (caminhada), avaliações físicas e psicológicas periódicas e palestras informativas mensais. Há integração de ações de ensino – capacitação e orientação no trabalho com a população referida; extensão – exercícios, avaliações e palestras; e pesquisa, por desenvolver estudos na área de atividade física, saúde e psicologia do exercício.', 'https://revistas.uepg.br/index.php/conexao/article/view/6737', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cda32da1a94b3531e0', 'A EDUCAÇÃO EM SAÚDE NA PREVENÇÃO AO USO DE DROGAS', 'Rodrigues, Elisamara Ferreira; Silva, Amália Verônica Mendes da; Almeida, Ana Amélia Paolucci; Ricardo, Mônica Cândido Pereira; Detomi, Ana Luiza Silva; Silva, Janice Henriques da', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O artigo tem como objetivo apresentar as ações de educação em saúde, no âmbito da prevenção ao consumo de drogas, realizadas no projeto de extensão “GEMTI – Grupo de Estudantes que Multiplicam e Transformam Ideias”. As ações foram desenvolvidas com 318 alunos, divididos em 10 turmas com idade média de 15 a 19 anos, de duas escolas públicas de Belo Horizonte - MG. Foram desenvolvidas três intervenções por turma estabelecendose inicialmente a exposição do tema seguida por discussão com ampla participação dos alunos. Foram utilizados modelos anatômicos, recursos áudio visuais, imagens, esquemas e fotos com o intuito de “provocar a discussão” e levar a reflexão sobre as consequências diante das escolhas que trazem risco à saúde. Diante da participação dos alunos nas discussões, acredita-se que as ações realizadas pelo GEMTI repercutiram de maneira positiva permitindo a transmissão de conhecimento e a ponderação sobre o tema, mudanças de conceitos e hábitos de vida.', 'https://revistas.uepg.br/index.php/conexao/article/view/6741', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852cfa32da1a94b3531e6', 'JOGO DE XADREZ: CULTURA, DESENVOLVIMENTO DO RACIOCÍNIO LÓGICO E ESTÍMULO PARA A APRENDIZAGEM', 'Foppa, Nelson Kaus; Botan, Jonas; Assis, Luciana Mafalda Elias de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho apresenta algumas considerações sobre a inserção de um espaço cultural tendo como principal mediador o jogo de xadrez. A finalidade deste espaço cultural intitulado “Ponto do Xadrez”, consiste em oferecer aos seus participantes estudos teóricos sobre o jogo de xadrez e atividades que sejam motivadoras para sua prática. O “Ponto do Xadrez” está sendo desenvolvido na Universidade do Estado de Mato Grosso - Campus Universitário de Sinop e também, na Escola Estadual Olímpio João Pissinati Guerra, localizada no Município de Sinop. A partir da realização deste trabalho foi possível perceber algumas influências deste espaço cultural no cotidiano escolar de seus participantes. Alguns resultados indicam que é possível ensinar e praticar o jogo de xadrez de forma prazerosa, levando-se em conta o desenvolvimento das habilidades intelectuais de quem o pratica.', 'https://revistas.uepg.br/index.php/conexao/article/view/6761', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d1a32da1a94b3532f7', 'O PROTAGONISMO ESTUDANTIL NA EXTENSÃO UNIVERSITÁRIA: A EXPERIÊNCIA DO NÚCLEO DE ATUALIZAÇÃO PÚBLICA NA UNIVERSIDADE FEDERAL DO CARIRI', 'Lima Arrais, Estêvão; Antunes, Jeferson; Monteiro Ferreira, Jessica', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/16859', NULL, 'English', 'published', false, false, 'open', 'pdf')
