VALUES ('674852d3a32da1a94b353348', 'EXTENSÃO UNIVERSITÁRIA, FORMAÇÃO PROFISSIONAL E PROCESSO DE ASSESSORIA AO SISTEMA DE GARANTIAS DOS DIREITOS DE CRIANÇAS E ADOLESCENTES (SGDCA)', 'Lavoratti, Cleide', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/20122', NULL, 'English', 'published', false, false, 'open', 'pdf')
