VALUES ('674852d3a32da1a94b353354', 'MÁQUINAS QUE APRENDEM: DIVULGANDO TECNOLOGIAS À COMUNIDADE POR MEIO DA  EXTENSÃO UNIVERSITÁRIA', 'de Carvalho, Millena Lana Correia; Ekuni, Roberta; Valeze Elisbão do Nascimento, Gabriel; Miguel Nogueira de Souza, Bruno; Nagai, Mayla; Cardoso Carvalho Novaes, Thales', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/20808', NULL, 'English', 'published', false, false, 'open', 'pdf')
