INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353356', 'O QUE AS CRIANÇAS GOSTARIAM QUE VOCÊ SOUBESSE: UMA RODA DE CONVERSA SOBRE ANSIEDADE INFANTIL', 'Rossetti de Souza, Jamile; Queiroz Ale, Bruna; Martins, Jardielly Alencar Vasconcelos', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Ao tratar do binômio escola-família são comuns expectativas quanto a parcerias e a participação. Os debates atuais versam, predominantemente, sobre os papéis de ambas no processo educacional, bem como das mudanças que ocorreram nessas instituições socialmente construídas. Essa relação construída ao longo da história, foi se legitimando legalmente tanto na Constituição Federal como no ECA e na LDB. Neste contexto, o projeto de extensão “Minha família, minha escola e eu” foi elaborado com vistas a ampliar o diálogo e aproximar escola e família. Por meio de encontros mensais, foram desenvolvidas ações em seis rodas de conversa, com foco na partilhada de experiências, na discussão dos temas e no produzir de registros. O recorte aqui apresentado faz parte do quarto encontro de 2021, que teve como tema “Ansiedade infantil: o que as crianças gostariam que você soubesse”. Devido à pandemia de COVID-19, a ação foi desenvolvida por meio de plataformas digitais.', 'https://revistas.uepg.br/index.php/conexao/article/view/20957', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
