VALUES ('674852d3a32da1a94b353360', 'AÇÃO EM EXTENSÃO COMO PRÁTICA LIBERTADORA: EXPERIÊNCIA COM O TEMA DOS RESÍDUOS SÓLIDOS URBANOS NO ENSINO BÁSICO', 'Munaretto, Elisangela Christiane de Pinheiro Leite; Silva, Maclovia Corrêa da', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21488', NULL, 'English', 'published', false, false, 'open', 'pdf')
