INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b353362', 'A IMPORTÂNCIA DO TREINAMENTO DE DISCENTES PARA ATUAÇÃO NO PROJETO DE EXTENSÃO TRILHA FINANCEIRA', 'Silva dos Santos, Allisson; Braga Berenguer de Vasconcelos, Renata; Edival de Sousa, Signey Everton; Gomes Raposo Figueiredo, Jaciara; Martins da Silva, Renata Ellen', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho tem como objetivo relatar a importância do treinamento para a atuação no projeto de extensão Trilha Financeira, por meio das experiências discentes do Instituto Federal de Educação, Ciência e Tecnologia da Paraíba – IFPB. A construção deste relato perpassou pela análise de dados qualitativos e quantitativos, advindos dos estudantes de cursos superiores de Gestão Comercial e de Engenharia Civil e do curso técnico em Contabilidade. Diante do processo formativo executado, a maioria dos discentes se mostraram satisfeitos em relação aos aspectos gerais das capacitações. Além disso, eles consideram importante a participação em formações, antes dos integrantes de projetos de extensão entrarem em ação junto à comunidade. Os principais motivos para a preparação dos discentes são: maior segurança para entrar em ação, desenvolvimento do aprendizado e compreensão das finalidades do projeto de extensão como um todo.', 'https://revistas.uepg.br/index.php/conexao/article/view/21559', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
