VALUES ('674852d3a32da1a94b353368', 'PROMOÇÃO DA ATIVIDADE FÍSICA E SAÚDE ATRAVÉS DE PROJETO DE EXTENSÃO UNIVERSITÁRIA', 'Martinez Vargas, Leandro; Müller da Silva, Natally; Moleta Vargas, Thaiane; Goveia, Jean Carlos de; Dias da Silva , Amanda; Moreira do Carmo, Gonçalo Cassins', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21722', NULL, 'English', 'published', false, false, 'open', 'pdf')
