INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35336a', 'APRENDENDO A ENSINAR CIRCO: A CURRICULARIZAÇÃO DA EXTENSÃO UNIVERSITÁRIA E SEUS IMPACTOS NA FORMAÇÃO DOS DISCENTES', 'Araújo Oliveira, Natália; Ontañón Barragán, Teresa', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O estudo teve por objetivo compreender e acompanhar as vivências e aprendizagens dos discentes de um curso de Educação Física numa universidade pública, por meio da sua participação em um projeto de extensão que tinha como temática principal o ensino do circo para crianças. Contou com a realização de questionário e entrevista semiestruturada junto aos monitores participantes, no início e final do projeto, assim como observação participante das aulas. Os resultados mostram como o projeto contribuiu em várias dimensões da aprendizagem dos monitores, que adquiriram conhecimentos sobre o circo e sobre diversos aspectos didático-metodológicos. Por sua vez, as atividades circenses continuam se mostrando como um caminho interessante para abordar estes conhecimentos na formação inicial.
Palavras-chave: Extensão Universitária; Educação Física; Atividades Circenses; Circo.', 'https://revistas.uepg.br/index.php/conexao/article/view/21747', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35336b', 'A CURRICULARIZAÇÃO DA EXTENSÃO NO ÂMBITO DA UNIVERSIDADE ESTADUAL DO CENTRO-OESTE: PERCEPÇÕES DISCENTES', 'Limberger Meirinho, Bruno Mateus; Wichnoski, Paulo; Dall’Agnol Silvério, Eduardo; Soares, Matheus', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O novo paradigma que institui a curricularização de ações extensionistas em todos os cursos de graduação, coloca em evidência o papel da extensão na tríade organizacional das universidades brasileiras. No escopo dessa configuração, buscamos compreender como os acadêmicos do curso de licenciatura em matemática da Universidade Estadual do Centro-Oeste (UNICENTRO) percebem a curricularização da extensão a partir da experiência vivida com ela. A pesquisa se constituiu com a postura fenomenológica, cujo desdobramento revela percepções sobre as diferenças entre os contextos acadêmico e social-extensionista, evidenciadas pelas ações de extensão; percepções sobre os aspectos limitadores e, sobretudo, sobre os aspectos potencializadores, vistos e antevistos à medida que a extensão se consolide no referido curso como componente curricular.', 'https://revistas.uepg.br/index.php/conexao/article/view/21776', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d3a32da1a94b35336f', 'EXPERIÊNCIAS VIVIDAS DE GÊNERO, SEXUALIDADES E RAÇA EM UM CURSO DE EXTENSÃO SOBRE EDUCAÇÃO ANTIRRACISTA', 'Fernando Guimarães Oliveira da Silva, Fernando Guimarães Oliveira da', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este texto é oriundo do curso de extensão Pressupostos para a educação antirracista nas escolas, realizado em 2022, por intermédio do Núcleo de Educação Antirracista de uma Universidade pública sul-mato-grossense. Metodologicamente, abordou-se as ações do curso na perspectiva da decolonialidade com o objetivo de levar docentes em formação inicial e continuada a pensarem sobre a temática da educação antirracista a partir dos demarcadores sociais das diferenças no sudoeste sul-mato-grossense. A abordagem da pesquisa foi qualitativa com recursos de coleta, análise e interpretação dos dados baseados na experiência vivida, de modo que foi possível apresentar relatos docentes referentes a dois temas: 1) gênero e sexualidades e 2) raça. O curso teve duração de seis meses e 7 cursistas o concluíram: 4 alunas e 3 professoras da educação básica local. Como apontamentos conclusivos, destaca-se a necessidade de a educação antirracista ser um tema constante no processo formativo inicial e continuad', 'https://revistas.uepg.br/index.php/conexao/article/view/21834', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
