VALUES ('674852d4a32da1a94b353376', 'EXTENSÃO UNIVERSITÁRIA E POLÍTICAS PÚBLICAS PARA AGRICULTURA SUSTENTÁVEL EM COMUNIDADES TRADICIONAIS', 'Marcos Rodrigues Figueiredo, Adriano; Freitas de Oliveira Junior, Oséias', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/21954', NULL, 'English', 'published', false, false, 'open', 'pdf')
