INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b35337e', 'OS DESAFIOS E POTENCIALIDADES DA ATUAÇÃO PROFISSIONAL DO ASSISTENTE SOCIAL NO ÂMBITO DA EXTENSÃO UNIVERSITÁRIA: UM RELATO DA INCUBADORA DE EMPREENDIMENTOS SOLIDÁRIOS (IESOL/UEPG)', 'Aparecida da Silva Albach, Camila; Rolim de Moura, Reidy', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho é compreender os desafios e potencialidades da atuação do/a Assistente Social no programa de extensão Incubadora de Empreendimentos Solidários (IESol/UEPG). Esta pesquisa foi realizada no ano de 2022 e foi baseada nas ações profissionais realizadas na IESol/UEPG, que trabalha com economia solidária (ECOSOL) e refere-se ao programa extensionista ao qual este artigo está vinculado. A metodologia utilizada remete à pesquisa qualitativa, com atribuições da bibliográfica e de campo, por meio de entrevistas semi estruturadas, as quais serão utilizadas para mensurar as reflexões. Dentre os principais resultados citamos a importância da extensão como campo aos recém formados, o acolhimento ao público externo, a supervisão de estagiários/as, as controvérsias da autogestão, entre outros.
Palavras-Chave: Extensão Universitária; Serviço Social; Prática Profissional; Economia Solidária.', 'https://revistas.uepg.br/index.php/conexao/article/view/22139', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
