VALUES ('674852d4a32da1a94b353380', 'ZOOTERAPIA: O IMPACTO DOS ANIMAIS NA SAÚDE E BEM-ESTAR DAS PESSOAS COM TEA', 'Bogoni Meneghetti Nascimento, Mateus; Silvério da Silva, Samara; Krull Moreira, Luana; Mariana Souza Sampaio, Kézya; Grandi, Juliana; Victor Schmidt Grando, João', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/22167', NULL, 'English', 'published', false, false, 'open', 'pdf')
