INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353384', 'VALIDAÇÃO DE JOGO EDUCATIVO SOBRE PREVENÇÃO DE QUEDAS EM PESSOAS IDOSAS DA COMUNIDADE: ALIANDO EXTENSÃO E PESQUISA', 'Rubira Dias, Jhenicy; Gomes Labegalini, Célia Maria; Sescon Nogueira, Iara; Padoin Lopes, Larissa; Denardi Antoniassi Baldissera, Vanessa; Silveira de Almeida Hammerschmidt , Karina', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este artigo objetivou validar o conteúdo e a aparência de um jogo educativo sobre prevenção de quedas em pessoas idosas da comunidade. Trata-se de estudo metodológico e quantitativo, utilizando amostragem não probabilística intencional para escolha de juízes. O jogo foi desenvolvido como parte do projeto de extensão “Assistência domiciliar de enfermagem às famílias de idosos dependentes de cuidados”, da Universidade Estadual de Maringá/PR. Os dados foram processados no software R, sendo calculado o Índice de Validade de Conteúdo (IVC) para o conteúdo, e o percentil para aparência, além de teste binominal e cálculo do coeficiente de Alpha de Cronbach. A versão final do jogo apresentou IVC geral de conteúdo de 96,8% e nível de concordância da aparência de 96,4%. Os itens no teste binominal apresentaram estatística superior a 0,78%. O Alpha de Cronbach do conteúdo foi 0.873 e aparência 0.825. O jogo foi considerado validado, estando apto para ser utilizado enquanto tecnologia educacional ', 'https://revistas.uepg.br/index.php/conexao/article/view/22218', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
