VALUES ('674852d4a32da1a94b353386', 'O CICLISMO EDUCACIONAL NAS AULAS DE EDUCAÇÃO FÍSICA E A PERCEPÇÃO DE SATISFAÇÃO ESCOLAR DE ESTUDANTES DO ENSINO FUNDAMENTAL', 'Jacob Martins, Clóvis; Antunes de Lima, Mariza; da Silva Gasparotto, Guilherme', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/22232', NULL, 'English', 'published', false, false, 'open', 'pdf')
