INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b353388', '‘CRIP CAMP - A DISABILITY REVOLUTION’: UMA VIA PARA DESLOCAMENTOS POSSÍVEIS NAS LEITURAS DE ESTUDANTES SOBRE AS PESSOAS COM DEFICIÊNCIA', 'Branco Carnevale, Luciana', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'Este trabalho analisou dados provenientes da extensão “A pessoa com deficiência: diálogos a partir do cinema e de outras mídias audiovisuais” e teve como objetivo apreender e discutir afetabilidades produzida pelo documentário Crip Camp: A Disability Revolution (2020) na docente pesquisadora e nos estudantes. A cartografia proposta por Rolnik (2011) foi utilizada no percurso metodológico, uma vez que o território abarcado pela pesquisa é “existencial”. Foram analisados os registros e comentários relativos às cenas que mais afetaram os estudantes. Algumas temáticas relacionadas à problemática das pessoas com deficiência foram escolhidas pela pesquisadora, quais sejam: ‘A diferença’, ‘Tutela, privacidade, dependência e autonomia’ e ‘A revolução pela via da deficiência’. A experiência tratada neste estudo permitiu o abalo de pré-concepções sobre as pessoas com deficiência, o reconhecimento de sua biopotência, e a necessidade da produção das redes de relações implicadas para a produção do ', 'https://revistas.uepg.br/index.php/conexao/article/view/22252', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
