INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b35339a', 'PROJETO DE EXTENSÃO FANBIO: DIVULGAÇÃO CIENTÍFICA SOBRE BIOLOGIA', 'Gonçalves , Julia; Cezar Pinto , Marcelo; Pires Lima , Laura Cristina; Vendruscolo, Giovana Secretti; Javier Nieto Castellanos , Nestor; Schmitz, Hermes José', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A extensão universitária possui um papel importante na divulgação científica. A biologia é uma disciplina do ensino básico e uma área das ciências naturais que constantemente é veiculada pelos meios de comunicação. Porém, ela possui temas complexos e geralmente não é regionalizada. Em contrapartida, desperta muita curiosidade, principalmente das crianças. Neste contexto, o projeto de extensão FanBio (Fanáticos por Biologia) tem como objetivo produzir materiais e atividades lúdicas de divulgação científica sobre temas de biologia. Este trabalho visa relatar os materiais didáticos produzidos, em forma de fanzines, e a atividade da Semana do Meio Ambiente realizada em um shopping de Foz do Iguaçu, Sul do Brasil. As atividades do projeto pautam-se na exploração dos diferentes sentidos e da curiosidade das crianças, buscando experiências sensoriais e que ficam na memória. O projeto contou com a participação de professores e estudantes de diferentes cursos da UNILA, além do público em geral.', 'https://revistas.uepg.br/index.php/conexao/article/view/22592', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b35339d', 'OFICINA “FENÔMENOS FÍSICO-QUÍMICOS EM PREPARAÇÕES COM OVOS”: A GASTRONOMIA ATUANDO NA PROMOÇÃO DE DIÁLOGOS INTERDISCIPLINARES EM UMA ESCOLA DO INTERIOR DO RIO DE JANEIRO', 'Bastos Ribeiro da Silva, Bruno; Nascimento Matoso Souto, Renata', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/22713', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b3533a2', 'USO DE METODOLOGIAS ATIVAS PARA EDUCAÇÃO EM SAÚDE BUCAL PARA SURDOS: RELATO DE EXPERIÊNCIA EXTENSIONISTA', 'Rocha Aguiar, Aisa; Weyll Abijaude Mansur Gonzaga, Ruanna; Santos Lemos, Camila; Ribeiro dos Santos, Deborah Evelyn; Souza Silva, Thalia; Silva Junior, Manoelito Ferreira', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste relato de experiência foi descrever uma ação extensionista educativa de saúde bucal com metodologia ativa para surdos. A ação foi realizada por integrantes do ‘Projeto Sorrir’ da Universidade Estadual do Sudoeste da Bahia, em parceria com o Centro de Apoio Pedagógico de Jequié/BA. Participaram seis surdos. Inicialmente, apresentaram-se onze termos relacionados à saúde bucal com imagens/legendas e seus respectivos sinais em Língua Brasileira de Sinais (Libras). Durante a apresentação de cada termo, houve interação com o público-alvo sobre o contexto do termo, com colaboração de dois professores de Libras da instituição. Para verificação de aprendizagem e fixação dos termos, realizou-se o jogo das três pistas, em que, para cada termo, haveria três dicas, e os participantes deveriam descobri-lo, respondendo em Libras ou apontando as imagens. A ação possibilitou interação e benefícios no conhecimento de Libras e de saúde bucal, tanto para os surdos como para os discentes e', 'https://revistas.uepg.br/index.php/conexao/article/view/23101', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
