VALUES ('674852d4a32da1a94b3533b5', 'SARAU CONTEMPORÂNEO: UM ENCONTRO CIENTÍFICO-CULTURAL NO CONTEXTO PÓS-PANDÊMICO', 'Peterini Boeira, Silvana; Jesser Segat, Hecson; Campara Soares, Daiane; Beier Guedes, Julia; Giacomini Delatorre, Leonel', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/23764', NULL, 'English', 'published', false, false, 'open', 'pdf')
