INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('674852d4a32da1a94b3533b6', 'CURRICULARIZAÇÃO DA EXTENSÃO: DESAFIOS E POSSIBILIDADES', 'Maria Martins, Angela; Bagnoli Ovidio, Rosângela', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A curricularização da extensão nas Instituições de Ensino Superior é um processo que vem sendo implementado a partir da publicação da Resolução CNE/CES nº 7, de 18 de dezembro de 2018 (Brasil, 2018), que estabelece a destinação de 10% da carga horária total do curso às atividades de extensão. O presente artigo se propõe a analisar diferentes concepções do termo em pauta e suas definições ao longo do tempo, assim como identificar desafios e possibilidades para sua execução. Trata-se de um artigo de revisão sistemática, constituído por análise bibliográfica e documental, nos moldes da pesquisa qualitativa. Neste estudo, aborda-se a extensão de maneira indissociável ao ensino e à pesquisa, como forma de aproximação entre a universidade e a sociedade, promovendo interações e transformações.
Palavras-chave: Curricularização da Extensão; Extensão Universitária; Ensino, Pesquisa e Extensão.', 'https://revistas.uepg.br/index.php/conexao/article/view/23806', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67bc99d9e27dfa1251894da2', 'PROGRAMA DE EXTENSÃO UNIVERSITÁRIA NO ÂMBITO DA IMUNIZAÇÃO: A PRÁTICA, EDUCAÇÃO EM SAÚDE E SISTEMAS DE INFORMAÇÃO', 'Lima Júnior, José Ferreira; Marques de Abrantes, Kennia Sibelly; Santana, Adriano Freitas de; Lima Araruna, José Fellipe; Alves Cesar, Eduardo; de Sousa Leite, Eliane', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/23167', NULL, 'English', 'published', false, false, 'open', 'pdf')
