INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67bc99d9e27dfa1251894da3', 'O PAPEL DA EXTENSÃO UNIVERSITÁRIA NO FORTALECIMENTO DO VÍNCULO COM A COMUNIDADE E NA DIVULGAÇÃO DO CONHECIMENTO PRÁTICO SOBRE SAÚDE OCULAR', 'Takeshi Ebihara, Vinicius; Corá da Silva, Juliana; Battalini Silva, Carolina; Isabely Morgan Magalhães, Fernanda; Marcela Granai, Jaqueline; Patrícia Barbosa, Carmem', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O curso teórico-prático de dissecação do olho foi parte do projeto de extensão “A extensão favorecendo a saúde ocular: Exposição museológica sobre conhecimentos oftalmológicos primários ao alcance da sociedade externa à universidade” do Programa Institucional de Apoio a Inclusão Social – Pesquisa e Extensão da Fundação Araucária. O referido curso teve como objetivo promover a integração entre comunidade interna e externa da UEM, visando a disseminação do conhecimento anatomofisiológico do olho. A metodologia consolidou o saber teórico com a prática da dissecação de olhos de boi visando o melhor aproveitamento na expansão e aquisição de conhecimentos oftalmológicos básicos. Os resultados mostraram que ações de extensão universitária integrando teoria e prática contribuem sobremodo com a sociedade, com alunos e professores na dinâmica do aprendizado. Conclui-se que mais ações sociais são necessárias a fim de fortalecer o vínculo universidade-sociedade e contribuir para a disseminação da ', 'https://revistas.uepg.br/index.php/conexao/article/view/23182', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
