VALUES ('67bc99d9e27dfa1251894db5', 'USO DO DESIGN POR UM PROJETO DE EXTENSÃO DE ENFERMAGEM PARA A PROMOÇÃO DA SAÚDE DE PESSOAS COM ALBINISMO', 'Palko, Nereida; Vianna de Queiroz, Maria Eduarda', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/23817', NULL, 'English', 'published', false, false, 'open', 'pdf')
