INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6943cb2df2f3b972440792f4', 'ENSINO-PESQUISA-EXTENSÃO NA PÓS-GRADUAÇÃO: RELATO SOBRE UMA ATIVIDADE RECREATIVA COM BASE NA EDUCAÇÃO CTS – CIÊNCIA, TECNOLOGIA E SOCIEDADE', 'Jesus, Andreia de; Belfort Silveira Amaral, Beatriz; Dell Anhol Almeida, Leonelo; Rios Assis, Fernanda Regina; Abrahão Amaral, Marília', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'O objetivo deste artigo é relatar uma experiência empírica a partir de uma atividade recreativa/educacional, direcionada a estudantes do Ensino Fundamental 1. A atividade faz parte da ação extensionista (AE) “Entre telas, sons e saberes”. A ação é resultado da parceria entre universidade e entidade social, e seu planejamento teve origem em uma disciplina de pós-graduação. Para a elaboração das atividades, foi considerado o contexto educacional de contraturno, com a seguinte fundamentação teórica: dialogicidade e alteridade; estudos CTS e concepção freiriana de extensão. Além disso, o planejamento da AE conecta dois métodos, temas geradores e sequências didáticas, e recursos tecnológicos voltados a estudantes do Ensino Fundamental 1. O resultado satisfatório da AE foi possível devido a: identificação das reais necessidades de suporte à instituição parceira; planejamento de atividades com coparticipação dos atores; dialogicidade com a comunidade; avaliação dos resultados com os profissio', 'https://revistas.uepg.br/index.php/conexao/article/view/25562', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('682f1d639d0aa41653407658', 'PRODUÇÃO DA BATATA-DOCE POR AGRICULTORES CAMPONESES EM FONDWA, HAITI', 'Weirich Neto, Pedro Henrique; Lafontant, Ludsonde; Milien, Jean-Fritz; Rocha, Carlos Hugo; Gomes, Jaime Alberti; Souza, Nátali Maidl de', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', 'A batata-doce [Ipomoea batatas L. (Lam.)] é um alimento fundamental para segurança alimentar do Haiti. Visando processos de produção mais sustentáveis caracterizou-se o sistema de produção de batata-doce na Região de Fondwa, Haiti. Foram visitados 39 camponeses, onde aplicou-se questionário semi-estruturado. Esses relataram 28 genótipos, porém somente 12 foram identificados no campo. O sistema de produção é familiar, com contratação ocasional de mão de obra. Foram citadas duas pragas de importância, Cylas formicarius e o Conoderus vespertus. A produtividade apresentou médias variando de 1,22 a 2,99 Mg ha-1, confirmando a expectativa de baixos valores. Os camponeses ganham entre HTG$ 41.000 e 51.000 (entre US$ 410,00 e 510,00) por safra. Estratégias para desenvolvimento sustentável devem ser estudadas, uso de genótipos adaptados, plantas de cobertura, construção da fertilidade química, física e biológica do solo e sistemas agroecológicos são ações que podem ser implementadas.
Palavras-c', 'https://revistas.uepg.br/index.php/conexao/article/view/24386', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
