INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('69033490b901ffe5ca64cccd', 'REFLEXÕES SOBRE O PDI: CURRICULARIZAÇÃO DA EXTENSÃO COMO INSTRUMENTO DE AUTONOMIA ESTUDANTIL', 'Toigo Trentin, Daiane; Calabró, Luciana; Inês Pessini, Magali', 'Revista Conexão UEPG', 'Agriculture', 'Agriculture', '', 'https://revistas.uepg.br/index.php/conexao/article/view/24772', NULL, 'English', 'published', false, false, 'open', 'pdf')
