INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838ba98', 'Análise Físico-química e Microbiológica do Mel de Abelha', 'Neves, Ana Paula Morais; Costa, Rubenia de Oliveira; Almeida, Alany Moisa Bezerra de; Machado, Antônio Vitor', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mel de abelha é um produto alimentício de grande valor nutritivo e de alta aceitabilidade por parte do consumidor, principalmente por ser considerado um produto terapêutico e benéfico à saúde. Esse produto é elaborado pelas abelhas a partir do néctar das flores, ou de exsudações sacarínicas de outras partes vivas das plantas. A legislação brasileira define os padrões para o mel de abelhas melíferas, estabelecendo os requisitos mínimos de qualidade que o mel destinado ao consumo humano deve possuir, no entanto, o mel pode ser facilmente adulterado com a adição de açúcares e xaropes. A microbiota varia, tendo além de microrganismos introduzidos pelas próprias abelhas, outros introduzidos de forma indesejada por falta de higiene na manipulação ou durante a extração e beneficiamento do mel. Diante disso, a fiscalização da qualidade do mel através de análises físico-químicas e microbiológicas é de fundamental importância, uma vez que busca contribuir na identificação de fraudes e mudanças', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3679', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838ba99', 'Cadeia Produtiva do Mel de Abelhas: Fonte Alternativa de Geração de Renda para Pequenos Produtores e Qualidade Físico-química do Mel', 'Costa, Rubenia de Oliveira; Machado, Antônio Vitor; Queiroga, Cízia Fabiana Mouta Almeida de; Leite Filho, Francisco Germano', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A cadeia produtiva do mel de abelhas está apresentando um acentuado crescimento global, principalmente no Brasil. Destacando-se a produção de mel orgânico na região Nordeste. Sabemos que o mel é utilizado pelo homem como fonte de energia desde a pré-história. Por muito tempo era obtido por extrativismo predatório, o que causava geralmente danos aos ecossistemas locais. Com as novas técnicas de manejo os apicultores além de proteger o meio ambiente adquiriram uma fonte alternativa de renda, principalmente na agricultura familiar.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3681', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838ba9a', 'Conservação de Furtas através da Utilização do Açúcar', 'Nóbrega, Jessica Yasmine de Lacerda; Costa, Rubenia de Oliveira; Machado, Antônio Vitor; Sousa, Anne Izabelly Oliveira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Um método bastante utilizado para a conservação de frutas é a conservação pela adição de açúcar, no qual a preservação ocorre pela concentração das frutas resultando na redução de atividade de água para o desenvolvimento de microrganismos, promovendo estabilidade ao alimento. Assim, todo alimento conservado pelo uso de açúcar deve receber um tratamento complementar para sua conservação. Sabe-se que as frutas são importantes componentes para nossa dieta alimentar, pois são alimentos que apresentam cor agradável, sabor e amora exóticos, além disso, são fontes ricas em vitaminas, especialmente pró-vitamina A e vitamina C, minerais e carboidratos, sendo uma importante fonte nutricional para o organismo humano. Os processos de conservação baseiam-se na eliminação total ou parcial dos agentes que alteram os alimentos ou na modificação ou supressão de um ou mais fatores necessários a esses agentes deteriorantes, de modo que o meio torne-se não propício a qualquer manifestação vital. O trabalh', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3682', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838ba9c', 'Atividade Antimicrobiana da Própolis: Revisão Bibliográfica', 'Pordeus, Carla Rocha; Costa, Rubenia de Oliveira; Machado, Antônio Vitor; Almeida Neto, Isidro Patrício de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'No universo das abelhas entre os muitos produtos e substâncias produzidas, destaca-se a própolis, configurada como uma substância resinosa natural, produzida por abelhas melíferas a partir de exsudatos coletados em diferentes partes das plantas, com relatos de utilização desde as antigas civilizações dado as suas propriedades terapêuticas, tanto no organismo humano quanto em outros animais. Os resultados deste uso na medicina popular ao longo do tempo, tem suscitado pesquisas acerca da real ação antimicrobiana da própolis a qual se atribui propriedades antioxidantes, antimicrobianas, anti-inflamatórias, anti-cariogênicas e até mesmo anti-cancerígenas. Neste contexto, a presente pesquisa tem por objetivo conhecer e analisar alguns aspectos relacionados à ação anti-microbiana da própolis sobre certos microrganismos.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3684', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838ba9f', 'Sensibilidade de Agentes Bacterianos Patogênicos Frente à Ação Antibacteriana da Própolis', 'Silva, Ana Cláudia Cavalcante; Ricarte, Fernando da Silva; Costa, Rubenia de Oliveira; Machado, Antônio Vitor', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As propriedades biológicas da própolis são amplamente relatadas sendo comuns variações nas mesmas em função da região onde foram produzidas. A ação antimicrobiana de própolis tem sido investigada sobre linhagens isoladas de infecções clínicas humanas, a exemplo dos Staphylococcus aureus, Escherichia coli, Enterococcus sp, Pseudomonas aeruginosa e Candida albicans. Os resultados mostram maior sensibilidade das bactérias Gram positivas e levedura em relação às Gram negativas. É possível concluir que, para os microrganismos estudados e amostras de própolis testadas em diferentes estudos, há diferenças na atividade antimicrobiana em função do local de produção e que isso se explica pela diferença de composição química da própolis.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3687', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838baa5', 'Avaliação microbiológica de bactérias aeróbias mesófilas no leite in natura produzido em uma associação rural em Garanhuns-PE', 'Castanha, Elisângela R.; Claudino-Filho, Sérgio C.; Silva, Elizabel O.; Silveira-Filho, Vladimir Mota', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Um dos maiores problemas na produção leiteira do Brasil é o desvio negativo na qualidade do processo primário, que abrange todo o manejo inicial da ordenha, resultando em grandes perdas em toda a cadeia. Com o intuito de verificar tais perdas, realizou-se uma avaliação da qualidade do leite in natura em uma associação de cinco produtores rurais em Garanhuns/PE. Na contagem de aeróbios mesófilos, aplicou-se a diluição seriada junto à técnica pour plate. Além disso, foram realizadas coletas de swabs no tanque de resfriamento e coleta de água para análise microbiológica, coleta de leite para análise físico-química e verificou-se a adoção de boas práticas pelos produtores. Para a validação estatística dos dados, foram utilizadas a Análise de Variância e o Teste de Tukey (p ≤ 0,05), sendo observadas diferenças significativas na população de mesófilos entre os diversos leites dos produtores. Constatou-se que dois dos cinco produtores apresentaram o leite fora dos padrões exigidos, e que junt', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3835', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838baa6', 'Estudo do Efeito da Pectina Cítrica na Produção de Micotoxinas por Aspergillus niger URM3856', 'Silva, Jonatas Carvalho; Silva, Osmar Soares; Porto, Tatiana Souza; Pereira, Ellyda Thamirys de Lima; Souto, Maria Eugênia Meliano Medeiros', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pectina é um carboidrato presente na parede dos vegetais, em especial a lamela média, que confere rigidez a sua estrutura. É amplamente utilizada na indústria de alimentos como aditivo alimentar. Este trabalho objetivou avaliar o efeito da pectina cítrica na produção das aflatoxina e ocratoxina A produzida por Aspergillus niger URM3856 durante o processo de crescimento e esporulação. O fungo foi cultivado em meio Czapek contendo 1% de pectina cítrica. O controle foi realizado sem a pectina. A produção de aflatoxina foi verificada inoculando o fungo em meio MAC (ágar-coco) com observação de fluorescência por raios UVA. A ocratoxina ‘A’ foi verificada através da mudança de cor por vapor de amônia nos meios batata-dextrose-ágar (BDA), MAC e extrato de levedura-sacarose (YES) durante um período de 7 dias. O estudo mostrou que Aspergillus niger URM3856 é produtor apenas de aflatoxina e que a adição de 1% de pectina cítrica no meio de crescimento inibiu a produção da micotoxina durante o p', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3838', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838baab', 'Segurança do trabalho na indústria de alimentos: A sinalização como aspecto fundamental', 'Costa, Mariana A.; Braga, Maria do Carmo A.', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo abordar e expor questões referentes à segurança nas indústrias de alimentos, destacando a sinalização de segurança. Seu desenvolvimento justifica-se pelo índice elevado de ocorrências de acidentes de trabalho no setor. É comum trabalhos nesta área destacarem a segurança do produto sem enfatizar a segurança inerente ao processamento. No entanto, um alimento seguro é o resultado de uma série de etapas que começa na matéria-prima e termina nas prateleiras dos supermercados, portanto, é imprescindível que se olhe para esta temática com uma visão periférica. Conhecer os principais problemas e desafios enfrentados nas indústrias é do encargo do profissional de alimentos responsável por todas as etapas do processamento e atendimento às exigências do mercado, com segurança. Concluiu-se que o uso de cores na sinalização de segurança, juntamente com o planejamento e monitoramento eficientes dos diferentes espaços, são ferramentas essenciais para diminuição dos ri', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3846', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bab2', 'Análise de diferentes marcas de farinhas de trigo: Teor de acidez, cor e cinzas', 'Laurintino, Thaíris Karoline Silva; Gomes, Líbia Danielly Barro de Carvalho; Lima, Raquel Danúbia; Ribeiro, Daniele Silva; Silva, Anderson Felipe Viana da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A farinha de trigo é um produto altamente consumido no mundo, ela é o ingrediente principal da receita de alimentos como o pão, biscoitos, bolos, massas e macarrão. A sua qualidade é determinada por alguns parâmetros físico-químicos como a acidez, a cor e teor de cinzas. Uma farinha de qualidade normalmente apresenta baixa acidez, cor branca e baixo teor de cinzas. Foi feita a análise de seis diferentes marcas de farinhas de trigo encontradas à venda em estabelecimentos comerciais da cidade de Garanhuns - PE quanto a esses parâmetros e foi encontrado que de modo geral as amostras analisadas apresentam-se dentro dos padrões estabelecidos pela legislação para acidez e cinzas, sendo classificadas como farinhas do tipo 1, com exceção de uma das amostras (E) que apresentava valor de acidez um pouco acima do máximo estipulado. Já em relação a cor, as mostras apresentaram bons valores de luminosidade, o que significa que as farinhas se aproximam da coloração branca estabelecida como padrão de', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3855', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bab3', 'Elaboração de néctar misto de umbu-cajá, couve-flor e gengibre: caracterização físico-química e sensorial', 'Souza, Laura Gabrielle de; Rocha, Érica Milô de Freitas Felipe; Silva, Kaciana Maria da; Leite, Bianca Nogueira; Neves, Carmem Camilli Martins', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mercado de bebidas prontas tem crescido devido à mudança de hábitos dos consumidores, pois optam por alimentos práticos e rápidos que se adequem ao seu cotidiano. Sendo assim, esse trabalho visou a elaboração de um néctar misto de umbu-cajá, couve-flor e gengibre, agregando valor ao produto, e avaliar suas propriedades físico-químicas e sensoriais. Para isso, realizou-se as seguintes análises: acidez, pH, sólidos solúveis totais, umidade, cinzas e açúcares (totais, redutores e não redutores). Foram determinados, também, testes de aceitação e intenção de compra do produto. Os resultados demonstraram que o néctar desenvolvido apresentou um pH dentro da faixa ácida (≤ 4,5) e, os parâmetros de acidez, sólidos solúveis e açúcares totais estão de acordo com a legislação vigente, favorecendo a conservação do produto. Os valores de açúcares redutores (10.50%) e não redutores (1.35%) encontraram-se similares aos resultados verificados em outros trabalhos. Com relação a aceitabilidade, o produ', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/3873', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bab7', 'QUALIDADE DE LEITES PASTEURIZADOS COMERCIALIZADOS NA CIDADE DE ABREU E LIMA-PE', 'Fialho, Márcia Cristina Vieira; Ximenes, Graciliane Nobre da Cruz; Santos, Márcia Monteiro dos; Silva, Millany Rodrigues de Oliveira e; Campos, Jenyffer Medeiros; Cortez, Neila Mello dos Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar as características físico-químicas (densidade, acidez, pH, amido, formol e peroxidase) de quatro marcas de leites pasteurizados comercializados na cidade de Abreu e Lima – PE. Muitas pesquisas no Brasil têm demonstrado que a qualidade do leite produzido e comercializado nem sempre atinge os padrões exigidos e estabelecidos. Os riscos envolvem deste a presença de adulterantes adicionados de forma fraudulenta com o objetivo de mascarar uma baixa qualidade, a presença de microrganismos patogênicos e ainda de substâncias químicas como pesticidas e antibióticos. Os resultados demonstram alterações na densidade e pH nas amostras A, B e C, alterações na acidez titulável em grau Dornic nas amostras B e C, apresentando os demais parâmetros, amido, formol e peroxidase, em conformidade. A amostra D não apresentou nenhum tipo de irregularidade. Desta forma, verifica-se que o leite pasteurizado que está sendo comercializado na cidade de Abreu e Lima-PE, não é 100%', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4697', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bab8', 'Mastite bovina ocasionada por Staphylococcus aureus e suas implicações em saúde pública', 'Silva Viana, Márcia Gabrielle; Silva Teixeira, Camilla Mércia; Matias de Araújo, Maryella Laryssa; Pessoa de Albuquerque Ferreira, Cássia Thaís', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A mastite é a doença de maior importância econômica na produção leiteira, pois acarreta enormes prejuízos devido à perda da produção, perca da qualidade do leite, gastos com serviços veterinários e medicamentos. Pode ser ocasionada por diversas formas, porém a Staphylococcus aureus é relatada como a bactéria mais causadora da doença. A doença é um potencial problema a saúde pública devido aos resíduos de bactérias, antibióticos e suas toxinas que podem ser eliminadas no leite e prejudicar a saúde dos consumidores, além de acarretar prejuízos para a indústria láctea. O objetivo desse trabalho foi relatar as consequências da mastite bovina ocasionada pela Staphylooccus aureus e suas implicações com saúde pública devido à ocorrência de vários surtos alimentares pela bactéria.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4698', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bab9', 'BENEFÍCIOS NUTRICIONAIS COMPOSTOS NO LEITE E SEUS DERIVADOS PARA A POPULAÇÃO GERIÁTRICA', 'de Luna Siqueira, Ana Bolena; Silva Teixeira, Camilla Mércia; Matias de Araújo, Maryella Laryssa; Pessoa de Albuquerque Ferreira, Cássia Thaís', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os laticínios são alimentos nutricionalmente densos que fornecem quantidades relevantes em proteínas, vitaminas e minerais, sendo estes necessários, principalmente para a manutenção do crescimento ósseo por toda a vida. A alimentação rica em cálcio, tal como leite e outros derivados é importante para a determinação do auge da massa óssea e para o impedimento de um futuro risco de osteoporose e outros acometimentos na saúde. O presente estudo teve como objetivo analisar e relatar o papel do leite e seus derivados para a nutrição, manutenção e saúde do idoso que o consome. O consumo de alimentos lácteos favorece a saúde e a regulação do metabolismo ósseo, além de proporcionar outros efeitos satisfatórios relacionados à imunidade, massa magra, microbiota intestinal, entre outros. Sendo assim, é benéfica a sua utilização regular, levando-se em conta as alterações fisiológicas que acometem esse estágio da vida.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4699', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838babd', 'AVALIAÇÃO DOS RÓTULOS DE DIFERENTES MARCAS DE IOGURTE COMERCIALIZADOS NA CIDADE DE PAU DOS FERROS – RN', 'Lacerda, Cíntia Gabriela de Souza; de Oliveira, Emanuel Neto Alves; de Oliveira, Silvana Nazareth; Feitosa, Bruno Fonsêca; de Souza, Rosane Liege Alves; Mesquita, Jorge Henrique Andrade', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A rotulagem é uma importante área da Embalagem e Logística, que objetiva apresentar ao consumidor informações essenciais do produto comercializado, dentre as quais: ingredientes, nutrientes e validade. Como o iogurte é um alimento apreciado por todas as idades, é necessário que as informações estejam presentes para auxiliar o consumidor na compra, estas que devem seguir, especialmente, a legislação RDC nº 259, de 20 de setembro de 2002, e RDC nº 360, de 23 de dezembro de 2003. Desta forma, este trabalho objetivou analisar diferentes rótulos de nove marcas de iogurte em supermercados de Pau dos Ferros-RN, bem como, avaliar sua adequação conforme a legislação. Dentre as amostras avaliadas, apenas uma atendeu às exigências dos regulamentos, mesmo considerando que a ausência de informações no rótulo poderá induzir o consumidor ao erro, de modo que se torna necessária uma maior fiscalização dos órgãos responsáveis para garantir a segurança dos consumidores.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4709', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838babe', 'DESENVOLVIMENTO E ESTUDO CINÉTICO DA FERMENTAÇÃO DE IOGURTES PREBIÓTICOS', 'de Oliveira, Emanuel Neto Alves; de Oliveira, Silvana Nazareth; Feitosa, Regilane Marques; Feitosa, Bruno Fonsêca; de Souza, Rosane Liege Alves; Fernandes, Antônia Victória', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os benefícios do leite a saúde humana podem ser incrementados quando associa-se a processos fermentativos, como no iogurte, e ingredientes funcionais, a exemplo da inulina. Deste modo, a pesquisa objetiva desenvolver iogurtes prebióticos e estudar a cinética fermentativa. Para isso, elaborou-se 4 formulações de iogurtes prebióticos variando as concentrações de açúcar (4, 6, 8 e 10%) e avaliou-se o processo através do pH e acidez, bem como, os teores de lipídeos e proteínas. Ao longo da fermentação, houve diminuição do pH, ao passo que percebeu-se aumento da acidez. A análise de proteína sugeriu que os resultados diminuíram conforme aumentou-se a concentração de sacarose nas formulações. Além disso, os teores de lipídeos classificam o produto como desnatado segundo a legislação. Ajustando-se as curvas, percebeu-se que o modelo polinomial ajustou-se bem para os dois parâmetros, com valores de R2 superiores a 0,94 para pH e superiores a 0,99 para acidez.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4710', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838babf', 'ANÁLISE DO LEITE IN NATURA COMERCIALIZADO NO MUNICÍPIO DE TABOLEIRO GRANDE – RN', 'de Oliveira, Emanuel Neto Alves; de Oliveira, Silvana Nazareth; Almeida, Francisco Lucas Chaves; Feitosa, Bruno Fonsêca; de Souza, Rosane Liege Alves', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O leite por ser considerado o alimento mais perfeito da natureza apresenta composição química rica em nutrientes essenciais a alimentação humana, mas que também aumenta significativamente o risco de contaminação e adulterações. Assim, o presente trabalho teve como objetivo avaliar a qualidade de amostras de leite cru comercializadas na cidade de Taboleiro Grande-RN. As análises realizadas no produto foram: densidade, determinação de extrato seco, determinação de acidez em ácido láctico, determinação qualitativa de amido, determinação qualitativa de peróxido de hidrogênio). Observou-se então a partir dos resultados uma variação em diversos parâmetros, sendo que todas as amostras apresentaram ausência de amido e peroxido de hidrogênio e estabilidade ao etanol. No entanto 40% apresentaram-se fora dos padrões para acidez e densidade.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4711', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bac2', 'Rótulagem de queijos coalho comercializados em Pau dos Ferros-RN', 'Santos, Joyce Eunice Freitas; de Oliveira, Emanuel Neto Alves; de Oliveira, Silvana Nazareth; Fernandes, Aline Elvina Rodrigues; Dias, Andressa Rafaelly Maia; de Oliveira, Danielle Bezerra', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O queijo coalho é um produto obtido através da coagulação do leite por meio do coalho ou enzimas coagulantes. Eles devem ser acondicionados em embalagens plásticas contendo lista de ingredientes, identificação do lote, identificação de origem, entre outras informações que são importantes para o consumidor. Sendo assim, objetivou-se avaliar os rótulos e embalagens de nove marcas de queijo coalho. Levando em conta as informações obrigatórias que devem conter nos rótulos, apenas uma marca forneceu todas as informações necessárias no rótulo, representando 11,11% do total de embalagens observadas.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4715', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bac5', 'AVALIAÇÃO FÍSICO-QUÍMICA DO SORO DE QUEIJO COALHO PRODUZIDO NO MUNICÍPIO DE JUCATI – PE', 'Silva, Maria Fernanda; Moraes Neto, Venâncio Ferreira; Libório, Pedro Rocha', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho teve como objetivo a caracterização e avaliação da qualidade físico-química do soro de queijo coalho produzido no município de Jucati-PE. Os experimentos foram realizados nos laboratórios de química e de física da UFRPE/UAG. As amostras foram submetidas à determinação de acidez °Dornic, pH, teor de umidade, teor de cinzas, atividade de água e teor de lactose. Todas as variáveis analisadas atenderam aos parâmetros exigidos pela legislação. Assim, é possível se escolher o uso mais adequado deste resíduo como complemento alimentar no futuro, além de contribuir com o meio ambiente e a comunidade.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4723', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bac7', 'INFLUÊNCIA DO COMPORTAMENTO REOLÓGICO EM PROPRIEDADES FÍSICO-QUÍMICAS DO SORO DE QUEIJO COALHO DO MUNICÍPIO DE JUCATI – PE', 'Da Silva, Suzana Pedroza; Neto, Venancio Moraes; Da Silva, Maria Fernanda; Libório, Pedro Rocha', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo desse trabalho foi verificar a influência do comportamento reológico das propriedades físico-químicas pH e acidez titulável do soro, proveniente da fabricação de queijo coalho de pequenas unidades de produção do município de Jucatí. Na fabricação do queijo, em torno de 85 a 95% do volume do leite utilizado resulta em soro de queijo que é descartado pelos produtores, podendo ser destinado para a produção de diferentes produtos. Durante a verificação do comportamento reológico as variáveis dependentes pH e Acidez, não sofreram grandes variações, no entanto foi notado que a medida que a temperatura e rotações aumentaram, o valor do pH aumentou e consequentemente a acidez diminuiu, o valor de pH máximo obtido foi de 6,64, uma diferença de apenas 0,25 a mais do valor inicial, não influenciando de forma significativa para uso em outros alimentos.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4725', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838baca', 'TEXTURA DE QUEIJO DE COALHO IMPREGNADO DE AROMAS DE VINHO', 'DE MELO, BRUNO DAVINCI NUNES; MORAIS, SAMARA DE MACÊDO; NETO, JOAO CASSIMIRO; AMARAL, JOÃO BOSCO SOUSA; BRAGA, ANA LUÍZA MATTOS; DA SILVA, FRANKLIN JOSÉ PERES', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo produzir um queijo coalho com aroma de vinho e estudar a composição centesimal e as características de textura instrumental no produto final. Para tanto, foram produzidas duas amostras de queijo coalho, sendo que, uma das amostras foi submetida a um período de infusão e a outra não passou por nenhum tratamento diferenciado (queijo coalho branco). As amostras foram avaliadas através de composição centesimal, pH e textura instrumental (TPA e Compressão uniaxial em alta deformação). A textura do queijo impregnado de aroma foi diferente do queijo coalho tradicional, assim como o teor de pH e composição de gordura e umidade. Este queijo aromático mostrou-se mais duro, menos elástico e coeso.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4731', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bacb', 'ANÁLISE FÍSICO-QUÍMICA DE LEITE EM PÓ DESNATADO COMERCIALIZADO NA CIDADE DE GARANHUNS-PE', 'CHINELATE, Gerla Castello Branco; Dos Santos, Elyson José Neves', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Foram realizadas as determinações de umidade, acidez total e gordura em três marcas de leite em pó desnatado. As amostras foram adquiridas no comércio da cidade de Garanhuns/PE. Os teores de umidade variaram de 2,52 a 4,33 g/100g, os de gordura de 0,00 a 0,76 g/100g e a acidez total de 16 a 17 ºD. O objetivo deste trabalho foi realizar a analise de diferentes marcas de leite em pó desnatado verificando se os mesmo estão de acordo com a legislação vigente.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4734', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bacd', 'ELABORAÇÃO E AVALIAÇÃO SENSORIAL DO QUEIJO PETIT SUISSE SABOR CAJÁ, SEM ADIÇÃO DE GORDURA', 'Sulino, Reginaldo Ferreira; CHINELATE, GERLA Castello Branco', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Avaliar a aceitação sensorial do queijo Petit Suisse sem gordura, elaborado com três concentrações de polpa de cajá (10, 20 e 30%) foi o objetivo do estudo. Noventa e três julgadores participaram do teste de aceitação sensorial em que avaliaram os atributos de aparência, aroma, cor, sabor, textura e aceitação global. A preferência e a intenção de compra dos consumidores também foram avaliadas. De acordo com a análise estatística não houve diferença significativa para os atributos avaliados, entre as formulações ao nível de 5% de significância, exceto para o atributo textura da formulação com 10% de polpa. Todas as formulações do queijo Petit Suisse tiveram boa aceitação global e não diferiram estaticamente entre si ao nível de 5% de significância. A adição da polpa de cajá contribuiu para a boa aceitação do Petit Suisse, tornando-o uma boa opção para aqueles que procuram uma alimentação com baixo teor de gordura.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4752', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bad1', 'Rotulagem de Derivados Lácteos em Acordo com as Novas Legislações da Anvisa', 'Ximenes, Graciliane N.C.; Nascimento, Ítalo R.S.; de Farias, Tatianne Andrade Leonam; Cortez, Neila M.S.; Campos, Marcia J.; Oliveira, Keliane Lima', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho teve o intuito de avaliar os rótulos das embalagens dos produtos derivados do leite disponíveis em supermercados da região metropolitana de Recife, buscando a concordância destes com a Resolução ANVISA/RDC Nº 26 (BRASIL, 2015) e com a Lei Nº 13.305 (BRASIL, 2016). Foram analisados 397 produtos lácteos, dentre eles amostras de leite UHT, leite em pó, achocolatados, leites fermentados, queijos e requeijões. A rotulagem nutricional de alimentos auxilia o consumidor permitindo que ele conheça a composição do alimento e dessa forma tenha acesso a informações que impactam diretamente a segurança e saúde de quem se alimenta. A linguagem dos rótulos fornece dados do produto ao cliente, indicando quando a caso de ingredientes que podem ser alergênicos ou ocasionarem alguma intolerância. Dos produtos vistoriados observou-se que ainda há um baixo percentual de produtos adequados às novas regras de rotulagem, apenas 3,8% no universo de 397 amostras.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4763', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bad7', 'Cookies Made with Galactomannans and Xyloglucans from Leguminosae Seeds', 'Pereira Martins, Jéssica Roberta; Lima dos Santos, Nayanne; Chastinet Braga, Renata; Silva, Francisca Andrea Kercia; Lima Chaves, Maria Juciene', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os polissacarídeos são aplicados em diversos tipos de alimentos. Estas macromoléculas são consideradas como fibras dietéticas. Este trabalho objetivou enriquecer cookies com polissacarídeos de sementes regionais. A composição centesimal, análise físico-química e sensorial foram realizadas para a caracterização dos cookies. De acordo com os resultados, apenas o teor de proteína não diferiu estatisticamente entre os cookies. Quando comparado com o padrão, o biscoito preparado com polissacarídeo de Adenanthera pavonina indicou uma maior quantidade de fibra assim como o teor de umidade. O biscoito com polissacarídeo de Hymenaea courbaril apresentou mais diferenças quando comparado ao padrão, com uma diminuição no teor de gordura e acidez, além de maior umidade e cinzas. Na análise física, observou-se que os biscoitos nos quais se adicionou polissacarídeo tiveram sua espessura aumentada e seu diâmetro diminuído. Eles também tinham uma perda de peso menor em comparação com o padrão. Pela aná', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/4824', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bad8', 'RELATO DE EXPERIÊNCIA: ANÁLISE DE ALIMENTOS EM DEBATE', 'da Silva, Suzana Pedroza; Melo, Juliana Hellen da Silva; Silva, Marcelo Edvan dos Santos; da Silva, Angelica Simplício; Costa, Emerson Rodrigues', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A discussão temática foi promovida por alunos do Curso de Engenharia de Alimentos da UFRPE/UAG visando estimular os discentes ao desenvolvimento de suas habilidades analíticas e decisórias, expondo-lhes a situações rotineiras na vida do profissional desta área. Este trabalho consistiu na elaboração/seleção, apresentação e discussão de casos envolvendo Análises de Alimentos desenvolvidos por discentes e docentes, publicados em anais de eventos e revistas, assim como em artigos científicos e experiências na indústria de alimentos. Foram contemplados todos os alunos, principalmente alunos do primeiro ao quarto período, onde ocorre maior número de evasão. Os alunos do quinto e sexto período participaram na condição de instrutores do debate. Esta foi a primeira edição do projeto, entretanto, esperamos que seja reeditado anualmente, principalmente por causa da evidente motivação e relatos positivos entre todos os envolvidos, o qual promoveu conhecimento e interação.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5004', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bae2', 'CARACTERIZAÇÃO FÍSICO-QUÍMICA DE AGUARDENTE COMPOSTA DE CASCA DE ZIZIPHUS JOAZEIRO', 'da Silva, Suzana Pedroza; da Silva, Thayná Torres; Amaral, Yuri Matheus Silva; Almeida, Cinara Vanessa de Muniz; Gomes, Suellen Arlany Silva', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Aguardente composta é uma bebida com teor alcoólico entre 38 e 54% em volume, com adição de substância de origem vegetal ou animal. O Juazeiro (Ziziphus joazeiro Mart.-Rhamnaceae) é uma planta de pequeno a médio porte presente na caatinga brasileira, sendo utilizada desde a medicina popular ou mesmo em shampoo e creme dentais, principalmente por causa de sua ação saponificante. Este trabalho teve como objetivo caracterizar físico-quimicamente amostras de aguardente composta de casca de Z. joazeiro produzidas na cidade de Ibirajuba-PE. Foram realizadas as análises de densidade relativa, grau alcoólico, acidez total, acidez fixa, acidez volátil, pH, extrato seco, cinzas, sólidos solúveis totais e análise visual das amostras de aguardente, todas seguindo metodologia do Instituto Adolfo Lutz. De acordo com os resultados, foi verificada a boa qualidade da bebida. Entretanto, sugere-se para futuros trabalhos, realizar análises de ésteres, aldeídos, somatório de furfural, açúcares, alcoóis su', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5109', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838bae9', 'ELABORACÃO E CARACTERIZAÇÃO FÍSICO-QUÍMICA DE SUCO MISTO DE CAJU COM BETERRABA', 'Feitosa de Figueiredo, Rossana Maria; Carmo de Lima, Ana Raquel; da Silva, Raphaela Maceió; Dos Santos, Francislaine Suelia', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O suco misto de frutas e hortaliças é uma tendência de mercado e vem sendo estudado revelando suas características nutricionais e funcionais da mistura. Objetivou-se com este trabalho elaborar sucos mistos de caju com beterraba. Foram elaboradas três formulações de sucos mistos nas seguintes proporções: F1 - 20% suco de caju e 80% suco de beterraba; F2 - 50% suco de caju e 50% suco de beterraba; F3 - 80% suco de caju e 20% suco de beterraba. Os sucos mistos de caju e beterraba foram classificados como alimentos ácidos (F3), 3,7 &lt; pH &lt; 4,5, e pouco ácidos (F2 e F3), pH &gt; 4,5; alimentos com alta umidade (aw  &gt; 0,9) e alta relação SST/ATT. O suco F3 apresentou o maior teor de sólidos solúveis totais e teor de minerais (cinzas). Diante disso, a elaboração dos sucos mistos de caju com beterraba apresentaram resultados tecnicamente ajustados, recomendando-se sua produção, sendo considerada como uma alternativa promissora para o aproveitamento do pedúnculo do caju.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5124', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9d50e69ae81838baec', 'CARACTERIZAÇÃO FÍSICO-QUÍMICA DE FARINHAS DE FRUTAS TROPICAIS', 'Feitosa de Figueirêdo, Rossana Maria; de Melo Queiroz, Alexandre José; Andrade Araújo, Karoline Thays; da Silva, Raphaela Maceió; da Silva, Renato Costa', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Objetivou-se elaborar farinha a partir das cascas de abacaxi, banana, melão e laranja e caracterizá-las físico-químicamente. O experimento foi conduzido no Laboratório de Armazenamento e Processamento de Produtos Agrícolas, da Universidade Federal de Campina Grande, Campina Grande-PB. Foram utilizados resíduos domésticos das cascas, estas foram secas em estufa de secagem com circulação de ar por convecção, na temperatura de 60 ºC. As cascas após o processamento de secagem foram trituradas em liquidificador industrial, peneiradas e armazenadas em embalagens à vácuo até o momento de realização das análises físico-químicas, onde determinou-se os seguintes parâmetros: teor de água, pH, acidez total titulável, teor de cinzas, atividade de água (aw), sólidos solúveis (°Brix) e cor pelo sistema CIELAB expressa em L*, a* e b*. Utilizou-se o programa ASSISTAT versão 7.7 para a análise estatística dos dados, aplicando-se o teste de Tukey ao nível de 5% de significância.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5127', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838baf1', 'TOXICIDADE DA FARINHA DO RESÍDUO DE SEMENTES DE CAROLINA', 'Figueirêdo, Rossana Maria Feitosa de; Queiroz, Alexandre José de Melo; Silva, Raphaela Maceió da; Araújo, Karoline Thays Andrade; Santos, Francislaine Suelia', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A descoberta de novas fontes de matéria-primas alimentícias oriundas de resíduos agrícolas vem sendo contemplada com cada vez mais estudos tendo em vista a necessidade de se dar destino adequado aos descartes e por constituir materiais com grande potencial econômico. Os resíduos de uma extração gerados no processamento de matérias-primas geralmente tem granulometria maior que o objeto da extração e muitas vezes contém nutrientes importantes.Objetivou-se com este estudo avaliar a toxicidade da farinha do resíduo de sementes de Carolina sob bioensaio com Artemia salina. O experimento foi conduzido no Laboratório de Armazenamento e Processamento de Produtos Agrícolas (LAPPA) da Universidade Federal de Campina Grande (UFCG), Campina Grande-PB. Para análise de toxicidade foi utilizado o método do bioensaio sob método da Artemia salina, por meio de incubação, exposição e contagem. Os resultados foram submetidos a tratamento estatístico utilizando o Probit, o qual forneceu os valores de DL50.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5133', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838baf5', 'AVALIAÇÃO DE ROTULAGEM DE QUEIJO DE COALHO NAS REGIÕES AGRESTE E SERTÃO DE PERNAMBUCO, BRASIL', 'Araújo, Milena Eduarda Santos Lins; Godone, Roberta Luciana Nascimento; Santos, Yeda Hellen Monarderlles; Wanderley, Maria Carolina Albuquerque; Monteiro, Hyago Freitas', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O queijo de coalho é um dos produtos artesanais mais comercializados na região Nordeste do Brasil, principalmente Pernambuco. Esse fato chama atenção para a necessidade de informar corretamente o consumidor sobre os aspectos nutricionais do produto. O objetivo do trabalho foi avaliar as informações nutricionais e obrigatórias contidas nos rótulos de queijos de coalho tipos A (produzido com leite pasteurizado) e B (produzido com leite cru), selecionados aleatoriamente nas cidades de Arcoverde, Catende e Garanhuns. Foram avaliadas 22 marcas diferentes, sendo 10 marcas do tipo A e 12 do tipo B. Informações nutricionais importantes como teor de sódio, colesterol, gorduras estavam ausentes em muitas marcas. Informações obrigatórias nos rótulos como prazo de validade, data de fabricação e ausência de glúten também estavam em desacordo com a legislação. Dessa maneira, é importante que a fiscalização seja mais ativa nos produtos de origem artesanal, principalmente o queijo de coalho.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5140', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838baf6', 'BLEND DE POLPAS DE UMBU E JAMELÃO NA PRODUÇÃO DE ESTRUTURADO', 'Almeida de Souza, Silvia Maria; Oliveira Mascarenhas, Angélica Maria de; Acosta Martinez, Ernesto; Freitas de Jesus, Gabriela; Peruch Camilloto, Geany', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Alimento estruturado ou “engineered food” são geralmente produzidos com matérias-primas de baixo custo, oriundas de frutas que se encontram fora de classificação para comercialização in natura ou excedentes de produção durante o período de safra. Os hidrocolóides como alginato, pectina e gelatina, irão atuar como agentes de união, facilitando o corte e retendo umidade, contribuindo para a melhoria da textura. O presente trabalho tem como objetivos estudar o efeito da massa de pectina, alginato e gelatina na formulação do estruturado de um mix de polpas de umbu e jamelão: um produto inovador para ser comercializado pelos agricultores aumentando assim sua renda. E possível produzir estruturados de mix de polpas de umbu e jamelão com atividade de água entre 0,60 e 0,71; firmeza entre 55 e 125 g e elasticidade entre 37 e 50%.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5141', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bafa', 'OBTENÇÃO E CARACTERIZAÇÃO DE ACEROLA EM PÓ PELO MÉTODO FOAM MAT', 'de Almeida, Elizane Melo; Barros de Carvalho Gomes, Líbia Danielly; de Oliveira, Silvana Nazareth', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A aceroleira (Malpighia emarginata) é uma planta de clima tropical cujos frutos apresentam alto teor de vitamina C, além de ser rica em antocianinas e de baixo valor calórico. Entretanto, a acerola apresenta uma maturação rápida com perda de sua firmeza (textura) e tem sua coloração, sabor e aroma modificados. Nesse contexto, a secagem em camada de espuma surge como método capaz de prolongar a vida útil e impedir a deterioração e perda do valor comercial. Este trabalho teve como objetivo a caracterização física e físico-química da espuma de acerola, bem como a caracterização físico-química dos pós obtidos pelo método de secagem em camada de espuma em diferentes temperaturas. Conforme os resultados obtidos, a espuma de acerola apresentou over run superior à 100%, estabilidade de 99,56% e densidade de 0,419 g/cm3 que foi ideal para o processo de secagem. Os pós de acerola podem ser classificados como alimentos ácidos.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5154', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bafe', 'CONTROLE DE QUALIDADE DO PERCENTUAL DE BIXINA EM COLORÍFICOS COMERCIALIZADOS EM CAMPINA GRANDE', 'Luiz, Márcia Ramos; Jacinto Almeida, Raphael lucas; Santos, Newton Carlos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A Bixina é o carotenoide mais utilizado pela indústria alimentícia. É extraída convencionalmente das sementes do urucum sendo utilizado diretamente na produção de coloríficos. O colorífico é um condimento amplamente utilizado na culinária brasileira onde o atributo mais importante na sua comercialização é o impacto visual causado pela cor. Dessa forma, o objetivo deste trabalho foi avaliar a qualidade dos coloríficos comercializados em Campina Grande – PB em relação ao teor de bixina através da leitura em espectrofotômetro. Das amostras analisadas, houve uma variação muito grande nos resultados, sendo uma apresentando quase o dobro de outra. Não há na Legislação vigente uma padronização da quantidade utilizada deste pigmento nos coloríficos comercializados, por isso a importância desse estudo, fazendo-se uma reflexão da necessidade da implantação de uma legislação específica para padronização desse produto.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5161', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838baff', 'AVALIAÇÃO DA ROTULAGEM DE MORTADELAS FATIADAS COMERCIALIZADAS EM PIRANHAS-AL', 'Moura, Rodrigo Leite; Dos Santos, José Marcos Sousa', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A legislação brasileira define rotulagem como toda inscrição, legenda, imagem ou toda matéria descritiva ou gráfica, escrita, impressa, estampada, gravada, gravada em relevo ou litografada ou colada sobre a embalagem do alimento. Objetivou-se nesse trabalho, verificar se a rotulagem praticada na comercialização de mortadelas fatiadas pelos três principais estabelecimentos do ramo, no município de Piranhas-AL, se adequam aos critérios exigidos pelas legislações SMG nº 554 de 13 de julho de 2001 e RDC nº 360 de 23 de dezembro de 2003. Considerando a SMG nº 554, 100% dos estabelecimentos estavam em desacordo com o especificado na legislação para as informações descritas. Com relação à RDC nº 360, este tipo de produto apresenta-se isento de rotulagem nutricional. Os três mercados apresentaram falhas nos rótulos dos alimentos fatiados e embalados, tanto na presença, como na ausência do cliente mostrando a falta de fiscalização por órgãos competentes acarretando em possíveis danos aos direit', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5165', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb00', 'AÇÃO ANTIMICROBIANA DE EXTRATOS PRODUZIDOS A PARTIR DE FUNGOS FILAMENTOSOS SOBRE Staphylococcus aureus ISOLADOS DE MASTITE BOVINA', 'Teixeira, Renato Henrique Florêncio; Moraes Neto, Venancio Ferreira de; Silva, Rodrigo Henrique Fidelix; Lima, Marilene da Silva; Nunes, Ana Paula Rodrigues', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A mastite, inflamação da glândula mamária, gera preocupações por ser uma enfermidade que causa prejuízos na produção leiteira. O objetivo desse estudo foi testar a ação antimicrobiana de extratos produzidos a partir de fungos filamentosos, sobre estirpes de Staphylococcus aureus isoladas de bovinos com mastite. Nesse experimento foram utilizados os fungos Penicillium roqueforti 40074 e Penicillium camemberti, em dois meios sólidos diferente, produzindo quatro tipos de extratos aquosos (PCAC, PCTC, PRAC, PRTC). Estes foram testados frente as estirpes, do microrganismo e aquelas que apresentaram sensibilidade foram submetidas a um novo teste com discos de antimicrobianos comerciais. Os extratos PRAC e PRTC não demonstraram atividade sobre as estirpes. Os extratos PCAC e PCTC inibiram 30% e 40% dos microrganismos, respectivamente. O antibiótico mais eficaz frente as cepas foi o Meropenem com halo de 27,2. A penicilina apresentou menor halo, 3mm.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5166', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb03', 'AVALIAÇÃO DA COMPOSIÇÃO GRAXA PRESENTE NO FEIJÃO GUANDU TORRADO E MOÍDO', 'da Silva, Suzana Pedroza; da Silva, Maria Fernanda; Vieira, Januacele Dos Santos; Silva, Marcelo Edvan dos Santos; da Silva, Angélica Simplício', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O feijão guandu (Cajanus cajan) é um tipo de leguminosa facilmente encontrada no interior do Nordeste brasileiro. Sua aplicação é vasta na área agronômica e para alimentação animal, sendo menos exploradas as formas para consumo na alimentação humana. Este trabalho foi desenvolvido com o objetivo de avaliar a composição graxa presente no feijão guandu torrado e moído artesanalmente. Foram realizadas as análises de índice de acidez (IA), teor de ácidos graxos livres (%AGL) e índice de saponificação (IS), para fins de consumo como bebida por infusão. Foi observada uma boa relação entre os valores de IA (1,6 mgNaOH/g), %AGL (1,13 mgNaOH/g) e IS (147,50 mgNaOH/g) quando comparado a outras espécies como o café, indicando que a bebida pode ser preparada por infusão e consumida na alimentação humana.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5171', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb05', 'MODELAGEM CINÉTICA DA FERMENTAÇÃO DA CERVEJA', 'Fernandes da Silva, João Henrique; Prohmann Tschoeke, Isabelle Cristine; Gomes, Glêce Milene Santana; Costa Souza, Thibério Pinho; Cavalcanti, Jorge Vinícius Fernandes Lima', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O consumo da cerveja está enraizado aos hábitos de consumo alimentar há séculos, entretanto apenas nos últimos 150 anos sua produção e consumo tornaram-se expressivos entre as bebidas alcoólicas. O desenvolvimento deste trabalho teve como objetivo verificar o efeito da adição de nitrogênio proteico e do pH na fermentação alcóolica da cerveja avaliando o seu comportamento fermentativo em termos de produção de etanol. Foi realizado um planejamento fatorial 22, com ponto central, para avaliar o efeito do nitrogênio proteico e do pH na fermentação. A produção de etanol alcançou o ponto máximo do processo fermentativo com valor final de 38,6 g/L. O modelo cinético proposto se ajustou bem aos resultados experimentais podendo ser usado para cervejas do tipo lager.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5173', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb0c', 'CARACTERIZAÇÃO FÍSICO-QUÍMICA E AVALIAÇÃO SENSORIAL DE PITAIA (Hylocereus undatus) CULTIVADA NO AGRESTE MERIDIONAL PERNAMBUCANO', 'Fernandes da Silva, João Henrique; Barbosa de Souza, Íris; Moura da Silva, Mairon; Laranjeira Soares, Sâmia Joyce; Santana Gomes, Glêce Milene', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pitaia fruto exótico da América Central e do Sul foi introduzida no Brasil nos anos 90 e recentemente passou a ser cultivada na região do Agreste Meridional Pernambucano. A espécie Hylocereus undatus, também conhecida como pitaia branca, foi analisada quanto as características físico-químicas e sensoriais. Conforme os resultados descritos a seguir, a pitaia foi caracterizada quanto ao teor de sólidos solúveis (8,1° Brix), pH (4,2), acidez total titulável (3,13%), umidade (87,45%), cinzas (0,72%), açúcares redutores (9,92%) e não redutores (1,32%). A avaliação sensorial demonstrou que a pitaia é uma fruto bem aceito pelos julgadores, confirmado pelos Índices de Aceitabilidade para os atributos Aparência, cor, sabor, textura e impressão global superior a 70%. Além disso, a maiorias dos julgadores (56,41%) afirmaram o interesse em comprar o fruto em estudo. Diante do estudo realizado, conclui-se que a pitaia é uma fruto promissor.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5188', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb0e', 'ESTUDO DA DESIDRATAÇÃO OSMÓTICA DA BATATA DOCE (IPOMOEA BATATAS)', 'de Oliveira Alves, Thálita Cristyne; Martins, Pierre Corrêa; do Carmo, Amanda Silva', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo desse estudo foi determinar uma condição otimizada para a desidratação osmótica de fatias de batata doce utilizando soluções aquosas ternárias contendo sacarose e cloreto de sódio para as variáveis de operação: temperatura, tempo, concentração de solutos e de cloreto de sódio. As fatias foram colocadas em recipientes com as soluções desidratantes e acondicionados em uma incubadora com controle de agitação e temperatura. Foi utilizado um delineamento experimental estatístico fatorial do tipo 24 para as variáveis de operação, cujos parâmetros de avaliação foram a Perda de massa, Perda de umidade, Redução da atividade de água e duas Relações de desempenho adotadas para a operação. Os resultados demonstraram que as concentrações de soluto e de sal e a temperatura são as variáveis de operação mais significativas. Os valores médios da faixa ótima dessa operação são: 50 oC, 50% em peso de solutos, 8% em peso de sal e 140 min.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5192', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb12', 'AVALIAÇÃO DO EFEITO ANTIMICROBIANO DO ÓLEO ESSENCIAL DE CRAVO EM FILMES DE POLI (CLORETO DE VINILA)', 'Malta, Sanderson Hudson da Silva; Carvalho, Daiane de Souza; Vinhas, Glória Maria; DE LIMA, MARÍLIA SILVA DUARTE; Caetano, Viviane Fonseca', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Novos sistemas de embalagens de alimentos podem incluir substâncias com propriedades antimicrobianas que ajudam na preservação do alimento, além de prolongar seu tempo de prateleira.  Para o desenvolvimento desses sistemas, agentes com ação antimicrobiana são incorporados ao polímero. Uma alternativa de agentes antimicrobianos naturais são os óleos essenciais (OEs). Esses vêm sendo avaliados com sucesso para fins de embalagens antimicrobianas.  Neste trabalho foi avaliado a ação antimicrobiana do óleo essencial de cravo (OEC) em filmes de poli(cloreto de vinila). Os filmes de PVC puro e PVC/OEC foram analisados por FTIR e determinados os grupos funcionais em ambos os filmes. A atividade antimicrobiana apresentou total inibição do filme PVC/OEC para a bactéria E. coli. Os resultados obtidos indicam que os filmes incorporados com o agente antimicrobiano tem grande potencial para ser aplicado na área alimentícia.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5198', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb15', 'ELABORAÇÃO E CARACTERIZAÇÃO DE SORVETE SABOR CHOCOLATE UTILIZANDO FARINHA DE BANANA VERDE COMO SUBSTITUTO DE GORDURA', 'Delvaz, Caroline; Rodrigues, Alice Elaine Nunes; Ribeiro, Daniele Silva; Chinelate, Gerla Castello Branco', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo desta pesquisa foi avaliar a elaboração e caracterização de sorvete de chocolate substituindo a gordura por farinha de banana verde (FBV) através de análises físico-químicas como: teor de carboidratos, cinzas, lipídios, proteínas, umidade, fibras, overrun, taxa de derretimento e valor energético total (VET). Foram elaboradas três formulações: controle (100% de gordura); F1 (50% de gordura e 50% de FBV); e F2, (100% de FBV). Os sorvetes de formulação F1e F2 apresentaram VET reduzido em mais de 25%, podendo ser considerado pela legislação um alimento light, além de apresentar uma boa quantidade de fibras. A FBV também proporcionou menor taxa de derretimento às formulações elaboradas. Diante dos resultados conclui-se que é viável a inserção de FBV como substituinte de gordura, na formulação de sorvete de chocolate, pois pode agregar valor, dispondo de um produto light, rico em fibras e de reduzida taxa de derretimento no mercado.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5201', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb17', 'APLICAÇÃO DE FERRAMENTAS DA QUALIDADE NO CONTROLE DE PERDAS NA ETAPA DE ENCHIMENTO DO PROCESSO PRODUTIVO DE UMA INDÚSTRIA DE BEBIDAS DE PEQUENO PORTE', 'de Araújo Silva, Claudia Valéria; Santos Sales, André Felipe de Melo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi estudar, definir e propor melhorias no processo de envase de bebidas em uma indústria da cidade de Garanhuns – PE, utilizando-se ferramentas da qualidade: folha de verificação, gráfico de Pareto e diagrama de Ishikawa. O método utilizado foi o estudo de caso, tendo caráter descritivo, exploratório e explicativo. Após o acompanhamento da linha de produção, pôde-se analisar os dados, através das ferramentas da qualidade, e observar que o principal problema relacionado à linha de envase foi a quantidade de garrafas sujas, ocorrendo com maior frequência (80,8%). Esta falha evidenciou a necessidade de retrabalho, representando-se um custo de falha interna. A principal sugestão encontrada para o problema foi à adesão de inspetores eletrônicos após a lavagem das garrafas. A utilização da gestão da qualidade e outras técnicas de melhoria contínua podem significar rápidas mudanças e baixo investimento, reduzindo-se desperdícios e aumento da produtividade.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5203', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb20', 'ELABORAÇÃO, ANÁLISE FÍSICO-QUÍMICA E SENSORIAL DE QUEIJO SIMBIÓTICO FRESCO E DEFUMADO', 'Santos, Aldeci França Araujo dos; Oliveira, Rodrigo lira; Porto, Camila souza; Dantas, Willamys Rafael Santos; Porto, Tatiana souza', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mercado consumidor está avançando com relação a demanda por alimentos simbióticos, de boa qualidade nutricional e produtos produzidos de forma artesanal. A justificativa para a elaboração de queijos frescos e defumados simbióticos foi desenvolver um produto alternativo que proporcionasse benefícios aos consumidores, uma vez que tais elementos estimulam seletivamente a proliferação de bactérias desejáveis no intestino. Este trabalho foi desenvolvido com o objetivo de elaborar queijos artesanais, fresco e defumado com adição de probiótico e prebióticos, assim como caracterizar físico-químicamente e avaliar sensorialmente a aceitabilidade dos mesmos. Os queijos foram elaborados com a mistura de mix de fibras (frutoligossacarídeos, Inulina e Polidextrose) e cultura comercial probiótica. Os produtos desenvolvidos não apresentaram diferenças significativas para os parâmetros físico-químicos quando comparados com a literatura, apresentando na analise sensorial o índice de aceitação acima de', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5231', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb21', 'ANÁLISE DE CAROTENOIDES DA POLPA IN NATURA E DESIDRATADA DE FRUTOS DE TRÊS ESPÉCIES ALIMENTÍCIAS E MEDICINAIS OCORRENTES EM PERNAMBUCO', 'Medeiros, Rafael Augusto Batista; Silva, Raquel Barbosa; Silva-Júnior, Edvaldo Vieira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O bacupari (Garcinia brasiliensis Mart.), o biribá (Annona mucosa Jacq.) e o araçá (Psidium guineense Sw.) apresentam um potencial teor de carotenoides devido a sua coloração. Tendo em vista isto, objetiva-se verificar o teor de carotenoides destes frutos antes e depois da desidratação. A polpa dos frutos sofreram desidratação a 70 °C até atingirem 15% de umidade em estufa com circulação de ar forçado. Foi verificado sua umidade e seu teor de carotenoides in natura e após a desidratação. As frutas em estudos não diferiram significantemente no teor de umidade. Quanto aos carotenoides, o bacupari apresentou maior média de carotenoides, tanto in natura quanto desidratado (191,8  e 480,4 mg/100 g, respectivamente). A desidratação acarretou em perdas consideráveis dos carotenóides, entretanto os produtos desidratados destes frutos ainda retiveram altos teores deste pigmento.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5232', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb25', 'PERFIL DE TEXTURA DE MARCAS COMERCIAIS DE MAIONESE', 'Almeida, Renata Duarte; Firmino Romão da Silva, Luis Paulo; de Sousa Rodrigues, Larissa Monique; Ferreira Constantino, Jamilly Salustiano; Vieira, Agdylannah Felix', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A constante busca por alimentos de qualidade e práticos que se adequem as preferências dos consumidores impulsiona o mercado a inovar em novas técnicas para avaliação e obtenção dos mesmos, nesse ramo os molhos, como a maionese, estão em ascensão. Com isso objetivou-se com o estudo avaliar o perfil de textura de diferentes marcas comerciais de maionese nas temperaturas de comercialização e de refrigeração após aberto para consumo. Observou-se que os maiores valores para os parâmetros avaliados foram obtidos na temperatura de refrigeração mesmo que a diferença entre esta e a temperatura ambiente (25ºC) tenham sido pequenas. As três marcas avaliadas apresentaram valores distintos entre si com relação aos parâmetros estudados, e podem se adequar as preferências de diferentes tipos de consumidores.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5238', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb28', 'AVALIAÇÃO FISICO-QUÍMICA E DE TEXTURA INSTRUMENTAL DE GELEIA MISTA DE JABUTICABA E PITANGA', 'Almeida, Renata Duarte; Firmino Romão da Silva, Luis Paulo; de Sousa Rodrigues, Larissa Monique; Ferreira Constantino, Jamilly Salustiano; Vieira, Agdylannah Felix', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O processamento de polpa e a fabricação de geléias são produtos de interesse comercial para a região nordeste do Brasil. Este trabalho teve por objetivo desenvolver geléias mista de polpa de jabuticaba e de pitanga, com diferentes proporções em sua formulação, avaliando as características físicas e físico-químicas apresentadas por esse produto. As amostras foram elaboradas com diferentes proporções de polpa de jabuticaba (30, 50, 70 e 100%) e polpa de pitanga (70, 50, 30, 100%) com adição de 0,5% de pectina. As elaboradas foram analisadas quanto ao teor de pH, sólidos solúveis totais, acidez titulável e textura instrumental. A caracterização físico-química apresentou resultados dentro do padrão da legislação para a geleia e similares a trabalhos encontrados na literatura.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5241', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb29', 'AVALIAÇÃO SENSORIAL DE ACEITABILIDADE DO IOGURTE ARTESANAL SIMBIÓTICO', 'Porto, Camila Souza; Matos, Heloisa; Oliveira, Rdrigo L; Porto, Tatiana Souza; Andrade, Vanda Duarte', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O iogurte é obtido por meio de fermentação sendo muito frequente na mesa dos consumidores em todo o mundo. A suplementação da dieta com iogurte contendo prebiótico e probióticos (simbióticos) pode favorecer ao equilíbrio da microbiota intestinal humana, uma vez que estimulam seletivamente a proliferação ou atividade de populações de bactérias desejáveis no cólon, assegurando um papel importante na saúde dos indivíduos. Portanto o uso de simbióticos faz-se necessário para que o intestino tenha um funcionamento ótimo e para que haja um equilíbrio entre as populações bacterianas benéficas. Assim, o objetivo deste trabalho foi avaliar sensorialmente os iogurtes simbióticos sabor maracujá e natural, bem como a sua aceitabilidade. Os resultados das formulações dos iogurtes simbióticos apresentaram boas notas na análise sensorial, bem como nos índices de aceitação e intenção de compra, demonstrando o potencial para comercialização de novos produtos funcionais.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5242', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb2b', 'CARACTERIZAÇÃO FÍSICO-QUÍMICA DO SUCO CLARIFICADO DE ABACAXI E AVALIAÇÃO SENSORIAL DO VINHO DE ABACAXI E GENGIBRE', 'Cadengue, Tamires Pessoa Neves; Ribeiro, Daniele da Silva; da Silva, João Henrique Fernandes; Gomes, Glêce Milene Santana; Silva, Giselle de Carvalho', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O desenvolvimento desta pesquisa objetivou produzir um vinho de abacaxi e gengibre, estudando as características físico-químicas do suco clarificado, a aceitação sensorial e a intenção de compra do produto final. O suco integral de abacaxi apresentou características físico-químicas: pH (3,52±0,03), sólidos solúveis totais (13,40±0,0) e acidez total titulável (0,55±0,0%). Durante a fermentação o pH, que tem relação inversa com a acidez, houve um aumento gradativo, passando de 3,49±0,03 no início para 3,66±0,06 ao final da fermentação (72h). Na análise sensorial, o vinho recebeu média global 6,92 (“gostei ligeiramente”). O Índice de Aceitabilidade foi de 76,9% e 36,6 % dos provadores alegaram que provavelmente/certamente comprariam o vinho. A análise sensorial e intenção de compra revelaram que é necessário um aperfeiçoamento da técnica quanto às características sensórias, proporcionado uma bebida mais adocicada, com sabor e aroma de fruta mais acentuados e, consequentemente, com maior a', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5244', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb2c', 'SECAGEM DA CASCA DE MANGA TOMMY ATKINS: COEFICIENTE DE DIFUSIVIDADE EFETIVO E MODELAGEM MATEMÁTICA', 'Nóbrega André, Anastácia Maria Mikaella Campos; Rodrigues, Larissa Monique de Sousa; Almeida, Renata Duarte; Constantino, Jamilly Salustiano Ferreira; Vieira, Agdylannah Felix', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O aproveitamento de resíduos como matéria-prima para a produção de alimentos processados surge como uma alternativa para reduzir o desperdício de alimentos. O presente trabalho foi realizado com o objetivo de secar a casca da manga variedade Tommy Atkins, nas temperaturas de 50, 60 e 70 ºC e estudar o ajuste de modelos matemáticos de secagem aos dados experimentais. O coeficiente de difusividade efetiva (Def) na secagem da manga Tommy Atkins, estimado pelo modelo Fick, aumentou com a elevação da temperatura, os valores do coeficiente de difusividade efetiva obtidos nesta pesquisa variaram entre 6,6611x10-10 a 16,383x10-10 m2. s-1 para o teor de água inicial analisado, a energia de ativação para difusão líquida para manga Tommy Atkins foi de 38,061 kJ mol-1. Dentre os modelos avaliados e conforme os resultados obtidos para os coeficientes de determinação ajustado, a equação de Page seguida pela equação de Henderson e Pabis foram as que melhor representaram os dados experimentais para de', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5245', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb2e', 'Estudo das condições de conforto térmico em escolas públicas municipais de tempo integral na cidade de João Pessoa – PB', 'Diniz dos Santos, Gabrielle; Dutra Furtado, Gil; Silva dos Santos, Joel; Sousa Gonzaga, Bruno; Almeida da Silva, Ingrid', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A alteração dos constituintes de recobrimento do solo por materiais impermeáveis, o alto crescimento urbano e a consequente supressão da vegetação urbana, vem modificando ainda mais o microclima urbano e tornando críticas as condições de conforto térmico nos centros urbanos e áreas habitacionais. Atualmente boa parte das escolas públicas de tempo integral na cidade de João Pessoa/PB sofre as consequências das alterações no campo térmico urbano da cidade. Dessa forma, o estudo do conforto térmico em escolas públicas de tempo integral na cidade de João Pessoa\PB é de suma importância para a compreensão do desenvolvimento das atividades educativas e rendimento escolar dos alunos. Sendo assim, o objetivo principal deste trabalho é verificar o Índice de Conforto Térmico (IDT) em três escolas de tempo integral da cidade de João Pessoa/PB. Para a realização da pesquisa, foi feito o reconhecimento e caracterização das três amostras experimentais: Escola Municipal de Ensino Fundamental Cônego J', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5555', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb2f', 'ESTUDO DA PRECIPITAÇÃO DO SEMIÁRIDO BAIANO USANDO ANÁLISES DE AGRUPAMENTO E DISTRIBUIÇÃO DE PROBABILIDADE', 'da Silva Melo, Valneli; Mainar de Medeiros, Raimundo; Pereira Dantas, Milena; Dayane Silva do Ó, Kely', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A precipitação é de soberana importância aos estudos climáticos, pois quando determinada em excesso ou deficiência, provocam calamidades aos setores: agropecuário, agronegócio, irrigação, geração de energia, armazenamento, represamento e abastecimento humano e socioeconômico entre outros. Utilizaram-se os dados pluviais mensais de 91 postos no período de 1984 a 2014 (31 anos). Os dados tratados foram submetidos a análise de agrupamento e os mesmos geraram três regiões homogênea de estudo. O objetivo deste trabalho foi testar o ajuste de diferentes funções de distribuição de frequência à precipitação média anual. Foram testadas as distribuições de probabilidade Exponencial, Gumbel I, Gama, Log-normal, Normal, Weibull, Lojística, Beta entre outras. A série de dados utilizados foram obtidos da base de dados da Superintendência do Desenvolvimento do Nordeste (SUDENE) e Agencia Nacional das Águas (ANA). A aderência das distribuições foi testada pelo teste de Kolmogorov-Smirnov ao nível de 5', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5556', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb30', 'CARACTERIZAÇÃO PLUVIOMÉTRICA, PRECIPITAÇÕES MÁXIMAS E BALANÇO HÍDRICO PARA DIFERENTES REGIMES PLUVIOMÉTRICOS EM MESOREGIÕES DE PERNAMBUCO', 'Antônio Assunção Montenegro, Abelardo; Júlio Machado Guimarães, Miguel; Lopes, Iug; Gonçalves Leal, Brauliro; Maria Medrado de Melo1, Juliana; Lopes, Breno', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho tem por objetivo analisar o ajuste dos dados de precipitação máxima anual à distribuição de extremos de Gumbel, estimar as precipitações máximas anuais para os períodos de retorno, identificar, por meio da técnica de Quantis, o perfil da precipitação e a sua variabilidade temporal e espacial, além da realização do balanço hídrico para as classes quantílicas em diferentes mesorregiões de Pernambuco. O maior valor de precipitação anual registrado na região do Sertão foi de 1275,7 mm, o menor de 156,1 mm para os anos de 1985 e 1993, respectivamente. Já na região Agreste, o ano 2010 foi o ano mais chuvoso, com 1446 mm, e 2015 o ano mais seco, com apenas 362,2 mm. Na região litorânea, os anos de 2004, com 2532,7 mm, e de 1998, com 1249,7 mm, foram os que apresentaram maior e menor precipitação anual, respectivamente. Com a técnica de Quantis observa-se observar que as séries históricas estudadas possuem precipitações anuais médias Q(0,50) de 524,2; 863,9 e 2296,9 mm, par', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5557', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb3b', 'Painel têmporo-espacial e box-plot para a análise da pluviosidade na região do Cariri Paraibano', 'Jaricélia Sena, Jaricélia Patrícia de Oliveira Sena oliveira; Lucena, Daisy Beserra Lucena Beserra; Neto, João Miguel Moraes Neto Moraes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A região semiárida apresenta alta irregularidade de chuvas, falta de acesso à água, longos períodos de estiagens e secas recorrentes, afetando diretamente toda a população e a economia da região. Diante do exposto, o objetivo deste trabalho é conhecer um pouco sobre a variabilidade, anomalia e verificação de anos padrões (seco, habitual e úmido) do regime pluviométrico através do painel têmporo-espacial e do gráfico do box-plot para a microrregião do Cariri Paraibano. Estes métodos são bastante simples e permitem gráficamente a análise exploratória dos dados e identificação de eventos padrão. O range utilizado para classificação dos anos super seco e super úmido foi de 5% a 95%, respectivamente. Os resultados confirmam que a região apresenta uma acentuada distribuição pluviométrica tanto temporal como espacial. A partir do cálculo utilizando o box-plot para o período interanual, foram identificados dois eventos extremos, que destacam-se do restante da série de dados, o ano de 1993, ano', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5589', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb3f', 'CARACTERIZAÇÃO FÍSICA E FÍSICO-QUÍMICA DE FRUTOS DE PIMENTÃO COM DIFERENTES COLORAÇÕES', 'Lucena, Maria Laura; Lopes, William Eugênio; de Medeiros, Erika Valente; Chinelate, Gerla Castello Branco; Lopes, Maely Nunes; Bernardo, Desirée Bridgitt de França', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O Pimentão é um fruto de suma importância para o mercado econômico brasileiro, este fruto possui uma ampla faixa de aplicação em indústrias e na culinária. Porém, os consumidores têm sido mais rigorosos quanto às exigências no padrão de qualidade dos alimentos a serem consumidos, principalmente os consumidos in natura. Alguns atributos de qualidade dos produtos comercializados são fatores determinantes na hora da compra. Além disso, vem crescendo a procura por pimentões de diferentes colorações, abrangendo um mercado consumidor diferenciado que pode pagar por produtos com valor agregado. Por isso, o objetivo do presente estudo foi avaliar a qualidade física e físico-química de pimentões com diferentes colorações. Para isso, foram coletadas amostras de pimentões de cores diferentes (verde, amarelo e vermelho) comercializados em Garanhuns, Pernambuco. O delineamento experimental utilizado foi inteiramente ao acaso com três tratamentos, distribuídos em esquema fatorial 3 x 1, sendo três n', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5915', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb40', 'DEMANDA DE CONSUMO DE ÁGUA NO MUNICÍPIO DE SÃO BENTO DO UNA – PE, BRASIL', 'de Holanda, Romildo Morant; Medeiros, Raimundo Mainar de; de França, Manoel Vieira; ferraz, juan xavier', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'ResumoO consumo de água para diversos usos e a poluição dos mananciais contribui de forma efetiva para a redução da disponibilidade de água doce, tornando-se fator limitante para o desenvolvimento. A deficiência hídrica e os elevados custos para a busca por novas fontes de água torna necessária a realização de políticas públicas voltadas ao uso racional desse recurso. A reutilização d’água constitui-se em prática de armazenamento, racionalização, uso e de conservação de recursos hídricos, com a capacidade de reduzir a descarga de poluentes em corpos receptores, conservando esses recursos para o abastecimento de água e outros usos mais exigentes quanto à qualidade. Objetiva-se a realizar análise da influência da variabilidade climática na demanda de água no município de São Bento do Una. A metodologia adotada consistiu em duas etapas: na primeira realizou-se toda a caracterização da área estudada, com informações obtidas a partir de pesquisas ao site do Instituto Brasileiro de Geografia', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/5927', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb43', 'ELABORAÇÃO E CARACTERIZAÇÃO FÍSICA DE PETIT SUISSE PREBIÓTICO DE LEITE DE BÚFALA FERMENTADO COM KEFIR', 'Santos, Rebeca Morais Silva; De Sousa, Francisca Moisés; De Almeida, Renata Duarte; Gusmão, Thaisa Abrantes Souza; Alves, Jéssica Ingrid Da Silva; De Gusmão, Rennan Pereira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O petit suisse é um queijo fresco, geralmente consumido como sobremesa no Brasil e bastante apreciado principalmente pelo público infantil, representa uma alternativa para o processamento de derivados de leite a partir do kefir, sendo possível a sua elaboração com leites provenientes de diferentes espécies, como o leite de búfala. O objetivo desta pesquisa foi à elaboração e a caracterização física (cor e perfil de textura) de queijo petit suisse a partir de leite de búfala fermentado com kefir, utilizando-se inulina como substância prebiótica. Foram elaboradas três formulações com diferentes concentrações de inulina: F1 = 5%, F2 = 10% e F3 = 15%. Na análise de cor verificou-se que a inulina torna as amostras mais claras, em vista de sua coloração branca que dilui os pigmentos contidos no produto. O comportamento dos parâmetros de textura avaliados foi influenciado pela adição de diferentes concentrações de inulina, ou seja, sofreu um crescimento diretamente proporcional com a adição d', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/6259', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb44', 'MATURAÇÃO FISIOLÓGICA DE TOMATE CEREJA', 'Monteiro, Shênia Santos; Martins, Laesio Pereira; Silva, Elnatan Alves da; Monteiro, Shirley Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O tomate é um dos frutos mais produzidos e consumidos no Brasil, em decorrência das características sensoriais e nutricionais. Porém, possui alta perecibilidade, o que se deve, principalmente ao estágio de maturação dos frutos, influenciando diretamente na sua vida pós-colheita e na escolha por parte do consumidor. Diante disso, o presente trabalho teve como objetivo avaliar os compostos bioativos do tomate cereja em função dos estádios de maturação. O experimento foi realizado no Setor de Agricultura da Universidade Federal da Paraíba, Campus-III, Bananeiras-PB. Foi utilizado o delineamento inteiramente casualizado, com quatro repetições. Foram avaliadas as variáveis: cor, ácido ascórbico (mg.100.g-1), clorofila a e b (mg.100.g-1), licopeno (mg.100.g-1) e', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/6265', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb47', 'QUALIDADE FÍSICO-QUÍMICA DO TOMATE SUBMETIDO A DIFERENTES TIPOS DE ARMAZENAMENTO', 'Xavier, Layra C.A.; de Medeiros, Erika Valente; Berguer, Lúcia Raquel Ramos; Chinelate, Gerla Castello Branco; Gueiros, Marcos André F', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do presente estudo foi avaliar os atributos físicos e os sólidos solúveis totais (SST) de tomates comercializados em mercados de pequeno a grande porte na cidade de Garanhuns-PE e submetidos à diferentes formas de armazenamento. Os frutos foram coletados, aleatoriamente, em quatro tipos de estabelecimentos comerciais (quitanda, mercado de pequeno porte, mercado de grande porte e hipermercado) e submetidos à temperatura ambiente e refrigerada (inferior a 5°C). O delineamento experimental utilizado foi em blocos casualizados, sob um arranjo fatorial 4 x 2, sendo o tipo de estabelecimento comercial (quitanda, mercado de grande porte, hipermercado e mercado de pequeno porte) e a temperatura de armazenamento dos frutos (temperatura inferior a 5°C e temperatura ambiente) considerados como fatores. Foram utilizados dois frutos por unidade experimental para análises físicas e físico-químicas. Os frutos foram avaliados pela aparência externa, diâmetro transversal e longitudinal, espe', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/6294', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb49', 'PERFIL DE TEXTURA DE BARRA DE CEREAL MISTA COM APROVEITAMENTO DE SUBPRODUTO DE SUCO DE FRUTAS', 'Farias, Juanne Queiroz; de Sousa, Carolina Fontes; Almeida, Renata Duarte; de Sousa, Severina; Mata, Mario Eduardo Rangel Moreira Cavalcanti; Tomé, Anna Emanuelle Soares', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho consiste em elaborar barras de cereais mistas, utilizando o subproduto do suco de abacaxi e de caju. Foi utilizado um Planejamento Fatorial completo 2² e a Metodologia de Superfície de Resposta. O planejamento contou com cinco níveis diferentes, com três pontos centrais totalizando sete ensaios. As variáveis independentes foram concentração de subprodutos de suco de abacaxi e de caju na proporção de 1:1, em (%), e tempo de cozimento, em minutos. Foi realizado o perfil de textura das barras, analisando a Firmeza, Adesividade, Coesividade, Elasticidade, Gomosidade e Mastigabilidade. Foi utilizado o software Statística 7.0 para análise dos resultados do planejamento adotado. Com relação aos resultados foi verificado que a variável tempo de cozimento apresentou maior efeito sobre a caracterização da textura. Diante disso, é notória a importância da elaboração desse trabalho para o aproveitamento de alimentos.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/6360', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb4a', 'CARACTERIZAÇÃO QUÍMICA DE KOMBUCHA A BASE DE CHÁS DE HIBISCO E PRETO', 'Mota, Mercia Melo de Almeida; Mota, Mércia Melo de Almeida', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A kombucha é uma bebida agridoce fermentada de origem asiática, conhecida por suas propriedades medicinais e por seus componentes bioativos. É preparada a partir da fermentação de chá açucarado por um consórcio simbiótico de bactérias acéticas e leveduras (SCOBY) à temperatura ambiente. Diante disto, o presente trabalho teve como objetivo elaborar e caracterizar kombuchas preparadas à base de chá preto e chá de hibisco, e adoçadas com açúcar demerara. Inicialmente, fez-se uma cinética de fermentação durante a produção das kombuchas, determinando, assim, que 4 dias de fermentação são necessários para obter uma bebida com qualidade sensorial aceitável. Por fim, determinou-se o teor de açúcares totais, açúcares redutores, compostos fenólicos, flavonoides e antocianinas das bebidas após o período de fermentação e maturação. Diante dos resultados obtidos concluiu-se que as kombuchas possuem compostos bioativos satisfatórios para que esta bebida possa ser classificada como alimento funcional', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/6365', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb4e', 'ASPECTOS DE QUALIDADE DE HAMBÚRGUERES DE FRANGO COM SUBSTITUIÇÃO PARCIAL DE GORDURA POR FARELO DO RESÍDUO DE CAJÁ (SPONDIAS MOMBIN L.)', 'Santos, José Robenilson Sousa dos Santos Robenilson Sousa', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O consumo de produtos cárneos processados está associado ao desenvolvimento de doenças crônicas em função dos teores de gordura saturada, sódio e aditivos químicos que apresentam. Visando desenvolver um produto cárneo mais saudável o presente estudo teve como objetivo utilizar o farelo do resíduo de cajá como substituto de gordura em hambúrguer de frango, analisando seus parâmetros físicos de qualidade. Foram elaboradas três formulações de hambúrguer de frango: um tratamento controle (HFC), e dois tratamentos com substituição de gordura: 50% de substituição (HF50) e 100% de substituição de gordura por farelo de resíduo de cajá (HF100). Os tratamentos foram submetidos às análises físico-químicas, como a composição química (umidade, cinzas, carboidratos, proteínas e lipídeos), pH, Aa e CRA e parâmetros de cor (L*, a*, b*). Os hambúrgueres apresentaram a composição centesimal atendendo a legislação vigente. O teor de lipídeos decresceu gradualmente conforme a substituição da gordura por f', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/6595', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb50', 'Obtenção, rendimento e caracterização de CMS produzida com resíduos da filetagem de Tilápia do Nilo', 'Bernadino Filho, Raimundo; Almeida Xavier, Layra Catarina', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As indústrias de processamento de peixes geram grandes quantidades de resíduos, que quando não aproveitados ou descartados de forma adequada representam um potencial perigo para o meio ambiente. A utilização dos resíduos da filetagem de peixes para obtenção de Carne Mecanicamente Separada – CMS pode ser uma alternativa de matéria-prima na elaboração de alimentos. Objetivou-se nesta pesquisa a obtenção de CMS de tilápia do Nilo e determinar a sua composição físico-química, cálculo de rendimento e qualidade microbiológica. A matéria-prima utilizada para obtenção foram carcaças de tilápia provenientes do processo de filetagem manual, doadas por uma indústria de beneficiamento de pescado, localizada em Natal/RN. Nas análises microbiológicas determinou-se Staphylococcus coagulase positiva, Salmonella sp. e Coliformes a 45°C. Nas características físico-químicas determinou-se a umidade, cinzas, lipídeos e proteínas. O cálculo do rendimento de extração foi realizado em relação ao peso das carc', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/7534', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655c9e50e69ae81838bb51', 'Benefícios e características da Kombucha: Uma revisão', 'Weschenfelder, Simone; Dário Petry, Alexandra', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A Kombucha é uma bebida agridoce fermentada de origem asiática, conhecida por suas propriedades medicinais e compostos bioativos. É preparada a partir da fermentação de chá açucarado por uma associação simbiótica de bactérias e leveduras (SCOBY) à temperatura ambiente. Embora sua composição química seja muito variável, alguns componentes como ácidos orgânicos, vitaminas e polifenóis estão comprovadamente presentes na maioria e, devido à presença desses compostos bioativos, vem sendo caracterizada como alimento funcional. Estudos demonstram que a Kombucha possui propriedades antioxidantes e antimicrobianas e que seu consumo pode ter efeito protetor contra doenças cardiovasculares, diabetes, promover funções hepáticas e estimular o sistema imunológico. Diante disto, o presente trabalho teve como objetivo realizar uma revisão de literatura a respeito das principais características da Kombucha como alimento funcional, destacando os principais efeitos benéficos que a ingestão da bebida pode', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/7539', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb57', 'Dez anos de certifica minas café: O que mudou para o produtor familiar da microrregião de Alfenas?', 'Silva, Roberta Bessa Veloso; Ferreira, Eric Batista; Alves, Sandra de Souza', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O estado de Minas Gerais é responsável por aproximadamente 51,5% da safra brasileira de cafés, exportando para mais de 70 países do mundo. No contexto em que o mercado se encontra, as propriedades rurais estão buscando a valorização do café e adotando as boas práticas agrícolas por meio da certificação que é uma das exigências do mercado consumidor interno e externo. Diante desse cenário, os objetivos deste trabalho foram verificar as práticas dos produtores familiares certificados da microrregião de Alfenas para a obtenção da certificação, as dificuldades enfrentadas, bem como os benefícios obtidos. Foram analisadas 23 propriedades das cidades de Fama, Machado, Paraguaçu e Poço Fundo, certificadas pelo do Certifica Minas Café. Foram feitas entrevista com os proprietários rurais utilizando-se um questionário semiestruturado. Constatou-se que as maiores dificuldades enfrentadas foram a rastreabilidade e a adequação ambiental. O maior benefício percebido foi o aumento na produtividade da', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8045', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb59', 'As geotecnologias e o agronegócio brasileiro: Um estudo de caso na produção de Soja', 'Rodrigues Palmeira, Ana Carolina; de Freitas Furtado, Bruno Eduardo; de Vasconcelos Silva, Ermerson; de Freitas Furtado, Guilherme', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O uso de tecnologia como ferramenta de gestão, monitoramento e controle dos processos produtivos, tem sido cada vez mais frequente, notadamente na agricultura, uma vez que há necessidade de otimização da produção e incremento da produtividade para garantir o suprimento de uma demanda crescente. Esse trabalho tem como objetivo analisar o uso das geotecnologias no agronegócio brasileiro, destacando as principais metodologias aplicadas, dentre as tecnologias utilizadas no cultivo brasileiro de soja, destacam-se uso de sensoriamento remoto através dos índices de vegetação e uso de VANT’S, os quais podem ajudar na avaliação do comportamento de genótipos, práticas de manejo e impactos de estresses bióticos e abióticos, contribuindo na tomada de decisão dos produtores. O uso coerente das geotecnologias na agricultura pode promover maior eficiência na produção agrícola, redução de mão de obra e do uso de insumos, através das aplicações pontuais nos locais necessários, monitoramento de estádios', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8331', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb5a', 'MELÃO: TAXAS DE CRESCIMENTO DA PRODUÇÃO, EXPORTAÇÃO E IMPORTAÇÃO', 'Araújo Aragão, Adalberto; Gazzola, Rosaura; Dalla Porta Gründling, Roberta', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A região Nordeste do Brasil é a principal produtora de melão do país contribuindo com mais de 90% da produção nacional. O estado do Rio Grande do Norte produziu 58,23% desse total, o Ceará 14,66%; a Bahia 10%; Pernambuco 7,49% e Piauí 4,73%. O mercado de melão está representado por aproximadamente 20 países. Os países analisados representam acima de 90% da produção, exportação e importação. São 26 países produtores, 13 exportadores e 20 importadores. As taxas de crescimento da produção, exportação e importação foram estimadas estatisticamente por meio de um modelo de regressão não linear com forma funcional. O grande destaque do estudo é a China com produção de 43% do melão mundial. A taxa de crescimento da exportação da China também se destaca já que é de 29,42% com alta significância estatística. A Espanha é o país que mais ganha no mercado exportador de melão com 22% das exportações, porém com taxa de crescimento da produção negativa (-5,06% a.a.). Destacam-se Emirados Árabes. Singa', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8375', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb5b', 'FRAUDES NO LEITE: PRINCIPAIS TIPOS E RESPECTIVOS MÉTODOS DE DETECÇÃO', 'Toté de Medeiros, Ana Letícia; Castello Branco Chinelate, Gerla; dos Santos Bernardino, Maria Itais; Braz da Silva, Wanessa; de Oliveira Silva, Karla Rayana; Cabral Barbosa, Rafaele; Nunes Lopes, Mael', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O leite é um alimento de origem animal que apresenta alto valor nutritivo e que é cada vez mais consumido pela população que busca um estilo de vida mais saudável e alimentos mais práticos. Junto ao aumento do consumo, cresce a preocupação de autoridades e técnicos da área a respeito da qualidade do leite que é comercializado, devido a possibilidade de fraudes nessa matéria-prima. A forma mais comum de fraude no leite caracteriza-se pela adição de água no leite com o intuito de aumentar o seu volume. Porém, surgiram outros tipos de adulterações, com outras finalidades, como adição de conservantes, neutralizantes, reconstituintes que são utilizados  para encobrir a fraude por adição de água, utilizando substâncias mais comumente aplicadas como amido, sacarose e cloretos. Além destas, pode-se encontrar a fraude pela inserção do soro ao leite. Diante disso, o presente trabalho teve como objetivo realizar uma revisão de literatura a respeito das principais fraudes no leite e seus respectiv', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8482', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb5c', 'PRODUÇÃO E MERCADO INTERNACIONAL DE MANGA', 'Araújo Aragão, Adalberto; Gazzola, Rosaura; Dalla Porta Gründling, Roberta', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mercado brasileiro é produtor e exportador de manga. Esse estudo mostra os principais produtores, exportadores e importadores mundiais de manga entre 2008 e 2018. Os dados foram obtidos no FAOSTAT, transformados em log neperiano e a análise efetuada foi o cálculo da taxa de capitalização contínua, denominada taxa de crescimento anual. A Índia é o principal produtor mundial com 38,19% com taxa de crescimento da produção de 4,63% a.a. Sua participação na exportação mundial é de 11,35% com taxa de crescimento da exportação de -2,43% a.a. A China e a Tailândia são o segundo e terceiro produtores mundiais. Destacam-se Egito, Malaui e Nepal, com taxas de crescimento da produção acima de 10% a.a., altamente significativas. Na exportação de manga, respondem por 40,91% das exportações mundiais o México, a Holanda e a Índia. O Brasil é o 7º exportador mundial com 8,8% e taxa de crescimento de 6,29%a.a. No mercado exportador destacam-se com taxas de crescimento acima de 20%a.a. e altamente sign', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8566', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb5d', 'Avaliação crítica sobre a legislação brasileira quanto ao uso de ácido ascórbico como aditivo alimentar em sucos e polpas de frutas', 'Coelho, Raquel Macedo Dantas; da Costa, Ana Paula Souza', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O ácido ascórbico, também denominado vitamina C, é hidrossolúvel e termolábil. Os seres humanos são incapazes de sintetizar o ácido ascórbico, por isso valem-se essencialmente da alimentação através de frutas, hortaliças e vísceras para suprir sua demanda. Além do seu valor nutricional, o ácido ascórbico é empregado como aditivo alimentar devido o seu caráter antioxidante. Este trabalho objetivou analisar criticamente as Instruções Normativas Nº 37 de 01 de outubro 2018, do Ministério da Agricultura, Pecuária e Abastecimento - MAPA e a Instrução Normativa nº 37, de 01 de outubro de 2018 - MAPA: a primeira, a qual requer um teor mínimo de ácido ascórbico de origem natural para determinados sucos e polpas de fruta; e a segunda por, ao mesmo tempo, permitir o uso do aditivo ácido ascórbico (INS 300) para esses tipos de bebidas. A partir desta análise crítica evidenciou-se esta contradição que compromete a ação fiscalizatória do cumprimento dos padrões de identidade e qualidade para sucos ', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8653', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
