VALUES ('67655ca050e69ae81838bb70', 'OBTENÇÃO E CARACTERIZAÇÃO DE AMIDO DA SEMENTE DA JACA POR SECAGEM EM LEITO DE JORRO', 'Tatiaia de Morais Dias, Juliana; Rodrigues da Silva, Layanne; JACIANE ARAUJO RODRIGUES, THAIS; Trindade Rocha, Ana Paula; Ferreira da Silva, Shirlyanne', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8758', NULL, 'English', 'published', false, false, 'open', 'pdf')
