VALUES ('67655ca050e69ae81838bb73', 'Potencial hepatoprotetor da geleia real: Uma avaliação acerca dos marcadores enzimáticos de lesão', 'Alves de Sousa , Lavínia; da Rocha, Rute Emanuela; dos Anjos Barros, Nara Vanessa; Alves da Costa, Jardel; dos Santos Beserra Pessoa, Márcia Luiza', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8766', NULL, 'English', 'published', false, false, 'open', 'pdf')
