INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb74', 'PROPRIEDADES FÍSICO-QUÍMICAS E ANTIOXIDANTES DE MÉIS COMERCIAIS PRODUZIDOS NA REGIÃO DE LONDRINA', 'Barrionuevo Ressutte, Jéssica; Norika Yassunaka HATA, Natália; da SILVA, José Renato; SPINOSA, Wilma Aparecida; de Morais PINHEIRO, Gabriela', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mel é um composto rico em compostos com atividade bioativa, no entanto, nos últimos anos, esse produto tem sido alvo de adulterações. Nesse sentido, o objetivo desse trabalho foi avaliar a qualidade de quatro méis comerciais produzidos na região de Londrina. Os parâmetros avaliados foram umidade, pH, acidez total, cinzas, condutividade elétrica, açúcares redutores, reação de Lund, hidroximetilfurfural, atividade diastásica, cor e capacidade antioxidante e redutora. Os resultados mostraram que todas as amostras se encontraram dentro dos padrões estabelecidos pela legislação Brasileira, com exceção da análise de açúcares redutores, em que duas amostras apresentaram valores inferiores ao padrão estabelecidos pela legislação. Todas as amostras apresentaram capacidade antioxidante e redutora, sendo essas superiores para as amostras com maiores índices de açúcares redutores. Desse modo, conclui-se que pesquisas que verifiquem a qualidade dos méis comerciais são necessárias, de modo a se as', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8767', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
