INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bb96', 'AVALIAÇÃO FÍSICA E QUÍMICA DE GELEIAS COMERCIAIS COM E SEM ADIÇÃO DE ACIDULANTES', 'Furtini Haddad, Felipe; Alice Andrade Oliveira, Ana', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As tendências do setor alimentício são ditadas pelo mercado consumidor, que cada vez mais vem buscando adquirir produtos saudáveis e de alta qualidade sensorial. A geleia, produto elaborado com frutas e de elevado consumo pela população brasileira, apresenta uma oportunidade para a utilização de diversas formulações diferentes em sua elaboração, podendo minimizar a utilização de aditivos alimentares, aumentando suas tendências de sensorialidade e saudabilidade. Diante disso, o objetivo deste trabalho foi analisar física e quimicamente geleias comerciais com e sem a adição de acidulantes. As geleias foram analisadas quanto ao pH, acidez titulável total, sólidos solúveis totais, cor, atividade de água e perfil de textura. Geleias sem acidulantes em sua formulação apresentaram menor acidez titulável total e saturação na tonalidade, além de maiores valores no pH e em parâmetros de textura como dureza, gomosidade e elasticidade, evidenciando a possibilidade do desenvolvimento de geleias com', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8838', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bba2', 'Carne de codorna e farinha de semente de abóbora como ingredientes em patê: Uma reflexão', 'de Oliveira Morais,  Ildeson Tiago; Alves Coelho Gracindo, Ângela Patrícia; Fonseca Feitoza, João Vitor; da Silva Maia, Keliane; da Nóbrega Santos, Edilayane', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A carne de codorna é muito apreciada pelos seus bons aspectos sensoriais, contudo não é comum encontrá-la comercialmente como ingrediente em produtos cárneos, principalmente na forma de patê. Os produtos cárneos são conhecidos por seus altos teores de gorduras saturadas, logo, já existe uma tendência na indústria de alimentos para o desenvolvimento de produtos com ingredientes funcionais que, quando consumidos, proporcionem benefícios à saúde humana. A semente de abóbora é conhecida pelo seu conteúdo lipídico poli-insaturado, sendo um ingrediente promissor para melhorar a qualidade nutricional dos produtos cárneos. Portanto, objetiva-se com este trabalho realizar uma revisão de literatura com ênfase na aplicação desses ingredientes em produtos cárneos como o patê. Os mecanismos de busca utilizados foram os de maior facilidade de acesso, como o Portal de Periódicos da Coordenação de Aperfeiçoamento de Pessoal de Nível Superior (CAPES), o Google Acadêmico, o Scientific Electronic Library', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8858', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bba5', 'Agentes naturais no controle oxidativo de manteiga de garrafa: Inovação e promoção de saúde', 'Fonseca Feitoza, João Vitor; da Silva maia, Keliane; Alves da Silva, Jean Berg', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8865', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bbac', 'CARACTERIZAÇÃO DE BARRAS DE CEREAIS ENRIQUECIDAS COM COCO OURICURI (Syagrus coronata)', 'Almeida Silva, Joanna Beatriz; Santos Leite, Kerolayne; Pereira Lopes Neto, José Honório; dos Santos Silva, João Victor; Rodrigues Lima, José Rafael', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho teve como objetivo desenvolver barra de cereal adicionada de coco ouricuri (Syagrus coronata) e realizar análises físico-químicas e microbiológicas. A palmeira do coco ouricuri é predominantemente encontrada na região sertaneja, seu fruto possui tamanho aproximado de dois centímetros e são utilizados na produção de doces, como a cocada e também na produção de óleo. O uso do coco ouricuri na produção da barra de cereal, além de agregar valor nutricional à mesma, apresenta uma importância socioeconômica à região produtora, pois dessa maneira apresenta-se uma nova destinação para o fruto. Para a elaboração do produto, inicialmente os cocos foram coletados e higienizados. Na produção da barra de cereal fez-se a aglutinação do xarope (mel, xarope de glucose e óleo de coco) sob aquecimento, até atingir a concentração de 85-89 °BRIX. Logo em seguida, os ingredientes secos foram misturados ao xarope e foram obtidas 4 formulações com diferentes porcentagens de coco ouricuri ', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8875', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bbb0', 'DESENVOLVIMENTO DE BARRAS DE CEREAIS COM FARINHA DE BATATA-DOCE', 'Wruck, Leonardo Rodrigues; Munhoz, Cláudia Leite; Ferreira, Thales Henrique Barreto; Vieira, Pedro Coura', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Atualmente os consumidores estão mais atentos a alimentos que proporcionem benefícios ao organismo, assim, barras de cereais estão ganhando mercado, principalmente, com adição de outros ingredientes, como batatas doces. Desta forma, objetivou elaborar barras de cereais com adição de diferentes teores de farinha de batata-doce. As barras foram elaboradas com flocos de arroz, açúcar mascavo, uva passa, farelo de aveia, xarope ligante. A farinha da batata-doce e as barras de cereais adicionadas à farinha foram submetidas às determinações de cinzas, cor e umidade. O teste de aceitabilidade foi utilizado uma escala hedônica de 9 pontos, com 60 julgadores não treinados avaliando os atributos aparência, cor, aroma, textura, sabor, sabor da batata, doçura e qualidade global e sua avaliação de aceitação sensorial. Os resultados obtidos nas caracterizações físicas da farinha foram umidade 9,88, cinzas 2,81 e para os parâmetros de cor foram 87,89 para L*, 1,66 para a* e 24,75 para o b*. Os atribu', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8880', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bbb2', 'ANÁLISE SENSORIAL DE GRÃOS DE AMENDOIM TRATADOS COM PRODUTOS NATURAIS OBTIDOS DE CASCA DE LARANJEIRA', 'de Souza Rezer, Ana Paula; Junges, Emanuele; Granella, Vanusa; Oliveira Hornes, Márcio; Cecconi Deon, Barbara', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho verificou a preferência do amendoim cru e torrado com a aplicação de óleo essencial e extrato aquoso e pó da casca de laranja (Citrus sinensis) utilizados na redução de fitopatógenos de armazenamento em grãos de amendoim. Utilizaram-se cascas de laranja para realizar os tratamentos, sendo: tratamento 1 (T1) extrato aquoso, produzido a partir de 100g de cascas trituradas em liquidificador em 1L de água destilada e esterilizada; tratamento 2 (T2) óleo essencial, extraído através do método de hidrodestilação com aparelho Clevenger; tratamento 3 (T3) testemunha, utilizado na mesma proporção água destilada e esterilizada e tratamento 4 (T4) extrato em pó, produzido a partir de 100 g de cascas secas em estufa por 24h e em seguida triturado em liquidificador. Os tratamentos líquidos foram aplicados sobre o amendoim na proporção de 2% do peso e o tratamento em pó foi aplicado na mesma proporção, para cada 100g de grãos, 2g de extrato em pó. Após 2 dias da aplicação dos trat', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8882', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca050e69ae81838bbb4', 'Elaboração de iogurte de umbu com adição de mucilagem de palma e diferentes tipos de açúcares', 'de Andrade Braga , Bruna; Cotrim Santos, Bianca; Geraldo Amaral, Juliano; Elena Zanuto, Márcia; Camelo Eloi de Souza, Cassiara', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8884', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbc0', 'ELABORAÇÃO DE PÃO DE QUEIJO COM ADIÇÃO DE OKARA', 'Benedetti, Silvia; Larissa Aguiar, Danielli; Anne Mateus, Jady; Gonsalves Sturnich, Winnie', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A soja é uma leguminosa rica em proteínas, constituindo uma boa fonte de minerais, como ferro, potássio, magnésio, zinco, cobre, fósforo, manganês e vitaminas do complexo B, além das isoflavonas, que são compostos bioativos com comprovados benefícios à saúde. O extrato hidrossolúvel de soja é um produto obtido a partir da lavagem, maceração e aquecimento de grãos de soja, do qual resulta um subproduto denominado okara. O okara é rico em proteínas, lipídeos, fibras e de baixo valor de mercado, podendo ser incorporado na formulação e enriquecimento nutricional de produtos alimentícios, como produtos de panificação. O pão de queijo é um alimento originário do estado de Minas Gerais, amplamente consumido no Brasil. Portanto, este projeto teve como objetivo a elaboração de pão de queijo com adição de okara e a avaliação de suas características físico-químicas, físicas e aceitação sensorial. Foram desenvolvidas três formulações (A, B e C) de pães de queijo utilizando as concentrações de 10, ', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8902', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
