VALUES ('67655ca150e69ae81838bbc7', 'Estudo do impacto do conteúdo de umidade no mel proveniente da apicultura familiar em Mata Atlântica do Vale do Ribeira, São Paulo', 'Bonaldi Cano, Cristiane; Benitez Bosco, Laura; Fernandes Pinto da luz, Cynthia; Ferigolli, Emiliana Gomes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8911', NULL, 'English', 'published', false, false, 'open', 'pdf')
