INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbc8', 'Influência do espessante na textura de queijo petit suisse sabor açaí (Euterpe oleracea Mart.)', 'Reges, Bianca Mara; de Sousa Oliveira, Vandesonia Maria; de Farias, Virna Luiza; Oliveira, Lidenes; Liberato Milhome, Maria Aparecida', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8912', NULL, 'English', 'published', false, false, 'open', 'pdf')
