INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbc9', 'Desenvolvimento de smoothie de Skyr com mucilagem de palma (Opuntia ficus-indica (L.) Miller) e saborizado com polpa de umbu (Spondias tuberosa).', 'Geraldo Amaral, Juliano; Elena Zanuto, Márcia; Camelo Eloi de Souza, Cassiara; Ribeiro Marinho, Milena; Santos Souza, Anderson', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O crescente aumento das doenças crônicas não transmissíveis tem estimulado a procura do consumidor por alimentos funcionais. Portanto, este estudo teve como objetivo a preparação e caracterização de smoothies, utilizando o iogurte Skyr, a mucilagem de palma como espessante e a polpa de umbu para sua saborização. Foram elaboradas quatro formulações distintas de acordo com o processamento do Skyr (dessorado ou sem dessorar) e tipo de açúcar (açúcar de coco ou demerara). As formulações foram submetidas à caracterização química, determinação do teor de constituintes bioativos, atividade antioxidante e análise reológica. Dentre os resultados obtidos, destacaram-se na polpa de umbu valores elevados de ácido ascórbico (11,59 mg.100 g-1), compostos fenólicos (56,70 mg.EAG.100 g-1), atividade antioxidante total (59,85%) e baixo teor lipídico (0,31 mg.100 g-1). Os smoothies apresentaram acidez titulável e pH compatíveis com os exigidos pela legislação brasileira para iogurtes, baixo teor lipídic', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8913', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbcb', 'Osmotic dehydration with complementary drying as a social technology: Use of bananas out of the standard from cv. Grande naine.', 'Massulo, Andreia; Pascoli Cereda, Marney', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8915', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbd3', 'Brownie com mel e castanha de caju: Elaboração e aceitação', 'Lima, Helder Levi Silva; Cavalcante, Márcia Roberta Freitas; Amaral, Sheyla Maria Barreto; Damaceno, Marlene Nunes; Freitas, Francisca Nayara Ferreira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Esse estudo teve por finalidade inovar uma receita tradicional de brownie adicionando mel e castanha de caju e avaliar aceitação sensorial, intenção de compra, frequência de consumo e o índice de aceitabilidade. Para isso foi elaborado o produto e aplicado um teste afetivo de aceitação utilizando a escala de atitude de nove pontos, com 126 avaliadores não treinados, dos quais 65% eram mulheres e 35% homens, com faixa etária entre 18 e 60 anos. Os resultados evidenciaram que independente do gênero o produto teve uma boa aceitação, com escore médio global de 8,11, que corresponde a “comeria muito frequentemente". Quanto à intenção de compra 67% dos avaliadores certamente comprariam o produto, já a frequência de consumo ficou situada entre "moderado" e "sempre" (83%). O teste afetivo demonstrou que o produto teve ótima aceitabilidade (90%) e independente do gênero ou faixa etária eles certamente consumiriam e comprariam o produto.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8926', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbd5', 'Utilização de subprodutos da agroindústria cervejeira e vinícola como fonte de compostos bioativos e fibra alimentar no desenvolvimento de cookies', 'Munhoz, Mariane Daniele; Tischler Nizer, João Victor; Teixeira Macagnan , Fernanda; Pereira, Ariel Laurentino; Moura Borowski , Joyce', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os subprodutos da agroindústria cervejeira e vinícola podem contribuir para o desenvolvimento de produtos mais funcionais, uma vez que bagaço de malte e de uva são fontes de compostos bioativos e fibra alimentar. O objetivo deste trabalho foi estudar a aplicação desses subprodutos na produção de cookies. Para isso, foram desenvolvidas duas formulações, com substituição parcial (25 e 50%) da farinha de trigo por um mix de farinha de bagaços de uva e malte (25% e 75%, respectivamente). Foram realizadas análises tecnológicas (antes e após cocção para: perda de massa, expansão horizontal, expansão vertical e índice de expansão aparente), microbiológicas (Salmonella, estafilococos e coliformes a 45 °C), de composição centesimal, atividade antioxidante (ABTS e DPPH), e análise sensorial de aceitação e intenção de compra, comparando as diferentes formulações em duas sessões (sem informação e com informação da presença dos subprodutos fontes de fibras e antioxidantes). Os resultados demonstrar', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8931', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbd8', 'Potencial antioxidante e composição química do anil (Coccocypselum geophiloides): uma espécie nativa do Planalto Norte Catarinense', 'Borowski, Joyce Moura; Nizer, João Victor Tischler; Daniele  Munhoz, Mariane; Macagnan, Fernanda Teixeira; Pereira, Ariel Laurentino', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Apesar do alto valor nutricional e potencial econômico, muitas espécies nativas e exóticas brasileiras permanecem inexploradas. No Planalto Norte Catarinense, diversas espécies de flora nativa ainda não foram estudadas, dentre elas está o anil (Coccocypselum geophiloides). Assim, este trabalho visou caracterizar o anil quanto a sua composição química e potencial antioxidante. As amostras parcialmente secas foram avaliadas quanto a sua composição química (umidade, cinzas, proteínas, lipídeos, fibra alimentar e suas frações solúvel e insolúvel) e potencial antioxidante (teor de polifenóis e capacidade antioxidante). Dentre os resultados obtidos têm-se destaque para a fibra alimentar a qual representa 64,48% da composição química do anil. Este componente possui elevada relevância funcional e nutricional devido ao papel que desempenha no organismo humano. O teor de polifenóis e a elevada capacidade antioxidante do anil também merecem destaque, principalmente por não terem sido influenciado', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8935', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbd9', 'Avaliação da qualidade microbiológica e físico-química de bebidas lácteas fermentadas sabor coco comercializadas em Lavras-MG', 'Oliveira, Diana; Balduino, Bruna; Venâncio, Anderson; Albergaria, Francielly; Piccoli, Roberta', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As bebidas lácteas são alimentos de alto valor nutricional que levam em sua composição o soro do leite, podendo ser fermentadas, ou não. Entretanto, antes de ser consumida, é importante se atentar aos riscos de contaminação microbiológica e se assegurar de que as condições de armazenamento foram corretas. Neste sentido, o objetivo do trabalho foi avaliar a qualidade microbiológica e físico-química de algumas marcas de bebida láctea fermentada de coco, comercializadas em Lavras-MG. Foram coletadas amostras de cinco marcas distintas, denominadas de A, B, C, D e E, em um estabelecimento comercial. Foram avaliadas as contagens totais de bactérias láticas, fungos filamentosos, psicrotróficos e aeróbios mesófilos. Análises de pH, temperatura e acidez foram realizadas para avaliar a qualidade físico-química. De todas as marcas de bebidas fermentadas de coco, nenhuma apresentou contaminação. A contagem de bactérias láticas, entretanto, se mostrou inferior à legislação vigente, de 106 UFC mL-1,', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8936', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbdb', 'Clitoria ternatea: Avaliação do tempo de extração de compostos fenólicos obtidos pela técnica assistida por ultrassom', 'dos Santos, Luan Gustavo; Gomes, Bruno Marques; Alves da Silva, Gisele Fernanda; Guimarães Martins, Vilásia', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8940', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
