VALUES ('67655ca150e69ae81838bbe3', 'VALIDAÇÃO DA VIDA DE PRATELEIRA DE CARNE SUÍNA CONGELADA', 'Dal''Prá Brand, Rafaela; Ramos Messias, Camila', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8949', NULL, 'English', 'published', false, false, 'open', 'pdf')
