INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbe8', 'ACEITAÇÃO SENSORIAL DE SORVETE DE MILHO VERDE “IN NATURA”', 'Aguirre Martins, Patrícia; de Souza Rezer, Ana Paula; Granella, Vanusa; Cecconi Deon, Barbara; Oliveira Hornes, Marcio', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A demanda por alimentos saudáveis vem exigindo a busca por novas formulações que melhorem a qualidade nutricional e atendam a outras tendências como ser um produto clean label. O sorvete é um alimento bastante versátil, tem excelente aceitação pela população em geral, mas pode apresentar uma composição rica em ingredientes calóricos e com aditivos químicos. O objetivo desse estudo foi verificar aceitação sensorial de uma formulação de sorvete com adição de milho verde “in natura”. A elevada aceitação sensorial, um bom resultado para o teor de sólidos solúveis totais e overrun demonstrou que a formulação estudada é uma opção interessante para elaboração de um sorvete tanto para a indústria como para produção artesanal.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8958', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbf9', 'INFLUÊNCIA DA CONCENTRAÇÃO DE SACAROSE E GORDURA SOBRE A CARACTERÍSTICAS DO DOCE DE LEITE OVINO ZERO LACTOSE: Influence of the Concentration of Sucharose and fat on the Characteristics of the Dulce de', 'Perin, Larissa; Karolina Cherobin , Ana; Almeida, Carlos; Mohr, Elisa; Rigo, Elisandra', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8978', NULL, 'English', 'published', false, false, 'open', 'pdf')
