INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbfb', 'Secagem e avaliação de laranja Citrus sinensis em estufa e micro-ondas', 'Grellmann, Daiane Karina; Back, Patr´ícia Inês Kemper; Bones, Scheila Andrieli Silveira; Scherer, Glaciela Cristina Rodrigues Da Silva; Martinazzo, Janine', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8982', NULL, 'English', 'published', false, false, 'open', 'pdf')
