INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bbfe', 'Ação bactericida de compostos majoritários de óleos essenciais sobre células planctônicas e sésseis de Bacillus cereus', 'Carlota Gonçalves, Michelle; Junqueira Pinelli, Juliana; Hilsdorf Piccoli, Roberta; Azevedo Balduino, Bruna; Henrique Venâncio, Anderson', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Bacillus cereus é uma bactéria patogênica associada à toxinfecções alimentares, capaz de formar biofilmes sobre superfícies de processamento de alimentos. Uma alternativa para controlar o crescimento de B. cereus nas indústrias de alimentos são os óleos essenciais e ou seus componentes majoritários, compostos naturais com propriedades antibiofilmes. Desse modo, o objetivo do trabalho foi avaliar a ação bactericida dos componentes majoritários de óleos essenciais, cinamaldeído, citral e carvacrol, e suas combinações sobre células planctônicas e sésseis de B. cereus ATCC 14579. A concentração mínima bactericida (CMB) dos compostos majoritários sobre as células planctônicas foi determinada empregando-se a técnica de macrodiluição em caldo BHI, avaliando-se concentrações entre 0,016 a 2%. A concentração mínima bactericida do biofilme (CMBB) foi determinada após a formação dos biofilmes de B. cereus em microplaca de poliestireno por 72 h a 37 °C. Os biofilmes foram expostos à soluções dos c', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8985', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bc01', 'Perdas pós colheita de frutas e hortaliças em mercados da região de Bom Jesus do Itabapoana – RJ: Post harvest losses of fruits and vegetables in markets in the region of Bom Jesus do Itabapoana - RJ', 'FLORES DUTRA, HAYLANE PAOLA; Caetano Menditi, Ana Clara; CAETANO MENDITI, LARISSA; CARVALHO BOTELHO RIBEIRO, MARISA', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/8988', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bc12', 'Viabilidade econômica e análise de risco: um estudo comparativo das regiões cafeeiras de Minas Gerais', 'Priest Mattedi, Adriana; Cristine Dutra, Tatiane; Ciro de Oliveira, Daive; rezende, marcelo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/9415', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bc14', 'Utilização da farinha da semente de abóbora na produção de alimentos funcionais: Uma revisão', 'Montenegro STAMFORD, Thayza Crhistina; de Melo, Flávia Alexsandra B.Rolim; Fonseca GALVÃO, Maria Brígida', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A semente de abóbora por muitas vezes é um subproduto descartado, porém vem ganhando espaço e importância devido às suas propriedades nutricionais e a capacidade de ação antioxidante. Ademais, ela é rica em ácidos graxos poliinsaturados, compostos bioativos, como carotenóides e compostos fenólicos. Considera-se uma excelente fonte de proteína vegetal e de fibras, auxiliando no trânsito intestinal. Visto que o desperdício desse resíduo ainda é constante, é necessário adotar medidas sócio-econômicas para o aproveitamento integral dos alimentos, trazendo agregação nutricional aos novos produtos elaborados ou enriquecidos, bem como diminuindo a produção de lixo orgânico. O objetivo principal desta revisão é abordar a importância do aproveitamento integral da semente de abóbora para produção de alimentos funcionais e pontuar suas propriedades nutricionais.', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/9585', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67655ca150e69ae81838bc18', 'CARACTERIZAÇÃO FÍSICO-QUÍMICA E ELABORAÇÃO DE QUEIJO AZUL', 'Rufino, Jose Venâncio de Abreu; Alexandre, Lignalva Tamires Câmara; Barbosa, Neila Mello dos Santos; Silva, Rikelyne Gonçalves; Leite, Mércia Aurélia Gonçalves', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/9599', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c692', 'MODELOS DE GESTÃO E TRATAMENTO DE RESÍDUOS SÓLIDOS', 'Barros, Diogo Fernandes; Gadelha, Antônio José Ferreira; Rocha, Clarice Oliveira da; Nascimento Ribeiro, George do', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Resíduos são os resultados de processos de diversas atividades da comunidade de origem: industrial, doméstica, hospitalar, comercial, agrícola, de serviços e ainda da varrição pública. Os resíduos apresentam-se nos estados sólido, gasoso e líquido. Produzidos em todos os estágios das atividades humanas, os resíduos, em termos tanto de composição como de volume, variam em função das práticas de consumo e dos métodos de produção. As principais preocupações estão voltadas para as repercussões que podem ter sobre a saúde humana e sobre o meio ambiente (solo, água, ar e paisagens). Os resíduos perigosos, produzidos, sobretudo pela indústria, são particularmente preocupantes, pois, quando incorretamente gerenciados, tornam-se uma grave ameaça ao meio ambiente. A compreensão da problemática do lixo e a busca de sua resolução pressupõem mais do que a adoção de tecnologias. Uma ação na origem do problema exige reflexão não sobre o lixo em si, no aspecto material, mas quanto ao seu significado s', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/368', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c695', 'SUSTENTABILIDADE ECONÔMICA, SOCIAL E AMBIENTAL DA CARCINICULTURA: O CASO DO ESTADO DO RIO GRANDE DO NORTE', 'Abreu, Mônica Cavalcanti Sá de; Mattos, Paloma de; Padilha, Ana Claudia Machado; Padula, Antonio Domingos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este artigo analisa a competitividade e sustentabilidade da aquicultura de camarão no Rio Grande do Estado de Norte que é o mais importante produtor brasileiro. O método foi o estudo de caso, utilizando entrevistas para a coleta de dados primários que foi realizada em 21 empresas para identificar sua dinâmica econômica, ambiental e social. Os resultados revelam algumas insuficiências na conduta adotada no processo de fornecimento global de alimentos. O caso estudado mostra fragilidades de inovação alimentar e regime de governança, bem como a necessidade de coordenar esforços na tentativa de responder às crescentes preocupações sobre o impacto social e ambiental da aquicultura de camarão nos países em desenvolvimento.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/371', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c696', 'EDUCAÇÃO PARA A SUSTENTABILIDADE AMBIENTAL E SOCIAL EM CACHOEIRA DOS ÍNDIOS - PB', 'Barros, José Deomar de Souza; Silva, Maria de Fátima Pereira da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho é resultado de uma pesquisa realizada com estudantes da Educação de Jovens e Adultos da Cidade de Cachoeira dos Índios – PB, tem como objetivo compreender a percepção ambiental desses alunos nos aspectos da Educação Ambiental. A pesquisa foi realizada no período de 03 a 18 de setembro de 2009, contendo uma amostra de 40 alunos. Foi realizada visitas as escolas e aplicado um questionário contendo questões objetivas e subjetivas abordando os aspectos socioeconômico e também a compreensão que os educandos construíram a cerca das definições de meio ambiente e dos problemas que os mesmos presenciam no seu cotidiano.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/372', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c69e', 'PERFIL DOS PRODUTORES FAMILIARES DO P.A. JACURUTU SEDE I, NO MUNICÍPIO DE CANINDÉ-CE, BRASIL', 'Cabral, Bruna Delfino; Pereira, Daniel Santiago; Sousa Júnior, Luiz Fernando Venancio de; Colares, Getuliana Sousa; Ramos, Liliane Ferreira; Sousa Filho, José Valdir de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Foram realizadas 53 entrevistas semi-estruturados com agricultores familiares residentes no Projeto de Assentamento Federal- Jacurutu sede 01, na cidade de Canind&eacute;-CE, considerando os aspectos sociais, ambientais e produtivos do assentamento atividade. Foram realizadas 53 entrevistas semi-estruturados, com os agricultores familiares. Das fam&iacute;lias entrevistadas, 49 eram assentadas pelo INCRA e 04 fam&iacute;lias eram agregados, ou seja, fam&iacute;lias de amigos e/ou parentes que fixaram moradia nas depend&ecirc;ncias do assentamento Jacurutu Sede 01 sem a autoriza&ccedil;&atilde;o do INCRA, totalizando 185 pessoas em todas as fam&iacute;lias entrevistadas. O grau de instru&ccedil;&atilde;o apesar de baixo, foi superior ao encontrado em outros trabalhos, o uso do fogo &eacute; uma pr&aacute;tica ainda ainda comum, e dependem cada vez mais das rendas n&atilde;o-agr&iacute;colas e existe uma grande depend&ecirc;ncia das rendas n&atilde;o agr&iacute;colas especialmente dos pa', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/521', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a4', 'OS IMPACTOS DA URBANIZAÇÃO NA CIDADE DE MOSSORÓ/RN', 'Pereira dos Santos, Allysson; Serafim de Oliveira, Ludimilla Carvalho; Freitas Costa, Tiago Montenegro de; Lopes Costa, Claudinete Lígia; Moura, Maria da Conceição Freitas', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Em observ&acirc;ncia aos fen&ocirc;menos marcantes na Cidade de Mossor&oacute;/RN, buscou-se desenvolver uma pesquisa in loco na Avenida Rio Branco, correspondendo aos trechos que ligam a Estrada da Raiz a entrada do Bairro Santa Delmira, com o objetivo de identificar e analisar os impactos ambientais ocasionados pela perda da biodiversidade da Avenida citada, e como procedimentos metodol&oacute;gicos realizou-se uma visita em campo com a aplica&ccedil;&atilde;o do formul&aacute;rio FMEA - AN&Aacute;LISE DO MODO E EFEITOS DE FALHA, que analisa o grau de severidade, ocorr&ecirc;ncia, detec&ccedil;&atilde;o e abrang&ecirc;ncia.&nbsp; Mediante a aplica&ccedil;&atilde;o do referido formul&aacute;rio, constatou - se vari&aacute;veis ambientais preocupantes no cen&aacute;rio urban&iacute;stico da &aacute;rea em estudo. Portanto, pode-se perceber que os riscos ambientais mesmo estando abaixo da escala considerada risco (R=/&gt;50), in&uacute;meros efeitos negativos foi observado ao ambiente, ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/756', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a5', 'A PARTICIPAÇÃO DA SOCIEDADE CIVIL EM PROCESSOS DECISÓRIOS AMBIENTAIS', 'Nunes Coletti, Roseli', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Informa&ccedil;&otilde;es atuais acerca do crescimento da participa&ccedil;&atilde;o da sociedade civil na aplica&ccedil;&atilde;o das pol&iacute;ticas ambientais, bem como, do aumento da conscientiza&ccedil;&atilde;o da popula&ccedil;&atilde;o em geral para com o meio ambiente, demonstram a preocupa&ccedil;&atilde;o que essa tem&aacute;tica tem despertado, nos &uacute;ltimos tempos, em todo o mundo. Nessa seara insere-se o tema deste artigo, pois objetiva avaliar a participa&ccedil;&atilde;o da sociedade civil em processo decis&oacute;rio de alguns instrumentos da pol&iacute;tica ambiental nacional, a saber: zoneamento ambiental; avalia&ccedil;&atilde;o de impacto ambiental, e o licenciamento ambiental, quando da aplica&ccedil;&atilde;o desses. Para tanto se far&aacute; uma breve revis&atilde;o bibliogr&aacute;fica da tem&aacute;tica em quest&atilde;o com o intuito de estabelecer um arcabou&ccedil;o te&oacute;rico conceitual acerca das possibilidades de participa&ccedil;&atilde;o p&ua', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/820', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a6', 'Development of students ''perception of the 7th year of basic education in a public school about the consious use of the water', 'Medeiros, Aline Carla de; Moreira Pereira, Emmanuel; Soares Sousa, Luci Cleide Farias; Silva Sousa, José da; Borba Borges, Maria da Glória; Maracajá, Vivian Patrícia Borba Borges; Silva Sousa, Jesseni', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Water is a vital natural resource for the existence of living beings, it would be impossible without it there is life on the planet, however, a finite resource, which has an economic value, worthy of rational and conscious use. The objective of this work was the development of students'' perception of the 7th year of primary education in a public school about the conscious of the use of water. The same was developed in a public school in the municipality of Pombal - PB, with a group of 40 students enrolled in the 7th grade of elementary school. It was applied 40 questionnaires containing 12 questions in order to make a survey about students ''prior knowledge on the subject, but also develop the students'' perception about the conscious use of water.  By applying a didactic sequence, with the application of a questionnaire, a lecture, a visit to canal station and water treatment, and finally, presentation of a play. There were several answers when asked about the usefulness of water for dr', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/854', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b3', 'ANÁLISE AMBIENTAL DE UNIDADES DE CONSERVAÇÃO ATRAVÉS DOS MÉTODOS SWOT E GUT: O CASO DO PARQUE ESTADUAL RESTINGA DE BERTIOGA', 'Carbonari, Juliana Helena Braga; Favero, Jana Menegassi del; Banzato, Bárbara de Moura; Arouca, José Augusto Cabral', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Criado recentemente devido &agrave; sua relev&acirc;ncia ecol&oacute;gica, o Parque Estadual Restinga de Bertioga (PERB) localiza-se em uma &aacute;rea que tende a sofrer cada vez mais com os impactos decorrentes de um inevit&aacute;vel processo de desenvolvimentismo econ&ocirc;mico. Portanto, faz-se necess&aacute;ria a imediata implanta&ccedil;&atilde;o de programas de gest&atilde;o ambiental integrados que garantam o pronto estabelecimento do PERB e a participa&ccedil;&atilde;o popular ativa frente ao mesmo. Deste modo, o presente trabalho teve como objetivo realizar um diagn&oacute;stico ambiental da &aacute;rea do parque e seu entorno atrav&eacute;s do uso dos m&eacute;todos SWOT e GUT a fim de identificar as urg&ecirc;ncias no estabelecimento da UC. Foram analisados question&aacute;rios obtidos atrav&eacute;s de entrevistas semiabertas com pessoas-chaves ligadas &agrave; cria&ccedil;&atilde;o do PERB, sendo apontados os principais fatores externos e internos do parque. As potencia', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1772', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b5', 'AGROFUELS: BIODIESEL AS A SUSTAINABLE ALTERNATIVE ENERGY', 'Sousa, Luci Cleide Farias Soares; Gomes, Carlos Antônio Pontes; Almeida, Pedro Gomes de; Borges, Maria da Glória Borba; Andrade, Sanduel Oliveira de; Oliveira, Alexandro Veras Barreto de; Silva, Débor', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A busca intensiva por biocombust&iacute;veis como uma alternativa ao petr&oacute;leo apresenta grande import&acirc;ncia principalmente para os pa&iacute;ses emergentes, como o Brasil, uma vez que sua produ&ccedil;&atilde;o colabora com a conserva&ccedil;&atilde;o do meio ambiente, mediante a redu&ccedil;&atilde;o dos gases respons&aacute;veis pelo efeito estufa. Mediante esta problem&aacute;tica, a presente pesquisa visa &agrave; realiza&ccedil;&atilde;o de uma levantamento bibliogr&aacute;ficos sobre a produ&ccedil;&atilde;o de biodiesel como uma alternativa energ&eacute;tica sustent&aacute;vel. O Brasil &eacute; considerado pela comunidade mundial como um pa&iacute;s privilegiado, por ser de grande biodiversidade e muito rico em plantas oleaginosas, cujas culturas, em sua grande maioria, s&atilde;o restritas a fins aliment&iacute;cios. H&aacute; um enorme potencial a ser explorado em rela&ccedil;&atilde;o ao aproveitamento energ&eacute;tico de culturas oleaginosas, foco de nosso estu', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1796', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b6', 'THE CONTRIBUTION OF ROTATIONAL GRAZING FOR ENVIRONMENTAL SUSTAINABILITY', 'Sousa, Luci Cleide Farias Soares; Salgado, Alberto Bandeira; Gomes, Carlos Antônio Pontes; Almeida, Pedro Gomes de; Ferreira, Reginaldo Tácio França Vieira; Borges, Maria da Glória Borba; Andrade, San', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho tem por finalidade mostrar a contribui&ccedil;&atilde;o que o pastejo rotacionado proporciona para a sustentabilidade do sistema de produ&ccedil;&atilde;o da atividade leiteira no Nordeste brasileiro, relacionando os aspectos de cuidados com o solo, ciclagem de nutrientes, deposi&ccedil;&atilde;o de mat&eacute;ria org&acirc;nica e fauna do solo. As preocupa&ccedil;&otilde;es mundiais com os impactos ambientais se contrastam com a necessidade crescente de consumo de sua popula&ccedil;&atilde;o, fazendo com que se torne incessante a busca por sistemas de produ&ccedil;&atilde;o menos impactantes e que desenvolva a sustentabilidade t&atilde;o necess&aacute;ria para o planeta. A agropecu&aacute;ria de modo geral, sempre se destacou entre as atividades impactantes, devido necessitar de grandes &aacute;reas, provocando desmatamentos, compacta&ccedil;&atilde;o do solo e geradora de gases de efeito estufa. Sendo o leite o primeiro alimento do grupo dos mam&iacute;feros e o m', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1797', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b7', 'Levantamento das espécies e origem de árvores e arbustos das praças públicas em Goianésia – GO  – Brasil', 'Alves, Stefânia Poliana de Lima; Xavier, Elitania Gomes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A arte de usar plantas na ornamenta&ccedil;&atilde;o de ambientes acompanha a qualidade de vida e o bem estar social das pessoas. Para a realiza&ccedil;&atilde;o deste trabalho foi realizado um levantamento das esp&eacute;cies de plantas que foram utilizadas na ornamenta&ccedil;&atilde;o das pra&ccedil;as de Goian&eacute;sia Goi&aacute;s. Bem como foi realizada a compara&ccedil;&atilde;o da taxa de plantas nativas do Cerrado, plantas de outros biomas nacionais e plantas ex&oacute;ticas cultivadas. O levantamento inicial indicou que a cidade &eacute; totalmente arborizada, nas cal&ccedil;adas percebeu-se a predomin&acirc;ncia de tr&ecirc;s esp&eacute;cies em maior concentra&ccedil;&atilde;o que s&atilde;o a Caesalpinia pluviosa (sibipiruna), Licania tomentosa (oiti) e Tabebuia Ssp. (ip&ecirc;). &Eacute; necess&aacute;rio que haja mais pesquisas em rela&ccedil;&atilde;o ao potencial das plantas nativas do Cerrado e parcerias de entidades de pesquisas com os governantes locais e a popula&', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1842', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6bb', 'CENÁRIO E PERSPECTIVAS DA EDUCAÇÃO AMBIENTAL', 'Pereira Junior, Ednaldo Barbosa; Gonçalves, Catia Moreira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente artigo caracteriza-se no levantamento bibliogr&aacute;fico em diferentes bases de pesquisa que concerne ao conhecimento sobre educa&ccedil;&atilde;o Ambiental. Percebe-se que na Escola, o espa&ccedil;o apropriado para a forma&ccedil;&atilde;o ou pelo menos, tem por des&iacute;gnio a forma&ccedil;&atilde;o de cidad&atilde;os face aos m&eacute;todos e o car&aacute;ter investigativo, que ao analisar o espa&ccedil;o do aluno, contribui para o conhecimento emp&iacute;rico, te&oacute;rico e cr&iacute;tico da realidade. Nas condi&ccedil;&otilde;es pr&aacute;ticas, como treinamento de pessoal para a realiza&ccedil;&atilde;o efetiva da multidisciplinaridade do tema educa&ccedil;&atilde;o ambiental,&nbsp; envolvendo um maior n&uacute;mero de aluno, orientando a preservar o meio em que vivem, e assim tornarem-se multiplicadores em suas casas, juntos aos familiares, visinhos e outras pessoas mais pr&oacute;ximas do seu conv&iacute;vio.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1915', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6be', 'Produtividade do sorgo forrageiro irrigado com água residuária oriunda de lagoas de estabilização', 'Araujo, Francisco Nilson', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'RESUMO Objetivando avaliar o desempenho da cultura do sorgo irrigado com &aacute;gua residu&aacute;ria, proveniente de lagoas de estabiliza&ccedil;&atilde;o, efetuou-se um estudo no per&iacute;odo de junho a outubro de 2010 em Fortaleza-CE. O experimento deu-se num ambiente protegido com o plantio da cultura do sorgo forrageiro em vasos. Comparou-se a produtividade em dois ciclos da cultura: o primeiro de 0-60 dias e o segundo, com a rebrota da cultura de 60-120 dias. A forrageira foi submetida a quatro tratamentos: (T1, &aacute;gua da rede de abastecimento; T2, &aacute;gua de esgoto; T3, &aacute;gua de esgoto + 30, 90, 150 kg de NPK por ha; T4, &aacute;gua de esgoto + 15, 45, 75 kg de NPK por ha), com quatro repeti&ccedil;&otilde;es. A irriga&ccedil;&atilde;o dos vasos deu-se atrav&eacute;s de regadores manuais. No primeiro ciclo, de 0 a 60 dias, os tratamentos: T1, T2, T3 e T4 alcan&ccedil;aram produtividades de 12,363; 27,977; 21,215 e 32,250 Mg ha-1 respectivamente; j&aacute; na re', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2021', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6bf', 'Estudo da Responsabilidade Socioambiental das Empresas em Sousa – PB - Brasil', 'Nóbrega, Monnizia Pereira; Moreira, Petrúcia Marques Sarmento; Silva, Kelli Fernanda da; Maracaja, Patricio Borges; Almeida Júnior, Admilson Leite de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A atual apreens&atilde;o da gest&atilde;o empresarial prescinde do conhecimento de novos paradigmas influenciados pelo neoliberalismo e pela corrida desenfreada na busca da sobreviv&ecirc;ncia no mercado global. Esta nova maneira de gerir tem como instrumento principal a ado&ccedil;&atilde;o da responsabilidade socioambiental, ou seja, integrar as estrat&eacute;gias comerciais, posturas &eacute;ticas, sens&iacute;veis &agrave;s necessidades dos grupos que, de alguma forma, s&atilde;o afetadas pelas atividades desenvolvidas pela empresa, buscando ao lado do lucro, o desenvolvimento social e a preserva&ccedil;&atilde;o ambiental. A responsabilidade social vem recebendo crescente inser&ccedil;&atilde;o no meio empresarial, tendo como substrato a ideia de sustentabilidade econ&ocirc;mica, social e ambiental, pressupondo a subordina&ccedil;&atilde;o da atividade empresarial ao bem estar coletivo das presentes e futuras gera&ccedil;&otilde;es. O presente estudo desenvolve-se em torno dos fun', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2040', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c0', 'O microempreendedor individual e a promoção do desenvolvimento socioeconômico', 'Maracajá, Patrício Borges; Nóbrega, Monnizia Pereira; Batista, Tamylla Thaise Elias; Moreira, Petrúcia Marques Sarmento; Almeida Júnior, Admilson Leite de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O &uacute;ltimo censo realizado pelo IBGE (2003) sobre a economia informal no Brasil, demonstrou que existiam mais de 10 milh&otilde;es de empresas informais atuando no Pa&iacute;s. A pesquisa revelou que a grande parte dessas empresas eram de trabalhadores informais que possu&iacute;am o pequeno neg&oacute;cio para prover a sua subsist&ecirc;ncia e a da sua fam&iacute;lia. Ante tal realidade, o Estado se viu compelido a procurar uma alternativa que solucionasse o problema e, consequentemente, retirassem esses trabalhadores da informalidade. Foi ent&atilde;o que foi institu&iacute;da a figura do Microempreendedor Individual atrav&eacute;s da LC 128/2008, possibilitando que milh&otilde;es de empreendedores aut&ocirc;nomos, empreendedores por oportunidade e desempregados tivessem a chance de abrir a sua empresa com baixo custo e obtivessem benef&iacute;cios e facilidades que favorecessem a continua&ccedil;&atilde;o da empresa. Assim, objetiva o presente trabalho investigar o impacto soci', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2045', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c2', 'ESTUDO DA ECOLOGIA DA PAISAGEM NO ESTUÁRIO DO RIO JAGUARIBE NO LITORAL DO CEARÁ (BRASIL) NUMA PERSPECTIVA GEOAMBIENTAL', 'Ferreira Costa, Carlos Germano', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A plan&iacute;cie litor&acirc;nea apresenta vulnerabilidade ambiental, ao mesmo tempo em que possui grande potencial para o desenvolvimento de atividades tur&iacute;sticas por apresentar caracter&iacute;sticas pr&oacute;prias de forte beleza c&ecirc;nica na forma&ccedil;&atilde;o da paisagem. No estudo em quest&atilde;o foi buscado compreender a din&acirc;mica que se estabelece na unidade geoambiental da plan&iacute;cie litor&acirc;nea e da Foz do Rio Jaguaribe entre os Munic&iacute;pios de Aracati e Fortim no Estado do Cear&aacute;. Com tal entendimento da &aacute;rea de estudo, foram determinados os problemas presentes no local, identificados e avaliados os impactos ambientais na Foz do Rio Jaguaribe e plan&iacute;cie costeira mediante as transforma&ccedil;&otilde;es da paisagem pela a&ccedil;&atilde;o natural e antr&oacute;pica utilizando a an&aacute;lise sist&ecirc;mica como m&eacute;todo para comprender a ecologia da paisagem. Com o entendimento da &aacute;rea de estudo obtido pel', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2068', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c3', 'Certificação Orgânica e suas diretrizes: um estudo na Associação Comunitária de Agricultores Familiares do Perímetro e Adjacências – Pau dos Ferros/RN', 'Medeiros, Aline Carla de; Batista, Kennya Cristiane Pereira; Fernandes Júnior, José Vivaldo Machado; Menezes, Edivaldo Rabelo de; Sales Júnor, Francisco Vieira; Borges, Maria da Gloria Borba; Freitas,', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Nas ultimas d&eacute;cadas a sustentabilidade e respeito com o meio ambiente, tem sido uma das maiores preocupa&ccedil;&otilde;es das empresas, do mesmo modo que a busca pela qualidade de vida que esses produtos possam vir a oferecer vem sendo um fator fundamental no momento da escolha de determinados produtos. Uma forma de obten&ccedil;&atilde;o de melhorias quanto &agrave; qualidade estaria na certifica&ccedil;&atilde;o de produtos org&acirc;nicos que, segundo a Sociedade Nacional da Agricultura (SNA), consiste em assegurar que um determinado produto, processo ou servi&ccedil;o obedece as normas e pr&aacute;ticas da produ&ccedil;&atilde;o org&acirc;nica. Logo, para a obten&ccedil;&atilde;o dessa certifica&ccedil;&atilde;o faz-se necess&aacute;rio a adequa&ccedil;&atilde;o a uma s&eacute;rie de exig&ecirc;ncias. Entre elas est&aacute; a necessidade de um constante planejamento e controle da qualidade desses produtos produzidos. Assim, o objetivo neste artigo foi identificar a efetiva&', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2147', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c6', 'INDICADORES DE QUALIDADE DO SOLO EM AGROECOSSISTEMAS', 'Rangel, Otacílio José P.; Vargas, Rozimelia', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A presente revis&atilde;o de literatura tem como objetivo descrever os principais indicadores de qualidade em agroecossistemas, dando &ecirc;nfase aos indicadores qu&iacute;micos e biol&oacute;gicos de qualidade do solo, com foco nos par&acirc;metros referentes aos microrganismos e &agrave; mat&eacute;ria org&acirc;nica. Existem v&aacute;rias propostas de indicadores para avaliar a qualidade do solo, como os f&iacute;sicos, qu&iacute;micos e biol&oacute;gicos. Os indicadores de qualidade f&iacute;sica do solo est&atilde;o associados &agrave; infiltra&ccedil;&atilde;o, reten&ccedil;&atilde;o e disponibiliza&ccedil;&atilde;o de &aacute;gua. J&aacute; os indicadores qu&iacute;micos afetam as rela&ccedil;&otilde;es solo-planta, o poder tamp&atilde;o e a mobilidade de contaminantes. Os indicadores biol&oacute;gicos s&atilde;o definidos como a presen&ccedil;a ou aus&ecirc;ncia de alguma esp&eacute;cie, planta ou animal, em dada &aacute;rea, associada &agrave; determinada condi&ccedil;&atilde', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2177', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c7', 'Diagnóstico visual da arborização tombada do municipio de Cerro Corá, RN, Brasil.', 'Sousa, Debora Ferraz Moura Alves de; Andrade, Francisco Marcelo Vicente de; Maracajá, Patrício Borges; Silveira, Leonardo Palhares da; Vasconcelos, Walmir Souza; Freire, Maciel dos Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A arboriza&ccedil;&atilde;o proporciona melhorias nas condi&ccedil;&otilde;es ambientais das cidades. As &aacute;rvores contribuem principalmente na manuten&ccedil;&atilde;o do microclima, diminuindo a polui&ccedil;&atilde;o e ainda na conserva&ccedil;&atilde;o da biodiversidade regional. Uma arboriza&ccedil;&atilde;o bem planejada poder&aacute; garantir a integridade da vegeta&ccedil;&atilde;o em conformidade com a infraestrutura urbana. O objetivo deste trabalho foi diagnosticar a situa&ccedil;&atilde;o da vegeta&ccedil;&atilde;o arb&oacute;rea tombada na zona urbana de Cerro Cor&aacute;, RN, Brasil. Para a amostragem foi utilizado o m&eacute;todo qualiquantitativo, sendo identificada a esp&eacute;cie, a ocorr&ecirc;ncia, e o estado fitossanit&aacute;rio. Foram amostrados 21 indiv&iacute;duos arb&oacute;reos, totalizando 9 esp&eacute;cies, nas quais apenas 8 s&atilde;o nativas e 13 de origem ex&oacute;tica. Quase 52,4% dos indiv&iacute;duos apresentaram bom estado fitossanit&aacute;r', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2202', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d1', 'Comparativos de levantamentos fitossociológicos realizados em diferentes áreas da Caatinga', 'Santos, José Ozildo dos; Maracajá, Patrício Borges; Chave, Alan Del Carlos Gomes; Santos, Rosélia Maria de Sousa; Fernandes, Almair de Albuquerque', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A fitossociologia pode ser definida como a ci&ecirc;ncia das comunidades vegetais ou o conhecimento da vegeta&ccedil;&atilde;o em seu sentido mais amplo. Ela serve para explicar os fen&ocirc;menos que se relacionam com a vida das plantas dentro das unidades ecol&oacute;gicas. No cen&aacute;rio atual, ela &eacute; considerada uma valiosa ferramenta na determina&ccedil;&atilde;o das esp&eacute;cies mais importantes dentro de uma determinada comunidade. Atrav&eacute;s dos levantamentos fitossociol&oacute;gicos &eacute; poss&iacute;vel estabelecer graus de hierarquiza&ccedil;&atilde;o entre as esp&eacute;cies estudadas. O objetivo do presente artigo &eacute; estabelecer um comparativo entre os resultados referentes a quatro levantamentos fitossociol&oacute;gicos realizados em diferentes &aacute;reas de caatinga, determinando as esp&eacute;cies de maiores valores de domin&acirc;ncia e de valor de import&acirc;ncia. Constatou-se que os levantamentos flor&iacute;sticos e fitossociol&oacute;gi', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2487', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d4', 'Saneamento Básico: uma questão de qualidade ambiental na cidade de Pombal - PB', 'Freitas, Angleib Justino Figueiredo de; Gomes, Alcides Rodrigues; Almeida, Ricardo Ricelli Pereira de; Ferreira, Aline Costa; Crispim, Diêgo Lima; Chaves, Alan Del Carlos Gomes; Andrade, Luis Carlos F', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Um dos componentes fundamentais na infraestrutura de uma localidade é o saneamento básico. Esse serviço é indispensável para a saúde humana e para o meio ambiente. Entretanto, esse serviço não consegue acompanha o ritmo do crescimento populacional e o desenvolvimento desordenado dos ambientes urbanos. O presente trabalho teve a finalidade de analisar as condições do saneamento básico da cidade de Pombal-PB, com o propósito de investigar alguns serviços de saneamento básico na cidade supracitada. No desenvolvimento do trabalho foram utilizados dados bibliográficos (incluindo consultas à Internet, livros e publicações referentes ao assunto e à área em estudo). Além disso, realizou-se um levantamento de campo, utilizando a metodologia espontânea (Ad Hoc) para verificar possíveis impactos ambientais. Constatou-se que as condições do saneamento básico na cidade de Pombal-PB, necessita de uma intervenção do poder público e de algumas ações pontuais.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2536', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d6', 'Perspectivas Teórico-Conceituais sobre Desenvolvimento Sustentável e Economia Solidária', 'Feitosa, Anny Kariny', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A presente pesquisa tem como objetivo fornecer informa&ccedil;&otilde;es sobre o desenvolvimento sustent&aacute;vel e economia solid&aacute;ria como alternativa de gera&ccedil;&atilde;o de renda e exerc&iacute;cio da cidadania para popula&ccedil;&otilde;es exclu&iacute;das do mercado de trabalho. A metodologia adotada foi pesquisa bibliogr&aacute;fica e documental, por meio da busca principalmente em livros, peri&oacute;dicos e nos diplomas legais pertinentes. Assim, conclui-se que, apesar das dificuldades, a economia solid&aacute;ria resiste e tem demonstrado significativos os resultados de benef&iacute;cios apontados no campo da gera&ccedil;&atilde;o de trabalho e renda, da cidadania e do desenvolvimento sustent&aacute;vel local e meio ambiente.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2638', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6da', 'Processo de Implantação de Sistema de Gestão Ambiental (SGA) baseado na NBR ISO 14001', 'Costa, Raquel de Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este artigo busca elucidar atrav&eacute;s de revis&otilde;es bibliogr&aacute;ficas o processo de implanta&ccedil;&atilde;o de um Sistema de Gest&atilde;o ambiental (SGA) com base na norma ISO 14001. Ele explica &nbsp;teoricamente todas as etapas que devem ser seguidas pela organiza&ccedil;&atilde;o que deseja implantar um SGA ou somente alinh&aacute;-lo a um outro sistema de gest&atilde;o, como o Sistema de Gest&atilde;o de Qualidade (SGQ) elaborado a partir da norma ISO 9001, por exemplo. Um aspecto descrito neste trabalho &eacute; o uso da metodologia PDCA (Planejar-Executar-Verificar-Agir) a partir de uma pol&iacute;tica ambiental para implanta&ccedil;&atilde;o do SGA ISO 14001. Com essa metodologia &eacute; poss&iacute;vel dividir o sistema de gest&atilde;o em fases, buscando continuamente a melhoria do desempenho ambiental da empresa, seja ela de pequeno, m&eacute;dio ou grande porte.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2735', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6db', 'LEVANTAMENTO FLORÍSTICO DA ARBORIZAÇÃO URBANA NAS PRINCIPAIS VIAS PÚBLICAS DO MUNICÍPIO DE BOA VENTURA – PB', 'Carvalho, Jaires Alvarenga de; Soares, Fernanda de Santana; Lacerda, Marcos Andre; Silva, Zaqueu Lopes da; Medeiros, Egnaldo Nascimento de; Medeiros, Roberta de Souza; Costa, João Paulo Medeiros', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este estudo teve como objetivo&nbsp;diagnosticar as esp&eacute;cies existentes nas principais ruas do munic&iacute;pio de Boa Ventura &ndash; PB, mais precisamente nas quatro ruas com maior fluxo e com maior n&uacute;mero de &aacute;rvores. O trabalho de coleta de dados foi realizado atrav&eacute;s de visitas &ldquo;in loco&rdquo;, entre os dias 14/05/2013 e 31/05/2013 nas ruas Ang&eacute;lica Soares, Coronel Zuza Lacerda, Augusto Ramalho e Em&iacute;lia Leite. Foi aplicado um question&aacute;rio aos moradores dessas localidades para obter informa&ccedil;&otilde;es sobre a percep&ccedil;&atilde;o dos entrevistados quanto &agrave; arboriza&ccedil;&atilde;o urbana local. Atrav&eacute;s do diagn&oacute;stico obtido nas ruas de estudo e da aplica&ccedil;&atilde;o do question&aacute;rio ficou constatado que a arboriza&ccedil;&atilde;o das principias ruas do munic&iacute;pio de Boa Ventura &ndash; PB conta com 240 &aacute;rvores, distribu&iacute;das em quatro esp&eacute;cies e quatro fam&iac', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2881', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6dc', 'Um Planeta Basta', 'Lucchine, Fernanda Rocha', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '&Eacute; frequente a busca de infinitas solu&ccedil;&otilde;es em rela&ccedil;&atilde;o aos problemas ambientais, que desde meados do s&eacute;culo XX ganha cada vez mais destaque. O assunto se tornou obrigat&oacute;rio em discuss&otilde;es pol&iacute;ticas, empresariais, em reuni&otilde;es mundiais como a Rio 92 e Rio +20, entre pesquisadores e em alguns setores dos movimentos sociais. A quest&atilde;o ambiental &eacute; fundamental &agrave; exist&ecirc;ncia humana, pois &eacute; do ambiente que prov&eacute;m a base material de reprodu&ccedil;&atilde;o da vida, ali&aacute;s, das diversas formas de vida. Em outras palavras, &eacute; do ambiente que s&atilde;o extra&iacute;dos os recursos para produ&ccedil;&atilde;o de abrigo, alimento, artefatos t&eacute;cnicos, vestu&aacute;rio, entre tantas outras coisas necess&aacute;rias &agrave; manuten&ccedil;&atilde;o da vida, qualquer que seja a forma de organiza&ccedil;&atilde;o social que os humanos estabeleceram, n&atilde;o ser&aacute; poss&', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2953', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e1', 'MÉTODOS DE AVALIAÇÃO DE IMPACTOS AMBIENTAIS UTILIZADOS NA REVISTA BRASILEIRA DE GESTÃO AMBIENTAL', 'Silva, Tatiana Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Avaliar um impacto ambiental é compreender a extensão das modificações que as ações humanas promovem no meio ambiente. E para as diferentes situações, objetivos ou empreendimentos são apresentados na literatura diferentes métodos de identificação e avaliação de impactos ambientais. Nesta revisão apresentaram-se os seguintes métodos: Ad Hoc, Listagem, Superposição de Cartas, Modelos de Simulação, Matrizes, Diagrama de Interação e Análise do Tipo Efeito de Falha, Modelo proposto por Moreira (2006) e Observação em Campo.  A partir desse conhecimento buscaram-se na Revista Brasileira de Gestão Ambiental, artigos publicados que tenham se valido de métodos para avaliação de impactos. Ao término da seleção dos artigos, realizou-se uma análise a fim de identificar o método mais aplicado em relação ao total de publicações pelo periódico, apresentando o Ad Hoc como o método com maior aplicação pelos autores.Palavras-chave: Ad Hoc, Análise do Tipo Efeito de Falha e Listagem', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/3168', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ef', 'A SECA NO SERTÃO PARAIBANO: CAUSAS E CONSEQUÊNCIAS', 'Sobrinho, Antonio Izidro; Sousa, Aleksandro Jânio Jacinto de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Esta pesquisa, de natureza bibliográfica, tem por objetivo geral identificar as causas e diagnosticar as consequências produzidas pela seca no sertão paraibano. O Polígono das secas apresenta um regime pluviométrico marcado por extrema irregularidade de chuvas, no tempo e no espaço. Nesse cenário, a escassez de água constitui um forte entrave ao desenvolvimento socioeconômico e, até mesmo, à subsistência da população. A ocorrência cíclica das secas e seus efeitos catastróficos são por demais conhecidos e remonta aos primórdios da história. A seca é o fenômeno climático causado pela falta ou insuficiência de chuvas numa região, por um longo período de tempo, o que provoca consideráveis desequilíbrios hidrológicos. Ela ocorre quando a evapotranspiração - fenômeno que consiste no transporte da água do solo para o ar, através das plantas - ultrapassa por algum tempo a precipitação. Em outras palavras, existe seca numa região determinada quando acaba a disponibilidade de água para a evapotr', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4356', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6f1', 'INTERFERÊNCIA DO REGIME PLUVIOMÉTRICO NA INCIDÊNCIA DE FOCOS DE CALOR NO SUDESTE PARAENSE CONSIDERANDO O FENÔMENO EL NIÑO OSCILAÇÃO- SUL', 'Neves, Raisa Rodrigues; Sousa, Lilian Paixão Aleixo de; Araujo, Eduirbe Castro de; Gonçalves, Edkeyse Dias', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Esta pesquisa teve como objetivo quantificar a ocorrência do número de focos de calor em 9 municípios localizados no Sudeste Paraense e verificar sua relação com o regime pluviométrico da região, considerando a interferência dos fenômenos climáticos El Niño e La Niña. Para isso, foram utilizados dados do Instituto Nacional de Pesquisas Espaciais e ferramentas do Sistema de Informações Geográficas. Após a obtenção dos dados, foram criados mapas de densidade pelo método de Kernel para representar as incidências de queimadas. Os dados de precipitação foram obtidos pelo Sistema de Informações Hidrológicas (ANA) e as falhas foram preenchidas através do método de ponderação regional. A partir disso, foi possível elaborar gráficos para comparar os períodos de ocorrência de focos de calor com o regime pluviométricos da área em estudo. Como resultados, verificou-se que no ano de 2010 houve uma redução nos índices de chuva dos municípios, principalmente nas áreas de Cumaru do Norte, Santa Maria ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4412', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6f2', 'Diagnóstico da comunidade bentônica no âmbito do licenciamento ambiental da ponte sobre o rio Corrente, Correntina - BA', 'Ratton, Eduardo; Ramos, Sandra Martins; Giusti, Donizeti Antonio; Nadal, Carlos Aurélio', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo deste artigo é apresentar uma síntese sobre o processo de licenciamento de obras lineares e resultados obtidos no diagnóstico da macrofauna bentônica, realizado durante elaboração do EIA/RIMA da ponte projetada sobre o rio Corrente, município de Correntina, na diretriz da BR-135/BA. As coletas foram realizadas em agosto de 2013 (período de estiagem) e janeiro de 2015 (período chuvoso). Para a amostragem da macrofauna bentônica foram determinados dez pontos amostrais distribuídos ao longo do rio Corrente, abrangendo trechos a montante e a jusante da implantação do empreendimento. No momento da coleta foram aferidos os seguintes parâmetros: profundidade do canal (m), pH, temperatura da água (°C), oxigênio saturado (%) e oxigênio dissolvido (mg/L). Os parâmetros abióticos que apresentaram maior variação entre os períodos amostrais foram: pH (menores valores no período de chuva), temperatura da água e OD (mais elevados no período de maior pluviosidade). A estrutura e composição ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4452', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6f5', 'SISTEMAS DE GESTÃO AMBIENTAL EM CURTUMES', 'Silva, Tayanne Graciette Nascimento; Santos, Gil Rodrigues dos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O amplo e rápido crescimento populacional ocasionou um grande desequilíbrio ambiental devido à falta de planejamento socioambiental da população acarretando assim uma série de impactos ambientais. Neste contexto, houve também uma crescente procura por produtos de couro e com isso foram surgindo os impactos ambientais devido a utilização durante o processamento e fabricação de produtos altamente tóxicos. Desta forma, os curtumes necessitam de uma rigorosa fiscalização por meio do cumprimento das normas ambientais relativas ao licenciamento ambiental e ao controle do meio ambiente por conta do alto consumo de recursos naturais e grande produção de resíduos que é gerado. A Gestão Ambiental é a forma mais eficaz de controle ambiental das atividades de produção, pois tem como objetivo identificar as ações que se adequam mais as obrigações legais e por meio de um rigoroso sistema de planejamento. Esse trabalho teve como objetivo mostrar a importância do Sistema de Gestão Ambiental (SGA) na p', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4585', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6f7', 'Mapeamento setorial com a utilização de índices de sustentabilidade no município de Juruá no Estado do Amazonas', 'Fernandes, Lindemberg Lima; Mattos, Matheus Augusto Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Estudos e alternativas na análise de índices de sustentabilidade são importantes para o controle e promoção da qualidade de vida de toda a população. Neste contexto, esse artigo teve como objetivo investigar a situação do município de Juruá-AM por meio de indicadores sociais, culturais, econômicos e ambientais. Foram utilizados quatro métodos de análise: índices sociais, culturais, econômicos e ambientais. Para tanto, foram empregados algumas informações por meio de dados secundários de órgãos governamentais, tais como: SNIS, IBGE e COSAMA. Os resultados indicaram que desde a fundação do município de Juruá ocorreram mudanças na estrutura municipal e no cotidiano dos moradores. Contudo, muito irrisórios em relação ao potencial que a região oferece para os seus habitantes.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4666', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6fd', 'Morfometria das bacias hidrográficas dos rios Caraparu e Maguari-Açú, Região Metropolitana de Belém, Pará, Brasil', 'Moraes dos Santos, Luma Lorena; Menescal Bittencourt, Germana; Silvano Silva Rodrigues, Rodrigo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Objetivou-se realizar a caracterização morfométrica das bacias hidrográficas dos rios Caraparu e Maguari-Açú, localizados na Região Metropolitana de Belém, nordeste do Estado do Pará. Inicialmente gerou-se o Modelo Digital de Elevação a partir de SRTM com resolução espacial de 30 m, utilizando o sistema de informações geográficas, por meio do software ArcGis 10.1 e da extensão ArcHydro, foram calculados alguns parâmetros morfométricos para o estudo do comportamento hidrológico das bacias. As áreas de drenagem encontradas foram de 373,993 km² para o rio Caraparu e 21,228 km² para o rio Maguari-Açú; os perímetros foram de 148,159 km e 39,155 km, respectivamente. As bacias hidrográficas dos rios possuem formato alongado, comprovado por seus coeficientes de compacidade, fator de forma, índice de circularidade e de alongamento; com baixas densidades de drenagem e com padrões dendríticos. A forma mais alongada das bacias hidrográficas indica que as precipitações pluviométricas sobre elas se ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4747', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6ff', 'Uma abordagem histórica e teórica das políticas públicas de combate à seca e convivência com o semiárido', 'Sousa, Jacimone Delfino de; Lima, Decio Carvalho; Brito, Felipe Cesar da Silva; Maracaja, Patricio Borges; Paiva, Ana Catarina Costa de; Medeiros, Aline Carla de; Medeiros, Altevir Paula de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente artigo busca apresentar as bases históricas e teóricas das políticas de combate aos efeitos da seca na região Nordeste, abordando as principais políticas e grupos criados a fim de combater os efeitos dos longos períodos de estiagem. Enfatizando-se as tentativas de desenvolvimento da região.No tocante ao desenvolvimento econômico e sustentável serão explicitadas estratégias de convivência com as secas, bem como os novos paradigmas das políticas públicas e suas consequencias econômicas e ambientais. Interpretando a sustentabilidade como sendo indispensável para o desenvolvimento, com base na eficiência tecnológica e na racionalidade produtiva, sendo necessária e possível para a convivência com o semiárido.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4749', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c701', 'Importância socioeconômica e cultural da COOPERVIDA na agricultura familiar do Rio Grande do Norte', 'Maracajá, Patrício Borges; Paiva, Anna Catarina Costa de; Silva, Cesar Carlos Martins da; Medeiros, Aline Carla de; Medeiros, Altevir Paula de; Silva, Rosilene Agra da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A realidade dos movimentos sociais é bastante dinâmica, diversa e complexa, há exemplo disso, foi o que o Brasil viveu em meados dos anos 1970 e 1980, ao qual tratou de um período em que os sujeitos sociais buscavam seus direitos políticos e igualitários, em virtude a resistência ao regime autoritário da época. Com o passar dos anos, ocorreu o surgimento de outras formas de organização popular institucionalizadas que tinham o propósito acessar uma democracia humanizada. Com base nessa conjuntura histórica e na luta oscilante do cooperativismo brasileiro, existe atualmente uma legislação específica. A Cooperativa de Assessoria e Serviços Múltiplos ao Desenvolvimento Rural – COOPERVIDA surgiu de um processo de debate forte e coletivo de uma nova proposta de assessoria técnica voltada para a base agroecológica e camponesa. Pensou-se no nome e na logo, ao qual tivessem uma maior representação da proposta a ser trabalhada na agricultura familiar, como sendo Cooper = Cooperativa, Vida = novo', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4758', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c702', 'Estresse salino e adubação mineral na composição nutricional da cultura do milho', 'Maracajá, Patrício Borges; Lima, Decio Carvalho; Ferreira, Alcides Almeida; Medeiros, Aline Carla de; Medeiros, Altevir Paula de; Silva, Francisco Alves da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A salinidade é um dos fatores com maior influencia no estágio de crescimento, desenvolvimento e produção das culturas. Neste sentido, se objetivou avaliar a influência de água de qualidade inferior sobre o crescimento, absorção e distribuição de macronutrientes na cultivar de milho AG1051 em ambiente protegido.  O experimento aonde as plantas AG1051 foram conduzidas em citropote com capacidade de 3,5 kg, foi executado no Centro de Ciências e Tecnologia Agroalimentar-CCTA da Universidade Federal de Campina Grande- UFCG na cidade de Pombal, PB. O delineamento experimental adotado foi inteiramente casual, em esquema fatorial 5 x 4 x 2, com quatro repetições, correspondentes a cinco níveis de condutividade elétrica da água - CEa (0,3; 1,1; 1,9; 2,7; 3,5 dS m-1), quatro doses de Sulfato de Cálcio (2,5; 3,2; 3,9 e 4,6 g) e duas Sulfato de Magnésio ( 2,5 e 3,5 g). Sendo assim, permite-se concluir que há diferença entre níveis de água de irrigação, apresentando posições de decréscimo no cresci', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4760', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c707', 'Mineração de caulim no município de Equador-RN Brasil: andragogia e percepção ambiental', 'Andrade, André Luís Simões; Maracaja, Patricio Borges; Sousa, Antonio Augusto Pereira de; Medeiros, Aline Carla de; Oliveira, Djane de Fátima', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os impactos antropomórficos no meio ambiente têm sido amplamente discutidos em diversas atividades produtivas, variando somente a intensidade de como será catastrófica a realidade futura caso nada seja realmente feito. O consenso é de que o ponto inicial para as mudanças comportamentais está na conscientização, para tanto, as instituições públicas, privadas e filantrópicas promovem campanhas de informação, poderes públicos criam leis e consumidores corporativos e individuais tomam atitudes proativas quanto a questão ambiental. Neste trabalho buscou-se, através de pesquisa bibliográfica em uma amostra de 23 trabalhos no período de 1991 a 2011, a identificação de que as soluções para a problemática ambiental causada pela mineração e beneficiamento do caulim em Equador/RN vêm sendo tratada apenas de forma tecnológica e, pautado em estudos científicos multidisciplinares, demonstrar que há viabilidade em focar os esforços mitigadores na área educacional, pautado na Andragogia, despertando a', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4797', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c70a', 'Caracterização morfométrica da bacia hidrográfica do rio Tauá, nordeste paraense', 'Lira Pessoa, Francisco Carlos; Conceição Paiva de Ataide, Lorena; Silvano Silva Rodrigues, Rodrigo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As características físicas de uma bacia constituem elementos de grande importância para avaliação do seu comportamento hidrológico. Foi utilizado o Modelo Digitais de Elevação (MDE) para o cálculo de variáveis associadas as características morfométricas da Bacia Hidrográfica do Rio Tauá situada no nordeste paraense, afim de obter o conhecimento quantitativo das variáveis e planejar o gerenciamento deste recurso hídrico. Para realizar a caracterização da rede de drenagem, tomou-se os seguintes valores para o rio Tauá: Comprimento da rede de drenagem (Lu) de 177,96 km, sendo que seu canal principal possui 39,41 km; Comprimento axial da bacia (LB) de 29,30 km Observou-se que as características de declividade da bacia informam que o relevo é predominante plano e uma forma alongada, possibilitando fácil escoamento das águas superficiais, sendo seu sistema de drenagem bem ramificado. Os resultados observados no presente trabalho podem ser utilizados para a análise da adequação do local das e', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4943', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c710', 'Projeto de horta orgânica e suas conjunturas em CREE-MOS como promoção de interação familiar, escolar e social de crianças com necessidades especiais', 'Paiva, Anna Catarina Costa de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O crescimento no consumo de alimentos saudáveis (livres de agrotóxicos) se deve a relação direta que os mesmos têm com a obtenção de saúde. Com isto sua alta demanda no mercado eleva os custos e dificulta quantidade para aquisição. Diante desse embate instituições de ensino que almejam consumi-los procuram alternativas para produção orgânica em seu espaço físico com auxílio de técnicos e ONGs através de trabalho voluntário. Durante quatro anos o Centro Regional de Educação Especial de Mossoró (CREE – MOS) e o Grupo Verde de Agricultura Alternativa (GVAA) desenvolveram o Projeto de produção de alimentos orgânicos, junto aos alunos portadores de variadas necessidades especiais, com atividades focadas na agroecologia e no desenvolvimento sustentável. Onde, a máxima resposta das atividades é feita através das Manhãs Verdes. Cuja proposta dessas manhãs recreativas foi proporcionar a integração com a comunidade local e âmbito escolar, além de conferir melhorias às diversas atividades aos est', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4975', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c711', 'Observação dos principais impactos ambientais inseridos no contexto dos empreendimentos de geração de energia eólica', 'Paiva, Anna Catarina Costa de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A demanda energética no Brasil está ampliando sua capacidade instalada para gerar energia cada vez mais limpa, renovável e estável. O estudo das questões ambientais e energéticas vem sendo uma proposta de um novo diálogo para os profissionais e sociedade. Com isso, o Estado do Rio Grande do Norte surge com forte potencial para construção de novos parques eólicos para geração de energia.  O que pode ocasionar a origem de uma ampla alteração da paisagem local após a sua instalação. Dentre essas modificações, pode-se retratar: impacto visual, ruído local, desmatamento da mata nativa e impacto com a fauna. Então, o presente estudo objetivará na busca observação do parâmetro ambiental inserido no contexto da energia eólica e suas possíveis soluções.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4976', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c712', 'Programa uma Terra e Duas Águas no Contexto da Agricultura Familiar do Semiárido do Rio Grande do Norte', 'Paiva, Anna Catarina Costa de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O semiárido Brasileiro é marcado por diversas desigualdades sociais, principalmente por água e por terra. Por isso, foi criado em 2007 o Programa Uma Terra e Duas Águas - P1+2, sendo integrado como uma das ações do Programa de Formação e Mobilização Social para Convivência com o Semiárido da Articulação do Semiárido Brasileiro – ASA BRASIL. Como uma das instituições fundadoras da ASA e que trabalha na execução de tecnologias sociais para convivência com semiárido, dentre elas o P1+2 tem-se a Cooperativa de Trabalho de Assessoria e Prestação de Serviços Múltiplos para o Desenvolvimento Rural – COOPERVIDA, onde as ações desenvolvidas têm importância no fortalecimento da agricultura familiar. Este trabalho tem como objetivo realizar o estudo de diagnóstico sobre o contexto da importância do P1+2 na agricultura familiar. Pensando nisso, optou-se por um estudo sobre o P1+2 executado pela COOPERVIDA através de Contrato de Parceria que beneficiou as cidades de Serra do mel/RN e Mossoró/RN, co', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4977', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c713', 'Desempenho agronômico da melancia sob fontes de matéria orgânica e biofertilizantes', 'de Figueredo, Janailson Pereira; Linhares, Paulo Cássio Alves; Silva, Joselma Nogueira da; Irineu, Toni Halan da Silva; Silva, Josimar Nogueora da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A melancia é uma cultura de importância econômica, que responde de forma satisfatória à adubação orgânica, sendo uma alternativa de produção sustentável, proporcionando incremento na produtividade. Assim, o objetivo deste experimento foi avaliar o desempenho agronômico da melancia em função de diferentes fontes de matéria orgânica incorporadas ao solo e biofertilizantes. O experimento foi realizado no período de março a junho de 2012, em condições de campo, na Universidade Estadual da Paraíba-PB. O delineamento experimental adotado foi o de blocos completos casualizados, no esquema fatorial 6 x 3, com 4 repetições. O primeiro fator constituiu-se de 6 fontes de matéria orgânica (F1= húmus de minhoca, F2= esterco bovino, F3= esterco caprino, F4= cama de suíno, F5= cinza de madeira e F6= resíduo sólido de biofertilizante) e o segundo fator foi constituído por três tipos de biofertilizantes (B1= biofertilissante não enriquecido, B2= biofertilissante enriquecido com farinha de rocha e o B3=', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4986', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c718', 'Levantamento e análise da arborização urbana da Av. São João na cidade de Cáceres-MT', 'de Melo, Rodrigo; Rodrigues, Wellens Millene Moraes; da Silva, Fulvianny Cristina; Franco, Fernanda Miguel; Agustini, Kátia Utre', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A paisagem urbana está em constante alteração, o aumento da população acelera ainda mais essas mudanças, onde antes era constituído por vegetação nativa agora é uma paisagem composta por pavimentação e construções. Nesse contexto, este trabalho teve como objetivo verificar as condições da arborização, assim como a situação das calçadas da Avenida São João, na cidade de Cáceres-MT. Dessa forma, buscou-se diagnosticar as condições da arborização do local, possíveis causas dos problemas encontrados e os impactos resultantes do mau planejamento do manejo da arborização urbana. Primeiramente foi realizado um censo das espécies arbóreas que se encontravam na Avenida São João no trecho entre a rodoviária e o hospital Bom Samaritano. Foi realizado também um levantamento com relação às características das calçadas. Na análise a respeito das espécies plantadas é constatado um número maior de espécies exóticas, sendo um total de 65%. Quanto ao porte, 59% são de grande porte, 38% médio e apenas 3%', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5267', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c719', 'Impactos das alterações de uso e ocupação do solo considerando a variabilidade climática e hidrológica na região do semiárido', 'Maracajá, Patricio Borges; Medeiros, Paulo da Costa; Siqueira, Mariana da Silva de; Ribeiro, George do Nascimento; Alcântara, Hugo Morais de; Medeiros, Aline Carla de; Afonso, João Paulo Sobral Dias', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '- O uso e ocupação do solo associado a variabilidade climática em regiões semiáridas influenciam diretamente o regime hidrossedimentológico de pequenas bacias hidrográficas estritamente rurais. O quinto relatório do Intergovernmental Panel on Climate Change (IPCC) alertou sobre fenômenos climáticos e meteorológicos extremos como secas e eventos de chuvas intensas. No semiárido brasileiro as áreas rurais são ocupadas prioritariamente por agricultores familiares que tem seu modo produtivo baseado no cultivo de sequeiro e na pecuária de subsistência fortemente dependentes do clima, sendo assim, uma região muito vulnerável a essas mudanças climáticas. Para caracterização do clima futuro foram utilizadas anomalias médias de precipitação para o período de 2040-2069 projetadas por seis modelos climáticos do IPCC.Este trabalho visa diagnosticar o impacto de mudanças climáticas sobre a lâmina escoada e a produção de sedimentos em uma pequena bacia hidrográfica, utilizando ferramentas computacio', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5272', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c71b', 'Impacto econômico no custo da água potável Sobre a renda familiar em zona rural da Bacia hidrográfica do rio paraíba/PB', 'Barros, José Romário Lacerda de; Maracaja, Patricio Borges; Medeiros, Paulo da Costa; Ribeiro, George do Nascimento; Alcântara, Hugo Morais de; Medeiros, Aline Carla de; Afonso, João Paulo Sobral Dias', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Dentre os instrumentos de gestão previstos na Lei nº 9.433/97, a cobrança pelo uso da água, é um dos mais complexos no processo de implementação da Política de Recursos Hídricos. Uma das grandes dificuldades da valoração dos recursos hídricos é que não existem mercados de água formais. Para apoiar a valoração da água é importante considerar os princípios da teoria econômica, com a finalidade de considerar os aspectos subjetivos inerentes a esta teoria, tais como aspectos socioeconômicos, que irão avaliar se o preço da água está dentro da faixa de renda dos usuários. O presente trabalho apresenta simulações de demandas de água para consumo humano, com a finalidade de avaliar o impacto econômico sobre a renda familiar dos moradores da comunidade Salão, localizada na zona rural do Município de Serra Branca, Região do Alto Curso do Rio Paraíba/PB. Foi observado que os maiores impactos estão associados às famílias de baixa renda, e com maior número de moradores por domicílio, sendo a água m', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5274', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c71e', 'O estudo da geração de resíduos sólidos orgânicos: Na feira da Prata da cidade de Campina Grande', 'Oliveira, Francisco Fabrício Damião de; Sousa, Glaucio de Meneses; Santos, Valterlin da Silva; Lima Araujo, Breno José Barbosa; Vieira de Figueiredo, Caio Franklin', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A urbanização e industrialização das sociedades modernas têm originado uma produção e acúmulo de resíduos sólidos. Um dos tipos de resíduos sólidos mais produzidos diariamente por diversos setores da sociedade são os resíduos orgânicos, resíduos estes de origem animal ou vegetal, oriundos da vida doméstica ou urbana, da atividade agrícola ou industrial, de saneamento básico, entre outros. Em geral, os hortifrútis das feiras livres caracterizam-se pela produção efetiva de resíduos sólidos orgânicos que são produzidos desde a recepção e organização dos alimentos nas barracas e/ou descartados no chão pelos feirantes até a disposição final inadequada, que acarreta diversos problemas ambientais como também de saúde. O presente estudo tem por objetivo quantificar o volume dos resíduos sólidos orgânicos gerados na comercialização de produtos de hortifruticultura, na Feira da Prata em Campina Grande - PB. O trabalho foi desenvolvido por meio de uma abordagem quantitativa junto aos comerciantes', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5329', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c71f', 'Avaliação socioeconômica dos impactos da seca 2012-2016 no perímetro irrigado de São Gonçalo – PB', 'Oliveira, Francisco Fabrício Damião de; Sousa, Glaucio de Meneses; Santos, Valterlin da Silva; Lima Araújo, Breno José Barbosa; Figueiredo, Caio Franklin Vieira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A região semiárida do nordeste brasileiro sofre com o estigma da seca desde séculos passados. Prejuízos como: falta de água para abastecimento, agricultura e pecuária, são os resultados mais frequentes. Desde 2012, essa região está sofrendo as consequências da pior seca da história. Muitos reservatórios secaram completamente. O reservatório de São Gonçalo, que devido à atual seca deixou de atender integralmente o suprimento de água para o Perímetro Irrigado de São Gonçalo. Com isso esse trabalho teve o objetivo de analisar o impacto econômico e social gerado pela atual seca (2012-2016) no Perímetro Irrigado de São Gonçalo – PB. Foi determinada uma amostra representativa e probabilística dos irrigantes colonos, em seguida feita uma entrevista com os irrigantes colonos com ajuda de um questionário semiestruturado. Como resultados, foi diagnosticado que a maioria dos irrigantes moram em residências construídas em alvenaria, tem sistema de abastecimento de água, tem algum grau de escolarid', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5332', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c720', 'Análise da situação do abastecimento de água na cidade de Sousa através da construção e aplicação de um sistema de indicadores', 'Oliveira, Francisco Fabrício Damião de; Sousa, Glaucio de Meneses; Sales, Luis Gustavo de Lima; Lima Araújo, Breno José Barbosa; Figueiredo, Caio Franklin Vieira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A temática abordada neste estudo foi o de abastecimento de água. O presente trabalho aborda os aspectos que abarcam o serviço público de abastecimento de água na cidade de Sousa. Buscou-se através de um sistema de indicadores analisarem os pontos positivos e negativos existentes no abastecimento de água da cidade, buscando contribuir com sugestões de melhorias para a prestação dos serviços de abastecimento de água em Sousa, serviços esses prestados pelo (DAESA) Departamento de Água, Esgotos e Saneamento Ambiental. Neste contexto, o objetivo geral é analisar a situação do abastecimento de água da cidade de Sousa. Os procedimentos metodológicos foram construídos a partir da concretização de algumas etapas necessárias à realização da pesquisa que teve como método de análise descritiva e exploratória. Quanto ao sistema de Indicadores utilizou-se o modelo pressão-estado-impacto-resposta que destacou os indicadores disponíveis pelo Daesa, bem como os índices de vulnerabilidade e de abastecim', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5352', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c722', 'Conflito de passagem de carros-pipas: Análise de estabilidade em Alagoa Nova e São Sebastião de Lagoa de Roça-PB', 'Aguiar, José Otávio; Barros, Mara Karinne Lopes Veriato', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A água é um recurso natural essencial, e não obstante o Brasil possuir cerca de 12% da água superficial doce do mundo essa água não é distribuída uniformemente. Dentre as regiões o Nordeste é que mais sofre com a escassez do recurso. Em virtude da situação de crise hídrica, que assola a região há aproximadamente seis anos, o trafego de carros-pipas e suas implicações ambientais se constitui em importante tema a ser debatido pela sociedade. À vista disso o presente trabalho teve como objetivos: Fazer um mapeamento do conflito socioambiental nas comunidades do Sítio Camucá, município de São Sebastião de Lagoa de Roça, e dos Sítios São Tomé e São José, município de Alagoa Nova, Paraíba identificando os principais atores e reivindicações; e construir um panorama a partir do método Fraser e Hippel (1984) com vistas a análise de estabilidade que apontasse uma possível solução para o conflito.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5420', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c726', 'Mudanças no Reconhecimento das Receitas Propostas no CPC 17- Contrato de Construção: uma análise no setor da construção civil com ações listadas na B3', 'Ventura Júnior, Raul; Alencar, Lucas Vieira Pereira de; Ventura, Ana Flávia Albuquerque; Silva, Hizzadora Pereira da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O processo de convergência contábil internacional buscou reduzir as divergências e irregularidades contábeis, aumentar a transparência e facilitar a comparação entre os demonstrativos das entidades, por meio da padronização das normas contábeis. Algumas dessas normas referem-se ao reconhecimento das receitas decorrentes dos contratos de construção, impactando diretamente no setor. Assim, o objetivo deste trabalho foi analisar se as mudanças ocorridas no reconhecimento das receitas após a publicação do CPC 17 Contrato de Construção exerceram alguma influência na análise econômico-financeira das empresas do setor de construção civil listadas na B3 entre os anos de 2010 a 2013. A pesquisa se enquadra como um estudo descritivo e quantitativo. No universo da análise constam 17 entidades de capital aberto do setor de construção civil com ações negociadas na B3 que publicaram seus relatórios contábeis referentes ao exercício de 2010 a 2013. Após a análise dos dados, se obteve o resultado de q', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5471', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c728', 'Impacto das obrigações acessórias na atualização dos profissionais contadores', 'Ventura Júnior, Raul; Pereira, Gilcivan dos Santos; Lima Júnior, Carlos Roberto Fonseca; Ventura, Ana Flávia Albuquerque', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Esta pesquisa tem o objetivo de avaliar os impactos das obrigações acessórias no cumprimento das normas brasileiras de contabilidade pelos escritórios de serviços contábeis localizados em Guarabira/PB. Para revisão bibliográfica dos termos “contabilidade”, “normatização contábil”, “obrigações acessórias”, “escritórios de contabilidade” e demais análise da pesquisa, foram revisitados 91 autores, datados entre 1993 e 2016. O presente estudo é descritivo, de cunho qualitativo e de natureza exploratória. O universo da pesquisa contou com 93 profissionais contábeis e a amostra final com 35. Como conclusão, é convergente afirmar que o profissional contábil deve fluir em permanente processo de evolução de seus atributos profissionais, bem como, de deveres analíticos no que se refere a estudos teóricos do setor contábil. Já do ponto de vista das contribuições da pesquisa, essa oferta a possibilidade de reforço teórico quanto a contabilidade e as dificuldades das obrigações acessórias frente ao', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5474', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c730', 'Atributos químicos de um neossolo quartzarênico em relação à adubação com nitrogênio e fosforo', 'Sousa, Luciano Fernandes; Santos, Antônio Clementino; Neves Neto, Duval Nolasco das; Santos, José Geraldo Donizetti dos; Oliveira, Leonardo Bernardes Taverny de; Oliveira Filho, José Hugo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo desse trabalho foi estudar uma melhor estratégia de adubação nitrogenada e fosfatada sobre as características químicas do solo proporcionando aumento produtivo para pastagens. O delineamento experimental utilizado foi blocos casualizados, com quatro doses de nitrogênio (0, 40, 80 e 120 kg ha-1) e duas doses de fósforo (100 kg ha-1 e 200 kg ha-1 de P2O5 por ano), os resultados foram submetidos a teste de variância e de significância (teste t-student a 5% de probabilidade) e os efeitos das doses de N e P comparados por meio de equação de regressão linear ou quadrática. A adubação fosfatada com 100 kg ha-1 de P2O5 associada a doses de N apresentou aumento no teor de matéria orgânica no solo enquanto que a dose de 200 kg ha-1 de P2O5 causou efeito contrário. A adubação fosfatada com 200 kg ha-1 de P2O5 associada a doses de N propiciou uma tendência de aumento gradual do pH.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5570', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c732', 'Proposta de um modelo de gestão para o uso eficiente da água no perímetro irrigado de São Gonçalo no sertão paraibano', 'Vieira, Allan Sarmento; Sarmento, Raquel Cristina Soares Silveira; Queiroga, Francisco de Assis; Figueiredo, Francisca Natalia Lacerda; de Araújo, Ialine Dantas Casimiro; da Silva, Iukênia Bezerra', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A água é recurso natural importante à vida na terra e, à medida que as atividades econômicas emergem, requer cada vez mais água em quantidade e qualidade. Para amenizar e equacionar o problema de escassez hídrica no sertão paraibano é necessário de um modelo de gestão que aprimore o uso eficiente da água. Dessa forma, esta pesquisa tem como objetivo principal propor um modelo de gestão que promova a adequação do uso eficiente da água, numa escala de tempo plurianual, para que os colonos do Perímetro Irrigado de São Gonçalo, localizado no sertão Paraibano aprendam a conviver com os efeitos da seca. A metodologia utilizada na pesquisa foi pesquisa bibliográfica, exploratória, estudo de caso e visita in loco por meio de uma abordagem quali-quantitativa. Considerando os dados coletados e os métodos para o cálculo das demandas da água foram obtidos os resultados numa escala plurianual, na qual foi escolhido e proposto à tecnologia social, denominada barreiro trincheira modificado (BTM). Ess', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5616', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c734', 'Percepção do Setor Urbano Sobre o Uso Racional da Água na Sub-bacia do Rio do Peixe-PB.', 'Vieira, Allan Sarmento; Sarmento, Raquel Cristina Soares Silveira; Figueiredo, Francisca Natalia Lacerda; de Araújo, Ialine Dantas Casimiro; de Oliveira Barbosa, Andrea Dantas; da Silva, Iukênia Bezer', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'No meio de inúmeros recursos naturais disponíveis na terra, a água é o mais utilizado pelos seres vivos para sanar suas necessidades, tanto para o consumo, como para atividades econômicas. Devido a inúmeros fatores, a demanda por água torna-se cada vez maior, ocasionando o aumento da escassez. A pesquisa em questão teve como objetivo principal, determinar a percepção sobre as práticas de utilização da água da sub-bacia do Rio do Peixe-PB no setor urbano, localizada no Sertão Paraibano. Esta pesquisa iniciou-se com uma revisão bibliográfica dos principais conceitos sobre gerenciamento e economia da água e utilizou-se como instrumento na obtenção da percepção a aplicação de um questionário semiestruturado, considerando uma abordagem qualitativa. O universo da população total da área estudada é composta por 239.102 mil habitantes, e com auxílio da técnica de amostragem probabilística aleatória, foi obtida uma amostra de 385 habitantes, os quais foram aplicados os questionários tanto on-li', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5618', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c737', 'Crescimento de cultivares de mamoeiro em função da adubação com esterco bovino', 'de Lima, Rafael Rocha; Silva, Ricardo de Sousa; Sousa, Valéria Fernandes de Oliveira; Nobre, Reginaldo Gomes; Nóbrega, Jackson Silva; de Souza, Francisco Marto; Lima, Ellen Caroline Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mamoeiro (Carica papaya L.) é uma planta largamente cultivada no Brasil, além da Indonésia e República Dominicana. Objetivou-se avaliar o crescimento de duas crescimento de cultivares de mamoeiro em função da adubação com esterco bovino no semiárido nordestino. O experimento foi conduzido em delineamento de blocos casualizados, em esquema fatorial 4 x 2, sendo quatro doses de esterco bovino (0,0; 20,0; 40,0 e 60,0% do volume do substrato) e duas variedades de mamoeiro (Formosa e Hawaii), totalizando 8 tratamentos, com 4 repetições, totalizando 32 unidades experimentais. Os recipientes utilizados foram sacos de polietileno de 1,0 L de capacidade, preenchidas com material de solo + esterco, de acordo com o tratamento adotado. Aos 40 dias após a emergência, foram avaliadas: número de folhas por planta, diâmetro de caule, altura de plantas, massa fresca da parte aérea, massa fresca total, massa seca da parte aérea e massa seca total. A interação entre os fatores cultivares e doses de est', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5638', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c738', 'Modelo matemático para avaliação de impacto ambiental (AIA)', 'Carrera, Yuri Araujo; Lima, Jucyanna Celia Lopes; Maia, Joyce de OliveirA; Junior, Antonio Pereira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O uso da modelagem matemática em questões ambientais, auxilia na interpretação de dados obtidos a partir das matrizes de interação. O objetivo dessa pesquisa foi a elaboração de um Índice de Qualidade Ambiental para esse núcleo. A partir da avaliação quantiqualitativa dos principais impactos ambientais no núcleo Cidade Nova. Marabá - PA, e a proposição de cinco medidas para a mitigação deles. O método utilizado foi o dedutivo, com pesquisa qualiquantitativa exploratória, associada ao levantamento de dados documentais, cujo recorte temporal situou-se entre 2008 a 2017. Os dados foram obtidos com a aplicação da Matriz de Leopold, para cálculos dos valores de magnitude, importância e significância de cada fator ambiental analisado (supressão vegetal, saneamento básico, qualidade do ar e Área de Preservação Ambiental - APP. Os dados obtidos indicaram, para o IQA, um valor igual 80%, qualitativamente, índice “bom”. Todavia, houve indicação da existência de impactos de natureza negativa (alt', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5650', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c739', 'Proposta de recuperação de área degradada por queimadas no município de Marabá - PA', 'Silva, Tathiane; Junior, Antonio Pereira; Varanda, Thales; Albuquerque, Alisson; Silva, Phaloma', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As ações antrópicas decorrentes do abrupto crescimento populacional no entorno de áreas de proteção permanente – APP, resultam em diversas consequências, como as queimadas. Por analisar os aspectos danosos dessa atividade, o objetivo dessa pesquisa foi elaborar uma proposta de recuperação de área degradada em uma APP situada à margem direita do rio Itacaiúnas, no município de Marabá - PA. O método aplicado foi dedutivo e a pesquisa foi de natureza aplicativa, e seguiu o protocolo estabelecido pelo Instituto Chico Mendes de Biodiversidade e Conservação. O levantamento de dados documentais ocorreu com recorte temporal entre 2003 a 2017. Os dados indicaram que: (1) os valores para a acidez foram elevados (4,0 cmolc.dm3); (2) houve diminuição do teor de matéria orgânica (1,4 dag. Kg), quando comparada com a área controle (MO = 2,1 dag. Kg); (3) redução de concentrações de Potássio (40 mg.dm-3; AC = 82 mg.dm-3) e Fósforo (1,0 mg.kg-3; AC = 10 mg.dm-3). Entretanto, noventa dias após as queim', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5652', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c73a', 'Parâmetros físico-químicos das águas da bacia do rio Gurguéia, Piauí-PI', 'Junior, João Fernandes da Silva; Campos, Liliane Pereira; Sousa, Gasparino Batista de; Guimarães, Gabriella Santana Carreiro', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O rio Gurguéia drena todo o extremo sul do estado do Piauí, e tem como seus principais afluentes os rios Paraim, Contrato e riacho Barra Verde.  Toda a bacia vem sofrendo transformações em seus ecossistemas aquáticos, devido ao uso inadequado do solo, os desmatamentos, queimadas e problemas de desertificação, provocando assoreamento e diminuição da sua vazão e interferindo na qualidade das águas. O presente trabalho teve como objetivo avaliar com uso de técnicas multivariadas os parâmetros físico-químicos das águas dos rios Gurguéia, Paraim, Contrato e riacho Barra Verde. As coletas das amostras foram realizadas no período chuvoso novembro de 2016 a abril de 2017,  no período seco de maio a setembro de 2017, totalizando 12 amostragens de água.  Os pontos amostrados foram os  rios Gurguéia; Paraim; Contrato e riacho Barra Verde. As determinações dos parâmetros físico-químicos foram realizadas no laboratório da Estação de Tratamento de Águas – ETA, da Companhia de Águas e Esgoto do Piauí', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5653', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c73c', 'Produção de pão a base de leite de cabra condimentado com diferentes concentrações de açafrão (cúrcuma longa l)', 'Araujo, Alfredina dos Santos; Alves, Rerisson do Nascimento; Pereira, Maria Angélica Freitas; Silva, Joana Simone Soares da; Barbosa, Thaísa Cidarta Melo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Resumo: Os pães são considerados boa fonte de energia e nutrientes para o ser humano, e sua  produção a partir do leite de cabra surge-se como uma alternativa para agregar valor a caprinocultura brasileira, enquanto o açafrão (cúrcuma longa l) pode ser aplicado aos pães com a finalidade de conferir características sensórias como aroma e cor diferenciados. Objetivou-se desenvolver pães de leite caprino condimentado com e sem açafrão, e avaliar o seu perfil físico-químico e microbiológico durante o armazenamento. Os pães foram elaboradas utilizando as formulações: (F1): sem açafrão; (F2): 0,5% de açafrão; (F3): 1% de açafrão, nas quais foram realizadas análises físico-químicas e microbiológicas. Em relação a composição centesimal dos pães, a utilização de 0,5% e 1% do açafrão alterou a composição química dos pães, com destaque para o aumento de proteínas e cinzas. Para a qualidade microbiológica as formulações de pães apresentaram resultados satisfatórios nos primeiros dias de armazename', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5690', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c73e', 'Roteirização de caminho ótimo para coleta seletiva de embalagens cartonadas na região central da cidade de Embu das Artes – SP', 'Gonçalves, Max Filipe Silva; Xavier, Welton Santos; Trevisan, Carlos Eduardo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O trabalho foi desenvolvido com o intuito de melhorar a performance da coleta seletiva das embalagens cartonadas através da disposição de pontos de entrega voluntária ao longo da região estudada e, posteriormente, a roteirização do melhor caminho a ser utilizado por um veículo que fosse recolher o resíduo nesses pontos e leva-los à uma cooperativa local. Para tal utilizou-se da revisão da literatura sobre o tema e trabalhos semelhantes que forneceram base para os estudos, dentro da região escolhida mapeou-se os pontos eleitos para receber o resíduo do consumidor final e através de simulação computacional e programação linear descobriu-se o caminho mais curto a ser percorrido para realização da coleta. Apesar do resultado satisfatório na obtenção do caminho mínimo o baixo valor agregado do resíduo torna sua coleta semanal inviável, sendo o mais recomendado uma coleta mensal e, em conjunto, a ação do poder público como motivador legal tanto para empresas quanto população no retorno desse', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5694', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c741', 'Monitoramento da qualidade da água do rio Mundaú nos municípios de Garanhuns e Correntes,PE', 'Costa, Maísa Gonçalves; Leitão C. de Araújo, Marina de Sá; Leite de Carvalho, Lidiana Barbosa', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A presente pesquisa teve como objetivo, monitorar a qualidade da água do rio Mundaú nos municípios de Garanhuns-PE e Correntes-PE, relacionando os resultados com a disponibilidade do serviço de esgotamento sanitário. A pesquisa ocorreu em três pontos específicos, sendo dois em áreas de nascentes, situadas no Agreste Meridional, e outro ponto, em um trecho do rio que corta o município de Correntes. Através da análise, realizada tanto pelo estudo de relatórios fornecidos pela Companhia Pernambucana de Saneamento-COMPESA, no período de 2012 a 2016, como pela pesquisa de campo no período entre março e julho de 2017, foi possível observar o constante estado de contaminação do manancial devido à elevada carga de fosfato na água, representando uma média de 0,22 mg/L de fosfato, valor muito acima do permitido pela resolução 357/05 do CONAMA, que é de 0,03 mg/L de fosfato. A partir dos resultados da pesquisa de campo, foi possível constatar níveis altíssimos de coliformes totais nos pontos do P', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5721', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c746', 'Caracterização de cachaça artesanal produzida na zona da Mata de Minas Gerais', 'Costa, Marcos Vinício Acipreste; Prado Junior, Leonardo Souza do; Gadelha, Hugo Sarmento; Almeida, Francileuda Batista de; Silva, Cesar Carlos Martins da; Sá, João Paulo Natalino de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A maior parte da cachaça artesanal produzida não possui garantia que o produto está em conformidade com os requisitos estabelecidos pela legislação vigente. A certificação é uma forma de evidenciar a conformidade do produto quanto aos requisitos de qualidade e segurança alimentar, além de demonstrar o compromisso do produtor com as questões ambientais e de responsabilidade social. Este trabalho teve como objetivo caracterizar a partir de parâmetros físico-químicos uma cachaça artesanal não certificada pelo Ministério da Agricultura Pecuária e Abastecimento (MAPA), produzida na Zona da Mata de Minas Gerais, visando sua adequação para possível regulamentação. As análises físico-química da cachaça, demonstram que os parâmetros referentes a acidez volátil, graduação alcoólica, pH, álcoois superiores, aldeídos, furfural, chumbo e cobre foram inferiores aos valores de referência preconizado pela legislação vigente. Porém as análises referentes aos teores de aldeído demonstraram valores próxi', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5768', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c74a', 'AVALIAÇÃO FÍSICO-QUÍMICA E MICROBIOLÓGICA DE ÁGUA POTÁVEL DE UMA INSTITUIÇÃO DE ENSINO SUPERIOR LOCALIZADA NA ZONA DA MATA MINEIRA', 'Monteiro, Renata da Silva; Prado Junior, Leonardo Souza do; Gadelha, Hugo Sarmento; Almeida, Francileuda Batista de; Silva, Cesar Carlos Martins da; Sá, João Paulo Natalino de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A água é um elemento natural e imprescindível para a manutenção da vida, porém pode veicular diferentes contaminantes físicos, químicos e microbiológicos, acarretando riscos à saúde do consumidor. Esta pesquisa teve como objetivo avaliar a qualidade físico-química e microbiológica da água utilizada para ingestão humana em uma instituição de ensino superior, localizada na região de Ponte Nova, Minas Gerais. As amostras foram analisadas em relação aos parâmetros físico-químicos e microbiológicos exigidos pela Portaria nº 2.914, de 12 de dezembro de 2011, do Ministério da Saúde (MS). Os resultados para os parâmetros físico-químicos ( dureza, cloretos, cloro residual total e pH) das amostras analisadas encontram-se dentro do limite máximo estabelecido. Em relação aos parâmetros microbiológicos, a contagem de coliformes totais e Escherichia coli nas amostras A, B e C, foram todas inferiores ao estabelecido pela legislação vigente. As contagens de bactérias mesófilas para as amostras A e B, ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5778', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c74b', 'Gerenciamento dos resíduos de equipamentos eletrônicos no IFPB – Campus de Sousa: Análise à luz da sustentabilidade ambiental', 'Marques, Jacyara Farias Souza; Maracaja, Patricio Borges; Almeida, José Cezário de; Aragão, Jônica Marques Coura; Aragão, Richard Weiny; Melo, Wellington Ferreira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O grande volume de resíduos de equipamentos eletroeletrônicos à atual cultura de consumo fomentando a obsolescência programada, que acompanhada da inovação tecnológica intensa e contínua, ocasiona um grave problema aos sistemas ambientais, interferindo em toda a cadeia produtiva dos sistemas agroindustriais e, possivelmente, gerando sensível impacto na qualidade de vida de todos os seres. Essa observação conduz à seguinte problematização: O sistema de gestão adotado pelo IFPB – Campus Sousa para o gerenciamento dos resíduos elétricos e eletrônicos demonstra-se ambientalmente adequado? Para tanto, registra-se como objetivo geral da pesquisa: analisar a gestão dos resíduos elétricos e eletrônicos (Linha Verde) no IFPB Sousa no período de 2013 a 2017. Para a realização da pesquisa, pretende-se utilizar como método o dedutivo. O procedimento metodológico, quanto ao meio, consiste em pesquisa documental e, quanto à abordagem, mista: qualitativa e quantitativa. O estudo promoverá o conhecime', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5782', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c74c', 'Os principais microorganismos causadores da mastite bovina e suas consequências na cadeia produtiva de leite', 'Alencar, Maria Carmem Batista de; Gadelha, Hugo Sarmento; Sousa Neto, Odilon Lucio de; Roberto, Stephanny Batista de Alencar; Figueiredo, Carla Heloisa Alencar de; Sá, João Paulo Natalino de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A mastite bovina é uma doença multifatorial que ocasiona a inflamação da glândula mamaria de mamíferos, dentre eles a vaca. A mastite é uma inflamação de preocupação mundial, principalmente na área agroindustrial, pois esta enfermidade acarreta inúmeros prejuízos para o produtor (diminuição em volume de leite sintetizado, gasto com medicamento, diminuição da qualidade físico-química e microbiológica do leite, dentre outros), para a indústria ( menor rendimento para a produção de queijos e maior tempo para a fermentação de derivados lácteos fermentados) e para o consumidor ( risco de saúde publica , por intoxicação e infecção alimentar, resíduos de antimicrobianos no leite que podem gerar fatores de resistência microbiana e problemas alergênicos). Dentre os diferentes agentes causadores de mastite bovina, os micro-organismos demonstram grande relação direta com esta enfermidade. Dessa forma, esta revisão tem como objetivo descrever os principais micro-organismos reportados na literatura', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5785', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c74d', 'A utilização dos nanocarreadores de principios ativos para alimentos', 'Santos, Camila Lais Alves dos; Alencar, Maria Carmem Batista de; Gadelha, Hugo Sarmento; Sousa Neto, Odilon Lucio de; Figueiredo, Carla Heloisa Alencar de; Sá, João Paulo Natalino de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A nanociência e a nanotecnologia são áreas do conhecimento e inovação que vêm despertando interesse cada vez maior da comunidade científica, dos profissionais do setor industrial e da mídia. Diferentes nanocarreadores estão sendo desenvolvidos com diferentes composições, morfologias e propriedades de superfície, sendo reportado para a utilização na indústria de alimentos principalmente os lipossomas, as nanopartículas lipídica solida, nanopartículas poliméricas e as nanoemulsões. Muitos compostos de grande impacto mercadológico na indústria de alimentos, como os aromas, corantes naturais e bioativos (carotenoides, flavonoides, curcumina, dentre outros), apresentam limitações para serem utilizados diretamente na área de alimentos. A utilização de nanocarreadores para vincular estes princípios, pode favorecer a proteção destas substancias.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5787', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c753', 'Uso da farinha da casca de laranja (Citrus sinensis L.) na elaboração de pães de méis', 'Melo, José Robson de Lima; Nogueira, Lídia Paloma da Silva; Albuquerque, Tiago da Nóbrega; Araújo, Morgana Aragão; Lopes, Maíra Felinto; Diniz, Amanda Arielle Rodrigues', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os consumidores estão cada vez mais conscientes, em relação à saúde e a sua qualidade de vida e estão percebendo cada vez mais a ligação entre saúde e nutrição. Por isso, a busca por alimentos funcionais vem mostrando um crescimento progressivo nos últimos anos. Sendo assim este estudo objetivou-se formular, avaliar microbiologicamente e sensorialmente os pães de meles a partir do enriquecimento com a farinha da casca de laranja em diferentes concentrações. Realizaram-se as análises microbiológicas dos pães de méis, tendo como resultado sua a aptidão ao consumo estando dentro dos padrões higiênicos, de acordo com a legislação. A avaliação sensorial evidenciou que todas as amostras foram bem avaliadas, entretanto a amostra que se destacou foi a que conteve maior concentração da farinha, ainda assim realizou-se a análise de componentes principais, através do método CATA (CheckAllThatApply) mostrando a correlação de cada amostra com os atributos sensoriais.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5827', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c755', 'Análise da aceitabilidade do suco de de cascas de abacaxi', 'Costa, Rubenia de Oliveira; Pereira, Jéssica de Sousa; Machado, Antonio Vitor; Alves, Flávia Mota de Figueredo; Neto, José Nunes De Oliveira; Araújo, Ionaly Gomes De', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As perdas pós-colheitas do fruto acumulam um volume de 30% da produção. Devido o índice significativo de perdas e ao acúmulo de resíduos provenientes do cultivo de abacaxi alguns agricultores e pecuaristas vêm utilizando os resíduos da produção para complementar a alimentação animal. Em épocas de falta de ração animal na região do semiárido nordestino os restos do abacaxi (casca, folhas, coroa, frutos descartados) podem ser utilizados como forma de suplemento na alimentação para os bovinos e caprinos. Este estudo tem como objetivo analisar a aceitabilidade do suco de abacaxi, produzido a partir das cascas da fruta. Os procedimentos adotados nesta pesquisa foi inicialmente um levantamento bibliográfico, em seguida foram elaboradas três amostras de suco, dispostas da seguinte forma: na primeira amostra o suco foi produzido a partir das cascas do abacaxi, na segunda amostra o suco foi produzida a partir da polpa ‘in natura’, já a terceira amostra, o suco foi produzido a partir da polpa de', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5984', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c756', 'Gestão de resíduos em oficinas mecânicas, um estudo de casos sobre descarte de óleo lubrificante no município de Belém-PA', 'Lima, Jarleson dos Santos; dos Santos, Geovanna Carolina Santos; Rodrigues, Rodrigo Silvano Silva; dos Santos, Filippe Vilhena', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As atividades realizadas por oficinas mecânicas quando não efetuadas de acordo com as legislações ambientais recomendadas estão sujeitas a ocasionar problemas ambientais. Esta pesquisa tem a finalidade de analisar a relação de quatro oficinas mecânicas de Belém/PA com a saúde ambiental na região, na qual foi efetuada a metodologia de aplicação de questionários acerca da estrutura dos estabelecimentos, uso de equipamentos de proteção individual pelos funcionários, produção, armazenamento e descarte de resíduos e efluentes. Os dados coletados foram trabalhados estatisticamente através do software Microsoft Excel, como apresentações dos resultados foram caracterizadas as oficinas mecânicas de acordo com as estatísticas apresentadas pelos estabelecimentos; notou-se um nível de conhecimento e cuidado socioambiental na oficina mais estruturada. A importância do acompanhamento pelos órgãos competentes dessas atividades, sendo as mesmas com grande potencial poluidor, faz-se essencial no contex', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5985', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c757', 'Impactos ambientais da atividade mineradora no município de Caraúbas-RN', 'Paula, Edgley Alves de Oliveira; Pereira, Karla Elita Viegas; Japiassú, André; Agra, Pollyanna Freire Montenegro; Carvalho, Josevi de Souza; Lopes, Jessica Rafaelly Almeida', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A mineração é uma atividade propulsora do desenvolvimento econômico do país, como também no tocante aos fatores sociais, uma vez que é significativa fonte de emprego e renda. No entanto, caracteriza-se também pelo alto potencial degradador, pois a execução desta atividade causa impacto significativo ao meio ambiente, pois o seu desenvolvimento acarreta, muitas vezes, poluição visual, degradação paisagística, contaminação das águas, redução da cobertura vegetal, destruição ou modificação dos habitats, danos à saúde, depreciação dos imóveis, ruídos e vibrações, dentre outros aspectos negativos. Para isso foi elaborada uma Matriz, método bastante utilizado na identificação e avaliação de impactos ambientais. O método foi aplicado na identificação dos possíveis impactos quali e quantitativo da pedreira no município de Caraúbas-RN nos meios físicos, bióticos e socioeconômico. Com isso, os resultados obtidos serviram como subsídios para a avaliação de impactos da atividade mineradora, e pode', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5990', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c759', 'A Gestão Ambiental no âmbito municipal: Uma análise em um município do Sertão Paraibano', 'Andrade, Adriana Salviano de; Figueirêdo, Andréia Conrado; Silva, Érika Lira da; Silva, Kardelan Arteiro da; Silva, Maria do Rosário Cavalcante', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do artigo é analisar a gestão ambiental no município de Pombal-PB com base na Agenda Ambiental na Administração Pública (A3P). Para isso, a metodologia caracterizou-se como uma pesquisa exploratória, sendo utilizado o método de estudo de caso aplicado, com caráter qualitativo. Desse modo, um questionário foi elaborado e adaptado para coleta de dados com os principais temas contidos na A3P, levando em consideração os cinco eixos temáticos da agenda, sendo aplicado na Secretaria de Meio Ambiente e Secretaria Municipal de Educação, e aos respectivos secretários em exercício no município. A partir das informações colhidas foi possível fazer uma análise e estruturação dos resultados, onde nota-se que o município com relação às práticas ao meio ambiente se encontra em estado deficiente sob o ponto de vista de planejamento, conhecimento e ações voltadas para tais práticas ambientais, contudo, verificou-se que o município está tentando implantar práticas de gestão ambiental.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5997', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c75b', 'DIAGNÓSTICO SOCIOAMBIENTAL DA CIDADE DE CARAÚBAS-RN', 'Paula, Edgley Alves de Oliveira; Lopes, Jessica Rafaelly Almeida Lopes; Azevedo, Ricardo Dantas; Carvalho, Josevi de Sousa; Japiassú, André; Agra, Pollyanna Freire Montenegro; Medeiros, Aline Carla de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O crescimento das cidades faz surgir os problemas provenientes da falta de planejamento no processo de urbanização. O aumento populacional impulsiona as pessoas a ocupar espaços em áreas sem infraestrutura e com serviços públicos ineficientes. Esse fator contribui diretamente para o surgimento de problemas socioambientais, em virtude de a população ser carente e não ter consciência sobre os fatores que degradam o meio social e ambiental. Nesse âmbito, objetivou-se realizar um diagnóstico socioambiental na cidade de Caraúbas-RN. Para isso, a cidade foi dividida em quatro bairros principais, sendo eles o bairro Alto de São Severino, bairro Leandro Bezerra, bairro Sebastião Maltez e Centro. Com os parâmetros de divisão estabelecidos, foram elaborados e aplicados 494 questionários socioambientais, sendo 98 no bairro Alto de São Severino, 170 no bairro Leandro Bezerra, 126 no bairro Sebastião Maltez e 100 no Centro. Também foram realizados registros fotográficos em cada bairro. Os dados for', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6007', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c761', 'Variabilidade da precipitação na Amazônia oriental e nordeste brasileiro sobre a influência do aumento do CO2', 'de Moraes, Bergson Cavalcanti; Veloso, Priscilla Pinheiro; Pedrosa, João Paulo da Costa; Higuchi, Luiz Felipe Masami Serrão; Rodrigues, Rodrigo Silvano Silva', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este estudo teve como objetivo identificar e descrever a influência do aumento da concentração do dióxido de carbono na atmosfera sobre a precipitação na região da Amazônia Oriental e Nordeste brasileiro, nos anos de 1958 a 2017. Devido ao CO2 contribuir no efeito estufa e por consequência na alteração climática, é importante conhecer as mudanças que ocorrem nas variáveis meteorológicas, sabendo que a concentração de CO2 vem aumentando desde a revolução industrial com previsão de continuar aumentando. Para dados de precipitação foi utilizado o banco de dados do GPCC (Global Precipitation Climatology Centre) da NOAA (National Oceanic and Atmosferic Administration) e para o CO2 foi utilizado os registros disponíveis de Scripps Institution of Oceanrography. Para reconhecer e classificar a influência do CO2 na precipitação, foi realizado para cada década uma correlação estatística de Pearson utilizando o software Grads, e então uma análise comparativa com a média da precipitação acumulada ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6109', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c764', 'Lâminas de água múltiplas via sistema de irrigação subsuperficial no cultivo de alface do grupo crespa', 'Silva, Mateus Gonçalves; Siqueira, Eliezer Cunha; Cassimiro, Carlos Alberto Lins; Oliveira, Francisco Sales; Feitosa, Selma Santos; Silva, Edvanildo Andrade', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O propósito do estudo foi avaliar á eficiência de um sistema de irrigação subsuperficial de baixo custo, a partir da aplicação de lâminas decrescentes de água, para o desenvolvimento vegetativo de plantas de alface do grupo crespa. Para tanto, desenvolveu-se um ensaio no setor de Olericultura do Instituto federal da Paraíba, Campus Sousa, Unidade São Gonçalo. O delineamento experimental utilizado foi o inteiramente casualizado, e os tratamentos foram compostos de cinco lâminas de água (25, 50, 75, 100 e 125% da evapotranspiração de referência, estimada pela equação de Penman-Monteith), repetidos quatro vezes. As variáveis avaliadas constaram de massa de matéria seca da parte aérea, raiz e total e o número total de folhas por planta. A aplicação de 25% de lâmina de água proporcionou os menores valores de acúmulo de massa, não sendo, portanto, recomendada para esse sistema, já a aplicação de 50%, proporcionou acúmulo de massa similar as maiores lâminas, 75, 100 e 125% da evapotranspiraçã', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6132', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c769', 'Sistematização da Assistência de Enfermagem em um hospital de ensino do município de Belém', 'DA SILVA, ANA GRACINDA IGNÁCIO; LAMEIRA, LARISSE JESSICA DE FREITAS; DIAS, RUDNELSON VIEIRA MAGALHAES', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Introdução: A Sistematização da Assistência de Enfermagem (SAE) é uma metodologia científica de que o enfermeiro dispõe para aplicar seus conhecimentos técnico-científicos e humanos na provisão do cuidado ao paciente, pautados no compromisso ético, na responsabilidade e no assumir o cuidar do outro. Métodos: No presente estudo foi utilizada a metodologia exploratória descritiva, de natureza qualitativa. Resultados e Discussão: os resultados obtidos foram dispostos em quatro categorias: 1ª Significado da Sistematização da Assistência de Enfermagem; 2ª Realização da SAE na Unidade; 3ª Fatores que dificultam a realização da SAE ; 4ª Forma com que a SAE pode ser mais bem aplicada no cotidiano da enfermagem. Conclusão: Acredita-se que é necessário investimento maior das academias, órgãos de legislação e científicos da Enfermagem, assim como investimento e consciência profissional do papel clínico do enfermeiro sobre o assunto para que possa de fato beneficiar os pacientes com assistência cl', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6165', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c76a', 'Morfofisiologia de sementes crioulas de tomate cereja produzidas sob adubação orgânica', 'Silva, Mateus Gonçalves; Nascimento, Danielle Maria do; Dantas, Maria Candida de Almeida Mariz; Moreira, Joserlan Nonato; Nascimento, Daiane Carvalho da Silva; Filho, Francisco de Sales Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As sementes crioulas são patrimônio histórico dos agricultores familiares, capaz de garantir a sobrevivência de espécies locais e de se adaptarem as situações adversas. O presente trabalho teve como objetivo analisar morfofisiologicamente sementes crioulas de tomate cereja (Lycopersicum esculentum Mill var. Cerasiforme), produzidas sob condições de adubação orgânica, no alto sertão da Paraíba. O experimento foi realizado nos setores de olericultura e Laboratório de Sementes do IFPB-Campus Sousa. O estudo foi desenvolvido em duas etapas. A primeira foi a implantação do campo de multiplicação de sementes, utilizou-se o espaçamento de 1,0 m entre linhas e 0,40 m entre plantas, e o sistema de irrigação por micro aspersão. O delineamento utilizado foi de blocos casualizados com 5 tratamentos (T1= 0 Kg, T2= 11,52 Kg, T3= 17,28 Kg, T4= 23,04 Kg, T5= 28,80 Kg) e 4 repetições As doses a serem utilizadas nessa pesquisa foram baseadas nas exigências da cultura e nas disponibilidades de oferta de ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6182', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c76b', 'Teor de umidade e potencial hidrogeniônico do mel de abelha Jandaíra produzido em Sousa, Paraíba', 'Silva, Mateus Gonçalves; Rolim, Hermano Oliveira; Dantas, Maria Candida de Almeida Mariz; Moreira, Joserlan Nonato; Junior, Ednaldo Barbosa Pereira; Neto, João Ferreira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A Jandaíra (Melipona subnitida Ducke) é uma espécie de abelha indígena sem ferrão bastante conhecida por muitos agricultores familiares do alto sertão paraibano. O mel elaborado por esta abelha é consideravelmente apreciado pelos consumidores, devido às diversas qualidades organolépticas e antissépticas que lhes são atribuídas. A avaliação de parâmetros como teor de umidade (%) e pH, identifica a qualidade do mel e o torna um alimento mais seguro possibilitando maior e melhor comercialização. O objetivo desse trabalho foi avaliar o percentual de umidade (%) e o potencial hidrogeniônico do mel de abelha Jandaíra produzido em Sousa, no alto sertão paraibano. O experimento foi realizado no IFPB-Campus Sousa, unidade de São Gonçalo. As amostras de mel foram coletadas em meliponário racional, acondicionadas em potes plásticos e mantidas em câmara fria à temperatura de 2 a 10 ºC até a realização das análises no laboratório de análises físico-químicas. O tratamento constituiu no tempo de arma', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6183', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c76e', 'Comportamento da Biomassa de Cryptostegia madagascariensis Bojer ex Decne em Solos da Caatinga sob Estresses Abióticos', 'Medeiros, Aline Carla de; Andrade, Leonaldo Alves de; Mesquita, Francisco de Oliveira; Oliveira, Cleiton José de; Maracaja, Patricio Borges; Medeiros, Jailma dos Santos de; Japiassu, André', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A espécie invasora Cryptostegia madagascarinsis constitui uma ameaça à biodiversidade de vastas áreas da Caatinga e ecossistemas associados, devido a sua  capacidade de dominar os mais diversos ambientes, onde se estabelece formando densos maciços populacionais, competindo, com vantagens, com as flora autóctone. Neste sentido, este trabalho teve como objetivo avaliar o crescimento inicial através da biomassa seca de C. madagascariensis em solos do bioma caatinga sob efeitos da salinidade e umidade. A pesquisa foi desenvolvida em abrigo telado do Laboratório de Ecologia Vegetal, do Departamento de Fitotecnia e Ciências Ambientais, do Centro de Ciências Agrárias, da Universidade Federal da Paraíba, Areia-PB no período de agosto de 2015 a janeiro de 2016. Os tratamentos foram organizados em esquema fatorial 4x4x2, sendo quatro níveis de salinidade, quatro níveis de umidade e dois tipos de solos. Os tratamentos foram distribuídos em blocos casualizados, com quatro repetições e a unidade ex', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6237', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c76f', 'Características do disclosure ambiental das empresas brasileiras de papel e celulose cadastradas no B3', 'Ferreira Marques de Melo, Janaina Marques; de Sousa Costa Rolim, Keyla Cristine; Queiroz Reis, Cristiane Queiroz', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Estudos recentes sobre o disclosure ambiental das empresas apontam que estas não divulgam voluntariamente as informações negativas, corroborando com a Teoria da Divulgação. Neste aspecto, delimitando o estudo para as empresas de alto impacto ambiental, pertencentes ao setor de papel e celulose, esta pesquisa objetivou analisar as características do disclosure ambiental que estão listadas no site da B3 no período de 2014 a 2016. O proceder metodológico foi uma análise de conteúdo utilizando os Relatórios de Administração, as Notas Explicativas e os Relatórios de Sustentabilidade e comparação com estudos correlatos no mesmo setor, utilizando variáveis de investigação, além de identificar a proporção dos itens monetários ambientais em relação aos itens do patrimônio. Como principais resultados, constatou-se que a maioria das informações evidenciadas são do tipo declarativa e positiva, no entanto, houve um avanço, pois, algumas empresas divulgaram informações consideradas negativas (eviden', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6249', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c774', 'Caracterização físico-química e microbiológica de conserva do fruto de cajarana em meio ácido', 'Costa, Willianny de Medeiros; Alves, Gilcean Silva; Araújo, Alfredina dos Santos; Medeiros, Weverto Pereira de; Albuquerque, Tiago da Nóbrega; Linhares Filho, Everaldo da Nóbrega', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os frutos são bastante susceptíveis à deterioração e uma das formas para retardar esses processos é através de sua conservação por acidificação. Os ácidos agem de formas diferentes no processamento de alimentos, eles contribuem para melhorar a sua qualidade degustativa. O presente trabalho tem como objetivo a elaboração e caracterização físico-química e microbiológica da conserva dos frutos de cajarana em meio ácido (picles de cajarana). O sal, açúcar, vinagre, água, folha de louro foram colocados ao mesmo tempo e levados ao fogo ate sua temperatura de ebulição onde logo ao atingir a 95°C foram adicionados os frutos deixando-os por 2 minutos, logo em seguida foram acondicionados em recipientes de vidros devidamente esterilizados e submetidos a resfriamento em uma bandeja com gelo para evitar seu cozimento em excesso. Após um período de 7 dias de maturação dos picles de cajarana foi realizada a sua caracterização físico-química, analisando os seguintes parâmetros: pH, sólidos solúveis t', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6307', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c775', 'Percepção sobre educação ambiental e política dos 3R’S dos estudantes de escola pública no município de Pombal-PB', 'Lima, Thamirys Lorranne Santos; Araújo, Jotácia Estrela Barbosa; Albuquerque, Tiago da Nóbrega; Sousa, Alana Kamyle dos Santos; Sales, Ricélia Maria Marinho', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O crescente aumento das populações urbanas, a falta de planejamento ambiental e de programas de conscientização, bem como, a falta de informação para a população em geral, são alguns dos fatores que contribuem para o aumento da degradação ambiental. O ambiente escolar e as práticas de ensino podem ser utilizados como proposta de educação visando à preservação do ambiente. Neste contexto, objetivou-se com a realização deste estudo, avaliar as percepções ambientais e captar os conhecimentos sobre a política dos 3R’S dos alunos do terceiro ano do ensino médio da Escola Estadual Arruda Câmara do município de Pombal, Paraíba. Os procedimentos metodológicos pautaram-se na abordagem direta com aplicação de um questionário a 27 discentes, onde responderam perguntas discursivas e de múltipla escolha sobre educação ambiental e política dos 3R’S. Destacou-se que, a maioria dos alunos possui pouco conhecimento sobre os assuntos abordados. É perceptível, no entanto, a necessidade da inserção da Edu', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6308', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c77f', 'Criação racional de abelhas jandaíra e sua importância ambiental', 'Silva, Mateus Gonçalves; Oliveira Neto, Jose Nunes de; Dantas, Maria Cândida de Almeida Mariz; Moreira, Joserlan Nonato; Gadelha, Hugo Sarmento; Junior, Ednaldo Barbosa Pereira; Medeiros, Aline Carla ', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A Melipona subnitida trata-se de uma abelha tipicamente encontrada na região nordeste do Brasil, considerada agente polinizador imprescindível para preservação de diversas espécies vegetais encontradas no bioma Caatinga. Devido a ações de desmatamento e expansão da agricultura convencional utilizando-se agrotóxicos, essa espécie é cada vez menos encontrada na natureza. O estudo tem como finalidade explanar sobre a meliponicultura com a abelha Jandaíra através de uma revisão bibliográfica acerca da importância ambiental dessa atividade. Diante a aclaração do conteúdo conclui-se que a criação racional de abelhas Jandaíra é imprescindível para preservação da espécie de abelha e também de diversas espécies vegetais que dependem desse agente polinizador, além de fornecer renda extra para os agricultores familiares através da vendo do mel.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6402', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c780', 'Avaliação da sustentabilidade hídrica dos reservatórios Engenheiro Ávidos e São Gonçalo no Estado da Paraíba', 'REIS, CRISTIANE QUEIROZ; DE FARIAS, CAMILO ALLYSON SIMÕES; SANTOS, VALTERLIN DA SILVA', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os problemas decorrentes da escassez hídrica poderiam ser minimizados se houvesse um melhor aproveitamento das águas dos reservatórios existentes acompanhado de uma avaliação dos desempenhos dos mesmos por meio de indicadores de sustentabilidade bem definidos. Este trabalho tem como objetivo analisar a sustentabilidade hídrica do sistema de reservatórios composto pelos açudes Engenheiro Ávidos e São Gonçalo quanto aos seus múltiplos usos e identificar os problemas relativos ao uso inadequado de suas águas. Esse sistema de reservatórios está localizado no semiárido paraibano, uma região em que a escassez hídrica prejudica e limita o desenvolvimento econômico e social, além de ser fonte de conflitos entre os diversos usuários da água. Os principais usos desses reservatórios são atendimento da demanda de duas importantes cidades paraibanas, Sousa e Cajazeiras, e do Perímetro Irrigado de São Gonçalo. A metodologia consistiu em analisar dois cenários operacionais por meio do Sistema de Supo', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6416', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c784', 'Visão de universitários sobre problemas ambientais e resíduos sólidos na cidade de Pombal-PB', 'Silva, Amanda Kelly da; Alves, Maria Jaízia dos Santos; Albuquerque, Tiago da Nóbrega; Gomes, Jaqueline de Sousa; Sales, Ricélia Maria Marinho', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Nos tempos atuais, surgiram preocupações globais quanto aos inúmeros problemas decorrentes do desenvolvimento e do equilíbrio injusto entre as necessidades econômicas, sociais e ambientais das gerações presentes e futuras. Um dos maiores desafios urbanos é o melhoramento da deposição de resíduos sólidos, bem como a extração de recursos naturais de forma descontrolável. Diante desse pequeno parcial de problemas ocasionados pela sociedade, buscaram-se opiniões de universitários cursando Engenharia Ambiental, para obter um reflexo de como podemos melhorar e onde podemos, e como a universidade esta agindo para também fazer sua parte diante do propósito, propondo aos mesmos a percepção de problemas ambientais locais. Diante do questionário proposto podemos observar a visão de vários pontos importantes e que estão no nosso cotidiano, não apenas individualmente, mas no conjunto discente, universidade e sociedade. Levando a identificar qual o papel de cada um e o que os mesmos estão realizando', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6435', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c787', 'Riscos de desastres: Análise bibliométrica e sociométrica em periódicos nacionais e internacionais', 'Baldissera, Juliano Francisco; Hoffmann, Tuanny; Fiirst, Clóvis; Dall''Asta, Denis; Zachow, Marlowa', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo pesquisa é analisar a produção científica sobre riscos de desastres no Brasil, com intenção de encontrar dados mais específicos do Estado do Paraná, publicadas em periódicos nacionais e internacionais, a partir de pesquisa nas bases de dados SPELL, SCIELO, SCOPUS, WEB OF SCIENCE e SCIENCE DIRECT. Foi utilizada como procedimento de análise as leis da bibliometria, sendo elas: Lei de Bradfort; Lei de Lotka e Lei de Zipf. Na produção científica foi sistematizado de acordo com as áreas de conhecimento da CAPES, bem como, com o extrato QUALIS-CAPES. Além disso foram também analisadas as redes de sociométricas entre instituições e autores. O resultado desse trabalho foi alcançado a partir dos dados coletados e analisados, trazendo satisfação ao demonstrar que houve centralidade (degree) do tema riscos, como esperado, pois foi o termo mais recorrente de acordo com a similitude dos termos encontrados na pesquisa, sendo eles atribuídos ao risco de problemas ambientais. Em relação à c', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6504', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c789', 'Agenda ambiental da administração pública (A3P): Percepção dos servidores da UFPB', 'Luna, Clelia Mirlei F.; Vieira, Francisco Cavalacante; Carvalho, José Ribamar M.; Carvalho, Enyedja Kelly Martins de A.; Belchior, Karllene R. C.', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A sustentabilidade e a gestão ambiental são temas recorrentes nas discussões na área de administração pública. Nesse contexto, o Governo Federal, a partir da Agenda Ambiental da Administração Pública (A3P) vem procurando incentivar práticas que favoreçam o desenvolvimento sustentável. Nesse sentido, o presente estudo buscou identificar a percepção dos servidores técnico-administrativos da Universidade Federal da Paraíba (UFPB) em relação à importância da utilização das ações descritas na agenda, por meio da aplicação de um questionário subdividido de acordo com os cinco eixos temáticos da A3P.  Para tanto foi realizada uma pesquisa descritiva, quantitativa e qualitativa. Os resultados apontam para a importância de se desenvolver práticas na instituição que possam estar sistematizadas e alinhadas ao contexto da sustentabilidade na gestão pública.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6517', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c78b', 'CONTRATOS DE INTEGRAÇÃO VERTICAL NO AGRONEGÓCIO: Monopólio Produtivo versus Desenvolvimento Econômico à Luz da Lei nº 13.288/16', 'Maracajá, Patrício Borges; Almeida, José Cezário de; Carneiro, Cynara Rodrigues; Rolim Filho, Antônio Braz', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A Lei nº 13.288/16 trata de fato jurídico recorrente no dia-a-dia atual da agroindústria, mas que não detinha regulação específica. Trata-se dos contratos de integração vertical, negócios jurídicos responsáveis pela aglutinação dos setores econômicos de produção, industrialização e comercialização. A nova lei estabeleceu critérios para a celebração do ajuste, assim como conceituou diversos institutos inerentes à avença. Sendo recente a tratativa da matéria, diversos aspectos apresentam-se nebulosos, a exemplo da violação aos princípios contratuais pelo novo contrato; a possibilidade de dissimulação de contrato de trabalho e a efetividade do instrumento como mecanismo de fomento ao agronegócio. Dessa forma, constitui objetivo geral desse trabalho discutir acerca das repercussões jurídicas pela utilização do novo modelo de contratos de integração vertical agroindustriais, apontando os efeitos sociais, econômicos e ambientais – positivos ou negativos – gerados pela operacionalização advin', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6530', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c78d', 'Cinética de secagem de polpa de manga (Mangifera indica L.) em camada de espuma', 'Andrade, Maria Jakelline Clementino de; Nobre, Rafaela de Sousa; Albuquerque, Tiago da Nóbrega; Martins, Georgiana Maria Vasconcelos; Vieira, Francisca Jussandra Alves', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar a cinética de secagem da polpa da manga da marca Doce Mel® em camada de espuma. A polpa da manga foi elaborada mediante um planejamento experimental fatorial completo 22. A temperatura (50 a 70°C) e concentração de emulsificante (5,5 a 10 g) são as variáveis do processo. A cinética de secagem ocorreu em período de taxa decrescente. Os modelos matemáticos: Lewis, Henderson&amp;Pabis, Logistic, Logaritmico e Aproximação da Difusão, ajustaram bem aos dados experimentais, o modelo Aproximação da difusão, apresentou coeficiente de determinação superior a 98,68% e DQM inferiores a 0,0306. Verificou-se influência da temperatura e da concentração de emulsificante na constante de cinética de secagem. De acordo com as constantes de secagem apresentadas pelo modelo Aproximação da Difusão, recomenda-se a secagem da polpa da manga nas seguintes condições: temperatura de 50°C e concentração de emulsificante de 5,5 g.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6559', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c78e', 'Posicionamento de marca: Uma análise da marca Gurupy', 'Morais, Maria Águida Karlianne Leite; Monte, Washington Sales do; Gomes, Wygna Wenne de Oliveira; Menezes, Edivaldo Rabelo de; Lima, Márcia Janiele Nunes da Cunha', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este artigo tem por objetivo analisar o posicionamento da marca Gurupy na visão das redes de supermercados do Rio Grande do Norte que vendem seus produtos. Sua relevância está ligada a importância que é dada por parte dos consumidores as marcas. O trabalho inicia com uma revisão teórica sobre os conceitos de marca e posicionamento, história das primeiras marcas e as estratégias e gerenciamentos da mesma. Posteriormente são apresentadas a metodologia da pesquisa e a técnica de análise utilizada. Optou-se por utilizar a metodologia do tipo qualitativa. Os dados foram coletados por meio de um questionário que foi enviado por e-mail aos cinco compradores das redes ligadas a Gurupy. A partir da análise dos dados adquiridos com os questionários, foi percebido que mesmo tendo um número razoável de concorrentes a Gurupy tem um bom posicionamento de sua marca, tanto sob a visão das redes de supermercados quanto na visão dos clientes finais', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6583', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c78f', 'Avaliação da Satisfação dos Serviços da Unimed em Pau dos Ferros / RN: Uma Aplicação do Modelo SERVQUAL', 'Monte, Washington Sales do; Vidal, Tereza Raquel Bezerra; Menezes, Edivaldo Rabelo de; Lopes, Nágela Maria Alves; Araujo, Morgana Aragão', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este artigo tem como objetivo avaliar a satisfação dos serviços oferecidos pela Unimed Alto Oeste Potiguar/RN. Para tal, identificaram-se os fatores de satisfação destes serviços através de um questionário, construído e elaborado a partir do modelo de Parasuraman, utilizando-se dos seus indicadores para a avaliação dos serviços prestados pela empresa em estudo. O trabalho inicia com uma revisão teórica sobre os conceitos de serviços, satisfação e comportamento do consumidor. Posteriormente os métodos de pesquisa e as técnicas de análise utilizadas. Optou-se por utilizar metodologia do tipo quantitativa. Os dados foram coletados por meio de um questionário baseado na ferramenta SERVQUAL, adaptada, aplicado junto a uma mostra não probabilística por conveniência  com 70 usuários da empresa. No entanto, através dos resultados conclui-se que fica evidenciado que em geral, a qualidade dos serviços está com um nível de satisfação considerado bom em todas as dimensões avaliadas. Um dos aspecto', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6584', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c791', 'O MARKETING E A CUSTOMIZAÇÃO: Um estudo bibliométrico', 'Monte, Washington Sales do; Menezes, Edivaldo Rabelo de; Lima, Márcia Janiele Nunes da Cunha; Leite, Emiliana Maria de Queiroz; Silva, Francisco Neirivaldo da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O Marketing possibilita o valor e a satisfação do cliente com determinados produtos, ele consiste no desenvolvimento de estratégias para vendas, comunicações e desenvolvimento do negócio e pode se dá de diferentes formas. O marketing aplicado a customização de produtos possibilita uma melhor divulgação de determinadas marcas, sendo uma aposta alta no comércio do século XXI servindo como estratégia máster de marketing. O presente artigo objetiva investigar o desenvolvimento do conceito de customização no mercado atual e perpassa uma investigação bibliográfica em diferentes fontes como no período de 2000 a 2015, buscando na literatura o desenvolvimento dos conceitos de marketing e customização ao longo do tempo. Observa-se que a customização de produtos vem sendo utilizada amplamente como estratégia de marketing pelos empresários, que com este diferencial buscam conquistar o cliente e personalizar o atendimento, sendo um detalhe positivo e inovador.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6600', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c793', 'QUALIDADE NO ATENDIMENTO: PADRONIZAÇÃO COM BASE NO MODELO PDCA', 'Monte, Washington Sales do; Menezes, Edivaldo Rabelo de; Benevides, Nígila Maria da Costa; Paula, Luciana Isabelli Costa de; Araújo, Morgana Aragão', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O uso do PDCA (Ciclo de controle estatístico do processo, que pode ser repetido continuamente sobre qualquer processo ou problema.) costuma propiciar resultados significativos nas empresas. Mas, é preciso verificar em que consiste este método e se há alternativas a ele. Para tal, são analisados conceitos como: conhecimento, solução de problemas, metodologia, método e técnica. Estes conceitos são considerados sob a ótica da gestão da qualidade. Este artigo tem o objetivo de prover um aporte para uma fundamentação teórica e uma estrutura de interligação envolvendo diferentes conceitos que podem ser relacionados ao PDCA. O giro do ciclo PDCA deve ser feito constantemente, trazendo resultados de melhoria contínua para os processos e, consequentemente para a organização. Este estudo procura demonstrar a importância da utilização deste ciclo para garantia da qualidade do produto/serviço. Para a contextualização do tema, o artigo se propôs a um estudo observacional e qualitativo através de um', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6602', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c794', 'Segurança no Trabalho em Agroindústria: a percepção dos trabalhadores de chão de fábrica de um laticínio em Sousa-PB', 'Maracaja, Patricio Borges; Gadelha, Patricia Sibelly Barbosa de Oliveira; Gadelha, Hugo Sarmento; Lima, Caetano Jose de; Melo, Wellington Ferreira; Braga, Geórgia Vieira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O Brasil é a quarta nação do mundo que mais registra acidentes durante atividades laborais, atrás apenas da China, Índia e Indonésia. Estes acidentes são causados por atos inseguros ou por condições inadequadas. O objetivo desta pesquisa foi levantar as percepções dos colaboradores internos de uma agroindústria do setor de laticínio quanto à segurança do trabalho. A revisão de literatura desenvolveu um olhar histórico sobre a questão do trabalho e ainda as noções atuais de trabalho. Quanto à metodologia, esta pesquisa é delineada como exploratória, descritiva e de campo, com abordagem quantitativa. A segurança e a saúde dos trabalhadores constituem temática crucial para o sucesso das agroindústrias. Na empresa estudada, as percepções dos colaboradores, em termos gerais, são positivas quanto à administração, à chefia direta, às responsabilidades e ao ambiente de trabalho, assim quanto aos EPI’s. Conquanto, quando se pesquisa sujeitos em situação de subordinação resta sempre a dúvida em ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6614', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c795', 'Práticas de educação ambiental no distrito de irrigação do perímetro irrigado várzeas de Sousa/PB', 'Gadelha, Hugo Sarmento; Lima, Caetano Jose de; Soares, Jardel de Freitas; Gadelha, Patrícia Sibelly Barbosa de Oliveira; Melo, Wellington Ferreira de; Braga, Geórgia Vieira; Moreira, Amanda Rezende', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Face invisível da realidade sustentável e da segurança alimentar no Brasil, sobretudo para o setor produtivo é a educação ambiental. A educação ambiental deve ser o primeiro passo para instigar a consciência crítica sobre as questões ambientais. Consiste em área temática pouco explorada pela academia local na região de Sousa – PB. Assim, diversas inquietudes com as questões ambientais moveram esta pesquisa com o objetivo de conhecer as práticas de educação ambiental junto aos agricultores familiares, no âmbito do Distrito de Irrigação do Perímetro Irrigado Várzeas de Sousa. Quanto à metodologia, essa pesquisa é delineada como exploratória, descritiva e de campo. Conclui-se que a matéria ambiental nas Várzeas de Sousa encontra-se à mercê de iniciativas do pequeno produtor rural, conquanto ações relativas a palestras ou cursos sobre as temáticas atinentes ao meio ambiente ou à educação ambiental sejam citadas. Fato é que, inúmeras instituições poderiam contribuir substancialmente com pes', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6615', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c798', 'A importância da gestão hídrica no controle das enteroparasitoses', 'Maracajá, Patrício Borges; Braga, Georgia Vieira; Melo, Wyara Ferreira; Almeida, José Cezário de; Rolim, Fagno Dallino; Oliveira, Thyffany Laurents Limeira de; Silva, Cristiana Russo Lima da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A água é primordial para a manutenção da vida como conhecemos, no entanto, a má gestão desse líquido tão precioso pode provocar doenças parasitarias e infecciosas. As doenças parasitárias acarretam uma série de danos à população atingida, apesar de não apresentarem altas taxas de mortalidade, tais doenças produzem um impacto direto na qualidade de vida do individuo, provocando alterações psicossociais e danos físicos. Essas situações passam a sobrecarregar os serviços de saúde, tendo em vista, uma demanda que muitas das vezes não recebe o devido tratamento. Diante dessa contextualização, observa-se quão relevante é tratar desse problema de saúde pública, ainda, muito presente na nossa região e no nosso país. Com isso, a pesquisa tem a finalidade de identificar a importância da gestão hídrica no controle as enteroparasitoses. No que se refere às considerações metodológicas, o estudo trata-se de uma revisão bibliográfica, realizada a partir do levantamento dos artigos nas seguintes bases', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6618', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c79a', 'Avaliação do nível de competitividade em uma indústria de laticínios da cidade de Sousa-PB', 'Olivera, Marcos Macri; Barbosa, Maria de Fátima Nóbrega; Rodrigues, Luma Michelly Soares', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O estudo sobre o nível de competitividade da indústria permite o conhecimento mais aprofundado das variáveis positivas e negativas que indicam o sucesso ou insucesso das atividades e processos desempenhados, além do feedback quanto ao que deve ser melhorado e até que ponto a empresa pode se considerar competitiva frente ao padrão de concorrência no mesmo setor. Nesse contexto, o estudo teve como principal objetivo, verificar o nível de competitividade de uma indústria do setor de laticínios da cidade de Sousa-PB. A pesquisa é exploratória e descritiva; bibliográfica e estudo de caso, utilizando-se como meio de pesquisa um questionário realizado através de entrevista e de procedimentos de natureza qualitativa para análise e discussão dos dados. Evidenciou-se que a empresa em questão conhece o significado de competitividade e a considera importante para o crescimento da empresa frente ao mercado, além de ser avaliado o nível de competitividade de maneira forte, representando 77% positiva', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6621', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c79b', 'Sistema de gestão ambiental e suas relações com a competitividade: estudo de caso em empresa processadora de sorvetes e picolés em Sousa – Paraíba', 'Rodrigues, Danilo Gonçalves; Barbosa, Erivaldo Moreira; Barbosa, Maria de Fátima Nóbrega', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O estudo de possíveis relações entre o sistema de gestão ambiental e a competitividade de empresas tem sido tema de estudo de alguns pesquisadores. Pressões externas de diversos stakeholders em prol da incorporação da variável ambiental nas estratégias de negócios tem acentuado cada vez mais as demandas por estudos dessa natureza. Nesse contexto, o objetivo dessa pesquisa é identificar as possíveis formas de contribuições de um Sistema de Gestão Ambiental, baseado na norma NBR ISO 14001:2004, para a competitividade em empresa da indústria de sorvetes e picolés em Sousa – PB. O método adotado nesta pesquisa foi o estudo de caso e as técnicas de pesquisa foram entrevistas em profundidade com os gerentes mais diretamente envolvidos com as dimensões gestão ambiental e competitividade. A partir dos modelos teóricos e dos critérios adotados para análise das dimensões em estudo, os resultados mostraram que a organização apresenta uma situação ambiental fraca e uma competitividade em nível méd', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6633', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c79d', 'Elaboração e avaliação da qualidade de bebida tipo smoothie adoçada com mel de abelhas', 'Araújo, Jayuri Susy Fernandes de; Xavier, Leidiana Elias; Soares, Wisla Kívia de Araújo; Albuquerque, Tiago da Nóbrega; Meireles, Bruno Raniere Lins de Albuquerque; Silva, Cláudio Leite da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A elaboração de produtos à base de frutas, que sejam práticos e seguros, buscam associar sabor agradável com alegações funcionais. Os smoothies constituem bebidas de consistência suave semilíquida, que vai ao encontro das necessidades de um nicho de mercado que demanda novos produtos mais saudáveis e próximos aos naturais, como o mel. Desta forma, objetivou-se elaborar e caracterizar smoothies preparados à base de frutas e adoçados com mel em diferentes concentrações. Todas as formulações foram elaboradas com manga, uva e maracujá nas proporções de 50%, 30% e 20%, respectivamente, variando as concentrações de mel adicionadas, S0 (sem adição de mel), S1 (5% de mel), S2 (10% de mel) e S3 (15% de mel). Foram realizadas análises físico-químicas de pH, acidez, sólidos solúveis totais (SST) e ácido ascórbico (Vitamina C). Os resultados de pH, acidez e ácido ascórbico não diferiram estatisticamente entre as formulações elaboradas. Todas as formulações apresentaram altos teores de Vitamina C, ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6678', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c79e', 'O PRONAF semiárido e a convivência com a seca: a utilização de crédito rural para a construção de barragens subterrâneas', 'Targino, Giliard Cruz; Pedroza, Laisianne Mendes; Cirilo, Thalia Ferreira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho tem como objetivo abordar, inicialmente, aspectos principais acerca do Programa Nacional de Fortalecimento da Agricultura Familiar (PRONAF), que, através de suas diversas linhas de financiamento, tem conseguido promover ao produtor rural um manifesto progresso na produção campesina; buscar-se-á, posteriormente, tratar de uma linha de financiamento específica, voltada, prioritariamente, à aplicação de recursos em infraestrutura hídrica, qual seja, o PRONAF Semiárido, considerando que, nas regiões semiáridas, umas das maiores dificuldades do produtor rural é, indubitavelmente, a convivência com os períodos de estiagem, havendo a necessidade, portanto, da utilização de mecanismos que, de certa maneira, possam proporcionar um melhor aproveitamento das águas pluviais, por meio do investimento em técnicas modernas. Ainda mais especificamente, objetiva-se explanar a utilização do crédito proveniente do PRONAF Semiárido na construção das barragens subterrâneas, que configur', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6691', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c7a5', 'A dinâmica socioeconômica e ambiental a partir da atividade minero-metalúrgica em Barcarena, Pará, Brasil (1980-2010)', 'Oliveira, Rafaele Freitas de; Lira, Bruna Roberta Pereira; Nascimento, Thays Valente do; Fernandes, Lindemberg Lima; Chaves, Juliane Ribeiro das; Fialho, Hailton César Pimentel', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A partir da década de 70, algumas cidades da região Amazônica sofreram bastantes modificações na sua organização socioespacial em virtude da implantação dos chamados Grandes Projetos na Amazônia. O município de Barcarena é um exemplo disso, e a partir da instalação do Complexo Industrial, uma nova configuração social, econômica e ambiental começou a se processar no município. Desta forma, o objetivo da presente pesquisa consiste em analisar a dinâmica socioeconômica e ambiental no município durante o período de 1980 a 2010. Para tanto, foi levantado algumas informações por meio de dados secundários do município em relação a demografia, IDHM, PIB, e dados de infraestruturas básicas, como por exemplo, tipo de abastecimento de água, esgotamento sanitário, disposição de resíduos e energia elétrica. Além disso, foi realizado o mapeamento de uso e ocupação do solo na região. Resultados apontam que Barcarena possui uma grande importância no cenário econômico estadual, uma vez que figura entre', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6977', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c7a6', 'Estudo Prévio do Impacto Ambiental e Econômico na Propriedade e os Princípios Constitucionais Ambientais', 'Reis, Luiz Carlos; Duarte, Erich dos Reis', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Analisam a evolução das leis ambientais, a biodiversidade e sua crise. A incorporação do código florestal (Lei 12.651), da lei federal da política nacional do meio ambiente (lei 6.938/81). O estudo prévio de impacto ambiental (EPIA), e os princípios constitucionais que regem a esse respeito. Apresenta sugestão para elaboração do (EPIA) baseados nos princípios do direito ambiental.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/6991', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c7a8', 'Análise multitemporal da supressão vegetal com o uso de georreferenciamento', 'Matos Rodrigues, Ana Beatriz; Giuliatti, Nathalia Melo; Junior, Antonio Pereira; Jesus, Edmir dos Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A Amazônia é uma importante área do território nacional devido a sua rica biodiversidade de espécies de fauna e flora, no entanto. Para isso, o objetivo da pesquisa foi analisar, em escala multitemporal, as alterações decorrentes do desflorestamento no município de Lábrea (AM). O método utilizado foi dedutivo com pesquisa quantitativa complementada com levantamento de dados documentais em sites eletrônicos especializados: do Instituto Brasileiro de Geografia e Estatística (IBGE) e Instituto Nacional de Pesquisas Espaciais (INPE), com recorte temporal de 2009 a 2018. A análise dos dados obtidos, entre 1995 e 2005, indicou que o desflorestamento reduziu de forma linear, sendo que, em 1997, a área desflorestada correspondia a 1,37% do território municipal e, em 2005, a 0,26%. Já no período de 2010 a 2015 houve um acréscimo na retirada da biomassa, o que equivaleu a 0,35% do município de Lábrea.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7114', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c7ab', 'Programa Nacional de Alimentação Escolar em Ibiara-PB', 'Pereira, Jocimario Alves; Jesus, Joelma Farias Vieira de; Medeiros, Marcos Barros de; Costa, Natanaelma Silva da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A educação pública brasileira é alvo de debate e reflexão, sempre buscando á escola ideal, que atenda as necessidades da sociedade. Com essa perspectiva de uma escola para todos passamos por diversas teorias pedagógicas, projetos e programas, que buscam promover além da formação cientifica e cidadã. Com as dimensões continentais do Brasil e as instabilidades históricas de nossa política administrativa, tornasse passível de duvidas à efetivação de programas ou projetos nacionais, o que leva á um terreno fértil para pesquisas e diálogos da confirmação positiva de seus resultados. Uma vez que o Pnae se apresenta como um programa de importância sistêmica no campo da educação e da agricultura familiar, visto que uma vez bem executado apresenta benefícios múltiplos aos públicos envolvidos. Que é exatamente o objetivo desse trabalho. O trabalho foi realizado no município de Ibiara – PB, cidade do alto sertão paraibano que fica a 460 km da capital do estado. Atendendo uma população estudantil ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7192', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7b1', 'Os tipos de própolis e sua utilização em lesões cutâneas', 'Eufrásio de Lacerda, Leonária; Maracajá, Patrício Borges; Nóbrega, Karla Gomes da; Ferreira Melo, Wyara; Dallino Rolim, Fagno; Ferreira, Antônio Eudes; Melo, Edjair Raimundo de; Freires, Maria Amanda ', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A própolis é bastante utilizada na medicina popular, principalmente na cicatrização de ferimentos, sendo além de cicatrizante, um antibiótico natural sem efeitos colaterais, possui um baixo custo de produção e de fácil acesso à população. Foi através dessa constatação empírica que se despertou a percepção sobre a necessidade de executar uma revisão bibliográfica sobre os possíveis materiais já construídos no meio científico e voltados à temática, pois é importante haver a relação entre as comprovações encontradas pela ciência e os hábitos que são desenvolvidos em meio a população. Diante do exposto, o presente estudo objetivou executar uma revisão bibliográfica que apresente, através dos estudos expostos, os tipos de própolis que podem ser utilizadas nas lesões cutâneas, examinando assim sua efetividade no processo de cicatrização. Trata-se de uma revisão bibliográfica do tipo exploratória, baseando-se no seguinte questionamento: quais os tipos de própolis utilizadas nas lesões cutânea', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7486', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7b2', 'Qualidade físico – química e microbiólogica de mél de abelha africanizadas produzidas no munucípio de Nazarezinho-PB', 'Maracajá, Patrício Borges; Gomes, Damião Junior; Castro, Ánubes Pereira de; Pessoa, Lais de Oliveira; Campos, Rogenia Araujo; Medeiros, Aline Carla de; Peixoto, Patrícia Custódio', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O Mel de abelha é um alimento natural proveniente do néctar das plantas através das abelhas. A qualidade do mel é determinada por diversos fatores como, por exemplo,  a florada, o clima, as práticas de higiene empregadas em sua extração. Dessa forma, o mel de abelha da espécie Appis Mellifera L. tem suas próprias características microbiológicas e físico-químicas determinando a sua qualidade. O objetivo deste estudo é avaliar as características físico-químicas e microbiológicas de méis de abelhas Apis mellíferas produzidas por diferentes associações e apicultores informais na cidade de Nazarezinho, localizado no Sertão da Paraíba. Com o a finalidade de verificar a qualidade do produto produzido e comparar os resultados com os exigidos pela legislação brasileira vigente para mel. Assim, foram estudadas 30 amostras de méis, provenientes de diferentes origens florais. Sendo 10 amostras obtidas no comercio local, 10 amostras de meleiros e 10 amostras de Associações. Foram realizadas análise', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7501', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7bf', 'Tipos de variações de espectro infravermelho de queijo de manteiga adulterado com óleo vegetal', 'Medeiros, Isandra de França; Vicentini, Nívea Maria; Anjos, Virgílio dos; Leite, Antônio Iranaldo Nunes; Medeiros, Uliana Karina de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O trabalho objetivou constatar os tipos de alterações ocorridas no espectro infravermelho do queijo de manteiga, quando fraudado com óleo vegetal. Para isso, utilizou-se um método instrumental, a espectroscopia infravermelho médio, por ser rápida, confiável e ecoeficiente, já que elimina o uso de reagentes perigosos e elimina o descarte de produtos danosos ao meio ambiente. Produziu-se amostras de queijo de manteiga falsificados com óleo vegetal em proporções de 0 a 100% de substituição da manteiga de garrafa por óleo que foram analisadas em triplicatas. Os espectros obtidos demonstraram variações nas principais regiões do espectro do queijo de acordo com a intensidade da fraude. Os espectros obtidos foram tratados por quimiometria quando demostrou-se por meio da Análise de Componente Principal-PCA, haver alterações nas principais regiões do espectro do queijo de manteiga suficientes para caracterizar a fraude, demonstrado assim a eficiência do método.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7630', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7c1', 'Efeito da aplicação de revestimentos comestíveis em frutas e hortaliças minimamente processadas', 'Almino, Heulyson Arruda; Santos, Saint Clair Lira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As frutas e hortaliças minimamente processadas se apresentam como uma alternativa para os consumidores que estimam por produtos mais saudáveis, livres de aditivos químicos, prontos para o consumo e boa qualidade. Porém o processamento mínimo de frutas e hortaliças afetam diretamente a fisiologia dos produtos, pois essas operações resultam em danos a integridade do tecido, que por conseguinte ocasionam num aumento da deterioração. Desse modo, os revestimentos comestíveis se tornam essenciais para favorecer a manutenção da qualidade e segurança desses alimentos. Assim, o objetivo desta revisão bibliográfica é expor alguns efeitos de revestimentos comestíveis em frutas e hortaliças minimamente processadas. Com a base de dados apoiada através de consultas a artigos científicos, trabalhos de dissertação e teses listados nas bases SCIELO, CAPES E NDLTD. Delineou-se a busca apenas por literatura publicada nos últimos 6 anos, portanto os publicados de 2013 a 2019.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7634', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7c3', 'Beneficiamento e caracterização de resíduos da romã orgânica para aproveitamento agroindustrial', 'Andrade, Mychelle Lira; Fonseca, Jeniffer Viviany Santos; Nogueira, Lidia Paloma Silva; Cavalcanti, Mônica Tejo; Sousa, Pahlevi Augusto', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A romã (Punica granatum L.) é uma fruta arbórea, geralmente usada como planta ornamental e explorada pelas suas características medicinais, suas sementes são utilizadas na preparação de sucos e apresentam vários nutrientes. Considerando estes aspectos, objetivou-se avaliar as características físico-química e a composição centesimal das sementes de romã orgânica. As sementes foram secas em um secador solar e logo depois foram trituradas e peneiradas para obtenção da farinha, foram realizadas análises físico-químicas e avaliação da composição centesimal da farinha obtido. Os resultados para a atividade de água (0,44), pH (4,17) e umidade (4,70%) demonstraram que o pó pode apresentar uma boa vida de prateleira, podendo ser utilizada durante longo prazo. Dentre os parâmetros analisado verificou-se que os principais constituintes da farinha, foram os carboidratos (68,38%), lipídeos (13,52%) e proteínas (11,08%), respectivamente.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7637', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7c9', 'Pobreza e meio ambiente nas cidades do Brasil da América Latina', 'Maracaja, Patricio Borges; Oliveira, Luan Gomes dos Santos de; Silva, Aldeone Pereira; Medeiros, Aline Carla de; Barbosa, Fernanda Fernandes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A questão ambiental tomou dimensões alarmantes, as quais redefiniram a geopolítica mundial. Este trabalho tem como objetivo principal realizar uma revisão de literatura acerca dos três eixos: cidade, meio ambiente e pobreza. Destacando o seu viés político. Espera-se que as idéias aqui postas possam contribuir para a formação de um saber prudente, não só crítico, mas interventivo, com condição sine qua non para o exercício da cidadania garantida, mas não efetivada no espaço neoliberal.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7720', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7cd', 'Estudo comportamental da precipitação pluviométrica no município de Crato-Ceará, no período entre 1974-2009', 'Pinto, Nijair Araújo; Bezerra Neto, Francisco das Chagas; Silva, Demaiara Henrique da; Felizardo, Romeu de Oliveira; Crisostomo, Natália Cruz; Barboza, Eliezio Nascimento; Sampaio, Maria Raquel Leite', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A precipitação é caracterizada como o processo de condensação e deslocamento em direção a superfície terrestre a partir de gotas de água. A precipitação pluviométrica no Nordeste é caracterizada pela alta variabilidade espaço-temporal, com poucos dias de chuvas mesmo no período de não estiagem e caracterizado por precipitações irregulares, variando espacialmente e de um ano para outro. O município de Crato está localizado geograficamente no Nordeste brasileiro, situado na Região Metropolitana do Cariri (RMC) e clima semiárido. Pesquisas relacionadas com análise temporal de precipitação pluviométrica têm grande relevância tendo em vista a vulnerabilidade da sociedade, economia e meio ambiente as condições climáticas, especialmente variabilidade de pluviométrica nas regiões tropicais. É nesse contexto que esse artigo está inserido, com objetivo analisar o comportamento das precipitações ocorridas em Crato, Ceará no período de 1984 a 2009. Para a realização desse estudo, foram utilizados ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7729', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7ce', 'Análise temporal do comportamento da precipitação pluviométrica na cidadede Fortaleza (CE), Brasil', 'Pinto, Nijair Araújo; Bezerra Neto, Francisco das Chagas; Maia, Adryele Gomes; Crisostomo, Natália Cruz; Barboza, Eliezio Nascimento; Beserra, Marcelo Nobre dos Santos; Sampaio, Maria Raquel Leite', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A história do semiárido nordestino está profundamente relacionada com secas severas, impactando no aumento da fome, pobreza e consequentemente no desemprego e êxodo rural, isso acontece devido à irregularidade das chuvas e aos baixos índices pluviométricos. A cidade de Fortaleza, CE está inserido na porção norte do Estado do Ceará, com tropical úmido, com período chuvoso no período de verão e seca no período de inverno, com duas estações climáticas bem definidas: chuvosa e seca. Pesquisas relacionadas com análise temporal de precipitação pluviométrica têm grande relevância tendo em vista a vulnerabilidade da sociedade, economia e meio ambiente as condições climáticas, especialmente variabilidade de pluviométrica nas regiões tropicais. É nesse contexto que esse artigo está inserido, com objetivo analisar o comportamento das precipitações ocorridas em Fortaleza, Ceará no período de 1984 a 2008. Para a realização desse estudo, foram utilizados dados disponibilizados pela Secretária dos Re', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7730', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7cf', 'Potencialidade da biodegradação de corantes têxteis', 'Bezerra Neto, Francisco das Chagas; Maia, Adryele Gomes; Felizardo, Romeu de Oliveira; Crisostomo, Natália Cruz; Barboza, Eliezio Nascimento; Neves, Daniel José Formiga; Sampaio, Maria Raquel Leite', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A partir da industrialização cresceu-se a necessidade de aumentar a produção de bens de consumo que geraram diversos impactos negativos ao meio ambiente. Destaca-se as indústrias têxteis que liberam efluentes de difícil degradabilidade, onde os métodos tradicionais não são eficientes, necessitando de outras técnicas alternativas, como o uso de microrganismos que possuem enzimas especificas para transformar as enormes cadeias aromáticas em cadeias alifáticas, no qual é mais fácil de ser degradada. Na biodegradação de corantes têxteis são utilizados fungos, bactérias, enzimas, algas e cianobactérias, sendo mais eficientes que as técnicas utilizadas nas estações de tratamento de água e esgoto e é mais viável economicamente. Portanto, esse trabalho de revisão de literatura tem como objetivo buscar analisar a potencialidade do processo biodegradação dos corantes têxteis.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7731', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7d7', 'Caracterização físico-química, microbiológica e sensorial de cocada adicionada de maxixe saborizada com polpa de frutas', 'Félix Rodrigues de Abrantes, Isabela; Piovesan, Natiéli; dos Anjos Dantas, Emelly Naiara; Bordin Viera, Vanessa; Silveira Martins, Ana Cristina', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O Cucumis anguria L. é uma hortaliça de clima tropical que apresenta uma diversidade de nutrientes, sendo seu baixo valor calórico um fator considerado atrativo desta hortaliça. Atualmente, o maxixe tem pouca utilização causando muitas vezes sua perda pós-colheita. Assim objetivou-se elaborar diferentes formulações de cocada adicionadas de maxixe saborizadas com polpa de fruta e avaliar suas características físicas, físico-químicas, microbiológicas e sensoriais. Para isso, foram desenvolvidas três formulações da cocada adicionadas de maxixe variando a adição de polpas (graviola, maracujá e abacaxi). Foram realizadas análises de umidade, cinzas, acidez, pH, atividade de água e sólidos solúveis totais, análises microbiológicas de contagem de bolores e leveduras, micro-organismos mesófilos e psicotróficos, bem como avaliação sensorial. Os resultados da atividade de água e o teor de sólidos solúveis totais apresentaram-se maiores na cocada de maxixe saborizada com polpa de graviola. Já o m', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7892', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7d9', 'Importância das condições higiênico-sanitárias e boas práticas de fabricação em serviços de alimentação', 'Bezerra, Adriana Rodrigues; Arcanjo, Narciza Maria de Oliveira; Medeiros, Isandra de França; Costa, Bárbara Jéssica Pinto', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Diante do contexto mundial é de extrema importância que a alimentação venha assegurar a satisfação das necessidades nutricionais e da saúde da população, para isso é imprescindível que essa seja segura e de qualidade. As boas práticas de fabricação (BPF) em serviços de alimentação buscam garantir condições higiênico-sanitárias em conformidade com a legislação vigente, no intuito de proporcionar um alimento seguro. Essas são preestabelecidas pela Agência Nacional de Vigilância Sanitária (ANVISA) a qual objetiva a regulamentação dos setores destinados a prestação de serviços em Unidades de Alimentação e Nutrição (UAN). Buscando inferir sobre a realidade dos serviços de alimentação, este trabalho tem como desígnio refletir sobre os resultados obtidos no que tange às condições higiênico-sanitárias de alguns serviços de alimentação analisados outrora. Pretendendo alcançar tal propósito foi feito uma revisão bibliográfica nas plataformas SCIELO, MEDLINE, PUBMED e BVS, baseada em 20 trabalhos', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7915', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7de', 'Avaliação da rotulagem de diferentes marcas de biscoitos integrais', 'de Souza, Pahlevi Augusto; Júnior, José Valter Florêncio; Pinto Costa, Bárbara Jéssica; Fonseca Feitoza, João Vitor; Medeiros Brito, Igor Matheus; Moraes de Lima, Antonia Elane Cristina', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O interesse da população brasileira em se informar a respeito dos alimentos que compõem sua dieta tem se tornado cada vez maior. Tal comportamento ocorre em virtude das novas tecnologias da indústria alimentícia, bem como da oferta de produtos que prometem ajudar a manter uma vida mais saudável. Dentre esses produtos, os biscoitos integrais vêm conquistando cada vez mais espaço no mercado devido às suas características nutricionais, sendo uma opção de lanche com melhores benefícios à saúde. Tendo isso em vista, objetivou-se com este trabalho realizar uma avaliação de rotulagem de diferentes marcas de biscoitos integrais comercializados em Currais Novos, no Rio Grande do Norte, bem como verificar a conformidade dos rótulos com a legislação para a rotulagem nutricional e outras informações obrigatórias. Rótulos de oito marcas diferentes de biscoitos integrais foram escolhidos aleatoriamente em supermercados e mercadinhos do município de Currais Novos – RN e nomeadas, por questões éticas,', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7959', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7df', 'Técnica para liberação do predador Euborellia annulipes (Dermaptera: Anisolabididae)', 'Maracajá, Patrício Borges; Batista, Jacinto de Luna; Oliveira, Gemerson Machado de; Lacerda, Letícia Barbosa de; Araújo, Heloísa Martins de; Medeiros, Aline Carla de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O uso excessivo e inadequado dos defensivos agrícolas e os consequentes reflexos negativos sobre o meio ambiente evidenciam a necessidade de buscas de métodos alternativos ao controle químico de insetos pragas, tendo o controle biológico como um dos métodos mais relevantes. Entre os insetos benéficos com maior potencialidade de uso, encontram-se os da ordem Dermaptera, dando ênfase a espécie Euborellia annulipes. Porém um dos grandes problemas na expansão do controle biológico aplicado, principalmente para predadores, está nas técnicas de liberação em campo, onde existe uma escassez de trabalhos. Desta forma, objetivou-se avaliar a técnica de liberação do predador E. Annulipes. A técnica para liberação foi composta por dois fatores: idade da postura (um, três e seis dias após a oviposição) e umidade na cápsula de liberação (presença e ausência), com dez repetições de dez ovos para cada tratamento. Cada postura foi acondicionada no interior de cápsula biodegradável, contendo orifícios d', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/7987', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7e1', 'A aplicação das licitações sustentaveis na UFCG – PB – Brasil', 'Soares, Jardel de Freitas; Melo, João Mendes de; Mendes, Jéssica Ruana Lima', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A complexidade dos problemas ambientais na atualidade exige uma postura de atenção e compromisso com práticas sustentáveis com o objetivo de possibilitar a harmonização e compatibilização do crescimento econômico e a preservação do meio ambiente, de modo a garantir vida digna às presentes e futuras gerações. A partir dessa perspectiva, surge no âmbito da Administração Pública, as denominadas Licitações Sustentáveis, por meio do qual se estabelece critérios ou práticas de sustentabilidade a serem observados pelos participantes do certame, como facilidades para reciclagem, vida útil mais longa dos produtos, geração de menos resíduos na utilização, e menor consumo de matéria-prima e energia. A temática escolhida se mostra de grande valia, uma vez que é notório que a preservação do meio ambiente encontra-se ameaçada diante do atual padrão de consumo, razão pela qual cabe ao Poder Público se investir de uma gestão socioambientalmente responsável, a fim de diagnosticar e mitigar os impactos ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8017', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7e3', 'OCCUPATIONAL RISKS IN BRAZILIAN AGRICULTURE', 'Medeiros, Aline Carla de; Oliveira, Marina Cartaxo Braga Morais de; Medeiros, Fernando Estevam de; Maracaja, Patricio Borges', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '- Poucos estudos no setor agrícola contemplando o viés saúde e aspectos do trabalho em detrimento do econômico ainda é escasso. Este trabalho tem como objetivo identificar, a partir de publicações brasileiras, os riscos ocupacionais e as doenças do trabalho na agricultura. Foi realizado uma revisão integrativa da literatura, com busca na base de dados da Biblioteca Virtual em Saúde e no Portal do Medical Publisher a partir da combinação no uso dos Descritores Controlados em Ciências da Saúde: Riscos Ocupacionais e Agricultura. Foram identificadas 171 publicações e nove constituíram a amostra final. Após realização da pesquisa, foram identificados os seguintes riscos ocupacionais em ordem de importância: químicos, físicos, ergonômicos, psicossociais e de acidentes. Quanto às doenças vinculadas ao trabalho agrícola e decorrentes da exposição a tais fatores, destacaram-se lesões musculoesqueléticas, câncer, doença da folha do tabaco verde, doenças mentais, cansaço físico, cansaço mental, ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8027', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7e7', 'Estação de tratamento de efluentes: teoria em benefício da prática', 'Carneiro, Edson  Carneiro Nascimento; Santos, Saint Clair Lira; Araújo da Silva, George Gérson', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Com o passar dos anos as normas ambientais passaram a ser mais severas com as indústrias que destinam efluentes de forma imprudente no meio ambiente. O estudo em questão avaliou o funcionamento de uma Estação de Tratamento Efluente de uma engarrafadora de refrigerantes localizada na cidade de João pessoa – PB, a mesma conta com uma estrutura composta por um pré–tratamento, tratamentos primário, secundário e terciário, onde cada etapa possui uma atuação especifica no processo. O objetivo do estudo é realizar um mapeamento das informações do processo, avaliar pontos peculiares que necessitavam de melhorias. A metodologia para pesquisa provê contribuições para o processo, no controle operacional e nos parâmetros de qualidade do tratamento, procurando de forma científica conciliar teoria com a prática utilizando métodos combinados, observando e intervindo de forma direta com o propósito de fornecer alternativas eficientes ao sistema, como por exemplo, controle do oxigênio dissolvido na lag', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8076', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7e9', 'Características qualitativas e sensoriais do leite das diferentes espécies domésticas', 'Medeiros, Weverton Pereira de; Andrade Junior, Alberto Luiz Freire de; Andrade, Romário de Oliveira; Silva, Dénison Alexandre da; Albuquerque, Tiago da Nóbrega; Santos, Edilayane da Nóbrega', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O leite é um dos alimentos de origem animal mais consumido pela população mundial, devido a sua absoluta importância nutricional contendo carboidratos, gorduras, proteínas, vitaminas e minerais, e constitui a maior e melhor fonte de cálcio na alimentação humana, além de ser um alimento versátil do ponto físico-químico, que apresenta conjuntura ideal para ser adaptado de acordo com a necessidade e preferência do indivíduo. Nos dias atuais podemos encontrar diversos tipos de leite, entre eles o bovino, caprino, ovino e de búfala, os quais se diferem em suas características sensoriais. Objetivou-se com este trabalho de revisão, buscar informações sobre o leite das diferentes espécies de ruminantes domésticos, visando o que está sendo estudado, principalmente, suas características qualitativas e sensoriais. Para a seguinte revisão bibliográfica, foram pesquisados artigos nas bases de dados do LILACCS, Scientific Eletronic Library Online (SciELO), acessados através do portal de periódicos d', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8197', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7ea', 'Modelos matemáticos aplicado no conforto térmico: um estudo em dois ambientes de condições microclimáticas distintas em Juazeiro do Norte - CE', 'Bezerra Neto, Francisco das Chagas; Oliveira, Bruno Barbosa de; Caiana, Clarice Ribeiro Alves; Silva, Ana Millene dos Santos; Queiroz, João Paulo Borges de; Marques, Agilio Tomaz; Barboza, Eliezio Nas', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As cidades brasileiras vêm sofrendo nas últimas décadas diversas modificações, como consequência dessas modificações, destaca-se a formação de um espaço superficial e degradado. Esse crescimento desordenado vem causando mudanças na composição da atmosfera e no clima local. Sendo assim, o presente trabalho tem como objetivo principal verificar dois índices relacionados com o conforto térmico humano: Índice de Calor (IC) e o Índice de Desconforto Térmico (IDT), em dois ambientes de condições microclimáticas diferentes na área urbana da cidade de Juazeiro do Norte/CE. Para a realização da pesquisa, a coleta de dados foi realizada a partir da utilização do aparelho Termo-Higro-Anemômetro digital portátil, durante o período mais quente do ano, com coletas nos meses: agosto, setembro, outubro, novembro e dezembro de 2019. Para os cálculos do Índice de calor (IC) e Índice de desconforto térmico (IDT) foram aplicadas as metodologias de Steadman (1979) e Thom (1959). Os resultados evidenciaram ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8199', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7ed', 'Análise de Swot aplicada a uma empresa artesanal de laticínios no município de Cajazeiras-PB', 'Santos, Maria Alcantara dos; Sousa, Neliane Dias de; Gonçalves, Magda da Silva; Sousa, Milena Nunes Alves de; Tavares, Francisco Edval Leite; Alencar, Rosana Ferreira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A agroindústria é um setor da economia que tem passado por processos de evolução que se deve a uma maior valorização desse tipo de empreendimento respaldada em uma procura crescente por produtos naturais dentro dos padrões de qualidade. A organização de uma agroindústria deve ser voltada a atender a demanda do mercado e para isso o uso de ferramentas como a análise de SWOT pode auxiliar no desenvolvimento e crescimento. O presente trabalho teve como objetivo realizar a análise de SWOT de uma agroindústria que trabalha com laticínios no município de Cajazeiras-PB. A metodologia constou com uma visita a agroindústria para avaliar as instalações físicas; aplicação de um questionário estruturado com perguntas referentes a fatores internos e externos que envolvem o processo de funcionamento da empresa; formação da Matriz SWOT baseada nos dados obtidos; determinação de estratégias de enfrentamento para as ameaças e fraquezas identificadas. Os resultados mostraram que a empresa possui boa est', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8312', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c7f6', 'Potencial turístico rural do município Monte das Gameleiras/RN', 'Cordeiro, José Lucivaldo Torquato; Lucena, Carmelita Érica Azevedo de; Medeiros, Marcos Barros de; Feitosa, Maria Ariadny Moreira; Costa, Natanaelma Silva da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este trabalho tem o escopo de apresentar a possibilidade de incluir os Agricultores Familiares no apoio ao turismo em Monte das Gameleiras/RN e traçar um perfil das demais potencialidades turísticas do município, procurando despertar os interesses dos empresários e gestores públicos para as vantagens econômicas da sustentabilidade local e coibir o turismo exploratório que tem caráter predatório. Assim, identificar, para utilização pública, os potenciais turísticos do município do Monte das Gameleiras; definir ações para a Inclusão da Agricultura Familiar na rota do turismo local; propor ações de formação para a valorização do município e dos munícipes; apontar ações que possam promover atividades sustentáveis e alertar para o caráter predatório do turismo exploratório. Usufruímos também da Metodologia Participativa de Extensão Rural - MEXPAR cujo viés está voltado à sustentabilidade local. A MEXPAR assume como pressuposto básico que todo conhecimento é uma produção social e que, portan', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/8505', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c801', 'Dificuldades em georreferenciamento de imóveis rurais: : um estudo de caso', 'de Sousa Araujo, Raí; Lopes Alves, Dalieva; Batista, José de Carlos; de Sousa Alves, Leonardo; Pereira da Costa, Gilvania; Barboza, Eliezio Nascimento; de Lucena Neves, Annelyse Esequiel; de Sousa Ara', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/9675', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c803', 'Modalidades transversais e a psicoeducação: o desenvolvimento intersubjetivo através da educação ambiental', 'Castelhano, Marcos Vitor Costa; Medeiros, Emilly de Sousa; Ramalhano Neto, Adaci Estevam', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os aspectos políticos-educacionais expressos pelos moldes da transversalidade perante dos sistemas educativospermeiam um conjunto de possibilidades metodológicas, dialógicas e dinâmicas nas lapidações das atividades e dosplanejamentos pedagógicos, trazendo à tona as tendências descentralizantes como formativas essenciais, tendo diferentestemáticas alusivas, a exemplo da educação em saúde e os eixos ambientais. Nos campos interativos, entende-se que aeducação ambiental, sobretudo em seus panoramas críticos, promove o desenvolvimento intervenções e estratégias capazes deelucidar e edificar habilidades sociointerativas e socioemocionais perante de suas entrelinhas participativas, fortificandoposturas pró-ambrosia em vistas de seus sentidos emancipatórios-inclusivos, utilizando-se do meio ambiente enquanto planomotivador e relacional. Seguindo as afirmativas citadas, o estudo em questão discute sobre como os processos psicoeducativosligados a educação em saúde podem influir positivamente n', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/10166', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c804', 'A psicologia escolar enquanto norteadora de práticas sustentáveis: um panorama interdisciplinar', 'Silva, Elthon Bezerra e; Castelhano, Marcos Vitor Costa; Formiga, Mayara Millena Moreira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os estudos relacionados a valorização das práticas sustentáveis representam vieses e metodologias teórico-práticasessenciais para a construção de novas interações com o meio ambiente, promovendo a elaboração de constantesemancipatórias-inclusivas em suas possibilidades e perspectivas críticas-dialógicas, permeando o desenvolvimento dehabilidades intra e interpessoais em seus sentidos socioemocionais. Nos campos psicológicos, entende-se, por via da interaçãoda psicologia ecológica, que os entendimentos das relações entre os seres humanos e o meio ambiente envolvemfuncionamentos e dinâmicas fundamentais nos processos ressignificação e readaptação nos panoramas vinculativos, indo alémdas aborígenes técnicas unilaterais, atravessando novas conotações perceptivas e vivenciais-contemplarias. Seguindo asafirmativas supracitadas, o presente estudo como a Psicologia Escolar, enquanto área profissional consolida no universopsicológico-científico, pode influir positivamente nos direcionamentos si', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/10167', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff4d6a63682f044c807', 'A gestão ambiental e a agenda 2030 para as escolas rurais de Caridade - CE', 'Chaves , Alan Del Carlos Gomes; Rocha, Maria Zilma Sampaio; Silva Filho, José Pereira da; Maracaja, Patricio Borges; Melo, Wyara Ferreira; Santos, Sângela Maria Pereira dos; Sousa, Maria Alexandra Abr', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pesquisa tem como objetivo analisar a relevância da gestão ambiental e sua contribuição para os Objetivos de Desenvolvimento Sustentável (ODS) da Agenda 2030 nas escolas rurais do município de Caridade, Ceará. O estudo busca entender como essas práticas podem influenciar o desenvolvimento sustentável e a conscientização ambiental da comunidade escolar, além de identificar os principais desafios e perspectivas para sua implementação. A pesquisa adotou uma abordagem integrativa, explorando dados e conceitos relacionados à sustentabilidade no contexto educacional rural. Os resultados indicam que a implementação de práticas sustentáveis nas escolas rurais enfrenta diversos desafios, como a escassez de recursos financeiros, infraestrutura inadequada e a necessidade de capacitação contínua de professores e gestores para o uso de metodologias voltadas à sustentabilidade. Conclui-se que, apesar dos obstáculos, a gestão ambiental nas escolas pode contribuir significativamente para o alcance d', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11013', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c80a', 'Avaliação físico-química de lasanha de carne de rã-touro (Rana catesbeiana) em duas formulações', 'da FRANCA, David Araújo Monteiro; Nascimento, Flávia da Silva; da Silva, Mônica Ranchelle Ferreira; Figueiredo, Maria José de; Augostinho, Ana Kellis de Sousa', 'Editora Verde', 'Agriculture', 'Agriculture', 'O consumo de r&atilde;, apesar de ainda ser restrito, vem ganhando adeptos a cada dia. Considerada como ex&oacute;tica, sua carne possui sabor requintado e textura agrad&aacute;vel, al&eacute;m de representar uma fonte de prote&iacute;na de alto valor biol&oacute;gico. Lasanha &eacute; um prato feito com camadas alternadas de massa, queijo, carnes e algum tipo de molho, existindo diversos sabores comercializados em restaurantes e supermercados na forma industrializada. O sabor da lasanha, e at&eacute; mesmo o seu t&iacute;tulo, &eacute; definido de acordo com o tipo de carne utilizada na formula&ccedil;&atilde;o. O objetivo deste trabalho foi analisar a f&iacute;sico-qu&iacute;mica de lasanhas elaboradas com carne de r&atilde; em duas formula&ccedil;&otilde;es. Levando-se em considera&ccedil;&atilde;o o conceito funcional da carne de r&atilde;, procurou-se elaborar formula&ccedil;&otilde;es de lasanhas com teores reduzidos de colesterol. Al&eacute;m da carne de r&atilde;, utilizou-se t', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/860', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c80c', 'Avaliação das condições higiênico-sanitárias (Boas Práticas de Fabricação) das indústrias de sorvetes de Governador Valadares-MG', 'MORAIS, Ana C. A.; VILELA, Anderson F.; MACHADO, Fernanda V.; GONÇALVES, Mariana M.; FREITAS, Núbia C.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O sorvete &eacute; uma guloseima apreciada principalmente nos dias de calor e em cidades de clima quente. Apesar de refrescante, saboroso e bastante nutritivo, est&aacute; bastante relacionado a contamina&ccedil;&otilde;es microbiol&oacute;gicas (33%). As mais frequentes s&atilde;o por estafilococos (9%) e por coliformes (11%). Este trabalho objetivou avaliar as condi&ccedil;&otilde;es higi&ecirc;nico-sanit&aacute;rias das ind&uacute;strias de sorvetes de Governador Valadares-MG. Das nove f&aacute;bricas de sorvetes registradas na Vigil&acirc;ncia Sanit&aacute;ria municipal, oito delas aceitaram participar do trabalho se submetendo &agrave; avalia&ccedil;&atilde;o. Todas as ind&uacute;strias foram inesperadamente inspecionadas, sendo verificados os 149 itens constantes na lista de verifica&ccedil;&atilde;o adaptada, constru&iacute;da a partir da Resolu&ccedil;&atilde;o 275/2002 da ANVISA. O controle e garantia da qualidade se mostraram bastantes insatisfat&oacute;rios com valores de ad', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/867', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c814', 'Conservação dos frutos do umbuzeiro em três de maturação e sob duas temperaturas de refrigeração', 'Santos, Adriana; Vieira, Maria Marlene; Bezerra, Júlia; Medeiros, Lorena; Venceslau, Welida', 'Editora Verde', 'Agriculture', 'Agriculture', 'O umbuzeiro (Spondias tuberosa ssp.) &eacute; uma planta t&iacute;pica do sert&atilde;o e do agreste destaca-se por possuir diversos mecanismos contra a falta de &aacute;gua, como &agrave;s ra&iacute;zes modificadas, os xilop&oacute;dios. Entretanto, durante o per&iacute;odo de m&aacute;xima produ&ccedil;&atilde;o, existe uma grande perda do produto devido &agrave; falta de uma infra-estrutura adequada. O trabalho teve como objetivo avaliar a conserva&ccedil;&atilde;o de frutos g&ecirc;nero Spondias: umbu (Spondias tuberosa ssp.) na regi&atilde;o do semi&aacute;rido da Para&iacute;ba, durante o per&iacute;odo p&oacute;s-colheita, sob duas temperaturas de armazenamento, em tr&ecirc;s est&aacute;dios de matura&ccedil;&atilde;o. Foram considerados os seguintes est&aacute;dios de matura&ccedil;&atilde;o para os frutos de umbuzeiro avaliados: est&aacute;dio I &ndash; frutos com quebra da colora&ccedil;&atilde;o verde - Breacker (B); est&aacute;dio II &ndash; frutos com in&iacute;cio da pigm', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/887', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c81b', 'Determinação da oxidação da gordura em fritura industrial', 'TAGUCHI, Cristina M.; DINIZ, Carlos A. A.; VILELA, Anderson F.; NETO, Erasto F. A.; SANTOS, Jeffrey T. L. A.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Atualmente o consumo de alimentos fritos e pr&eacute;-fritos implica em maior ingest&atilde;o de &oacute;leos e gorduras submetidos a elevadas temperaturas. O processo de fritura desenvolve caracter&iacute;sticas de odor, sabor, cor e textura, tornando os alimentos mais atraentes para o consumo, al&eacute;m da praticidade de preparo. Dessa forma, com o aquecimento do lip&iacute;deo durante a fritura podem ocorrer modifica&ccedil;&otilde;es nas qualidades funcionais, sensoriais e nutricionais do alimento e do pr&oacute;prio lip&iacute;deo. &Agrave; medida que a fritura acontece a gordura ou &oacute;leo de fritura vai se tornando cada vez mais alterada at&eacute; que chega ao ponto de n&atilde;o poder ser mais usada, mas infelizmente n&atilde;o existe nenhum par&acirc;metro cient&iacute;fico que indica esse momento. A partir desse momento o lip&iacute;deo deve ser descartado e um lip&iacute;deo novo deve ser usado. Neste contexto este trabalho objetivou determinar a qualidade da gordura ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/899', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c81c', 'Desenvolvimento de tecnologia para bolo na caneca enriquecido com farinha da casca de banana verde', 'B. SILVA Jr., Joselito; O. S. DANTAS, José; W. B. MELO, Calionara; S. BRITO, Mariany; T. S. MATIAS, Mikaella', 'Editora Verde', 'Agriculture', 'Agriculture', 'Se tratando do aproveitamento da banana, j&aacute; se encontra no mercado produtos resultantes do aproveitamento da banana, como a farinha da casca, que permiti tamb&eacute;m o uso das frutas rejeitadas para a venda in natura. O consumo da farinha da casca da banana verde ainda &eacute; pouco difundido, pois se trata de uma nova tecnologia empregada &agrave; banana. A produ&ccedil;&atilde;o do bolo na caneca representa um novo h&aacute;bito de consumo devido &agrave; facilidade e praticidade em prepar&aacute;-lo. O objetivo do presente estudo foi o desenvolvimento de um alimento alternativo de alto valor nutricional e de preparo acess&iacute;vel. O material utilizado na realiza&ccedil;&atilde;o desse trabalho foi &agrave; casca de banana verde, onde foram lavadas e desinfetadas para se eliminar as sujidades que se encontravam na superf&iacute;cie da casca, posteriormente enxaguadas, depois colocadas no secador e trituradas para a produ&ccedil;&atilde;o da farinha. Os ingredientes utili', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/900', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c81f', 'Avaliação físico-química de lasanha de carne de rã-touro (Rana catesbeiana) em duas formulações', 'A. M. da FRANCA, David; S. AUGOSTINHO, Ana Kellis; da S. NASCIMENTO, Flávia; F. da SILVA, Mônica Ranchelle; de FIGUEIREDO, Maria José', 'Editora Verde', 'Agriculture', 'Agriculture', 'O consumo de r&atilde;, apesar de ainda ser restrito, vem ganhando adeptos a cada dia. Considerada como ex&oacute;tica, sua carne possui sabor requintado e textura agrad&aacute;vel, al&eacute;m de representar uma fonte de prote&iacute;na de alto valor biol&oacute;gico. Lasanha &eacute; um prato feito com camadas alternadas de massa, queijo, carnes e algum tipo de molho, existindo diversos sabores comercializados em restaurantes e supermercados na forma industrializada. O sabor da lasanha, e at&eacute; mesmo o seu t&iacute;tulo, &eacute; definido de acordo com o tipo de carne utilizada na formula&ccedil;&atilde;o. O objetivo deste trabalho foi analisar a f&iacute;sico-qu&iacute;mica de lasanhas elaboradas com carne de r&atilde; em duas formula&ccedil;&otilde;es. Levando-se em considera&ccedil;&atilde;o o conceito funcional da carne de r&atilde;, procurou-se elaborar formula&ccedil;&otilde;es de lasanhas com teores reduzidos de colesterol. Al&eacute;m da carne de r&atilde;, utilizou-se t', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/903', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c826', 'Análise de parâmetros físico-químicos do leite produzido em uma granja leiteira de Bananeiras-PB', 'A. QUEIROZ, Charllie''s; M. S. SILVA, João; B. MEIRELES, Severina; D. S. ARAÚJO, Lady; P. SANTOS, Esmeralda', 'Editora Verde', 'Agriculture', 'Agriculture', 'A tecnologia do leite e derivados fundamenta-se no estudo da produ&ccedil;&atilde;o, composi&ccedil;&atilde;o e qualidade da mat&eacute;ria-prima, sendo essenciais e importantes os par&acirc;metros f&iacute;sico-qu&iacute;micos do leite para os crit&eacute;rios tecnol&oacute;gicos na fabrica&ccedil;&atilde;o dos derivados, pois estes influenciam no rendimento, caracter&iacute;sticas sensoriais e qualidades nutritivas dos produtos. A realiza&ccedil;&atilde;o das an&aacute;lises de rotina e/ou de plataforma &eacute; imprescind&iacute;vel para determinar a qualidade f&iacute;sico-qu&iacute;mica do leite. O objetivo deste trabalho foi avaliar os par&acirc;metros f&iacute;sico-qu&iacute;micos do leite bovino produzido em uma granja leiteira localizada no munic&iacute;pio de Bananeiras-PB. As an&aacute;lises f&iacute;sico-qu&iacute;micas foram conduzidas no Laborat&oacute;rio de Controle de Qualidade de Alimentos (LCQA) pertencente ao Centro de Ci&ecirc;ncias Humanas, Sociais e Agr&aacute;ri', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/910', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c827', 'Farinha de Maracujá: Caracterização da Qualidade Físico-química para uso como Ingrediente Funcional', 'De Almeida BEZERRA, Roberto Robson; Tejo CAVALCANTI, Mônica; Leandro da SILVA, André; Ferreira SULINO, Reginaldo; C. B. Chinelate, Gerla', 'Editora Verde', 'Agriculture', 'Agriculture', '&Eacute; cada vez maior o uso de produtos naturais pela popula&ccedil;&atilde;o em geral. Apesar de diversos estudos, muitos produtos ainda possuem seu uso e suas poss&iacute;veis indica&ccedil;&otilde;es terap&ecirc;uticas baseado no conhecimento popular. No caso do maracuj&aacute;, h&aacute; muito tempo suas propriedades sedativas j&aacute; s&atilde;o conhecidas, especialmente quando utilizadas as infus&otilde;es ou tinturas das folhas do maracujazeiro. Recentemente foi descrita uma nova propriedade relacionada ao fruto: a atividade hipoglicemiante da farinha produzida a partir de sua casca, por&ccedil;&atilde;o rica em pectina, uma fra&ccedil;&atilde;o de fibra sol&uacute;vel que, quando hidratada, regula respostas metab&oacute;licas na redu&ccedil;&atilde;o de absor&ccedil;&atilde;o de nutrientes, como glic&iacute;dios e lip&iacute;dios, devido &agrave; forma&ccedil;&atilde;o de uma camada gelatinosa na mucosa intestinal, mecanismo que pode explicar sua a&ccedil;&atilde;o hipoglice', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/911', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c828', 'Farinha de Banana Verde: Caracterização Físico-química para uso como Ingrediente Funcional', 'Bezerra da COSTA, Franciscleudo; De Almeida BEZERRA, Roberto Robson; C. B. CHINELATE, Gerla; Leandro da SILVA, André; Ferreira SULINO, Reginaldo', 'Editora Verde', 'Agriculture', 'Agriculture', 'A banana &eacute; uma das frutas mais consumidas no mundo, sendo produzida na maioria dos pa&iacute;ses tropicais, representa a quarta fonte de energia depois do milho, arroz e trigo. Sua alta concentra&ccedil;&atilde;o de amido a partir do processamento em farinha &eacute; de interesse como fonte alimentar e prop&oacute;sito industrial. Em pa&iacute;ses como o Brasil e a Venezuela, onde se consome muito trigo importado, este pode ser mesclado com outros cereais e vegetais com alto conte&uacute;do de amido como fontes de nutrientes com menos custos. A banana possui vari&aacute;vel fonte de minerais, sendo um importante componente na alimenta&ccedil;&atilde;o em todo o mundo. Seu sabor &eacute; um dos mais importantes atributos de qualidade, a polpa verde &eacute; caracterizada por uma forte adstring&ecirc;ncia determinada pela presen&ccedil;a de compostos fen&oacute;licos sol&uacute;veis, principalmente taninos. &Agrave; medida que a banana amadurece, ocorre polimeriza&ccedil;&atilde;o', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/912', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c82a', 'Caracterização físico-química de queijos de coalho produzidos e comercializados no Sertão paraibano', 'C. MEDEIROS, Katianne; F. S. NETO, João; dos S. N. de MELO, Fernanda; S. MARTINS, Simone; dos S. ARAÚJO, Alfredina', 'Editora Verde', 'Agriculture', 'Agriculture', 'O leite &eacute; um alimento rico em nutrientes, do mesmo modo s&atilde;o os produtos feitos a partir dele, sendo assim bastante consumidos. Dentre estes, est&aacute; o queijo de coalho que &eacute; muito popular principalmente na regi&atilde;o Nordeste do Brasil. A atividade de produ&ccedil;&atilde;o do queijo de coalho &eacute; exercida principalmente por pequenos produtores estabelecidos na zona rural, significando sua principal fonte de renda. Por&eacute;m a falta de crit&eacute;rios de qualidade da mat&eacute;ria-prima e das t&eacute;cnicas de processamento permite que atinjam o mercado produtos de baixa qualidade com falta de padroniza&ccedil;&atilde;o do produto.&nbsp;Diante do exposto, objetivou-se neste trabalho caracterizar o queijo de coalho produzido e comercializado no Sert&atilde;o paraibano. Foram coletadas amostras de queijos de coalho em quatro queijeiras diferentes, com cinco repeti&ccedil;&otilde;es cada e encaminhadas sobre refrigera&ccedil;&atilde;o ao Laborat&oacu', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/914', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c82d', 'Caracterização físico-química da amêndoa da manga Tommy Atkins', 'V. DEODATO, José Nildo; A. S. SILVA, Geraildo; dos S. ARAÚJO, Alfredina; B. M. ALMEIDA, Maria Climene; Tejo CAVALCANTI, Mônica', 'Editora Verde', 'Agriculture', 'Agriculture', 'A manga (Mangifera indica L.) pertence &agrave; fam&iacute;lia Anacardiaceae, &eacute; uma fruta com grande quantidade de polpa, de tamanho e formato vari&aacute;vel, aroma e cor agrad&aacute;vel que faz parte do elenco das frutas tropicais de grande import&acirc;ncia econ&ocirc;mica. Descrita como um fruto de drupa carnosa, achatado lateralmente, com varia&ccedil;&otilde;es conforme a variedade a qual influencia no tamanho, forma, colora&ccedil;&atilde;o, presen&ccedil;a de fibras, aroma e sabor da manga. &Eacute; constitu&iacute;da por casca (exocarpo), polpa comest&iacute;vel (mesocarpo) e caro&ccedil;o (endocarpo), com fibras mais ou menos abundantes que se adentram no mesmo caro&ccedil;o e na polpa. A casca &eacute; lisa, pode ser de cor vari&aacute;vel verde ao amarelo, ao alaranjado e ao vermelho em algumas variedades, sendo mais marcada a altera&ccedil;&atilde;o para vermelho no lado exposto ao sol. A agroind&uacute;stria da manga &eacute; uma atividade em expans&atilde;o e pro', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/917', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c82e', 'Avaliação físico-química de polpa e creme de açaí comercializado na cidade de Campina Grande-PB', 'P. da SILVA, Poliana; T. ROCHA, Ana Paula; S. SILVA, Gabriela; C. M. dos SANTOS, Jacyelli; T. de ARAÚJO, Gilmar', 'Editora Verde', 'Agriculture', 'Agriculture', 'O a&ccedil;aizeiro (Euterpe oleracea Mart.) &eacute; uma palmeira tropical nativa da Amaz&ocirc;nia. Seus frutos s&atilde;o utilizados na produ&ccedil;&atilde;o da polpa de a&ccedil;a&iacute;, um alimento muito consumido pelas popula&ccedil;&otilde;es regionais, principalmente, do Par&aacute;, Amazonas, Maranh&atilde;o e Amap&aacute;. O objetivo deste trabalho foi avaliar e comparar a qualidade f&iacute;sico-qu&iacute;mica de polpa e creme de a&ccedil;a&iacute; comercializado na cidade de Campina Grande-PB. Foram realizadas an&aacute;lises f&iacute;sico-qu&iacute;micas de duas marcas comerciais distintas (A e B) de polpa de a&ccedil;a&iacute; e apenas uma marca de creme de a&ccedil;a&iacute;. As an&aacute;lises realizadas foram: pH, s&oacute;lidos sol&uacute;veis em &ordm;Brix, atividade de &aacute;gua, acidez, cinzas, cor (L*, a*, b*), a&ccedil;&uacute;car redutor, a&ccedil;&uacute;car n&atilde;o redutor e a&ccedil;&uacute;cares totais, com triplicata em cada par&acirc;metro para a ob', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/918', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c830', 'Avaliação microbiológica de farinha de sementes de jaca (Artocarpus heterophyllus)', 'RODRIGUES, Maria do S. A.; ARAÚJO, Alfredina dos S.; PEREIRA, Karla D.; ARAÚJO, Magno de S.; DEODATO, José N.V.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O fruto da jaqueira &eacute; muito popular nas regi&otilde;es tropicais do mundo e um volume expressivo de subprodutos como cascas e sementes est&atilde;o dispon&iacute;veis como res&iacute;duos. Suas sementes s&atilde;o ricas em nutrientes tais como prote&iacute;nas, fibras e sais minerais, podendo ser utilizadas como alimento, minimizando a polui&ccedil;&atilde;o ambiental, j&aacute; que esses res&iacute;duos conduzem a s&eacute;rio problema quanto &agrave; sua elimina&ccedil;&atilde;o. Farinha &eacute; o produto obtido atrav&eacute;s de moagem da parte comest&iacute;vel de vegetais. A farinha de sementes de jaca pode ser aproveitada na alimenta&ccedil;&atilde;o como ingrediente de &ldquo;multimisturas&rdquo;, como tamb&eacute;m na suplementa&ccedil;&atilde;o de produtos como p&atilde;es, biscoitos e bolos. Este trabalho teve como objetivo elaborar farinha com sementes de jaca e investigar a sua microbiologia. Produziu-se a farinha secando-se as sementes em secador de bandeja com ven', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/920', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c833', 'Avaliação físico-química de doce artesanal de mamão com banana com diferentes concentrações de açúcar', 'C. M. SILVA, Karla; P. M. OLIVEIRA, Janine; Tejo CAVALCANTI, Mônica; B. COSTA, Franciscleudo; Ferreira SULINO, Reginaldo', 'Editora Verde', 'Agriculture', 'Agriculture', 'A ind&uacute;stria aliment&iacute;cia vem buscando a melhoria de processos objetivando a produ&ccedil;&atilde;o de alimentos com qualidade para garantir sua perman&ecirc;ncia no mercado. O mam&atilde;o &eacute; fonte de carboidratos, vitaminas (principalmente C e A), fibra, pot&aacute;ssio e pequenas quantidades de prote&iacute;nas, gorduras, c&aacute;lcio e s&oacute;dio, al&eacute;m de fornecer cor, sabor, aroma e textura para a dieta humana. A banana &eacute; consumida em sua quase totalidade na forma in natura, por popula&ccedil;&otilde;es de alta e baixa renda, em virtude do alto valor nutritivo e baixo custo e diversos s&atilde;o os produtos que podem ser obtidos da banana: polpa ou pur&ecirc;, n&eacute;ctar, fruta em calda, produtos desidratados (banana liofilizada, flocos e fruta na forma de passa) e doces diversos, incluindo gel&eacute;ias e doce de massa (bananada). Segundo a legisla&ccedil;&atilde;o brasileira vigente, &ldquo;doce de fruta em calda&rdquo; &eacute; definido co', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/925', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c834', 'Análise do teor de pigmentos e fenólicos do camapú (physalis angulata L.)', 'F. LOPES, Maíra; L. de MEDEIROS, Lorena; dos S. PEREIRA, Tamires; I. N. MOREIRA, Flávia; M. V. FERNANDES, Ítala', 'Editora Verde', 'Agriculture', 'Agriculture', 'O g&ecirc;nero Physalis L. &eacute; uma planta considerada arbustiva, abundante e r&uacute;stica, seu fruto apresenta-se na forma de uma baga carnosa, em forma de globo, com di&acirc;metro que varia entre 1,25 e 2,50 cm e peso entre 4 e 10 g. A busca por novos insumos provenientes de vegetais superiores &eacute; ampla, e tende em vista os seguintes par&acirc;metros: efic&aacute;cia, seguran&ccedil;a e qualidade. No pa&iacute;s, se procura incrementar as pesquisas cient&iacute;ficas com plantas, em especial aquelas de origem end&oacute;gena, como no caso da Physalis angulata L. No Brasil, o fruto &eacute; consumido como produto fino, com alto valor agregado, e est&aacute; sendo incorporado nos cultivos de pequenas frutas. Assim, o prop&oacute;sito deste estudo foi avaliar os pigmentos e compostos fen&oacute;licos do fruto de Physalis angulata L visando fornecer fundamentos para a elabora&ccedil;&atilde;o de produtos aliment&iacute;cios &agrave; base deste fruto. O experimento foi conduz', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/926', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c838', 'Caracterização física e físico-química de Canavalia ensiformis L.', 'F. LOPES, Maíra; F.dos SANTOS, Adriana; I. N. MOREIRA, Flávia; M. V. FERNANDES, Ítala; S. PEREIRA, Tamires', 'Editora Verde', 'Agriculture', 'Agriculture', 'A Canavalia ensiformis L, conehcida popularmente como feij&atilde;o-de-porco, &eacute; uma leguminosa origin&aacute;ria das regi&otilde;es ocidentais da &Iacute;ndia, de ciclo anual, herb&aacute;cea, erecta e suas estruturas variam de 75 a 85 cm ao atingir a matura&ccedil;&atilde;o, os legumes maduros medem de 25 a 35 cm de comprimento por 3 cm de largura e cont&ecirc;m cerca de 10 a 15 sementes. N&atilde;o h&aacute; registro sobre o uso desta leguminosa quer na alimenta&ccedil;&atilde;o humana ou animal no Brasil, mas, segundo alguns autores, esta &eacute; apreciada na forma de legume verde no Ceil&atilde;o, &Iacute;ndia e Jap&atilde;o. Suas folhas s&atilde;o usadas como verdura, e as sementes s&atilde;o cozidas como feij&atilde;o, embora tenham que passar por tratamento pr&eacute;vio para eliminar as v&aacute;rias toxinas que possuem. As amostras foram colhidas manualmente no munic&iacute;pio de Paulista-PB ap&oacute;s maduros. O experimento foi realizado no Laborat&oacute;rio de An&', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/930', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c842', 'Condições higiênico-sanitárias de alimentos comercializados por ambulantes no município de Coronel Fabriciano-MG', 'SILVA, Kívia A. G.; MORAIS, Ana C. A.; VILELA, Anderson F.; MOREIRA, Diego A. S.; Santos, Suelene H. G.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O comportamento alimentar da sociedade sofreu grandes mudan&ccedil;as nos &uacute;ltimos anos devido &agrave;s transforma&ccedil;&otilde;es econ&ocirc;micas, sociais e culturais. O pouco tempo e as grandes jornadas de trabalho faz com que as pessoas realizem suas refei&ccedil;&otilde;es cada vez mais fora do lar, &agrave; jornada de trabalho, o pouco tempo para realizar as refei&ccedil;&otilde;es, os recursos financeiros e locais pr&oacute;ximos aos locais de trabalho s&atilde;o fatores que influenciaram na forma&ccedil;&atilde;o de novas praticas alimentares da sociedade moderna. Os estabelecimentos de alimenta&ccedil;&atilde;o como ambulantes e trailers s&atilde;o uma op&ccedil;&atilde;o para a popula&ccedil;&atilde;o em geral uma vez que produzem lanches r&aacute;pidos e baratos. Devido ao aumento do consumo de lanches r&aacute;pidos, propagou-se na sociedade a presen&ccedil;a de comerciantes, principalmente informais, que preparam e comercializam alimentos como cachorros-quentes, s', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/940', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c843', 'Qualidade microbiológica de leite pasteurizado tipo B comercializado na cidade de João Pessoa – PB', 'MARQUES, Gilmardes N. MARQUES; PEIXOTO, Érika T.; MELO, Adma N. F.; GOMES, Isrrael F. A.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O leite &eacute; o produto oriundo da ordenha de vacas sadias, bem alimentadas, descansadas; em condi&ccedil;&otilde;es adequadas de higiene. &Eacute; um dos alimentos mais completos, devido ao alto teor de prote&iacute;nas, carboidratos, &aacute;cidos graxos, sais minerais, vitaminas e &aacute;gua; sendo facilmente contaminado por muitos microrganismos que encontram condi&ccedil;&otilde;es favor&aacute;veis de multiplica&ccedil;&atilde;o. Por ser considerado o mais nobre dos alimentos &eacute; indispens&aacute;vel para a alimenta&ccedil;&atilde;o de todas as faixas et&aacute;rias. Desde a obten&ccedil;&atilde;o at&eacute; a industrializa&ccedil;&atilde;o, devido a manipula&ccedil;&otilde;es err&ocirc;neas exp&otilde;e-se o leite a diversas contamina&ccedil;&otilde;es, as quais diminuem a vida &uacute;til do produto e/ou oferece riscos &agrave; sa&uacute;de p&uacute;blica. Portanto para redu&ccedil;&atilde;o da carga microbiana do leite se faz o processo de pasteuriza&ccedil;&atilde;o,', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/941', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c848', 'Análise microbiológica de água de bebedouros das escolas da cidade de Pombal - PB', 'CÂNDIDO, Ana F. de M.; MELO, Fernanda dos S. N.; ARAÚJO, Alfredina dos S.; PEREIRA, Karla D.; ARAÚJO, Magno S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A &aacute;gua &eacute; uma subst&acirc;ncia inorg&acirc;nica de fundamental import&acirc;ncia para os seres vivos, quer &nbsp;seja nas rea&ccedil;&otilde;es qu&iacute;micas biol&oacute;gicas ou na higiene dos alimentos. &Eacute; o constituinte mais abundante da mat&eacute;ria viva, cerca de 75% da constitui&ccedil;&atilde;o, tornando-se assim ve&iacute;culo de transporte e interc&acirc;mbio das subst&acirc;ncias intra e extracelular. A atividade humana gera res&iacute;duos que em contato com o meio ambiente proporciona efeitos indesej&aacute;veis e negativos aos seres vivos. A contamina&ccedil;&atilde;o da &aacute;gua pode se d&aacute; em fun&ccedil;&atilde;o da falta de rede de esgoto, da manuten&ccedil;&atilde;o inadequada dos reservat&oacute;rios, agrot&oacute;xicos e aterros sanit&aacute;rios, que contaminam os len&ccedil;&oacute;is fre&aacute;ticos, tornando-se assim um eficiente meio transmissor de doen&ccedil;as. Em raz&atilde;o dessas evid&ecirc;ncias que envolvem a sa&uacute;d', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/946', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c84d', 'Análise sensorial de manga Tommy Atkins com o uso de biofilmes comestíveis', 'COSTA, Eliane S.; SANTOS, Adriana F.; SILVA, Fernanda Vanessa G.; VIEIRA, Maria Marlene S.; BEZERRA, Júlia M.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A manga Tommy Atkins &eacute; a mais produzida pela sua boa aceita&ccedil;&atilde;o no mercado nacional e internacional, sendo tamb&eacute;m uma variedade muito produtiva. O uso de f&eacute;cula de mandioca como mat&eacute;ria-prima adequada para a elabora&ccedil;&atilde;o de biofilmes comest&iacute;veis proporciona bom aspecto e brilho intenso, tornando os frutos e as hortali&ccedil;as comercialmente mais atrativos devido &agrave; forma&ccedil;&atilde;o de pel&iacute;culas resistentes e transparentes e a efici&ecirc;ncia como barreiras &agrave; perda de &aacute;gua. Os testes sensoriais fazem parte do controle da qualidade de um produto por ser uma medida multidimensional integrada com in&uacute;meras vantagens, entre as quais a possibilidade de determinar a aceita&ccedil;&atilde;o de um produto por parte dos consumidores. O objetivo deste trabalho foi avaliar a aceita&ccedil;&atilde;o sensorial de manga Tommy Atkins produzido pelo sistema de produ&ccedil;&atilde;o convencional durant', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/953', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c850', 'Preferência e intenção de consumo de ambrosias preparadas com diferentes produtos com poder adoçante', 'PINHEIRO, Wyvya B. F.; LOPES, Maíra F.; BESERRA, Gardênia A.; SULINO, Reginaldo F.; FERREIRA, Angra C. N.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A ambrosia &eacute; um tipo de doce de leite comercializado em feiras livres e muito consumido no Brasil. Sua formula&ccedil;&atilde;o &eacute; artesanal e tem como ingredientes principais leite, ovos e a&ccedil;&uacute;car. Os testes afetivos em fun&ccedil;&atilde;o do local de aplica&ccedil;&atilde;o podem ser de laborat&oacute;rio, localiza&ccedil;&atilde;o central e uso dom&eacute;stico. Basicamente, os testes afetivos podem ser classificados em duas categorias: de prefer&ecirc;ncia e de aceita&ccedil;&atilde;o. Neste contexto, o presente trabalho teve por objetivo verificar a inten&ccedil;&atilde;o de consumo de diferentes tipos de doces de leite, conhecidos por ambrosia. Os doces foram elaborados com leite, ovos, cravos e diferentes produtos com poder ado&ccedil;ante, sendo o da amostra A a sacarose, da amostra B o leite condensado e da amostra C a rapadura. Os testes sensoriais empregados foram quanto &agrave; prefer&ecirc;ncia, atitude de consumo e ideal de do&ccedil;ura. Os te', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/956', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c851', 'Perfil sensorial de melão rendilhado osmoticamente desidratado', 'LOPES, Maíra F.; SANTOS, Adriana F.; MEDEIROS, Lorena L.; OLIVEIRA, Kelly Jullyanny A.; FERREIRA, Wallber C.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O mel&atilde;o (Cucumis melo L.) &eacute; uma fruta de popularidade ascendente no mundo. Apesar de ser considerado um produto de elevado valor comercial e ser muito apreciado por suas caracter&iacute;sticas sensoriais, apresenta uma vida p&oacute;s-colheita relativamente curta quando em temperatura ambiente, o que tem contribu&iacute;do para o elevado &iacute;ndice de desperd&iacute;cio e dificultado sua comercializa&ccedil;&atilde;o nos mercados distantes dos centros de produ&ccedil;&atilde;o. A desidrata&ccedil;&atilde;o osm&oacute;tica permite tanto a remo&ccedil;&atilde;o de &aacute;gua do produto quanto &agrave; modifica&ccedil;&atilde;o de suas propriedades pela impregna&ccedil;&atilde;o de solutos desejados. O presente trabalho teve como objetivo avaliar caracter&iacute;sticas sensoriais de mel&atilde;o desidratado osmoticamente. O trabalho foi desenvolvido no Laborat&oacute;rio de Tecnologia de Produtos Hort&iacute;colas da UATA, UFCG em Pombal &ndash; PB. Os mel&otilde;es fora', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/957', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c854', 'Efeito de diferentes condimentos na aceitação sensorial de pasta de alho', 'XAVIER, Leidiana E.; LIMA, Anderson F.; LOPES, Maíra F.; SANTANA, Andressa G.; FONTES, Sabrina M.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O consumo de molhos sempre foi significativo na mesa dos brasileiros. A pasta de alho &eacute; um desses tipos de molhos. Como o pr&oacute;prio nome descreve, o alho &eacute; a hortali&ccedil;a primordial desse produto. Este trabalho teve por objetivo avaliar sensorialmente tr&ecirc;s tipos de pasta de alho condimentada. De in&iacute;cio, fez-se o descascamento do alho e a lavagem. A mat&eacute;ria-prima (dentes de alho in natura) foi descascada com o aux&iacute;lio de facas e triturada em liquidificador. Houve a adi&ccedil;&atilde;o dos demais ingredientes leite, &oacute;leo, sal e condimentos espec&iacute;ficos para a obten&ccedil;&atilde;o da pasta. Os temperos escolhidos para diferenciar as pastas de alho foram o or&eacute;gano (Origanum vulgare) e a c&uacute;rcuma (Curcuma longa), fazendo com que as pastas fossem divididas em amostras: PPA1 (pasta de alho com or&eacute;gano), PPA2 (pasta de alho com c&uacute;rcuma) e PPA3 (pasta de alho com or&eacute;gano e c&uacute;rcuma). Tais t', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/960', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c855', 'Aceitação sensorial de cookies adicionados de farinha do albedo de maracujá', 'MARTINS, Wiaslan F.; ARAUJO, Alfredina S.; MELO, Fernanda S. N.; PEREIRA, Karla D.; CAVALCANTI, Mônica T.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O maracuj&aacute;, por ser um fruto de clima tropical, tem distribui&ccedil;&atilde;o por todo pa&iacute;s e sua utiliza&ccedil;&atilde;o para a produ&ccedil;&atilde;o de suco resulta em grande quantidade de res&iacute;duos, uma vez que cerca de 60 a 70% do peso total do fruto s&atilde;o representados por casca, albedo e sementes. Gra&ccedil;as ao teor de fibras bruta encontrado no albedo do maracuj&aacute;, pode-se sugerir sua utiliza&ccedil;&atilde;o como farinha ou incorporada a outros produtos direcionados para pessoas que necessitam aumentar a ingest&atilde;o de fibras. Os biscoitos s&atilde;o produtos bastante consumidos no Brasil, sendo o segundo maior mercado consumidor mundial. O objetivo deste trabalho foi elaborar a farinha do albedo do maracuj&aacute; de res&iacute;duo de uma ind&uacute;stria de polpa de fruta da cidade de Pombal-PB, adicionar como ingrediente e avaliar sensorialmente o produto. A farinha do maracuj&aacute; foi obtida atrav&eacute;s de secagem em estufa a 7', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/961', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c856', 'Análise Sensorial: Macarrão elaborado com farinha de arroz integral', 'Araújo, Janaína F. P.; Nascimento, Veridiana F.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Com a moderniza&ccedil;&atilde;o da ind&uacute;stria de alimentos, e visando atender &agrave;s necessidades de todos os consumidores, o macarr&atilde;o elaborado com farinha de arroz integral surge como alternativa para atender &agrave;s necessidades de pessoas com intoler&acirc;ncia alimentar ao gl&uacute;ten ou que realizam algum tipo de dieta espec&iacute;fica. Portanto, foi pensando por esse segmento, que foi elaborada a massa de macarr&atilde;o caseira, na cidade de Jo&atilde;o pessoa com o intuito de obter aproveitamento global e conhecimento do produto, determinar quais par&acirc;metros est&atilde;o envolvidos durante a formula&ccedil;&atilde;o para que ocorra uma padroniza&ccedil;&atilde;o do produto e analisar sensorialmente o produto, pois &eacute; de grande import&acirc;ncia avaliar a aceitabilidade mercadol&oacute;gica e a qualidade do produto, sendo parte inerente ao plano de controle de qualidade do produto. A an&aacute;lise sensorial foi feita por meio dos &oacute;rg&ati', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/962', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c858', 'Diagnóstico do local de preparo da alimentação escolar na zona urbana do município de Solânea-PB', 'Silva, Andre; Menezes, Keliana; Costa, Jaqueline; Ataíde, Celene; Figueiredo, Maria J.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Uma vez que a qualidade do alimento est&aacute; inteiramente relacionada &agrave;s condi&ccedil;&otilde;es higi&ecirc;nico-sanit&aacute;rias, o objetivo deste trabalho foi realizar o diagn&oacute;stico dos locais de preparo da alimenta&ccedil;&atilde;o escolar na Zona urbana do munic&iacute;pio de Sol&acirc;nea-PB, &nbsp;por meio da aplica&ccedil;&atilde;o de um check list baseado na Resolu&ccedil;&atilde;o RDC 275 da ANVISA. Com rela&ccedil;&atilde;o &agrave;s edifica&ccedil;&otilde;es e instala&ccedil;&otilde;es verificou-se a presen&ccedil;a de objetos estranhos ao ambiente (100%), inexist&ecirc;ncia de &acirc;ngulos abaulados entre paredes e teto (100%), a falta de lavat&oacute;rios de uso exclusivo (100%) e de instala&ccedil;&otilde;es sanit&aacute;rias para os manipuladores (90,9%), enquanto 63,6% das escolas n&atilde;o apresentaram separa&ccedil;&atilde;o estrutural entre zonas de prepara&ccedil;&atilde;o de alimentos. A ilumina&ccedil;&atilde;o encontrou-se adequada em 100% das', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/964', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c85e', 'Estudo da produção de aguardente de laranja em escala laboratorial.', 'Vilela, Anderson; Morais, Ana; Assis Neto, Erasto; Silva, Kívia; Baracho, Rafael', 'Editora Verde', 'Agriculture', 'Agriculture', 'O processo de produ&ccedil;&atilde;o dos derivados da cana-de-a&ccedil;&uacute;car &eacute; determinado pela sazonalidade dacolheita desta mat&eacute;ria-prima. Na entressafra os engenhos tornam-se improdutivos, ficando com toda infraestrutura e m&atilde;o-de-obra ociosa e poderiam ser aproveitados partindo-se de um novo ingrediente.O objetivo deste trabalho foi estudar a fermenta&ccedil;&atilde;o alco&oacute;lica do caldo de laranja e a destila&ccedil;&atilde;o do fermentado para produ&ccedil;&atilde;o de aguardente de laranja (Citrussinensis) com alternativa para o produtor de aguardente na entressafra ao mesmo tempo incorporando um novo produto ao portf&oacute;lio dos produtores. As amostras de laranja Perausadas foram selecionas, lavadas manualmente em &aacute;gua corrente de torneira, espremidas mecanicamente para extra&ccedil;&atilde;o do caldo que foi clarificado pelo uso de solu&ccedil;&atilde;o de gelatinasem sabor a 10% (5mL/L) e ent&atilde;o foifiltrado. Depois o caldo foi s', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/976', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c861', 'Desenvolvimento e aceitação de cocada enriquecida com o mesocarpo da melancia (Citrillus lanats var lanatus)', 'Leite, Clotildes; Araújo, Anna Cláudia; Vieira, Danise; Lima, Fabiano; Lisboa, Jemima', 'Editora Verde', 'Agriculture', 'Agriculture', 'A tecnologia de alimentos abrange uma s&eacute;rie de t&eacute;cnicas utilizadas para o aproveitamento integral dos alimentos, umas dessas t&eacute;cnicas &eacute; a produ&ccedil;&atilde;o de cocadas. A entrecasca da melancia &eacute; um subproduto rico em fibra alimentar insol&uacute;vel. Logo, o seu aproveitamento na elabora&ccedil;&atilde;o de produtos aliment&iacute;cios pode contribuir para o aumento dos teores de fibra insol&uacute;vel na dieta. Conhecendo-se os efeitos fisiol&oacute;gicos exercidos pelo mesocarpo da melancia e a crescente necessidade de se desenvolver tecnologias para o aproveitamento de subprodutos industriais, o objetivo do presente estudo foi desenvolver e avaliar a aceitabilidade de cocadas enriquecidas com e sem o mesocarpo da melancia. Os frutos de melancia encontravam-se no estado de matura&ccedil;&atilde;o adequado, o a&ccedil;&uacute;car foi adquirido observando-se o prazo de validade. As melancias foram higienizadas, sanitizadas, cortadas e as entrecas', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/982', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c869', 'Controle de Qualidade de Sorvetes com Farinha de Maracujá', 'OLIVEIRA, Cybelle Pereira de; CAVALCANTI, Mônica Tejo; BEZERRA, Roberto Robson De Almeida; da SILVA, André Leandro; CHINELATE, Gerla Castello Branco', 'Editora Verde', 'Agriculture', 'Agriculture', 'Segundo a Ag&ecirc;ncia Nacional de Vigil&acirc;ncia Sanit&aacute;ria, sorvete ou gelado comest&iacute;vel &eacute; "um produto aliment&iacute;cio obtido a partir de uma emuls&atilde;o de gordura e prote&iacute;nas, com ou sem adi&ccedil;&atilde;o de outros ingredientes e subst&acirc;ncias, ou de uma mistura de &aacute;gua, a&ccedil;&uacute;cares e outros ingredientes e subst&acirc;ncias que tenham sido submetidas ao congelamento, em condi&ccedil;&otilde;es tais que garantam a conserva&ccedil;&atilde;o do produto no estado congelado ou parcialmente congelado, durante a armazenagem, o transporte e a entrega ao consumo". Os sorvetes podem veicular microrganismos patog&ecirc;nicos por m&aacute; pasteuriza&ccedil;&atilde;o, contamina&ccedil;&atilde;o durante a elabora&ccedil;&atilde;o, armazenamento inadequado, distribui&ccedil;&atilde;o, mat&eacute;ria-prima contaminada e falta de higiene em m&aacute;quinas e utens&iacute;lios. O presente trabalho teve como objetivo analisar microbiologic', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/995', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff7d6a63682f044c86a', 'Avaliação das Boas Práticas de Fabricação (BPF’s) em panificadoras do estado da Paraíba', 'Silva, João Maria Soares da; SILVA, Edjailda G.; OLIVEIRA, Renan E. S.; SANTOS, Esmeralda P.; SALES, Fernanda A. S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A agroind&uacute;stria da panifica&ccedil;&atilde;o &eacute; um dos setores mais importantes para o segmento de processamento de alimentos no Brasil. O controle do processo e dos manipuladores s&atilde;o crit&eacute;rios que devem ser estabelecidos nas panificadoras. As Boas Pr&aacute;ticas de Fabrica&ccedil;&atilde;o (BPF&rsquo;s) s&atilde;o ferramentas necess&aacute;rias para o controle higi&ecirc;nico-sanit&aacute;rio nos estabelecimentos que manipulam alimentos. O objetivo deste trabalho foi avaliar as Boas Pr&aacute;ticas de Fabrica&ccedil;&atilde;o (BPF&rsquo;s) em panificadoras no estado da Para&iacute;ba. Aplicou-se o question&aacute;rio em 10 (dez) panificadoras localizadas nas cidades de Sum&eacute;, Sol&acirc;nea, Bananeiras e Areia, microrregi&otilde;es do Curimata&uacute; e Brejo Paraibano. O per&iacute;odo de aplica&ccedil;&atilde;o dos question&aacute;rios foi durante o m&ecirc;s de agosto de 2009. Aplicou-se question&aacute;rios estruturados avaliando-se os par&acirc;me', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/996', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c86d', 'A VIOLÊNCIA OBSTÉTRICA EM SUAS DIFERENTES FORMAS DE APRESENTAÇÃO NO CONTEXTO MATERNO-INFANTIL', 'Santos, Beatriz Azevedo de Almeida; Auzenir de Oliveira Abrantes Monteiro; Fernandes, Hellita do Nascimento; Oliveira, Kelly Bezerra de; Nóbrega, José Cândido da Silva; Oliveira, Deyse Janiele Bernard', 'Editora Verde', 'Agriculture', 'Agriculture', 'Sabe-se que o ciclo gravídico-puerperal é marcado por diversas transformações, sejam elas físicas, emocionais, psicológicas, sociais, o que resulta em um momento de extrema vulnerabilidade para a mulher. Dito isto, além de lidarem com essas manifestações inerentes ao processo de gestação, são constantemente impactadas por atos violentos no contexto da maternidade, configurando-se como violência obstétrica. 
O conceito de “violência obstétrica” ainda é debatido por vários estudiosos, o que dificulta estipular um significado para tal, sendo mais prevalente seu uso nos países latinos-americanos, tendo a Venezuela como pioneira na América Latina por considerar a violência obstétrica como ilegal (CARVALHO; BRITO, 2017) 
&nbsp;Nesse sentido, o termo é considerado relativamente novo, sendo a violência obstétrica um tema inicialmente debatido no ano 1950 nos Estados Unidos, através a partir da Ladies Home Journal, que publicou uma matéria intitulada de “Crueldades nas maternidades” que mencion', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/9194', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c86f', 'REFLEXOS DA VIOLÊNCIA INTRAFAMILIAR NO DESENVOLVIMENTO INFANTIL', 'Santos, Beatriz Azevedo de Almeida; Silva, Aline Cristina; Silva, Francisca Daiana Estrela; Oliveira, Kelly Bezerra de; Nóbrega, José Cândido da Silva; Oliveira, Deyse Janiele Bernardo; Monteiro, Auze', 'Editora Verde', 'Agriculture', 'Agriculture', 'Considerando que todo e qualquer ser humano desenvolve atitudes, condutas e comportamentos baseados na sua relação com as várias instâncias que o cerca, o meio familiar é um importante elemento contributivo no desenvolvimento infantil, uma vez que é no seio familiar que são constituídas as primeiras referências da criança, e onde, iniciam o processos como socialização, construção da identidade e formação de valores (REIS; PRATA; PARRA, 2018).&nbsp;
A influência que o âmbito familiar exerce sobre o desenvolvimento da criança é inegável, e quando esse contexto é permeado por eventos de violência as consequências são ainda mais severas, podendo ser evidenciadas através de problemas que afetarão diversas esferas da vida da criança, como prejuízos a saúde e nas relações familiares e sociais (BATISTA et al., 2013).
A violência intrafamiliar ou doméstica se constitui para além de atos de agressão física, sendo compreendido como um fenômeno mais complexo do que pensamos, com variadas consequên', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/9198', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c871', 'A VIOLAÇÃO DE DIREITOS NA ASSISTÊNCIA AS PERDAS GESTACIONAIS: REFLEXÕES SOBRE A VIOLÊNCIA OBSTÉTRICA', 'Santos, Beatriz Azevedo de Almeida; Fernandes, Hellita do Nascimento; Neves, Annelyse Esequiel de Lucena; Oliveira, Kelly Bezerra de; Nóbrega, José Cândido da Silva; Oliveira, Deyse Janiele Bernardo; ', 'Editora Verde', 'Agriculture', 'Agriculture', 'A perda gestacional é um evento que ocorre com certa frequência nos serviços obstétricos e segue sendo um desafio aos profissionais de saúde ligados à assistência materno-infantil, uma vez que a equipe não sente-se completamente segura e preparada para lidar com situações de luto e sentimentos advindos da perda (AOYAMA et al., 2018).
Dito isto, considerando o despreparo e a insegurança dos profissionais de saúde no manejo aos cuidados prestados às mulheres e seus familiares em situação de perda gestacional, estes acabam por gerar lacunas na assistência ou reproduzir práticas obsoletas e desrespeitosas (AMTHAUER et al., 2012).
No contexto da maternidade, práticas que caminham em desencontro com a humanização do parto e nascimento ou, ainda, violam os direitos da mulher em seu ciclo gravídico puerperal ou processo reprodutivo são caracterizadas como violência obstétrica.
A violência obstétrica é um fenômeno multifacetado, compreendido como todo ato ou omissão praticado por profissionais ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/9202', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c887', 'Atividade bactericida do extrato da própolis em animais domésticos', 'Araújo, Adjane Karla Cândido de; Silveira, Andressa Sampaio da; Gurjão, Thyago Araújo; Araújo, Fernanda Maria Pinto; Assys, Francisco de; Araújo, Péricles Estanislau Cordeiro de; Porto Filho, José Mat', 'Editora Verde', 'Agriculture', 'Agriculture', 'A própolis é um subproduto das abelhas coletada a partir de resinas de brotos de plantas. Tal substância, quando encontrada na natureza, tem como função atuar na vedação das colmeias a fim de proteger as abelhas de outros animais intrusos à colmeia, atuando como antisséptico nos alvéolos ou mesmo protegê-las do frio. A utilização da própolis na medicina humana e veterinária tem sido frequente, onde uso é mencionado há pelo menos 300 a.C, havendo, atualmente, relatos de que a própolis possui propriedades fitoterápicas com ação antioxidante, anti-inflamatória, antibiótica e antifúngica com obtenção de bons resultados. Quanto a sua ação bactericida podemos destacar o uso do extrato de própolis no tratamento da mastite bovina apresentando resultados superiores ou semelhantes aos dos antimicrobianos utilizados na terapia dessa enfermidade, os frangos que fizeram uso da própolis apresentaram melhores desempenhos dos 14 aos 21 dias de idade, no que tange aos caninos, o extrato de própolis obt', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10021', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c888', 'Qualificação físico-química de méis comercializados no sertão paraibano', 'Felix, Nayara; Pereira, Deborah Margarida', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10022', NULL, 'English', 'published', false, false, 'open', 'pdf')
