INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c889', 'Indução de práticas Agroecologicas na apicultura com a construção de um sistema Agroflorestal no município de Sumé-PB', 'Almeida Inô , Claudiney Felipe Almeida Inô; da Silva Trajano, Vitória Regina; Muniz da Silva , Karla Gabriele; Bezerra da Silva , José Vinícius; Vasconcelos, Viviane', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10023', NULL, 'English', 'published', false, false, 'open', 'pdf')
