INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c893', 'Utilização do extrato de própolis no tratamento coadjuvante de hiperadrenocorticismo de cães - revisão', 'Medeiros, Aline Carla de; Gurjão, Thyago Araújo; Lima , Dennis Fábio Silva; Henrique  Mascarenhas, Nágela Maria Henrique Mascarenhas; de Assys Romero da Mota Sousa, Francisco; da Costa, Rhayssa Vieira', 'Editora Verde', 'Agriculture', 'Agriculture', 'O mel é utilizado desde os tempos remotos para tratamento de feridas em humanos. Cirurgiões egípcios faziam aplicação do mel com gordura para feridas complicadas, crônicas e indolentes. Ele também é capaz de de promover a epitelização, estimular a angiogênese e a granulação de feridas. Seus derivados como o própolis possui fonte nutritiva e tem a capacidade de reduzir odores. Pode existir uma variação na atividade anti-inflamatória dependendo da planta e do processamento sofrido pelo mel. Deve-se ter uma preocupação na utilização do mel sem ser esterilizado pois ele não é recomendado para o tratamento de ferimentos.&nbsp; Somente o mel medicinal é recomendado para o uso em ferimentos.&nbsp; Um grande número de substâncias tem sido encontrado nas amostras de própolis: ceras, resinas, bálsamos, óleos aromáticos, pólen e outras substâncias orgânicas. a composição química da própolis é variável e dependente dos locais de coleta, diante disso apresenta diferenças nas composições, consequent', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10035', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c89a', 'O extrato da própolis e a saúde da próstata', 'Gurjão, Thyago Araújo; Fernandes, Vanessa Eulália Silva Bezerra; de Assys Romero da Mota Sousa, Francisco; Silva, Jamily Martins; sousa, Sara Barbosa; Ribeiro, Renata Elias; Silva, Eliza da Cruz; Masc', 'Editora Verde', 'Agriculture', 'Agriculture', 'Atenuando a sinergia entre a ciência farmacológica convencional e a busca de produtos naturais que ofereçam suporte ao tratamento de inúmeras patologias, pesquisas trazem resultados satisfatórios em relação ao uso do própolis, sendo uma substancia antioxidante, anti-inflamatória, antifúngica, antibacteriana e antitumoral,&nbsp; rica em&nbsp; e ácidos fenólicos, aldeídos, aldeídos fenólicos, cetonas, flavonoides e ésteres do ácido cafeico que são agentes atuantes com capacidade anti-inflamatória que atuam inibindo a produção de ácido araquidônico e por sequência a síntese de prostaglandinas tendo ainda atuação auxiliar na atividade fagocitária. Seu uso na rotina clínica veterinária é visto em diversas situações mediante sua capacidade antimicrobiana em casos onde há resistência, estudos em humanos revelam que o uso de diferentes tipos de própolis brasileiros apresentaram efeitos inibitórios sobre células cancerígenas de próstata, inibindo a fase S e G2 do ciclo celular, além da ativação', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10043', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c89c', 'Contaminação do mel, cuidados e controles - revisão', 'Medeiros, Aline Carla de; Nascimento Júnior, Aelson Alves; Gurjão, Thyago Araújo; Januário, Deborah Margarida Pereira; Henrique  Mascarenhas, Nágela Maria Henrique Mascarenhas; Fernandes, Vanessa Eulá', 'Editora Verde', 'Agriculture', 'Agriculture', 'A contaminação do mel ocorre por fontes primárias, sendo elas pó, ar, solo, néctar, pólen e o aparelho digestivo das abelhas, exemplos de contaminação antes da colheita. Já na contaminação secundária, depois da colheita, advém da contaminação cruzada, manipulação, instalações e equipamentos, também por presença de insetos, locais inapropriados pela incidência do vento entre outros. A contaminação química do mel está ligado ao tratamento das abelhas com fármacos, como os antibióticos que são utilizados no tratamento de doenças bacterianas nas abelhas, onde a presença de resíduos constituem um risco para a saúde dos consumidores, como reações alérgicas, modificação da flora intestinal, resistência bacteriana e choques anafiláticos. Ainda na produção no campo com o uso de pesticidas para controle de pragas e doenças que afetam as abelhas. A ocorrência de contaminação microbiológica tem como fatores a falta de higiene na extração, contendo néctar floral, poeira, terra, pólen, o trato diges', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10045', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affad6a63682f044c89f', 'Reprodução de abelha rainha, fator importante para produção elevada da colmeia', 'Lucena, Hemilly Rayane de Sales; Gurjão, Thyago Araújo; Henrique  Mascarenhas, Nágela Maria Henrique Mascarenhas; de Souza , Ohana Gaudêncio; de Assys Romero da Mota Sousa, Francisco; Borges Maracajá,', 'Editora Verde', 'Agriculture', 'Agriculture', 'A apicultura se difundiu por vários países, dentre eles o Brasil que possui características de um país tropical o que favorecem a evolução das diversidades de abelhas, com a metodologia da zootecnia que tem como finalidade o desenvolvimento racional da atividade a partir da qual podem ser produzidos e comercializados mel, própolis, geléia real, pólen e apitoxinas, porém, sua principal função é o fornecimento de polinização. Por ser uma atividade essencialmente rural que utiliza recursos naturais para a produção de produtos, protege o meio ambiente e acrescenta mercadologia ecológica aos produtos produzidos por esta atividade. Uma colónia de abelhas é uma unidade biológica completa composta por criaturas sociais que atuam como um “superorganismo” e é caracterizada pela cooperação entre indivíduos, cada um dos quais desempenha um papel extremamente importante na sobrevivência geral da colónia. As abelhas melíferas estão totalmente desenvolvidas (ovo, larva, pré-pupa, pupa e adulto) e são', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10050', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8a1', 'Apicultura inserida no contexto da agricultura sustentável - revisão', 'José Matias Porto Filho; Medeiros, Aline Carla de; Silva Filho, Jose Pereira da; Gurjão, Thyago Araújo; Maracaja, Patricio Borges; Pereira, Daniel Santiago; Stefani Silva Vicente; Francisco de Assys R', 'Editora Verde', 'Agriculture', 'Agriculture', 'Com toda a degradação do meio ambiente na região Nordeste do Brasil nos últimos anos, a apicultura por não agredir o meio ambiente se torna uma ótima alternativa para a questão do desenvolvimento sustentável. A apicultura além de ser ecológica é comprovadamente rentável, podendo ser desenvolvida em toda região que possua clima e solo favorável e que exista uma vegetação abundante rica em floradas, sendo assim uma atividade sustentável com grande importância econômica. Diferente da maioria das atividades rurais a apicultura não é destrutiva, ela é uma das poucas atividade agropecuárias que cumpre com os requisitos do tripé da sustentabilidade: o econômico, gerando fonte renda para os agricultores; o social, pois utiliza a mão de obra que em maior parte das vezes é familiar; e o ecológico, porque não é necessário desmatar para criar abelhas. Na agricultura familiar de base ecológica a apicultura acaba sendo uma prática indispensável, pois as abelhas polinizam as lavouras, pomares e pasta', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10052', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8a3', 'Análise sistemática a respeito da produção apícola de cunho sustentável nos ambientes domésticos com foco no semiárido nordestino.', 'José Matias Porto Filho; Medeiros, Aline Carla de; Gurjão, Thyago Araújo; Yasmin Hosana Nascimento Porto; Almeida, Rossino Ramos de; Francisco de Assys Romero da Mota Sousa; Bruna Santos da Silva; Nág', 'Editora Verde', 'Agriculture', 'Agriculture', 'Uma das maiores problemáticas da atualidade, sobretudo, no que tange a produção sustentável de insumos oriundos da criação de abelhas, diz respeito a perda das populações de tais animais, fato gerado pela junção de inúmeros fatores, principalmente, pelo uso indiscriminado de agrotóxicos, os quais são responsáveis por envenenar diversas colmeias, além de não favorecerem a produção ecológica, bem como, pelo estabelecimento de problemas de sanidade ocorridos por meio da instalação de pragas e doenças nas colônias, que diminuem, consideravelmente, o potencial produtivo, gerando assim, perdas drásticas, especialmente, na produção de mel. Cabe pontuar que as abelhas prestam um significativo serviço ambiental, seja com a polinização, que promove a manutenção dos ecossistemas, como também por meio da produção de diversos materiais, principalmente, alimentos, que surgem como importantes fontes de renda na agricultura familiar, uma vez que a cadeia produtiva da apicultura promove a geração de em', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10055', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8a7', 'A importância da preservação das abelhas – uma revisão', 'José Matias Porto Filho; Flasner Maciel Lemos; Silva, Rosilene Agra da; Gurjão, Thyago Araújo; Maria Vitoria da Silva; Priscilla Karla; Almeida, Rossino Ramos de; Francisco de Assys Romero da Mota Sou', 'Editora Verde', 'Agriculture', 'Agriculture', 'As abelhas são seres pertencentes ao Reino Animal, Filo Arthropoda, Classe Insecta e a ordem Hymenoptera. No mundo, são conhecidas mais de 20.000 espécies. Sua criação é uma cultura que agrega importantes benefícios, sendo eles econômicos e ambientais. Essa atividade pode ser subdividida em apicultura, que se trata da criação de abelhas Apis mellifera, que possuem ferrão, as quais foram introduzidas no Brasil por meio do homem; e a meliponicultura que é a atividade de criação de abelhas-sem-ferrão, que são nativas do Brasil. Estes animais tem sua importância destacada devido sua capacidade de produzir mel, própolis, geleia real, entre outros produtos, além de serem importantes insetos polinizadores de diversos ecossistemas, atuando como principais mecanismos de perpetuação da flora e fauna silvestre. Tanto a meliponicultura como a apicultura são atividades agropecuárias mais sustentáveis e importantes aliadas à preservação ambiental, pois não gera impactos ambientais negativos. Economi', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10059', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8b1', 'Comparativo das análises físico-químicas de mel de abelha do município de Catolé do Rocha-PB e São José do Rio do Peixe-PB', 'dos Santos Araújo, Alfredina; Allan Alves Fernandes, Eryck; Kauan Carvalho Campos, Endrew; Ferreira, Weslayna Firme; Eugênia Morais Bezerra, Maria; Cristina Gomes Colman, Victória', 'Editora Verde', 'Agriculture', 'Agriculture', 'A apicultura no Brasil é uma prática ancestral, transmitida de geração em geração, que se consolidou como um hábito enraizado na população devido aos inúmeros benefícios associados ao consumo de seus produtos. A legislação do mel inclui regulamentos e normas para garantir da qualidade do produto. De acordo com a legislação brasileira, o mel é classificado como um produto de origem animal, produzido pelas abelhas Melíferas a partir do néctar das flores, composta por glicose e frutose. A Instrução Normativa nº 11, de&nbsp; 20 de outubro&nbsp; de&nbsp; 2000,&nbsp; que&nbsp; estabelece&nbsp; o&nbsp; Regulamento&nbsp; Técnico&nbsp; de&nbsp; Identidade&nbsp; e&nbsp; Qualidade&nbsp; do&nbsp; Mel foi estabelecida com intuito de evitar fraudes nos produtos, garantindo um produto seguro, puro e de qualidade. O trabalho teve como objetivo realizar as análises físico-química do mel oriundo da cidade de Catolé do Rocha-PB e São José do Rio do Peixe-PB, onde foram realizadas análises em triplicatas ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10082', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8b2', 'Forídeo uma ameaça para abelhas (Apidae: Meliponini): uma revisão de técnicas de controle', 'Prado Júnior, Leonardo Souza do; Maia, Adryele Gomes; Soares, Kilmer Oliveira; Andrade, Anderson Bruno Anacleto de; Maracaja, Patricio Borges; Costa, Victor Luiz Queiroz Claudino; Gomes, Nicolle Borba', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10085', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8b3', 'Abelhas em um ambiente urbano:  a meliponicultura como ferramenta de conscientização ambiental', 'Maracajá, Patricio Borges; Prado Junior, Leonardo Souza do; Rodrigues Gomes, Nicolle Borba Maracajá; Maia, Adryele Gomes; Soares, Kilmer Oliveira; Andrade, Anderson Bruno Anacleto de; Nepomuceno, Taya', 'Editora Verde', 'Agriculture', 'Agriculture', 'Introdução: A crescente população mundial e a extinção das abelhas são temas que tem preocupado toda a sociedade em todo o mundo pelo motivo desses insetos serem importantes polinizadores de culturas agrícolas. A maioria das culturas cultivadas em ambientes urbanos precisa de abelhas para a polinização.&nbsp;No entanto, pouco se sabe sobre as populações de abelhas em áreas urbanas e pouca atenção tem sido dada à função destes polinizadores nas cidades. A criação de abelhas nativas ou abelhas sem ferrão é chamada de Meliponicultura, e por não possuírem ferrão, essas abelhas têm sido utilizadas em muitas situações. Portanto, faz necessário estudar a ecologia das abelhas polinizadoras em jardins urbanos e contribuir para a agricultura urbana.&nbsp;Objetivos: Portanto, pretende-se abordar questões como a diversidade de abelhas em áreas urbanas, bem como examinar a atratividade das plantas hospedeiras em hortas e jardins urbanos, e examinar os efeitos da paisagem e das variáveis ​​locais so', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10086', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8b7', 'Biomateriais aplicados na Medicina Veterinária - Revisão de Literatura', 'José de Medeiros Dantas Neto; Gurjão, Thyago Araújo', 'Editora Verde', 'Agriculture', 'Agriculture', 'O biomaterial, são meios alternativos pelos quais são utilizados para melhor interação nos sistemas biológicos dosanimais, podendo ser natural ou não, e sua composição seria a união de substâncias para melhor recuperação em tecidoslesionados, exemplo, órgãos, tecidos, funções do corpo. E sua aplicabilidade seria um meio mais eficiente e alternativopara não que seja um processo mais invasivo, tendo em vista que os seus pós são mais eficientes do que esses meiosinvasivos, como por exemplo, cirurgias ortopédicas, cirurgias neurológicas, etc. O material utilizado no trabalho emquestão seria artigos já publicados sobre biomateriais e aplica-los ao campo da medicina veterinária, fazendo com queseja mais especifico à área. O método em questão seria comparativo, já que há uma similaridade com campo da medicinahumana que possui estudos sobre o tema abordado. Os tipos de biomateriais mais utilizados, são os metais, já que sãomais utilizados em procedimentos ortopédicos, tendo em vista que possui', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10170', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8c1', 'Potencial zoonótico do Ophidascaris robertsi e sua relevância para a medicina veterinária', 'André Luiz do Bú Lucena; Gurjão, Thyago Araújo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Concomitantemente à crescente interação entre seres humanos e animais silvestres, emerge-se a preocupação daincidência de doenças de caráter zoonótico. A descoberta científica mais recente, publicada na revista “EmergingInfectious Diseases", na edição de setembro de 2023, refere-se ao achado de um exemplar de Ophidascaris robertsi nocérebro de uma australiana de sessenta e quatro anos de idade. O incidente despertou a atenção, tanto da comunidadecientífica como da população em geral, para o déficit de estudos dedicados à investigação de parasitas ofídicospotencialmente patogênicos à espécie humana, além de medidas profiláticas capazes de impedir que esses eventosisolados venham a se tornar uma questão cotidiana. Nessa perspectiva, a presente pesquisa objetivou investigar, emmaterial teórico, estudos que contemplassem a biologia do Ophidascaris robertsi, com foco em seu ciclo evolutivo, demodo a elucidar a importância desse parasita no âmbito das ciências médicas veterinárias. Os repres', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10185', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8c2', 'Psitacose na interface entre humanos e aves – Revisão Bibliográfica', 'Dennis Fábio Silva Lima; Gurjão, Thyago Araújo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os microrganismos da família Chlamydiaceae são patógenos intracelulares obrigatórios de aves e mamíferos. A vasta quantidade e diferentes espécies desta família permite a infectação de muitos hospedeiros,&nbsp; devido ao seu alto tropismo tecidual variável, que proporciona o surgimento de inúmeras doenças agudas e crônicas, as quais vão desde infertilidade sexualmente transmissível, até tracoma, doenças respiratórias e cardiovasculares. Psitacose é o nome dado a uma patologia infecciosa gerada pela bacteria Chlamydia psittaci, a qual pode ser transmitida a humanos por meio de contato direto com aerossóis oriundos das secreções de aves - Psittaciformes - contaminadas e assintomáticos. Em 1879 foi descrito o primeiro surto de psitacose, descrito por Jacob Ritter, associando a doença a papagaios e tentilhões. Já os surtos pandêmicos de psitacose humana de 1929 e 1930 estavam ligados à importação de psitacídeos infectados oriundos da América do Sul destinados à Europa e América do Norte. P', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10186', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affbd6a63682f044c8c7', 'Utilização de medicamentos humanos em animais domésticos: implicações e efeitos adversos.', 'Rhayssa Vieira Soares Da Costa; Gurjão, Thyago Araújo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Conforme a Agência Nacional de Vigilância Sanitária, a automedicação é caracterizada pela iniciativa de umdoente, ou de seu responsável, em obter ou produzir e utilizar um produto que acredita lhe trará benefícios notratamento de doenças ou alívio de sintomas, sem a orientação de um profissional de saúde qualificado. Um dos fatoresque levam à intoxicação por medicamentos é a cultura da automedicação familiar, o que faz com que seja empregado omesmo comportamento com seus animais de estimação - ou seja, se o animal está apresentando um sintoma parecidocom o que o ser humano apresenta, o responsável medica com o que ele habitualmente se automedica. Segundo oSistema Nacional de Informações Tóxi-farmacológicas (SINTOX), os números de intoxicações causadas pormedicamentos superam os das intoxicações originadas por outros agentes tóxicos como, por exemplo, agrotóxicos,produtos de limpeza e cosméticos. Os medicamentos estão entre as principais causas de intoxicação nos animais decompanhia no ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10192', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8d2', 'Aspectos fisiológicos de berinjela sob condição de déficit hídrico e aplicação de nanofertilizantes de Zn e bioinoculante', 'Freitas, Leandro Nunes de; Souza, Jose Ebson Janoca de; Pereira, Francisco Hevilásio Freire', 'Editora Verde', 'Agriculture', 'Agriculture', 'A deficiência hídrica é um dos principais fatores que limitam o desenvolvimento da olericultura como importante atividade econômica do sertão paraibano. Sendo assim, o trabalho teve como objetivo, avaliar os mecanismos fisiológicos de tolerância ao déficit hídrico em plantas de berinjela tratadas com nanofertilizantes. O experimento foi realizado em condições de campo na Fazenda Experimental do CCTA/UFCG, Campus de Pombal-PB, utilizando a berinjela cultivar ‘Ciça’. Os tratamentos foram arranjados no esquema de parcela subdividida 2 x 5, onde foram combinados dois níveis de irrigação (50% e 100% da evapotranspiração potencial - ETo) e cinco tratamentos relativos à aplicação de zinco e bioinoculante (sulfato de Zn; nano-ZnO foliar; nano-ZnO foliar + Bio; sulfato de Zn + Bio e controle). O delineamento experimental utilizado foi em blocos casualisados, com quatro repetições. Foram avaliadas as trocas gasosas, carotenoides totais e extravasamento de eletrólitos. A aplicação de nanopartícul', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10648', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8d3', 'Toxicidade residual de Abamectina sobre Apis mellifera', 'Silva, Emanoely Karoliny Santos da; Costa , Jacquelinne Alves de Medeiros Araújo; Costa, Ewerton Marinho da; Alves, Luiz Henrique Gonçalo; Santos, Poliana Linhares dos; Cardoso, Tiago Augusto Lima Car', 'Editora Verde', 'Agriculture', 'Agriculture', 'A abelha Apis mellifera é essencial em áreas agrícolas e um desafio é atrelar o controle químico de pragas com sua conservação. Portanto, objetivou-se avaliar a toxicidade residual de Abamectina em função do tempo após a pulverização sobre A. mellifera. O experimento foi realizado sob condições de laboratório em delineamento inteiramente casualizado e esquema fatorial 3 X 5, sendo duas doses do inseticida Abamectina, 0,0054 g i.a/L-1 e 0,0068 g i.a /L-1, uma testemunha (água destilada) e cinco tempos de exposição após a pulverização (1, 2, 3, 24 e 48 horas). Após a exposição, foram avaliadas a mortalidade e os distúrbios motores das abelhas a 1, 2, 3, 4, 5, 6, 12 e 24 horas. A Abamectina nas doses 0,0054 g i.a/L-1 e 0,0068 g i.a /L-1 respectivamente, ocasionou cerca de 26% e 34% de mortalidade após 1 hora da pulverização, 16% e 18% após 2 horas, 22% e 32%, após 3 horas, 28% e 34% após 24 horas e 40% e 48% após 48 horas. Foi observado que o inseticida Abamectina, independente da dose e ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10649', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8d5', 'Crescimento de mudas de maracujazeiro-amarelo sob estresse salino e métodos de aplicação de silício', 'Rodrigues , Samuel Saldanha; Maia , Orquídea Suassuna; Pereira , Rennan Fernandes; Lins, Lays Klécia Silva; Mesquita, Evandro Franklin de; Fernandes, Fernanda Suassuna', 'Editora Verde', 'Agriculture', 'Agriculture', 'A salinidade é um problema comum em muitas lavouras no semiárido brasileiro, demandando estudos sobre substâncias que atenuem seus efeitos deletérios, como o silício. Neste trabalho, foi avaliado o crescimento de mudas de maracujazeiro amarelo sob irrigação salinizada e aplicação de silício. Foram avaliados os tratamentos: T1 - irrigação com água de condutividade elétrica (CE) de 1,2 dS m-1; T2 - irrigação com água de CE de 4,0 dS m-1 (salinizada); T3 - irrigação salinizada, com aplicação de silício no solo; T4 - irrigação salinizada, com aplicação de silício via foliar; e T5 - irrigação salinizada, com silício via solo e foliar. No T3, aplicou-se solução com 0,5 g de H4SiO4 L-1. No T4, solução com 0,2 g de H4SiO4 L-1 nas folhas. No T5, aplicou-se, via solo, solução com 0,25 g de H4SiO4 L-1, enquanto, nas folhas, foi aplicada solução com 0,1g de H4SiO4 L-1. O delineamento foi inteiramente casualizado, com cinco repetições. Os dados foram submetidos à análise de variância e ao teste de ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10653', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8dd', 'Pigmentos fotossintéticos de algodoeiro em função das lâminas de irrigação e aplicação foliar de ácido salicílico', 'Trigueiro, Ericlys Daniel Nascimento; Silva, Gleisson dos Santos da; Lima, Geovani Soares de; Nóbrega, Jackson Silva; Silva, Julio Cesar Agostinho da; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O algodoeiro é uma das principais culturas do mundo e de elevada importância para o Nordeste brasileiro, porém sua exploração pode ser limitada pela escassez hídrica. O uso de substâncias para melhorar o desempenho das culturas sob condições de estresse hídrica tem se destacado como alternativa promissora, dentre elas destaca-se à aplicação foliar de ácido salicílico. Objetivou-se avaliar a biossíntese de pigmentos fotossintéticos de algodoeiro de fibra naturalmente colorida sob lâminas de irrigação e aplicação foliar de ácido salicílico. A pesquisa foi realizada em condições de campo no Centro de Ciências e Tecnologia Agroalimentar, da Universidade Federal de Campina Grande, Pombal – PB. O delineamento de blocos casualizados foi utilizado, em esquema fatorial 5 × 5, referindo-se a cinco lâminas de irrigação (40, 60, 80, 100 e 120% da Evapotranspiração da cultura - ETc) e cinco concentrações de ácido salicílico (AS = 0; 1,5; 3,0, 4,5 e 6,0 mM) com três repetições. Avaliou-se os teores ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10678', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8e0', 'Crescimento de tomate-cereja em função da solução nutritiva salobra e aplicação foliar de ácido ascórbico em cultivo semi-hidropônico', 'Silva, Fellype Jonathar Lemos da; Lima, Geovani Soares de; Gheyi, Hans Raj; Costa, Denis Soares; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'Dentre as olerícolas, o tomate é a segunda espécie mais cultivada no mundo, com elevada importância econômica e social, sendo uma excelente fonte de emprego e renda. A utilização de águas com elevados teores de sais, afetam negativamente as plantas, limitam seu crescimento e a sua produção. Nesta perspectiva, a aplicação foliar de ácido ascórbico é uma alternativa promissora na mitigação do estresse salino sobre as plantas. Objetivou-se avaliar o efeito da aplicação do ácido ascórbico no crescimento do tomate-cereja ‘Laranja’ cultivado com soluções nutritivas salobras em sistema semi-hidropônico. Foi utilizado o delineamento em blocos casualizados, em esquema fatorial 5 × 4, sendo cinco níveis de condutividade elétrica da solução nutritiva - CEsn (2,1-Testemunha; 2,8; 3,5; 4,2 e 4,9 dS m-1) e quatro concentrações do ácido ascórbico - AsA (0, 150, 300 e 450 mg L-1), com quatro repetições. O incremento na condutividade elétrica da solução nutritiva a partir de 2,1 dS m-1 reduziu o cresci', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10681', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8e3', 'Pigmentos fotossintéticos de tomate cereja hidropônico sob estresse salino e peróxido de hidrogênio', 'Soares , Lauriane Almeida dos Anjos; Silva, Luderlândio de Andrade; Lima, Geovani Soares de; Guedes, Maria Amanda; Siqueira, Ana Clara Farias; Gheyi, Hans Raj', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar os efeitos da aplicação foliar de peróxido de hidrogênio nos pigmentos fotossintéticos do tomate cereja laranja sob solução nutritiva salina em sistema hidropônico. O experimento foi desenvolvido em casa de vegetação em Pombal - PB, utilizando a Técnica de Fluxo Laminar de Nutriente - NFT. Os tratamentos foram distribuídos em esquema de parcelas subdivididas, sendo a parcela constituída de quatro níveis de condutividade elétrica da solução nutritiva - CEsn (2,1; 2,8; 3,5 e 4,2 dS m-1) e as subparcelas de duas concentrações de peróxido de hidrogênio – H2O2 (0 e 48 μM), com três repetições e duas plantas por parcela. A salinidade da solução nutritiva afetou de forma negativa a síntese de pigmentos fotossintéticos das plantas de tomate cereja em sistema hidropônico, aos 70 dias após o transplantio. A aplicação de H2O2 na concentração de 48 μM promoveu aumento nos teores de clorofila a tomate cereja laranja.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10686', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8e4', 'Mecanismos fisiológicos de tolerância ao déficit hídrico em plantas de berinjela tratadas com nanofertilizantes e bioinoculantes', 'Costa, Francisco Macelo Nascimento da; Silva, Whashington Idalino da; Souza, Jose Ebson Janoca de; Pereira, Francisco Hevilásio Freire; Barroso , Filipe de Paula Vieira; Ramos, Carlos Sávio Gomes', 'Editora Verde', 'Agriculture', 'Agriculture', 'RESUMO: A deficiência hídrica é um dos principais fatores que limitam o desenvolvimento da olericultura como importante atividade econômica do sertão paraibano. Sendo assim, o trabalho teve como objetivo, avaliar os mecanismos fisiológicos de tolerância ao déficit hídrico em plantas de berinjela tratadas com nanofertilizantes. O experimento foi realizado em condições de campo na Fazenda Experimental do CCTA/UFCG, Campus de Pombal-PB, utilizando a berinjela cultivar ‘Ciça’. Os tratamentos foram arranjados no esquema de parcela subdividida 2 x 5, onde foram combinados dois níveis de irrigação (50% e 100% da evapotranspiração potencial - ETo) e cinco tratamentos relativos à aplicação foliar de nanofertilizantes (sulfato de Zn; nano-ZnO foliar; nano-ZnO foliar + Bio; sulfato de Zn + Bio e controle). O delineamento experimental utilizado foi em blocos casualisados, com quatro repetições. Os parâmetros fisiológicos avaliados foram: Pigmentos (clorofilas a clorofila b) e potencial osmótico do', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10691', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8e8', 'Crescimento de pepino sob solução nutritiva salina e ácido salicílico em sistema hidropônico', 'Gheyi , Hans Raj; Soares , Lauriane Almeida dos Anjos; Mendonça, Allysson Jonhnny Torres; Lima, Geovani Soares de; Sá, Valeska Karolini Nunes Oliveira de; Torres , Rafaela Aparecida Frazão', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10698', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8e9', 'Trocas gasosas de pepino sob solução nutritiva salina e ácido salicílico em sistema hidropônico', 'Gheyi , Hans Raj; Soares , Lauriane Almeida dos Anjos; Mendonça, Allysson Jonhnny Torres; Lima, Geovani Soares de; Sá, Valeska Karolini Nunes Oliveira de; Torres , Rafaela Aparecida Frazão', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10700', NULL, 'English', 'published', false, false, 'open', 'pdf')
