INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8ec', 'Eficiência fotoquímica de mini-melancia cultivada sob estratégias de irrigação com déficit hídrico e ácido salicílico', 'Dantas, Maíla Vieira; Silva, Vitor Manoel Bezerra da; Lima, Geovani Soares de; Silva, Josélio dos Santos da; Gheyi, Hans Raj; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho, avaliar os efeitos da aplicação foliar de ácido salicílico sobre a eficiência fotoquímica em plantas de mini-melancia cultivada sob estratégias de irrigação com déficit hídrico. A pesquisa foi desenvolvida na fazenda experimental ‘Rolando Enrique Rivas Castellón’ pertencente ao Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, em São Domingos, Paraíba. Os tratamentos consistiram da combinação de quatro estratégias de irrigação com déficit hídrico em diferentes fases de desenvolvimento da cultura - EID, correspondendo a 100% da evapotranspiração da cultura (ETc), denominada: SE-plantas sob irrigação plena e 60% da ETc nas fases: VE – plantas irrigadas com estresse hídrico na fase vegetativa; FL - plantas sob estresse hídrico na fase de floração; FR - estresse hídrico na fase de frutificação e duas concentrações de ácido salicílico (0 e 3,6 mM), em esquema de parcelas subdivididas, em que as EID corresponderam as parc', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10706', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8ed', 'Trocas gasosas de mini-melancia cultivada sob diferentes estratégias de irrigação com déficit hídrico e ácido salicílico', 'Dantas, Maíla Vieira; Silva, Vitor Manoel Bezerra da; Lima, Geovani Soares de; Gheyi, Hans Raj; Soares, Lauriane Almeida dos Anjos; Silva, Smyth Trotsk de Araújo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho avaliar os efeitos da aplicação foliar de ácido salicílico sobre as trocas gasosas de mini-melancia cultivada sob estratégias de irrigação com déficit hídrico. A pesquisa foi desenvolvida na fazenda experimental ‘Rolando Enrique Rivas Castellón’ pertencente ao Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, em São Domingos, Paraíba. Os tratamentos consistiram da combinação de quatro estratégias de irrigação em diferentes fases de desenvolvimento da cultura - EID, baseadas na evapotranspiração da cultura – ETc (SE-plantas sob irrigação plena e 60% da ETc nas fases: VE – plantas irrigadas com déficit hídrico na fase vegetativa; FL - plantas sob déficit hídrico na fase de floração; FR - déficit hídrico na fase de frutificação) e duas concentrações de ácido salicílico (0 e 3,6 mM), em esquema de parcelas subdivididas, em que as EID corresponderam as parcelas e as concentrações de AS, as subparcelas, com 3 repetições e ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10707', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8f5', 'Trocas gasosas de quiabeiro cultivado sob níveis de reposição hídrica e polímero hidroretentor', 'Silva, Saulo Soares da; Soares , Lauriane Almeida dos Anjos; Trigueiro, Ericlys Daniel Nascimento; Almeida , Flávia de Sousa; Lima , Geovani Soares de; Silva, Julio Cesar Agostinho da', 'Editora Verde', 'Agriculture', 'Agriculture', 'RESUMO: O quiabeiro tem grande importância socioeconômica na região Nordeste do Brasil, destacando-se como fonte de emprego e renda. Contudo, nessa região, a escassez hídrica dificulta a produção agrícola, tornando-se uma necessidade o uso de estratégias de manejo da irrigação para amenizar os efeitos do déficit hídrico nas plantas. Nesse contexto, objetivou-se avaliar as trocas gasosas de quiabeiro cultivado sob níveis de reposição hídrica e doses de polímero hidroretentor. O experimento foi conduzido em vasos adaptados como lisímetros de drenagem em condição de casa-de-vegetação, nas dependências do Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, Campus de Pombal-PB. Os tratamentos foram distribuídos em blocos casualizados, em arranjo fatorial 2 × 4, sendo constituídos pela combinação de dois fatores: dois níveis de reposição de água (40 e 100% da evapotranspiração da cultura - ETc) associados a quatro doses de polímero hidroretentor (0,0; 1,0', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10724', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8f6', 'Fitomassas de quiabeiro cultivado sob níveis de reposição hídrica e polímero hidroretentor', 'Trigueiro, Ericlys Daniel Nascimento; Almeida , Daniel da Conceição; Almeida , Flávia de Sousa; Silva , Saulo Soares da; Lima , Geovani Soares de; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'RESUMO: A escassez hídrica destaca-se como um dos fatores limitantes para expansão da agricultura no semiárido do Nordeste brasileiro. Nesse contexto, é imprescindível a busca por estratégias para minimizar os efeitos do déficit hídrico sobre os cultivos. Diante do exposto, objetivou-se com o presente estudo avaliar o acúmulo de fitomassa de quiabeiro cultivados sob níveis de reposição hídrica e doses de polímero hidroretentor. O experimento foi conduzido em vasos adaptados como lisímetros de drenagem em condição de casa-de-vegetação, nas dependências do Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, Campus de Pombal-PB. Os tratamentos foram distribuídos em blocos casualizados, em arranjo fatorial 2 × 4, sendo constituídos pela combinação de dois fatores: dois níveis de reposição de água (40 e 100% da evapotranspiração da cultura - ETc) associados a quatro doses de polímero hidroretentor (0,0; 1,0; 2,0 e 3,0 g L-1) com três repetições. A irriga', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10725', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c8fb', 'Índices fisiológicos da goiabeira sob irrigação deficitária e aplicação foliar de ácido ascórbico na fase vegetativa', 'Silva, Saulo Soares da; Queiroz, Victor Ferreira; Lacerda, Cassiano Nogueira de; Lima , Geovani Soares de; Silva, Letícia da Luz; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'RESUMO: A adoção de práticas de irrigação eficientes e a utilização de compostos que ajudam a minimizar os efeitos do estresse hídrico são fundamentais para melhorar a produtividade, a qualidade dos frutos e a sustentabilidade do cultivo de goiaba no semiárido Nordestino. Por tanto, objetivou-se com este trabalho avaliar os efeitos da aplicação foliar de ácido ascórbico nos índices fisiológicos da goiabeira sob zdéficit hídrico na fase vegetativa no semiárido Paraibano.  Os tratamentos foram constituídos da combinação de duas estratégias de manejo da irrigação, sendo uma com déficit hídrico - EMI (VE - plantas irrigadas com déficit hídrico (50% da evapotranspiração da cultura - ETc) e irrigação plena, SE - plantas sob irrigação plena durante todo o ciclo (100% da evapotranspiração da cultura - ETc) e na fase vegetativa e quatro concentrações de ácido ascórbico - AsA (0, 200, 400 e 600 mg L-1), distribuídos em delineamento de blocos casualizados, em esquema de parcelas subdivididas com ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10731', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c90b', 'Rendimento econômico da cultura da couve em sistemas consorciados com coentro, alface e cebolinha', 'Sousa, Anielson dos Santos; Lacerda, Rodolfo Rodrigo de Almeida; Souza , Leandro de Pádua; Costa, Caciana Cavalcanti; Lacerda, Ivislanne de Sousa Queiroga; Oliveira, Odair Honorato de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O que pode se esperar dos consórcios é a maximização dos recursos ambientais, econômicos e produtivos das culturas envolvidas enquanto seu estudo econômico permite a eficiente tomada de decisões. Desta forma, objetivou-se avaliar o rendimento econômico da produção da couve, coentro, alface e cebolinha, em sistemas consorciados comparados ao seu monocultivo. O delineamento experimental foi composto por 11 tratamentos correspondendo a quatro policultivos, três consórcios e quatro monocultivos, distribuídos em delineamento de blocos ao acaso, com quatro repetições. Foram avaliadas: a produtividade, os custos operacionais totais (COT), a receita bruta, a receita líquida, o índice de lucratividade e a taxa de retorno. Em todos os sistemas estudados, a maior participação foi referente ao custo com mão de obra. Apesar dos acréscimos nos COTs (Custos Operacionais Totais) dos sistemas em policultivo, esses sistemas se mostram viáveis economicamente em comparação com os bicultivos.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10750', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c90c', 'Crescimento de maracujazeiro-azedo irrigado com águas salobras e aplicação foliar de prolina', 'Lima, Geovani soares de; Santos, Larissa Fernanda Souza; de Lima, Vera Lucia Antunes; Silva, André Alisson Rodrigues da; Nóbrega, Jackson Silva; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O semiárido brasileiro apresenta fontes hídricas com elevados teores de sais, um dos principais fatores que proporciona estresse abiótico em culturas sensíveis ao estresse salino, como o maracujazeiro-azedo. Neste contexto, a busca por estratégias capazes de mitigar os efeitos nocivos das águas salobras nas plantas são essenciais para garantir a produção de alimentos. Objetivou-se com este estudo avaliar os efeitos da aplicação foliar de prolina no crescimento de maracujazeiro-azedo irrigado com águas salobras na fase fenológica de mudas. A pesquisa foi conduzida sob condições de ambiente protegido pertencente à Unidade Acadêmica de Engenharia Agrícola da Universidade Federal de Campina Grande, em Campina Grande – PB, utilizando-se o delineamento experimental inteiramente casualizado, em esquema fatorial 5 × 2, sendo cinco níveis de condutividade elétrica da água de irrigação CEa - (0,6; 1,2; 1,8; 2,4 e 3,0 dS m-1) e com e sem aplicação de prolina (0 e 15 mM) com quatro repetições e du', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10752', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c90d', 'Pigmentos fotossintéticos de maracujazeiro-azedo irrigado com água salobra e prolina', 'Soares, Lauriane Almeida dos Anjos; Santos, Larissa Fernanda Souza; de Lima, Vera Lucia Antunes; Borborema, Lucyelly Dâmela Araújo; de Lima, Geovani soares; Arruda, Thiago Felipe de Lima', 'Editora Verde', 'Agriculture', 'Agriculture', 'A produção de frutíferas no nordeste brasileiro vem enfrentando desafios devido as suas fontes hídricas salobras, no caso do maracujazeiro-azedo como principal fonte de renda para pequenos agricultores e sensível ao estresse salino, estratégias viabilizem o uso destas águas é essencial para manter a sobrevivência destas famílias. Nesse contexto, este estudo avaliou os efeitos das concentrações de prolina no crescimento e qualidade de maracujazeiro-azedo irrigados com águas salobras na fase de formação de mudas. A pesquisa foi conduzida sob condições de ambiente protegido pertencente à Unidade Acadêmica de Engenharia Agrícola da Universidade Federal de Campina Grande, em Campina Grande – PB, utilizando-se o delineamento experimental inteiramente casualizado, em esquema fatorial 5 × 2, sendo cinco níveis de condutividade elétrica da água de irrigação CEa - (0,6; 1,2; 1,8; 2,4 e 3,0 dS m-1) e sem e com aplicação de prolina (0 e 15 mM) com quatro repetições e duas plantas por parcela, perf', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10753', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c91e', 'Condicionamento de sementes de melancia com bioestimulante para atenuar o estresse salino', 'Pinheiro Lopes, Kilson; Dantas de Lima, Erlânia Erica; Lacerda Lopes, Geraldavane; de Sena Rodrigues, Antônio Carlos; Alves Sousa, Alesia; Sousa, Valéria Fernandes de Oliveira', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o condicionamento fisiológico de sementes de melancia com bioestimulante à base de Ascophyllum nodosum como atenuante do estresse salino. O experimento foi realizado no Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, Campus Pombal, PB. O delineamento experimental utilizado foi o inteiramente casualisado, em esquema fatorial 3 × 5, sendo três concentrações de bioestimulante à base de A. nodosum (0,0; 1,0 e 2,0 mL L-1) e cinco concentrações salinas (0,3; 1,0; 2,0; 3,0; 4,0 dS m-1). O bioestimulante com a concentração de 1,0 mL L-1, estimulou o vigor favorecendo rapidez na germinação, a primeira contagem e o índice de velocidade de germinação das sementes de melancia em salinidade de até 3,0 dS m-1. O bioestimulante melhora o vigor e crescimento das plântulas de melancia em condições de estresse salino até 3,0 dS m-1.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10782', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c91f', 'Adubação com torta de filtro de cana-de-açúcar não atenua estresse salino em pimenta biquinho', 'Palmeira, Irlan Victor de Sousa; Pereira, Daniel Duarte; Nascimento, Marlene P. do; Dias, Thiago J.; Basilio, Ana Gabriela Sousa; Silva, Ramon F. da', 'Editora Verde', 'Agriculture', 'Agriculture', 'A escassez de recursos hídricos é um desafio global, especialmente em regiões semiáridas, necessitando o uso de água salina para irrigação. A produção de alimentos sob irrigação com água salina é limitada devido ao estresse salino, afetando negativamente o desenvolvimento e a produção das plantas. Esta pesquisa objetivou avaliar se a adubação com torta de filtro in natura da cana-de-açúcar atenua os impactos da salinidade na produção vegetal. O experimento foi conduzido em blocos casualizados, testando cinco condutividades elétricas da água de irrigação (0,5; 1,3; 3,25; 5,2 e 6,0 dS m-1) e cinco doses de resíduo de cana-de-açúcar (0; 34,8; 120,0; 205,2; 240,0 kg ha-1). Os tratamentos foram delineados por meio de uma matriz central box, com três repetições e três plantas por repetição. As variáveis analisadas foram altura da planta, número de folhas, número de flores, diâmetro do caule, clorofila total, fluorescência total, eficiência quântica máxima do fotossistema II e condutância est', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10795', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c922', 'exemplo', 'Medeiros, Aline Carla de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este artigo examina o papel da formação audiovisual como instrumento pedagógico para a educação cooperativista de jovens no meio rural, a partir da experiência da Associação Raízes da Cultura (ASSORAC), em Campina Grande–PB. Inspirada na pedagogia freireana e nos princípios da educomunicação, a pesquisa adota abordagem qualitativa, combinando observação participante, análise de produtos audiovisuais e entrevistas com jovens comunicadores envolvidos em processos formativos. O estudo identifica que as oficinas de audiovisual promovidas pela ASSORAC constituem espaços de letramento crítico, nos quais a produção de narrativas próprias fortalece a consciência de pertencimento, estimula o protagonismo juvenil e favorece a compreensão dos princípios do cooperativismo solidário, no qual pode ser aplicado à apicultura e meliponicultura no interior da Paraíba. Os resultados apontam que a apropriação comunitária de tecnologias de comunicação, aliada à mediação pedagógica contextualizada, potencia', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10803', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c924', 'Pigmentos fotossintéticos de maracujazeiro-azedo ‘BRS Gigante Amarelo’ irrigado com água salina e adubação potássica', 'Torre, Rafaela Aparecida Frazão; Soares, Lauriane Almeida dos Anjos; Lima, Vera Lúcia Antunes de; Souza, Weslley Bruno Belo de; Lima, Geovani Soares de; Paiva, Francisco Jean da Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Semiárido brasileiro é caracterizado por condições climáticas que favorecem o acúmulo de sais nos corpos hídricos. Sob condições de salinidade, processos como, crescimento e produção das plantas são afetados negativamente. Contudo, a adubação potássica pode ser uma alternativa viável que possibilite a mitigação dos efeitos deletérios dos sais sobre as culturas. Objetivou-se avaliar a síntese de pigmentos fotossintéticos do maracujazeiro-azedo ‘BRS Gigante-amarelo’ irrigado com águas salinas e adubação potássica. O experimento foi realizado sob condições de campo na fazenda experimental da Universidade Federal de Campina Grande, em São Domingos, Paraíba. Adotou-se o delineamento em blocos casualizados, em esquema fatorial 5 × 4, sendo cinco níveis de condutividade elétrica da água de irrigação - CEa (0,3; 1,1; 1,9; 2,7 e 3,5 dS m-1) e quatro doses de potássio - DK (60; 80; 100 e 120% da recomendação de K2O) com três repetições. O aumento da condutividade elétrica da água de irrigação ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10806', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c926', 'Crescimento e fitomassa de genótipos de algodoeiro de fibra naturalmente colorida sob turnos de rega', 'Santos, José Rubens Casuza; Ferreira, Ana Paula Nunes; Almeida, Evanilson Souza de; Lima, Geovani Soares de; Nobre, Reginaldo Gomes; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'A escassez hídrica é um fator limitante para o setor agrícola, ocasionando limitação no cultivo de algodão, fazendo-se necessária a adoção de estratégias de irrigação que viabilizem sua produção. Neste contexto, objetivou-se avaliar o crescimento e acúmulo de fitomassa de genótipos de algodoeiro de fibra colorida sob turnos de rega. A pesquisa foi realizada na Fazenda Experimental Rolando Enrique Rivas Castellón da Universidade Federal de Campina Grande (UFCG), localizada no município de São Domingos, Paraíba. O delineamento foi em blocos casualizados, em esquema fatorial 3 × 4, sendo três genótipos de algodoeiro de fibra colorida (‘BRS Rubi’, ‘BRS Jade’ e ‘BRS Safira’) e quatro turnos de rega (3, 6, 9 e 12 dias), com três repetições e 20 plantas por parcela, sendo duas plantas por cova. As plantas foram avaliadas quanto a área foliar, altura de plantas, fitomassa seca do caule e fitomassa seca da parte aérea. ‘BRS Rubi’ apresentou maior crescimento em altura de plantas e acúmulo de fi', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10808', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c92d', 'Teores de açúcares em frutos de bananeira cultivada sob déficit hídrico de irrigação e aplicação de ácido giberélico', 'Nascimento, Patrick Lima do; Souza, Cícero Jardel Praça de; Medeiros, Brencarla; Paiva, Francisco Jean da Silva; Lima, Geovani Soares de; Soares, Lauriane Almeida dos Anjos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O uso do ácido giberélico pode ser uma alternativa viável para o controle da maturação dos frutos, possibilitando assim um maior tempo de prateleira. Objetivou-se avaliar o efeito do ácido giberélico sob a maturação de frutos de bananeira cv. Nanicão, cultivada sob estratégias de manejo do déficit hídrico. Os frutos foram produzidos na Fazenda Experimental ‘Rolando Enrique Rivas Castellón’ pertencente ao Centro de Ciências e Tecnologia Agroalimentar – CCTA, da Universidade Federal de Campina Grande – UFCG. Utilizou-se o delineamento inteiramente casualizado, em esquema fatorial 3 × 2, sendo três estratégias de manejo da irrigação com déficit hídrico nas fases fenológicas – EM (sem estresse hídrico – Irrigação plena durante todo o ciclo de cultivo (100% da evapotranspiração da cultura - ETc); déficit hídrico (50% da ETc) na fase juvenil; e na fase de frutificação) e dois métodos de conservação dos frutos (com e sem ácido giberélico). Foram analisados açúcares redutores, não redutores e ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10816', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c92e', 'Partição de biomassa em plantas de rabanete suplementadas com magnésio foliar sob restrição hídrica', 'Martins, Viviane Silva; Cavalcante, Diogo Santos; Linhares, Paulo Cássio Alves; Gomes, Rayane Nunes; Barros, Milena Emanuela de Jesus; Rego, Gabriel Sidharta dos Santos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo da pesquisa foi avaliar a ação do magnésio (Mg) suplementar para atenuar os efeitos do déficit hídrico no acúmulo de biomassa de plantas de rabanete. Foi conduzido um experimento, em delineamento de blocos casualizados, com 6 tratamentos (n= 6). Os tratamentos (T) foram: Mg foliar (sem: Mg0% e com: Mg2%) em plantas de rabanete sob condições hídricas [irrigado e déficit hídrico (DH)], com base na capacidade de campo (CC): T1 = Irrigado + Mg0%; T2 = Irrigado + Mg2%; T3 = DH50%CC + Mg0%; T4 = DH50%CC + Mg2%, T5 = DH30%CC + Mg0% e T6 = DH30%CC + Mg2%. Foram avaliadas as seguintes características: acúmulo de massa seca da raiz (MSR), parte aérea (MSPA) e total (MST), e relação raiz/parte aérea (R/PA). Não houve diferença significativa entre os tratamentos testados para a MSPA e MST. O T4 apresentou maior MSR. Para a R/PA apenas o T2 apresentou os menores valores. Assim, o Mg2% foliar promoveu maior partição de biomassa e acúmulo de massa seca em plantas de rabanete em condições d', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10817', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c931', 'Biomassa e tolerância do maracujazeiro sob estresse salino e silício', 'Sá, Francisco Vanies da Silva; Medeiros-Sá, Rita de Cássia Nascimento; Linhares, Paulo Cássio Alves; Dantas, Lucas David Vieira; Lima, Alisson Serafim de; Barbosa, Luan Cordeiro de Souza', 'Editora Verde', 'Agriculture', 'Agriculture', 'O estresse salino é um risco para o cultivo do maracujazeiro no semiárido brasileiro. Com isso, objetivou-se avaliar o acúmulo de biomassa e tolerância ao estresse salino do maracujazeiro amarelo cv. ‘SCS437 Catarina’ na fase inicial de desenvolvimento. O delineamento experimental usado foi o de inteiramente casualizado, composto por três tratamentos: T1 - água de 0,3 dS m-1 (Testemunha), T2 - água de 2,5 dS m-1 e T3 - água de 2,5 dS m-1 + 3,5 g de CaSiO3, com cinco repetições. As plantas foram cultivadas em sacos plásticos contendo 1 dm3 de solo durante 30 dias. As plantas do maracujazeiro cv. ''SCS437 Catarina'' foram avaliadas quanto à massa seca da parte aérea, massa seca da raiz, índice de tolerância da parte aérea e da raiz. O aumento da salinidade da água diminuiu em 50,1% e 34,9% a massa seca da parte aérea e a massa seca da raiz do maracujazeiro. A irrigação com água salina de 2,5 dS m-1 diminui o acúmulo de biomassa da parte aérea e da raiz do maracujazeiro cv. ''SCS437 Catarina', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10821', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798affed6a63682f044c932', 'Crescimento inicial de cultivares de mamoeiro sob estresse salino', 'Oliveira, Alexandre Xavier de; Sá, Francisco Vanies da Silva; Silva Júnior, Janildo Pereira da; Santos, Maria Cecília Aquino dos; Rego, Gabriel Sidharta dos Santos; Medeiros-Sá, Rita de Cássia do Nasc', 'Editora Verde', 'Agriculture', 'Agriculture', 'O estresse salino é um risco para o cultivo do mamoeiro no semiárido brasileiro. Com isso, objetivou-se avaliar o crescimento inicial de cultivares de mamoeiro sob estresse salino. A pesquisa foi desenvolvida em casa de vegetação. O delineamento experimental usado foi o inteiramente casualizado, em esquema fatorial 2 x 2, com quatro repetições. O fator 1 é composto por duas cultivares mamoeiro (C1- Formosa (Sunrise Formosa) e C2 - Havaí (Sunrise Solo)), e o segundo fator foi composto por dois níveis de salinidade (0,3 e 2,5 dS m-1). As plantas foram cultivadas em sacos plásticos contendo 1 dm3 de solo durante 30 dias. As plantas de mamoeiro foram avaliadas quanto à altura, diâmetro do caule, número de folhas e comprimento da raiz. A água salina de 2,5 dS m-1 diminui a altura, diâmetro do caule e comprimento da raiz da cultivar Sunrise Formosa e diminuiu o número de folha e comprimento da raiz da Sunrise Solo. A cultivar Sunrise Formosa é mais vigorosa que Sunrise Solo. A cultivar Sunri', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10822', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c93c', 'Um Uso do Mel em Formulações Farmacêuticas: Desafios e Perspectivas', 'Ventura, Samuel; Araújo Gurjão, Thyago; Romero da Mota Sousa, Francisco de Assys; Lenner, Mateus', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10857', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c93d', 'Uso de geléia real como imunomodulador: Revisão', 'Costa Furtado, Bruna; Gurjão, Thyago Araújo; Farias do Nascimento, Enzo Gabriel; Queiroz Lima, Sara Felícia; de A. Espíndola, Júlio César; Barbosa Claudino, Luan; Oliveira dos Santos , Rachel', 'Editora Verde', 'Agriculture', 'Agriculture', 'Estudos mostram que as abelhas são responsáveis por cerca de até dois terços dos alimentos produzidos no mundo e que elas têm papel fundamental na produção de oxigênio, em razão de sua significativa ação polinizadora. Abelhas têm muita relação com melhora da imunidade, pois muito do que elas produzem favorecem a saúde e bem-estar. Elas são responsáveis pela produção de mel, da própolis e da geleia real. Para a tradicional e milenar medicina chinesa, o mel pode tratar várias partes do corpo. O mel contém proteínas, vitaminas e sais minerais. O mel tem alto potencial energético, o mel é muito nutritivo e tem função antibacteriana.&nbsp; As funções do mel são diversas, o mel é usado na prevenção e tratamento de doenças respiratórias, aplicado na saúde estomacal, favorece a cicatrização e publicações e dados mostram que o mel ajuda o sistema imunológico. As abelhas produzem mel e coletam na vegetação resinas para produzirem a própolis — as abelhas usam a própolis para protegerem a colmeia ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10864', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c93f', 'Varroa destructor: Ameaça Persistente à Apicultura Mundial', 'Alves, Edson Henrique Cabral; Queiroz, Fernanda Rodrigues de; Sousa, Francisco de Assys Romero da Mota; Gurjao, Thyago Araújo; Oliveira, Larissa Silva Nelo; Chaves, Franc Jand Macêdo; Barros, Keila Ta', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10869', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c940', 'Uso da geleia real como estimulante de hormônios precursores do ciclo estral', 'Gurjao, Thyago Araújo; Silva, Djailton Ferreira da; Souza, Francisco de Assys Romero da Mota; Araújo Neto, Adauto Graciano de; Oliveira, Larissa Silva Neto; Vicente, Stefani Silva; Silva, Edilson De S', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10879', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c945', 'A importância da multiplicação de rainhas na apicultura:  uma estratégia de impacto na saúde da colônia', 'dos Santos Neta, Maria Luiza; Silva Nelo Oliveira, Larissa; Araújo Gurjão, Thyago; Santos De Souza, Lara; Martins, Rebeca; Ouriques Nascimento, Maria Clara; Duarte da Silva, Carlos Andrey; Henrique Ma', 'Editora Verde', 'Agriculture', 'Agriculture', 'O conhecimento da criação de abelhas faz parte do estudo das formas de criação dos animais sendo de grande importância quanto a multiplicação de rainhas, tendo em vista que o apicultor garante o bom desempenho de produção da colmeia. Através da multiplicação haverá melhores condições no processo de polinização das flores, tendo por consequência um maior rendimento para o produtor e maior produção das culturas frutíferas de grande importância econômica. Como estratégia de melhoramento na produção da colmeia, tem por seguinte a implantação de novas rainhas somando com as demais do apiário. Vale destacar que faz-se necessário uma maior atenção na introdução de uma rainha jovem à colônia, sendo realizada uma boa seleção genética para haver um retorno positivo para o apicultor. Além disso, é importante citar que a multiplicação de rainhas na apicultura tem uma ação positiva na resistência contra pragas e doenças, oferecendo também um campo de segurança para a colônia em situações de frio ou', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10899', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c947', 'Acidentes anafiláticos em cães e gatos: Papel do sistema imunológico frente a picadas de abelhas', 'Silva Nelo Oliveira , Larissa; Luiza dos Santos Neta , Maria; Andrey Duarte Da Silva, Carlos; Araújo Gurjão, Thyago; de Assys Romero da Mota Sousa, Francisco; Santos de souza, Lara; Martins Pinto, Reb', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10913', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c94a', 'Alterações arteriais na reação anafilática por picada de abelha: uma abordagem clínica', 'Luiza dos Santos Neta, Maria; Andrey Duarte Da Silva, Carlos; Silva Nelo Oliveira, Larissa; Araújo Gurjão, Thyago; de Assys Romero da Mota Sousa, Francisco; Santos de souza, Lara; Martins Pinto, Rebec', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10917', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c94c', 'Importância da Suplementação de Neonatos com Geleia Real', 'Gurjão, Thyago Araújo; Adauto Graciano de Araújo Neto; Edilson de Sousa da Silva; Djailton Ferreira da Silva; Stefani Silva Vicente; Mascarenhas, Nágela Maria Henrique; Oliveira, Larissa Silva Nelo; S', 'Editora Verde', 'Agriculture', 'Agriculture', 'A geleia real, secreção produzida pelas glândulas hipofaríngeas das abelhas operárias, é conhecida por suas propriedades nutricionais e terapêuticas. Este estudo investiga a importância da suplementação de neonatos de abelhas com geleia real, enfocando seus impactos no desenvolvimento e na saúde das colônias. A pesquisa foi conduzida em apiários comerciais, onde grupos de colônias receberam diferentes regimes de suplementação com geleia real durante o período crítico do desenvolvimento das larvas. Os resultados mostram que a suplementação com geleia real promove um crescimento mais rápido e uniforme dos neonatos, aumentando a eficiência na conversão alimentar e a robustez das abelhas jovens. Além disso, observou-se uma melhoria na resistência a doenças e um aumento significativo na produção de mel e na atividade das colônias. O estudo também revela que a suplementação contribui para uma maior longevidade das abelhas operárias, influenciando positivamente a sustentabilidade das colônias', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10931', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c94f', 'Elevação da Temperatura e Sua Influência no Desconforto das Colmeias', 'Gurjão, Thyago Araújo; Enzo Gabriel; Djailton Ferreira da Silva; Stefani Silva Vicente; Luan; Adauto Graciano de Araújo Neto', 'Editora Verde', 'Agriculture', 'Agriculture', 'A elevação da temperatura é um fator climático que pode impactar significativamente o bem-estar e a produtividade das colmeias. Esta revisão examina como o aumento das temperaturas ambientais afeta o conforto das colônias de abelhas e a consequentemente a produção de mel. O aumento das temperaturas pode levar a uma série de problemas para as colônias, incluindo estresse térmico, que compromete a capacidade das abelhas de manter a temperatura interna ideal da colmeia. Esse desconforto pode reduzir a eficiência da coleta de néctar e a produção de mel, além de afetar negativamente a saúde das abelhas. O estresse térmico também pode influenciar o comportamento das abelhas, resultando em uma menor capacidade de defesa contra predadores e parasitas. A revisão inclui análises de estudos que mostram que colônias expostas a temperaturas elevadas têm uma maior taxa de mortalidade e um declínio na qualidade do mel produzido. Além disso, abordamos estratégias de manejo que podem ajudar a mitigar e', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10934', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c952', 'A importância da suplementação para abelhas', 'Lucena, André Luís do Bú; Diniz, João Victor Guedes; Gurjão, Thyago Araújo; Porto Filho, José Matias; Oliveira, Larissa Silva Neto; Segundo Neto, Américo Porto; Carneiro, Fernando Henrique da Cruz; So', 'Editora Verde', 'Agriculture', 'Agriculture', 'A suplementação alimentar para abelhas é uma prática essencial em períodos de escassez de recursos naturais, como néctar e pólen. Durante o inverno ou em áreas com baixa diversidade floral, as abelhas podem enfrentar desnutrição, o que afeta diretamente sua saúde e produtividade. A suplementação pode ser feita com açúcares (xarope de açúcar ou fondant) e substitutos de pólen, garantindo que as colônias mantenham reservas adequadas de energia e proteínas. A nutrição adequada impacta na longevidade das abelhas, no desenvolvimento das crias e na capacidade da colônia de resistir a patógenos e parasitas, como o ácaro Varroa destructor. Além disso, a suplementação pode melhorar o desempenho das colmeias na produção de mel e na polinização agrícola, aumentando a eficiência dos serviços ecossistêmicos prestados pelas abelhas. No entanto, a composição e a qualidade dos suplementos devem ser cuidadosamente ajustadas para evitar desequilíbrios nutricionais e efeitos adversos à saúde das colônias', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10937', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c953', 'Salmonelose, um problema na falta de manejo da colmeia e do mel', 'André Luiz do Bú Lucena; Gurjão, Thyago Araújo; Fernando Henrique; Américo Porto; João Victor', 'Editora Verde', 'Agriculture', 'Agriculture', 'A salmonelose, uma infecção bacteriana causada pelo gênero Salmonella, pode representar um risco significativo à segurança do mel e à saúde pública quando práticas inadequadas de manejo das colmeias e do processamento do mel são adotadas. Embora a presença de Salmonella em produtos apícolas seja rara, sua contaminação pode ocorrer através do contato com superfícies, equipamentos ou água contaminada durante a colheita, processamento ou armazenamento do mel. Além disso, condições insalubres no apiário, falta de higiene no manuseio do mel, ou manejo inadequado das colmeias podem contribuir para a proliferação de patógenos, incluindo a Salmonella. A infecção pode resultar em problemas graves de saúde humana, como intoxicações alimentares, e comprometer a comercialização do mel. Dessa forma, práticas de manejo rigorosas e protocolos de higiene são cruciais para prevenir a contaminação, preservando a qualidade do mel e garantindo sua segurança para o consumo. A implementação de boas práticas', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10938', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c959', 'Acariose e suas atividades parasitárias dentro de colmeias de abelhas  Apis Mellifera', 'Franc Jand Macedo Chaves; Nagela Maria Henrique Mascarenhas; Rodrigues de Queiroz, Fernanda; Edson Henrique Cabral Alves; Francisco de Assys Romero da Mota Sousa; Thyago Araújo Gurjão; Jullyana Duarte', 'Editora Verde', 'Agriculture', 'Agriculture', 'A acariose em abelhas Apis Mellifera mostra que essa condição, está especialmente relacionada ao ácaro Acarapis wood,
pode causar sérios problemas nas colmeias, como a redução da imunidade, diminuição do peso e da longevidade das
abelhas, além de contribuir para a disseminação de doenças. No Brasil os casos graves de acariose ainda são considerados
raros, mas há indícios de aumento na taxa de infestação, o que exige vigilância constante dos apicultores. Além do
Acarapis wood e Varroa destructor, foram relatadas infestações por outros ácaros, como larvas de Leptus sp. e
Tyrophagus putrescentiae, embora o impacto direto desses parasitas sobre a mortalidade das colônias ainda seja objeto de
estudo. A infestação por Leptus sp. foi observada em abelhas operárias em São José dos Campos, SP, enquanto T.
putrescentiae foi encontrado em colmeias no Sul do Brasil. Esses ácaros podem se associar ao enfraquecimento das
colônias, No ácaro Acarapis wood que vive nas traqueias torácicas das abelhas, ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10951', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c964', 'Benefícios da conectividade das colmeias para o bem-estar das abelhas', 'Mascarenhas, Nágela Maria Henrique', 'Editora Verde', 'Agriculture', 'Agriculture', 'Promover o bem-estar das abelhas envolve criar e manter um ambiente que suporte a conectividade física e ecológica das colmeias. Colmeias localizadas em ambientes bem conectados, com acesso a recursos e condições adequadas, tendem a experimentar menos estresse. Isso é crucial para a saúde das abelhas, pois o estresse pode afetar a cognição e o comportamento das abelhas. A conectividade permite um gerenciamento mais eficiente das colônias, reduzindo problemas como falta de alimento e exposição a patógenos. A comunicação entre colmeias e a coordenação de recursos contribuem para a eficiência na coleta de néctar e pólen, além de melhorar a saúde geral das colônias. Colmeias em ambientes conectados têm maior resiliência a choques ambientais e doenças, devido à diversidade e à colaboração entre diferentes colônias. Uma rede de colmeias situadas em áreas com diversidade floral oferece uma variedade de fontes de alimento. Isso é crucial para a saúde das abelhas, pois proporciona uma dieta equ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10967', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b001d6a63682f044c968', 'Abelhas felizes e saudáveis vivem em colmeias conectadas', 'Mascarenhas, Nágela Maria Henrique', 'Editora Verde', 'Agriculture', 'Agriculture', 'O conceito de que "abelhas felizes e saudáveis vivem em colmeias conectadas" pode ser interpretado tanto no sentido literal quanto figurado. Nesse resumo foi abordado uma visão abrangente sobre como a conectividade das colmeias e o ambiente afetam o bem-estar das abelhas. Em algumas regiões, a proximidade entre colmeias pode facilitar o acesso a recursos como néctar e pólen, que são essenciais para a saúde das colônias. Colmeias que estão em áreas próximas podem compartilhar informações sobre fontes de alimentos através de sinais químicos e comportamentais. O apoio mútuo entre as colônias também influência na conectividade, pois, colônias próximas podem beneficiar-se umas das outras, especialmente em termos de controle de parasitas e doenças. A presença de várias colônias pode reduzir a pressão de patógenos, uma vez que a diversidade genética e a troca de informações entre as abelhas podem fortalecer a resistência geral. Quando o assunto é a infraestrutura de manejo dos apiários, o uso', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/10971', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c971', 'Avaliação das condições higiênico-sanitárias das lanchonetes de um campus universitário de Governador Valadares-MG', 'SILVA, Marcela P.; ANDRADE, Hianna M. C.; VILELA, Anderson F.; MIRANDA, Ana P. P.; FERNANDES, Wellington L.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os alimentos s&atilde;o essenciais &agrave; vida, pois, al&eacute;m de regularem fun&ccedil;&otilde;es org&acirc;nicas, fornecem combust&iacute;vel e material de constru&ccedil;&atilde;o para reparo dos tecidos. A alimenta&ccedil;&atilde;o refere-se ao fornecimento de todas as subst&acirc;ncias necess&aacute;rias para o crescimento, manuten&ccedil;&atilde;o e reprodu&ccedil;&atilde;o do organismo. Apesar de todo conhecimento cient&iacute;fico alcan&ccedil;ado, ainda hoje pesquisas apontam que as doen&ccedil;as veiculadas por alimentos s&atilde;o as que t&ecirc;m maior propaga&ccedil;&atilde;o e que os agentes biol&oacute;gicos representam a principal causa. Uma forma de controlar a contamina&ccedil;&atilde;o de alimentos por esses agentes s&atilde;o as Boas Pr&aacute;ticas de Fabrica&ccedil;&atilde;o (BPF), que s&atilde;o cuidados higi&ecirc;nico-sanit&aacute;rios de produ&ccedil;&atilde;o de alimentos de maneira mais segura para o consumidor. Assim, o presente estudo foi realizado nas', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1001', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c975', 'Desenvolvimento e aceitabilidade de bolos de cenoura adicionados de ingredientes funcionais', 'PEREIRA, Tamires S.; LOPES, Maíra F.; FERNANDES, Ítala M. V.; SANTOS, Adriana F.; MOREIRA, Flávia I. N.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os alimentos funcionais s&atilde;o aqueles que colaboram para melhorar o metabolismo e prevenir problemas de sa&uacute;de. O interesse dos consumidores por alimentos que al&eacute;m de nutrir promovam benef&iacute;cios &agrave; sa&uacute;de tem aumentado nos &uacute;ltimos anos, destacando-se o interesse principalmente pelos alimentos funcionais. A combina&ccedil;&atilde;o de soja com cereais &eacute; desej&aacute;vel, pois, al&eacute;m de adequado balanceamento de amino&aacute;cidos essenciais, pode-se obter sabor e aroma mais agrad&aacute;veis. Este trabalho visou formular e avaliar sensorialmente bolos de cenoura elaborados com diferentes ingredientes funcionais. Os bolos foram preparados utilizando farinha de trigo, cenoura, &oacute;leo de soja, e a&ccedil;&uacute;car cristal, constituindo a massa b&aacute;sica (F1), a outra amostra foi acrescida de ingredientes funcionais, farinha de soja e granola (F2). As formula&ccedil;&otilde;es foram processadas no Laborat&oacute;rio de Tecno', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1007', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c976', 'Avaliação sensorial de marcas de bebida láctea comercializadas na cidade de Solânea–PB', 'PENA, Jefferson C.; OLIVEIRA, Renan E. S.; SANTOS, Thiago E. S.; SANTOS, Damara I. S.; FIGUEIREDO, Maria J.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A an&aacute;lise sensorial vem se destacando com uma ferramenta eficaz na avalia&ccedil;&atilde;o da aceita&ccedil;&atilde;o de produtos por consumidores. As bebidas l&aacute;cteas fermentadas apresentam-se expostas ao mercado atrav&eacute;s de diversas marcas, as quais implantam caracter&iacute;sticas que podem diferencia-las dos concorrentes. Assim, o objetivo deste trabalho foi avaliar as caracter&iacute;sticas sensoriais de marcas de bebidas l&aacute;cteas comercializadas no munic&iacute;pio de Sol&acirc;nea&ndash;PB. As an&aacute;lises foram desenvolvidas no Laborat&oacute;rio de An&aacute;lise Sensorial do Centro de Ci&ecirc;ncias Humanas, Sociais e Agr&aacute;rias &ndash; UFPB, Campus III Bananeiras. Foram realizadas coletas de tr&ecirc;s marcas comerciais de bebida L&aacute;ctea em diferentes locais de comercializa&ccedil;&atilde;o avaliando lote, data de fabrica&ccedil;&atilde;o e estado de conserva&ccedil;&atilde;o do produto. O quadro de an&aacute;lise foi composto por 45 me', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1008', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c978', 'Bebida mista de cajá e água de coco: Estudo de aceitabilidade', 'FERNANDES, Ítala; LOPES, Maíra; SÁ, Fabiana; SILVA, Francegildo S.; COSTA, Josimária', 'Editora Verde', 'Agriculture', 'Agriculture', 'A ind&uacute;stria, cada vez mais consciente do potencial brasileiro como produtor de frutas no mundo, est&aacute; se beneficiando da tecnologia para investir num mercado crescentemente em expans&atilde;o: o de sucos prontos. Diante desta perspectiva, a formula&ccedil;&atilde;o de bebidas mistas, pode ser utilizada como uma alternativa para melhorar as caracter&iacute;sticas nutricionais de determinados sucos, pela complementa&ccedil;&atilde;o de nutrientes fornecidos por frutas diferentes. A elabora&ccedil;&atilde;o de uma bebida mista &agrave; base de &aacute;gua-de-coco al&eacute;m fornecer um produto de sabor diferenciado, pode tornar-se uma boa op&ccedil;&atilde;o de utiliza&ccedil;&atilde;o destes frutos, principalmente da &aacute;gua-de-coco, que &eacute; altamente perec&iacute;vel e de sabor delicado muito sens&iacute;vel ao tratamento t&eacute;rmico e a a&ccedil;&atilde;o de aditivos quando conservada isoladamente pelos m&eacute;todos tradicionais, al&eacute;m disso, a &aacute', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1012', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c979', 'Análise sensorial de hambúrguer produzido com carne de camarão (Litopenaeusvannamei): Shrimpburg', 'LIMA, Marília; ROCHA, Simone; SOUSA, Elton; FIGUEIREDO, Maria; FABRÍCIO, Gizelda', 'Editora Verde', 'Agriculture', 'Agriculture', 'O hamb&uacute;rguer, principal integrante dos mais variados sanduiches &eacute; o produto c&aacute;rneo industrializado obtido da carne mo&iacute;da de animais de a&ccedil;ougue, moldado e submetido a processo tecnol&oacute;gico adequado. O pescado por sua vez &eacute; um alimento saud&aacute;vel de reconhecida perecibilidade, todavia, o camar&atilde;o, um dos principais representantes deste setor apresenta enormes dificuldades em manter o seu mercado. Este trabalho objetivou analisar a aceitabilidade de um hamb&uacute;rguer produzido com carne de camar&atilde;o. Para o estudo, foram produzidos hamb&uacute;rgueres de camar&atilde;o, que depois de devida comprova&ccedil;&atilde;o de qualidade f&iacute;sico-qu&iacute;mica e microbiol&oacute;gica foram submetidos &agrave; an&aacute;lise sensorial. O teste foi realizado no Laborat&oacute;rio de Desenvolvimento e An&aacute;lise Sensorial de Alimentos da UFPB, em cabines individuais com 70 potenciais consumidores. Foi utilizada uma escala he', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1013', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c97f', 'Estudo microbiológico da farinha de banana (Musa sapientum L.): Cultivar prata', 'COSTA, Ruann R.; SILVA, Kívia A. G.; MONTEIRO, Roberta P.; ARAÚJO, Aline K. P.; ASSIS NETO, Erasto F.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Brasil &eacute; o 2&deg; maior produtor mundial de banana, com ampla dissemina&ccedil;&atilde;o da cultura em seu territ&oacute;rio. Economicamente, a banana destaca-se como a segunda fruta mais importante em &aacute;rea colhida, quantidade produzida, valor da produ&ccedil;&atilde;o e consumo. &Eacute; cultivada por grandes, m&eacute;dios e pequenos produtores, sendo 60% da produ&ccedil;&atilde;o proveniente da agricultura familiar. Os alimentos podem veicular diversos microrganismos patog&ecirc;nicos, e essa contamina&ccedil;&atilde;o representa um perigo &agrave; sa&uacute;de p&uacute;blica, motivo de preocupa&ccedil;&atilde;o dos &oacute;rg&atilde;os de vigil&acirc;ncia sanit&aacute;ria, caso as condi&ccedil;&otilde;es de higiene durante o processamento sejam inadequadas. A elabora&ccedil;&atilde;o de novos produtos aliment&iacute;cios ou o enriquecimento de produtos de panifica&ccedil;&atilde;o, por exemplo, &eacute; uma proposta valida &agrave; promo&ccedil;&atilde;o da sa&uacut', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1020', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c981', 'Avaliação nutricional de escolares da cidade de Governador Valadares-MG', 'MORAIS, Ana C. A.; SIQUEIRA, Camila R. A.; CABRAL, Amanda D.; SANTOS, Juliana B. B.; NACIMENTO, Carolina T.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O estado nutricional de uma crian&ccedil;a possui papel fundamental para que seu crescimento seja progressivo. Logo, altera&ccedil;&otilde;es de d&eacute;ficit ou excesso implicam em riscos potenciais de agravos &agrave; sa&uacute;de dessas crian&ccedil;as, bem como em futuros problemas de rela&ccedil;&otilde;es interpessoais e funcionais dentro da comunidade. Este trabalho avaliou o estado nutricional de escolares, utilizando vari&aacute;veis antropom&eacute;tricas, particularmente o peso e a estatura em associa&ccedil;&atilde;o com a faixa et&aacute;ria e com o g&ecirc;nero. A popula&ccedil;&atilde;o estudada foi composta de 71 crian&ccedil;as de seis a nove anos, sendo 37 crian&ccedil;as com seis anos, 30 crian&ccedil;as com sete anos, tr&ecirc;s crian&ccedil;as com oito anos e uma crian&ccedil;a com nove anos, matriculadas na Escola Municipal Pio XII em Governador Valadares-MG. A massa corporal foi obtida com os escolares descal&ccedil;os em uma balan&ccedil;a digital. Para a medi&', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1022', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c985', 'Diagnóstico de local de preparo da alimentação escolar na Zona rural do município de Solânea-PB', 'ATAÍDE, Celene S.; ANDRADE, Romário O.; MENEZES, Keliana G.; COSTA, Jaqueline M.; FIGUEIREDO, Maria J.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A obten&ccedil;&atilde;o de alimentos seguros est&aacute; diretamente relacionada &agrave;s condi&ccedil;&otilde;es em que estes s&atilde;o preparados. O objetivo deste trabalho &eacute; realizar o diagn&oacute;stico dos locais de preparo da alimenta&ccedil;&atilde;o escolar da Zona rural do munic&iacute;pio de Sol&acirc;nea-PB, &nbsp;atrav&eacute;s da aplica&ccedil;&atilde;o de check list baseado na Resolu&ccedil;&atilde;o RDC 275 da ANVISA. Verificaram-se altos &iacute;ndices de n&atilde;o conformidades, analisando-se &agrave;s edifica&ccedil;&otilde;es e instala&ccedil;&otilde;es verificou-se em 71,4% das escolas a presen&ccedil;a de objetos estranhos ao ambiente, inexist&ecirc;ncia de &acirc;ngulos abaulados entre paredes e teto (100%), a falta de lavat&oacute;rios de uso exclusivo e de instala&ccedil;&otilde;es sanit&aacute;rias para os manipuladores (100%); aus&ecirc;ncia de divis&otilde;es no local de preparo dos alimentos (100%). Em 85,7% das escolas a ilumina&ccedil;&atilde;o ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1027', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c989', 'Avaliação microbiológica da água consumida por comunidade rural do município de Pombal - PB', 'MARTINS, Wiaslan F.; ARAUJO, Alfredina dos S.; FARIAS, Natália S. de; SULINO, Reginaldo F.; Cavalcanti, Mônica Tejo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Embora seja um elemento essencial &agrave; vida, a &aacute;gua tamb&eacute;m pode trazer riscos &agrave; sa&uacute;de se for de m&aacute; qualidade, servindo de ve&iacute;culo para v&aacute;rios agentes biol&oacute;gicos e qu&iacute;micos. As doen&ccedil;as de veicula&ccedil;&atilde;o h&iacute;drica s&atilde;o causadas, principalmente, por microrganismos patog&ecirc;nicos de origem ent&eacute;rica, animal ou humana, transmitidos basicamente pela rota fecal-oral e ingeridos na forma de &aacute;gua ou alimento contaminado. Os coliformes termotolerantes s&atilde;o bact&eacute;rias de um subgrupo dos coliformes totais e a Escherichia coli &eacute; o principal representante de origem exclusivamente fecal. As linhagens patog&ecirc;nicas podem causar desde diarr&eacute;ia, febre, c&oacute;lica, v&ocirc;mito, calafrios, e mal estar, at&eacute; graves quadros de diarr&eacute;ia sanguinolenta. A utiliza&ccedil;&atilde;o de testes para a determina&ccedil;&atilde;o de indicadores de contamina&cced', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1032', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c98a', 'Análise físico-química de queijo ralado comercializado em Bananeiras-PB', 'GOMES, Luam; ANDRADE, Romário O.; TOMÉ, Lucas; BELTRÃO, Fabiana; OLIVEIRA, Saul', 'Editora Verde', 'Agriculture', 'Agriculture', 'Queijo ralado &eacute; o produto obtido por esfarelamento ou ralagem da massa de uma ou at&eacute; quatro variedades de queijos de baixa umidade aptos para o consumo humano, podendo ser parcialmente desidratado ou n&atilde;o. Objetivou-se neste trabalho avaliar a qualidade f&iacute;sico-qu&iacute;mica de queijos ralados comercializados no Munic&iacute;pio de Bananeiras-PB. Amostras de queijo ralado com denomina&ccedil;&atilde;o de origem certificada pelo Servi&ccedil;o de Inspe&ccedil;&atilde;o Federal (SIF) foram adquiridas ao acaso, no per&iacute;odo Setembro 2010, em tr&ecirc;s estabelecimentos comerciais em Bananeiras-PB. Foram coletadas 5 marcas diferentes, onde amostras foram analisadas quanto aos par&acirc;metros f&iacute;sico-qu&iacute;micos de qualidade: teores de umidade, pH,&nbsp; acidez, prote&iacute;nas, lip&iacute;deos. Observou-se que todas as marcas analisadas s&atilde;o constitu&iacute;das de queijo parmes&atilde;o, 90% de queijo tropical, 80% de queijo parmes&atilde;o', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1034', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c98b', 'Avaliação físico-química e microbiológica de carne de camarão cultivado (Litopenaeus vannamei)', 'LIMA, Marília; ROCHA, Simone; SOUSA, Elton; FIGUEIREDO, Maria; FABRÍCIO, Gizelda', 'Editora Verde', 'Agriculture', 'Agriculture', 'O termo gen&eacute;rico "pescado" compreende os peixes, crust&aacute;ceos, moluscos, anf&iacute;bios, quel&ocirc;nios e mam&iacute;feros de &aacute;gua doce ou salgada, usados na alimenta&ccedil;&atilde;o humana. Nesta perspectiva, segundo estimativas da Organiza&ccedil;&atilde;o da Agricultura e Alimenta&ccedil;&atilde;o (FAO), houve um crescimento significativo no com&eacute;rcio mundial de pescado e de seus produtos nos &uacute;ltimos 10 anos. O cultivo de camar&atilde;o &eacute; uma das atividades econ&ocirc;micas que mais crescem em v&aacute;rios pa&iacute;ses do mundo. Dada a import&acirc;ncia do camar&atilde;o para a economia do Brasil e as exig&ecirc;ncias cada vez mais acentuadas dos pa&iacute;ses importadores, quanto &agrave; qualidade do produto final, faz-se necess&aacute;rio o desenvolvimento e aprimoramento de t&eacute;cnicas de processamento p&oacute;s-colheita dos camar&otilde;es cultivados. Dessa forma, visando a identifica&ccedil;&atilde;o de mat&eacute;ria-prima com ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1035', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c98c', 'Estudo de composição físico-química da farinha de Cenoura', 'MOREIRA, Diego; ARAÚJO, Aline; COSTA, Ruann; DAMIÃO, Felipe; SILVA, Kívia', 'Editora Verde', 'Agriculture', 'Agriculture', 'As cenouras (Daucus carota L.) s&atilde;o grandes fontes de&nbsp;fibra&nbsp;diet&eacute;tica,&nbsp;antioxidantes, minerais e &beta;-caroteno. Este &uacute;ltimo, respons&aacute;vel pela colora&ccedil;&atilde;o alaranjada caracter&iacute;stica do vegetal, &eacute; uma provitamina A, Ele ajuda o desempenho dos receptores da&nbsp;retina, melhorando a&nbsp;vis&atilde;o. Tamb&eacute;m ajuda a manter o bom estado da&nbsp;pele&nbsp;e das&nbsp;mucosas. A vitamina a suficiente para o ser humano, pode se alcan&ccedil;ar na contagem de cem gramas de cenoura diariamente.&Agrave; produ&ccedil;&atilde;o de farinhas apresenta grande variabilidade para a ind&uacute;stria de alimentos, principalmente em produtos de panifica&ccedil;&atilde;o, produtos diet&eacute;ticos e alimentos infantis, por serem rica fonte de amido e sais minerais. A obten&ccedil;&atilde;o da farinha de cenoura e apontada por muitos trabalhos com uma sa&iacute;da para aumentar as propriedades nutricionais de muitos produtos. O obje', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1036', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c98e', 'Caracterização físico-química da banana prata verde (Musa ssp)', 'ARAÚJO, Alfredina; CAVALCANTI, Mônica; FARIAS, Verlânia; SULINO, Reginaldo; ALMEIDA, Maria C.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A banana prata (Musa spp) &eacute; uma das frutas que mais se destaca no mundo devido a sua composi&ccedil;&atilde;o e ampla comercializa&ccedil;&atilde;o. A banana prata verde, al&eacute;m de possuir uma vida mais longa do que o fruto j&aacute; maduro, &eacute; um produto com elevado teor de carboidratos de lenta digest&atilde;o, principalmente o amido resistente. O objetivo deste trabalho foi avaliar as caracter&iacute;sticas f&iacute;sico-qu&iacute;micas de bananas n&atilde;o maturadas com apar&ecirc;ncia externa no est&aacute;dio 1 de amadurecimento (verde). Estes dados ser&atilde;o importantes para a adequada sele&ccedil;&atilde;o dos frutos para processamento quando se tem como objetivo oferecer uma mat&eacute;ria prima com alto teor de amido resistente. A banana foi adquirida no mercado local da cidade de Pombal (PB), encaminhada ao Laborat&oacute;rio de Tecnologia de Gr&atilde;os e Cereais da UFCG, onde foram limpas em &aacute;gua corrente e cloradas a 20 ppm por 15 minutos seg', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1038', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c992', 'Caracterização físico-química e valor calórico de sanduíches naturais comercializados na cidade de Juazeiro do Norte - CE', 'SILVA, Luzia; SILVA, Janeanne; SOUSA, Francinalva; SOUSA, Elisabete', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os grandes avan&ccedil;os cient&iacute;ficos e tecnol&oacute;gicos ocorridos nos &uacute;ltimos anos nos mais diversos setores das atividades ligadas ao agroneg&oacute;cio t&ecirc;m propiciado o surgimento de novos produtos (exemplo: produtos derivados da soja, do trigo) destinados a um p&uacute;blico consumidor cada vez mais esclarecido e interessado em novidades que atendam &agrave;s suas necessidades (Camardelli, 2003). No Brasil visualiza-se uma tend&ecirc;ncia de crescimento no n&uacute;mero de refei&ccedil;&otilde;es realizadas fora do domic&iacute;lio. Em m&eacute;dia, a popula&ccedil;&atilde;o brasileira gasta 25% das despesas alimentares em consumo fora de casa, de acordo com a Pesquisa de Or&ccedil;amento Familiar (POF) do Instituto Brasileiro de Geografia e Estat&iacute;stica e da Associa&ccedil;&atilde;o Brasileira de Bares e Restaurante (ABRASEL, 2011). O aumento significativo no consumo de fast &ndash; foods tem sido verificado nos &uacute;ltimos anos, revelando tend&ecir', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1042', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c997', 'Elaboração de bolo enriquecido com linhaça (Linum usitatissimum L) e caracterização de sua aceitabilidade', 'DIAS, Victor H. L.; MATIAS, Mikaella T. S.; MEDEIROS, Danilo S.; MELO, Calionara W. B.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A linha&ccedil;a &eacute; considerada como um alimento funcional, ou seja, que cont&eacute;m, al&eacute;m de seus nutrientes b&aacute;sicos (carboidratos, prote&iacute;nas, gorduras e fibras), elementos que podem diminuir o risco de algumas doen&ccedil;as, pois seu uso cont&iacute;nuo pode proporcionar aumento da defesa org&acirc;nica e redu&ccedil;&atilde;o do ritmo de envelhecimento celular. O consumo da linha&ccedil;a pode ser feito juntamente com outros alimentos, na forma de ingredientes para o preparo de massas, p&atilde;es, tortas, sopas ou at&eacute; mesmo como acompanhamento de frutas, saladas e gr&atilde;os. O bolo &eacute; um alimento a base de massa de farinha, geralmente doce e cozido no forno. A fortifica&ccedil;&atilde;o de alimentos tem sido utilizada como medida de sa&uacute;de p&uacute;blica para erradicar manifesta&ccedil;&otilde;es de defici&ecirc;ncias nutricionais. Os alimentos enriquecidos podem proporcionar aumento das defesas do organismo e ajudar a reduzir o r', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1059', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c99f', 'Uso do mel de abelha (Apis mellifera L.) na comunidade Meia Pataca – PB', 'DANTAS, José O. S.; AQUINO, Italo de S.; MENEZES, Keliana G. de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O mel &eacute; considerado um produto especial, utilizado pelo homem com diversas finalidades desde os tempos remotos. Entretanto percebe-se que o consumo na nutri&ccedil;&atilde;o humana se restringe mais ao uso como ado&ccedil;ante, devido o seu alto teor de a&ccedil;&uacute;cares. Sua maior utilidade &eacute; no uso fitoterap&ecirc;utico pela medicina popular, por causa da composi&ccedil;&atilde;o complexa. Devido as suas a&ccedil;&otilde;es terap&ecirc;uticas, se tornou mais comum encontrar uma grande variedade de produtos farmac&ecirc;uticos e cosm&eacute;ticos com mel em sua composi&ccedil;&atilde;o. O presente trabalho teve como objetivo fazer um levantamento junto aos produtores de mel da Comunidade Meia Pataca, localizada entre os munic&iacute;pios de Esperan&ccedil;a e Rem&iacute;gio, estado da Para&iacute;ba, sobre as finalidades de venda do mel produzido na regi&atilde;o. A pesquisa foi de car&aacute;ter explorat&oacute;rio, com base em dados prim&aacute;rios, obtidos por m', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1067', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9a6', 'Caracterização dos estabelecimentos que comercializam a carne suína na cidade de João Pessoa, Paraíba', 'CRUZ, George R. B. da; PASCOAL, Leonardo A. F.; SILVA, Jordanio F. da; MARTINS, Terezinha D. D.; SILVA Jr, Joselito B.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Nos dias atuais os consumidores precisam ter confian&ccedil;a no alimento que est&atilde;o ingerindo, caso contr&aacute;rio eles preferem mudar seus h&aacute;bitos alimentares a comer alimentos que n&atilde;o transpasse seguran&ccedil;a. Visualizando o setor comercial nos dias atuais &eacute; not&oacute;ria a exist&ecirc;ncia de tr&ecirc;s tipos de estabelecimentos que comercializam a carne su&iacute;na (supermercados, a&ccedil;ougues e feiras livres), apresentando cada um uma forma diferente de manuseio que, dependendo de como se proceda, pode comprometer a qualidade e/ou contaminar microbiologicamente a carne su&iacute;na. Tendo em vista a grande facilidade de contamina&ccedil;&atilde;o desse produto, este trabalho teve como objetivo caracterizar os estabelecimentos que comercializam a carne su&iacute;na na cidade de Jo&atilde;o Pessoa, Para&iacute;ba. Foi desenvolvido um checklist com vinte quest&otilde;es fechadas, esse foi aplicado em seis supermercados, tr&ecirc;s a&ccedil;ougues', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1074', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9aa', 'Efeito da temperatura e da concentração de maltodextrina na massa específica da polpa de umbu-cajá', 'MELO, Karla dos S.; FERNANDES, Tâmila K. da S.; QUEIROZ, Alexandre J. de M.; FIGUEIRÊDO, Rossana M. F. de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O umbu-caj&aacute; &eacute; um fruto com qualidades sensoriais apreciadas, pode ser consumido na sua forma in natura, ou processada, como polpa, suco, etc. Um dos m&eacute;todos de processamento de frutas &eacute; a secagem por aspers&atilde;o, neste m&eacute;todo deve-se utilizar aditivos na polpa com a finalidade de facilitar a secagem. O aditivo mais utilizado &eacute; a maltodextrina, devido ao seu baixo valor e a baixa higroscopicidade. No processo de secagem por aspers&atilde;o uma das propriedades da mat&eacute;ria-prima que influenciam no resultado final do produto obtido &eacute; a massa especifica, esta caracter&iacute;stica esta diretamente relacionada com o tamanho da part&iacute;cula. Diante do exposto, foram determinadas as massas especificas da polpa de umbu-caj&aacute; com adi&ccedil;&atilde;o de diferentes concentra&ccedil;&otilde;es de maltodextrina (0; 2,5; 5; 7,5; 10; 12,5 e 15%) nas temperaturas de 10, 20, 30, 40 e 50 &ordm;C. Os dados experimentais foram submetido', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1078', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9ad', 'Formulação de sopão com hortaliças desidratadas e espessantes sem glúten', 'SILVA, Josélia J. da; LIMA, Eliza D. P. de A.; FIGUEIRÊDO, Paloma C. da S.; FERREIRA, Willma K.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A sopa tem enorme import&acirc;ncia em nossa alimenta&ccedil;&atilde;o pela variedade de nutrientes que nos fornece, como tamb&eacute;m pelos benef&iacute;cios que desencadeia a n&iacute;vel funcional. Devido ao crescimento do consumo de produtos nutritivos e de f&aacute;cil preparo, o objetivo deste estudo foi produzir sop&otilde;es com hortali&ccedil;as desidratadas e espessantes sem gl&uacute;ten. Foram formulados cinco sop&otilde;es utilizando: ab&oacute;bora caboclo e leite, batata inglesa, cenoura, cebola, coentro, piment&atilde;o amarelo, piment&atilde;o vermelho, tomate e alho desidratados, sal e espessantes como: fub&aacute; de milho, gelatina em p&oacute;, farinha de milho, amido de milho, f&eacute;cula de mandioca e farinha de arroz. Os sop&otilde;es foram avaliados quanto &agrave; atividade de &aacute;gua e composi&ccedil;&atilde;o centesimal. A formula&ccedil;&atilde;o do sop&atilde;o no qual foi utilizado o fub&aacute; de milho e a gelatina como espessante, apresentou mai', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1081', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9b3', 'Helmintos de importância higiênico-sanitária em maparás (Hypophthalmus edentatus) e tambaquis (Colossoma macropomum) comercializados no sudeste do Pará/Brasil', 'SALGADO, Raquel L.; PAIVA, Irislene S.; OLIVEIRA, Wíldiney F.; CCOSTA, Bruna M.; SILVA, Priscilla D. L.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O pescado vem se destacando no mercado mundial pelo seu alto valor nutritivo, constituindo-se em uma fonte prot&eacute;ica de alto valor biol&oacute;gico, rica em lip&iacute;dios insaturados, vitaminas e sais minerais. Na regi&atilde;o amaz&ocirc;nica o pescado constitui a principal fonte de renda dos moradores de zonas ribeirinhas. Entretanto, apesar da grande import&acirc;ncia para a sa&uacute;de e economia local, o pescado comercializado no sudeste paraense ainda &eacute; pouco estudado quanto a sua fauna parasitol&oacute;gica de import&acirc;ncia higi&ecirc;nico-sanit&aacute;ria. Neste contexto, o presente trabalho objetivou avaliar a diversidade da fauna parasit&aacute;ria de interesse comercial e em sa&uacute;de p&uacute;blica de duas das principais esp&eacute;cies pesqueiras do sudeste do Par&aacute;. Durante os meses julho de 2010 a janeiro de 2011, foram analisados 30 exemplares de tambaqui (Colossoma macropomum) e 30 exemplares de mapar&aacute; (Hypophthalmus edentatus) adqui', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1134', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9b5', 'Biscoitos tipo cookie de okara de soja: Elaboração e avaliação organoléptica', 'CAVALCANTI, Mônica Tejo; ALMEIDA, Maria Climene Bezerra de Medeiros; ONIAS, Eliane Alves; ALVES, Ana Marina Assis; CHINELATE, Gerla Castello Branco', 'Editora Verde', 'Agriculture', 'Agriculture', 'A soja &eacute; uma excelente fonte de prote&iacute;na de boa qualidade para alimenta&ccedil;&atilde;o humana, de baixo custo e altamente dispon&iacute;vel, pode ser tamb&eacute;m considerada funcional, pois contem subst&acirc;ncias fisiologicamente ativas capazes de atuar como moduladores dos processos metab&oacute;licos. Considerando os in&uacute;meros benef&iacute;cios que a soja pode trazer para os consumidores, a inclus&atilde;o dessa leguminosa e seus derivados como parte da dieta di&aacute;ria &eacute; altamente recomend&aacute;vel, pois contribuem para prover os nutrientes necess&aacute;rios para o crescimento. O extrato aquoso hidrossol&uacute;vel da soja &eacute; um produto obtido a partir da lavagem, macera&ccedil;&atilde;o e aquecimento de gr&atilde;os de soja. Os gr&atilde;os lavados e macerados s&atilde;o mo&iacute;dos e aquecidos para, ent&atilde;o, passarem por um processo de filtra&ccedil;&atilde;o que separa o extrato aquoso de seu subproduto, a okara. O objetivo dess', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1341', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9b6', 'Atitude de compra de bebida fermentada a base de soja sabor mel', 'SILVA, André Leandro; ALVES, Ana Marina Assis; VIEIRA, Danise Medeiros; CHINELATE, Gerla Castello Branco; LIMA, Soares Elias Rodrigues', 'Editora Verde', 'Agriculture', 'Agriculture', 'A popula&ccedil;&atilde;o de um modo geral est&aacute; mais consciente da rela&ccedil;&atilde;o existente entre alimenta&ccedil;&atilde;o e sa&uacute;de. Sendo assim, a ind&uacute;stria busca novas alternativas para o desenvolvimento de alimentos de boa aceitabilidade e com ingredientes capazes de promover a sa&uacute;de. A soja e seus derivados t&ecirc;m recebido aten&ccedil;&atilde;o dos pesquisadores, principalmente devido &agrave; quantidade e qualidade de sua prote&iacute;na, sendo considerada, dentre os vegetais, o melhor substituto de produtos de origem animal. Al&eacute;m disso, a soja &eacute; importante fonte de outros compostos, como fibras, oligossacar&iacute;deos com potencial prebi&oacute;tico, como rafinose e estaquiose, vitaminas e minerais. A soja &eacute; largamente utilizada no processamento de in&uacute;meros produtos destinados a alimenta&ccedil;&atilde;o. O extrato hidrossol&uacute;vel de soja &eacute; um produto de aspecto semelhante ao leite bovino e de alto val', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1342', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9b7', 'Barra de cereal com okara de soja: Elaboração e Avaliação Sensorial', 'BESERRA, Gardênia Alves; CAVALCANTI, Mônica Tejo; ONIAS, Eliane Alves; ALVES, Ana Marina Assis; CHINELATE, Gerla Castello Branco', 'Editora Verde', 'Agriculture', 'Agriculture', 'A soja [Glycine max (L.) Merrill.] e os seus produtos v&ecirc;m sendo amplamente estudados devido n&atilde;o somente ao seu valor nutricional, mas tamb&eacute;m devido as suas propriedades funcionais na ind&uacute;stria de alimentos, e como alimento funcional, porque exerce a&ccedil;&atilde;o moduladora em determinados mecanismos fisiol&oacute;gicos atrav&eacute;s de suas prote&iacute;nas e isoflavonas. O processo de produ&ccedil;&atilde;o do extrato de soja tem como subproduto um material caracterizado como uma massa &uacute;mida de alta coesividade, com prote&iacute;na de qualidade superior a dos outros derivados da soja. O material seco pode ser incorporado a uma grande variedade de alimentos, reduzindo a quantidade total de calorias e aumentando a quantidade e qualidade de fibras. De acordo com a denomina&ccedil;&atilde;o dada por publica&ccedil;&otilde;es pertinentes, este res&iacute;duo &eacute; chamado okara, um subproduto de baixo valor de mercado e rico em proteinas com alto v', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1343', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
