INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9cc', 'A FORMAÇÃO DOCENTE E O CURRÍCULO: PROMOVENDO A IDENTIDADE CAMPESINA', 'Oliveira, Maria das Graças Gomes de; Silva, Cláudio César da; Costa Silva, Wagner Alexandre; Rodrigues, Ana Cláudia da Silva; Romão dos Santos, Cristina Elizabeth', 'Editora Verde', 'Agriculture', 'Agriculture', '_', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1428', NULL, 'English', 'published', false, false, 'open', 'pdf')
