VALUES ('6798b003d6a63682f044c9ce', 'AVALIAÇÃO DA ACEITAÇÃO PINTADO (Pseudoplatystoma corruscans) E CatFish (Ictalurus punctatu) DEFUMADOS PELO PROCESSO DE DEFUMAÇÃO LIQUÍDA', 'Ferreira, Leisyanne Ojeda; Altemio, Ângela Dulce Cavenaghi; Peixoto, Thamires da Silva; Pinedo, Rosalinda Arévalo', 'Editora Verde', 'Agriculture', 'Agriculture', '_', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1480', NULL, 'English', 'published', false, false, 'open', 'pdf')
