INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b003d6a63682f044c9d1', 'O OURO VERDE DO SEMIÁRIDO: PALMA FORRAGEIRA CONHECIMENTOS E UTILIDADES', 'Pereira Filho, Raimundo Raniêr; Pereira, Emmanuel Moreira; Sousa, Luci Cleide Farias Soares; Sousa, José da Silva; Borges, Maria da Gloria Borba; Silva, Rosilene Agra da', 'Editora Verde', 'Agriculture', 'Agriculture', '_', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1702', NULL, 'English', 'published', false, false, 'open', 'pdf')
