INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9d6', 'TIPOS DE PELAGENS DOS FILHOS DE REPRODUTORES MACHOS “PO” DA RAÇA QUARTO DE MILHA EM MICROREGIÃO DO SERTÃO PARAIBANO', 'Maracaja, Patricio Borges; Marques, Ana Valéria Mello de Souza; Oliveira, Alexandro Veras Barreto de; Silva, Rosilene Agra da; Bezerra Maia, Francisco Denis Rodrigues', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar os tipos de pelagens dos filhos de reprodutores machos &ldquo;PO&rdquo; da ra&ccedil;a quarto de milha em Microregi&atilde;o do Sert&atilde;o Paraibano. Os dados foram coletados de criat&oacute;rios de equinos da ra&ccedil;a Quarto de Milha P.O., localizados nos munic&iacute;pios de S&atilde;o Bento e Brejo do Cruz. As informa&ccedil;&otilde;es constam de uma caderneta de monta padr&atilde;o da ra&ccedil;a, recomendada pela Associa&ccedil;&atilde;o Brasileira de Criadores de Cavalos Quarto de Milha. Os animais avaliados foram: DOM ROXAO ETERNALADY-P109413 de pelagem tordilha; HERCULES APOLLO MRL &ndash;P095828 de pelagem castanha; DEGAS JAY -P117270 de pelagem cremelo; CAMBARA GOLDEN &ndash; P090388 de pelagem alaz&atilde;o. De acordo com os dados das fichas de registro geneal&oacute;gico da ABQM, entre os anos de 2007 at&eacute; 2011, do total de 78 crias nascidas 39 foram f&ecirc;meas e 39 machos, sendo que DOM ROXAO ETERNALADY originou 22 f&ecirc;meas e 17 macho', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1928', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9d7', 'IMPORTÂNCIA DA ALIMENTAÇÃO ARTIFICIAL ENERGÉTICA PARA MANUTENÇÃO DAS Apis mellifera L. NO PERÍODO DE ESTIAGEM NO MUNICÍPIO DE POÇO DE JOSÉ DE MOURA – PB.', 'Andrade, Anderson Bruno Anacleto de; Maracajá, Patrício Borges; Silva, Rosilene Agra da', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com esse trabalho identificar entre os apicultores da Associa&ccedil;&atilde;o dos Criadores de Abelhas do Munic&iacute;pio de Po&ccedil;o de Jos&eacute; de Moura, quais fizeram uso da alimenta&ccedil;&atilde;o artificial energ&eacute;tica no per&iacute;odo de estiagem. Para realiza&ccedil;&atilde;o do levantamento foram entrevistados onze apicultores, que contribu&iacute;ram informando a quantidade de enxames que possu&iacute;a na &uacute;ltima florada ocorrente, se ocorreu o fornecimento de algum tipo de alimenta&ccedil;&atilde;o artificial no per&iacute;odo de seca, e a quantidade atual de enxames no api&aacute;rio. Os apicultores que fizeram manejo alimentar forneceram alimenta&ccedil;&atilde;o do tipo energ&eacute;tica e tamb&eacute;m disponibilizaram &aacute;gua para as abelhas no per&iacute;odo de escassez de alimento, os quais conseguiram manter seus enxames. A maioria dos apicultores n&atilde;o forneceu nenhum tipo de alimenta&ccedil;&atilde;o artificial e enfrent', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1929', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9da', 'USO DO INDICE DE SUSTENTABILIDADE DA PECUÁRIA BOVINA: ESTUDO DO MUNICIPIO DE POMBAL/PB', 'Maracajá, Patrício Borges; Schmidt Filho, Ricardo; Borges, Maria da Gloria Borba; Carvalho, Jacqueline Liedja Araujo Silva; Silva, Rosilene Agra da', 'Editora Verde', 'Agriculture', 'Agriculture', 'A produ&ccedil;&atilde;o interna brasileira apresenta grande heterogeneidade no sistema produtivo, h&aacute; &aacute;reas geogr&aacute;ficas que possuem desafios, como o Nordeste Setentrional, pouca precipita&ccedil;&atilde;o h&iacute;drica, h&aacute; per&iacute;odos de estiagem que a situa&ccedil;&atilde;o torna-se dif&iacute;cil at&eacute; mesmo o abastecimento animal como exemplo da atividade da pecu&aacute;ria bovina. Neste contexto surge o objetivo desse estudo analisar se a atividade leiteira bovina &eacute; sustent&aacute;vel econ&ocirc;mica, social e ambiental no munic&iacute;pio de Pombal, localizado no Semiarido nordestino paraibano. Para qualificar e quantificar a sustentabilidade tomou-se como base o teste denominado de &Iacute;ndice Global de Sustentabilidade (IGS), com 15 perguntas, relacionados aos tr&ecirc;s segmentos da sustentabilidade, com respostas Sim para satisfat&oacute;rio e N&atilde;o para insatisfat&oacute;rio, maior que 50%, a atividade enquadra-se na sustent', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1932', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9db', 'AVALIAÇÃO DO NÍVEL TECNOLÓGICO DA PRODUÇÃO BOVINA LEITEIRA DO MUNICIPIO DE POMBAL/PB', 'Schmidt Filho, Ricardo; Aleixo, Divane Lima; Borges, Maria da Gloria Borba; Carvalho, Jacqueline Liedja Araujo Silva; Silva, Rosilene Agra da', 'Editora Verde', 'Agriculture', 'Agriculture', 'A produ&ccedil;&atilde;o de leite bovina &eacute; um segmento de destaque no Brasil, terceiro maior produtor do mundo. Mas internamente o sistema produtivo n&atilde;o &eacute; heterog&ecirc;neo, muitas propriedades n&atilde;o disp&otilde;e t&eacute;cnicas adequadas que garantam quantidade do produto. Pombal, munic&iacute;pio da Para&iacute;ba tem um grande potencial produtivo leiteira, em rela&ccedil;&atilde;o o Estado paraibano. Este estudo tem como objetivo identificar as principais caracter&iacute;sticas tecnol&oacute;gicas praticadas pelos produtores locais entender as dificuldades de inser&ccedil;&atilde;o no mercado competitivo. O presente estudo foi desenvolvido com base em refer&ecirc;ncias bibliogr&aacute;ficas e trabalho de campo, atrav&eacute;s de question&aacute;rios aplicados em uma amostra aleat&oacute;ria com dez propriedades. &nbsp;Constatou-se o que 60% praticam a atividade a mais de 30 anos, nenhum tem ensino superior, apenas o ensino m&eacute;dio, fundamental I e II.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1934', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9df', 'TERMOGRAFIA COMO FERRAMENTA DE AVALIAÇÃO DO ESTRESSE TÉRMICO EM VACAS LEITEIRAS', 'Nascimento, Maria Evelaine de Lucena; Souza, Bonifácio Benício de; Araújo, Marília da Piedade Roque de; Nogueira, Francisco Roserlândio Botão; Queiros, Aline Francelina de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Foram realizadas observa&ccedil;&otilde;es em 28 vacas mesti&ccedil;as, resultantes do cruzamento de Bos tauros com Bos indicus, em diferentes fases de lacta&ccedil;&atilde;o, em experimento realizado no Instituto Federal da Para&iacute;ba &ndash; Campus Sousa, entre 5:00 e 7:00 horas da manh&atilde; e 14:00 e 16:00 horas da tarde, durante 6 dias. Foram registradas as frequ&ecirc;ncias respirat&oacute;rias (FR) determinada por observa&ccedil;&otilde;es dos movimentos do arco costal, temperatura da superf&iacute;cie do olho (TO) a partir de imagens termogr&aacute;ficas obtidas por meio de uma c&acirc;mera infravermelha e, temperatura de globo negro e umidade relativa do ar (ITGU). Com o objetivo de analisar o uso da termografia infravermelha como ferramenta de apoio para avaliar o estresse t&eacute;rmico. Os valores m&eacute;dios das vari&aacute;veis em quest&atilde;o apresentaram eleva&ccedil;&atilde;o significativa para o per&iacute;odo da tarde, quando comparados com o da manh&atilde', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/1943', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9e2', 'INFLUÊNCIA DA ALIMENTAÇÃO ARTIFICIAL ENERGÉTICA NA MANUTENÇÃO DE ENXAMES DE Apis mellifera L. DURANTE ESTIAGEM NO MUNICÍPIO DE SÃO JOÃO DO RIO DO PEIXE – PB.', 'Maracajá, Patrício Borges; Andrade, Anderson Bruno Anacleto de; Medeiros, Antônio Tadeu de Brito; Almeida Neto, Isidro Patricio de; Guedes, Wellinghton Alves; Bulhões, Anderson Amaral de; Silva, Rosil', 'Editora Verde', 'Agriculture', 'Agriculture', 'O manejo alimentar das col&ocirc;nias &eacute; de fundamental import&acirc;ncia para que o apicultor n&atilde;o tenha preju&iacute;zos na sua atividade. Portanto, objetivou-se identificar entre os apicultores da Associa&ccedil;&atilde;o dos Apicultores do Vale do Rio do Peixe - APIVALE, quais fizeram uso da alimenta&ccedil;&atilde;o artificial energ&eacute;tica no per&iacute;odo de estiagem e a influ&ecirc;ncia desta alimenta&ccedil;&atilde;o para manuten&ccedil;&atilde;o e sobreviv&ecirc;ncia dos seus enxames. O trabalho foi realizado com entrevistas feitas a dez apicultores, que contribu&iacute;ram informando a quantidade de enxames que possu&iacute;a na &uacute;ltima florada ocorrente, se ocorreu o fornecimento de algum tipo de alimenta&ccedil;&atilde;o artificial no per&iacute;odo de seca, e a quantidade atual de enxames no api&aacute;rio. A maioria dos apicultores forneceu alimenta&ccedil;&atilde;o artificial do tipo energ&eacute;tica aos enxames, os apicultores que optaram por n&', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2354', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9e3', 'FLORA APÍCOLA DO ESTRATO ARBUSTIVO EM MUNICÍPIOS DA MICRORREGIÃO DE CATOLÉ DO ROCHA-PB', 'Silva, Carlos Alberto de Lima e; Silva, Damião Pedro da; Pinto, Maria do Socorro de Caldas; Silva, Kelina Bernardo; Silva, Rosilene Agra da', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com este estudo conhecer a flora ap&iacute;cola do estrato arbustivo em munic&iacute;pios da microrregi&atilde;o de Catol&eacute; do Rocha-PB. O levantamento dos dados foi realizado atrav&eacute;s da aplica&ccedil;&atilde;o de&nbsp; question&aacute;rios, sendo entrevistados 55 apicultores, onde foram levantados dados sobre a flora arbustiva, junto aos apicultores dos munic&iacute;pios de Brejo dos Santos, Catol&eacute; do Rocha, Jeric&oacute; e Riacho dos Cavalos-PB. Em rela&ccedil;&atilde;o &agrave; flora ap&iacute;cola para o estrato analisado na vegeta&ccedil;&atilde;o de caatinga, foram identificadas 10 fam&iacute;lias, 18 g&ecirc;neros e 23 esp&eacute;cies. Verificou-se ainda que a fam&iacute;lia Fabaceae foi a que apresentou um maior n&uacute;mero de esp&eacute;cies, seguida pelas Euforbiaceae, Malvaceae e Boraginaceae, respectivamente.&nbsp; Para o estrato arbustivo as fam&iacute;lias Lamiaceae, Combretaceae, Verbenaceae, Solanaceae, Boraginaceae e Apocynaceae estev', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2357', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9eb', 'AÇÕES DE ATER PARA INTRODUÇÃO E DESENVOLVIMENTO DA APICULTURA NO MUNICÍPIO DE PARARI DE 2008 À 2012.', 'Cavalcante, Roberto Carlos; Souza, José Thyago Aires de; Silva, Arlene Braz da Conceição; Souza, João Paulo Aires de; Brito, Genilson Bezerra de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A Pnater sugere que se melhorem os processos de gest&atilde;o social. Estabelece ainda que a nova Ater &eacute; um processo educativo, permanente e continuado, que se deve alicer&ccedil;ar em uma pr&aacute;tica dial&oacute;gica e em uma pedagogia construtivista. Essa Extens&atilde;o Rural deve contribuir para uma melhor rela&ccedil;&atilde;o entre o urbano e o rural, para a melhoria da qualidade de vida, para o fortalecimento da cidadania e para a produ&ccedil;&atilde;o de alimentos limpos. O objetivo desse trabalho &eacute; fornecer informa&ccedil;&otilde;es sobre as a&ccedil;&otilde;es desenvolvidas pelos &oacute;rg&atilde;os ATER no munic&iacute;pio de Parari-PB para a introdu&ccedil;&atilde;o e o desenvolvimento da apicultura. Parari est&aacute; localizado na microrregi&atilde;o do Cariri Ocidental do estado da Para&iacute;ba. As a&ccedil;&otilde;es foram desenvolvidas durante o per&iacute;odo de 2008 &agrave; 2012, onde inicialmente identificamos alguns agricultores familiar j&aac', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2379', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9ef', 'CARACTERIZAÇÃO DAS ESPÉCIES MELÍPONAS E PERDAS DE ENXAMES NAS AGROVILAS DA SERRA DO MEL – RN', 'Borba, Luis Henrique Fernandes; Lira, Gunthinéia Alves de; Pereira, Daniel Santiago; Araújo, Ítala Iara Medeiros de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com esta pesquisa realizar um levantamento das esp&eacute;cies de abelhas ind&iacute;genas sem ferr&atilde;o criadas em melipon&aacute;rios das agrovilas rurais no munic&iacute;pio de Serra do Mel bem como a perda de enxames durante os anos de 2011 &agrave; mar&ccedil;o de 2013. Foram entrevistados 24 meliponicultores &ldquo;in loco&rdquo; atrav&eacute;s de interrogat&oacute;rio direto, utilizando-se question&aacute;rio formal por escrito. Para a an&aacute;lise das respostas, foram utilizadas ferramentas da an&aacute;lise estat&iacute;stica descritiva. Observou-se a perda de 67,14% dos enxames entre os anos de 2012 e 2013. Verificou-se que a esp&eacute;cie Melipona subnitida D. predomina nos melipon&aacute;rios das Agrovilas do munic&iacute;pio de Serra do Mel. Conclui-se que os meliponicultores sabem a import&acirc;ncia da atividade, mas que para tornarem a atividade racional necessitam de treinamentos espec&iacute;ficos para a esp&eacute;cie.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2401', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9f0', 'CARACTERIZAÇÃO DOS MELIPONICULTORES NAS AGROVILAS DA SERRA DO MEL – RN', 'Borba, Luis Henrique Fernandes; Lira, Gunthinéia Alves de; Pereira, Daniel Santiago; Araújo, Ítala Iara Medeiros de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com esta pesquisa realizar um diagn&oacute;stico do perfil atual dos meliponicultores das agrovilas rurais no munic&iacute;pio de Serra do Mel quanto aos aspectos econ&ocirc;micos, sociais, ambientais, produtivos, organizacionais, comerciais e do acesso ao cr&eacute;dito. Foram entrevistados 24 meliponicultores &ldquo;in loco&rdquo; atrav&eacute;s de interrogat&oacute;rio direto, utilizando-se question&aacute;rio formal por escrito. Para a an&aacute;lise das respostas, foram utilizadas ferramentas da an&aacute;lise estat&iacute;stica descritiva. Foi diagnosticado que a meliponicultura no munic&iacute;pio &eacute; uma atividade predominantemente masculina (100%) e que 75% dos entrevistados n&atilde;o concluiu o ensino fundamental. Quanto &agrave; comercializa&ccedil;&atilde;o do mel, foi identificado que 79,17% dos que exploram a atividade usavam e comercializam o produto, com o pre&ccedil;o variando de R$ 25,00 a R$ 90,00 o litro.&nbsp; Com rela&ccedil;&atilde;o ao n&iacut', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2402', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9f9', 'ESTUDO MORFOMÉTRICO DE ABELHAS JANDAÍRA (Melipona subnitida Duck) CRIADAS EM CORTIÇOS RACIONAIS NO MUNICÍPIO DE SÃO JOÃO DO RIO DO PEIXE – PB', 'Silva, Luderlanio de Andrade; Aleixo, Divane de Lima; Sobrinho, Paulo Henrique Galvão; Andrade, Anderson Bruno Anacleto de; Araújo, Whalamys Lourenço de; Figueiredo, Lizaiane Cardoso de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Em virtude da grande dissemina&ccedil;&atilde;o da abelha Janda&iacute;ra (Melipona subnitida Duck) em diversas regi&otilde;es do Nordeste brasileiro, este trabalho teve por objetivo realizar um estudo morfom&eacute;trico desta esp&eacute;cie de melipona, criada em corti&ccedil;os artificiais no munic&iacute;pio de S&atilde;o Jo&atilde;o do Rio do Peixe &ndash; PB. A pesquisa foi dimensionada em um melipon&aacute;rio presente na regi&atilde;o Sertaneja Paraibana, num total de 30 abelhas, de 10 distintos corti&ccedil;os. Com o aux&iacute;lio de uma lupa e paqu&iacute;metro digital fez-se as medidas, onde os esp&eacute;cimes em estudo apresentaram, em m&eacute;dia, 8,85mm de Comprimento Transversal; 3,38mm de Comprimento Longitudinal; 7,84 mm de Pernas Coletoras; 6,99mm de Asas Anteriores; 5,18mm de Asas Posteriores, ambos com um peso m&eacute;dio de 0,0520mg. Al&eacute;m das mensura&ccedil;&otilde;es, foram descritas as caracter&iacute;sticas morfol&oacute;gicas externas como colora&cce', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2423', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9fa', 'MAPEAMENTO DA FLORA APÍCOLA ARBÓREA DAS REGIÕES POLO DO ESTADO DO PIAUÍ', 'Aleixo, Divane de Lima; Sobrinho, Paulo Henrique Galvão; Andrade, Anderson Bruno Anacleto de; Araújo, Whalamys Lourenço de; Silva, Maria Kaline do Nascimento; Oliveira, Fernanda Andrade de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O conhecimento da flora ap&iacute;cola de uma determinada regi&atilde;o constitui uma ferramenta essencial para que o apicultor otimize a sua produ&ccedil;&atilde;o. O presente estudo, desenvolvido no Estado do Piau&iacute;, teve como objetivo identificar e catalogar as esp&eacute;cies ap&iacute;colas arb&oacute;reas existentes nas regi&otilde;es consideradas polo do Estado (Regi&otilde;es Norte, Serra da Capivara, Picos e Simpl&iacute;cio Mendes), bem como observar o per&iacute;odo de florescimento e sua aptid&atilde;o a n&eacute;ctar e/ou p&oacute;len pelas abelhas.&nbsp; O levantamento apibot&acirc;nico foi realizado entre os meses de agosto de 2009 a dezembro de 2010. Foram feita coleta do material vegetal mensalmente, de acordo com o per&iacute;odo de flora&ccedil;&atilde;o, e para verificar a presen&ccedil;a de abelhas. O material vegetal foi herborizado conforme as t&eacute;cnicas usuais em bot&acirc;nica, e encaminhado para o Laborat&oacute;rio de Zootecnia da Universidade Fede', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2424', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044c9ff', 'UM ESTUDO SOBRE A VEGETAÇÃO NATIVA DO PARQUE ESTADUAL DO PICO DO JABRE, NA SERRA DO TEIXEIRA, PARAÍBA', 'Santos, Rosélia Maria de Sousa; Santos, José Ozildo dos; Maracajá, Patrício Borges', 'Editora Verde', 'Agriculture', 'Agriculture', 'Em pleno sert&atilde;o nordestino &eacute; poss&iacute;vel tamb&eacute;m se encontrar verdadeiras &lsquo;ilhas verdes&rsquo;, cuja vegeta&ccedil;&atilde;o ignora a agressividade do clima da regi&atilde;o em volta e se mant&eacute;m com suas folhagens, mesmo nos per&iacute;odos de seca. Um dos exemplos mais pr&oacute;ximo dessas chamadas &lsquo;ilhas verdes&rsquo;, &eacute; a Serra do Teixeira, onde se encontra o Parque Estadual do Pico do Jabre. Nessa &aacute;rea de preserva&ccedil;&atilde;o ambiental, que no passado sofreu diversos inc&ecirc;ndios e a a&ccedil;&atilde;o predadora do homem, ainda &eacute; poss&iacute;vel encontrar v&aacute;rias esp&eacute;cies nativas, que apresentam um elevado porte, contrastando-se com os aspectos apresentados pela vegeta&ccedil;&atilde;o que se desenvolve nas &aacute;reas adjacentes &agrave; mencionada serra. O presente trabalho tem por objetivo identificar as esp&eacute;cies de grande porte encontradas com maior frequ&ecirc;ncia na &aacute;rea do P', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2742', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca00', 'CARATERIZAÇÃO FÍSICO-QUÍMICA DE FARINHA DA ENTRECASCA DE MELANCIA (Citrullus lanatus)', 'de Andrade, Romário Oliveira; de Lima, Gustavo Santos; Santiago Neto, João Felipe; Antonino Nunes, Pedro Germano; de Sousa Augustinho, Ana Kelis', 'Editora Verde', 'Agriculture', 'Agriculture', 'A melancia (Citrullus lanatus), origin&aacute;ria do continente africano, &eacute; pertencente &agrave; fam&iacute;lia das cucurbit&aacute;ceas. Com a crescente preocupa&ccedil;&atilde;o do desperd&iacute;cio de alimentos, &eacute; importante encontrar novas formas de reaproveitamento desses res&iacute;duos, estes que na maioria das vezes s&atilde;o ricos em nutrientes importantes para a alimenta&ccedil;&atilde;o humana, como fibras, vitaminas, prote&iacute;nas, carboidratos, entre outros. Tendo o objetivo de elaborar farinha a partir da entrecasca da melancia (C. lanatus) e determinar sua caracteriza&ccedil;&atilde;o f&iacute;sico-qu&iacute;mica. Foi utilizada a entrecasca para obten&ccedil;&atilde;o da farinha, foram feitos cortes em fil&eacute;s e em seguida feito a secagem &agrave; temperatura de 60&deg;C por 72 horas, ap&oacute;s secagem o material foi triturado obtendo a farinha. Determinada a composi&ccedil;&atilde;o f&iacute;sico-qu&iacute;mica seguindo a metodologia do Institu', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2824', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca05', 'ACEITAÇÃO SENSORIAL DE BEBIDA MISTA DE FRUTOS DO GÊNERO SPONDIAS A BASE DE ÁGUA DE COCO', 'Bezerra, Júlia Medeiros; Silva, Amanda Kelly; Alves, Ana Marina Assis; Vieira, Maria Marlene Silva; Santos, Adriana Ferreira', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo o desenvolvimento de formula&ccedil;&otilde;es de bebidas mistas, com &aacute;gua de coco e polpas de frutos do g&ecirc;nero Spondias (umbu e umbu-caj&aacute;), na forma pronto para beber e sua aceita&ccedil;&atilde;o sensorial. Foram avaliadas oito formula&ccedil;&otilde;es com diferentes concentra&ccedil;&otilde;es da polpa dos frutos do g&ecirc;nero Spondias de 25, 35 e 45% (umbu) e 25, 30 e 35% (umbu-caj&aacute;) e teores de s&oacute;lidos sol&uacute;veis de 11 e 13&deg;Brix. As formula&ccedil;&otilde;es foram submetidas &agrave; avalia&ccedil;&atilde;o sensorial dos par&acirc;metros de: cor, aroma, sabor e aceita&ccedil;&atilde;o global. Para o atributo sabor para as bebidas de umbu o n&iacute;vel de aceita&ccedil;&atilde;o situou-se entre &ldquo;desgostei moderadamente&rdquo; e &ldquo;n&atilde;o gostei nem desgostei&rdquo;, enquanto que, para a bebida mista de umbu-caj&aacute; o atributo sabor ficou entre &ldquo;desgostei ligeiramente&rdquo; a &ld', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2834', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca06', 'BEBIDA MISTA DE TAMARINDO A BASE DE AGUA DE COCO', 'Bezerra, Júlia Medeiros; Vieira, Maria Marlene Silva; Santos, Adriana Ferreira; Souza, Diego Gadelha', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi desenvolver formula&ccedil;&otilde;es de bebidas mistas, com &aacute;gua de coco e suco de tamarindo, na forma pronto para beber. Foram testadas quatro formula&ccedil;&otilde;es com duas concentra&ccedil;&otilde;es de polpa de tamarindo. As concentra&ccedil;&otilde;es de polpas foram de 20 e 30% de polpa. As bebidas formuladas foram submetidas a tratamentos t&eacute;rmico &agrave; temperatura de 90&deg;C por 1 minuto, envasadas e fechadas com tampas pl&aacute;sticas com lacre. Foram realizadas avalia&ccedil;&otilde;es f&iacute;sico-qu&iacute;micas. De acordo com os resultados, observou-se que a formula&ccedil;&atilde;o F1 foi a que apresentou melhor palatabilidade, enquanto que, a formula&ccedil;&atilde;o F2 foi a que obteve o maior teor de acido asc&oacute;rbico. Concluiu-se que a mistura de &aacute;gua de coco e suco de tamarindo s&atilde;o vi&aacute;veis na elabora&ccedil;&atilde;o de bebidas, dentro do processamento utilizado e pode representar um bom pot', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2835', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca0b', 'QUALIDADE DE DOCE EM MASSA DE BANANA ADICIONADO DE COMPONENTES FUNCIONAIS', 'Bezerra, Júlia Medeiros; Araújo, Jayuri Susy Fernandes de; Santana Neto, Deocleciano Cassiano; Alves, Ana Marina Assis; dos Santos, Adriana Ferreira', 'Editora Verde', 'Agriculture', 'Agriculture', '&nbsp; Resumo: A busca por uma alimenta&ccedil;&atilde;o mais saud&aacute;vel tem estimulado o aumento de consumo de produtos funcionais. O objetivo desse trabalho foi a elabora&ccedil;&atilde;o de quatro formula&ccedil;&otilde;es de doce de banana enriquecido com linha&ccedil;a e polpa de a&ccedil;a&iacute; e avaliar suas caracter&iacute;sticas f&iacute;sico-qu&iacute;micas. Foram testadas quatro formula&ccedil;&otilde;es do doce em massa de banana com diferentes concentra&ccedil;&otilde;es de linha&ccedil;a e a&ccedil;a&iacute;, 0 % de produto funcional (controle), 40 % de linha&ccedil;a, 50 % de a&ccedil;a&iacute; e 40 e 50% de linha&ccedil;a + a&ccedil;a&iacute;. Avaliou-se os teores de umidade, cinzas, SS, AT, pH, SS/AT, &Aacute;c, asc&oacute;rbico, AST e prote&iacute;na. De acordo com os resultados, observou-se que a formula&ccedil;&atilde;o F2 foi a que apresentou a melhor palatabilidade para a rela&ccedil;&atilde;o SS/AT e maior teor de prote&iacute;na, enquanto a F3 obteve o m', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2843', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca10', 'FORMULAÇÃO E QUALIDADE DE NÉCTAR DE CAJÁ ADICIONADO COM LINHAÇA E EXTRATO DE SOJA', 'Gomes, Jaqueline Sousa; Souza, D. G.; Santos, A. F.; Silva, A. K.; Alves, M. J. DOS S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A procura por alimentos saud&aacute;veis e com alto valor nutritivo vem aumentando nos &uacute;ltimos anos. O objetivo desse trabalho foi desenvolver formula&ccedil;&otilde;es de um n&eacute;ctar de caj&aacute; com a adi&ccedil;&atilde;o de linha&ccedil;a e extrato de soja, e avaliar a sua qualidade. Foram elaboradas cinco formula&ccedil;&otilde;es de n&eacute;ctar com tr&ecirc;s concentra&ccedil;&otilde;es da polpa de caj&aacute; e duas concentra&ccedil;&otilde;es de linha&ccedil;a e extrato de soja (5 e 3%), sendo a base de &aacute;gua mineral. Os s&oacute;lidos sol&uacute;veis foram corrigidos para 18 &deg;Brix. As bebidas formuladas foram submetidas a tratamento t&eacute;rmico &agrave; temperatura de 90&ordm;C por 2 minutos. As an&aacute;lises realizadas foram SS, %, AT (g.100g-1), pH, rela&ccedil;&atilde;o SS/AT e &Aacute;cido asc&oacute;rbico (mg.100g-1). O n&eacute;ctar de caj&aacute; apresentou um teor de s&oacute;lidos sol&uacute;veis totais e acidez total em de acordo com a l', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2850', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca16', 'AVALIAÇÃO SENSORIAL DE BATATA-DOCE ROXA “CHIPS” E PALITO', 'Costa, Jessyka Silva; Silva, Gabriela Souza; Cavalcanti, Mônica Tejo; Araujo, Jayuri Fernandes', 'Editora Verde', 'Agriculture', 'Agriculture', 'AVALIA&Ccedil;&Atilde;O SENSORIAL DE BATATA-DOCE ROXA "CHIPS" E PALITO ARA&Uacute;JO, J. S. F1; COSTA, J. S.1; SILVA, G. M. S.1; CAVALCANTI, M. T.2 1 Graduandas de Engenharia de Alimentos da Universidade Federal de Campina Grande 2 Professora UATA/CCTA/UFCG RESUMO O mercado consumidor tem se mostrado cada vez mais exigente na busca por alimentos nutritivos, que tragam em sua formula&ccedil;&atilde;o algum apelo saud&aacute;vel, mas, que ainda assim seja agrad&aacute;vel sensorialmente em todos os aspectos. Com base neste enfoque, este trabalho teve como objetivo verificar a aceita&ccedil;&atilde;o de batatas doce roxa frita no formato "chips" e palito. O teste de aceita&ccedil;&atilde;o foi realizado por 60 avaliadores n&atilde;o treinados (consumidores) que avaliaram os atributos de apar&ecirc;ncia, cor, aroma e textura por meio de uma escala hed&ocirc;nica estruturada de nove pontos, como tamb&eacute;m a inten&ccedil;&atilde;o de compra do produto. A batata doce roxa frita no formato', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2863', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca17', 'AVALIAÇÃO SENSORIAL DE DOCE DE CHOCOLATE “BRIGADEIRO” COM POTENCIAL FUNCIONAL', 'Cavalcanti, Monica Tejo; Araujo, Jayuri Fernades; Costa, Jessyka Silva; Silva, Gabriela Souza', 'Editora Verde', 'Agriculture', 'Agriculture', 'AVALIA&Ccedil;&Atilde;O SENSORIAL DE DOCE DE CHOCOLATE &ldquo;BRIGADEIRO&rdquo; COM POTENCIAL FUNCIONALSILVA, G. M. S.1; COSTA, J. S.1; ARA&Uacute;JO, J. S. F1; CAVALCANTI, M. T.21 Graduandas de Engenharia de Alimentos da Universidade Federal de Campina Grande2 Professora UATA/CCTA/UFCGRESUMOA preocupa&ccedil;&atilde;o dos consumidores em rela&ccedil;&atilde;o &agrave; alimenta&ccedil;&atilde;o vem mudando muito nas &uacute;ltimas d&eacute;cadas, neste contexto o presente trabalho teve como objetivo avaliar a aceita&ccedil;&atilde;o de um doce &ldquo;brigadeiro&rdquo; sabor chocolate com potencial funcional elaborado com a biomassa da banana verde e farinha de arroz. O teste sensorial foi realizado com 60 avaliadores n&atilde;o treinados (consumidores), onde avaliaram os atributos apar&ecirc;ncia, cor, sabor, textura e aroma e a intens&atilde;o de compra do produto elaborado. O brigadeiro apresentou boa aceita&ccedil;&atilde;o, com escore variando de 6 (gostei moderadamente) a 8 (goste', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2868', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca19', 'BISCOITO COM SUBSTITUIÇÃO PARCIAL DE FARINHA DE TRIGO POR FARINHA DE ARROZ VERMELHO', 'Farias, Fernanda Gomes de; Silva, Elaine Juliane da Costa; Silva, Geraildo Alexandre Sousa e; De Lira Andrade, Mychelle De Lira; Cavalcanti, Mônica Tejo', 'Editora Verde', 'Agriculture', 'Agriculture', 'A boa qualidade nutricional, facilidade de consumo, disponibilidade em diferentes variedades e custo acessível, são fatores que contribuem para maior popularidade dos biscoitos consumidos em quase todos os níveis de sociedade, a partir deste nicho este trabalho teve como objetivo a elaboração de biscoito salgado enriquecido com farinha de arroz vermelho polido. Foram elaborados o biscoito padrão, contendo unicamente farinha de trigo e o biscoito enriquecido com 20% da farinha de arroz vermelho polido. Os biscoitos foram analisados biometricamente e sensorialmente. Observou-se que ao enriquecer os biscoitos salgados com a farinha de arroz, o biscoito perdeu volume, apresentando espessura bem menor quando comparada ao biscoito padrão, isto se deve provavelmente a diminuição da rede de glúten formada. Porém, ao avaliar os produtos sensorialmente, foi observado boa aceitação entre os avaliadores (consumidores) podendo ser uma alternativa para elaboração de produtos de panificação mais saud', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/2871', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca1c', 'AVALIAÇÃO SENSORIAL DA FIBRA DO PEDÚNCULO DO CAJÚ (Anacardium occidentale L.) EM DIFERENTES CONCENTRAÇÕES COMO RECHEIO EM PASTEIS', 'Oliveira, Cybelle Pereira de; Sales, Airton Ricart Rodrigues de; Lima, Anderson Florentino de; Silva, Jéssica Leite da; Santana, Andressa Gonçalves de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A utilização industrial do pedúnculo de caju é direcionada principalmente ao mercado interno com a produção de sucos e doces. Estas indústrias geram resíduos conhecidos popularmente como bagaço de caju, que em geral são reaproveitados para enriquecimento da ração animal ou descartados por falta de incentivo de seu uso na alimentação humana. O objetivo desse trabalho foi elaborar um recheio para pasteis utilizando-se da fibra do pedúnculo de caju em diferentes concentrações, tendo como formulação padrão um pastel com recheio de frango, e avaliar sua influência sensorial na aceitação do produto. Os resultados estatísticos foram calculados com o auxílio do software Assistat e histogramas foram elaborados através do Excel. Em relação a aceitação, os pasteis com 60% de fibra e 40% de frango apresentaram maior índice de aceitação quando comparado aos demais formulações, exceto com relação ao atributo aroma. Os pasteis com 100% de fibra ficaram em segundo lugar em aceitação, seguido dos paste', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/3133', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca21', 'Caracterização e potencial funcional dos méis de abelhas melíponas no Estado da Paraíba', 'Pimenta, Sennyone Fernandes; Ferreira, Wallber Carneiro; Barbosa, Joicy Lima; Bezerra, Erick dos Anjos; Cavalcanti, Mônica Tejo; Santos, José Lucas Guilherme', 'Editora Verde', 'Agriculture', 'Agriculture', 'Entre as abelhas sociais, além da conhecida Apis mellifera, estão as da tribo Meliponini, que agrupa vários gêneros de abelhas sem-ferrão. As abelhas se-ferrão foram as únicas espécies produtoras de mel empregadas até 1838, antes da introdução da abelha europeia. Existem hoje no Brasil inúmeras espécies de abelhas sem-ferrão e ainda há muito trabalho de pesquisa a ser feito para conhecer essa diversidade que a cada dia tem novas surgindo. Diversos parâmetros físico-químicos vêm sendo utilizados na caracterização do mel, pois se trata de um alimento complexo com composição variada em função da origem floral e geográfica, assim como pelas condições climáticas. O estado da Paraíba se apresenta como uma gama de possibilidades para estudo dos Meliponineos, tendo em vista a grande diversidade de espécie ativas presente neste estado. O objetivo desse trabalho foi avaliar teor de fenólicos totais através do método de Folin-Ciocalteau, utilizando como padrão o ácido gálico, foram analisados tam', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/4515', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b006d6a63682f044ca28', 'Visitantes florais da alfazema-do-campo (Vitex agnus castus) em Petrolina, Pernambuco', 'Ribeiro, Márcia de Fátima; Santos, Karina Pereira dos; Mariano, Aline Mariza Costa', 'Editora Verde', 'Agriculture', 'Agriculture', 'A alfazema-do-campo (Vitex agnus castus) é uma planta originária do mediterrâneo que se adapta bem às condições da caatinga do NE brasileiro. Ela tem caraterísticas que lembram a lavanda (Lavandula spp.), quanto à flor, odor e aspectos medicinais. Oferece pólen e néctar e é muito atrativa para abelhas e outros insetos. Dessa forma, o presente trabalho teve por objetivo identificar os visitantes florais desta planta.  O estudo foi realizado com duas plantas de alfazema-do-campo localizadas na Embrapa Semiárido, em Petrolina (PE), durante novembro e dezembro de 2016 e abril de 2017. As observações (n= 9 dias) foram realizadas de 08h00 as 14h10, em períodos de dez minutos a cada meia hora. Em outros dias, quando não foram realizadas observações, alguns visitantes florais foram coletados com uma rede entomológica para posterior identificação taxonômica. Os resultados mostraram que houve grande prevalência de irapuá (Trigona spinipes) e abelha-branca (Frieseomelitta doederleini). Outras esp', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5299', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca36', 'Produção de abelhas rainha (Apis mellifera L.) em colmeias não orfanadas na Embrapa Amazônia Oriental', 'Andrade, Andrio Andrade de; Pereira, Daniel Santiago; Venturieri, Giorgio Cristino; Muller, Peter Hans Pessoa de Melo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este estudo objetivou avaliar o método de produção comercial de rainhas “Queen Right” adaptado às condições da Amazônia Oriental para produção de abelhas rainha africanizadas (Apis mellifera L.). Os ensaios foram realizados durante o mês de setembro de 2016 no Apiário da Embrapa Amazônia Oriental, em Belém-PA. Foram preparadas 03 colmeias Iniciadoras-Terminadoras utilizando-se como recria o modelo mini-recria Ribeirão Preto acoplado em colmeia Langstroth separados por tela excluidora. As larvas para transferência foram obtidas a partir de colônia de apicultor da região com índice produtivo e higiênico conhecidos. Foi utilizado o método proposto por Doolittle (1899), e, as larvas foram transferidas às células artificiais utilizando-se agulha chinesa. Não se fez uso de geleia real como indutor à aceitação das larvas por parte das operárias. Encontrou-se que a taxa de produção de rainhas foi de 75%.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5317', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca3d', 'ALTERAÇÕES NO CRESCIMENTO E ACÚMULO DE MASSA SECA NO FEIJÃO CAUPI SUBMETIDO A DIFERENTES LÂMINAS DE IRRIGAÇÃO', 'SOUZA, FERNANDA SILVA DE; MENDEIROS, ANDERSON BARBOSA DE; GOMES, ITALLO HARLAN REINALDO ALVES; ALVES, ÁLVARO JOAQUIM SOARES; FERREIRA, MARIA GEANE DA SILVA', 'Editora Verde', 'Agriculture', 'Agriculture', 'O feijão caupi é uma espécie leguminosa de importância econômica e social para as regiões Norte e Nordeste. Encontram-se diversas variações de produtividade em razão de manejo adequado, fertilidade do solo, disponibilidade de nutrientes, viabilidade das sementes e principalmente disponibilidade de água. Objetivou-se analisar a influência do déficit hídrico no estágio vegetativo, sobre as características agronômicas de produção do feijão caupi. O trabalho foi realizado na Universidade Federal de Campina Grande- Campus de Pombal em casa de vegetação, as sementes foram semeadas em baldes de 6 litros, contendo solo classificado como franco-arenoso, não salino e não sódico, o material coletado foi proveniente do município de Pombal - PB e 5 sementes por balde. Utilizou-se delineamento experimental de blocos casualizados, com arranjo fatorial 4x5, as plantas foram irrigadas apenas com água até os 15 dias de vida, a partir dos 16 dias até os 52 dias de vida, foram irrigados com solução nutrit', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5374', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca42', 'ESTRATÉGIAS DE REMEDIAÇÃO DE UM SOLO SALINO-SÓDICO COM DIFERENTES CONDICIONADORES DE SOLO', 'VERIATO, RAFAEL G.; ROCHA, JOSINALDO LOPES ARAÚJO; GUIMARÃES, MARIA LUIZA C.; ARAUJO, KARIOLANIA FORTUNATO PAIVA', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito do cultivo de gramíneas e adição de material vegetal associados ou não a corretivos na remediação de um solo degradado por sais e sódio. O experimento foi conduzido em delineamento inteiramente casualizado, em esquema fatorial 3 x 3 + 1, onde foram combinados três tratamentos referentes ao cultivo do solo com gramínea (incorporação de material vegetal, cultivo com milheto e solo sem cultivo), três tratamentos referentes ao uso de corretivos (sem corretivo, sulfato de cálcio e enxofre elementar) e um tratamento adicional (solo não salino) com três repetições. A aplicação de enxofre elementar ou sulfato de cálcio ao solo contribuiu de forma am o melhoramento dos atributos químicos do solo em estudo. Da mesma forma a fibra de coco mostrou-se como alternativa promissora na melhoria do solo salinizado.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5381', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca46', 'PROCESSAMENTO DO FUBÁ DA PAIXÃO: PRODUTO DO PATRIMÔNIO GENÉTICO DO SEMIÁRIDO BRASILEIRO', 'OLIVEIRA, MÁRCIA R. T.; ANDRADE, TULIO H. L.; ALMEIDA, SORAYA A.; SILVA, PRISCYLLA V. B.; SILVA, FRANCYANE A.; DIAS, EMANOEL', 'Editora Verde', 'Agriculture', 'Agriculture', 'Famílias agricultoras do Território da Borborema cultivam milho a partir de sementes crioulas, pertencentes aos bancos de sementes por eles organizados e parte desses grãos são transformados em fubá. Diante do exposto, objetivou-se com esse trabalho acompanhar e descrever as etapas do processo de transformação dos grãos de milho de variedades crioulas em fubá, procurando identificar os pontos críticos do processo. A metodologia utilizada para coleta dos dados foi investigativa, tendo como base o acompanhamento in loco de todas as etapas da transformação dos grãos de milho armazenados na AS-PTA até obtenção do fubá, acompanhadas de documentações fotográficas, entrevistas e anotações das informações repassadas. O processamento do milho realizado pelos agricultores familiares do Polo da Borborema segue as etapas tradicionais de transformação de grãos de milho em farinha ou fubá comum, constituindo uma oportunidade de geração de renda e fortalecimento da agricultura familiar.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5385', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca4a', 'ELABORAÇÃO E DETERMINAÇÃO FÍSICO-QUÍMICA DE IOGURTE DE AÇAÍ (Euterpe oleracea) ADICIONADO DE GUARANÁ (Paullinia cupana) EM PÓ', 'NUNES, MARCOS V.; BATISTA, ELISABETH M.; COSTA, GLÓRIA L. VITAL DA; SOUZA, PAHLEVI A. DE; BESERRA, HIRLLEN N. BESSA RODRIGUES', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os objetivos deste trabalho foram a elaboração e determinação físico-química de iogurtes de açaí adicionados de guaraná em pó. O delineamento experimental procedeu no Laboratório de Leites e Derivados do Instituto Federal de Educação, Ciência e Tecnologia do Rio Grande do Norte – Campus Pau dos Ferros. Foram elaboradas 3 formulações de iogurte, sendo elas: formulação A (13,8% de polpa de açaí), formulação B (11,2% de polpa de açaí e 2,6% de guaraná em pó) e formulação C (12,1% de polpa de açaí e 1,7% de guaraná em pó), nas quais foram realizadas análises físico-químicas (pH, acidez, umidade, cinzas, açucares totais e proteínas). Os dados obtidos mostram que as formulações A, B e C apresentaram os seguintes resultados: pH (4,56; 4,59 e 4,55), acidez (0,65; 0,72 e 0,58) umidade (73,00; 71,10 e 72,30), cinzas (0,28; 0,46 e 0,61), açúcares totais (9,78; 18,31 e 9,75) e proteínas (5,79; 5,30 e 6,24). Diante dos resultados pode-se concluir que, quanto à composição físico-química das três for', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5390', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca4c', 'ELABORAÇÃO E CARACTERIZAÇÃO FÍSICO-QUÍMICA DE SORVETE COM SUBSTITUTOS DE GORDURA E AÇÚCAR', 'ANDRADE SOBRINHO, LUIZ G.; SÁ, AYLA D. F.; GOMES, QUÉZIA O.; LIMA, THAMIRYS L. S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A mudança no estilo de vida da população, tem se tornado cada vez mais frequente devido a grande preocupação com a alimentação e consequentemente com a saúde, no entanto, o mercado de produtos light/diet torna-se extremamente promissor. Diante deste contexto, objetivou-se a realização de um estudo que busque o desenvolvimento e caracterização físico-química de um sorvete utilizando inulina, como substituto de gordura, e os edulcorantes sorbitol e aspartame como substitutos de açúcar. Desta forma, foram elaboradas duas formulações; sendo um padrão com sacarose e gordura vegetal (P), e outra utilizando base pronta para gelados comestíveis formulada com inulina e edulcorantes (D). As duas amostras foram submetidas às análises de umidade, cinzas, proteína total, lipídios, carboidratos e realizou-se ainda o cálculo do valor energético. Os resultados demonstraram que o sorvete elaborado com substitutos de gordura e açúcar apresenta um valor energético reduzido, sendo uma boa opção para os co', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5392', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca4d', 'AVALIAÇÃO MICROBIOLÓGICA E SENSORIAL DE SORVETE SABOR NATA A BASE DE INULINA E EDULCORANTES', 'ANDRADE SOBRINHO, LUIZ G.; SÁ, AYLA D. F.; GOMES, QUÉZIA O.; LIMA, THAMIRYS L. S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'O sorvete é um alimento obtido a partir de uma emulsão de gorduras e proteínas, que através de um processo de batimento e congelamento, produz uma substância cremosa, suave e agradável ao paladar. O consumo de alimentos de baixa caloria tem aumentado muito nos últimos anos e a indústria de produtos lácteos, enfrenta o corrente desafio de atender a este público. No entanto, a única forma de avaliar a aceitação de um novo produto é por meio de testes sensoriais. Aliado a este contexto, o objetivo do presente estudo é elaborar um sorvete sabor nata utilizando inulina e edulcorantes como substitutos de gordura e açúcar respectivamente, e avaliar o seu perfil microbiológico e sensorial. Produziram-se duas formulações de sorvetes, onde as mesmas foram submetidas às análises de Salmonella sp/25g, Coliformes a 45oC e Staphylococcus coagulase positiva/g. Para a avaliação sensorial realizou-se os testes de aceitação e intenção de compra. As duas formulações de sorvetes encontram-se de acordo com', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5393', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca51', 'QUALIDADE PÓS-COLHEITA DE TOMATE COM RECOBRIMENTO  COMESTÍVEL DE ALGAS', 'GOMES, FERNANDO ANTÔNIO LIMA; ARAÚJO, RAILENE HÉRICA CARLOS ROCHA; PESSÔA, URIEL CALISTO MOURA; TORRES JUNIOR, GILBERTO ANTÔNIO; OLIVEIRA, ÁGDA MALANY FORTE DE', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho, verificar a eficiência do uso de recobimentos comestíveis a base de algas, sob a conservação pós-colheita de tomate. O mesmo foi desenvolvido no Laboratório de Tecnologia de Pós-Colheita de Frutos, do Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, Campus Pombal, constando  da proporção 1:1 de ágar e Chlorella sp., respectivamente, constituindo formulações de recobrimentos nas seguintes concentrações T1: 0% (ágar + Chlorella sp.), T2: 1% (ágar + Chlorella sp.), T3: 2% (ágar + Chlorella sp.) e T4: 3% (ágar + Chlorella sp.), acrescidos de 0,5 mL/L de óleo mineral. Após a imersão dos frutos na formulação, acondicionou-se em B.O.D a 10ºC e 42% UR seguido da análise após 8 dias de armazenamento. O experimento foi realizado em delineamento inteiramente ao acaso, com 4 repetições e 2 frutos por parcela. Verificou-se que o recobrimento T2, 1% de ágar + 1% de Chlorella sp. mantiveram os melhores indicativos de qualidade no', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5397', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca52', 'INFLUÊNCIA DA SECAGEM NA COMPOSIÇÃO CENTESIMAL DA CASCA DO ABACAXI', 'LEITE, DANIELA DANTAS DE FARIAS; LIMA, ANA RAQUEL CARMO DE; QUEIROZ, ALEXANDRE JOSÉ DE MELO; SANTOS, FRANCISLAINE SUELIA DOS; LISBÔA, JEMIMA FERREIRA', 'Editora Verde', 'Agriculture', 'Agriculture', 'Cerca de ¾ do abacaxi são considerados rejeitos pela indústria de polpa de frutas, mas esses rejeitos possuem elevados teores de açúcares, fibras, um razoável conteúdo proteico, além de vitaminas. Diante disso, o trabalho foi realizado com o objetivo de se estudar a influência da temperatura de secagem da casca de abacaxi sobre os parâmetros físico-químicos. As cascas foram submetidas à secagem em estufa com circulação a ar nas temperaturas de 75 °C e 85 ºC, e submetidas a análises de teor de água, cinzas, pH, acidez, atividade de água, sólidos totais e solúveis e parâmetros de cor. Diante dos resultados o resíduo da casca do abacaxi caracterizou-se como um material com alto teor de sólidos e conteúdo mineral após os tratamentos de secagem estudados. Nos processos de secagem o tratamento com a maior temperatura originou amostras com maiores pH, sólidos totais, sólidos solúveis e em todos os parâmetros de cor, acarretando efeito inverso para atividade de água, teor de água e teores de c', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5398', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca55', 'AVALIAÇÃO DO ESTADO NUTRICIONAL DO ARROZ VERMELHO COM DOSES DE BORO E ENXOFRE DA SOLUÇÃO NUTRITIVA', 'RAPOSO, ROBERTO WAGNER CAVALCANTI; SANTOS, GAUDÊNCIO PEREIRA DOS; VIEIRA, MONTESQUIEU DA SILVA; PEREIRA, WALTER ESFRAIN; FÉLIX, VICTOR JÚNIOR LIMA', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito de doses de boro e enxofre no estado nutricional do arroz vermelho. O experimento foi conduzido em casa de vegetação sob solução nutritiva, aplicando quatro doses de ácido bórico (H3BO3), 0,135; 0,270; 0,540 e 1,08 mg L-1 e duas de MgSO4.7H2O 32 e 48 mg L-1 com um delineamento experimental inteiramente casualizado num fatorial 4 x 2 constituído por 11 plantas por bandeja. Após 42 dias de germinação avaliou-se os teores de N, P, K, S e B nas folhas e raízes das plantas. Os tratamentos influenciaram os teores de potássio nas folhas e nitrogênio e fósforo nas raízes, os demais elementos avaliados não sofreram interferências significativas.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5401', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca5b', 'ANÁLISE PRELIMINAR DOS EFEITOS TÓXICOS DO CÁDMIO NO CRESCIMENTO DE PLÂNTULAS DE Phaseolus vulgaris L.', 'OLIVEIRA, JOSÉ LUCAS DOS S.; SILVA, EDEVALDO DA; SANTOS, PEDRO S. DOS; SOUSA, CYNTHIA ARIELLY A.; GUILHERME, MARIA DE FÁTIMA DE S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os metais pesados são elementos químicos tóxicos que podem estar presente naturalmente no ambiente, ou ser proveniente de atividades antrópicas. As concentrações de cádmio no ambiente têm aumentado em virtude da grande quantidade de resíduos sólidos que são depositados inadequadamente no meio ambiente. Essa pesquisa avaliou o efeito de concentrações experimentais de cádmio no crescimento da raiz de feijão (Phaseolus vulgaris L. (var. BRS Estilo)). Ela foi desenvolvida no Laboratório de Pesquisas Ambientais, da Universidade Federal de Campina Grande, campus de Patos, entre agosto e outubro de 2016. Foram utilizadas quatro concentrações experimentais de cádmio: 0,3; 0,5; 1,0 e 3,0 mM, mais o controle de variância, com água deionizada. As sementes foram germinadas em placas de Petri e as medidas da raiz foram realizadas por meio de um paquímetro digital. As medidas foram realizadas após 48h de exposição ao cádmio, sendo determinado o potencial inibitório para o crescimento da raiz. O feij', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5437', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca5c', 'Atividades desenvolvidas durante estágio em laboratório de Apícola de Colégio Agrícola no Estado da Paraíba', 'Silva, Maurizetes da Cruz da; Veríssimo, Suênia Maria Ramos; Lima, Rodrigo Silva de; Nero, Joana D´Arck Pê de; Leite, Deborah Cruz', 'Editora Verde', 'Agriculture', 'Agriculture', 'Sendo uma das atividades mais antiga da agropecuária, a apicultura envolve uma cadeia de produção diversificada para o homem do campo como o mel, geleia real, própolis, cera, pólen e apitoxina, além de sua maior contribuição a polinização para produção agrícola e preservação da mata nativa, baixa custo inicial. Diante das necessidades de conhecer e identificar os obstáculos e potencialidades do sistema de criação e manejo. Objetivou- se desenvolver métodos de manejo no setor apícola que contemplasse o ensino a e pesquisa na relação com as técnicas de manejo de criação. As atividades foram realizadas junto ao Laboratório Apícola do Colégio Agrícola “Vidal de Negreiros” do Centro de Ciências, Humanas, Sociais e Agrarias, Campus III Bananeiras, Paraíba. Entre as diversas atividades foram realizadas a manutenção e segurança do Laboratório Apícola, como também revisão das colméias de Apis mellifera L. e a captura de exames passivos e ativos, os quais receberam alimentação artificial proteic', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5492', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca5e', 'Perfil das propriedades e produtores de mel no município de Taperoá, Paraíba', 'Silva, Israel Walter Hilário da; Vale, Vanderleia Alves do; Melo, Thiago Sousa; Souza, José Thyago Aires; Ferreira, Roberto Carlos Cavalcante', 'Editora Verde', 'Agriculture', 'Agriculture', 'A Apicultura e a Meliponicultura, destacam-se entre as principais atividades pecuárias no Brasil e na região Nordeste, devido a estas se caracterizarem como fontes de renda, principalmente em propriedades de base familiar. Neste sentido objetivou-se caracterizar o perfil das propriedades e dos produtores da apicultura e meliponicultura no município de Taperoá, Paraíba. Este trabalho trata-se de uma pesquisa quali-quantitativa, realizada entre os meses de setembro e dezembro de 2014 envolvendo dez apicultores e meliponicultores do município de Taperoá no Cariri Paraibano, foram usados questionários para caracterizar a atual situação destas atividades no município. As variáveis estudadas foram: O gênero das abelhas criadas, área total da propriedade, área destinada à criação de abelhas, além de dados socioeconômicos, como: idade, tempo de atividade, renda familiar, sexo e escolaridade. A maioria das propriedades apícolas possui área total maior que 2 hectares (ha), sendo que mais de 1 ha', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5495', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca5f', 'Produtividade e manejo alimentar de colmeias apícolas durante período de estiagem no Cariri Paraibano', 'Vale, Vanderleia Alves do; Silva, Israel Walter Hilário da; Souza, José Thyago Aires; Melo, Thiago Sousa', 'Editora Verde', 'Agriculture', 'Agriculture', 'A atividade apícola é essencialmente ecológica e comprovadamente rentável, a exploração racional das abelhas é uma prática cada vez mais se destaca no Brasil. A Apicultura está entre as principais atividades pecuárias no Brasil e na região Nordeste, devido a esta se caracterizar como fontes de renda, principalmente em propriedades de base familiar. Objetivou-se caracterizar a produção da apícola, bem como o manejo alimentar das colmeias no município de Taperoá no Cariri paraibano durante período de estiagem. Foi realizada uma pesquisa quali-quantitativa, entre os meses de setembro e dezembro de 2014 envolvendo produtores do município de Taperoá, Paraíba, foram usados questionários abordando as variáveis: número de colmeias, produção por apiário, os produtores que alimentam artificialmente as colmeias. Houve aumento no número de colmeias em algumas propriedades de 2013 para 2014, contudo a estiagem e a deficiência de manejo fizeram com que a produção fosse reduzida. Percebeu-se o desint', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5497', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca60', 'Escrituração zootécnica em colmeias de Apis mellifera sob alimentação artificial em período de estiagem no Sertão Paraibano', 'Maracajá, Patrício Borges; Pereira, Emmanuel Moreira; Andrade, Anderson Bruno Anacleto de; Silva, Kaique Oliveira; Souza, Tulio Alberto de Oliveira; Lima, Tiago Silva; Santos, José Lucas Guilherme; Si', 'Editora Verde', 'Agriculture', 'Agriculture', 'A apicultura é caracterizada como a exploração racional de abelhas do gênero Apis, possibilitando com essa atividade a obtenção de bons resultados econômicos, ecológicos e sociais. Nos últimos anos, o Nordeste vem obtendo um grande êxito no desenvolvimento da apicultura, contudo sendo fundamental que se utilize de técnicas de manejo adequadas para que o apicultor venha a evitar perdas futuras. Nesse sentido, objetivou-se acompanhar por meio da escrituração zootécnica colmeias de Apis mellifera sob alimentação artificial em período de estiagem no Sertão paraibano. O presente trabalho foi realizado em apiário experimental da Universidade Federal de Campina Grande, Campus Pombal, no período de 27 de agosto a 29 de setembro de 2016. O trabalho foi realizado através de coleta de dados com a utilização de fichas para escrituração zootécnica, com a inclusão de dados como: tamanho do enxame, reserva de alimento, postura da rainha, quantidade de mel pronto para ser colhidos, entre outras variáv', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5498', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca66', 'Relato sobre o perfil de mulheres atendidas pelo projeto de extensão “Abelha Operária Empoderada”', 'Sales Junior, Francisco Vieira; Silva, Antonia Francimar da; Almeida, Kaísa Iana Aires de; Silva, Wesley Breno de Freitas; Carvalho, Leonardo Emmanuel Fernandes de; Mesquita-Carvalho, Luciene Xavier d', 'Editora Verde', 'Agriculture', 'Agriculture', 'Para pessoas que apresentam vulnerabilidade social, uma das formas de garantir uma fonte de renda extra é através de atividades artesanais. O artesão é aquele profissional que possui a sensibilidade no olhar de transformar um simples objeto em uma obra de arte, através da produção manual. O projeto Abelha Operária Empoderada, realizado na mesorregião de Pau dos Ferros no Alto Oeste Potiguar, tem como intuito estimular o empoderamento feminino no âmbito do trabalho, qualificando mulheres de baixa renda da região para a produção de produtos artesanais de base apícola. Neste trabalho, objetivou-se verificar o perfil sócio-econômico das mulheres atendidas pelo referido projeto, sendo para isso aplicado um questionário semiestruturado com os seguintes pontos norteadores: a região que mora; a disponibilidade para participar de todas as atividades previstas no projeto; a vulnerabilidade social e sua escolaridade. Com isto podemos concluir que se fazem necessárias mais políticas de capacitação', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5510', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca69', 'Perfil dos criadores de Apis mellifera L. no município de Aparecida, Paraíba', 'Silva, Mateus Gonçalves; Andrade, Weliton Carlos de; Gomes, Mayslane de Sousa; Dantas, Maria Cândida de Almeida Mariz; Moreira, Joserlan Nonato; Sousa, Vanclea Teles da Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'A criação de abelhas é uma atividade de grande importância cultural, social e econômica, e vem sendo amplamente desenvolvida por pequenos agricultores do Nordeste. Dessa forma, objetivou-se caracterizar os apicultores do município de Aparecida na Paraíba, conforme seus aspectos sociais, econômicos, de produção e de venda. O período de realização da pesquisa ocorreu entre agosto e setembro de 2017, com entrevistas e aplicação de questionário direto aos produtores, observando os seguintes parâmetros: sexo, distribuição etária, grau de escolaridade, acesso a crédito, associativismo, tempo de atividade, colmeias em produção, formas de vendas dos produtos da colmeia e qual a representação da apicultura na renda familiar. Pode-se que os apicultores aparecidenses, possuem bastante experiência na área, estão organizados em cooperativas, mas ainda carecem de recursos e instrumentos que contribuam no aumento na produção e desenvolvimento da apicultura no município, possibilitando melhores condiç', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5513', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca6c', 'COMPOSIÇÃO QUÍMICA DE UM NEOSSOLO FLÚVICO EM FUNÇÃO DA MATÉRIA ORGÂNICA E DIFERENTES LAMINAS DE IRRIGAÇÃO', 'FERREIRA, DANIEL DA S.; MESQUITA, EVANDRO F.; SANTOS, ALBANIZA P. DE LIMA; DINIZ NETO, MANOEL ALEXANDRE; MARTINS, FLÁVIO J. R.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito da adubação orgânica e diferentes lâminas de irrigação nas alterações das propriedades químicas de um NEOSSOLO FLÚVICO Eutrófico. Os tratamentos foram distribuídos em blocos casualizados usando o esquema fatorial 2x5, referente a duas lâminas de irrigação de 100 e 50% baseado na evapotranspiração da cultura (ETc), cinco doses de esterco bovino para elevar o teor de matéria orgânica de 1,8% para 2,8; 3,8; 4,8 e 5,8%, com quatro repetições, perfazendo 40 parcelas com 15plantas de quiabo por parcela. Após 140 dias após aplicação dos tratamentos, foi coletada amostra de solo e feita a analisada química para saber os teores de pH, fósforo (P), cálcio (Ca), magnésio (Mg), potássio (K) e sódio (Na). A aplicação de esterco bovino ao solo entre 4,8 e 5,8% e a irrigação com 100% da evapotranspiração da cultura – Etc proporcionaram incrementos nos atributos químicos do Neossolo Flúvico Eutrófico.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5542', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca6e', 'GERENCIAMENTO DOS RESÍDUOS SÓLIDOS EM UMA INDÚSTRIA DE FABRICAÇÃO DE SACOLAS PLÁSTICAS NA CIDADE DE POMBAL - PB', 'FERREIRA, LAIANY TÁSSILA; SILVA, LUISA THAYNARA M. DE S.; SEVERO, CIBELLE GUIMARÃES SILVA; CAVALCANTI, INGRI LÉLIS R.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A problemática relacionada aos impactos ambientais devido ao setor industrial é algo presente e preocupante no Brasil, pois o gerenciamento inadequado dos processos produtivos pode gerar consequências que afetam os meios antrópico, biótico e físico. Nesse sentido, o presente trabalho objetivou-se avaliar o gerenciamento dos resíduos sólidos de uma Indústria localizada no munícipio de Pombal – Paraíba. Nesta indústria ocorre a reciclagem de materiais plásticos do tipo Polietileno, para a produção de sacolas plásticas. Foram observados os impactos ambientais ocorrentes na fase de operação do empreendimento, desde a fase da triagem até a fase beneficiamento das sacolas plásticas. Os impactos ambientais foram elencados a partir dos métodos de avaliação de impactos ambientais Ad Hoc e CheckList, e foram percebidos impactos positivos e negativos.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5544', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca73', 'COMPONENTES DE PRODUÇÃO DA ABOBRINHA SOB ADUBAÇÃO NITROGENADA COM E SEM SILÍCIO', 'SILVA, F. L.; SOUSA, C. S.; MESQUITA, E. F.; FIGUEREDO, L. L.; LIMA, A. S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito de doses de nitrogênio na presença e ausência de Si na produtividade da cultura da abobrinha. Para isto, o experimento foi conduzido em condições de campo no período de dezembro de 2016 a março de 2017, adotando-se o delineamento em blocos casualizados (DBC), em esquema fatorial 6 x 2, constituídos por seis doses de nitrogênio (0; 30; 60; 90; 120 e 150 Kg/ha), a fonte de nitrogênio utilizada foi ureia (45% de N), com e sem silício (2,0 L ha-1), utilizando o silicato de potássio (12% SiO2 e 12% K2O) e três repetições, perfazendo 36 parcelas experimentais, a irrigação foi realizada por gotejamento. Foram avaliadas as seguintes variáveis: massa média dos frutos (kg); produção total de frutos (g planta-1) e produtividade (kg ha-1). O aumento da doses de nitrogênio proporcionou aumento na produção da abobrinha. A aplicação de silício afetou toas as variáveis do experimento. A dosagem máxima de nitrogênio afetou negativamente a produtividade da abobrinha.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5549', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca77', 'ESTÁGIO SUPERVISIONADO: A Importância dos Equipamentos Tecnológicos no Ambiente Escolar', 'SUASSUNA SOBRINHO, NELSON SUASSUNA; SANTOS, ALBANISA PEREIRA DE LIMA; MELO, DALILA REGINA MOTA; LIMA, WESLEY VINÍCIOS SUASSUNA; SUASSUNA, CESENILDO FIGUEREDO; MELO, EMANUELA CANDIDA', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo desse relatório é apresentar as experiências vividas em sala de aula, como também buscar novas metodologias de ensino para enriquecer e melhorar a aprendizagem dos alunos, com o uso de equipamentos tecnológicos. O presente trabalho foi desenvolvido no Centro de Ensino Fundamental Luzia Maia– Catolé do Rocha – PB.   Trata das atividades referentes ao componente curricular Estágio Supervisionado II do curso de Licenciatura Plena em Ciências Agrárias, da Universidade Estadual da Paraíba campus IV, onde na ocasião foi realizadas intervenções em sala de aula, pesquisas de referências bibliográficas dos conteúdos aplicados no estudo, em específico o momento de intervenção em sala de aula. A partir das avaliações desse estudo, conclui-se pela necessidade de implementação de práticas direcionadas ao uso de equipamentos tecnológicos para possibilitar o melhor desenvolvimento do ensino e aprendizagem no ambiente escolar.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5662', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca78', 'DESAFIOS ENFRENTADOS PELOS PROFESSORES ORIENTADORES DO ESTÁGIO SUPERVISIONADO', 'de Souza, Joilma Maria; Sales Solano, Alane Rayane; Mota de Melo, Dalila Regina; Lucena Bezerra, Lisiane', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi identificar os desafios enfrentados pelos professores orientadores na realização do Estágio Supervisionado do Curso de Licenciatura em Ciências Agrárias da UEPB e apontar caminhos para melhoria da realização do estágio da formação docente. A pesquisa foi conduzida em 2016 na Escola Agrotécnica do Cajueiro/UEPB. Foi aplicado um questionário contendo cinco perguntas que foram aplicadas aos professores orientadores do estágio. Conclui-se que os desafios enfrentados pelos professores orientadores do estágio é a falta de tempo, tanto para os professores e/ou estagiários, a falta de condições adequadas de trabalho e experiência profissional dos estagiários. Os caminhos para melhoria do estágio foram: melhores condições de trabalho em sala de aula; maior tempo no estágio; o aluno estagiário deve superar o medo e a insegurança para assumir a sala de aula e o professor supervisor de Estágio deve acompanhar efetivamente o aluno durante o desenvolvimento do estágio.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/5886', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca7c', 'Oficina de técnicas de manejo em sistemas apícolas: despertando o interesse na  criação de abelhas', 'Wolff, Luis Fernando; Lacerda, Dayane Cristine de Oliveira; Gomes, Mário Conill; Tavares, Marisa Sandra Wienke; Jesus, Juliana Aparecida Mateus Pereira de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A criação de abelhas é uma atividade que não proporciona impacto ambiental e, que oportuniza lucratividade ao produtor. Tanto a meliponicultura quanto a apicultura têm se consolidado na agricultura familiar, pois possibilitam uma alternativa de renda às famílias. No intuito de difundir a prática da atividade apícola, foi realizada uma oficina de Técnicas de Manejo em Sistemas Apícolas, na III Semana Integrada de Inovação, Ensino, Pesquisa e Extensão, da Universidade Federal de Pelotas (UFPEL) no ano de 2017. A oficina visou promover os conhecimentos sobre o desenvolvimento de práticas apícolas, manejo de meliponários de forma sustentável e a identificação das espécies de abelhas nativas sem ferrão, em especial as de ocorrência natural no Rio Grande do Sul. Apresentou também os mecanismos de defesa e os benefícios do bem estar animal na meliponicultura. Objetivou-se contribuir com a conscientização dos interlocutores sobre a importância da criação e preservação das abelhas, considerando', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6043', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca7e', 'Físico-química do mel de abelhas produzido e comercializado na região do município de Sousa, Paraíba', 'Silva, Mateus Gonçalves; Santos, Adriana da Silva; Epaminondas, Poliana Sousa; Pinto, Kalielson Renato da Silva; Silva, Kássia Raffaela Roque; Rodrigues, Bryan Ivie Oliveira', 'Editora Verde', 'Agriculture', 'Agriculture', 'Entende-se por mel o produto alimentício produzido pelas abelhas melíferas, a partir do néctar coletado das flores ou das secreções procedentes de partes vivas das plantas ou de excreções de insetos sugadores de plantas que ficam sobre partes vivas de plantas, que as abelhas recolhem, transformam, combinam com substâncias específicas próprias, armazenam e deixam madurar nos favos da colmeia. A qualidade dele depende de alguns fatores como: origem botânica do néctar coletado, espécie da abelha, condições ambientais e do manejo pré e pós-colheita. Este trabalho teve como objetivo determinar as características físico-químicas de amostras de mel comercializadas e provenientes de produção em comunidades rurais da região da cidade de Sousa (PB). Foram utilizadas 20 amostras de mel, provenientes de 20 colônias localizadas na zona rural da referida região. As amostras foram armazenadas em embalagens de vidro transparentes, com tampa de rosca, capacidade para 500g, previamente lavados e esteril', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6046', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca81', 'A meliponicultura na extensão rural: fomentando a produção alternativa.', 'Sousa, Breno Henrique de; Gomes, Mário Conill; Lacerda, Dayane Cristine de Oliveira; Wolff, Luis Fernando', 'Editora Verde', 'Agriculture', 'Agriculture', 'A meliponicultura, ou seja, a criação de abelhas sem ferrão, é uma atividade sustentável, pela ausência de impactos ambientais e pela contribuição com o meio ambiente, por meio da polinização realizada pelas abelhas. Tem sido muito utilizada na agricultura familiar, integrando a criação de abelhas à produção agrícola. Além da renda obtida pela comercialização dos produtos apícolas, a polinização dos cultivos tem gerado renda devido à maior qualidade e tamanho aos frutos e aluguel dos enxames para a polinização dirigida. Durante o Estágio supervisionado III do curso de Licenciatura em Ciências Agrárias da Universidade Federal da Paraíba, realizou-se oficina de intervenção na Comunidade do Salgado, localizada no município de Casserengue (PB), objetivando apresentar a meliponicultura como uma atividade alternativa de renda, viável e tangível na realidade local. Além da oficina, foram confeccionados folders sobre meliponicultura, distribuídos aos agricultores durante a prática e fornecendo', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6049', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca86', 'Toxicidade de espinetoram e espinosade, via ingestão, sobre Apis mellifera L', 'Coelho, Micaela Silva; Rodrigues, Vitor da Silva; Costa, Ewerton Marinho da; Silva, Kaique Oliveira; Mendonça, Allysson Jonhnny Torres', 'Editora Verde', 'Agriculture', 'Agriculture', 'As abelhas em geral são insetos importantes para agricultura por contribuírem para a polinização de diversas flores e, consequentemente, para obtenção de frutos. Dentre as espécies de abelhas, Apis mellifera (Hymenoptera: Apidae) é um dos principais polinizadores em áreas agrícolas no mundo. No entanto, apesar da importância dos polinizadores, é crescente os casos de mortalidade de abelhas nas lavouras devido ao uso abusivo de produtos fitossanitários, principalmente os inseticidas sintéticos utilizados no manejo das pragas agrícolas. Portanto, o objetivo do trabalho foi avaliar os inseticidas Espinetoram e Espinosade, nas doses mínima e máxima recomendada para o controle de pragas em cucurbitáceas, via ingestão, sobre A. mellifiera. O trabalho foi realizado no laboratório de Entomologia do CCTA/UFCG, Campus Pombal-PB, em Delineamento Inteiramente Casualizado, composto por cinco tratamentos [Testemunha absoluta (água destilada), duas dosagens de Espinetoram (120 e 160 g/ha) e duas dosa', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6054', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca88', 'Manual de Boas Práticas de Fabricação no entreposto de mel em Aparecida,Paraíba', 'Nóbrega, Juliana Pereira da; Silveira, Andressa Soares da; Sousa, Christian Raphael Azevedo De; Bezerra, Naiara Menezes; Gomes, Maria Luiza Alves', 'Editora Verde', 'Agriculture', 'Agriculture', 'O mel é basicamente uma solução saturada de açúcares simples (principalmente glicose e frutose) produzido a partir dos néctares das flores que as abelhas coletam e combinam com substâncias específicas produzidas por elas. Esta mistura é armazenada e deixada maturar nos favos. Além dos açúcares, no mel existem pequenas quantidades de sais minerais, vitaminas, enzimas, aminoácidos, substâncias aromáticas, ácidos orgânicos, pigmentos e outras substâncias. A coloração, o aroma e o sabor do mel variam em função das floradas das quais as abelhas coletaram o néctar. A segurança alimentar dessa matéria prima exige cuidados desde o início da sua produção, até sua chegado no entreposto responsável pelo seu beneficiamento. As Boas Práticas de Fabricação (BPF) trazem um conjunto de medidas que devem ser adotadas pelas unidades de extração e beneficiamento do mel a fim de garantir a qualidade sanitária e a conformidade do produto. É necessário que a produção do mel seja toda realizada, desde o camp', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6056', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca89', 'Maionese caseira com adição de mel de Apis mellifera L.', 'Augusto, Letícia Pinheiro; Medeiros, Weverton Pereira de; Araújo, Alfredina dos Santos; Rodrigues, Maria do Socorro Araújo; Pinheiro, Larissa da Silva Santos; Alencar Segundo, Rosemberg', 'Editora Verde', 'Agriculture', 'Agriculture', 'Maionese é um molho à base de óleo e ovo, com a forma de uma emulsão, preparado a frio e condimentado com vários temperos, muitas pessoas optam por consumi-la devido as suas características organolépticas ou culturais. Por ser um alimento com ingredientes de origem animal (ovos), a maionese caseira é suscetível à presença de Salmonella sp., uma espécie de bactéria que provoca gastroenterite, septicemia e febre entérica. O mel por ser um excelente adoçante natural, com ação antimicrobiana, que tem a capacidade de impedir ou desativar o crescimento dos microrganismos e que vem a proteger contra doenças transmitidas por alimentos. Além de ser uma ótima fonte de energia por ser rico em carboidratos. Esta pesquisa teve por objetivo elaborar uma maionese com adição de mel de abelha Apis mellifera, caracterizando-a quanto aos parâmetros físico-químicos e microbiológicos. Para a caracterização das amostras foram realizadas análises de pH, condutividade, acidez titulável, umidade, cinzas, sólid', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6057', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca8a', 'Achocolatado com adição de mel de abelha Apis mellifera L.', 'Rodrigues, Amanda Araujo; Bernardino, José Matheus Figueiredo; Araujo, Alfredina dos Santos; Barreto, Josélia Silva; Pinheiro, Larissa da Silva Santos; Alencar Segundo, Rosemberg', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os achocolatados são alimentos consumidos em todo o mundo em que sua composição mais simples, contém cerca de 70% de sacarose ou de outros açúcares. As suas características nutricionais, assim como sua conveniência e praticidade, fazem com que o produto seja bem aceito pelo consumidor. A utilização de mel de abelha para elaboração de achocolatado é uma forma de enriquecimento com o intuito de agregar valor às mesmas na substituição do açúcar. Objetivou-se desenvolver um achocolatado com adição de mel de abelha verificando suas características físico- químicas e microbiológicas. Para a caracterização das amostras foram realizadas análises de pH, condutividade, acidez titulável, umidade, cinzas, sólidos solúveis, coliformes a 35ºC, coliformes a 45ºC, Staphylococcus ssp., Salmonella sp./25g e Fungos filamentosos e leveduras. Todas as amostras físico-químicas foram feitas em duplicatas. No que diz respeito a sólidos solúveis totais a literatura indica que as bebidas lácteas achocolatadas p', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6058', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca8c', 'Toxicidade sobre Apis mellifera L. de combinações de inseticidas usados no  controle de pragas em cucurbitáceas.', 'Silva, Luiz Antônio Freire Alencar; Barros, Carlos Henrique Peixoto de; Conceição, Leandro Clemente da; Costa, Ewerton Marinho da; Callou, Sávio Matheus de Sá', 'Editora Verde', 'Agriculture', 'Agriculture', 'As abelhas são consideradas os agentes mais adaptados e eficientes no processo de polinização. Em áreas agrícolas, um dos polinizadores mais eficientes é a abelha Apis mellifera (Hymenoptera: Apidae), pois sua presença é imprescindível para obtenção de frutos em várias culturas exploradas economicamente, como, por exemplo, em áreas de produção de cucurbitáceas. Contudo, apesar da importância para polinização, nos últimos anos tem-se observado o desaparecimento de abelhas em áreas agrícolas, sendo o uso de produtos fitossanitários considerado o recurso tecnológico mais impactante para os agentes polinizadores. Com isso, o número de pesquisas relacionadas ao tema vem crescendo, e a busca por informações que subsidiem o manejo de pragas com ênfase na preservação de agentes benéficos as culturas é fundamental. Portanto, o objetivo do trabalho foi avaliar os inseticidas Imidacloprido+Betaciflutrina e Clorantraniliprole+Abamectina, nas doses mínima e máxima recomendada para o controle de pra', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6060', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b009d6a63682f044ca91', 'Ultrapassando as barreiras de produção: As relações sociais da associação dos  apicultores de São Bentinho', 'Maracajá, Patrício Borges; Farias, Jordany Ramalho Silveira; Medeiros, Aline Carla de; Costa, Amanda Pereira da; Almeida, Patricia Pereira; Santana, Diogenes Silva de Medeiros', 'Editora Verde', 'Agriculture', 'Agriculture', 'A Apicultura é uma atividade econômica que vem crescendo eocupando espaço no mercado Brasileiro. No Nordeste ainda é uma atividade recente, no entanto já se configura como fonte de renda para pequenos produtores rurais, principalmente no Semiárido. O Nordeste chega a ser responsável por um terço da produção brasileira. Essa atividade vemcrescendo na região, principalmente devido apresentar baixo custo de implantação e manutenção. Além de possuir mercado favorável, estudos apontam também para o potencial apícola de diversas regiões do semiárido. Esse trabalho objetiva divulgar as relações sociais da Associação dos Apicultores de São Bentinho, bem como sua história, desde o início de suas atividades em 2009, graças a incentivos da Articulação do Semiárido (ASA) e da Associação dos Apicultores do Sertão Paraibano (ASPA). Após a realização de capacitações, aquisição de material, as atividades começaram no quintal de casa, devido a ausência de uma Casa de Extração de Mel, que viria se torna', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6068', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca93', 'Pudim de mel aromatizado com capim-santo', 'Araujo, Luan Gabriel de; Lima, Eduarda Sousa e; Barros, Theo Albino Ribeiro; Ferreira, Weslayna Firme; Cândido, Ana Flávia de Melo', 'Editora Verde', 'Agriculture', 'Agriculture', 'O pudim é a sobremesa mais popular das mesas brasileiras, é uma receita de origem portuguesa, com o tempo a popularidade do pudim se expandiu, agradando o paladar de diversos povos e gerações, seu sucesso pode ser explicado por seu sabor delicioso e também por ser um docemuito fácil e rápido de se fazer e sempre com formulações novas. Os alimentos funcionais possuem potencial para promover a saúde por meio de mecanismos não previstos pela nutrição convencional, devendo ser salientado que esse efeito restringe-se à promoção da saúde e não à cura de doenças. A busca por produtos naturais e saudáveis cresceu muito, motivo pelo qual o consumo de mel tem aumentado nos últimos anos. Mel é um produto rico em açúcares – o néctar original possui até 87% onde predominam glicose e frutose e que possui também, em quantidades muito menores, aminoácidos, minerais, ácidos orgânicos, enzimas, entre outros. O capim-santo tem como composição o limoneno, citronelal, mirceno, geraniol e o seu principal o ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6070', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca94', 'Pratos culinários sofisticados utilizando o mel da abelha Partamona cupira  Smith, 1863', 'Arruda, Maria Micaele Pereira; Vidal, Autenice Guilherme; Vidal, Thayna Guilherme', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se trabalhar a valorização e agregador valor a produção de mel produzido pelas abelhas sem ferrão, (Partamona cupira), permitindo aos meliponicultores uma potencialização do mel como matéria prima em pratos sofisticados salgados e doces finos. Tendo em vista o mel ser uma fonte de nutrientes, como: cálcio, fósforo, potássio, sódio, vitaminas C e B,além de proteínas e carboidratos. O trabalho foi desenvolvido na comunidade rural Sitio Duas Serras do município de Serra Branca no cariri paraibano. Com esse objetivo de utilizar o mel como ingrediente de pratos tradicionais da culinária nordestina, combinando com uma variedade de outrosingredientes regionais, foram criados pratos como: vinagrete, carne, molho, massas, doces, brigadeiros, ganaches e tortilhas e sempre tendo o mel como ingrediente marcante. Dentre os pratos criados os destaques foram, o doce de umbu com mel, o alfajor que utiliza caju com mel, brigadeirocom fruta de palma e mel, a empada salgada com carne de sol car', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6071', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca97', 'AVALIAÇÃO PRODUTIVA DE GENÓTIPOS DE FEIJÃO-CAUPI SUBMETIDOS AO ESTRESSE SALINO', 'Silva Junior, Eugênio Gonçalves; Ferreira da Silva, Anselmo; Forte Oliveira, Agda Malany; Sousa Lima, Jucelino; Ramalho do Nascimento, Fernanda', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se por meio deste trabalho avaliar a tolerância de genótipos do feijão-caupi submetidos a diferentes níveis de solução salina através de parâmetros produtivos. O trabalho foi realizado em 2013, na Universidade Estadual da Paraíba. O experimento foi constituído por dois genótipos de feijão-caupi, G1 = BRS Guariba, G2 = BRS Marataoã. O delineamento experimental utilizado foi DBC com 5 níveis de solução salina (0,8; 1,5; 3; 4,5 e 6 dS m-1), sendo 2 parcelas por tratamento em 4 blocos. Os parâmetros analisados foram: Peso de Vagem (PV), Comprimento de Vagem (CV), Número de Grãos (NG) e Peso de Grãos (PG). Os dados foram submetidos à análise de variância ao teste F, até 5% de significância. O genótipo G1 não tolerou o estresse acima de 3 dS m-1, no entanto, sobressaiu ao G2 em todos os parâmetros analisados, onde o mesmo reduziu gradativamente de acordo com o acréscimo das soluções salinas.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6404', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca98', 'AVALIAÇÃO PRODUTIVA DAS SEMENTES DE ACESSOS DO PINHÃO MANSO EM CLIMA SEMIÁRIDO', 'BATISTA, SAMYLLE GARCIA; MAIA, JOSEMIR MOURA; LIMA, JUCELINO SOUSA; SILVA JUNIOR, EUGÊNIO GONÇALVES; LIMA, JOSÉ CLEVERTON CUNHA', 'Editora Verde', 'Agriculture', 'Agriculture', 'Neste estudo, foram avaliados o desempenho fenológico de acessos de pinhão manso com desenvolvimento agronômico relevante em clima semiárido, durante dois ciclos produtivos. O experimento foi conduzido em campo na cidade de Catolé do Rocha - PB. Mudas de pinhão-manso, com 35 dias de idade, dos acessos CNPAPM-X, CNPAPM-III, CNPAPM-XI e CNPAPM-XIII, foram transplantadas para campo e cultivadas em delineamento de blocos casualizados com quatro blocos e três repetições totalizando 48 plantas. Todas as análises foram realizadas do 12º ao 18º mês após o transplantio. Os dados coletados foram submetidos à análise estatística para teste de significância e diferenças de médias ao nível de 1 e 5% de probabilidade pelo Teste Tukey. Podendo conclui, até o momento, e por esses períodos de observações que os acessos CNPAPM-XI e CNPAPM-XIII obtiveram um maior número de frutos e peso total dos frutos, não se observando diferenças estatísticas para os demais parâmetros estudados.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6411', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca99', 'CARACTERISTICAS FENOLOGICAS DE MAMOEIRO CULTIVADO SOB LÂMINAS DE IRRIGAÇÃO E BRASSINOSTERÓIDE', 'SOUZA, DHAYANE SANTOS; SOUSA, JOIMA MARIA; MAIA, JOSEMIR MOURA; SILVA, ANSELMO FERREIRA; ARAÚJO, ELCILENE ALVES', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os principais fatores limitantes da produtividade da cultura do mamão no nordeste são os estresses abióticos, sendo o déficit hídrico um desses fatores. Nesse contexto, avaliou-se as características agronômicas do mamoeiro em função da aplicação de brassinosteróide e lâminas de irrigação durante a fase vegetativa. O experimento foi conduzido em vasos utilizando a variedade Hawaí. O delineamento experimental utilizado foi em blocos cazualizados, em esquema fatorial 5x2 com quatro repetições. Sendo cinco lâminas de irrigação (60; 80; 100; 120 e 140% da evapotranspiração de referência - ET0), com (1,0 mg L-1) e sem brassinosteróide. O brassinosteróide foi aplicado via foliar aos 95 dias após o transplante e para avaliação dos efeitos dos tratamentos foi levado em conta o volume e umidade da raiz, umidade do caule e folha. Houve efeitos significativos (p≤0,01) para todos em função da aplicação do hormônio tendo o melhor desempenho quando irrigados com 100% da ET0.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6413', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca9b', 'O USO DAS TECNOLOGIAS DE INFORMAÇÃO E COMUNICAÇÃO NO ENSINO DE QUÍMICA', 'Costa, Maria Sheila Alves da; Ramos, Emanuel Victor da Silva; Silva, Ailton Linhares da; Silva, Hiago Aristides da; Santos, Francisco Rodrigo Vieira dos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O artigo intitulado “O uso das tecnologias de informação e comunicação no ensino de química” tem por objetivo refletir acerca das possibilidades de ensino e aprendizagem mediadas a partir da inserção de tecnologias informativas e comunicativas, que ao serem direcionadas pedagogicamente podem contribuir para o desenvolvimento de melhores processos de ensino e aprendizagem de Química. Desta forma, nos propomos por meio deste trabalho compreender como didaticamente elas podem ser introduzidas no ensino de Química, a ponto de potencializar os índices de aprendizagens discentes, visto que, boa parte dos conteúdos curriculares de químicas são apreendidos de forma dificultosa e desprazerosa por muitos discentes, o que dificulta ainda mais o ensino dotado de assimilação e compreensão de aplicabilidade no cotidiano. A construção deste trabalho pautou-se na utilização da pesquisa bibliográfica de abordagem qualitativa, apresentando dentre outros referenciais teóricos, Tardif (2014), Leão (2013) ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6647', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044ca9f', 'AGROTÓXICO COMO TEMÁTICA NO ENSINO DE QUÍMICA COM ÊNFASE NO IMPACTOS AMBIENTAIS: UMA ANÁLISE BIBLIOGRÁFICA', 'Sales, Luciano Leal de Moraes; Santos, Antoniel Pereira dos; Silva, Everton Vieira da', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este trabalho tem um intuito de trazer o tema transversal “Agrotóxico” como uma temática de ensino categórico nas salas de aulas onde se encontram alunos que, no seu cotidiano, possuem um contato direto com essas substâncias (herbicidas, bactericidas, fungicidas e etc.), porém não possuem uma instrução, aprendizagem técnica, nem conhecimento crítico perante os agrotóxicos e se utilizam do conhecimento passado de geração em geração para manipulação desses agentes. A maioria dos alunos que detém este conhecimento empírico dos agrotóxicos reside em zonas rurais (são esses os alunos prioritários que enfatizam esta pesquisa). Com uma análise bibliográfica de artigos há uma visão mais elaborada dos conceitos que veementemente mostram concepções antagónicas aos conhecimentos repassados para alunos do ensino médio, em principal foco àqueles que residem na zona rural e se deslocam para a cidade em busca de um melhor ensino. O trabalho mostra as principais deficiências no ensino em se tratar des', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6652', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044caa2', 'A QUÍMICA E A FÍSICA NUMA ABORDAGEM MULTIDISCIPLINAR E INTERDISCIPLINAR.', 'Batista, Boanerges da Silva; Ferreira Neto, Manoel Cristovão; Sousa, Wagney William Pereira de; Sales, Luciano Lealde Moraes', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este artigo trata-se de uma pesquisa quantitativa e descritiva, realizada em duas turmas da educação básica, uma turma de 1º e uma de 3º ano do Ensino Médio Regular, na E. E. E. F. M. Nelson Batista Alves, localizada na cidade de Bernardino Batista na Paraíba. O objetivo é debater a importância do desenvolvimento de um ensino multidisciplinar com aplicações embasadas na interdisciplinaridade, envolvendo as disciplinas Física e Química, buscando mostrar o ponto de vista de cada educando sobre os conceitos que envolvem Modelo Atômico. Desta maneira, adotou-se como ponto crucial a realização de pesquisas bibliográficas numa perspectiva qualitativa, que vários autores abordam a temática relacionada com a multidisciplinaridade e a interdisciplinaridade sobre Modelos Atômicos, para se confrontar com as respostas dos Discentes pesquisados, tendo como referências principais as obras de Bicalho, Cordiolli e Greca. Observam-se com isso que os educandos das disciplinas Química e Física possuem vi', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6655', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044caa8', 'APLICATIVOS PARA CONSULTA E ENSINO DE ELEMENTOS DA TABELA PERIÓDICA', 'Figueiredo, Luislândia Vieira de; Corrêa, Adriana Moreira de Souza; Silva, Egle Katerinne Souza da; Silva, Edilson Leite da', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os conteúdos de Química são vistos como de difícil compreensão pelos alunos. Por isso, os educadores precisam buscar recursos alternativos para favorecer o aprendizado deste componente curricular. Para isso, o docente precisa conhecer seus educandos e utilizar dos recursos disponíveis no cotidiano do aluno para que eles possam ser motivados a conhecer os assuntos a serem trabalhados. Por esta razão desenvolveu-se a pesquisa em tela com o objetivo de apresentar oito aplicativos, para uso e ensino da Tabela Periódica, temática essencial para a compreensão das relações estudadas na disciplina de Química. Para isso, buscou-se na loja virtual de aplicativos Play Store, jogos que contribuam para a internalização de conceitos pelo educando e, na sequência, os aplicativos foram apresentados. Desse modo, trata-se de uma pesquisa de abordagem qualitativa, de natureza descritiva que visa o levantamento dos recursos disponíveis e suas funcionalidades. Como resultados identifica-se a variedade de f', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6661', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044caaa', 'POTENCIAL CARIOGÊNICO DOS REFRESCOS INDUSTRIALIZADOS DETERMINADO A PARTIR DE MEDIDAS EMPÍRICAS', 'Souza, Elvis Stanlley Leite de; Wanderley, Albaneide Fernandes; Silva, Cícero Patrício da', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente trabalho busca, por meio de embasamentos teóricos, determinar através de práticas laboratoriais o potencial cariogênico, que os refrescos industrializados possuem, visto que os mesmos apresentam uma quantidade considerável de açúcar e também uma alta concentração de ácidos que são grandes contribuintes para o desenvolvimento dessa patologia. Para o desenvolvimento da pesquisa, foram recolhidas 10 (dez) amostras de refrescos industrializados de marcas distintas, os quais foram preparados de acordo com o rótulo. Foram realizadas medidas utilizando um pHmetro, determinou-se assim o nível de concentração de hidrogênio catiônico presente em cada amostra. Em seguida, determinou-se a quantidade de Sólidos Solúveis Totais (SST), com o uso de um refratômetro com escala de medida em graus Brix. O resultado, mostrou que as amostras analisadas, apresentaram alto nível de acidez, bem como também uma quantidade considerável de sólidos solúveis totais. E com isso, o consumo constante deste', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6663', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044caab', 'A ÁGUA COMO FATOR INDISPENSÁVEL À VIDA E A IMPORTÂNCIA DA QUÍMICA NA ESTAÇÃO DE TRATAMENTO', 'Brito, Kildery Pedrosa de; Pedrosa, Isabelly Cavalcante; Silva, Flávio José da; Beserra, Willian Ribeiro; Silva, Everton Vieira da', 'Editora Verde', 'Agriculture', 'Agriculture', 'É importante destacar a significatividade da água como um recurso natural indispensável ára a vida de todas as espécies que habitam a terra. Sem ela não seria possível a existência de vida emte nosso planeta. A ingestão de água tratada é um dos mais importantes fatores para a conservação da saúde. |A água potável é o tipo ideal para o consumo humano, pois se encontra livre de qualquer tipo de contaminação, ela pode ser de uma fonte natural, desde que não haja nenhum tipo de contaminação em sua nascente ou percurso, pode ser também obtida através de um processo realizado nas Estações de Tratamento de Água (ETAs), onde a água passa por uma série de etapas envolvendo aplicações químicas e físicas. A aplicação de produtos químicos durante o processo é indispensável e fundamental para obtenção de água potável. Este trabalho trata-se de uma pesquisa aplicada de aspecto bibliográfico, utilizando uma abordagem descritiva de seus objetivos e procedimentos técnicos que possibilitam argumentar me', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6664', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cabd', 'A IMPORTÂNCIA DA TERAPIA LÚDICA NO CUIDADO DE CRIANÇAS HOSPITALIZADAS: UMA REVISÃO DE LITERATURA', 'da Silva, Cristina Gonçalves; Cartaxo, Laurita da Silva; Alves, Wallace Pires; Bezerra, Felipe Gonçalves', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOO ambiente hospitalar é visto como lugar de aflição e sofrimento, onde a criança pode sentir e absorver tal situação com mais amplitude do que o adulto, como consequência, podem responder de forma negativa, com reações de impaciência, temor, desordem, choro, irritação etc. É importante preparar emocionalmente as crianças para estes momentos, requerendo um cuidado diferenciado e peculiar, capaz de reconhecer e suprir suas necessidades. O ato de brincar propriamente dito é uma atividade própria da infância e no período hospitalar funciona como terapia lúdica, permitindo acrescer as chances de sobrevida.OBJETIVOSAnalisar estudos sobre a importância da terapia lúdica no cuidado de crianças hospitalizadas.METODOLOGIA Trata-se de uma revisão bibliográfica, realizada a partir de uma busca nas bases de dados: Biblioteca Virtual em Saúde (BVS), Scientific Eletronic Library (Scielo), pelo cruzamento dos descritores “Hospitalização”, “Criança”, “Terapia” mediante o uso do operador boole', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6790', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cabf', 'ABUSO SEXUAL NA INFÂNCIA E A ASSISTÊNCIA DA EQUIPE DE ENFERMAGEM', 'Figueiredo Dantas, Núbia Maria; Da Silva, Francymárcia Capitulino; Araújo de Oliveira, Amanda Beatriz; Bertino Véras, Gerlane Cristinne', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOApontado pela Organização Mundial de Saúde (OMS) como uma importante questão de saúde pública, o abuso sexual infantil pode ser definido como qualquer tipo de contato ou comportamento sexual entre uma criança e alguém em posição de poder sobre ela, envolvendo atos que possam coagir ou motivar a vítima na participação de práticas sexuais, seja por meio de toques, prática sexual propriamente dita, entre outras ações que englobam tanto contato físico sem ou com penetração (WHO, 2003; RAABE; SPENGLER, 2013).No Brasil, a violência sexual infantil é um fenômeno frequente, onde o agressor normalmente é um familiar, que envolve a criança em um processo gradual de intimidação, por possuir uma relação de confiança ou poder sobre ela, interferindo no seu desenvolvimento e deixando sequelas que se estendem, por vezes, até a vida adulta (WHO, 2003; CHARTIER; WALKER; NAIMARK, 2010).Frente ao impacto do contexto supracitado nas diferentes esferas da vida do sujeito, se faz necessário que o ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6793', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cac3', 'BULLYING E AS PRODUÇÕES ACADÊMICAS: UM ESTUDO EXPLORATÓRIO', 'Ramos Soares, Luísa de Marillac; Gomes, Cristina da Silva; de Barros, Cintia Baião', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃO A necessidade de estudar sobre bullying surgiu por dois motivos: o primeiro diz respeito ao desejo de fazer uma interação discursiva entre saúde e educação, visto que há interface entre esses dois campos; e o segundo, devido a forma que vem se propagando, através de relatos cotidianos, no âmbito acadêmico, quer seja através do envolvimento como expectador ou como vítima da prática do bullying, nas histórias de vida pessoal, acadêmica ou mesmo nos estágios supervisionados.O conceito de bullying é utilizado por muitos estudiosos, a exemplo de Chaves e Souza (2018) Oliveira, Menegotto, Pasini e Levandowski (2013) como toda ação em que o sujeito é/está envolvido em situações de violência física ou psicológica, em que a frequência e a intensidade dos atos acontecem promovidas por alguém ou por um grupo, geralmente sem motivos aparente, em direção a uma ou mais pessoas, cujo objetivo é de intimidar ou mesmo agredir, em uma relação de subjugação de outrem.A partir desta compreensão', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6797', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cac5', 'DISCUSSÃO SOBRE A EFETIVIDADE DAS PROPRIEDADES TERAPÊUTICAS DO MEL DE ABELHAS NO TRATAMENTO DE FERIDAS', 'Lopes da Silva Leite, Francisca Simone; de Castro, Anúbes Pereira; Carneiro, Cynara Rodrigues; Lopes Ramalho, Maria Iasmin', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOO mel é um dos produtos fornecidos pelas abelhas mais conhecidos e disseminados pelo mundo, foi um dos primeiros alimentos do homem, que os utilizavam também como recurso medicinal (ESCOBAR; XAVIER, 2013). É um produto único dotado de numerosas propriedades terapêuticas, sendo utilizado pela medicina popular sob diversas formas e associações como fitoterápicos (MELO et al., 2016).O uso do mel é relatado desde a antiguidade em diversas partes do mundo e ainda hoje tem grande prestígio devido ao seu alto valor calórico e terapêutico (VICTOR et al, 2017). Existem vários fatores que podem contribuir para a propriedade antimicrobiana desta substância, dentre os quais: baixa atividade de água, alta pressão osmótica, baixo valor de pH, sistema glucose-oxidase, com a formação de peróxido de hidrogênio, alta taxa carbono/nitrogênio, baixo potencial redox, relacionado ao alto conteúdo de açúcares redutores, baixo conteúdo de proteínas, presença de agentes químicos e substâncias volátei', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6799', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cac8', 'FORMA DE CONTENÇÃO FÍSICA E MECÂNICA UTILIZADAS PELAS EQUIPES DE URGÊNCIA', 'Nascimento Soares, Vanessa Alves; Oliveira, Geane Silva; Barbosa Neto, Antônio de Freitas', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOA contenção tem por finalidade restringir os movimentos físicos do pacientem, devido ao grau de risco que apresenta para os demais que estejam presente com ele. A contenção deverá ser realizada por prescrição medica, conforme descrito na resolução de nº 1598/2000 do Conselho Federal de Medicina (CFM) e resolução n° 427/2012 do Conselho Federal de Enfermagem (COFEN). Existe a contenção física realizada de forma manual pelos profissionais de saúde, contenção mecânica onde os profissionais iram utilizar faixas ou amarras e a contenção química onde o profissional irá fazer uso de medicamentos. Ao se deparar em situação onde se necessite aplicar a contenção pela equipe de urgência, se faz necessário o planejamento e a utilização da sua forma correta.OBJETIVOS Conhecer através da literatura pertinente a forma de contenção física e mecânica utilizadas pelas equipes de urgência.METODOLOGIAPara a construção deste resumo expandido foram utilizados artigos das bases de dados BVS (Biblio', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6802', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cac9', 'IDOSOS INSTITUCIONALIZADOS: FATORES ASSOCIADOS A INSTITUCIONALIZAÇÃO', 'de Alencar, Valceni Pinto; da Silva Santos, Leandro Nonato; Monteiro da Silva Pinto, Cícera Maria; Silva, Dalila Oliveira', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOO envelhecimento populacional mundial é visto como um triunfo excepcional da humanidade e concomitantemente como uma adversidade quanto à qualidade de vida e ao bem-estar. De acordo com as estatísticas, estima-se que Brasil, haverá a existência de aproximadamente 17,6 milhões idosos, e em até 2025 esta população crescerá 16 vezes, ocupando o sexto lugar na classificação do ranking mundial a respeito a população idosa (ARAÚJO et al., 2017).Atualmente no Brasil, há um crescimento progressivo do número de pessoas idosas e, consequentemente gerando diversas questões na gestão de políticas públicas, dentre elas, o aumento da procura por Instituições de Longa Permanência (ILPs), as quais são conceituadas como espaço residencial com serviços de saúde e socioassistenciais para uma assistência integral (Cavalcante et al., 2016). Todavia, viver nessas instituições pode favorecer o decréscimo das atividades físicas e mentais, isolamento social, dentre outras problemáticas (BATISTA et. a', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6803', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044caca', 'LEVANTAMENTO BIBLIOGRAFICO ACERCA DA VIOLENCIA CONTRA A MULHER EM MONOGRAFIAS DO CURSO DE PSICOLOGIA', 'de Medeiros Batista, Agda Cristhina; Maciel Travassos, Leilane Menezes', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOA desigualdade de poder entre os gêneros vem afetando diversas esferas da vida dos seres humanos. Ela se dá pelo processo de perpetuação de uma cultura que atribui papéis sociais e de relações de poder às condições biológicas e genéticas, como maneira de naturalizar a desigualdade (ZANATTA; FARIA, 2018). Uma das consequências mais preocupante dessa situação é a violência que vem sendo enfrentada pela mulher, que se configura de diferentes formas, como: física, sexual, psicológica e verbal. E os agressores podem vir da própria família ou do ciclo de convivência próximo (SCHRAIBER, et al, 2002).OBJETIVOSO presente trabalho objetivou realizar levantamento bibliográfico de trabalhos de conclusão de curso realizados pelos alunos do curso de Psicologia da Faculdade Santa Maria, localizada na cidade de Cajazeiras, no sertão da Paraíba, que efetuaram pesquisas voltadas à temática violência contra mulher. METODOLOGIARealizou-se um levantamento bibliográfico de trabalhos de conclusão d', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6804', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cad0', 'RELAÇÃO DO ESTROGÊNIO COM A OSTEOPOROSE EM MULHERES MENOPAUSADAS', 'Gonçalves, Ronaldo Fernandes; de Assis, Luciana Moura; Benício da Silva, Ana Júlia; Mesquita Andrade, Ana Beatriz', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOA menopausa é a fase na vida da mulher onde o corpo sofre mudanças fisiológicas, principalmente a baixa produção de estrogênio nos ovários, resultando na incapacidade feminina de ovular e procriar, além de causar irritabilidade, depressão, ataques cardíacos e doenças cardiovasculares. Esta variação provoca uma sintomatologia distinta, incluindo a desregulação do fluxo menstrual, fogacho, secura na pele, secura vaginal, distúrbios do sono, entre outros. Estes sintomas podem variar de acordo com os parâmetros sociais, econômicos e étnicos de cada mulher (MUCIDA, 2006). Sabe-se que o estrogênio contribui para fixação do cálcio nos ossos. E após a menopausa, grande parte das mulheres passa a perder progressivamente a massa óssea, caracterizando a osteoporose que apresenta impactos negativos na qualidade de vida da mulher.A osteoporose é uma doença em que ocorre a redução da massa óssea tornando os ossos frágeis e aumentando os riscos de fraturas (JUNQUEIRA E CARNEIRO 1999). Nela,', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6815', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cad1', 'SÍFILIS CONGÊNITA NO BRASIL: UMA REVISÃO INTEGRATIVA', 'Fernandes Silva, Roberson Matteus; Jeremias Almeida, Layane Ruth; de Lira, Rafaelle Cavalcante', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃO A sífilis é uma doença infectocontagiosa sistêmica, de evolução crônica, causada pela bactéria Treponema pallidum. Sua transmissão pode ocorrer por via sexual, vertical e sanguínea. A sífilis congênita é resultado da disseminação hematogênica do agente etiológico da gestante infectada não tratada ou inadequadamente tratada para o seu concepto, por via transplacentária (REIS et al., 2018). O diagnóstico precoce e o tratamento oportuno e adequado das gestantes e parcerias sexuais com sífilis no pré-natal, na Atenção Básica, são determinantes para impactar na redução da morbimortalidade associada à transmissão vertical (Ministério da Saúde, 2017). O pré-natal inadequado é o responsável por cerca de 70 a 90% dos casos encontrados. Assim, as maiores dificuldades observadas na assistência pré-natal são, a anamnese inadequada, sorologia para sífilis não realizada nos períodos preconizados (1º e 3º trimestres) e a ausência de tratamento do parceiro sexual entre outros (TOLDO, 2018).', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6817', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cad3', 'VIOLÊNCIA INSTITUCIONAL NA OBSTETRÍCIA', 'Lopes Linhares, Maria Fernanda; Barreto, Veruska Pedrosa; Soares Brandão, Lara Bianca', 'Editora Verde', 'Agriculture', 'Agriculture', 'INTRODUÇÃOA relação profissional de saúde e paciente, segundo Pedroso e López (2017), pode ser entendida como uma relação de poder, devido a visão da autoridade médica, o paradigma da confiança na medicina tecnológica e o cuidado em saúde, desse modo. A hierarquização e a supervalorização das práticas de saúde intervencionistas agravam ainda o contexto brasileiro da violência institucional na obstetrícia. De acordo com Aguiar (2010), dá indícios que, não são contemplados e ficavam à margem do cuidado, os sentimentos e sensações das mulheres em relação ao parto em parte das maternidades brasileiras. Além de que há a banalização, não só por parte dos profissionais de saúde, mas também das próprias mulheres das práticas de violência obstétrica pela ideia que se têm do atendimento público no Brasil.OBJETIVOSEssa revisão da literatura tem como objetivos expor o atual quadro da violência obstetrícia no contexto institucional, com ênfase nos paradigmas do descuido da relação profissional de s', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6819', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cad8', 'A IMPORTÂNCIA DA VACINAÇÃO CONTRA O HPV EM JOVENS DO SEXO MASCULINO: USO DA EDUCAÇÃO EM SAÚDE COMO ALTERNATIVA SENSIBILIZADORA', 'Almeida, Hélida Maravilha Dantas e Sousa; Dantas, Alison Rener Araújo; Nascimento, Arydyjany Gonçalves; Fernandes, Marcelo Costa', 'Editora Verde', 'Agriculture', 'Agriculture', 'O HPV é uma das IST’s, que apresenta mais de 150 genótipos diferentes, que podem desenvolver doenças que afetam ambos os sexos, porém é mais conhecida popularmente no gênero feminino, devido às ectopias e ao câncer do colo de útero. No Brasil, em 2018 foi investido mais de 500 milhões de reais para as campanhas vacinais, cujo público alvo é composto por meninas de 9 a 14 anos e meninos de 11 a 14. Todavia há déficit na adesão dessa campanha por parte dos meninos, justificado pela ausência de informações acerca das patologias desenvolvidas por esse vírus. Este estudo tem como alvo a reflexão do uso da educação em saúde para a sensibilização de jovens, aumentando a adesão das campanhas vacinais contra o HPV. Trata-se de estudo descritivo com abordagem qualitativa, realizado no mês de setembro de 2018 na Biblioteca Virtual de Saúde. Foi observado que a partir de uma maior educação e empoderamento do público alvo, a adesão a vacina pode ser mais fácil e o autocuidado mais presente, modific', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6824', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cad9', 'A IMPORTÂNCIA DOS SISTEMAS DE INFORMAÇÃO COMO TECNOLOGIA DE CUIDADO EM SAÚDE NA ATENÇÃO PRIMÁRIA', 'Soares, Jéssica de Freitas; de Souza Vieira, Jessiely Karine; Queiroga Freitas, Fabiana Ferraz; da Silva, Clarice Nascimento', 'Editora Verde', 'Agriculture', 'Agriculture', 'Sistema de Informação em Saúde (SIS) é definido pela Organização Mundial de Saúde como um mecanismo de coleta, processamento, análise e transmissão da informação necessária para se planejar, organizar, operar e avaliar os serviços de saúde, este tem sido implantado pelas instituições com vistas à redução de problemas, otimizando a organização da empresa, e o surgimento de informações importantes para a tomada de decisão. Com base nisso, a justificativa do presente estudo dar-se pelo questionamento de que se os profissionais da atenção primária à saúde utilizassem com mais eficiência os SIS, estariam mais cientes dos que os dados trazem, e trabalharia melhor os pilares da atenção primária. Tendo por objetivo averiguar a importância dos sistemas de informação como tecnologia de cuidado em saúde na atenção primária. O presente trabalho trata-se de uma revisão de literatura propondo uma discussão acerca da importância dos sistemas de informação como tecnologia de cuidado em saúde na atençã', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6825', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cae0', 'Elaboração de barra de cereal com resíduos secos de abacaxi e caju', 'Vieira, Danise Medeiros; Melo, Mylena Olga Pessoa; Silva, Virgínia Mirtes de Alcântara; Barros, Sâmela Leal; Nascimento, Amanda Priscila Silva; Santos, Newton Carlos', 'Editora Verde', 'Agriculture', 'Agriculture', 'A indústria de processamento de frutas gera um grande volume de resíduos sólidos, que muitas vezes, são descartados de maneira inadequada. Desse modo, a utilização destes resíduos para a produção de farinhas, proporciona a redução de um problema ambiental, possibilita a redução de custos e a melhoria no valor nutricional dos produtos. Diante deste cenário, objetivou-se utilizar farinhas obtidas através da desidratação de resíduos agroindustriais de abacaxi e caju como matéria-prima no processo produtivo de barras de cereais, proporcionando o desenvolvimento de um alimento com elevado valor nutricional. As amostras foram caracterizadas através dos seguintes parâmetros físico-químicos: teor de umidade, atividade de água, pH, acidez, proteínas, lipídeos e cinzas. Verificou-se que, a utilização da farinha dos resíduos é uma alternativa viável para o aproveitamento deste material e, observou-se a influência do percentual de farinha utilizado em todos os parâmetros avaliados. Foi observado t', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6839', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cae1', 'Cinética de secagem e sua influência nas dimensões de sementes de abóbora sem casca', 'Vieira, Danise Medeiros; Melo, Mylena Olga Pessoa; Silva, Virgínia Mirtes de Alcântara; Barros, Sâmela Leal; Nascimento, Amanda Priscila Silva; Santos, Newton Carlos', 'Editora Verde', 'Agriculture', 'Agriculture', 'A secagem aplicada as sementes de abóbora, proporciona o aumento da vida de prateleira do produto e consequentemente facilita a sua comercialização. Neste sentido, objetivou-se através do presente estudo realizar a cinética de secagem das sementes de abóbora sem casca em diferentes temperaturas do ar de secagem, ajustando os dados experimentais obtidos a modelos matemáticos empíricos e avaliar a influência da secagem em suas dimensões. A cinética de secagem das sementes de abóbora sem casca foi realizada em diferentes temperaturas do ar de secagem (50, 70 e 90 °C), ajustando os dados experimentais obtidos à modelos matemáticos empíricos de Handerson e Pabis, Lewis e Page. O tamanho das sementes foi analisado quanto ao comprimento, largura e espessura com auxílio de paquímetro digital. Com relação aos modelos matemáticos aplicados, o modelo de Page foi considerado o mais eficiente na descrição do processo de secagem de sementes de abóbora sem casca. Constatou-se que as dimensões das sem', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6840', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cae2', 'Implantação de um módulo agroflorestal com práticas agroecológicas no Campus Picuí, Paraíba', 'Ferreira, Valter Silva; Silva Júnior, José Elson; Melo, Djair Alves; Azevedo, Noatan Santos; Aguiar, Paulo Alexandre; Andrade Filho, Wagner Marinho', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi implantar um módulo de SAFs como atividade curricular no Campus Picuí-PB, visando promover o desenvolvimento técnico e socioeconômico dos alunos de Agroecologia, bem como estimular a preservação e manutenção de uma área verde denominada de Bosque florestal. A atividade de estudo foi desenvolvida no IFPB/Campus Picuí. O trabalho foi dividido em três momentos: implantação do banco de proteínas; construção de barramento; manejo do Bosque florestal e identificação das espécies. Proporcionou-se aos futuros profissionais da Agroecologia vivenciar o manejo de um módulo de SAFs. As ações realizadas no período da implantação do banco de proteínas e bosque florestal puderam contribuir para a mantença da flora local. Além da conservação da flora foi constatado no aumento de espécie da fauna como abelhas, pássaros e roedores. As ações realizadas no período da implantação do Banco de proteínas e Bosque florestal pode contribuir para a mantença da flora local. Através da i', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6842', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cae3', 'ACESSIBILIDADE PUERPERAL NA ATENÇÃO PRIMÁRIA EM SAÚDE: REVISÃO INTEGRATIVA', 'de Castro, Anúbes Pereira; de Araujo, Fábio Geraldo; da Silva, Edicleide Martins', 'Editora Verde', 'Agriculture', 'Agriculture', 'A assistência puerperal, desenvolvida pela Unidade de Saúde da Família (USF), não se volta apenas para o diagnóstico precoce e reabilitação de agravos à saúde, mas deve-se estar voltada para ações de promoção e proteção à saúde das parturientes. A pesquisa objetiva analisar o processo de acessibilidade das puérperas na Atenção Primária em Saúde, por meio de pesquisa bibliográfica, através de informações obtidas de artigos científicos indexados nas bases de dados da  SciELO - Scientific Eletronic Library Online, Literatura em Ciências da Saúde (LILACS) e Biblioteca Virtual em Saúde (BVS), foi realizado a análise dos objetivos, resultados, discussão e considerações finais de cada obra acadêmica publicada nos últimos cinco anos (2013 a 2017), sobre o tema em comento. Tomando por base os estudos analisados foi possível verificar que a literatura evidencia a importância da acessibilidade puerperal, entretanto existem obstáculos ao que concerne o acesso das mulheres até os serviços de saúde ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6843', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044cae9', 'AUDITORIA EM ENFERMAGEM: UMA ABORDAGEM ACERCA DA APLICAÇÃO NOS SERVIÇOS DE SAÚDE', 'Araújo Dantas, Alison Rener; de Alencar, Valceni Pinto; da Silva Santos, Leandro Nonato; Cardoso do Nascimento, Joseph Gabriel', 'Editora Verde', 'Agriculture', 'Agriculture', 'A auditoria nos serviços de saúde, está cada vez mais presente, e o profissional enfermeiro é o principal ator que exerce essa função. O presente estudo teve como objetivo analisar e expor o que diz as produções científicas acerca do tema auditoria em enfermagem e a aplicação desta no serviço de saúde. Trata-se de uma revisão de literatura, realizada no mês de junho de 2018, e que teve como base artigos publicados no intervalo entre os anos de 2010 e 2016. O levantamento bibliográfico se deu na base de dados Scientific Electronic Library Online (SciELO), tendo como descritores “auditoria em enfermagem” e “assistência a saúde”. A amostra foi composta por cinco artigos, sendo dois artigos publicados no ano de 2010, é apenas um publicado nos anos de 2011, 2012 e 2016. Todos os artigos que compõem a amostra, abordam de maneira geral pontos significativos sobre a temática da auditória em enfermagem e a assistência, explanando, principalmente a função e importância do enfermeiro auditor. Atr', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6849', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00cd6a63682f044caea', 'AVALIAÇÃO DAS AÇÕES PROGRAMÁTICAS DE HANSENÍASE NO MUNICÍPIO DE BONITO DE SANTA FÉ - PB', 'da Silva, Silvana Gomes; Assis Leitão, Luana Couto', 'Editora Verde', 'Agriculture', 'Agriculture', 'A hanseníase é uma doença endêmica nacional e nos últimos anos apresenta redução importante no número de casos, no entanto, ainda constitui um problema de saúde pública. O referido estudo objetivou avaliar as ações programáticas de hanseníase através de uma pesquisa avaliativa que emprega o estudo transversal com abordagem quantitativa, a coleta de dados foi realizada mediante a avaliação dos prontuários e do Sistema de Informação de Agravos e Notificações. Os resultados deste estudo, mostraram que os pacientes com hanseníase em sua maioria, eram do sexo feminino e da forma multibacilar, o diagnóstico destes casos, eram realizados através da demanda espontânea e a busca ativa, observou-se ainda que a vigilância dos contatos intradomiciliares não eram realizadas, e que o tempo de tratamento dos casos como paucibacilares ocorreram nos seis meses, já os multibacilares acima dos doze meses. Em relação à prevenção de incapacidades a maioria foram avaliadas, sendo prevalente o Grau I, as qua', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6850', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044caf0', 'DESCOBERTA TARDIA DO CÂNCER DE MAMA: AÇÕES FISIOLÓGICAS E REAÇÕES PSÍQUICAS', 'de Castro, Anubes Pereira; dos Santos, Sandra Jaqueline; Ferreira, Ana Paula', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivo: Analisar na literatura a descoberta e as complicações tardias do câncer de mama nas mulheres e de maneira específica: Listar as ações fisiológicas e as reações psíquicas do câncer de mama nas mulheres e apontar as dificuldades que as mulheres têm em lidar com a descoberta tardia do câncer de mama. Metodologia: Trata-se de uma revisão bibliográfica. Foi realizada buscas na Biblioteca Virtual em Saúde (BVS) de artigos publicados entre os anos de 2010 a 2018. Resultados: Os resultados desse estudo basearam-se na análise de 10 artigos científicos. Evidenciaram que muitas mulheres tinham medo de descobrir a doença, por esse motivo não procuravam o serviço de saúde e outras procuravam o sistema único de saúde (SUS) mas não obtiveram resultados rápidos, por isso o diagnóstico foi tardio.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6854', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044caf3', 'EDUCAÇÃO EM SAÚDE COMO FERRAMENTA PREVENTIVA PARA DOENÇAS CARDIOVASCULARES EM MULHERES: REVISÃO BIBLIOGRÁFICA', 'Dias de Morais Souto, Maria Neirismar; da Silva Rocha, Maiara Millian; Atanásio Dias, Luiz Gabriel', 'Editora Verde', 'Agriculture', 'Agriculture', 'Tendo em vista o alto índice de mulheres acometidas por doenças cardiovasculares (DCV), este respectivo trabalho tem como objetivo alertar o público feminino sobre as causas e os riscos que uma DCV pode trazer para a sua saúde. Dessa forma, buscamos analisar, informar e alertar sobre o índice de mulheres que são atingidas pelas DCVs através da revisão bibliográfica realizada nas plataformas digitais e em livros clínicos de enfermagem. Diante da questão norteadora analisada, ainda são precários meios de combates a essas comorbidades, sendo necessário a ação da saúde pública em educar as mulheres como forma de prevenção as DCVs', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6857', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044caf6', 'FATORES DE RISCO DO SUICÍDIO NAS ESCOLAS', 'Abreu, Delian; Oliveira, Maria de Fátima; da Silva, Isabele Sousa; da Silva Lima, Maria Edna', 'Editora Verde', 'Agriculture', 'Agriculture', 'Sabe-se que uma das principais consequências de determinados transtornos mentais e psicológicos como depressão, transtorno bipolar, esquizofrenia e abusos de drogas constitui-se em um ato agressivo contra si mesmo, o suicídio. O mesmo vem perseguindo a sociedade à tempos e visto com diversos olhares diferentes como: Religião, filosofia e psicologia. O suicídio vem causando inúmeras mortes em todo o mundo, ocorrendo também com jovens de idade escolar. O presente artigo, intitulado: Suicídio na escola: Fatores de risco e depressão, busca através de uma revisão bibliográfica, responder a seguinte pergunta de pesquisa: Quais as principais causas contribuintes para o percentual de suicídios na escola? Para isso, foi elegido o seguinte objetivo geral: Apresentar alguns fatores de risco associados ao suicídio, de forma que haja esclarecimento do assunto abordado. Percebido o objetivo geral, elencou-se os específicos: Descrever suicídio, utilizando-se de alguns dados que demonstrem sua triste ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6860', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044caf8', 'INICIATIVAS DE ENFRENTAMENTO DAS FAKE NEWS NAS ELEIÇÕES DE 2018', 'de Sousa, Iarley Pereira; de Almeida, Tadeu Lourenço', 'Editora Verde', 'Agriculture', 'Agriculture', 'As discussões acerca da propagação de notícias falsas na internet vêm se intensificando nos últimos anos e a busca por soluções que inibam o crescimento desenfreado das mesmas passou a ser uma preocupação mundial. Objetiva-se analisar a possibilidade de diminuição da propagação de notícias falsas, também nominadas como fake news nas eleições 2018. Ao longo da pesquisa optou-se pelo método de abordagem dialético. Quanto ao método de procedimento, o adotado é o comparativo e quanto à forma de abordagem do problema a modalidade utilizada é a qualitativa descritiva e o procedimento técnico é o bibliográfico- documental. Por fim, verificou-se que é possível a mitigação da violência na disseminação de fake news na rede mundial de computadores.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6863', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cafe', 'INTERNAÇÕES DE VÍTIMAS DE AGRESSÃO SEXUAL POR MEIO DE FORÇA FÍSICA NO BRASIL', 'Amorim da Silva Lira, Ana Paula; Silva, Williane de Oliveira; Figueiredo Pereira Batista, Jessika Lopes; Pereira Januário, Myrelle Kelly', 'Editora Verde', 'Agriculture', 'Agriculture', 'O abuso sexual é um grave problema da saúde pública, que leva a um elevado número de internações por ano em todo o país. O abuso sexual é caracterizado como uma atividade sexual não desejada, na qual o agressor faz uso de ameaças e de sua força física para envolver a vítima e praticar atos contra sua vontade. Portanto, este estudo analisar os casos de internação hospitalar das vítimas de agressão sexual por meio da força física no Brasil entre 2015 a 2017. Constitui-se em um estudo descritivo, de base secundária com abordagem quantitativa, realizado em outubro de 2018, através do Sistema de Informações Hospitalares (SIH), disponível de forma online no Departamento de Informática do Sistema Único de Saúde (DATASUS). A amostra foi composta pelo quantitativo de 720 internações. Foi identificado que a região Sudeste detém o maior número de internações, sendo as principais vítimas do sexo feminino, na faixa etária entre 10 a 14 anos. Tratar acerca da violência sexual ainda é delicado, já qu', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6870', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb04', 'Características biométricas de sementes crioulas de Crotalaria e Milheto', 'Santos, Dualyson da Silva; Monteiro, Shênia Santos; Lima, Juliana Ferreira de; Monteiro, Shirley Santos', 'Editora Verde', 'Agriculture', 'Agriculture', 'A germinação de sementes é base para a propagação de espécies nativas para o entendimento da regeneração natural em comunidades vegetais. O objetivou-se com este estudo determinar as características biométrica de sementes crioulas de Crotalaria e Milheto. O experimento foi conduzido na Universidade Federal da Paraíba, Bananeiras-PB. Utilizou-se sementes de Crotalaria spectabelis, Crotalaria juncea e Pennisetum glaucum, adquiridas dos agricultores familiares local. O delineamento utilizado foi inteiramente casualizado, com 4 repetições de 50 sementes. Avaliou-se o índice de velocidade de germinação, germinação, comprimento da raiz principal, hipocótilo e epicótilo, e determinação da massa fresca e seca das plântulas estudadas. Os resultados demostram a eficiência do teste de germinação para o potencial germinativo e viabilidade das sementes. As Crotalaria spectabelis e juncea demostraram qualidade fisiológica de sementes superior ao Pennisetum glaucum, o que concerne aos parâmetros de g', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6878', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb08', 'Programação', 'Azevedo, Kelvin Wesley de; Santos, Vanessa Érica Silva da', 'Editora Verde', 'Agriculture', 'Agriculture', 'I CONGRESSO SERTANEJO DE DIREITO PRIVADO28 E 29 DE AGOSTO DE 2019UFCG – CAMPUS I PROGRAMAÇÃO  28 DE AGOSTO 07:00 – INÍCIO DO CREDENCIAMENTO08:00 - CERIMÔNIA DE ABERTURA             APRESENTAÇÃO CULTURAL: EMILIANO PORDEUS08:30 – PALESTRA: O LAISSEZ FAIRE DA NORMATIZAÇÃO DA LIBERDADE ECONÔMICA E SEUS REFLEXOS NO ÂMBITO DO DIREITO PRIVADO BRASILEIRO: RETROCESSO OU AVANÇO?PROF. ANDRÉ GOMES ALVES 09:30 – PALESTRA: O PROBLEMA DO SUPERENDIVIDAMENTO NOS CONTRATOS BANCÁRIOS: UM ESTUDO DE CASOPROF. ANA CARLA ABRANTES 10:00 – PALESTRA: OS ENTRAVES DA PRÁTICA DO DIREITO DO CONSUMIDOR NOS JUIZADOS ESPECIAIS CÍVEIS: UMA ABORDAGEM SOBRE A BANALIZAÇÃO DO DANO MORAL, A INVERSÃO DO ÔNUS DA PROVA E O INDEFERIMENTO DA GRATUIDADE JUDICIÁRIAPROF. VANESSA ÉRIKA 11:00 – INTERVALO PARA ALMOÇO 14:00 – APRESENTAÇÕES DOS ARTIGOS CIENTÍFICOS APROVADOS17:00 – ENCERRAMENTO DAS APRESENTAÇÕES 19:00 – REABERTURA DAS ATIVIDADES19:10 - PALESTRA: DESAFIOS DA JOVEM ADVOCACIA: EMPREENDEDORISMO E MARKETING JURÍDICOPROF. PEDR', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6883', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb10', 'PROCESSO DE ENVELHECIMENTO: ATUAÇÃO DO ENFERMEIRO NA PREVENÇÃO E MANUTENÇÃO DA DIABETES E HIPERTENSÃO NA ATENÇÃO PRIMÁRIA', 'Pontes, Catarina Ferreira; Feitosa de Freitas, Erlane Aguiar', 'Editora Verde', 'Agriculture', 'Agriculture', 'O envelhecimento é um processo caracterizado por alterações físicas, biológicas, psicológicas e sociais, que atingem o idoso de forma única no percorrer da vida, necessitando de atenção priorizada e que possa garantir saúde e qualidade de vida, uma vez que o envelhecer se relaciona a mudanças orgânicas e, consequentemente, com o surgimento de doenças predisponentes para essa fase, sendo enfatizada a Hipertensão e Diabetes, que mais afetam os idosos e são responsáveis por complicações e comprometimento da saúde e do seu bem estar. Objetivo: Conhecer o processo de envelhecimento e a relação com a atuação do enfermeiro na prevenção e manutenção de doenças crônicas, como a HAS e a DM, no cenário da atenção primária. Metodologia: Trata-se de uma revisão bibliográfica, de abordagem qualitativa, fundamentada na análise de artigos científicos nacionais que trazem um suporte de informações sobre o processo de envelhecimento e a importância do enfermeiro na prevenção da HAS e DM. Resultados: Os ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6892', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb11', 'RASTREIO DO CÂNCER DO COLO DO ÚTERO NA ESTRATÉGIA DE SAÚDE DA FAMÍLIA', 'Furtado de Galiza, Dayze Djanira; Duarte, Yasmim Saldanha; Roque da Silva, Patricia Michele', 'Editora Verde', 'Agriculture', 'Agriculture', 'O exame ginecológico é um procedimento que gera apreensão em muitas mulheres. Por isso, cabe ao profissional buscar uma forma mais adequada de tornar esse momento mais acolhedor, sempre sanando dúvidas e repassando informações de seus benefícios. Esse exame permitirá que mulheres acometidas pelo Câncer de Colo de Útero (CCU), sejam diagnosticadas precocemente, aumentando suas chances de cura. O referido estudo tem como objetivo, identificar as variáveis que influenciam na qualidade do Exame ginecológico realizado por enfermeiros na Estratégia de Saúde da Família (ESF), bem como, determinar os fatores que levam a não adesão das usuárias a realização do exame. Trata-se de uma revisão integrativa da literatura, com base documental, descritivo, retrospectivo e de abordagem qualitativa. A pesquisa foi realizada no mês de novembro de 2018. Observou-se que, o rastreio é mais eficiente quando combinado ao exame ginecológico ou de Papanicolau, realizado periodicamente. E que para suprir as afli', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6893', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb15', 'SINTOMAS PSICÓTICOS: ATUAÇÃO DOS PROFISSIONAIS FRENTE AOS QUADROS PSICÓTICOS', 'de castro, Anubes Pereira; de Assis Alexandre, Andreza Kelly; de Sousa Oliveira, Ilyandra Rita', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se com esse estudo descrever e analisar a atuação do profissional da saúde em relação a pacientes que apresentam algum tipo de quadro psicótico, psicose (que é uma desordem psíquica que não diz respeito ao âmbito da personalidade) e existem inúmeros tipos de psicose ou transtornos psicóticos , como a esquizofrenia, epiléticos ou psicose maníaco depressivo são alguns exemplos de psicopatias mais conhecidas que existem, pesquisa coordenada por Paulo Rossi Menezes professor do departamento medicina (FM-USP) mostrou que os primeiros episódios de transtornos psicóticos ocorrem entre homens e mulheres com idade média de 30 anos e que varia muito entre grandes centros urbanos e regiões mais rurais, sendo  que transtornos  psicóticos são responsáveis por uma proporção significativa de carga global de doenças, em razão da incapacitação que causam. tem ainda evolução bastante variada e podem levar a graus elevados de impossibilidade. “grande parte dos pacientes requer cuidados especial', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6897', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb16', 'SISTEMA DE INFORMAÇÃO ELETRÔNICO COMO FERRAMENTA DE CONSUMO CONSCIENTE', 'de Alencar, Michel Avelino; Augusto de Souza, Rodrigo Alves; Lira Andriola, Márcia Nazaré; Pereira de Castro, Antonio Sandro', 'Editora Verde', 'Agriculture', 'Agriculture', 'O processo de industrialização de matéria prima e o consumo desenfreado ocasionam perda da diversidade vegetal e animal, promovendo impacto ambiental.  A partir dessa visão, iniciou-se a utilização de sistemas que evitam o consumo excessivo de papel, entre eles o SEI – Sistema de Informação Eletrônico, que promove o trabalho rápido e econômico quanto ao uso do papel. Com o objetivo de conhecer a história do consumo do papel na sociedade para compreender se há discussão dessa temática em publicações científicas que fomentem a preocupação com a problemática, este estudo foi desenvolvido a partir de uma investigação  no Scielo, e foi encontrado 43 artigos para discussão. Contatou-se que há publicações abrangendo a temática e que as discussões geram em torno de que o consumo desenfreado e a produção ocasionam impactos ambientais que repercutem socialmente. Conclui-se que toda essa preocupação quanto ao impacto ambiental tem que ser absorvido de maneira consciente e que o SEI é uma maneira ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6898', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb17', 'SUICÍDIO DE UNIVERSITÁRIOS: O VAZIO EXISTENCIAL DE JOVENS NA ATUALIDADE E A PRESSÃO DA VIDA ACADÊMICA', 'de Castro, Anúbes Pereira; Feitosa Aquino, Maria Rogéria; Alves Pereira, Francisca Brigyda', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente trabalho apresenta o importante potencial em explorar a saúde mental dos estudantes especificamente dos universitários. Esse estudo descritivo tem por objetivo explorar os principais motivos responsáveis pelo suicídio de universitários e a ansiedade dos mesmos em relação ao futuro. A estrutura atual da vida acadêmica, repleta de pressões para a escolha do curso e para ter um diploma, ameaça do desemprego e fracasso profissional têm desencadeado a depressão, a ansiedade e o uso excessivo de medicamentos, de modo que a saúde fragilizada dos universitários se conecta com as causas de suicídios no meio acadêmico em todo o Brasil.   Assim, favorecer a criação de estratégias de cuidado e que possam acolher o aluno em sua dimensão existencial.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6899', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb32', 'Comportamento predatório de Euborellia annulipes em diferentes fontes de alimento', 'Silva, Wedson Aleff Oliveira da; Wanderley, Maria José Araújo; Medeiros, Maria da Guia de; Dias, Ulisses de Souza; Viana, Pedro Henrique Feliciano', 'Editora Verde', 'Agriculture', 'Agriculture', 'Pesquisas voltadas para o controle biológico de pragas têm se intensificado, reduzindo os impactos causados pelo uso de inseticidas no ambiente, vida silvestre e humana. A tesourinha Euborellia annulipes tem mostrado ótimo potencial para o uso em programas de manejo de pragas. O objetivo deste trabalho foi avaliar o comportamento de busca e predação da tesourinha submetida a duas fontes de alimento, com finalidade de gerar informações para a construção do conhecimento agroecológico, visando reforçar o controle biológico de pragas em unidades de produção familiar. O trabalho foi realizado no laboratório de Entomologia, da Universidade Federal da Paraíba, em Bananeiras. O delineamento utilizado foi inteiramente casualizado com dois tratamentos (ovos do curuquerê-da-couve Ascia monuste orseis e pulgão Aphis gossypii) e cinco repetições. Em todos os tratamentos os predadores foram individualizados em cinco placas de Petri medindo 60 x 15 mm, onde se liberaram cinco unidades de ovos e de pu', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6946', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb38', 'RESPONSABILIDADE CIVIL NO DIREITO DE FAMÍLIA: DA CONFIGURAÇÃO DO DANO MORAL E POSSIBILIDADE DE REQUERIMENTO DE INDENIZAÇÃO POR ABANDONO AFETIVO PATERNO', 'Azevedo, Kelvin Wesley de; Moreira, Petrúcia Marques Sarmento; Silva, André Gustavo Medeiros; Souza, Gustavo Soares de', 'Editora Verde', 'Agriculture', 'Agriculture', 'RESPONSABILIDADE CIVIL NO DIREITO DE FAMÍLIA: DA CONFIGURAÇÃO DO DANO MORAL E POSSIBILIDADE DE REQUERIMENTO DEINDENIZAÇÃO POR ABANDONO AFETIVO PATERNO', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6959', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb3a', 'A EVOLUÇÃO E A EXTENSÃO DO PRINCÍPIO DA BOA-FÉ OBJETIVA NAS', 'Abrantes Neto, Ozório Nonato de; Farias, Arlindo Alves de; Azevedo, Kelvin Wesley de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A EVOLUÇÃO E A EXTENSÃO DO PRINCÍPIO DA BOA-FÉ OBJETIVA NAS', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6961', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb3b', 'UMA ABORDAGEM SOBRE A SOCIEDADE UNIPESSOAL DE ADVOCACIA: CONCEITUAÇÃO, REGULAMENTAÇÃO E TRIBUTAÇÃO', 'Holanda, Olga Pereira; Gomes Ferreira, Marília de Melo', 'Editora Verde', 'Agriculture', 'Agriculture', 'Com o desígnio de facilitar a legalização dos serviços de advocacia, criou-se, em 2016, uma legislação que autoriza a sociedade unipessoal de advogados, na qual, estabelece-se uma pessoa jurídica que tem suas próprias particularidades. Trata-se, dessa forma, da lei n 13.247/2016, que permite ao advogado registrar-se na Seccional da OAB, assentindo também que ele faça opção pelo regime tributário Simples Nacional. A presente pesquisa objetiva entender a criação, regulamentação, e a tributação aplicada às sociedades unipessoais de advocacia. Por sua vez, a pesquisa evidencia os seguintes objetivos específicos de constatar a responsabilização subsidiária e ilimitada da sociedade unipessoal de advocacia, identificar os impactos do chamado Simples Nacional na sociedade advocatícia unipessoal, e verificar as alterações do Estatuto da Advocacia suscitadas pela Lei supracitada. Recorrendo à legislação pertinente e com uma aplicabilidade metodológica voltada para a bibliografia, na qual, ao uti', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6962', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb3c', 'RESPONSABILIDADE CIVIL POR ROMPIMENTO DE NOIVADO: Análise jurisprudencial e doutrinária acerca da aplicação do dano', 'Neto, Gilson Gonçalves de Matos; Sousa, Ana Clara Melo; Estrela, Ana Aparecida Abrantes', 'Editora Verde', 'Agriculture', 'Agriculture', 'RESPONSABILIDADE CIVIL POR ROMPIMENTODE NOIVADO: Análise jurisprudencial e doutrinária acerca da aplicação do dano', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6963', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb40', 'INOVAÇÕES E OBSTÁCULOS DO PROCESSO ELETRÔNICO SOB A ÉGIDE DO NOVO CÓDIGO DE PROCESSO CIVIL', 'Souza, André Furtado de; Rodrigues Neves Farias, Maria Fernanda', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Processo Eletrônico surge como uma ferramenta útil para atender à tônica processual de maneira mais prática. Mas apesar da tamanha relevância, sua aplicabilidade ainda é comprometida em nível nacional, colocando em xeque todo um ideal de eficiência. Deste modo, o presente artigo tem o intuito de analisar a abordagem trazida pelo novo Código de Processo Civil acerca do Processo Eletrônico e, sumariamente, fazer breves considerações sobre as dificuldades encontradas no Judiciário quanto à temática. Quanto à metodologia, trata-se de uma pesquisa exploratória, dos tipos bibliográfica e documental, com a utilização dos métodos dedutivo e monográfico. Inferindo-se, pois, que o Processo Eletrônico não é padronizado em todo país e, do contrário, existe uma variedade de sistemas de automação. Também que o Código de 2015 poderia ter ido além, deixando ainda mais expresso a sua busca pela efetivação da padronização dos sistemas eletrônicos processuais, facilitando a atividade laboral dos aplica', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/6967', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb4d', 'EMPRESA INDIVIDUAL DE RESPONSABILIDADE LIMITADA (EIRELI) E AS CONSEQUENCIAS JURIDICAS SOBRE ABUSO DA PERSONALIDADE JURÍDICA', 'Ramalho, Rayane Fernandes; Moura, Eliza Tala Alencar', 'Editora Verde', 'Agriculture', 'Agriculture', 'A presente análise pretendeu destacar a Empresa Individual de Responsabilidade Limitada EIRELI, é de suma importância para as relações no direito privado as implicações jurídicas a respeito do abuso da personalidade jurídica e desvendando que a EIRELI trata-se de uma inovação que desburocratizou e forneceu segurança jurídica para o empresário, porém, não excluindo a probabilidade de fraude. Para atingir os objetivos propostos recorreu-se como método de abordagem o dedutivo, e como técnica de pesquisa a coleta de dados documental indireta e bibliográfica. Neste viés apontamos a relevância da desconsideração da personalidade jurídica que consiste em suspender os abusos produzidos pelo uso oposto a sua finalidade. Outrossim, a desconsideração da personalidade jurídica produz condição de subsidiariedade, ocasionando a responsabilização da pessoa natural, por causar lesividade a terceiros.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7004', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b00fd6a63682f044cb50', 'INFLUENCIADORES DIGITAIS: UMA ANÁLISE DA SUA ATUAÇÃO NA SOCIEDADE DE CONSUMO FRENTE AO DIREITO DO CONSUMIDOR', 'Almeida, Brena Benício de; Bezeirra, Clara Catharinne Huanna Costa', 'Editora Verde', 'Agriculture', 'Agriculture', 'O avanço da tecnologia nos últimos anos tem proporcionado novas formas de interação e engajamento social. Nesse contexto, surgiram os chamados influenciadores digitais, caracterizados como figuras de alto poder persuasivo que atuam como intermediadores, de notória eficácia, entre as marcas e os consumidores. No entanto, os digitais influencers, por vezes, atuam de maneira ilícita, de modo a propagar publicidade velada, abusiva ou enganosa. Sob esse viés, o presente trabalho se compromete a explanar acerca da influência que esses personagens exercem nas relações consumeristas e sua responsabilização pela propagação da publicidade lesiva, à luz do Direito do Consumidor. Este trabalho realiza um estudo indutivo, pois parte de uma análise singular para uma posterior averiguação em aspecto geral. O estudo evidencia que a responsabilização e fiscalização sobre esse tipo de publicidade ainda é insuficiente, constatando a necessidade de uma legislação específica e de punições mais severas a es', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7007', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb55', 'Adubação nitrogenada, irrigação e mulching no cultivo do maracujazeiro azedo', 'Sousa, Caio da Silva; de Mesquita, Evandro Franklin; Silva, Jordania Oliveira; Jales, Damião Vagno Dantas; Cavalcante, Lourival Ferreira; Maia, Diogo Dantas', 'Editora Verde', 'Agriculture', 'Agriculture', 'Objetivou-se objetivou-se avaliar o crescimrnto do maracujazeiro azedo (Passiflora edulis) e características térmicas do solo sob tipos de adubação nitrogenada, cobertura morta e manejo da irrigação. Os tratamentos foram distribuídos em blocos ao acaso, com três repetições e cinco plantas por parcela, arranjados no esquema fatorial 3x2 x2, referente ao manejo da irrigação: superficial- 7 horas); superficial e pulverizações aéreas- 9 horas) e (superficial e pulverizações aéreas- 16 horas); o solo sem e com cobertura morta, elaborada com restos de cultura da propriedade, adubação nitrogenada com sulfato de amônio e ureia. A adubação com nitrogênio e sulfato de potássio foi feita mensalmente na relação ao nível de 3 g de N e 3 g de K, respectivamente na forma de ureia e sulfato de amônio e sulfato de potássio aos 30 dias após o transplantio das mudas. Pelos resultados obtidos, a utilização da cobertura morta de solo constitui-se numa prática vantajosa para o cultivo do maracujazeiro azedo', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7014', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb5a', 'A importância das plantas medicinais na Umbanda e Candomblé na associação cultural no município de Puxinanã, Paraíba', 'Lima, Laura Ana Alves de; Santos, Viviane Galdino dos; Arruda, Deliane Andrade de; Santos, Vanderléia Galdino dos; Azevêdo, Camila Firmino de; Souza, Bruna dos Santos', 'Editora Verde', 'Agriculture', 'Agriculture', 'A utilização das plantas medicinais em práticas ritualísticas é algo bastante comum nas religiões existentes no Brasil, diante disso, o presente estudo apresenta uma pesquisa etnobotânica sobre o uso das plantas medicinais na Associação Cultural de Umbanda e Candomblé localizada em Puxinanã-PB. Foram feitas 50 entrevistas com pessoas que frequentam o terreiro, onde mostra o uso intenso das ervas naturais nos rituais, sendo as três mais citadas a jurema preta (Mimosa tenuiflora), liamba (Vitex agnus castus L.) e Pião roxo (Jatropha gossypiifolia L.), constatou-se também que todos os entrevistados acham importante a utilização das ervas, evidenciando a necessidade das mesmas se fazerem presentes nas ritualísticas da Umbanda e Candomblé. Os resultados confirmam que os entrevistados possuem um grande conhecimento e fazem uso nos rituais com as plantas medicinais, preservando a cultura popular na religião.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7031', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb5c', 'Preparação de produtos artesanais à base de plantas para tratamento animal', 'Silva, Juciely Gomes da; Jerônimo, Rayane Ellen de Oliveira; Azevedo, Camila Firmino de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Desde os primórdios o homem faz uso de plantas e produtos naturais, devido ao seu alto potencial de prevenção e cura das principais afecções acometida a eles. As plantas medicinais também podem ser usadas para tratar animais, in natura ou transformadas em diferentes tipos de preparações, sendo consideradas com alternativa segura, viável e de baixo custo, em especial para agricultores familiares, uma vez que reduz o uso de medicamentos sintéticos. Dessa forma, objetivou-se preparar diferentes produtos artesanais à base de plantas medicinais para uso animal, bem como incentivar e promover o uso de produtos naturais no tratamento e prevenção de doenças em animais. Foram produzidos sabonetes, pomadas e óleos artesanais por estudantes do Bacharelado em Agroecologia no Laboratório de Biologia do Campus II da UEPB. Tais produtos foram distribuídos com agricultores, tutores e entidades de proteção animal, além de expostos em eventos científicos e culturais, juntamente com mudas de espécies med', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7033', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb61', 'Produção orgânica de mudas de essências florestais nativas e distribuição em comunidades rurais do semiárido paraibano', 'Lima, Alex Serafim de; Silva, Francisca Lacerda da; Santos, Emmanuelly Calina Xavier Rodrigues dos; Silva, Natália Lara Ferreira da; Santos, José Geraldo Rodrigues dos; Diniz, José Paulo Costa', 'Editora Verde', 'Agriculture', 'Agriculture', 'Associado à degradação ambiental, o uso irracional de essências florestais nativas com fins farmacêuticos, industriais e medicinais, através da exploração das folhas, cascas, raízes e frutos, pode levar ao desaparecimento destas espécies. No bioma Caatinga, diversas espécies já integram a lista de ameaçadas de extinção. Contudo, são necessários meios rápidos e eficazes para a reversão dos efeitos negativos causados pela ação do homem. O projeto teve como objetivo contribuir para o reflorestamento de áreas degradadas na microrregião de Catolé do Rocha/PB com a produção e distribuição de mudas de florestas nativas da Caatinga. O projeto foi executado em condições de viveiro, na Universidade Estadual da Paraíba, Catolé do Rocha-PB, e consistiu na produção de 250 mudas orgânicas de aroeira, 250 mudas de cumarú, 250 mudas de sabiá e 250 mudas de mororó. Após a produção, as mudas foram distribuídas às comunidades rurais da microrregião de Catolé do Rocha, em que foram feitas algumas apresent', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7040', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb67', 'A agroecologia na escola', 'Alves, Bruna Laís Nascimento; Alves, Anne Caroline Bandeira Avelino; Lima, Gabriela Torres Costa', 'Editora Verde', 'Agriculture', 'Agriculture', 'A produção de alimentos é à base da agricultura, e em função das ações antrópicas inadequadas, causa prejuízos ao ambiente, por isso a agroecologia visa o desenvolvimento rural desde que minimize os prejuízos ao ambiente. O presente estudo tem por objetivo analisar a percepção dos alunos matriculados no ensino médio da escola ECI Estadual José Bronzeado Sobrinho no município de Remígio sobre agroecologia. A presente pesquisa foi desenvolvida na ECI Estadual José Bronzeado Sobrinho e ocorreu no mês de Agosto de 2019 no Município de Remígio-PB com um público de 20 jovens de faixa etária entre 15 a 18 anos e engajados do 1º ao 3º ano do ensino médio. Por meio de uma abordagem qualitativa de pesquisa, utilizou-se como instrumento a entrevista estruturada e analisou-se que os alunos apresentam dificuldades na compreensão do conceito da agroecologia. Embora afirmem que fazem consumo de produtos agroecológicos em suas residências. A escola é um importante espaço para disseminação de conceitos', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7050', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb6a', 'Emergência de plântulas e vigor de sementes de Anadenanthera colubrina (Vell.) Brenan (Fabaceae) em diferentes substratos e profundidades de semeadura', 'Azeredo, Gilvaneide Alves de; Silva, João Henrique Constantino Sales; Santos, Ricardo Monteiro dos; Medeiros, Maria da Guia de; Silva, Waldilene Rodrigues da', 'Editora Verde', 'Agriculture', 'Agriculture', 'O angico (Anadenanthera colubrina (Vell.) Brenan) é uma espécie arbórea nativa pertencente a família das Fabaceae que possui importância fundamental para a fauna e flora brasileira. Para a realização de testes de emergência e/ou germinação faz-se necessário escolher um substrato adequado a fim de proporcionar elevados percentuais de germinação e bom desenvolvimento das plântulas. Assim sendo, o presente trabalho teve como objetivo avaliar o efeito de diferentes substratos e profundidades de semeadura na emergência de plântulas e no vigor de sementes de angico. Para o desenvolvimento desta pesquisa, foram escolhidos dois substratos: areia e composto orgânico; e quatro profundidades de semeadura: 0 (superfície), 1, 3 e 5 cm. Foram avaliadas as seguintes características: emergência de plântulas (%); índice de velocidade de emergência (IVE); tempo médio de emergência (TME) e sobrevivência (%). O delineamento estatístico utilizado foi o inteiramente casualizado seguindo o esquema fatorial 2', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7054', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb6c', 'Brotação e sobrevivência de estacas de Moringa oleifera sob variações de luz e extrato aquoso', 'Costa, Patrícia da Silva; Meira, Kaline de Souza; Silva, João Paulo da; Silva, Alexandre Eugênio da; Silva Filho, Antônio Manoel da; Ferraz, Rener Luciano de Souza', 'Editora Verde', 'Agriculture', 'Agriculture', 'A Moringa oleifera é uma das plantas mais importantes do mundo, possui múltiplas utilidades e tolerância aos estresses abióticos, embora possa expressar baixa qualidade de mudas em ambiente protegido sob estresse luminoso e térmico. Objetivou avaliar a fotomorfogênese e consumo hídrico de estacas de M. oleifera sob variações do espectro de luz e extrato aquoso de tiririca, bem como identificar as variáveis mais importantes para explicação dos efeitos. Foi utilizado delineamento experimental inteiramente casualizado, em esquema fatorial 4x4, com três repetições. Foram estudadas quatro condições de luminosidade (luz branca, azul, vermelha e vermelho extremo) e quatro concentrações de EAT (0, 25, 50 e 100%). Semanalmente foram realizadas observações para determinação do número de brotação. Transcorridos 60 dias após o plantio, foi realizada avaliação do número de raízes e brotações sobreviventes. Ambientes protegidos irradiados com luz azul e aplicação de fitormônios possibilitaram a brot', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7056', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb6d', 'Morfometria radicular de Moringa oleifera em função do pré-tratamento de sementes com luz e extrato de tiririca', 'Costa, Patrícia da Silva; Meira, Kaline de Souza; Silva, João Paulo da; Silva, Alexandre Eugênio da; Silva Filho, Antônio Manoel da Manoel da; Ferraz, Rener Luciano de Souza', 'Editora Verde', 'Agriculture', 'Agriculture', 'Maior demanda por alimentos para garantia de segurança alimentar da população impulsiona o cultivo de plantas com potencial para múltiplos usos. Assim, objetivou-se avaliar a morfometria radicular de Moringa oleifera em função do pré-tratamento de sementes com luz e extrato de tiririca. A pesquisa foi realizada entre os meses de outubro e dezembro de 2018, no Laboratório de Fitopatologia pertencente ao Centro de Ciências Agrárias e Ambientais da Universidade Estadual da Paraíba, localizado no município de Lagoa Seca – PB. Utilizou-se delineamento inteiramente casualizado, em esquema fatorial 4x4, sendo quatro condições de luminosidade (luz branca, azul, vermelha e vermelho extremo) e quatro concentrações de extrato aquoso de tubérculos de tiririca (0, 25, 50 e 100%). As avaliações consistiram na medição do comprimento inicial da raiz, comprimento final da raiz e taxa de crescimento relativo da raiz. Para realização das análises foi utilizado o software Sisvar 5.6. A rizogênese da M. ol', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7058', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb6f', 'Proposta curricular das escolas do campo em Remígio, Paraíba', 'Cavalcante, Rita Cássia; Bezerra, Sidinéia Camilo', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente relato objetiva socializar parte da experiência de formação de educadores (as) do campo e a construção do currículo escolar, desenvolvido em 05 escolas do Município de Remígio/PB, parceria estabelecida entre a Universidade Estadual da Paraíba, Polo da Borborema, Secretaria de Educação e a ASPTA. O objetivo é contribuir com a formação docente e a (re) construção dos currículos das escolas do/no campo e (re) implementação dos Projetos Políticos Pedagógicos – PPP´s. A histórico da educação em estatísticas e relatórios MEC/INEP, assinalam para a invisibilidade, com que foram tratados nas políticas públicas educacionais, os sujeitos do campo. Porém, o marco definidor de ações de valorização da Educação do Campo veio por meio da LDB-9394/96 e as Diretrizes Operacionais para Educação Básica nas Escolas do Campo, que prevê um currículo contextualizado, considerando os saberes, identidades e culturas, priorizando pedagogias adequadas a essa população. Trabalhamos com princípios da: E', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7060', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb70', 'Crescimento inicial de feijão-caupi (Vigna unguiculata (L.) Walp.) sob variação de temperatura ambiente e condutividade elétrica da água', 'Costa, Patrícia da Silva; Sillva, Francisco de Assis da; Nascimento, Ronaldo do; Lima, Deise Maria Farias; Souza, Robson Fábio Alves de; Vasconcelos, Gleyka Nóbrega', 'Editora Verde', 'Agriculture', 'Agriculture', 'As mudanças climáticas promovem alterações na temperatura do ambiente e no regime de chuvas, refletindo-se em estresses térmico e hídrico, além de provocar instabilidade no rendimento das culturas. Objetivou-se avaliar a influência de temperatura e níveis de condutividade elétrica da água no crescimento inicial de feijão-caupi. O experimento foi conduzido em delineamento inteiramente casualizado, em esquema fatorial 2x5, com quatro repetições de 25 sementes crioulas, variedade corujinha. Os fatores consistiram de duas condições de temperatura (25 e 35 ºC) e cinco níveis de condutividade elétrica da água de umedecimento do substrato de germinação (0,4, 1,9, 3,4, 4,9 e 6,4 dS m-1). As avaliações consistiram na quantificação de variáveis de comprimento médio inicial e final da parte aérea, bem como a taxa de crescimento relativo. O aumento da temperatura do ambiente e da condutividade elétrica da água de umedecimento do substrato promoveu redução no crescimento das plântulas de feijão-cau', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7061', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb72', 'Avaliação participativa da qualidade do solo como proposta de construção do conhecimento agroecológico em um agroecossistema familiar', 'Silva, Wedson Aleff Oliveira da; Silva, Gerson João da; Rodrigues, Gabriel Torres; dos Reis, Eduarda Fernandes; Araújo, Alexandre Eduardo de; Melo, David Marx Gerson Antunes de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O manejo de agroecossistemas pode acarretar impactos na vida do solo. Partindo da ideia que as famílias agricultoras detêm muito conhecimento sobre a biodiversidade dos agroecossistemas e de seus solos, a avaliação desses solos com indicadores de qualidade do solo realizada juntamente com as famílias camponesas têm demonstrado que essa é uma opção viável no processo de transição agroecológica em busca de sistemas de produção cada vez mais sustentáveis. Nessa perspectiva, o objetivo do presente trabalho foi realizar avaliações participativas através de indicadores da qualidade do solo de um agroecossistema em transição agroecológica, Sítio Juazeirinho, Solânea-PB. Para tal foram escolhidos oito indicadores, tais como: Declividade; Estrutura; Compactação; Erosão; Cobertura vegetal; Cor; Atividade biológica e Matéria orgânica, sendo utilizados em quatro subsistemas agrícolas: Pasto, Roçado, Quintal Produtivo e Mata. Foi realizada uma abordagem descritiva das médias geral de qualidade do s', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7065', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb7a', 'Conservação de sementes de abóbora através de secagem convectiva', 'Ribeiro, Victor Herbert de Alcântara; Almeida, Raphael Lucas Jacinto; Melo, Mylena Olga Pessoa; Silva, Virgínia Mirtes de Alcântara; Barros, Sâmela Leal; Santos, Newton Carlos', 'Editora Verde', 'Agriculture', 'Agriculture', 'A secagem é uma forma de minimizar perdas, possibilitando o transporte, o armazenamento e aumentando a vida útil do produto. Portanto, o presente trabalho tem como objetivo realizar a secagem convectiva estudando o ajuste de curvas da secagem para sementes de abóbora em diferentes temperaturas. A secagem foi realizada em estufa de circulação de ar com velocidade de 1,5 m.s-1, nas temperaturas de 60 e 80 °C; e os modelos empíricos (Page, Lewis e Wing&amp; Singh), foram ajustados aos dados experimentais. Dentro os modelos empíricos aplicados o de Lewis e Page, apresentaram bons parâmetros estatísticos, no entanto, o modelo de Lewis foi considerado o de melhor ajuste devido a simplicidade de sua equação. Contudo, a secagem e uma técnica eficiente na conservação das sementes de abóbora, pois reduzem o teor de água aumentando a vida útil das mesmas.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7098', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb7b', 'Influência da temperatura sobre a composição físico-química de noni desidratado (Morinda citrifolia L.)', 'Ribeiro, Victor Herbert de Alcântara; Melo, Mylena Olga Pessoa; Silva, Virgínia Mirtes de Alcântara; Barros, Sâmela Leal; Nascimento, Amanda Priscila Silva; Santos, Newton Carlos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O noni é uma fruta exótica e pouco estudada no Brasil, porém há pesquisas que apontam seu elevado valor nutricional associado ao seu potencial antioxidante. Objetivou-se por meio do presente estudo, avaliar o potencial biotecnológico do noni, através da caracterização físico-química da fruta in natura e desidratada através de secagem convectiva, que foi realizada em secador com circulação de ar com as temperaturas de 50, 60 e 70 °C. As amostras in naturae desidratadas foram avaliadas com relação aos seguintes parâmetros: umidade, atividade de água, pH, acidez, teor de sólidos solúveis totais, ratio, proteínas, cinzas, vitamina C e lipídeos. Foi observado que o aumento da temperatura proporcionou a redução do teor de umidade e de atividade de água do produto, influenciando positivamente na estabilidade do produto. De maneira oposta, foi observada o aumento da acidez, sólidos solúveis totais, lipídeos, cinzas e vitamina C.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7099', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b012d6a63682f044cb97', 'IN VITRO STUDY OF A CHEMOSENSORY PROTEIN FROM SEA LOUSE Caligus rogercresseyi', 'Quiroz, Andres; Mutis, Ana; Pino, Jorge; Godoy, Ricardo', 'Editora Verde', 'Agriculture', 'Agriculture', 'The sea louse (Caligus rogercresseyi) is an ectoparasitic copepod that negatively affects salmon farming industry by reducing the health status of fish and producing significant economic losses. An alternative strategy to C. rogercresseyi control friendly with the environment or population´s health has been investigated. Previous information have pointed out that this crustacean has the ability of detecting semiochemicals. The use of semiochemicals as compounds capable of mediate the chemical communication between species could leads to the design of specific and harmless control traps. The olfactory system is the responsible for processing these chemical signals and chemosensory proteins (CSPs) are thought to act as specific carriers of these molecules. Therefore, the objective of this work was to evaluate the recombinant production of a previously identified CSP transcript from C. rogercresseyi (CrogCSP) transcriptome through the cloning, bacterial expression in competent cells and p', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7160', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cbf1', 'SETTLEMENT PREFERENCE OF THE WHITEFLY Trialeurodes vaporarorium IN TOMATO PLANTS DAMAGED BY Tuta absoluta', 'Rodrigo, Federico; Rossini, Carmen', 'Editora Verde', 'Agriculture', 'Agriculture', 'Ecological relations (both, beneficial and detrimental) between insects and plants have been deeply studied One of the cues that insects can detect and use to find their host plants is the emission of volatiles by the plants. These emissions vary when plants are exposed to abiotic and biotic factors (for example, herbivory). In this work, the interaction between two main pests of tomato (Solanum lycopersicum, Solanaceae), Tuta absoluta (Lepidoptera: Gelechiidae) and Trialeurodes vaporariorum (Hemiptera: Aleyrodidae) was studied. Based on our own observations during field work of these two insects living together on the same plants (eventhough nearby uninfected plants were available), an assay (N = XX replicates) where tomato plants damaged by 3 rd -instar-T.absoluta-larvae (n = 20-25 larvae/plant) were offered paired to undamaged plants to T. vaporariorum was performed. After 72h, adults preferentially settled on T.absoluta-damaged plants (19 ± 5) over undamaged (9 ± 1, p = 0.036, Wilc', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7228', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cbf2', 'THE HIGHLY AUTAPOMORPHIC ANDROCONIAL CHEMICAL BLENDS OF SYMPATRIC BRAZILIAN SULPHUR BUTTERFLIES (LEPIDOPTERA: PIERIDAE: COLIADINAE)', 'Lucas, Layse Albuquerque da Silva; Nobre, Carlos Eduardo Beserra; Navarro, Daniela Maria do Amaral Ferraz; Alves, Luiz Carlos; Maia, Artur Campos Dália; Padilha, Rafael José Ribeiro', 'Editora Verde', 'Agriculture', 'Agriculture', 'Chemical cues play an important role in the short-range communication of butterflies, remarkably in sexual attraction and mate choice. Differentiated scale patches on the wings of male butterflies, the androconia, are involved in the emission of pheromones. Here we describe the androconial morphology of six sympatric species of Neotropical sulphurs belonging to three genera of the Colias-clade (Lepidoptera: Pieridae), which occur in northeastern Brazil. The chemical composition of secretions was comparatively investigated to determine species-specific trends that might be involved in reproductive isolation and to verify if they yield phylogenetic signal. SEM imaging showed that the androconial patches from all species are differentiated from the non-androconial male wing surface by the higher density of scales, which compared to ordinary scales also exhibit larger windows in the upper lamellae that could facilitate the release of semiochemicals. Gas chromatography – mass spectrometry a', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7242', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cbf6', 'SPOTTED-WING DROSOPHILA (Drosophila suzukii) ATTACK AND FRUIT VOLATILE PROFILES: IN SEARCH FOR PARASITOID CHEMICAL CUES', 'González Ritzel, Andrés; Mato, Daniela; Vega, Gerardo de la', 'Editora Verde', 'Agriculture', 'Agriculture', 'The spotted-wing Drosophila (SWD), Drosophila suzukii, has become a major pest of berries and cherries worldwide. Originally from Asia, the insect has invaded Europe, North America and more recently South America, including austral regions in the southern cone. Different from other drosophilids that attack rotten fruit, SWD flies can colonize fruits that are still in the maturation process, hence of commercial value. Within potential integrated pest management methods, biological control with established parasitoid populations appears as an alternative worth exploring. While searching for suitable hosts, parasitoids of insects that develop inside the fruit may use host-related chemical cues such as volatile organic compounds (VOCs) released from the attacked fruit. Here we report our preliminary findings of blueberry VOCs prior and after colonization by SWD. Working with commercial blueberries, we sampled volatiles three times in relation to oviposition by SWD females: one day before (', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7250', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc14', 'Diatraea saccharalis (FABRICIUS, 1794) (LEPIDOPTERA: CRAMBIDAE) MALE RESPONSES IN WIND TUNNEL', 'Romero-Barrera, Yajaira; Sandoval-Caceres, Yuly; Cruz-Castiblanco, Ginna Natalia; Cely-Pardo, Liliana; Barreto-Triana, Nancy', 'Editora Verde', 'Agriculture', 'Agriculture', 'In order to determine the attraction of D. saccharalis males in wind tunnel, two bioassays were conducted on one- and two-days old (1 d.o. and 2 d.o.) virgin adults. The tests were carried out under controlled conditions 25°C, 50% HR, wind speed 0.30 m/s and inverted photoperiod 12h L:12h D, between the fifth and twelfth hour from the beginning of the scotophase. In the first trial (E1), male response to virgin females was evaluated, 15 males were tested by placing five females per age in a plastic cage. Each male was observed for 10 minutes, recording the response to the stimulus released by the females, Female free control was used (n = 10 for each male age). For the second trial (E2) male response to concentrated sex glands in n-hexane (16 female glands in average per ml) was evaluated. Thirty males were evaluated per treatment, applying 10µl of extract on a filter paper for each evaluation, and the response time to the stimulus and their behavior inside the tunnel was recorded duri', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7295', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc1b', 'A IMPORTÂNCIA DO FARMACÊUTICO NO TRATAMENTO DA OBESIDADE', 'Silva, Mateus Gonçalves; Francelino, Mikael Felipe V.; Neto, Vicente Saraiva dos S.; Meneses, Helmo Robério Ferreira de; Bezerra, Maria Eduarda F.; Cipriano, Ana Laura S.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A obesidade é uma doença, a mesma é caracterizada por o acumulo de gordura no corpo humano, esse excesso de adipócitos desencadeia danos e agravos à saúde, dos quais, cita-se: hipertensão arterial, cardiopatias, diabetes, hiperlipidêmicas, dentre outras. De acordo com estudo realizado por a Universidade de Washington em 2016, cerca de 2,1 bilhões de pessoas estão classificados como obesas ou com sobrepeso em todo mundo, na mesma pesquisa o Brasil, apresenta dados alarmantes, onde 1 a cada 5 brasileiros está obeso ou está sobrepeso. Neste contexto vários profissionais da saúde contribuem de forma positiva no tratamento da obesidade, dentre eles o farmacêutico, o qual possui papel fundamental na orientação a obesidade e das farmacoterapias utilizadas por enfermos. Dessa forma visou-se avaliar o nível de conhecimento dos participantes da pesquisa a respeito da patologia em questão, como também alertá-los sobre os riscos, agravos, prevenção e tratamento, além de destacar a importância do a', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7307', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc1f', 'HABEAS CORPUS 124.306/2016 E SUAS CONSEQUÊNCIAS NO ORDENAMENTO JURÍDICO BRASILEIRO', 'Silva, Mateus Gonçalves; Freitas, Igor Bezerra; Teixeira, Glícia Édeni de Lima; Cavalcante, Romélia Maia; Amorim, Samuel Ilo Fernandes', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente estudo mostra uma análise do julgamento do Habeas Corpus 124.306 RJ, impetrado pela 1ª Turma do Supremo Tribunal Federal, a qual decidiu, descriminalizar o aborto realizado durante o primeiro trimestre de gestação, independentemente do motivo que leve a mulher a interromper a gravidez. Teve como objetivo de evidenciar as consequências e os riscos do HC 124.306/2016 para nosso ordenamento jurídico. Para alcançar o objetivo proposto, foi desenvolvido uma pesquisa documental, de um caráter qualitativo, com abordagem dedutiva, a partir dos métodos de procedimentos monográfico e comparativo. O caso em tela fundamenta-se no principal direito fundamental tutelado pelo Estado, o direito à vida, em suas mais complexas nuances, como qual o momento ela se inicia, a inviolabilidade deste direito, os limites jurídicos protetivos dos fetos, em contraposição com os direitos fundamentais da mulher. O desenvolvimento do presente estudo possibilitou uma análise do julgamento pela primeira tur', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7311', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc2b', 'SEMIOCHEMICALS – VERSATILE NATURAL VOLATILES', 'Francke, Wittko', 'Editora Verde', 'Agriculture', 'Agriculture', 'Organisms are permanently surrounded by scents, which are made up of a broad spectrum of secondary metabolites originating from the ubiquitous pathways of classical catabolism or metabolism. Some of these volatiles are meaningful to the receiver or important for the sender but some do not seem to be registered at all. However, no naturally occurring compound is “just there”. Any chemical signal needs a receptor at the receiver site – and it may be asked whether semiochemicals may also be recognized by proteins that are not primarily involved in chemical communication. Consequently, it would make sense to generally screen semiochemicals for biological activities apart from their presently known function. Methyl p-hydroxybenzoate, a component of the honey bee queen pheromone, exhibits strong antibiotic properties. Similarly, (3S,6E)-2,3-dihydrofarnesol, (terrestrol),is a marking pheromone of male bumble bees and its enantiomer, released by the yeast Candida albicans show strong antibioti', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7422', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc2d', 'IDENTIFICATION AND SYNTHESIS AS TOOLS IN CHEMICAL ECOLOGY TO DECIPHER CHEMICAL MEDIATED INTERACTIONS BETWEEN ORGANISMS', 'Schulz, Stefan', 'Editora Verde', 'Agriculture', 'Agriculture', 'The identification of compounds used for communication between individuals of one or different species is fundamental to investigate chemoecological interactions. This is not only true for more traditional methods aiming to characterize a small set of active compounds of a particular interaction, but also mandatory for modern metabolomics approaches dealing with hundreds of compounds. In this contribution the approach followed by my group to identify these compounds will be presented, following two general concepts. A certain interaction can be clarified by isolating, synthesizing and testing target compounds, which is common practice. Besides this approach we also perform reverse Chemical Ecology, starting from Chemistry trying to identify many compounds and evaluate their activity. The latter procedure is exemplified by our work on springtails (Collembola), a sister group of the insects. Although their radiation is much smaller compared to insects, they are important members of many ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7424', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc2f', 'THE APPLICATION OF PROTEIN MASS SPECTROMETRY IN STUDYING POLYKETIDE BIOSYNTHESIS', 'Oldham, Neil J.', 'Editora Verde', 'Agriculture', 'Agriculture', 'Polyketide synthases (PKSs) are responsible for the production of a vast array of biologically active compounds that mediate interactions between organisms. Mass spectrometry (MS) is a powerful tool for studying the structure and enzymology of catalytic domains within PKSs. Here I present some of my group’s work on the use of MS to examine the biochemistry of domains from the trans-acyl transferase group of modular type I bacterial PKSs. In particular I will focus on the mechanism and significance of substrate specificity exhibited by ketosynthase domains and the mapping of interaction sites between PKS catalytic domains using carbene footprinting methodology.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7427', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc33', 'DIFERENCIAÇÃO DE MURCOTT TANGOR COM E SEM INFECÇÃO POR Alternaria alternata por RMN e MALDI MSI', 'Silva, Maria Fátima das Graças Fernandes da; Lopes, N. P.; Forim, M. R.; Ferreira, A. G.; Fernandes, J. B.; Isidoro, M M.', 'Editora Verde', 'Agriculture', 'Agriculture', 'A mancha marrom de alternaria (ABS), causada pelo fungo Alternaria alternata, é uma das mais graves doenças fúngicas de tangerinas e seus híbridos. O Murcott tangor é um dos mais suscetíveis a este fungo. Neste estudo, relatamos uma investigação sobre como A. alternata AT4303 influencia o perfil químico das folhas, caules e raízes de Murcott tangor. A quimiometria aplicada aos dados de HPLC-DAD foi utilizada para avaliar as semelhanças e diferenças entre os perfis cromatográficos. Os resultados indicaram que as maiores discriminações ocorreram nas folhas com sintomas comparados às sem sintomas após a infecção da cepa AT4303. Os espectros de 1H RMN obtidos a partir de extratos de folhas, utilizando um protocolo específico, mostraram que as concentrações das moléculas extraídas eram o suficiente para serem identificadas. Um exame mais detalhado dos espectros de RMN de 1H das folhas sintomáticas e controle negativo sugeriram a presença de quatro flavonoides. Tangeretina, nobiletina, apige', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7431', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b015d6a63682f044cc35', 'BIOLOGICAL PRODUCTION OF MOTH PHEROMONES IN CELL AND PLANT FACTORIES', 'Löfstedt, Christer', 'Editora Verde', 'Agriculture', 'Agriculture', 'The need for insect pheromones for pest control is increasing. Although synthetic insect pheromones can be produced in large volumes and used for mating disruption of insect pests to protect crops, the high cost of organic synthesis provides an obstacle for increasing the number of target insects and applications. Microbial cell factories as well as plants have been suggested as platforms for biological production of these high-value fine chemicals. Many moth sex pheromones are blends of modified fatty acids in the form of aldehydes, alcohols and acetates. By expressing the necessary and sufficient biosynthetic genes of insect and plant origin, we have made yeast and plants produce unsaturated fatty alcohols and acetates that are common moth pheromone compounds, as well as their fatty acid precursors. As a proof of concept, we co-expressed a ∆11 desaturase and a FAR in the Brewer’ s yeast Saccharomyces cerevisiae and produced (Z)-11-hexadecenol. In the OLEFINE project (OLEaginous yeast', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7437', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc3b', 'MARKERS OF OVIPOSITION PREFERENCE FOR THE ASIAN CITRUS PSYLLID', 'Amoros, María E.; Buenahora, José; Gurgueño, Anna P.; Rossini, Carmen', 'Editora Verde', 'Agriculture', 'Agriculture', 'The Asian citrus psyllid (ACP) is the vector of Huanglongbing, the most destructive citrus disease. Preliminary work has shown that ACP prefers to oviposit on Duncan grapefruit and Sweet Orange. Rough, Eureka and Cravo lemons showed variable results, whereas Citron was not preferred. Searching for biomarkers that may serve as kairomones for ACP females, the volatile organic compounds (VOCs) and the CDCl3 and D2O extracts from shoots of the mentioned varieties (N = 6/species) were analyzed by GCMS and NMR respectively. All processed data were submitted to multivariate analyses (MetaboAnalyst4.0). For the D2O extracts, the chemical profiles of Sweet orange and Duncan grapefruit were grouped; being different from the profiles of Citron while the Eureka, Cravo and Rough lemons exhibited intermediate profiles. These results correlated to the oviposition preference (PLS model, permutation test: P = 0.048). Correlation was traced to chemical shifts in the NMR spectra corresponding to compound', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7443', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc3d', 'IMPACT OF TRAP DESIGN FACTORS AND DEPLOYMENT METHODOLOGY ON THE PERFORMANCE OF SEMIOCHEMICAL-BAITED INTERCEPT TRAPS FOR FOREST Coleoptera.', 'Allison, Jeremy Dean', 'Editora Verde', 'Agriculture', 'Agriculture', 'Surveys of forest insect pests attempt to monitor populations by sampling the insect or quantifying the damage they cause. Those surveys that target the adult stage of an insect often use semiochemical-baited flight intercept traps. The development of survey and detection programs for forest insects is currently a reactionary trial-and-error process because of unexplained variation in trap design and deployment effects and a lack of consensus in the literature regarding trap performance among taxa and habitats. This approach is costly both in terms of the time required to develop and optimize survey tools and the amount of damage realized before management programs can be implemented. This talk will focus on: 1) the effect of trap design factors on the abundance and diversity of forest insects captured by intercept traps and potential underlying mechanisms; and 2) the impact of trap deployment protocol on intercept trap performance. Field trapping experiments were used to examine the i', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7445', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc3e', 'DIREITO À SAÚDE E FINANCEIRIZAÇÃO DA POLÍTICA DE SAÚDE NO BRASIL: UMA RELAÇÃO CONFLITUOSA', 'Rodrigues, Jyennyffer Barral; Lana, Emanuel Sampaio Borba; Lazaroto, Maria Laura Klein', 'Editora Verde', 'Agriculture', 'Agriculture', 'Nos termos do art. 196, da Constituição da República Federativa do Brasil de 1988, a saúde é direito de todos e dever do Estado, garantido mediante políticas sociais e econômicas, visando à redução do risco de doença e de outros agravos e ao acesso universal e igualitário às ações e serviços para sua promoção, proteção e recuperação (BRASIL, 1988). Contudo, o mundo capitalista tem levado à redução dos diretos sociais, estando a expropriação presente  na  gênese  do  capital,  sendo  exigida  como  condição  de  sua  reprodução  e expansão (LUPATINI, 2018). Com efeito, o presente trabalho explorará a relação conflituosa entre o direito à saúde e a financeirização da política de saúde no Brasil.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7446', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc3f', 'A ALIENAÇÃO PARENTAL NA GUARDA COMPARTILHADA E SUA APLICAÇÃO LEGAL DIANTE DE UMA DENÚNCIA DE ABUSO SEXUAL', 'Soares, Joyce Maria Borges; Nóbrega Macena, Airy John Braga da Nóbrega Macena', 'Editora Verde', 'Agriculture', 'Agriculture', 'A família, tida como núcleo da sociedade, firme alicerce para o desenvolvimento saudável das novas gerações, não deixa de sofrer, apesar de sua essência, com as constantes mutações dos séculos vindouros, necessitando desta maneira da tutela advinda do Direito. Neste contexto, se encontra a Lei 12.318/2010, que disciplina o fenômeno da alienação parental. O dispositivo legal traz diversos conceitos, estabelecendo regras e parâmetros para a atuação dos julgadores e impondo sanções para aqueles que de tal forma procederem. Porém, a busca pela justiça no Direito é árdua e ao se bater de frente com uma questão complexa, outras aparecem de imediato, inclusive quando se comenta sobre a guarda compartilhada e suas consequências na maturação da criança e do adolescente. Este trabalho tem como objetivo geral esclarecer as questões acerca dos temas acima citados, e como objetivos específicos explicar em que consiste a alienação parental; demonstrar como são aplicados pela legislação e jurisprudên', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7447', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc48', 'AÇÃO DIRETA DE INCONSTITUCIONALIDADE DA LEI ESTADUAL Nº 11.140 DE 08 DE JULHO DE 2018: Código de Bem-estar Animal da Paraíba', 'Ventura, Kívia de Sousa; Malta, Thainara Lima de Souza; Alves, Geíse Maria Lins; Santos, Haroldo Camilo dos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente estudo teve o objetivo de analisar os fundamentos utilizados para concessão das medidas cautelares junto a Ação Direta de Inconstitucionalidade (ADIn) da Lei Estadual nº 11.140 de 08 de julho de 2018 pelo Tribunal de Justiça do Estado da Paraíba, assim como, comparar os argumentos encontrados com aqueles da concessão de liminar pelo STF (Supremo Tribunal Federal) junto a ADIn 6071 – PB. Para tanto, anotações foram feitas após a leitura de cada uma das decisões e as semelhanças e diferenças entre os fundamentos utilizados em ambas as ações. Pareceu existir uma certa sobreposição entre as fundamentações das decisões no Tribunal de Justiça local e na Suprema Corte. Os parâmetros utilizados em ambas foram uma nota técnica do Ministério da Agricultura, alguns dispositivos constitucionais e a lei da Política Agrícola Nacional, não sendo utilizada a constituição do estado da Paraíba como parâmetro. Em sua decisão, o STF entendeu que o referido artigo apresenta inconstitucionalidade', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7460', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc51', 'A GOVERNANÇA DA ÁGUA NO BRASIL SOB UMA PERSPECTIVA REGIONAL', 'Lima, Lucas Alexandre de Oliveira; Araújo, Paulo César Batista de Araújo; Belem, Tayrane Gonçalves de Andrade; Leal, Marília Daniella Freitas de Oliveria; Veras, Ana Lívia Dias', 'Editora Verde', 'Agriculture', 'Agriculture', 'A gestão da água no mundo se tornou objeto de estudos de diferentes áreas, dado seu reconhecimento como direito humano fundamental. Sejam eles ambiental, social, econômica, jurídica ou política, a forma como os recursos hídricos são administrados, nesses contextos, compõe o que se conhece como Governança da Água ou Governança Hídrica. A governança da água compreende as políticas de participação, informação e gestão dos recursos hídricos, presentes nas agendas dos países. Essas ações são transferidas também para o âmbito regional na medida em que a divisão e a proteção das águas compartilhadas podem causar conflitos, os quais surgem, principalmente por problemas na governança desse recurso. Nesse sentido, esse artigo tem o objetivo de analisar como se dá a relação entre as políticas de gestão dos recursos hídricos no Brasil e as políticas de gestão de recursos hídricos na América Latina. O artigo utiliza-se de um método dedutivo de análise, partindo de uma premissa regional, para estabe', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7476', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc54', 'O PUNITIVISMO E A PROTEÇÃO À MULHER: ENTRE O EXCESSO DE LEGISLAÇÃO E AUSÊNCIA DE POLÍTICAS PÚBLICAS', 'Bernardo, Marília Elias', 'Editora Verde', 'Agriculture', 'Agriculture', 'Esta investigação nasce do questionamento feito acerca da necessidade de uma produção massiva de legislações voltadas ao combate da violência doméstica e da sua eficácia, premissa esta, observada a partir da sanção da Lei 13.871 de 17 de setembro de 2019, que altera a Lei Maria da Penha, para inserir em seu artigo 9º a responsabilidade do agressor no ressarcimento ao Sistema Único de Saúde, pelos serviços prestados no tratamento das lesões físicas e/ou psicológicas, sofridas pela(s) vítima(s) das suas ações. Percorre-se a partir dessa apuração, o levantamento de dados bibliográficos, documentais e estatísticos, que analisem o resultado da aplicação das normas voltadas à proteção da mulher e o seu impacto nos índices de violência. Por fim, trata sobre o que se presume ser, de fato, o problema a ser enfrentado para que se atinja a redução da violência doméstica no Brasil, quais sejam, a raiz cultural machista em oposição ao baixo investimento em políticas públicas de educação e conscient', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7479', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc55', 'INFORMAÇÃO JORNALÍSTICA: A MÍDIA E SUA INFLUÊNCIA NAS DECISÕES DO TRIBUNAL DO JÚRI', 'Maciel, Jonatas Claudio Farias; Santos, Vanessa Érica da Silva; Almeida, Rosana Santos de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A informação jornalística, apreciada por grande parte da população tem o dever de levar a notícia dos fatos ocorridos na sociedade, sua função primeira é de transmitir com autenticidade a informação. Com garantias constitucionais, amparada nas liberdades de opinião e pensamento a mídia livre é o pleno sinal de uma democracia forte e coesa, no entanto o poder de manobra de tais meios construindo um juízo de valor na sociedade implica diretamente interferindo no Tribunal do Júri, cujos jurados são membros da sociedade. Dessa forma, o presente estudo se consolida na análise da liberdade de imprensa na legislação pátria, enfocando como a mídia interfere nas informações de ordem criminal através de sua cobertura sensacionalista, realizando um pré-julgamento do acusado e interferindo na decisão do Júri Popular. Neste sentido evocaram-se formas que garantem a liberdade de informação e ao mesmo tempo demonstram meios de se coibir os excessos e se restabelecer a verdade dos fatos. Na realização', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7480', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc64', 'INTEGRATED USE OF BOTANICAL EXTRACTS AND NATURAL ENEMIES IN THE MANAGEMENT OF INSECTS-PEST', 'Bueno, Regiane Cristina Oliveira de Freitas; Bomfim, João Pedro de Andrade; Bonfim, Filipe Pereira Giardini; Oliveira, Lucas Alves de', 'Editora Verde', 'Agriculture', 'Agriculture', 'The species Bemisia tabaci (Hemiptera: Aleyrodidae) and Spodoptera frugiperda (Lepidoptera: Noctuidae) are important pests in agriculture around the world. They are problems for large crops, such as maize (Zea mays: Poaceae) and soybean (Glycine max: Fabaceae) and for horticultural crops, generally produced in smaller areas, such as tomato (Solanum lycopersicum: Solanaceae) and sweetpepper (Capsicum annuum: Solanaceae). As a way to reduce the effects of the attack of these insects, different tactics must be implemented in the context of Integrated Pest Management. Among these tactics are chemical control, using synthetic insecticides or natural products and biological control, with the use of natural enemies such as parasitoids and predators. In this context, the research group (AGRIMIP) has developed several studies aiming to evaluate the effect of botanical extracts and essential oils of plants of different taxonomic families on whiteflies and caterpillars, as well as to evaluate the', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7509', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc68', 'EPIDEMIOLOGIA DA TUBERCULOSE E EXPOSIÇÃO AOS FATORES DE RISCOS', 'Souza, Maria Alciene Saraiva de; Barbosa, Antônio de Freitas; Soares, Vanessa Alves Nascimento', 'Editora Verde', 'Agriculture', 'Agriculture', 'A tuberculose (TB) é uma doença causada pelo agente etiológico Mycobacterium tuberculosis e dependendo das fases possui sintomas tais como: febre, tosse, falta de apetite, sudorese e fadigas noturnas. Essa enfermidade é estudada pela epidemiologia, ciência das epidemias que observa a propagação, quantidade de casos, bem como diversos contextos que influenciem ou agravem os casos clínicos, caracterizando os fatores de risco para este problema. Segundo pesquisas realizadas na Biblioteca Virtual em Saúde (BVS), estudos apontam que no ano de 2012 cerca 8,6 milhões de pessoas foram infectadas pelo agente causador e 1,3 milhão foi a óbito no mundo. No Brasil, no ano de 2010, houve 2,4 de casos de mortes a cada 100 mil habitantes. De acordo com o Sistema de Informação de Agravos de Notificação (SINAN NET), foram diagnosticados 24 casos de TB na Paraíba e 01 caso em Cajazeiras entre os anos de 2016 e 2017.  A Organização Mundial de Saúde (OMS) visa diminuir 95% dos casos até o ano de 2035, vis', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7688', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc69', 'INCIDÊNCIA DE DOENÇAS DURANTE A MENOPAUSA', 'Soares, Vanessa Alves do Nascimento; Oliveira, Geane Silva; Braga, Maíra de Abreu', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente trabalho tem como objetivo analisar a incidência de doenças durante a menopausa. A pesquisa foi realizada nas bases de dados Scientific Eletronic Liberary online (SCIELO, LILACS e Biblioteca Virtual em Saúde (BVS), durante os meses de setembro a outubro, utilizando os descritores: incidência, menopausa e doença. A partir dos métodos de inclusão: últimos cinco anos, texto completo disponível, Brasil e português. Foram adotados os seguintes critérios de exclusão: aqueles que não se enquadravam com a pesquisa e os artigos repetidos. Com os filtros foram encontrados 08 artigos, dos quais restaram 04 após a realização da leitura após realizados os critérios de exclusão. Os dados mostram que a incidência de doenças no período da menopausa é evidente. São diversas as doenças prevalentes deste período, entre elas: Síndrome Metabólica (hipertensão arterial, distúrbios do metabolismo glicídico e lipídico, obesidade visceral), que a nível mundial é de 22% a 69% neste período; Doença Ca', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7691', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc6f', 'USO DE COLÁGENO COMO SUPLEMENTO NA OSTEOPOROSE', 'Nogueira, Vitória Bezerra; Assis, Luciana Moura de; Silva, Daniele Rodrigues da; Castro, Anúbes Pereira de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Com o processo de envelhecimento o corpo humano torna-se cada vez mais vulnerável a doenças e agravos, em virtude deste processo natural, cumulativo e irreversível caracterizado por modificações morfológicas e funcionais que atinge todo o organismo. O envelhecimento nas mulheres contribui com a maior parcela dos números de indivíduos acometidos com doenças como osteoporose (OP), em virtude dos baixos níveis de estrógeno o que leva a progressiva diminuição de massa óssea por meio de alterações tanto na remodelação quanto na reparação dessas estruturas. A OP é um distúrbio osteometabólico definido pela diminuição da densidade mineral óssea (DMO), com deterioração da integridade anatômica e estrutural do osso. O tecido ósseo é formado por minerais, osteócitos, osteoblastos, osteoclastos e o componente orgânico colágeno, que corresponde a cerca de 70% do volume total do tecido ósseo. Um dos componentes do tecido ósseo os osteoblastos, secretam moléculas de colágeno essenciais para a deposi', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7697', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc77', 'TAXA INSTANTÂNEA DE CRESCIMENTO POPULACIONAL DE Tetranychus bastosi TUTTLE, BAKER & SALES (ACARI: TETRANYCHIDAE) EM BATATA-DOCE', 'Breda, Mariana Oliveira; Silva, Dallisson Philipe da; Lima, Renata Pereira de; Santos, Thales Ferreira dos; Gonçalves, Fernanda da Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'Tetranychus bastosi Tuttle, Baker &amp; Sales, 1977 (Acari: Tetranychidae) é uma espécie com ocorrência restrita ao Brasil e já foi relatado infestando 36 espécies de plantas, entre ornamentais, frutíferas, leguminosas e plantas espontâneas. Sua ocorrência foi registrada nas regiões Nordeste, Sudeste, Centro-Oeste, Norte e no Distrito Federal, sendo a região Nordeste a mais abundante em número de plantas hospedeiras, entretanto pouco se sabe sobre seu crescimento populacional em espécies de importância agrícola para a região. Sendo assim, esse trabalho objetivou-se determinar a taxa instantânea de crescimento populacional (ri) desse ácaro em batata-doce, Ipomoea batatas L. (Solanaceae). Para o bioensaio, discos de folhas de 3,0 cm (Ø) contornados com algodão umedecido foram colocados em arenas contendo espuma de polietileno®. Em cada disco foram liberadas cinco fêmeas de T. bastosi obtidas da criação estoque. A arena foi mantida em câmara climatizada tipo BOD a 25°C de temperatura, 70 ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7738', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc78', 'OCORRÊNCIA DE AGENTES DE CONTROLE BIOLÓGICO NATURAL DE Thyrinteina arnobia (STOLL, 1782) (LEPIDOPTERA: GEOMETRIDAE) NO ESTADO DE ALAGOAS', 'Breda, Mariana Oliveira; Lima, Renata Pereira de; Rodrigues, Matheus Barros; Bezerra, Lucas Teles; Almeida, Camila Alexandre Cavalcante de; Santos, Jakeline Maria dos; Gonzaga, Elmadã Pereira; Gonçalv', 'Editora Verde', 'Agriculture', 'Agriculture', 'O cultivo de Eucalyptus spp. no estado de Alagoas é de recente implantação, visando estimular a diversidade produtiva da região, num cenário em que áreas canavieiras de encostas e declives acentuados, de baixo rendimento, estão sendo gradativamente substituídas por povoamentos florestais. O aparecimento de insetos-praga em implantações florestais de Eucalyptus spp. pode ocasionar perdas significativas, diminuindo a produção. Dentre eles, destaca-se a lagarta parda do eucalipto, Thyrinteina arnobia (Stoll, 1782) (Lepidoptera: Geometridae), considerada como a principal praga desfolhadora de Eucalyptus spp. no país. Dessa maneira, diversos métodos para controle de insetos, inseridos no contexto do Manejo Integrado de Pragas Florestais (MIP Floresta) vem sendo aprimorados para o manejo de T. arnobia. Dentre eles, o conhecimento da atuação de agentes de controle biológico natural, com ocorrência espontânea em campo, ocasionando mortalidade, é de fundamental importância para o monitoramento ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7739', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc7d', 'CARACTERIZAÇÃO DA ENTOMOFAUNA EM HORTA MEDICINAL AGROECOLÓGICA UTILIZANDO ARMADILHAS TIPO PITFALL', 'de Carvalho, Alyce Rocha; Breda, Mariana Oliveira; Alves, Carla da Rocha; Avelino, João Raphael Lima; Fortes, Clemens Rocha', 'Editora Verde', 'Agriculture', 'Agriculture', 'A caracterização da entomofauna constitui o primeiro passo para elaboração de estratégias para o Manejo Ecológico de Pragas (MEP), possibilitando o conhecimento de espécies que vivem em determinados locais e o seu relacionamento com o meio-ambiente, além das relações entre os mais diversos níveis tróficos. Para o estudo da entomofauna, o uso de armadilhas são técnicas de fácil aplicação e baixo custo. Assim, o objetivo deste trabalho foi realizar a caracterização da entomofauna associada ao ambiente de horta medicinal agroecológica utilizando armadilhas do tipo pitfall. O presente estudo foi realizado em horta medicinal agroecológica do Campus de Engenharias e Ciências Agrárias da Universidade Federal de Alagoas (CECA/UFAL), onde foram colocadas 10 armadilhas de solo do tipo pitfall constituídas de recipientes plásticos com capacidade volumétrica para 1,8L (150 mm x 147 mm) contendo 800 mL de água e detergente, na proporção de 5%. As coletas foram realizadas semanalmente totalizando qu', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7747', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc81', 'OCUPAÇÃO NOS COLÉGIOS: UMA ANÁLISE ACERCA DO ESCOPO JURÍDICO E A NECESSIDADE DO MOVIMENTO ESTUDANTIL', 'Bezerra Neto, Francisco das Chagas; Victor, Gabriela Pereira Victor; Queiroz, João Paulo de; Alves Caiana, Clarice Ribeiro; Araújo, Gabriel Lima', 'Editora Verde', 'Agriculture', 'Agriculture', 'O trabalho visa analisar, a partir do contexto histórico e seguindo-se para um escopo jurídico, e posteriormente entendimento jurisprudencial a importância dos protestos realizados em escolas do Estado de São Paulo e Paraná em contrapartida medidas consideradas abusos de poder, tanto legislativamente quanto executivamente. Nessa perspectiva, este estudo, através da pesquisa exploratória, de natureza qualitativa, método dedutivo, coleta de dados bibliográfico-documental, procedeu-se de modo a realizar uma análise dos fatos e os posicionamentos das autoridades públicas para a relevância social de um protesto político, sendo então, como instrumento para impedir que exageros por parte de órgãos públicos, trazendo em tona as necessidades de quem supre-se dos direitos educacionais. Por fim, trazer o legado que atuação estudantil sociopolítica acresce ao nosso âmbito jurídico do Brasil.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7804', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc83', 'LEVANTAMENTO E CARACTERIZAÇÃO DA ARTROPODOFAUNA EDÁFICA EM CLONE VE41 DE Eucalyptus urograndis EM ALAGOAS', 'Pontes, Dallison Philipe da Silva Almeida; Breda, Mariana Oliveira; Xavier, Maria Eugênia Vieira; Bezerra, Lucas Teles; Almeida, Camila Alexandre Cavalcante de; Santos, Jakeline Maria dos; Santos, Tha', 'Editora Verde', 'Agriculture', 'Agriculture', 'O conhecimento e caracterização da artropodofauna em povoamentos florestais de Eucalyptus spp. constitui uma ferramenta essencial para o desenvolvimento do programas de Manejo Integrado de Pragas Florestais, tendo em vista a possibilidade de detecção da ocorrência de insetos, exóticos e nativos, com o potencial para se tornar pragas, além da identificação de seus respectivos inimigos naturais. Além disso, permite analisar outras funções exercidas por esses organismos no solo, tais como: reciclagem de nutrientes, controle da cadeia trófica, revolvimento das camadas do solo, dentre outras. Dessa forma, o objetivo do presente estudo foi realizar o levantamento e a caracterização da artropodofauna edáfica associada ao clone VE41, em povoamento florestal de Eucalyptus urograndis. O estudo foi conduzido em um povoamento florestal experimental clonal de E. urograndis, numa área de aproximadamente 2,5 ha, localizada no Campus de Engenharias e Ciências Agrárias da Universidade Federal de Alagoa', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7816', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc85', 'POTENCIAL ACARICIDA DE Momordica charantia L. (CUCURBITACEAE) A Tetranychus urticae KOCH (ACARI: TETRANYCHIDAE)', 'Espinoza, David Jossue López; Rocha, Janynne Joyce de Lima; Silva, Aleska Batista de; Silva, Naely de Lima; Menezes, Karen Oliveira de; Silva, Gessyca Thays dos Santos; Trindade, Roseane Cristina Pred', 'Editora Verde', 'Agriculture', 'Agriculture', 'O ácaro rajado, Tetranychus urticae Koch, 1836 (Acari: Tetranychidae), causa danos econômico para diversas culturas, seu potencial está relacionado ao rápido ciclo biológico e elevado potencial reprodutivo. Essas características contribuem para sua acelerada capacidade de adquirir resistência aos acaricidas sintéticos, dificultando o controle dessa praga. Com isso, o controle alternativo é uma opção que pode contribuir para redução do nível populacional desses ácaros. Assim, almeja-se através deste trabalho avaliar a toxicidade do extrato etanólico de Momordica charantia L. (Cucurbitaceae) sobre T. urticae. Para tal, foi realizado teste de toxidade por contato direto desse extrato sobre os ácaros. As dosagens testadas para o extrato etanólico de M. charantia foram 0,1; 0,5; 1,0 e 1,5%, nas quais foram solubilizadas em água destilada e Tween 80 (0,005%). Foram utilizadas arenas de placas de Petri (9 cm) contendo uma esponja de polietileno umedecida com água destilada sobre esta foram ad', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7818', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc87', 'EXTRATO ETANÓLICO DE Dysphania ambrosioides L. PARA CONTROLE DE Tetranychus urticae KOCH, (ACARI: TETRANYCHIDAE)', 'Lima, Maurício Silva de; Rocha, Janynne Joyce de Lima; Silva, Aleska Batista de; Farias, Paulo Henrique Tavares Santos; Menezes, Karen Oliveira de; Silva, Gessyca Thays dos Santos; Trindade, Roseane C', 'Editora Verde', 'Agriculture', 'Agriculture', 'O ácaro rajado Tetranychus urticae Koch, 1836 (Acari: Tetranychidae) é considerado um dos ácaros pragas de maior importância econômica para agricultura, devido sua capacidade em atacar diversas culturas. O controle desta praga é realizado principalmente através do uso de acaricidas sintéticos, que cada vez mais seleciona populações resistentes e torna seu controle ainda mais difícil. Desse modo, pesquisas voltadas ao controle alternativo com uso de extratos para esse ácaro vêm crescendo bastante. Assim, objetivou-se avaliar a toxicidade do extrato etanólico de Dysphania ambrosioides L. (Amaranthaceae) sobre T. urticae. Para tal, foi realizado teste de toxidade por contato com extrato etanólico, o qual foi solubilizado em água destilada e Tween 80 (0,005%). As porcentagens testadas para o extrato etanólico de D. ambrosioides L. foram 0,1; 0,5; 1,0 e 1,5%. A toxicidade do extrato foi avaliada através do contato direto desse extrato sobre os ácaros. Foram utilizadas arenas a partir de pla', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7821', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc88', 'Cerconota anonella (SEPP., 1830) (LEPIDOPTERA: OECOPHORIDAE) EM POMAR DE ANONÁCEA EM RIO LARGO, ALAGOAS', 'Santos, Joice Kessia Barbosa dos; Santos, Eliane dos; Santana, Antônio Euzébio Goulart; Santos, Jakeline Maria dos; Lemos, Eurico Eduardo Pinto de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A broca do fruto das anonáceas, Cerconota anonella (Sepp., 1830) (Lepidoptera: Oecophoridae), é uma das pragas-chave em cultivos de anonáceas em regiões produtoras do País. O principal dano econômico causado à cultura se deve a inviabilidade da comercialização dos frutos em virtude das injúrias causadas. Os prejuízos podem ser de até 100%, pois as lagartas se alimentam da polpa e as galerias construídas facilitam o desenvolvimento de vários patógenos, tornando-se os frutos impróprios ao consumo ou extração da polpa. Os sintomas de ataque são facilmente reconhecidos devido aos resíduos de digestão que são depositados sobre a superfície do fruto à medida que a lagarta penetra no seu interior; os frutos ficam retorcidos ou com partes enegrecidas, quase sempre perfurados. O objetivo do trabalho foi avaliar o índice de infestação de C. anonella em frutos de pinha (Annona squamosa L.) em um plantio experimental no Campus de Engenharias e Ciências Agrárias da Universidade Federal de Alagoas (', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7822', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc8b', 'PATOGENICIDADE DE ESPÉCIES DE BOTRYOSPHAERIACEAE DO COQUEIRO À HOSPEDEIROS ALTERNATIVOS', 'Lima, Mayara Oliveira; Abreu, Larisse Araújo de; Feijó, Matheus Gomes Lessa; Assunção, Iraildes Pererira; Brito Neto, Mariote dos Santos; Barbosa, Tiago Jorge; Lima, Gaus Silvestre de Andrade; Nascime', 'Editora Verde', 'Agriculture', 'Agriculture', 'O coqueiro (Cocos nucifera L.) é uma das culturas tropicais perenes mais importantes e é amplamente cultivado no Brasil. Devido a busca por aumentos na produção houve o favorecimento da disseminação de doenças fúngicas, sobretudo as foliares causadas por espécies de Botryosphaeriaceae. Entre essas doenças, a queima das folhas é a principal e sua presença pode causar perdas significativas de produção. O conhecimento prévio de fatores relacionados a produção, tais como as condições ambientais favoráveis ao patógeno e a gama de hospedeiros alternativos, são extremamente necessários para a obtenção de sucesso no controle dessas doenças. Diante disso, o objetivo deste estudo foi testar a patogenicidade das espécies de Botryosphaeriaceae identificadas causando queima das folhas do coqueiro em coqueiro e outros hospedeiros frutíferos. Para tanto, a patogenicidade de três espécies de Botryosphaeriaceae (Lasiodiplodia theobromae e Lasiodiplodia brasiliense), identificadas causando queima das fo', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7832', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc95', 'Colletotrichum gloeosporioides sensu lato ASSOCIADA À PODRIDÃO VERMELHA DA CANA-DE-AÇÚCAR NO ESTADO DE ALAGOAS', 'Lima, Gaus Silvestre de Andrade; Abreu, Larisse Araújo de; Silva, Gilberlan Costa Santos da; Assunção, Iraildes Pereira; Costa, Jaqueline Figueredo de Oliveira; Feijó, Frederico Monteiro; Silva, Maria', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Brasil é o maior produtor mundial de cana-de-açúcar. Dentre as doenças que ocorrem na cultura, se destaca a podridão vermelha, que incide nas folhas, toletes e principalmente em colmos, prejudicando a produção e a qualidade do produto para a comercialização e industrialização. Trabalhos sobre a etiologia dessa doença são escassos e geralmente baseiam-se em caracteres morfológicos e culturais, apontando Colletotrichum falcatum como agente etiológico da doença. Contudo, o uso de análises mais completas, com base em dados moleculares podem revelar outras espécies associadas à doença. O objetivo do presente trabalho foi identificar espécies de Colletotrichum associadas à podridão vermelha da cana-de-açúcar. O isolado foi obtido de plantio comercial de Saccharum no estado de Alagoas, apresentando sintomas da doença. A caracterização cultural foi realizada mediante a mensuração do crescimento micelial do isolado a 25 °C, topologia e coloração da colônia cultivada em meio BDA sintético. A c', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7994', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc96', 'DETECÇÃO DE BADNAVÍRUS EM GENÓTIPOS DE CANA-DE-AÇÚCAR DO BANCO DE GERMOPLASMA DA SERRA DO OURO, MURICI-AL', 'Chaves, Lívia Francyne Gomes; Menezes, Lucas Marques; Silva, Sarah Jacqueline Cavalcanti da; Ferro, Mayra Machado de Medeiros; Lima, Mayara Oliveira de; Assunção, Iraildes Pereira; Lima, Gaus Silvestr', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Brasil é o maior produtor e exportador de açúcar do mundo, para isso o banco de germoplasma do Programa de Melhoramento Genético da Cana-de-açúcar (PMGCA/CECA/UFAL) tem sido primordial para o desenvolvimento de dezenas de variedades que ocupam mais de 65% da área de cultivo do país. Em 2015, estudos mostraram a presença de vírus do gênero Badnavirus ocorrendo em genótipos deste banco de germoplasma. O objetivo do presente estudo foi verificar a incidência e caracterizar espécies de badnavírus presentes no banco de germoplasma do PMGCA/CECA/UFAL. DNA total foi extraído, a partir de 60 genótipos de cana-de-açúcar, e utilizado como molde para amplificação da região RT/RNaseH por PCR. Posteriormente, os produtos foram diretamente sequenciados. As sequências foram montadas no programa CodonCode Aligner e alinhadas na ferramenta MUSCLE disponível no programa MEGA 7.0. Para determinação do posicionamento taxonômico foram feitas comparações pareadas utilizando o programa Sequence Demarcation', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/7999', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc99', 'A NOTORIEDADE DE UM GESTOR EM SAÚDE FRENTE UMA EQUIPE DE PROFISSIONAIS RESPONSÁVEIS NOS CUIDADOS DE SAÚDE COM OS PACIENTES', 'Oliveira, Paulo Renato de; SANTOS NETO, VICENTE SARAIVA DOS; PIRES, MARIA JOSÉ SOARES DE BELCHIOR; BELCHIOR, SANDRA MAIJANE SOARES DE; MARTINS, HELIANE ALVES', 'Editora Verde', 'Agriculture', 'Agriculture', 'A gestão eficiente em serviços de saúde é uma estrutura primordial, para assim objetivar uma administração compromissada com o bem estar dos seus clientes\pacientes, um tratamento mais ágil, adequado e seguro, o que reflete significativamente na promoção de uma melhor qualidade de vida seja através da prevenção em saúde evitando outras complicações, no tratamento de patologias instaladas possibilitando assim da melhor maneira e comodidade a satisfação do cliente\paciente que se encontra em condição de vulnerabilidade pela sua exposição aos riscos a sua integridade física ou mental, como também promovendo sempre que possível a cura diante das ofertas nos cuidados ao paciente, o que traz não só para o cliente\paciente, mas também para familiares e amigos um maior respeito e credibilidade nos serviços prestados pela instituição que se entende a toda a equipe de saúde envolvida no processo de restauração para qualidade de vida do enfermo. Com a presença de um gestor capacitado a frente de ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/8322', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798b018d6a63682f044cc9a', 'A CONTRIBUIÇÃO DO PROERD NO ENSINO REGULAR: CONSTRUÇÃO DA CIDADANIA', 'SANTOS NETO, VICENTE SARAIVA DOS; BELCHIOR, VERÔNICA CRISTIAN SOARES DE; PIRES, MARIA JOSÉ SOARES DE BELCHIOR; OLIVEIRA, PAULO RENATO DE; BELCHIOR, SANDRA MAIJANE SOARES DE', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Programa Educacional de Resistência às Drogas – PROERD, trata-se de um projeto que foi desenvolvido em Los Angeles nos Estados Unidos em 1983, como proposta para orientar crianças e adolescentes sobre os riscos e consequências de envolvimento com drogas, visando assim, a prevenção como proposta de evitar índices crescentes de prisões entre crianças e adolescentes por ocasião do contato, uso ou abuso de drogas, que acarretava na prática de outros crimes, e, depois de três décadas, hoje está implantado em mais de 50 países. O PROERD consiste em levar informações sobre as drogas e suas consequências de uma maneira lúdica e pedagógica construindo através de informações uma mentalidade entre os discentes de forma que esses em um primeiro contato direto ou indireto com as drogas estejam preparados para de forma confiante recusar a oferta, pois no decorrer das aulas são repassadas orientações de possíveis consequências sociais, orgânicas, econômicas e de relações humanas, quando por muitas ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/8323', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2fa', 'Eficiência da inoculação de Azospirillum brasilense associado com enraizador no crescimento e na produção de alface', 'Osvino Schimidt; Antonio Anicete de Lima; Luciano dos Reis Venturoso; Aniquely Ferreira Gomes; Bruno Antonio Azevedo Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito da inoculação de Azospirillum brasilense (AzBr) com e sem enraizador, no crescimento, produção de biomassa e resistência a pragas da alface, cultivar Lucy Brown. O experimento foi conduzido em casa de vegetação em recipientes plásticos com capacidade de 8,0 L no espaçamento 40 x 20 cm. O delineamento experimental foi de blocos casualizados em esquema fatorial (2x3)+1, sendo o primeiro fator Azospirillum com e sem enraizador de crescimento e o segundo doses de nitrogênio em cobertura, 0%, 50% e 100% da recomendação de adubação e uma testemunha com adubação convencional, com quatro repetições. Em doses médias de 50% de N em cobertura, tanto o AzBr, quanto a associação AzBr mais enraizador, apresentaram um incremento significativo na massa fresca da parte aérea e de raízes de 19,36% e 23,66%, respectivamente, em relação a dose máxima de N e a testemunha. A massa seca da parte aérea não diferiu significativamente nos diferentes tratamentos, embora tenha mostra', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4300', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4379cbb2c2c1af3060', 'Manejo dos sistemas agroflorestais em Tomé-Açu, Pará: Utilização dos resíduos de poda', 'Marinalva Cardoso Maciel (Universidade Federal do Pará); Osvaldo Ryohei Kato (Embrapa Amazônia Oriental); Gisele do Socorro dos Santos Pompeu (Universidade Federal do Pará); José Virgílio de Oliveira ', 'Editora Verde', 'Agriculture', 'Agriculture', 'O uso da madeira da poda agroflorestal surge como uma forma de incentivo ao manejo das árvores nos sistemas agroflorestais (SAFs) e como fonte de matéria prima para artesãos, proporcionando maior visibilidade ao componente arbóreo. O objetivo com esse estudo é avaliar o uso da poda como estratégia de manejo dos SAFs e na confecção de artefatos em madeira. A pesquisa foi realizada em uma propriedade da Associação de Produtores e Produtoras da Agricultura Familiar do Município de Tomé-Açu, e com artesãos da Associação de Artesãos da Amazônia, de Belém, Pará. Coletaram-se dados sobre a poda do componente arbóreo e sobre a compreensão da sustentabilidade no uso da poda no manejo dos SAFs e na atividade de artesanato. Os dados foram analisados pela estatística descritiva. A poda agroflorestal gerou 2,3 m3 de resíduos que foram utilizados para cobertura morta e a confecção de artefatos, portanto, o uso da madeira de poda se estabelece como mais um produto dos SAFs familiares, incentiva o man', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5604', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4379cbb2c2c1af3079', 'Relações estruturais e de diversidade de uma floresta ripária em unidade de conservação e sua zona de amortecimento', 'Natielle Gomes Cordeiro (Universidade Federal de Lavras); Inkamauta Valeda Cerda Plazas (Universidade Estadual do Sudoeste da Bahia); Christian Dias Cabacinha (Universidade Federal de Minas Gerais); L', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo do estudo foi analisar a estrutura, diversidade e heterogeneidade do componente arbóreo de uma Mata Ripária em uma Unidade de Conservação. Além disso, comparar a estrutura desta vegetação com a Mata Ripária da zona de amortecimento. A área de estudo está situada no Parque Estadual Lapa Grande, Minas Gerias (Brasil). O inventário florestal foi realizado na unidade de conservação (UC) e na sua zona de amortecimento. Como critério de inclusão, mensurou-se todos os indivíduos com DAP ≥ 3 cm, bem como a sua altura total. Processou-se os parâmetros fitossociológicos e florísticos da vegetação, e empreendeu-se a análise de correspondência distendida (DCA), análise de agrupamento de “cluster” do coeficiente de similaridade de Horn e o coeficiente de Jaccard. Foram amostrados 1.426 indivíduos dentro da unidade de conservação e 944 indivíduos para a zona de amortecimento. O índice de diversidade de Shannon encontrado para a UC foi de 4,61 nats.ind-1, a equabilidade de Pielou de 0,85. ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5822', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4379cbb2c2c1af309e', 'Teor de macronutrientes em girassol ornamental sob doses de esterco e efluente doméstico', 'Hans Raj Gheyi; Leandro de Oliveira Andrade; Reginaldo Gomes Nobre; Nildo da Silva Dias; Eric Mateus Soares Dias (UNIVERSIDADE DO ESTADO DO RIO GRANDE DO NORTE)', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os estercos são subprodutos da pecuária por vezes descartados, mesmo sendo potencialmente adubos orgânicos. A água residuária também é considerada outro subproduto de potencial para reuso na agricultura. Objetivou-se avaliar o teor de nitrogênio, fósforo e potássio em plantas de girassol ornamental (Helianthus annuus L., cv. Sol Noturno) adubadas com esterco bovino e irrigadas com efluente doméstico tratado. Os fatores estudados foram 2 tipos de água de irrigação (abastecimento e efluente doméstico) e 4 doses de esterco bovino (5, 10, 15 e 20%, com base em peso). Aos 60 dias depois do plantio (DAP), as plantas de girassol foram colhidas e fez-se a preparação das amostras de parte das plantas (raízes, caules, folhas e flor), as quais foram secadas em estufa com ventilação forçada a 62 °C, durante 72 horas e em seguida, realizou-se a determinação dos teores de nitrogênio (N), fósforo (P) e potássio (K) em uma amostra composta de diferentes partes. O teor de N foi influenciado positivamen', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4659', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4379cbb2c2c1af30a3', 'Fauna de Euglossina (Hymenoptera: Apidae) de um fragmento de Mata Atlântica do Alto Oeste Potiguar, Rio Grande do Norte', 'Thiago Mahlmann (INPA); Eduardo Alves de Souza (UFERSA); Michelle de Oliveira Guimarães-Brasil (IFRN); Daniel de Freitas Brasil (UFERSA)', 'Editora Verde', 'Agriculture', 'Agriculture', 'As abelhas da subtribo Euglossina encontram-se amplamente distribuídas na região Neotropical, sendo mais diversificadas nas florestas úmidas. Objetivou-se realizar um levantamento das espécies desta subtribo em um fragmento de Mata Atlântica, um remanescente de brejo de altitude, localizado em uma região do Semiárido Brasileiro. O estudo foi conduzido no município de Portalegre, Rio Grande do Norte, entre os meses de fevereiro e agosto de 2015. A coleta de dados foi realizada mensalmente entre às 08h00 e 16h00, com a utilização de armadilhas contendo as essências eucaliptol, eugenol e vanilina. Foram coletados um total de 123 machos, distribuídos em quatro gêneros e seis espécies, sendo elas: Eufriesea danielis (43,09%), Euglossa melanotricha (25,20%), Euglossa cordata (15,45%), Eulaema nigrita (13,82%), Euglossa fimbriata (1,63%) e Exaerete dentata (0,81%). O intervalo entre 08h00 e 10h00 foi o de maior atividade, com 54,4% do total dos machos coletados. A comunidade de abelhas da reg', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4832', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4479cbb2c2c1af30a5', 'Dinâmica espacial dos parâmetros físicos e químicos da água em viveiros de piscicultura', 'Antonio Clementino dos Santos (Universidade Federal do Tocantins); Otacilio Silveira Júnior (UFT); Danilo Gomes de Oliveira (IFTO); José Mário Lopes da Rocha (IFTO); Elisson Gomes da Silva (UFT); Caio', 'Editora Verde', 'Agriculture', 'Agriculture', 'O Brasil apresenta características que podem fazer do seu território o grande celeiro mundial para produção de organismos piscícolas cultivados. No entanto, para isso, é fundamental estudar os parâmetros físico e químico da água das áreas de cultivo, para que se possam buscar estratégias para evitar erros de manejos. Com isso, objetivou-se avaliar a dinâmica espacial dos parâmetros físicos e químicos da água de viveiros de piscicultura e sua relação de dependência. O estudo foi realizado em um viveiro escavado em terreno natural, localizado em uma propriedade, adjacente à fazenda experimental da escola de Medicina Veterinária e Zootecnia, da Universidade Federal do Tocantins, no município de Araguaína. Os pontos para coleta no grid foram obtidos através de GPS, considerando as dimensões da área total. Em cada ponto georreferenciado, foram realizadas coletas em duas profundidades diferentes, uma a 20 cm da superfície da água (profundidade 1), e outra a 20 cm do fundo do tanque (profundi', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4844', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1b6', 'Ocorrência de patógenos em cultivos de melancia e abóbora no sertão da Paraíba', 'M. G. F. O. Soares; J. A. Soares; J. A. A. Lima; T. A. L. Cardoso; M. A. Cezar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Por constituírem uma importante fonte de alimento, plantações de melancia e abóbora são comumente cultivadas no sertão paraibano, porém pouco se sabe sobre a ocorrência de patógenos causadores de doenças, os quais limitam a sua produtividade e renda aos produtores. Visando obter informações sobre a ocorrência dos patógenos virais e fúngicos em cultivos de abóbora e melancia situados em municípios produtores no sertão da Paraíba, amostras coletadas com sintomas de mosaico e deformação foliar, típicos de doenças virais foram analisadas pela técnica sorológica “enzime linked immuno sorbentassay” (Elisa) indireto para Papaya ring spot virus, type watermelon (PRSV-W), Watermelon mosaic virus (WMV), Zucchini yellow mosaic virus (ZYMV) e Cucumber mosaic virus (CMV). O teste de dupla difusão em Agar foi utilizado para verificar a presença de Squash mosaic virus (SqMV). Em contrapartida, amostras coletadas com sintomas de doenças fúngicas foram analisadas pelo isolamento do patógeno e visualiza', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3704', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1bb', 'Efeito de óleos essenciais e composto citronelal sobre a micoflora de sementes de feijão armazenadas', 'D. R. Brito; M. A. Ootani; R. W. S. Aguiar; G. P. S. Maciel; L. A. Lopes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Esse trabalho objetivou avaliar o efeito de óleos essenciais de Cymbopogon nardus, Eucalyptus citriodora e o composto citronelal como meios alternativos na conservação e qualidade sanitária de sementes de diferentes genótipos de feijão. Utilizou-se o delineamento inteiramente casualizado, com 200 sementes subdivididas em repetições de 50 para cada tratamento. As sementes de feijão Carioca, Caupi, Jalo e Preto, foram tratados com os referidos óleos essenciais nas doses de 5, 10, 20, 30% e Testemunha (tratadas apenas com água destilada esteril), posteriormente foram armazenadas por 15, 30, 45 e 60 dias. No final de cada período de armazenamento, foram realizados os bioensaios utilizando o método de Blotter test, para avaliação e identificação das colônias de fungos associados as sementes. os dados foram submetidos a análise de variância e as médias comparadas pelo teste de Tukey a 5% de probabilidade Os óleos utilizados se mostraram eficientes, por terem promovido o decréscimo no número ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3836', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1bd', 'Métodos de superação de dormência de sementes de Schinopsis brasiliensis', 'R. A. B. Azevedo; L. P. Barros; A. S. Souza; M. F. B. Coelho; J. W. N. Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Schinopsis brasiliensis é uma das espécies ameaçadas de extinção na Caatinga do nordeste brasileiro. Assim, objetivou-se avaliar diferentes tratamentos pré-germinativos afim de superar a dormência em  sementes de Schinopsis brasiliensis. O delineamento experimental foi inteiramente casualizado no esquema fatorial 5x2 com cinco repetições de 50 sementes. Os tratamentos consistiram em: a) escarificação com lixa metálica junto da micrópila; b) escarificação com lixa metálica do lado oposto da micrópila; c) escarificação com lixa metálica de um lado  da semente; d) escarificação com lixa metálica dos dois lados da semente e e) sem escarificação. Estes cinco níveis foram combinados com as sementes com ou sem lavagem em água. A porcentagem de emergência variou de 11,25 a 36,25%. A escarificação junto à micrópila combinada com a lavagem em agua proporcionou maior comprimento da parte aérea. A retirada do epicarpo e mesocarpo de Schinopsis brasiliensis seguida da lavagem em agua corrente por 1', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3910', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1c1', 'Álgebra de mapas aplicado na determinação das ocupações irregulares e o risco ambiental em Catolé do Rocha-PB', 'J. S. Almeida; J. C. Menezes Júnior; A. B. A. Andrade; W. F. Melo; A. W. R. Pereira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Resumo: O processo de crescimento desordenado e sem planejamento das cidades trouxe consequências desastrosas sobre o espaço urbano e a qualidade de vida da população, além de provocar profundas modificações no meio ambiente, contribuindo para geração de áreas vulneráveis. Dessa forma, o trabalho teve como objetivo avaliar o uso e ocupação do solo no meio urbano quanto a geração de riscos, adotando-se o munícipio de Catolé do Rocha-PB, como estudo de caso. Dentre os procedimentos metodológicos, partiu-se de revisão bibliográfica, consulta documental a fontes e dados oficiais, emprego de imagens de satélite, com aferição de informações em campo do uso e ocupação do solo, além de dados pluviométricos para avaliação dos territórios de risco. Constatou-se que a expansão urbana foi direcionada para área de manancial, assim como no sentido do Riacho Agon, desmatando parte da mata ciliar, contribuindo para a construção do risco. Tais problemas socioambientais só serão solucionados por intermé', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3925', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1c2', 'Estudo da viabilidade do uso de cisternas em assentamento rural no município de Várzea-PB', 'F. de A. Silva; M. T. L. Chaves; M. S. Silva; J. S. Nóbrega; R. P. Lira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A escassez hídrica é um dos grandes problemas enfrentados pelas famílias que residem no semiárido nordestino, interferindo diretamente na qualidade de vida das famílias. Diante desse contexto se faz necessário a adoção de técnicas que se constitua uma alternativa viável para a melhoria na convivência das famílias, entre elas, o uso de cisternas para a captação de água da chuva, mostra-se uma alternativa que vem ganhando destaque. Neste sentido este trabalho teve como objetivo avaliar a viabilidade do uso de cisternas na melhoria das condições de vida das famílias do assentamento Novo Horizonte, no município de Várzea – PB. A pesquisa foi realizada no assentamento rural Novo Horizonte, pertencente a zona rural do município de Várzea – PB, onde foram realizados aplicação de questionários a famílias residentes no local. Os questionários eram de natureza quantitativa, uma vez que os mesmos, foram traduzidos em números, opiniões e informações para classifica-los e analisa-los. O questionári', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3968', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1c5', 'Dosis de polvo de roca y sus efectos sobre el rendimiento del tomate', 'G. A. Bogado; O. D. Alvarez; V. R. S. Oviedo; C. R. Enciso Garay', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'La agricultura sustentable juega un rol muy importante en la producción continua de alimentos, donde se busca reducir la dependencia de fertilizantes minerales y el incremento del uso de fuentes naturales de nutrientes, con bajos impactos en el medio ambiente. Se ha evaluado el efecto de diferentes dosis de polvo de roca de origen basáltico en las características productivas del tomate cultivar Carina, a través de un experimento en el municipio de Caazapá, Departamento de Caazapá, Paraguay, en el periodo de 11/2012 a 04/2013. Los tratamientos consistieron en testigo sin fertilización, testigo experimental con fertilización química (basado en el análisis de suelo) y diferentes dosis de polvo de roca de 0,5; 0,75; 1,0; 1,25; 1,5 y 2,0 t ha-1. El diseño experimental fue de bloques completos al azar con tres repeticiones. Cada unidad experimental estuvo constituida de 24 plantas, de las cuales fueron evaluadas ocho. Las variables medidas fueron masa media de frutos, rendimiento comercial y', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3998', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1c7', 'Respostas de cultivares de girassol a doses crescentes de boro na entressafra do Cerrado Tocantinense', 'R. R. Fidelis; A. S. Dario; H. B. Barros; A. Capone; M. Z. Menegon', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No cerrado brasileiro a deficiência de boro no solo ocorre com maior frequência. A cultura do girassol é muito sensível à deficiência deste micronutriente, além de apresentar pouca eficiência em seu aproveitamento. Neste contexto, objetivou-se com este estudo avaliar as respostas de cultivares de girassol a doses crescentes de boro no período da entressafra no cerrado tocantinense. O experimento foi conduzido em Gurupi, (TO), com sistema de plantio direto em sucessão a soja, sobre Latossolo Vermelho Amarelo distrófico. O delineamento experimental utilizado foi de blocos casualizados, com quinze tratamentos e quatro repetições. Os tratamentos foram dispostos num esquema fatorial simples 3 x 5, constituído por três cultivares de girassol (variedade Br 122, híbridos Aguará 4 e Helio 863) e cinco doses de ácido bórico (0, 1, 2, 3 e 4 kg ha-1). As características avaliadas foram: altura de planta, diâmetro da haste, diâmetro do capítulo, concentração de boro foliar, massa de mil aquênios e ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4004', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1cc', 'Seleção de cultivares de cana-de-açúcar para a Zona da Mata Norte de Pernambuco II: Meio de safra', 'G. Q. Bastos; L. S. Souto; D. E. Simões Neto; A. C. Medeiros; J. A. Dutra Filho; A. P. C. Albuquerque', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Sendo os cultivares melhorados a base de sustentação e desenvolvimento do setor sucroeneregético no Brasil, objetivou-se com este trabalho avaliar o desempenho agroindustrial de 26 cultivares de cana-de-açúcar na microrregião canavieira da Mata Norte de Pernambuco. O experimento foi conduzido na área agrícola da Usina Olho D’água, onde foi utilizado o delineamento experimental em blocos casualizados com quatro repetições. As variáveis analisadas foram: toneladas de pol por hectare, toneladas de cana por hectare, fibra, pol % corrigida, pureza, teor de sólidos solúveis e açúcar total recuperável. Realizou-se a análise de variância conjunta dos experimentos e estimativa de parâmetros genéticos, as médias foram agrupadas pelo teste de Scott e Knott ao nível de 5% de probabilidade. Realizou-se ainda a rentabilidade econômica bruta de cada cultivar.  Constatou-se que a seleção de cultivares superiores deve ser baseada nas variáveis TPH e TCH. Como opções de cultivo comercial para a segunda ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4263', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1ce', 'Influência da concentração de proteína, da força iónica e o tipo de hidrato de carbono na formação de complexos tanino-proteína', 'F. C. Sousa; A. dos S. Araújo; M. E. M. Duarte; A. L. Pinto; A. P. S. Nascimento', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os taninos são compostos naturais que têm a propriedade de complexarem com as proteínas formando agregados insolúveis em solução. A interação destes compostos com as proteínas salivares leva à sensação de adstringência de alguns frutos (especialmente se pouco maduros) e bebidas como o vinho tinto e o chá. No presente estudo pretende-se verificar de que forma a concentração de protéina e tanino, as suas estruturas, hidratos de carbono e ainda a  força iónica, podem influênciar a formação de complexos tanino-proteina. Verificou-se que menores concentrações de proteína no meio vão provocar um aumento da adstringência. A estrutura da proteína também irá influência a formação de complexos tanino-proteína, o aumento da força iónica irá provocar uma diminuição da formação de complexos tanino-proteína, hidratos de carbono com uma estrutura não capsolante em elevadas concentrações irão provocar uma aumento da adstringência, ao contrário de hidratos de carbono com uma estrutura capsolante.Influe', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4446', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1cf', 'Levantamento fitossociológico de plantas daninhas na cultura da cenoura em monocultivo e consorciada com rabanete', 'A. F. Mendonça Júnior; V. F. S. de Paula; J. A. M. Araújo; E. M. Costa; A. P. M. S. Rodrigues', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O experimento foi conduzido na horta da Universidade Federal Rural do Semi-Árido (UFERSA), no período de setembro a dezembro de 2009, com o objetivo de realizar o levantamento fitossociológico nos seguintes tratamentos: sistema de monocultivo da cenoura (Daucus carota) e sistema de cultivo da cenoura consorciada com rabanete (Raphanus sativus). Para cada sistema de plantio foram realizadas 24 amostragens em quadrados vazados de 0,50 m de lado, onde as plantas daninhas foram coletadas e separadas por espécie, para determinação das seguintes características: número total de indivíduos por espécie, número total de parcelas que contém a espécie, freqüência, freqüência relativa, densidade, densidade relativa, abundância, abundância relativa, massa seca, massa seca relativa, índice de valor de importância (IVI), e o índice de valor de importância incluindo a massa seca (IVI-MS). Foram identificadas 19 espécies, distribuídas em 12 famílias botânicas. A família mais representativa foi a Poacea', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4450', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d4', 'Cinética de crescimento de levedura em mosto de cagaita para produção de bebida fermentada', 'Mara Elisa Soares de Oliveira; Clovis Maurilio de Souza; Alex Sander Rodrigues Cangussu; Ismael de Oliveira Pinto; Ana Cláudia Alencar Lopes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Resumo: Objetivo deste trabalho foi realizar o estudo inicial da cinética de crescimento de levedura para servir como base para futuros estudos visando determinar a potencialidade do mosto de cagaita como fonte de substrato na fermentação alcoólica de S. cerevisiae visando a produção de bebida fermentada. Os frutos foram coletados na região sul do estado de Tocantins e após clarificação foi realizado a inoculação com concentração inicial de 1,8 x 103 Células por ml. Os parâmetros analisados foram, pH, teor de sólidos solúveis e densidade ótica a 550nm e taxa de crescimento celular. Como resultados observamos que o TSS inicial apresenta valor bem acima do encontrado em outras frutas como cajá, melancia e caju, os valores de pH inicial do mosto encontra-se abaixo da maioria dos dados da literatura e abaixo do considerado ideal para o crescimento de leveduras e ainda que a velocidade de crescimento abaixo da maioria dos dados disponíveis na literatura são possivelmente decorrentes de fato', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2975', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d5', 'Ação de bioestimulantes no desempenho do cultivo de soja em duas condições de adubação fosfatada', 'Eduardo Assunção Ferreira; Valdere Martins dos Santos; Átila Reis da Silva; Dione Pereira Cardoso; Daniele de Cássia Vieira de Sousa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou avaliar a ação de bioestimulantes sobre características agronômicas e produtividade para a cultura da soja, em condições de baixa e alta dose de fósforo. O delineamento experimental utilizado foi o de blocos casualizados, com quatro repetições, sendo três bioestimulantes e uma testemunha. As características avaliadas foram às características agronômicas (AP = altura de planta; AIV = altura de inserção da 1a vagem; NVP = número de vagem por planta; NSP = número de sementes por plantas; e PCS = pesos de cem sementes) e a produtividade (PROD). Os ambientes com altas doses de fósforo proporcionaram os maiores valores de AP (70,3 cm), NVP (138,8), NSP (301,5) e PROD (2868,76 kg ha-1). Quanto às características AIV e PCS, no ambiente com alta dose de fósforo, não houve diferença estatística entre os tratamentos. Os melhores valores de AP, NVP e NSP são obtidos nos tratamentos T11 e T12, enquanto para PROD, no T13, em ambos os tratamentos destaca-se o bioestimulante, BU-EC. A alta d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3323', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d9', 'Variação Pluviométrica e Parâmetros Físico-químicos da Água Tratada para Distribuição em Porto Velho, Rondônia', 'Márcia Bay', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O regime pluviométrico do município de Porto Velho capital de Rondônia (Amazônia brasileira) é bastante regular, variando apenas nos três meses mais secos de cada ano (Aw na classificação de Köppen). A qualidade da água neste município é atualmente um fator preocupante, tendo em vista o rápido crescimento demográfico ocorrido nos últimos quatro anos. Este fato se deve aos investimentos federais em um grande complexo hidrelétrico construído no Rio Madeira em Porto Velho (Usinas de Jirau e Santo Antônio). Quanto maior o consumo de água, maior a quantidade de água a ser tratada para a distribuição. A adição de produtos químicos como sulfato de alumínio (Al2 (SO4)3) e cloro (Cl2) para o tratamento da água é feita com base em normas técnicas e a quantidade dos mesmos varia de acordo com o período do ano e o regime pluviométrico local. A variação da quantidade de chuva pode interferir nos valores de parâmetros básicos como pH, Turbidez e Cloro residual da água, sendo a proposta deste trabalh', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3445', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1da', 'Análises dos principais sais presentes nas águas de poços tubulares em duas comunidades rurais do município de Pombal-PB', 'Patrício Borges Maracajá; Diego Lima Crispim; Alan Dél Carlos Gomes Chaves; Ricardo Ricelli Pereira de Almeida; Augusto César Trigueiro Félix', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'RESUMO – O uso de água subterrânea captada de poços tubulares para suprir a demanda desse insumo no processo de irrigação para produção de hortaliças nas comunidades de Várzea Comprida dos Oliveiras e Bezerro, vem ocorrendo de forma sistemática pelos agricultores que vivem e trabalham nas suas pequenas propriedades rurais. A água subterrânea é uma reserva estratégica cada vez mais usada devido à escassez hídrica enfrentada pela nossa região nos últimos anos.  A pesquisa foi desenvolvida em 2 etapas, sendo a primeira delas o reconhecimento da área de estudo através de visitas in loco nas propriedades dos produtores, na qual foi realizado o levantamento quantitativo dos poços artesianos existentes na comunidade Várzea Comprida dos Oliveiras e na comunidade Bezerro, onde verificou-se um total de 18 (dezoito) poços tubulares, na qual a primeira consta com 11 (onze) poços e a outra com 07 (sete), além da análise da água do rio Piranhas que margeia as duas comunidades. Na segunda etapa foram', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3498', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1de', 'Mirmecofauna em agroecossistemas e sua função na transição agroecológica.', 'Marcelo Nivert Schlindwein; Fernando Silveira Franco; Cícero Santos Branco; Eliana Cardoso Leite; Daniel Mendes Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A diversificação da propriedade agrícola e o uso de sistemas agroflorestais trazem diversos benefícios para o agroecossistema, pela consequente atração de inimigos naturais e redução de insetos herbívoros. As formigas constituem um grupo importante de insetos em agroecossistemas. O objetivo com esse trabalho foi analisar a ocorrência de diferentes guildas de formigas em três estratégias de restauração florestal comparadas com uma floresta em estágio avançado de sucessão em um sistema agrícola. Para este fim foram realizadas coletas mensais de formigas durante os meses de fevereiro a julho de 2013 em uma propriedade agrícola, em diferentes áreas de ambientes florestais e agroflorestais. Observou-se com este experimento que as formigas predadoras ocorrem mais frequentemente em áreas com vegetação em estágio sucessional avançado, e que formigas cortadeiras ocorrem mais frequentemente em ambientes de vegetação em estágio inicial de sucessão.Ant fauna in agroecosystems and their role in agr', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3161', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e7', 'Crescimento inicial da berinjeleira sob adubação nitrogenada e fosfatada e irrigada com água de reúso', 'Whalamys Lourenço de Araújo; Manoel Moises Ferreira de Queiroz; Aldair de Souza Medeiros; Reginaldo Gomes Nobre; Eliane da Silva Ferreira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A utilização da água vem gerando alguns conflitos devido o aumento da escassez hídrica em todo o mundo, os setores de maior consumo são a agricultura responde por 70%, o setor industrial 22% e 8% corresponde ao uso doméstico. Objetivou-se com este trabalho avaliar os efeitos causados pelas doses de nitrogênio e fósforo e a irrigação com água de reúso doméstica pós-tratada em filtro de areia com fluxo intermitente durante o crescimento inicial da berinjeleira na região semiárida paraibana. O experimento foi realizado em ambiente protegido, no Centro de Ciências e Tecnologia Agroalimentar (CCTA/UFCG), Campus de Pombal – PB, e cujos tratamentos resultaram na combinação de dois fatores: quatro doses de adubação nitrogenada (N1 - 3,55; N2 - 6,2; N3 - 8,9; N4 - 11,55 g de N/vaso) e quatro doses de adubação fosfatada (P1 - 15,28; P2 - 26,74; P3 - 38,2; P4 - 49,66 g de P/vaso) correspondendo respectivamente a 40; 70; 100; 130% conforme indicação de adubação para a cultura da berinjela quando c', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3656', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1ea', 'Fenologia de uma espécie arbórea em ecótono Caatinga / Cerrado no sul do Piauí', 'Alan Cauê Holanda; Waldeídes Castro Sousa; Rejane Tavares Botrel; Anderson Marcos Souza; Danúbia Rejane Silva Brito', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi caracterizar a fenologia de uma população natural de Terminalia fagifolia Mart, localizada em ecótono entre os Biomas Cerrado e Caatinga, no município de Bom Jesus, sul do Estado do Piauí. Vinte indivíduos, com distância mínima de 20 metros entre si, foram marcados, utilizando GPS. Os dados fenológicos foram coletados durante um ano e as fenofases observadas foram brotação, desfolhamento, floração e frutificação. Para análise dos dados foram utilizados índices de atividade, intensidade e sincronia, além da correlação de Spearman que avaliou dados fenológicos em conjunto com variáveis ambientais. A análise fenológica indicou presença de todas as fenofases durante o período de estudos, sendo o desfolhamento observado continuamente, variando apenas em seu grau de intensidade. A população estudada apresentou sincronia perfeita entre os indivíduos nas fenofases desfolhamento e brotação. Quanto à correlação de Spearman, os resultados não indicaram correlações si', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3587', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1ef', 'Resposta funcional e capacidade predatória da fase larval de Ceraeochrysa caligata alimentada com Brevicoryne Brassicae', 'Pedro Paulo da Costa Alves Filho; Antônio Vinicius Corrêa Barbosa; Jessivaldo Rodrigues Galvão; Wilson José de Melo e Silva Maia; Joel Correa Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O pulgão, Brevicoryne brassicae (L.), é uma das principais pragas da cultura da couve. A necessidade de controle de insetos-pragas de forma racional e sustentável tem gerado a busca de medidas efetivas de controle. Objetivou-se estudar a capacidade predatória e a resposta funcional da fase jovem de Ceraeochrysa caligata (Banks) alimentada com o pulgão Brevicoryne Brassicae (L.), usando ninfas de segundo e terceiro instares. Foram utilizadas cinco densidades de presas, com cinco repetições com dois indivíduos por repetição. O Consumo aumentou proporcionalmente em função do estádio de desenvolvimento da larva, sendo significativamente maior no terceiro instar, representando acima de 75% do total. Os consumos médios diário e totais foram de 4,2 e 25,6; 10,2 e 70,2; 38,6 e 549,0 pulgões, para os três instares, respectivamente. Observou para a fase larval 23,4 e 644,8 pulgões. Constatou se duração média de 5,8; 6,7; 13,5 e de 26,0 dias para o primeiro, segundo e terceiro instares e fase lar', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3308', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f1', 'Variabilidade genética e coeficiente de determinação em genótipos de algodoeiro quanto a qualidade da fibra', 'F. M. Mundim; L. B. Sousa; D. O. C. Bonifácio', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O algodão é a mais importante fibra têxtil do mundo e a sua qualidade é o que garante o retorno investido pelo produtor. O trabalho teve como objetivo avaliar a variabilidade genética entre 22 genótipos de algodoeiro de fibra branca do Programa de Melhoramento Genético do Algodoeiro, da Universidade Federal de Uberlândia, quanto a qualidade da fibra e determinar o coeficiente de determinação genotípico dos caracteres. O experimento foi realizado na fazenda Capim Branco, em Uberlândia-MG, na safra 2012/2013. O delineamento experimental foi de blocos casualizados com três repetições. Avaliou-se 20 genótipos de algodoeiro. Com o auxílio do aparelho High Volume Instrument, determinou-se o índice de consistência a fiação, índice micronaire, maturidade da fibra, comprimento da fibra, uniformidade de comprimento, índice de fibras curtas, resistência, alongamento, reflectância e grau de amarelecimento. As linhagens do Programa de Melhoramento genético do Algodoeiro da Universidade Federal de U', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3618', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f4', 'Os impactos da tecnologia de mulching utilizada no cultivo do melão na região de Mossoró', 'M. L. R. Sousa; G. M. T. Queiroga; J. K. Silva; E. S. Siqueira; D. N. J. Rodrigues', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A tecnologia de mulching é uma ferramenta que possibilita a redução de gastos para os produtores no tocante a utilização de agroquímicos, água de irrigação e a utilização de mão-de-obra, além de promover melhoria na qualidade da fruta produzida e o aumento da produção. O presente trabalho objetivou avaliar os impactos provocados pelo uso do mulch no meio ambiental, social e econômico de uma comunidade rural de Mossoró/RN. Fez-se o uso de observações, entrevista semiestruturada e questionário estruturado, o qual foi aplicado a 12,5% dos participantes de um total de 32. Os resultados mostram que essa tecnologia é utilizada por todos os produtores, com o intuito de melhorar a produção do melão em quantidade e qualidade.  Contudo, o uso do mulch de polietileno, utilizado nessa técnica, acarreta preocupações quanto ao seu descarte pós-uso, com a utilização de práticas arcaicas como as queimadas que afetam de forma gradual a saúde do trabalhador e as propriedades biológicas do solo.The impac', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3397', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f5', 'Efeito da substância húmica na germinação de sementes de Myracrodruon urundeuva Fr. All.', 'L. M. Oliveira; A. C. M. Santos; A. R. Mota; P. B. de Souza; R. J. da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'AAs substâncias húmicas originam-se da oxidação e polimerização da matéria orgânica, apresentando elevadas massas moleculares e variados grupos funcionais. Dependendo da solubilidade em meio aquoso, as substâncias húmicas são divididas em ácido húmico, ácido fúlvico e humina. São poucas pesquisas relacionadas aos efeitos das substâncias húmicas na germinação de sementes, e não foram encontrados trabalhos utilizando a espécie Myracrodruon urundeuva Fr. All. A composição das substâncias húmicas é variada, isso dificulta o entendimento de seu efeito. O objetivo da pesquisa foi analisar o efeito de diferentes concentrações de substâncias húmicas na germinação de sementes de Myracrodruon urundeuva Fr. All. O trabalho foi desenvolvido no laboratório de sementes da Universidade Federal do Tocantins, no qual as sementes ficaram imergidas por 12 horas em solução contendo concentrações de 0,00; 0,25; 0,50; 0,75 e 1,00% de substância húmica, posteriormente foram colocadas para germinar em B.O.D r', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3491', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f6', 'Variabilidade espacial das características qualitativas e quantitativas da pastagem de capim Marandú em topossequência no Tocantins', 'S. P. Silva Neto; J. S. Lima; L. B. T. Oliveira; A. C. Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho avaliar a variabilidade espacial das características produtivas do pasto de Brachiária brizantha cv. Marandu em vertente, em função da fertilidade do solo. O experimento foi conduzido na fazenda da Escola de Medicina Veterinária e Zootecnia da Universidade Federal do Tocantins. Para a caracterização química do solo foi realizada amostragem em pontos da área onde a malha regular possui uma distância média de 2 m de um ponto a outro longitudinalmente e doze metros perpendicularmente, perfazendo um total de 160 pontos. A forrageira também foi coletada seguindo malha regular, porém, com distância média de quatro metros longitudinalmente e 12 m perpendicularmente, totalizando 80 amostras. As análises realizadas foram às seguintes: pH (CaCl2); (matéria orgânica, fósforo disponível (P) e potássio trocável (K+); cálcio trocável (Ca2+), magnésio trocável (Mg2+) e alumínio trocável (Al3+). Os dados de forragem e de solo foram submetidos à estatística descritiva e a', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3510', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f7', 'Crescimento inicial de ervilha sob diferentes níveis de compactação em dois tipos de solos', 'P. C. Hilst; A. C. B. Matos; H. S. Silva; A. L. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O manejo do solo pode alterar as propriedades físicas do solo, sendo de grande importância para garantir o estabelecimento de plântulas e produtividade. A inovação de implementos e máquinas agrícolas e excesso de tratos culturais durante o manejo são os principais fatores que interferem nestas características. Assim, objetivou-se avaliar o efeito da compactação de solos com diferentes classes texturais (argilosa e muito argilosa) no crescimento inicial de ervilha. O experimento foi montado em casa de vegetação com sementes de ervilha Itapuã 600. Cada tratamento contou com 4 repetições de 50 sementes em diferentes graus de compactação dos solos, com aplicações três cargas sobre os solos que resultaram em: argiloso: controle: 0,21, T1: 0,26, T2: 0,28 e T3: 0,33 MPa, textura muito argilosa: controle: 0,40, T1: 0,42, T2: 0,46 e T3: 0,53 MPa. Foram avaliados a porcentagem de emergência, IVE, VE, comprimento de parte aérea e raiz, massa seca de parte aérea, raiz e massa seca total. Para as d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3412', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f9', 'Estudo da cinética de secagem em camada delgada da bráctea da macambira', 'T. R. B. Pessoa; P. C. Martins; Â. A. El-Aouar; J. V. F. Portela', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A macambira é uma bromélia do sertão brasileiro e a sua principal utilização para consumo de suas brácteas é na forma de produtos secos, tais como a farinha. O objetivo deste trabalho foi estudar o processo de secagem em camada delgada da bráctea da macambira (Bromelia laciniosa, Mart.) in natura a diferentes temperaturas. A secagem convectiva foi realizada a 43, 49 e 56 °C em condições constantes de velocidade e umidade absoluta do ar. Foi utilizado um secador de leito fixo com escoamento de ar perpendicular as partículas, cujos ensaios de secagem foram conduzidos até que as amostras alcançassem massa constante. A cinética de secagem foi avaliada através das curvas experimentais de secagem. A difusividade efetiva média de umidade foi determinada através de correlações empíricas e da solução do modelo de Fick para a difusão de água líquida. O aumento da temperatura do ar de secagem provocou o aumento da taxa de secagem e a diminuição do conteúdo de umidade das amostras ao longo de toda', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3367', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1fe', 'Aspectos germinativos de cultivares de girassol armazenadas submetidos a estresse térmico', 'Renato Costa Nunes Leandro; Alexandre Bosco de Oliveira; Tatiana Maria da Silva; André Luís da Silva Parente Nogueira; Maria Neurilan Costa Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar a germinação de sementes de diferentes cultivares de girassol armazenadas sob condições de estresse térmico. O trabalho foi desenvolvido no Laboratório de Análise de Sementes do Departamento de Fitotecnia da Universidade Federal do Ceará (UFC), em Fortaleza - CE. Para a avaliação da influência da temperatura o experimento foi disposto em delineamento inteiramente casualizado em esquema fatorial (20 x 5), sendo vinte cultivares de girassol e cinco regimes de temperaturas (25,0; 27,5; 30,0; 32,5 e 35,0º C) e, respectivamente, conduzido quatro repetições. Foram avaliadas as seguintes variáveis: média da matéria fresca por plântula; média da matéria seca por plântula tempo médio de germinação; índice de velocidade de germinação; porcentagem de germinação. Os resultados foram comparados entre si pelo teste de Skott-Knott a 5% de probabilidade. A avaliação de estresse térmico promovido nas sementes de girassol, permitiram discriminar o híbrido Olissun como o que apresent', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3315', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a201', 'Componentes de produção de genótipos de feijão-caupi irrigados com água salina', 'K. Q. D. Brito; R. do Nascimento; G. J. Dantas Junior; J. E. A. Santos; I. A. C. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O feijão-caupi (Vigna unguiculata L. Walp), é uma leguminosa herbácea, considerada principal fonte protéica vegetal para famílias de baixa renda no Brasil. Cultivado em regiões de clima quente úmido e semiárido, torna-se uma opção para a região nordeste, uma vez que pode servir como alternativa de fonte de renda aos pequenos e médios produtores. Nesse sentido, objetivou-se avaliar as características produtivas de genótipos de feijão-caupi irrigados com água salina. Os tratamentos consistiam da combinação de dois fatores: Salinidade da água de irrigação (A1 - água de abastecimento com 0,8dSm-1 e  A2 - solução salina 4,8 dSm-1) e Genótipos de feijão-caupi (G1 - MNC04-762F-9, G2 - MNC04-762F-3, G3 - MNC04-762F-21, G4 - MNC04-769F-62 e G5 - MNC04-765F-153). Combinados os fatores, no delineamento inteiramente casualizado, resultaram em 10 tratamentos (2 níveis de salinidade x 5 genótipos), com 4 repetições. A irrigação com água salina se deu aos 12 DAS. As variáveis analisadas foram o númer', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3620', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a202', 'Crescimento do algodoeiro colorido pós-poda em solos com distintas PSTs e doses de esterco', 'J. J. Elias; L. L. S. Almeida; L. P. Souza; J. L. Barbosa; R. G. Nobre', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A pesquisa foi conduzida em ambiente protegido no CCTA/UFCG onde objetivou-se avaliar o crescimento de plantas de algodoeiro de fibra naturalmente colorida cv. BRS Topázio, no segundo ciclo produtivo pós-poda, em solos salino-sódico sob esterco bovino. Usou-se o delineamento de blocos casualizados em esquema fatorial 5 x 4, com 3 repetições, cujos tratamentos consistiram de cinco percentagens de sódio trocável - PST (13,6; 22,4; 30,1; 39,0 e 48,0%) e quatro doses de esterco bovino (0; 5; 10 e 15%). Ao encerrar a produção das plantas de algodoeiro (primeiro ciclo) realizou-se uma poda drástica, onde, após as brotações (segundo ciclo) avaliaram-se aos 51 e 91 dias após a poda (DAP) as variáveis: comprimento do ramo (CR), diâmetro do ramo (DR), diâmetro do caule (DC) e número de folhas (NF). Doses de 10% de matéria orgânica favoreceu o comprimento do ramo e, de 15% o diâmetro do ramo e do caule de plantas de algodoeiro cv. BRS Topázio aos 51 e 91 dias após a poda. Percentagens de sódio tr', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3715', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a203', 'Efeito da salinidade na germinação e desenvolvimento inicial da mamona ‘BRS energia’', 'G. J. Dantas Junior; K. Q. D. Brito; F. G. Souza; K. S. A. Brito', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A mamoneira possui destacável importância no mundo, tem como principal produto derivado do seu óleo que pode ser utilizado como matéria prima para o biodiesel. Objetivou-se com este trabalho avaliar os níveis de tolerância das sementes de mamona ao estresse salino simulados por NaCl. A pesquisa foi desenvolvida no Laboratório de Irrigação e Salinidade na Universidade Federal de Campina Grande. Em cada tratamento foram utilizadas 100 sementes, dispostas em quatro repetições de 25 sementes. O delineamento experimental utilizado foi o inteiramente casualizado. Para a avaliação da germinação sob estresse salino utilizou-se soluções de NaCl com as seguintes condutividade elétrica: 0,4; 1,2; 2,2; 3,2 e 4,2dSm-1. Realizou-se avaliações de porcentagem de germinação, tempo médio de germinação, velocidade média de germinação, índice de velocidade de germinação e aos 15 dias realizaram o comprimento da raiz primaria, da parte aérea, e pesou a massa seca e fresca das plântulas. As sementes de mamo', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3344', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a205', 'Primeiro ciclo de seleção massal na população PM3 de melão (Cucumis melo L)', 'J. Silva; I. D. E. de Carvalho; F. S. Oliveira; L. S. Medeiros; P. V. Ferreira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho realizar o primeiro ciclo de seleção massal na população PM3 de melão. Foi usada a população PM3 de melão, obtida pelo Setor de Melhoramento Genético de Plantas do Centro de Ciências Agrárias da Universidade Federal de Alagoas (SMGP/CECA/UFAL). A colheita foi realizada aos 75 dias após a semeadura. Os frutos foram colhidos totalizaram 1188 frutos, os quais foram analisados a morfologia externa, objetivando a formação de classes fenotípicas em função dos caracteres qualitativos, culminando na obtenção de 40 classes fenotípicas. A classe fenotípica CF 17 foi selecionada por apresentar cor do fruto amarelo, ausência de costelas, ausência de rendilhamento, cor da polpa salmão e formato do fruto arredondado a ovalado. Em seguida foi feita uma seleção dos frutos de melão para os seguintes caracteres quantitativos dentro da classe fenotípica selecionada: peso do fruto acima de 740,0 gramas; diâmetro longitudinal acima de 11,0 cm; diâmetro transversal acima de 10', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3473', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a206', 'Influência do NaClO na germinação de sementes de alface em Parnaíba-PI', 'M. C. S. Alves; M. S. Teodoro; M. N. Lacerda; L. M. S. Araújo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho foi desenvolvido em condições de casa de vegetação situada em Parnaíba-PI, município onde predominam altas temperaturas. Objetivou-se avaliar a germinação de diferentes lotes de sementes de alface antes e após a embebição em solução de hipoclorito de sódio (NaCIO). O delineamento experimental foi em blocos casualisados, com os tratamentos dispostos em arranjo fatorial 2 x 7 (duas variáveis como pré-germinativos: com imersão em NaClO e sem imersão em NaClO, e sete cultivares de alface), com quatro repetições. As variáveis analisadas foram: Primeira contagem do teste de germinação (PCG), Teste de germinação (TG) e Índice de velocidade de germinação (IVG). Analisando-se os dados obtidos, verificou-se que independente da presença ou ausência do tratamento pré-germinativo, a cultivar T6 foi a que apresentou os melhores resultados para as variáveis analisadas. Exceto T2, todas as outras cultivares que receberam tratamento com hipoclorito de sódio (NaClO) obtiveram resulta', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3405', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a209', 'Utilização de diferentes substratos na propagação de Pyrostegia venusta através de estacas', 'E. R. Rêgo; Â. M. S. Pessoa; J. G. Crispim; M. M. Rêgo; P. A. Barroso', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho teve por objetivo avaliar o desenvolvimento de clones de Pyrostegia venusta em diferentes tipos de substratos. O experimento foi conduzido em delineamento inteiramente casualizado, com 06 tratamentos e 10 repetições, cada repetição foi constituída por um tubete de polietileno com capacidade de 103cm3. Os tratamentos testados foram: (T1) 100% de areia lavada; (T2) 50% areia lavada + 50% substrato comercial Plantmax®; (T3) 100% de substrato comercial Plantmax®; (T4) 50% areia lavada + 50% de esterco bovino; (T5) 1/3 areia lavada + 1/3 esterco bovino +1/3 de Plantmax® e (T6) 50% esterco bovino + 50% de Areia lavada. Após 30 dias foram avaliados o número de estacas sobreviventes, comprimento do broto (cm), número de folhas, comprimento da folha (cm), número de raízes e comprimento da raiz principal (cm).  Os dados foram submetidos a análise de variância e as médias comparadas pelo teste de Tukey a 5% de probabilidade. Por meio da análise de variância (p<0,01), detectou-se sig', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3375', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a20a', 'Avaliação do efeito de borda da Reserva Biológica de Pindorama, SP', 'A. S. Ferraudo; S. V. Valeri; M. T. V. N. Abdo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Caracterizou dois fragmentos de floresta estacional semidecidual da Reserva Biológica de Pindorama, SP. Em 65 parcelas de 400 m2 avaliou-se: grau de infestação na parcela, distância da borda, altura, área basal e grau de infestação das quatro maiores árvores e num quadrante sorteado avaliou-se solo, a altitude, o número de espécies, o número, a área basal e a altura de todos indivíduos arbóreos com diâmetro a altura do peito (DAP) ≥ a 5 cm e a fitossociologia. O agrupamento hierárquico dividiu as parcelas em dois grupos onde determinou-se valores médios das variáveis, Índices de diversidade de espécies (H’) e Coeficiente de equabilidade (J) e a similaridade entre os grupos com o Índice de similaridade de Jaccard (ISJ). O agrupamento hierárquico, k-médias e componentes principais caracterizaram grupos de parcelas semelhantes e as variáveis com maior poder de discriminação foram: altura das quatro maiores árvores, número de indivíduos por parcelas, área basal total, infestação por parcel', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3398', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a20b', 'Parâmetros físico-químicos de polpas de fruta produzidas na cidade de Petrolina – PE', 'I. R. B. Carvalho; K. S. M. Sousa; A. C. Honorato; C. B. R. Dias; E. B. Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo avaliar os parâmetros físico-químicos de polpas de fruta produzidas e comercializadas na cidade de Petrolina-PE, tendo como referência a Instrução Normativa nº 1, de 7 jan. 2000, do Ministério da Agricultura que define as características físicas e químicas estabelecendo limites mínimos e máximos específicos para cada polpa de fruta. Foram avaliadas duas marcas (1 e 2) de polpas de abacaxi, cacau, caju, graviola, maracujá e umbu, analisadas quanto aos parâmetros de pH, sólidos solúveis totais (SST), acidez total titulável (ATT), ácido ascórbico, relação SST/ATT e sólidos totais. Os resultados permitem inferir que a marca 2 apresentou qualidade superior na maioria dos parâmetros avaliados quando comparado com a marca 1. Entretanto para alguns sabores de polpa as duas marcas não atenderam os valores padrões. Entre as polpas o único sabor que apresentou os padrões exigidos foi a polpa de caju em ambas as marcas, e a que apresentou resultado de pior qualidad', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3415', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a20c', 'Análise sensorial e desenvolvimento de embalagem para aguardente de algaroba', 'R. M. Feitosa; M. E. R. M. C. Mata; M. E. M. Duarte; V. B. Holanda; A. D. F. Lins', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com esse estudo realizar análise sensorial da aguardente de algaroba, desenvolver uma embalagem para sua comercialização e verificar a preferência de embalagem pelo seu aspecto visual. De acordo com a análise sensorial através do teste afetivo com 30 voluntários, detectou-se que quanto ao sabor não houve diferença para os avaliadores e a embalagem de vidro teve uma maior aceitação quanto à preferência em razão de conservar melhor as qualidades organolépticas da bebida que a embalagem PET, sendo este, portanto, o melhor material para o acondicionamento da aguardente. Para o processo de criação da embalagem fez-se uma pesquisa de campo, geração de conceitos e posteriormente uma análise de preferência visual dos conceitos, sendo o conceito 1 o  escolhido para a embalagem da aguardente de algaroba , e a embalagem que confere maior requinte com formas arredondadas que remetem à vagem da algaroba, apresentou uma diferença de apenas 3,1% de preferência.Sensory analysis and packag', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3496', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a20d', 'Cisternas de produção para melhoria da qualidade de vida no Semiárido do estado de Pernambuco', 'N. B. Cavalcanti; F. C. Rolim Neto; L. T. L. Brito; E. P. Ferreira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O Semiárido brasileiro requer uma particular atenção, dada à irregularidade das precipitações pluviométricas que ocorrem na região. A cisterna tipo calçadão do programa Uma Terra e Duas Águas – P1+2 assegura melhoria na dieta alimentar das famílias rurais, por permitir a inserção de frutas e hortaliças na alimentação. Com o presente trabalho objetivou-se realizar um levantamento da situação atual do uso das cisternas de produção e suas reais contribuições na melhoria da qualidade de vida de famílias rurais na microrregião do Vale do São Francisco, no Estado de Pernambuco. Foi realizada uma pesquisa exploratória e qualitativa no campo, com comunidades localizadas nos municípios de Petrolina, Afrânio e Dormentes. Pôde-se concluir que a implantação das cisternas do P1+2, tem se constituído em importante instrumento para melhoria da dieta alimentar das famílias, todavia, há necessidade de melhor acompanhamento técnico quanto ao uso racional e eficiente da água da cisterna.Production cister', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3613', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a20f', 'Produção de sorvetes e iogurtes a partir dos frutos figo da índia e mandacaru', 'L. A. Silva; J. P. Gomes; V. R. L. Fidelis; E. M. Pereira; W. P. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O figo da índia é a fruta que juntamente com o mandacaru fazem parte das espécies nativas da caatinga. Objetivou-se neste trabalho elaborar e caracterizar sorvetes e iogurte a partir do figo da índia e da polpa e casa do fruto do mandacaru. Foi obtido o sorvete de creme e iogurte natural para base e acrescido com polpa e casca para as formulações. Para a caracterização foram realizadas as análises físico-químicas de pH, vitamina C, sólidos solúveis (SS) e a acidez titulável (AT). O sorvete e o iogurte apresentaram comportamento ácido. O figo da índia e o fruto do mandacaru mostraram-se com grande potencial para o desenvolvimento de subprodutos com o sorvete e iogurte. Os valores de AT do iogurte (ᴓ 0,62) estão dentro dos padrões pré-estabelecidos.Production of ice cream and yoghurt from the cactus pearfruit and mandacaruAbstract: The Opuntia is a fruit, which together with the Cereus jamacaru are native species of the savanna. The objective of this study was to prepare and characterize', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3698', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a210', 'Estudo do potencial hidrogeniônico e das condições físicas dos clubes de Pombal - PB', 'G. A. S. Lima; A. M. B. M. Oliveira; L. F. O. Coelho; C. E. P. Morais', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As piscinas são um conjunto de estruturas artificiais que levam ao ser humano um contato direto com a água através de atividades aquáticas, como a natação. A qualidade da água das piscinas, assim como a estrutura física onde ela se comporta, são fatores de fundamental importância e por isso devem ser estudados, na busca de se obter uma melhor funcionalidade deste ambiente, bem como garantir a saúde dos usuários. A utilização deste recurso tem sido realizada de forma livre sem uma fiscalização adequada, trazendo consequências, como a proliferação de bactérias e/ou transmissão de outras doenças. Por estes motivos torna-se relevante o presente estudo, que teve como objetivo principal a análise de água e estrutura física das piscinas dos clubes públicos de Pombal-PB localizada na mesorregião do sertão paraibano.Study of the hidrgeniônico potential and physical conditions of the clubs of Pombal - PB Abstract: The pools are a set of artificial structures that lead to human being a direct con', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3734', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a21b', 'Desempenho fisiológico de sementes de algodão cultivadas em Luís Eduardo Magalhães, Bahia', 'T. R. Prado; O. M. Morais; W. S. Vale; R. T. C. Nunes; E. B. Ribeiro', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho foi desenvolvido no laboratório de tecnologia de sementes da Universidade Estadual do Sudoeste da Bahia, Campus de Vitória da Conquista UESB, com objetivo de avaliar a qualidade fisiológica de sementes de algodão (Gossypium hirsutum L.), utilizando-se cinco cultivares (DP 604, FM 993, BRS 368, TMG 642 e DELTA OPAL). As sementes foram submetidas aos seguintes testes: teor de água, peso de mil sementes, germinação, primeira contagem de germinação, índice de velocidade de emergência, emergência, comprimento da parte aérea, massa seca das plântulas e condutividade elétrica. O delineamento experimental utilizado foi o inteiramente casualizado, em quatro repetições de 50 sementes por tratamento. A cultivar TMG 642 demonstrou baixa qualidade fisiológica das sementes, quando comparados com as cultivares DP 604, FM 993, BRS 368, e DELTA OPAL. Os testes de germinação, condutividade elétrica e índice de velocidade de germinação mostraram eficiência na separação de cultivares d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3549', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a21e', 'Análise do regime hídrico de Patos-PB por meio do Índice de Anomalia de Chuvas (IAC)', 'E. F. Moura; M. C. Medeiros; M. F. A. Alves; D. L. Crispim; G. A. Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A seca é um fenômeno natural que o ser humano não consegue impedir que ocorra. Nesse sentido, a presente pesquisa tem por objetivo, analisar o comportamento do regime hídrico do município de Patos interior da Paraíba, no período de 1994 a 2009 utilizando o IAC. Para o desenvolvimento da pesquisa, realizou-se um levantamento pluviométrico de 15 anos obtidos no site da Agência Executiva de Gestão das Águas da Paraíba (AESA) de 1994 a 2009. Os dados foram disponibilizados em planilha eletrônica do Microsoft Excel com informações diárias, mensais e anuais e por último foi analisado o comportamento das precipitações através do Índice de Anomalia de Chuva (IAC), que é bastante simples e empregado para avaliação dos períodos secos ou úmidos. Pelo o estudo observou-se que apenas 2009 apresentou um mês (abril), como extremamente úmido e os demais anos foram classificados como muito úmidos, úmidos e secos. O ano mais seco foi 1998 que apresentou anomalias negativas de fevereiro a maio, seguido d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3805', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a222', 'Efeito do uso de diferentes compostos na produção de tomate (Lycopersicum esculentum Mill) em cultivo orgânico', 'F. J. S. Seixas; M. S. Teodoro; M. N. Lacerda; L. M. S. Araújo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo do presente trabalho foi avaliar, em condições de casa de vegetação, a influência de cinco compostos orgânicos na adubação de plantio e de cobertura de tomate híbrido do tipo Caqui. O delineamento experimental adotado foi o de blocos casualizados, com quatro repetições. Foram avaliados cinco tratamentos, contendo biomassa vegetal provenientes do banco de leguminosas da Embrapa Meio-Norte. As leguminosas utilizadas na confecção dos compostos foram o guandu Cultivar Fava Larga (Cajanus cajan), a Crotalária juncea (Crotalaria juncea L.), a Leucena (Leucaena leucocephala), a Gliricídia (Gliricidia sepium) e a Mucuna preta (Mucuna aterrima). A gramínea utilizada foi o capim elefante (Pennisetum purpureum). Os frutos do tomate começaram a ser colhidos no início do amadurecimento, por volta de 70 a 120 dias após o transplantio. Avaliaram-se a produção total de frutos (PTF), produção de frutos comerciais (PFC), número total de frutos (NTF), número de frutos comerciais (NFC), peso mé', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3705', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a225', 'Águas subterrâneas: Um estudo acerca da superexplotação sobre a microbacia III do Rio Salgado', 'V. S. Santos; M. A. P. Santos; R. M. Franca; M. S. Chaves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A Microbacia III do rio Salgado é uma das cinco microbacias que compõem a sub-bacia do salgado e está situada ao sudoeste do Estado do Ceará, sendo esta a que mais utiliza as águas subterrâneas do aquífero médio. Este trabalho retrata a problemática das águas subterrâneas visando à superexplotação, e com a finalidade estabelecer debate e discutir sobre a maneira mais racional para o uso consciente das águas da área de estudo. Devido à prática de determinadas atividades, temos impactos negativos sobre as águas subterrâneas da referida região que afetam diretamente na sua quantidade provocando rebaixamento do nível freático do aquífero. Utilizando referencial teórico, podem-se avaliar as condições do recurso hídrico e propor recomendações. Os resultados apontam que hoje temos um percentual de área com 20,92% que estão comprometidos com nível de rebaixamento de 20 metros. Medidas precisam ser tomadas antes que as consequências sejam irreversíveis ao recurso e os instrumentos do âmbito leg', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3538', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a226', 'Conservação pós-colheita de carambola sob refrigeração com  recobrimento de biofilme de gelatina e PVC', 'F. K. G. Santos; T. A. Oliveira; R. M. A. Ferreira; R. H. L. Leite; E. M. M. Aroucha', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar a Conservação pós-colheita de carambola com recobrimento de gelatina e PVC. Para isto, carambolas da cultivar ‘Gigante doce’ foram colhidas na maturidade fisiológica, transportadas para o Laboratório de Pós-colheita da Universidade Federal Rural do Semiárido sendo selecionadas quanto a maturação, sanificadas, secas e separadas em três grupos para a aplicação dos recobrimentos: os frutos foram recobertos  individualmente com uma solução filmogênica de gelatina a 10% com 1% de glicerol como agente plastificante, recobertos 4 frutos com filme flexível de policloreto de vinila (PVC) de 15μm por bandeja e testemunha (sem recobrimento). Os frutos foram armazenados a 10±1 ºC e 85-90% de UR, avaliados em intervalo de cinco dias durante 20 dias quanto a perda de massa, coloração da casca, firmeza de polpa, sólidos solúveis, acidez titulável, pH e ácido ascórbico. O delineamento experimental utilizado foi inteiramente casualizados, em esquema fatorial 3 x 5,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3653', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a228', 'Caracterização físico-química e microbiológica do esgoto da UEPB com proposta de tratamento para fins de reuso', 'M. U. Sousa; L. M. R. Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Nos últimos anos, a preocupação com as questões ambientais vem sendo bastante discutidas, onde merece destaque, o descarte indevido do esgoto doméstico no meio ambiente, portanto o presente estudo objetivou realizar a caracterização físico-química e microbiológica do esgoto descartado no solo, no Centro de Ciências e Tecnologia da Universidade Estadual da Paraíba, campus de Campina Grande – PB. Para tanto foram desenvolvidas análises físico-químicas, tais como pH, Fósforo Total, DBO, DQO, Nitratos, Nitritos, Nitrogênio Amoniacal, Orto-Fosfatos e Alcalinidade, bem como análise microbiológica (coliformes). Observou-se que o efluente na unidade em questão não recebe tratamento para seu descarte, sendo identificadas características físico-químicas e microbiológicas de esgoto in natura. Faz-se necessário desta forma, investimentos em análises periódicas para assim realizar um tratamento adequado ao efluente visando-se reduzir os riscos ambientais e de saúde pública. Após os resultados das a', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3764', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a22c', 'Influência de veranico na produção agrícola no município de Santa Filomena, Piauí, Brasil', 'T. S. Lima; T. A. Pimenta; H. E. A. Menezes; R. M. de Medeiros; J. L. G. Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste estudo foi verificar a relação entre a duração, em dias, dos maiores veranicos, e as produções de arroz, cana-de-açúcar, fava, feijão, mandioca, milho, banana e laranja para Santa Filomena – PI. Os dados utilizados consistem de séries diárias de precipitação do posto pluviométrico localizado em Santa Filomena – PI e gentilmente cedido pela empresa de assistência técnica e extensão rural do estado do Piauí (EMATER) para o período de dezembro de 1992 a março de 2010 e de produção agrícola anual das referidas culturas disponibilizadas pelo Instituto Brasileiro de Geografia e Estatística (IBGE) para o período de 1993 a 2010. Considerou-se veranico como sendo o número de dias consecutivos sem chuva ou com chuva abaixo de 2,0 mm/dia. E o mais longo período de veranico da estação chuvosa (dezembro a março), não havendo quebra entre os meses. Resultou-se que as produções de milho e banana no município de Santa Filomena – PI apresentaram relações diretamente proporcionais aos m', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4608', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a230', 'Crescimento de mudas de mamoeiro em condições controladas com água salina', 'Elaine Cristina Bezerra Silva; Debora Cristina Coelho; Franciédna Maria da Silva; Reginaldo Gomes Nobre; Eldon Macio Lacerda de Sousa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Diante a importância socioeconômica e alimentar do mamoeiro para a região nordeste, onde naturalmente ocorrem águas com teores elevados de sais, objetivou-se avaliar o crescimento de mudas de mamoeiro em casa de vegetação sob irrigação com água salina. Neste sentido, foi realizado um experimento, em ambiente protegido da Universidade Federal de Campina Grande, UFCG, Campus de Pombal, PB onde foram estudados, cinco níveis de salinidade da água de irrigação em uma cultivar de mamoeiro (Tainung-1). O delineamento experimental foi inteiramente casualizado, sendo a unidade experimental composta por quatro plantas úteis; as mudas de mamoeiro foram formadas em sacolas plásticas de 500 ml de volume; avaliou-se o crescimento e a massa seca da parte aérea das plantas. Sendo as variáveis submetidas ao teste F, e realizando análise de regressão polinomial para o fator salinidade da água. Sendo assim; A salinidade reduz o crescimento das mudas de mamoeiro; A altura de planta e diâmetro de caule foi', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3218', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a232', 'Avaliação da serapilheira em área de mata ciliar na bacia do rio Gurguéia sul do Piauí', 'Alan Cauê Holanda; Leovandes Soares Silva; Jaina Teresa Franco Costa; Allyson Rocha Alves; Eleide Maia Leite; Aluska Kelly Alves Nunes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Esse trabalho teve como objetivo avaliar ciclagem de nutrientes, através da deposição, estoque e decomposição de serapilheira em um remanescente de mata ciliar na Bacia do Rio Gurguéia. O experimento foi desenvolvido no munícipio de Bom Jesus-PI numa área de 17,8 ha de vegetação de caatinga. Para estimativa da quantidade produzida de serapilheira foram utilizados 15 coletores de madeira 1,00 m x 1,00 m, enumerados e distribuídos ao longo dos transectos. A serapilheira estocada foi estimada nas duas estações do ano (verão e inverno), retiradas com o auxilio de uma moldura de madeira vazada de 0,5 m x 0,5 m. Na avaliação da decomposição foram distribuídos 12 sacolas de náilon na superfície do solo, em cada caixa coletora, sendo retirada uma sacola de cada coletor a cada mês. A produção de serapilheira foi estimada em 3.266,8 kg. ha ̄ ¹, a fração folha apresentou maior contribuição com 2.076,1 kg ha ̄ ¹. A maior deposição ocorreu na estação seca. A serapilheira estocada apresentou maior a', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3201', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a237', 'Caracterização pós-colheita de figos (Ficus carica L.) produzidos sob diferentes condições de cultivo na Chapada do Apodi – CE.', 'Patrício Borges Maracajá; Francisco Limeira Silva; Monique Ellen Torres Silva; Pahlevi Augusto Souza; Raniely Nayanne da Silva Freitas', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A produção de figos para consumo in natura é limitada pelas chuvas, que causam elevadas perdas por podridão, o que pode dificultar o seu cultivo durante a estação chuvosa local (fevereiro a maio), época em que a fruta atinge a sua maior cotação. Essa dificuldade poderá ser contornada com o uso de ambiente protegido. Objetivou-se com o presente trabalho, realizar a caracterização da qualidade pós-colheita de figos produzidos sob cultivo protegido e a céu aberto na Chapada do Apodi- CE. Os frutos utilizados neste experimento foram colhidos em pomar experimental da Unidade de Ensino e Pesquisa (UEPE), pertencente ao Instituto Federal de Educação, Ciência e Tecnologia do Ceará (IFCE), localizada na Chapada do Apodi em Limoeiro do Norte – Ceará, onde os mesmos foram cultivados a céu aberto e em estufa.  Foram realizadas as seguintes análises: diâmetro do fruto, peso do fruto, firmeza da polpa, sólidos solúveis (SS), acidez titulável(AT), pH, RATIO e vitamina C. De acordo com os parâmetros a', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3316', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a244', 'Qualidade microbiológica de salada de frutas comercializadas por ambulantes na cidade de Juazeiro do Norte – Ceará', 'Lúcia Emanuele Barros Teixeira; Inácia dos Santos Moreira; Jôcy Emanuela Ferreira dos Santos; Deise Souza de Castro; Francinalva Cordeiro de Sousa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho avaliou a qualidade microbiológica de salada de frutas comercializadas por ambulantes na cidade de Juazeiro do Norte - Ceará. Foram coletadas seis amostras de salada de frutas, sendo duas em cada ponto de coleta. As amostras foram coletadas pela manhã no centro da cidade, as amostras foram mantidas em recipientes isotérmicos e levadas para o Laboratório de Microbiologia de Alimentos da FATEC – Cariri. Realizaram-se análises de coliformes a 45°C e Salmonella spp, segundo as Normas da APHA 2001. Os resultados foram interpretados de acordo com a RDC N°12, de janeiro de 2001 da ANVISA. Para coliformes a 45°C foram encontrados resultados iguais a 2,4x102 NMP/g; 1,5x102 NMP/g; 4,6x102 NMP/g; ≥2,4x102 NMP/g; 4,6x102 NMP/g e ≥2,4x102, para as amostras A1, A2, B1, B2, C1 e C2 respectivamente. Estes resultados revelam que 33,33% das amostras, encontra-se em desacordo com o padrão federal vigente que permite 5x102 NMP/g. Para Salmonella spp., os resultados encontrados foram de', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3089', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a247', 'Caixas para o transporte interno e armazenamento da goiaba ‘Paluma’ com injúria de impacto', 'Railene Hérica Hérica; Francisco Assis Sousa; Inácia dos Santos Moreira; Helton Sousa Silva; Tádria Cristiane Furtunato', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar o efeito de diferentes embalagens indicadas para o transporte interno e armazenamento da goiaba ‘Paluma’ sob a qualidade dos frutos com injúria de impacto. Utilizou-se o delineamento inteiramente casualizado em esquema de parcelas subdivididas no tempo, com quatro repetições e dois frutos por unidade experimental. Os tratamentos forma: T1, testemunha; T2, frutos submetidos a impacto, embalagem em caixa de polietileno; T3, frutos sem impacto, embalagem em caixa de polietileno; T4, frutos submetidos a impacto, embalagem em caixa de papelão; T5, frutos sem impacto, embalagem em caixa de papelão. Não há diferença na qualidade da goiaba ‘Paluma’ quando transportada ou armazenada em caixas de papelão ou de plástico do tipo polietileno. As goiabas tiveram qualidade adequada para comercialização até o terceiro dia de armazenamento. Ao final do armazenamento observou-se presença de estruturas fúngicas e maior perda de massa nos frutos com injuria de impacto', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3345', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a249', 'Avaliação de características agronômicas de cultivares de alface sob diferentes doses de nitrogênio', 'Ildon Rodrigues do Nascimento; Tiago Alves Ferreira; Rodrigo de Castro Tavares; Kellen Kiara Barros Milhomens; Maiko Emiliano Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A alface é uma hortaliça consumida principalmente na forma in natura, contem boas quantidades de vitaminas A, B1, B2, B6 e C. O fornecimento adequado de nutrientes é fundamental, sendo que o N para a alface está diretamente associado as características vegetativas, reprodutivas e morfológicas. O experimento foi conduzido no setor de Olericultura da Universidade Federal do Tocantins (UFT), na cidade de Gurupi. Foram utilizadas duas cultivares, Elba e Verônica. As mudas foram produzidas em bandejas de isopor de 128 células. Aos 27 dias após o transplantio, foram avaliadas as seguintes características: Massa fresca aérea (MFA) - Obtida com a pesagem das plantas coletadas; Número de folhas totais (NFT) - Através da contagem das folhas das planta; Diâmetro da cabeça (DC) - Obtido com auxilio de uma régua; Massa seca aérea (MSA) – Obtida através da secagem da massa verde em estufa a 60° C, ate atingir peso constante, quando as amostras foram pesadas novamente. Podemos destacar que a cv. Elba', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2940', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a251', 'Fitossociologia e estrutura diamétrica de um cerrado sensu stricto, Gurupi – TO', 'Valdir Carlos Lima de Andrade; Rômullo Quirino de Souza Ferreira; Priscila Bezera de Souza; Marilia Oliveira Camargo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo desse trabalho foi realizar um levantamento fitossociológico e determinar a estrutura diamétrica de um cerrado sensu stricto. Esse estudo foi conduzido na cidade de Gurupi - TO, na Fazenda Experimental da UFT Campus de Gurupi, sendo que o local compreende a área de reserva legal desta propriedade e está localizada sob as respectivas coordenadas geográficas 11”46’25 S e 49”02’54 W. Foram instaladas sistematicamente cinco parcelas de 20x50m cada, sendo distanciadas 20 m entre si, perfazendo um total de 5000 m², ou 0,5 ha de área amostral. Nessas parcelas foram amostrados todos os indivíduos arbustivo-arbóreos com circunferência altura do peito (CAP) ≥ a 10 cm.Foram amostrados 906 indivíduos, dos quais 868 vivos e 38 mortos em pé, distribuídos em 102 espécies, e 78 gêneros. A altura média da vegetação estimada foi de 7,31 m, o diâmetro médio encontrado foi de 9,49 cm além de ter apresentado uma área basal total de 9,69 m². O índice de diversidade de Shannon (H’) encontrado foi ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2996', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a255', 'Caracterização morfotintorial de Colletotrichum spp. causador de antracnose em frutos de figo cultivados experimentalmente no perímetro irrigado de São Gonçalo, Sousa-PB', 'Patrício Borges Maracajá; Antonia Mendes Meira Fernandes; Oscar Mariano Hafle; Nelieide Medeiros Gomes; Damião Junior Gomes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Como alternativa da inserção de novas culturas na região do Semiárido brasileiro temos o figo ''Roxo de Valinhos'' (Ficus carica L.) uma planta família Moraceae que pode muito bem ser inserida no contexto da agricultura familiar, mas que vem sofrendo infecção por um fungo do gênero Colletotrichum provocando importantes percas econômicas no agronegócio e também no campo da pesquisa e extensão. Este trabalho teve como objetivo caracterizar a morfologia de isolados de Colletotrichum spp. causador de antracnose pós-colheita em frutos de Ficus carica L. cultivado experimentalmente no perímetro irrigado da São Gonçalo no município de Sousa-PB. Primeiramente identificou os frutos com sintomas de antracnose seguido de sua desinfecção com álcool a 70%. Logo fez-se montagem em lâmina de microscopia para um prévia avaliação do patógeno. O fungo foi isolado em Batata-Dextrose-Ágar a 25ºC durante 10 dias. Seguidamente foi feito o microcultivo no mesmo meio de cultura para a análise morfo-tintorial do', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3401', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a256', 'Qualidade das águas cinza tratada com fitorremediação em unidades de produção agrícola', 'Aline Costa Ferreira; S Nicola; Jórgerson P. G. Pereir Pereira; Verena S. Baracuhy; Viviane F. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A irrigação é uma atividade que necessita de grande quantidade de água, o tratamento de águas cinzas provenientes de uma lavanderia pública em regiões semiáridas para reuso passa a ser uma alternativa de sobrevivência neste ambiente e favorável no desenvolvimento econômico sustentável. Nesse contexto, a pesquisa foi realizada no distrito de Ribeira no município de Cabaceiras - PB objetivando-se avaliar a qualidade da água cinza tratada com fitorremediação nas unidades de produção agrícola. Foram realizados dois tratamentos com(Tanque 2) e sem fitorremediação(Tanque 1), a cultura utilizada foi o capim elefante roxo. Foram coletadas amostras mensais e analisadas os seguintes parâmetros fisicoquimicos: Turbidez, pH, Condutividade elétrica (Ce), Demanda Quimica de Oxigenio(DQO) e Fostoro Total. Para a turbidez os valores dos tratamentos foram acima de 1.000 UNT. Na demanda química de oxigênio, o valor mínimo foi de 311mg/L (setembro) e máximo de 438mg/L (outubro) no tanque 2 em contraparti', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3332', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a25c', 'Macrofauna edáfica em consórcio de sorgo e soja sob incremento de nitrogênio na gramínea', 'L. A. M. Gonzaga; J. Silva; R. R. Fidelis; R. W. S. Aguiar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se fazer um levantamento da macrofauna edáfica em culturas do sorgo e soja em sistema de consórcio com aplicação de doses crescentes de nitrogênio na gramínea. Foram utilizadas armadilhas do tipo pitfalls e os tratamentos ficaram assim dispostos: T1,  vegetação natural; T2,  sorgo solteiro + aplicação 100 kg ha-1 de N; T3,  sorgo-soja com uma linha de soja + 0 kg ha-1 de N; T4,  sorgo-soja com uma linha de soja + 20 kg ha-1 de N; T5,  sorgo-soja com uma linha de soja + 40 kg ha-1 de N; T6,  sorgo-soja com uma linha de soja + 60 kg ha-1 de N; T7,  sorgo-soja com uma linha de soja + 80 kg ha-1 de N; T8,  sorgo-soja com uma linha de soja + 100 kg ha-1 de N; T9,  sorgo-soja com duas linhas de soja + 0 kg ha-1 de N; T10,  sorgo-soja com duas linhas de soja + 20 kg ha-1 de N; T11,  sorgo-soja com duas linhas de soja + 40 kg ha-1 de N; T12,  sorgo-soja com duas linhas de soja + 60 kg ha-1 de N; T13, sorgo-soja com duas linhas de soja + 80 kg ha-1 de N; T14,  sorgo-soja com duas linh', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2817', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a25d', 'Uso da argila no processo produtivo da cerâmica vermelha: Um estudo de caso no município de Paudalho, Pernambuco', 'Y. M. Paz; S. G. El-Deir; R. M. Holanda', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As frações granulométricas do solo são consideradas recursos naturais não renováveis, devido a escala de tempo necessária para sua formação. A argila possui elevada disponibilidade na natureza, e por isso seu uso ainda é indiscriminado. É a matéria-prima principal para as indústrias de cerâmica vermelha pulverizadas em todo o território brasileiro. O objetivo do trabalho foi realizar uma discussão acerca do recurso natural não renovável argila e seu uso no processo produtivo da Indústria de cerâmica vermelha. Este foi desenvolvido através de pesquisa bibliográfica, e estudo de caso com realização de visitas técnicas a uma indústria de cerâmica vermelha localizada no município de Paudalho no estado de Pernambuco. No ano de 2013 a Indústria X adquiriu para estoque e consumo 70.161 toneladas, para uma produção de 35.806.268 blocos de cerâmica. De todo o quantitativo produzido houve uma perda de 7,5%, que reflete em 4.768 toneladas de argila e num prejuízo aproximado de R$ 845.835,52. Atra', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2894', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a260', 'A problemática ambiental decorrente dos resíduos sólidos gerados no processo produtivo do queijo', 'E. C. A. Carolino; M. A. Silva; R. R. P. Almeida; D. L. Crispim; S. N. R. Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O processo de fabricação e comercialização de queijo, sejam eles em grandes agroindústrias ou de modo artesanal em pequenas propriedades rurais, é parte importante na economia brasileira, sobretudo para algumas regiões, a exemplo da região nordeste do Brasil. O objetivo deste trabalho foi efetuar uma caracterização preliminar da produção de queijo, enfatizando o levantamento de suas relações com o meio ambiente e os possíveis aspectos e impactos ambientais decorrentes da produção de queijo. Para tanto, utilizou-se como processo metodológico uma revisão bibliográfica da problemática em estudo a fim de se obter a maior quantidade possível de informações, além de fazer uma correlação com estudos que traz alternativas para o aproveitamento do principal efluente gerado no processo produtivo do queijo, que é o soro derivado do  leite. O soro do leite é um subproduto de alto potencial poluidor, e as empresas perceberam que agregando valor a esse subproduto derivado do leite tem-se uma alterna', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3630', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a262', 'Reúso de água na agricultura', 'H. M. M. Barros; K. X. L. Barosi; L. R. Chicó; L. P. Souza; M. K. L. Veriato', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A fixação do homem nas regiões do planeta tem acontecido em função de disponibilidade de elementos necessários à sua sobrevivência. Nesse sentido, a água, tem sido a forma de energia essencial à vida e a manutenção dos ecossistemas. No entanto sua escassez tem se tornado um problema de ordem global de forma que os governantes têm cada vez mais se preocupados em gerenciar de forma responsável tal recurso. A demanda crescente por água tem feito do reuso planejado um tema atual e de grande importância. Neste sentido, considera-se o reuso de água como parte de uma atividade mais abrangente que é o uso racional ou eficiente da água, o qual compreende também o controle de perdas e desperdícios, e a minimização da produção de resíduos e do consumo de água. A utilização de águas residuárias para os mais diversos fins já é uma realidade em diversos países do mundo. No Brasil, dentre os principais fatores que contribuíram para o aumentasse o interesse pela irrigação com efluentes, se encontram: ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3868', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a268', 'Recolhimento de embalagens vazias de agrotóxicos no Rio Grande do Norte de 2006 a 2014', 'A. M. P. Negreiros; R. Sales Júnior; T. S. Oliveira; A. S. P. Sousa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os agrotóxicos são substâncias utilizadas para o controle de agentes biológicos não desejáveis a produção agrícola, e o descarte inadequado de suas embalagens podem contaminar o meio ambiente e ainda colocar em risco a saúde pública. Sendo assim, este trabalho tem por objetivo quantificar o volume de tipos de embalagens que foram processadas e encaminhadas para incineração e reciclagem pela Central de Recebimento de Embalagens Vazias de Agrotóxicos de Mossoró – RN nos anos de 2006 a 2014. Neste período deram entrada na central um total de 488.76 t de embalagens vazias de agrotóxicos e até o final de 2014, 450.53 t desse material foram processados e transportados para recicladoras ou incineradoras, totalizando aproximadamente 92% das embalagens recebidas pela Central. As embalagens de Polietileno de Alta Densidade e papelão foram as que representaram o maior percentual de processamento e retirada da Central 40,36 e 28,10%, respectivamente.  Em contrapartida, os menores valores percentua', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3890', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a26b', 'Estudo de espécies de pescado potencialmente aproveitáveis na cadeia produtiva do litoral sul do Estado do Rio de Janeiro', 'E. Amorim; G. M. Oliveira; P. P. O. Silva; A. L. A. Jamas; J. D. dos S. Carvalho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No Rio de Janeiro, a produção de pescado ocorre de maneira ampla em contingente de espécies, porém, algumas se encontram em situação de sobrepesca, tornando-se importante o estudo de espécies potencialmente aproveitáveis do ponto de vista nutricional, tendo em vista o alto volume de desembarque e a baixa exploração econômica que estas oferecem no Estado. Com isso, a identificação e caracterização de novas fontes de aproveitamento do pescado para maior incorporação na cadeia produtiva, possibilita a obtenção de um produto de maior valor agregado. Este trabalho tem por objetivo fomentar o potencial que as principais espécies de bagre desembarcadas, Cathorops spixii (Agassiz, 1829) e Genidens barbus (Lapècede, 1803), oferecem na cadeia produtiva de pescado na região conhecida como Costa Verde, litoral sul do Rio de Janeiro, pois o bagre foi uma das dez espécies mais desembarcadas em nível nacional em 2010, e de baixo aproveitamento no mercado consumidor. Na Baía de Sepetiba no Município d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3472', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a26d', 'Manejo de pragas no controle de doenças no cultivo de hortícolas', 'W. L. Araújo; F. S. Sousa; A. B. A. Andrade; A. P. N. Ferreira; A. G. Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os insetos estão geralmente associados a uma planta, em sua maioria são considerados pragas, principalmente em cultivos agrícolas, sejam como pragas broqueadoras, sugadoras de seiva, ou até mesmo como vetores de fitopatógenos, sendo neste último uma das causas mais preocupantes, uma vez que muitos fitopatógenos patógenos causam doenças que ainda não tem-se um controle eficaz. Sabe-se que no modelo convencional de produção, o manejo das pragas são feitos por controle químico. Este trabalho teve como objetivo fazer uma revisão bibliográfica de trabalhos representativos a respeito do controle de pragas vetores de doenças. A mosca-branca (Bemisia ssp) foi o gênero que mais preocupa os produtores, uma vez que se apresentou como praga em uma grande quantidade de plantas hortícolas, e por ser vetor de vírus, doenças a te então, com controle restrito. Pulgões (Aphididae) também foram relatados, assim como a traça-das-crucíferas (Plutella xylostela) e do tomateiro (Tuta absoluta), controle biol', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3887', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a26f', 'Ocorrência de doenças do tomateiro na região de Guanambi, BA', 'S. C. Cardoso; M. A. S. Guimarães; J. H. S. Teixeira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As doenças do tomateiro são responsáveis por grandes prejuízos econômicos e a falta de conhecimento técnico no diagnóstico e controle dessas doenças onera os custos e limitam a sua produção. Esse trabalho tem como objetivo realizar um levantamento para identificação e registro de ocorrência de doenças do tomateiro na região de Guanambi, BA. O levantamento foi realizado nos Distritos de Morrinhos e Guirapá e nos Povoados de Brejos dos Padres e do Tanque. Para tanto, foram realizadas visitas nas áreas produtoras de tomate e para avaliação do histórico da área foi aplicado um questionário aos produtores. Amostras de plantas infectadas foram coletadas e levadas para análise no Laboratório de Fitopatologia do IFBaiano - Campus Guanambi ou enviadas para diagnóstico em Clinica Fitopatológica. Foram diagnosticadas nove doenças bióticas: vira cabeça do tomateiro (Tomato spotted wilt virus), oídio (Oidium sp.), murcha de fusário (Fusarium oxysporum), requeima (Phytophthora infestans), mofo preto', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3711', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a272', 'Avaliação da qualidade do solo em agroecossistemas na zona rural de São Bentinho-PB', 'Z. C. Vieira; S. N. Ribeiro; F. J. S. Melo; L. R. A. Alves; M. F. A. Alves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O crescimento da demanda por alimentos gera a expansão de áreas agrícolas ocasionando um aumento do desmatamento. Tais fatores contribuem para o crescimento da preocupação com a sustentabilidade dos sistemas agrícolas, o qual passa por uma percepção do espaço rural como agente ativo na conservação e proteção dos recursos naturais. O conhecimento dos limites de exploração dos ecossistemas rurais é fator primordial para que se obtenham sistemas agrícolas mais sustentáveis.  Diante do exposto o presente trabalho objetiva avaliar, através de uma extensa revisão bibliográfica, visitas em campo e utilização de índices de sustentabilidade, a qualidade do solo de dois agroecossistemas utilizados para o plantio de feijão e milho na zona rural de São Bentinho-PB; e finalmente, propor estratégias ou técnicas de manejo que venham tornar os agroecossistemas estudados mais sustentáveis. Conclui-se que a área de plantio de feijão apresentou um solo de melhor qualidade do que área de plantio de milho.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3596', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a275', 'Integração soja e pastagem: Uma revisão de literatura', 'C. A. Badji; J. S. Viana; J. G. Barbosa; T. R. C. Brito; J. A. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A necessidade do aumento de produção de alimentos de forma sustentável se faz cada vez mais presente. Neste aspecto, a soja (Glycine max (L.) Merrill) e a carne bovina são a base da alimentação mundial por serem fontes ricas em óleo e proteínas. No entanto, o cultivo convencional de soja e as pastagens extensivas não atende esses aspectos, principalmente quando relacionado à minimização dos impactos sobre o meio ambiente.  A integração lavoura – pecuária é uma solução viável para esta problemática, pois apresenta resultados positivos para produção de grãos de soja e para as pastagens, por meio do aumento da qualidade do solo, ciclagem de nutrientes, conservação da umidade, preparo único do solo, controle de plantas daninhas, interrompendo ciclos de insetos e doenças. Objetivou-se com esse trabalho apresentar a importância da soja para sistemas de integração lavoura-pecuária. Integrating soybean and pasture: A literature reviewAbstract: The needs for increasing the production of food in', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3536', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a27a', 'Composição florística e faunística de quintais agroflorestais da agricultura familiar no nordeste paraense', 'C. M. Oliveira; R. H. C. Almeida; A. P. Quaresma; O. R. Kato', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os quintais agroflorestais são comuns entre os agricultores familiares da Amazônia, sendo sistemas de uso da terra sustentáveis desenvolvidos a partir dos saberes tradicionais. Além de ter como principal finalidade a promoção da segurança alimentar, são espaços de socialização e lazer para os agricultores e, podem contribuir para a composição de sua renda pela venda do excedente da produção. O objetivo desse trabalho foi identificar a diversidade dos quintais, a partir da composição de flora e fauna. A pesquisa estudou 37 quintais agroflorestais em cinco comunidades em Igarapé-Açu e Marapanim, nordeste paraense, usando técnicas de observação direta em campo, aplicação de questionários semiestruturados, notas etnográficas e turnê guiada nos quintais agroflorestais. Foram 107 espécies vegetais identificadas e 12 animais. Estes dados revelam que há uma quantidade maior de espécies comparativamente a outros estudos, o que se pode inferir grande conhecimento tradicional empregado na constit', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3706', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a27d', 'Licenciamento ambiental: Conflito de interesses', 'K. H. S. Moura; N. da S. Dias; A. C. M. Souza; K. C. de F. Moura; M. da S. Câmara Neta', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O licenciamento ambiental foi criado pela Legislação Federal como um dos instrumentos da Política Nacional do Meio Ambiente na Lei Nº 6.938/81, tornando-se obrigatório para todas as atividades que possam interferir na qualidade do meio ambiente. Este instrumento visa a preservação, melhoria e recuperação da qualidade ambiental e proporcionar a vida, assegurando condições ao desenvolvimento socioeconômico, aos interesses da segurança nacional e a proteção da dignidade da vida humana. Nesse contexto, objetivou-se analisar o processo de licenciamento ambiental enquanto instrumento de política ambiental, evidenciando as principais dificuldades para a obtenção da licença ambiental. Entretanto, é imprescindível o conhecimento dos empreendedores a respeito dos danos ambientais caudados pelas suas atividades para que possam se adequar às exigências da prevenção aos recursos naturais e da compensação ambiental que lhes compete. Há necessidade de adequação do processo de licenciamento ambiental ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2793', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a27f', 'Armazenamento de atemoias (Annona squamosa x Annona cherimola) recobertas com filme PVC', 'P. B. Maracajá; F. B. da Costa; R. V. da S. Freitas; E. M. Batista; P. A. de Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A atemoia, assim como todos os frutos climatéricos, apresenta uma elevada perecibilidade, tornando-se importante a adoção de técnicas pós-colheita. Este trabalho teve como objetivo avaliar o armazenamento de atemoias recobertas com filme PVC. Os frutos utilizados foram da variedade ‘Gefner’ apresentando-se em estado de maturação verde-maduro. Estes foram transferidos para o laboratório de Química de Alimentos do IFCE, submetidos à higienização e divididos nos devidos tratamentos. O primeiro tratamento constou no armazenamento de cinco frutos em bandejas de isopor recobertos com filme PVC. O segundo, do recobrimento individual dos frutos em filme PVC, sendo estes acondicionados em bandejas de isopor e os frutos do controle. Estes foram armazenados durante 8 dias. O delineamento utilizado foi o DIC em esquema fatorial 3x4 com quatro repetições de cinco frutos por parcela. A cada tempo de armazenamento foram avaliadas: perda de massa, sólidos solúveis, acidez titulável, Ratio, pH e índice', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3349', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a285', 'Performance social corporativa: Análise da dimensão da estrutura do trabalho unidades produtivas de cotonicultura', 'D. B. Santos; L. S. Freitas; F. P. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A Performance Social Corporativa (PSC) ocorre por meio da mensuração das práticas de Responsabilidade Social Corporativa (RSC) e transmitidas pelos valores sociais e ambientais, além dos valores econômicos e legais. Para isso, o objetivo do presente trabalho idealizou-se em analisar a PSC, a partir da dimensão estrutura de trabalho de duas unidades produtivas (UP´s) de cotonicultura, denominadas de UP1 e UP2, situadas no Mato Grosso – Brasil, a luz do método triangulação de dados. Por conseguinte, o estudo focou-se nas abordagens quanti-qualitativa, conduzidas pelos métodos exploratórios e descritivos, sob as percepções dos gestores e colaboradores, tendo em vista a aplicação do método de triangulação dos dados, primários, secundários, bem como as inferências dos pesquisadores, derivadas dos questionários de perguntas objetivas e subjetivas. Logo, os resultados médios das médias da PSC da dimensão estrutura de trabalho das UP´s apresentam boas performances (B), contudo, com altos nívei', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3712', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a288', 'Crescimento e desenvolvimento inicial da cultura da moringa (Moringa oleifera Lam.) submetida à fertilização orgânica', 'L. S. Souto; A. C. Medeiros; J. A. Dutra Filho; T. M. A. Souza; T. A. Sousa; H. T. Oliveira Neto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A moringa (Moringa oleifera Lam) é uma árvore nativa da Índia e de elevada importância principalmente pelo seu valor nutricional, medicinal e de purificação da água. Este trabalho teve como objetivo avaliar o efeito de níveis de fertilização orgânica no crescimento e desenvolvimento inicial de mudas de moringa nas condições semiáridas do Estado da Paraíba, Brasil. O experimento foi conduzido em condições de túnel plástico, localizado no Centro de Ciências e Tecnologia Agroalimentar, da Universidade Federal de Campina Grande, Campus de Pombal, UFCG. Utilizou-se o delineamento inteiramente casualizado, com os tratamentos compostos de sete níveis de fertilização orgânica (0,0; 108,0; 216,0; 432,0; 864,0; 1728,0 e 3456,0 g.vaso-1), com quatro repetições. Foram avaliados os seguintes parâmetros: i) altura das plantas (cm), ii) diâmetro do caule (mm), iii) número de folhas, iv) fitomassa fresca das folhas, v) fiomassa seca da parte aérea (g), vi) fitomassa seca da raiz (g), vii) razão fitoma', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4268', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a289', 'Identificação de impactos ambientais em emprendimento ou atividade de indústria química', 'G. B. Sá; S. T. L. Rodrigues Segundo; M. K. L. Dantas; K. A. Silva; G. P. Freitas', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Resumo: A indústria química apresenta uma enorme variedade de processos e produtos, podendo ser considerado o setor mais diversificado da área industrial. É também o setor industrial sobre o qual se concentram de maneira mais intensa as preocupações quanto à contaminação ambiental. Objetivou-se com o trabalho destacar os aspectos ambientais dessa atividade e identificando os principais impactos ambientais provenientes deste empreendimento decorrentes das fases de planejamento, implantação e operação. Foi realizada uma revisão da literatura acerca de indústrias químicas e consultas a EIA/RIMAs, apresentando seus principais impactos potenciais e significativos (positivos e negativos), nas diversas fases do empreendimento. Tais impactos foram identificados a partir do método de Avaliação de Impactos Ambientais, listagem de controle simples (Check lists). Os principais impactos identificados foram compactação do solo, alteração nas características do solo, contaminação de rios e aquíferos,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4297', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a28b', 'Zoneamento ambiental do polo de desenvolvimento agroindustrial do Alto Piranhas, Estado da Paraíba', 'J. S. Almeida; J. M. Costa; P. B. Maracajá; P. X. Pamplona; W. F. Melo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo zonear os níveis de deterioração ambiental na paisagem entre os anos de 2001 e 2012, adotando os critérios da ecodinâmica nos municípios que compõe o polo de desenvolvimento agroindustrial do Alto Piranhas. Foram realizadas análises envolvendo a dinâmica da paisagem e da vulnerabilidade ambiental. A metodologia utilizada na pesquisa foi baseada em localizações pontuais, que inclui o processo de selecionar e combinar, através de procedimento de álgebra de mapas disponíveis em um SIG, cada variável geográfica contém diferenciação espacial e a combinação entre elas promove a subdivisão do espaço geográfico em regiões equiproblemáticas. Tomando-se por base as superposições dos mapas geológico, geomorfológico e pedológico foi efetuado o mapa de zoneamento ambiental, com informações que permitiram identificar as condições do meio natural e suas aptidões. Esses fatores foram comparados entre si, conforme a importância atribuída a elas. Os resultados indicaram ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4477', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a28f', 'Avaliação do potencial antimicrobiano do extrato etanólico bruto e frações da Sida santaremnensis H. MONTEIRO (MALVACEAE) sobre cepas de Rhodotorula spp.', 'Danielly Albuquerque da Costa; Egberto Santos Carmo; Edeltrudes de Oliveira Lima; Maria Carmem Batista de Alencar; Josefa Paula do Nascimento', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As leveduras do gênero Rhodotorula estão associadas a uma variedade de processos patológicos no homem, nos casos mais severos a taxa de mortalidade chega a 50%. A anfotericina B e o fluconazol são os fármacos de escolha utilizados no tratamento de infecções por Rhodotorula spp. no entanto, algumas cepas dessas leveduras já apresentam graus de resistência ao fluconazol. Por apresentarem diferentes propriedades terapêuticas e relatos de uso, as plantas do gênero Sida (Malvaceae) vêm sendo amplamente estudadas. A espécie Sida santaremnensis ocorre em quase todo o Brasil, apesar de sua ampla distribuição, não há relato de utilização dessa espécie na medicina popular. Contudo, verificando a variedade de compostos naturais, propriedades farmacológicas e relatos de uso descritos para espécies da família Malvaceae, notadamente no gênero Sida, e, visando contribuir para o desenvolvimento de novos antifúngicos, buscou-se avaliar através da determinação da Concentração Inibitória Mínima (CIM) e d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3499', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a292', 'Dinâmica de funcionamento da cadeia produtiva do mel no assentamento Tabuleiro Grande, Apodi/RN', 'Francicláudio de Paula; Kallyo Santos Moura; Karidja Carlos Moura; John Vasconcelos Fonteles', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A apicultura é considerada uma atividade secular, muito explorada por pequenos e grandes produtores rurais. É uma atividade em expansão em diversos países, inclusive no Brasil, pelo potencial de geração de trabalho e renda que possui, como também por contribuir para manutenção e preservação dos ecossistemas existentes. Mediante o exposto, essa pesquisa objetivou identificar a cadeia produtiva do mel em sua efetividade, no assentamento Tabuleiro Grande Apodi/RN, contribuindo para o desempenho operacional e eficiência. Como ferramentas para coletas de informação foram feitas visitas de observação e aplicados questionário com questões abertas e fechadas de cunho qualitativo e quantitativo. Identificou-se na pesquisa o nível de importância da apicultura para região estudada, interligando os aspectos sociais, econômicos e ambientais. Diante do exposto, pode-se concluir que a apicultura é importante e deve ser encarada como alternativa para a região estudada interligando os aspectos sociais,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2879', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a29c', 'Staphylococcus spp. em camarão minimamente processado refrigerado embalado a vácuo', 'Bárbara Camila Firmino Freire; Karoline Mikaelle de Paiva Soares; Antonio Cleyton Arruda de Azevedo; Amanda Sabino de Souza; Vilson Alves de Góis', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo do presente estudo foi avaliar o efeito dos tratamentos com lactato de sódio, ácido cítrico e ácido lático na contagem de Staphylococcus spp. em camarão minimamente processado estocado em refrigeração. Após a coleta das amostras, realizou-se o processamento mínimo utilizando dois tratamentos distintos: o controle e a imersão em solução bioconservante. Em seguida, as mesmas foram embaladas a vácuo e estocadas em refrigeração. Foi realizada a contagem de Staphylococcus spp. a partir do dia zero e repetida em intervalos regulares de 48 horas durante quatro dias. A aplicação dos aditivos resultou em reduções significativas nas contagens de Staphylococcus spp. durante o armazenamento refrigerado, podendo representar uma alternativa viável para aumentar a qualidade e a segurança microbiológica do camarão minimamente processado.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3313', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a29d', 'Estudo etnofarmacológico sobre produtos naturais e sintéticos citados para tratamento de casos suspeitos de micoses superficiais no município de Cuité – PB', 'Luiz Joardan Fernades de Lima; Danielly Albuquerque da Costa; Dayanne Fernandes Oliveira; Egberto Santos Carmo; Maria Carmem Batista de Alencar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O uso de plantas medicinais remonta desde a antiguidade e estas representam uma importante ferramenta na promoção à saúde, em vista do uso indiscriminado de medicamentos e da resistência microbiana. Em razão disso, o presente trabalho, teve como objetivo investigar as plantas medicinais e produtos sintéticos utilizados pela população do município de Cuité – PB, para o tratamento de micoses superficiais, a fim de catalogar e preservar o conhecimento popular, e analisar se há confirmação científica na literatura que comprove a atividade biológica destas plantas e produtos. Foi adotado um questionário, com perguntas semiestruturadas, e o estudo contou com a participação de 116 indivíduos, sendo realizado no Hospital e Maternidade Nossa Senhora das Mercês em Cuité – PB.  Os dados foram processados e analisados no programa SPSS (Statistical Package for the Social Sciences). Foram coletadas informações sobre as plantas e produtos utilizados, além da parte utilizada, forma de utilização, temp', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3468', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a29f', 'Óleos essenciais de manjericão e capim citronela no controle de larvas de Aedes aegypti', 'Líllian França Borges Chagas; Henrique Guilhon de Castro; Aloisio Freitas Chagas Júnior; Dione Pereira Cardoso; Ronice Alves Veloso', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar o efeito larvicida do óleo essencial do manjericão (Ocimum basilicum L.)e do capim citronela (Cymbopogon nardus L.) em larvas de Aedes aegypti. Os tratamentos utilizados para cada tipo de óleo foram: água destilada; água destilada + dimetilsulfóxido (DMSO); 2,5µL do óleo essencial; 5,0µL do óleo essencial; 7,5µL do óleo essencial; e 10,0µL do óleo essencial. As avaliações consistiram de contagem do número de larvas mortas em oito épocas (intervalos regulares de três horas). Os óleos essenciais de manjericão e do capim citronela apresentaram eficiente ação larvicida, causando a morte das larvas de A. aegypti em última fase larval. As alíquotas de 5,0, 7,5 e 10,0 µL do óleo essencial do capim citronela foram mais eficientes apresentando a partir da segunda época de avaliação 100% de larvas mortas.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3322', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a0', 'Desenvolvimento de um kit de reator de leito fixo de bagaço de cana-de-açúcar para uso didático', 'Andarair Santos; Francisco Klebson Gomes Santos; Rafaelle Santiago; Edna Aroucha; Ricardo Leite', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'É de fundamental importância o desenvolvimento de práticas de laboratório nos cursos de engenharia, porém os altos custos dos kits didáticos muitas vezes inviabilizam sua aquisição. No entanto, o presente trabalho teve como objetivo desenvolver um kit para aulas de cinética e reatores, utilizando materiais de fácil aquisição e com caráter ambiental, uma vez que o leito fixo é composto por bagaço de cana-de-açúcar. Para estudar a cinética, variou-se o volume de álcool etílico alimentado e a altura de leito fixo no reator, observando o comportamento do rendimento e da produtividade. Avaliou-se a influência da adição do álcool etílico e ácido acético na produção deste e avaliou-se a atividade operacional do recheio através do reuso do mesmo. A acidez do produto aumentou com o passar do tempo e após cerca de 12 horas manteve-se constante. O rendimento teve um aumento proporcional à diminuição do volume de alimentação e ao aumento da altura do leito fixo. Aplicando os valores obtidos em mod', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3351', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a3', 'Levantamento da disponibilidade de dados hidrométricos na Paraíba - Brasil', 'Patrício Borges Maracajá; Katherine da Silva Sousa; Iury Araujo Macêdo Dantas; Gabriela Braga de Sá; Anderson Bruno Anacleto de Andrade', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A limitação dos recursos hídricos na atualidade é um dos principais entraves para o desenvolvimento econômico e social, e leva a muitos desafios para o planejamento e gerenciamento deste recurso. O levantamento das informações e dados necessários para elaboração de estudos hidrológicos é realizado através de estações hidrométricas, cujas séries de dados têm sua importância proporcional à sua extensão temporal. O presente estudo objetiva elaborar um levantamento das estações pluviométricas e fluviométricas com existência e disponibilidade de dados de chuva e vazão das bacias hidrográficas do estado da Paraíba. O levantamento foi elaborado junto à Rede Hidrometeorológica Nacional da Agência Nacional de Águas – ANA, obtidos a partir seu portal Hidroweb, onde são disponibilizados os dados hidrológicos em séries históricas. Foram identificadas 79 estações pluviométricas e 20 estações fluviométricas com dados existentes na Paraíba, após esse levantamento foi elaborado um mapa temático para v', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3553', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a6', 'Características  Agronômicas de seis Cultivares de Bananeiras tipo Prata', 'Vagner Alves Rodrigues Filho; Milton Celso Padilha Júnior; Yago Cândido Pereira da Silva; Sérgio Luiz Rodrigues Donato; Tânia Santos Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A despeito da ampla aceitação comercial da ''Prata-Anã'' é necessário o aumento do portfólio de cultivares tipo Prata para os agricultores. Objetivou-se avaliar características agronômicas de bananeiras Prata em dois ciclos de produção. Utilizou-se delineamento experimental inteiramente casualizado, com seis tratamentos, ‘Prata-Anã’, ‘Maravilha’, ‘BRS Platina'', ''BRS Fhia-18'', ''Fhia-18'' e ''JV42-135'', cinco repetições e quatro plantas úteis por parcela. A ‘Maravilha’ é a mais produtiva, com maior massa das pencas, maior massa, comprimento e diâmetro do fruto; ''JV42-135'' apresenta maior porte, menos pencas e frutos; ''BRS Fhia-18'' é menos vigorosa; ‘BRS Platina’ assemelha-se mais à genitora, ‘Prata-Anã’.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3096', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a7', 'Estabilidade oxidativa da carne caprina armazenada sob congelamento', 'Julliana Isabelle Simionato; Marcondes Viana Silva; Jussimara Barros Oliveira; Maria Cecília Oliveira Lima; Luzimar Gonzaga Fernandez', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A oxidação lipídica é um dos fatores mais importantes que limitam a vida útil e a estabilidade comercial da carne e produtos cárneos. A oxidação lipídica da carne caprina armazenada sob congelamento, nos tempos de 0, 30, 60 e 120 dias, foi estudada utilizando-se peças do músculo longissimus dorsi, proveniente de animais caprinos, da raça Anglo-Nubiana, machos, não castrados, com idade inferior a oito meses, criados em regime extensivo.  Para tanto, realizou-se análise do índice de substâncias reativas ao ácido 2-tiobarbitúrico (TBARS), do índice de peróxido e a análise cromatográfica de fase gasosa. De acordo com os resultados encontrados para o TBARS e o índice de peróxido, as amostras não variaram de forma significativa (p>0,05) em relação ao tempo de estocagem. Destacaram-se como ácidos graxos majoritários, os ácidos palmítico, esteárico e oléico. A temperatura de armazenamento de -18ºC contribuiu para a manutenção da qualidade da carne caprina por, pelo menos, 120 dias.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2792', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2aa', 'Biometria e morfologia da semente e plântula de oiticica', 'Sebastião Medeiros Filho; Fábio Oliveira Diniz; Antônio Marcos Esmeraldo Bezerra; Francisco José Carvalho Moreira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A carência de trabalhos sobre plantas nativas da Caatinga nordestina é perceptível, sobretudo, no que se refere aos estudos de suas sementes. Dentre as referidas espécies, destaca-se por seus múltiplos usos, a oiticica (Licania rigida Benth). Objetivou-se com este trabalho determinar e descrever a biometria e morfologia da semente e plântula de oiticica. O trabalho foi conduzido no Laboratório de Análises de Sementes do Departamento de Fitotecnia/UFC. Foram realizadas, nas sementes, medições individuais de comprimento, largura e espessura e a determinação morfológica de suas partes internas e externas, além da caracterização da plântula com suas respectivas estruturas. A semente de oiticica é eurispérmica, apresenta comprimento de 3,1 a 5,0 cm, largura de 1,3 a 1,7 cm e espessura de 1,2 a 1,7 cm. O embrião é grande de formato linear, com cotilédones carnosos de cor branca amarelada, dobrados e apresentam nervuras e o eixo hipocótilo-radícula curto. Germinação inicia-se aos 15 dias, sen', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2965', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2ad', 'Adição de gesso agrícola e cinza de madeira ao substrato no desenvolvimento de mudas de baruzeiro (Dipteryx alata Vog)', 'N. S. Rincon; J. A. Almeida; C. J. Silva; C. A. Freitas; C. A. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar o desenvolvimento de mudas de baruzeiro (Dipteryx alata Vog) em função de proporções de gesso (0%; 1,6%; 3,2%; 4,8% e 6,4%) com base em volume e adubação com cinza de madeira (ausência e presença) misturadas ao substrato Bioplant®. Constituiu-se assim um esquema fatorial 5x2, em delineamento inteiramente ao acaso, com três repetições e quatro plantas por parcela. O experimento foi conduzido de janeiro a março de 2009, em viveiro com cobertura e laterais de sombrite preto (50% da luminosidade natural), situado na Fazenda Japão, município de Orizona, Goiás. Como recipiente foram utilizados sacos de polietileno de 15 x 25 cm, onde colocou-se uma sementes por recipiente, ficando a extremidade superior da semente cerca de 2,0 cm de profundidade. As irrigações foram realizadas diariamente, no período da tarde. Aos 152 dias após a semeadura, avaliou-se altura de muda (AM), diâmetro de caule (DC), número de folha (NF), número de folíolos por folha (NFF), núme', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2915', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2b5', 'Comportamento do regime pluviométrico no município de Catolé do Rocha no Estado da Paraíba, Brasil', 'José Geraldo Araújo Ferreira  Filho; Tainara Tâmara Santiago Silva; Danilo Rodrigues Monteiro; Soahd Arruda Rached Farias; Hallyson Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A região semiárida do nordeste lida periodicamente com chuvas irregulares em todo seu território, comprometendo o desenvolvimento da região. O objetivo deste trabalho é avaliar o regime de chuvas no município de Catolé do Rocha, identificar se a precipitação pluviométrica é suficiente para suprir as necessidades da população e apresentar formas para um bom aproveitamento e manejo da água de chuva. A área em estudo está localizada no estado da Paraíba, no município de Catolé do Rocha.O procedimento metodológico consistiu da análise de um banco de dados referentes aos últimos 17 anos, relacionados à precipitação do município de Catolé do Rocha, sendo estes dados oriundos da Agência Executiva de Gestão das Águas do Estado da Paraíba. A partir dos dados observados foi possível realizar uma análise estatística descritiva com valores de média, mediana, coeficiente de variação, máximo e mínimo, além de confrontar as demandas de água necessárias para suprir as pessoas e animais de produção do ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2890', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2b6', 'Comportamento reológico de iogurte de cajá comercializado em Campina Grande, Paraíba', 'Patricia Rodrigues Pê; Flávio Farias Gurjão; Gilmara Gurjão Carneiro; Taciano Pessoa; Débora Rafaelly Soares Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O estudo reológico contribui para o conhecimento da estrutura molecular, no controle de qualidade e aceitação de um determinado produto, auxilia no controle do processo industrial e em projetos de equipamentos no processamento dos materiais. Objetivou-se avaliar o comportamento reológico de iogurte de cajá e a adequação dos dados reológicos aos modelos de Ostwald-de-Waele, Herschel-Bulkley e Mizrahi-Berk e ainda o efeito da temperatura sobre o comportamento reológico. Os dados reológicos foram obtidos através de um viscosímetro Brookfield DV-II+Pro. Os ensaios foram realizados nas temperaturas 20, 30 e 40 °C e os resultados experimentais foram ajustados pelos modelos de Ostwalde-de-Waelle, Casson, Hershel Bulkey e Mizrahi-Berk, com auxílio do software STATISTICA, versão 7.0. O iogurte analisado neste experimento apresentou comportamento de fluido não newtoniano com características pseudoplástica. Os modelos reológicos de Hershel Bulkey e Mizrahi-Berk representaram satisfatoriamente o c', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2939', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2bb', 'Multiplicação de anador (Justicia pectoralis) in vitro', 'Rômulo Magno Oliveira Freitas; Sidney Carlos Praxedes; Narjara Walessa Nogueira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O trabalho teve como objetivo desenvolver um protocolo de micropropagação de segmentos nodais de anador (Justicia pectoralis). Para isso foram realizados dois experimentos. O delineamento estatístico utilizado foi o inteiramente casualizado, com 15 repetições. Os segmentos de J. pectoralis, após desinfestados, foram cultivados em meio MS durante 30 dias. No primeiro experimento, esse material foi repicado em três meios de cultura (MS, WPM e B5) e após 77 dias foram avaliados comprimento de plântula, número de raízes, número de folhas e o número de segmentos nodais. Para o segundo experimento foram testadas duas citocininas (BAP e Cinetina) nas seguintes dosagens 0,0; 0,5; 5,0 e 20,0 mM. Aos 60 dias após a repicagem foram avaliadas as seguintes características: números de folhas, número de raízes e número de explantes por planta. O meio MS foi o que apresentou maior comprimento de plântula. As demais variáveis não diferiram entre os meios utilizados. Por isso o meio MS foi utilizado par', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3986', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2bc', 'Diagnóstico e tendência da precipitação pluvial em Bom Jesus - Piauí, Brasil', 'Virgínia Mirtes de Alcântara Silva; Hudson Ellen Alencar Menezes; Hamstrong Ellen Alencar Menezes; Raimundo Mainar Medeiros; Valneli da Silva Melo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Com o objetivo de analisar a distribuição temporal e a tendência da precipitação pluvial para o município de Bom Jesus - PI relacionando o estudo com regressão linear e medidas de tendência central e de dispersão dos índices pluviométricos mensais e anuais, a estação chuvosa dura seis meses (novembro a abril) com valor médio do período de 875,1 mm, correspondendo a 88,86% da precipitação anual. Em 55 anos de precipitação observada sua média histórica é de 984,8 mm. Conforme a análise de regressão linear da série histórica de precipitação do período de 1960 a 2014, a tendência de maior variabilidade da precipitação centra-se entre os meses de novembro a abril, e os menores índices pluviométricos centra-se entre os meses de maio a setembro, que possui baixos índices pluviométricos.Diagnosis and trend rainfall in Bom Jesus - Piauí, BrazilAbstract: With the objective of analyse the temporal distribution and trend of rainfall for the city of Bom Jesus - PI related study with linear regressi', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3992', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2be', 'Obtenção e caracterização da farinha do albedo de maracujá (Passiflora edulis f. Flavicarpa) para uso alimentício', 'Wilton Pereira da Silva; Rennan Pereira de Gusmão; Enaile Tavares da Silva; Elaine Cristina Oliveira da Silva; Julice Dutra Lopes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O maracujá é uma fruta abundante no Brasil, que é considerado o maior produtor do mundo. Cerca de 52% do peso total do fruto é composto por casca (albedo e flavedo), que pode ser reutilizada na forma de farinha como uma fonte de nutrientes para a alimentação e enriquecimento de vários produtos alimentares. Assim, o objetivo do presente trabalho foi estudar o processo de fabricação de farinha do albedo de maracujá amarelo (Passiflora edulis f. Flavocarpa), com variações nas temperaturas de secagem e avaliar suas características físico-químicas e tecnológicas. Após o processo de maceração para remover a naringina (substância que provoca amargor) realizou-se a secagem convectiva, em secador de bandejas do albedo do maracujá amarelo nas temperaturas de 50, 60, 70 e 80°C. Após análise de teor de água e cor escolheu-se a farinha seca a 70°C que obteve baixo teor de água e maior luminosidade para realização das analises de cinzas, lipídios, fibras e minerais, além da avaliação morfológica por', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4062', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2bf', 'Processamento e caracterização físico-química do suco misto melancia com pepino', 'Rossana Maria Feitosa de Figueirêdo; Raphaela Maceió Silva; Regilane Marques Feitosa; Alexandre José de Melo Queiroz', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A junção da melancia com pepino trás grandes benefícios na melhoria da composição físico-química do produto. O suco misto de frutas vem sendo estudado para revelar as características nutricionais e funcionais da mistura. Sendo a melancia rica em água, potássio, ferro, magnésio, zinco e vitamina C e o pepino apresentando baixo consumo de energia, baixo teor de calorias e pequenas quantidades de vitamina C, a elaboração desses combinados aumenta a possibilidade de efeitos benéficos ao organismo. Objetivou-se, com este estudo, elaborar suco misto de melancia com pepino em diferentes concentrações e caracterizar físico-químicamente as formulações. Com a obtenção das polpas, foram elaboradas as seguintes formulações: F1-100% pepino; F2-50% melancia e 50% pepino; F3- 70% melancia e 30% pepino; F4- 90% melancia e 10% pepino e F5- 100% melancia. Foram realizadas analises físico-químicas em triplicata em todas as formulações para a caracterização de cada tratamento quanto: pH, sólidos solúveis ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4087', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c0', 'Avaliação de modelos matemáticos para estimativa da erosividade da chuva na região de São Mateus-ES', 'Robson Bonomo; Dione Pereira Cardoso; Fábio Ribeiro Pires', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se estimar a erosividade da chuva, mediante seis modelos matemáticos, de regressão linear avaliando entre estes, qual é mais indicado para as condições climáticas da região de São Mateus-ES. Os dados pluviométricos foram obtidos junto à Agência Nacional das Águas-ANA, sendo de 1947 a 2014 para Itauninhas, de 1971 a 2014 para Barra Nova, de 1981 a 2014 para São João da Cachoeira Grande e de 1993 a 2014 para Boca da Vala. Para estimar a erosividade da chuva, a partir da precipitação anual e do coeficiente de chuva, foram utilizadas diferentes equações utilizadas em outros estados com aplicação ao estado do Espírito Santo ou ajustadas para o próprio estado. Para os modelos matemáticos (II) e (I), os valores médios foram de 6.541,2 MJ ha-1 mm h-1 ano-1 a 936,357 MJ ha-1 mm h-1 ano-1 (Itauninhas), de 6.995,855 MJ ha-1 mm h-1 ano-1 a 1.420,296 MJ ha-1 mm h-1 ano-1 (Barra Nova), de 6.297,272 MJ ha-1 mm h-1 ano-1 a 1.014,815 MJ ha-1 mm h-1 ano-1 (São João da Cachoeira Grande) e de 5.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4132', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c1', 'Indicadores da sustentabilidade de uma propriedade rural de base familiar no estado de Mato Grosso do Sul', 'Emerson Machado de Carvalho; Anderson de Souza Gallo; Nathalia de França Guimarães; Rebeca Darc de Paula Santos; Camila Cunha', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho avalia a sustentabilidade de uma propriedade rural de base familiar, no estado de Mato Grosso do Sul, com o objetivo de apresentar linhas de trabalho para os aspectos menos sustentáveis e, dessa forma, alcançar maior sustentabilidade do sistema. O estudo foi realizado através de diagnóstico visual, baseando-se nos indicadores de sustentabilidade do método MESMIS “Marco para Evaluación de Sistemas de Manejo de Recursos Naturales Incorporando Indicadores de Sustentabilidad”. Para avaliação foram utilizados 36 indicadores e três parâmetros, abordando aspectos ambientais, sociais e econômicos. O resultado obtido com a avaliação da unidade de produção rural evidencia que a propriedade se encontrada alterada, demonstrando a necessidade de intervenções para se alcançar maior sustentabilidade ambiental, social e econômica. A propriedade apresenta alguns pontos críticos relacionados à ausência de área de preservação permanente e/ou reserva legal, baixa adoção da prática de r', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4149', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c3', 'Crescimento e produção do gergelim em diferentes níveis de solução organomineral', 'Messias Firmino de Queiroz; Emerson Lúcio Gomes Silva; Antonio Fernandes Monteiro Filho; Nair Helena Castro Arriel; Samuel Brilhante Gonçalves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O Gergelim (Sesamum indicum L.), espécie pertencente à família Pedaliaceae, é uma das oleaginosas, mais antigas utilizadas pela humanidade com potencial para diversos fins industriais. Nesse sentido objetivou-se avaliar o crescimento e a produção do gergelim fertirrigado com solução nutritiva organomineral. Realizou-se um experimento de campo no Centro de Ciências Agrárias e Ambientais da Universidade Estadual da Paraíba, Lagoa Seca, PB, sob fertirrigação por gotejamento, de agosto de 2013 a julho de 2014. O delineamento experimental foi em blocos casualizados com quatro repetições e seis tratamentos correspondendo a diferentes níveis da adubação recomendada (50-80-20) para a cultura do gergelim, são eles: (T1 = testemunha absoluta; T2 = 25%; T3 = 50%; T4 = 75%; T5 = 100% e T6 = 125%). As doses de biofertilizante influenciam a ‘AP’, o ‘DC’ e o ‘NFP’ de gergelim. O ‘NRP’, o ‘PSP’ e o ‘P1000’ não são influenciados pela fertirrigação com a solução organomineral. A ‘AP’, o ‘DC’ e o ‘NFP’ d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4205', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c6', 'Calidad fisiológica de semillas y variabilidad entre plantas en una población de arroz', 'Cristiane Deuner; Igor Kohls; Andreia da Silva Almeida; Luis Osmar Braga Schuch; Jerffeson Araujo Cavalcante', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'La calidad fisiológica de la semilla podría afectar el rendimiento de granos de arroz. Las diferencias en la calidad fisiológica de las semillas pueden causar la reducción y desuniformidad de la emergencia en el campo, acarreando una diferencia en el crecimiento inicial de las plantas, y consecuentemente afectando el cultivo y su rendimiento. Se realizo un experimento con el objetivo de evaluar la distribución espacial y la variabilidad en la población entre las plantas de arroz, en función de la calidad fisiológica de las semillas. Fueron utilizados nueve lotes de semillas de la cultivar BR-IRGA 410, siendo tres de alta, tres de media y tres de baja calidad fisiológica. Cada bloque consistió de nueve líneas de 5,5 metros de longitud, separadas por 0,12 metros. Se evaluó el número de fallas consecutivas y la variabilidad entre las plantas a través del coeficiente de variación de la altura de plantas y de la materia seca. El uso de las semillas con baja calidad fisiológica proporcionó m', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4254', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c7', 'Levantamento entomofaunístico de artrópodes em algodoeiro de fibra naturalmente colorida em Ipanguaçu-RN', 'Maurício Sekiguchi de Godoy; Bárbara Karine de Albuquerque Silva; Antônio Genildo Cordeiro; Francisco Edivino Lopes da Silva; Pedro Ramon Holanda de Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com esta pesquisa identificar a diversidade de artrópodes associados à cultura do algodão Gossypium hirsutum L. com pluma colorida, sendo realizados levantamentos entomofaunístico em Ipanguaçu-RN em áreas de produção. A área experimental foi composta por 15 variedades de algodão com pluma colorida: CNPA 2009-6; CNPA 2009-11; CNPA 2009-13; CNPA 2009-16; CNPA 2009-27; CNPA 2009-42; CNPA 2009-47; CNPA 2009-48; CNPA 2009-50; CNPA 2009-59; CNPA 2009-60; CNPA 2009-62; BRS RUBI; BRS AROEIRA; BRS TOPÁZIO. O levantamento foi realizado tendo como base três métodos de coleta ativa em pontos aleatórios da área experimental. As coletas consistiram da retirada manual de folhas e maçãs diretamente da planta, além da captura de insetos em pleno voo, com auxílio de rede entomológica. Foram encontrados um total 1884 insetos adultos e 66 larvas, dispostos em 8 ordens e 22 famílias. A família Aphididae: Hemiptera foi a mais numerosa entre o material coletado, com 1720 adultos dispersos nos tr', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4255', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c9', 'Profundidade de semeadura no desenvolvimento inicial de pseudocereais', 'Daniele Brandstetter Rodrigues; Jonas Albandes Gularte; Thais D''Avila Rosa; Lilian Vanusa Madruga de Tunes; Diego Cardoso de Medeiros', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar a influência da profundidade de semeadura na emergência de plântulas de sementes de  amaranto e quinoa. Foram avaliados os efeitos das profundidades de 0; 0,5; 1,0; 1,5 e 2,5 cm para amaranto e de 0; 1,5; 2,5; 3,5; e 4,5 cm para quinoa, obtidas por meio de anéis de pvc, com espessura equivalente a estes valores, que foram imersos no substrato para simular as profundidades de semeadura. O delineamento experimental foi inteiramente casualizado, com quatro repetições. Os dados foram submetidos à análise de variância e as médias, comparadas pelo teste de Tukey com 5% de probabilidade de erro. Foram realizados os testes de germinação, primeira contagem de germinação, emergência de plântulas em bandejas, massa de matéria seca e peso de mil sementes. A profundidade de semeadura para o melhor desenvolvimento inicial indicada para amaranto é de até 1,5 cm, e para quinoa até 2,5 cm.Seeding depth in the initial development of pseudocerealsAbstract: The object', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4269', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2cc', 'Caracterização morfométrica da bacia hidrográfica do igarapé da Prata, Capitão Poço, Pará, Brasil', 'Artur Sales de Abreu Vieira; Rodrigo Silvano Silva Rodrigues; Diêgo Lima Crispim; Francisco Carlos Lira Pessoa; Lindemberg Lima Fernandes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo realizar a caracterização morfométrica da bacia hidrográfica do igarapé da Prata, localizado no município de Capitão Poço, Pará. Inicialmente gerou-se o Modelo Digital de Elevação a partir de SRTM com resolução espacial de 30 m, utilizando o sistema de informações geográficas, por meio do software ArcGis 10.1 e da extensão ArcHydro, foram calculados alguns parâmetros morfométricos para o estudo do comportamento hidrológico da bacia. A área de drenagem encontrada foi de 115,283 km² e o perímetro de 70,151 km. A bacia hidrográfica do igarapé da Prata tem formato alongado, coeficiente de compacidade de 1,829, fator de forma de 0,356 e índice de circularidade de 0,294. A densidade de drenagem obtida para a bacia foi de 0,525 km/km², com padrão dendrítico. A forma mais alongada da bacia hidrográfica indica que a precipitação pluviométrica sobre ela se distribui em diferentes pontos. De maneira geral, suas características morfométricas denotam um controle est', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4313', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2ce', 'Métodos de aplicação de diferentes concentrações de H2O2 em milho sob estresse salino', 'Francisco Hevilásio Freire Pereira; Aldair de Souza Medeiros; Francisco Hélio Dantas Lacerda; Leandro de Pádua Souza; Evandro Manoel da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A aplicação exógena de H2O2 tem demonstrado eficiência na aclimatação das plantas aos estresses bióticos e abióticos devido estimular a ativação do sistema de defesa antioxidativo. Neste sentido, objetivou-se com o trabalho avaliar a influência do método de aplicação de diferentes concentrações de H2O2 sobre o crescimento inicial de plantas de milho irrigadas água salina. O experimento foi conduzido em ambiente protegido, com os tratamentos dispostos em delineamento inteiramente casualizado, em esquema fatorial 5 x 2, correspondente as concentrações de peróxido de hidrogênio (H2O2) de 0; 5; 10; 15 e 20 µmol L-1 aplicados na semeadura via água de irrigação e, pulverização foliar aos 15 dias após a semeadura (DAS), com quatro repetições e unidade experimental constituída por um vaso de 3 L contendo duas plantas de milho híbrido 4051. As plantas foram irrigadas com água de CE de 2,0 dS m-1. As 28 DAS verificou-se que a aplicação de H2O2 na semeadura e através de pulverização foliar promov', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4343', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d1', 'Uso de destiladores solares para fornecer água potável no semiárido Paraibano', 'Amonikele Gomes Leite de Alexandria; Vera Lucia Antunes de Lima; José Adailton Lima Silva; Bárbara Bruna Maniçoba Pereira; Tiago Silva Lima; Francisco José Loureiro Marinho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A escassez de água advinda das condições climáticas do semiárido paraibano tem forçado inúmeras famílias rurais a consumirem água de má qualidade, o que tem contribuído para o aumento de casos de doenças transmitidas pela água. Tendo em vista esta problemática, objetivou-se analisar como o uso de destiladores solares pode proporcionar a obtenção de água potável, e avaliar os benefícios socioeconômicos e ambientais advindos do uso desta tecnologia. Após os estudos, observou-se que os destiladores solares são uma tecnologia de baixo custo econômico, de fácil disseminação social, utilizam energia solar (limpa e renovável), e são capazes de fornecer água potável para atender as demandas hídricas de famílias que convivem com a escassez hídrica em regiões semiáridas.Use of solar distillers to provide drinking water in semiarid ParaibanoAbstract: The scarcity of water arising from climatic conditions of semi-arid Paraiba has forced many rural families to consume poor quality water, which has ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4376', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d2', 'Potencial antibiótico da própolis apícola Potiguar em bactérias de importância veterinária', 'Daniel Santiago Pereira; Wesley Adson Costa Coelho; Carlos Iberê Alves Freitas; Jean Berg Alves da Silva; Marinalva Oliveira Freitas; Maria Rociene Abrantes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A Própolis de abelhas africanizadas (Apis mellifera L.) é um produto da colmeia, elaborado a partir de exsudações de resinas que as abelhas recolhem de determinadas plantas. A composição química da própolis é complexa e relacionada à diversidade vegetal encontrada em torno da colmeia. Estudos recentes demonstram que a própolis possui uma série de propriedades biológicas, essas propriedades têm feito da própolis uma importante matéria-prima para as indústrias farmacêutica, alimentícia e de cosméticos. O estudo dessas propriedades é, portanto, necessário, a fim de se obter um produto com alto padrão de qualidade e valor agregado. Este trabalho tem como objetivo a avaliação do efeito de sete diferentes extratos alcoólicos da própolis (EAP) apícola Potiguar no desenvolvimento de quatro microrganismos de importância veterinária. As colmeias habitadas com enxames de abelhas africanizadas (Apis mellifera L.) selecionados para coleta da própolis estavam organizadas em apiários, distribuídos em', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4377', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d5', 'Espacialização dos serviços básicos de saneamento na zona rural do município de Pombal-PB', 'Luiz Gualberto de Andrade Sobrinho; Virgínia de Fátima Bezerra Nogueira; Sayonara Costa de Araújo; Gabriela Muricy de Souza Silva; José Adalberto da Silva Filho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os serviços de saneamento básico prestados a uma parcela considerável da população que reside em áreas rurais apresentam elevado déficit de cobertura. Desta forma, o objetivo do presente trabalho foi obter um diagnóstico sobre a realidade do acesso aos serviços de saneamento na zona rural do município de Pombal-PB. A metodologia adotada consistiu na análise de dados oriundos do Instituto Brasileiro de Geografia e Estatística através do Sistema de Informações Georreferenciadas Estatcart e espacialização das informações por meio do QGis 2.6.0. Os resultados indicaram que a cobertura de domicílios, por um sistema de abastecimento de água, esgotamento sanitário e manejo de resíduos sólidos, é considerada ineficiente, uma vez que as residências não são atendidos ou tem um atendimento inferior a 20%. Contatou-se ainda uma desproporcionalidade dos serviços entre as zonas urbana e rural do município. A ausência de saneamento compromete a saúde da população. Logo, o diagnóstico do acesso aos se', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4387', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2dc', 'Crescimento inicial de Erythrina velutina em diferentes substratos com adubação orgânica', 'Valmor Elias Tomczak; Mychelle Karla Teixeira de Oliveira; Jeferson Luiz Dallabona Dombroski; Rita de Cássia Araújo de Medeiros; Raul Martins de Farias', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Erythrina velutina é uma espécie arbórea nativa do Nordeste Brasileiro, empregada no paisagismo, na regeneração de áreas degradadas e na medicina popular. Objetivou-se com este trabalho avaliar o crescimento de mudas de Erythrina velutina produzidas em substratos com adubação orgânica. O experimento foi conduzido em delineamento inteiramente casualizado, com parcelas subdivididas no tempo, com cinco repetições, sendo a unidade experimental representada por 20 mudas. O primeiro fator foi constituído por dois substratos (solo de Mossoró-RN + esterco bovino (4:1) e solo de Angicos-RN + esterco bovino (4:1)), e o segundo fator constituído de dois acessos. Ao longo do experimento foram realizadas coletas, para avaliação de crescimento (28, 56, 84, 112 e 140 dias após a semeadura), com intervalos de 28 dias. Em cada coleta, as mudas foram analisadas quanto ao comprimento da parte aérea, ao número de folhas, ao diâmetro de coleto, à área foliar, à massa da matéria seca (caule, folhas, raiz, p', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3594', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2e2', 'Avaliação de água de poços tubulares para consumo humano no Município de Boa Vista, Paraíba', 'Débora Samara Cruz Rocha Farias; Soahd Arruda Rached Farias; José Dantas Neto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Na Região do Semiárido nordestino a diminuição da disponibilidade dos recursos hídricos superficiais tem levado a população da zona rural a buscar, nos recursos hídricos subterrâneos, a solução de seus problemas de abastecimento, o que tem acarretado um crescimento no número de perfurações de poços tubulares profundos. O trabalho objetivou avaliar a qualidade de águas utilizadas para consumo humano em áreas rurais da região de Boa Vista, Paraíba. As amostras de água foram coletadas em poços tubulares, em dois períodos: 4º trimestre de 2014 e 2º trimestre de 2015. As variáveis avaliadas foram: pH, CE, Ca, Mg, Na, K, HCO3 -, Cl, alcalinidade e dureza total e SDT. Das águas analisadas 94,55% são consideradas salgadas nas duas amostragens. Em sua maioria os teores de dureza, alcalinidade, cloreto, magnésio, sódio e potássio estão fora do limite estabelecido pela Portaria vigente no país. Com relação ao pH, as amostras se encontram dentro do padrão normal.Water quality for human consumption', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3943', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2e7', 'Desempenho inicial de plântulas de soja oriundas de sementes quimicamente tratadas', 'Rafael Oliveira Vergara; Vanessa Nogueira Soares; Gizele Ingrid Gadotti; Lilian Madruga Tunes; Henrique Roberto Maldaner', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A soja atualmente é um dos principais produtos do agronegócio brasileiro. Diversos fatores afetam a produtividade da cultura, entre eles o número de plantas estabelecidas merece devido destaque. Grande parte dos produtores brasileiros utiliza o tratamento químico de sementes com objetivo de melhorar o estande inicial de plantas. Neste trabalho se objetivou avaliar o desempenho inicial de sementes de soja tratadas quimicamente com os principais produtos disponíveis no mercado. Utilizou-se dois lotes da cultivar BMX Turbo RR, com distintos níveis de vigor, estes foram submetidos aos três principais tratamentos químicos do mercado. Foram avaliada emergência, índice de velocidade de emergência, comprimento e biomassa seca de raiz, área foliar. Ocorreu diferença entre os tratamentos, no lote de baixo vigor o tratamento quatro (fludioxonil, metalaxylm e tiametoxan) melhorou o desempenho, em sementes de alto vigor o tratamento não favoreceu o desempenho das sementes.Initial performance of soy', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4261', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2e8', 'Associação de fungicida protetor com fungicidas sistêmicos no controle de mancha-alvo na cultura da soja', 'Eduardo Bezerra de Moraes; Eduardo Andrea Lemus Erasmo; Francisco de Carvalho Ribeiro; Francileia de Sousa Rocha; Edilson Pereira de Matos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A mancha-alvo, cujo agente causal é o fungo Corynespora cassiicola vem ganhando importância entre as doenças na cultura da soja, principalmente na região de cerrado, em função de sua elevada severidade e potencial degenerativo à planta. O controle químico de doenças das plantas é uma medida que na maioria dos casos é eficiente e economicamente viável para garantir grandes produções e qualidade de produção. Objetivou-se nesse trabalho avaliar a eficiência da mistura de fungicida protetor aplicado em combinações com fungicidas sistêmicos visando o controle de mancha alvo na cultura da soja. O experimento foi conduzido no ano agrícola 2014/2015 em condições de campo na fazenda Boa Esperança, situada no município de Porto Nacional – TO. O delineamento experimental foi o de blocos ao acaso com quatro repetições, num total de seis tratamentos distintos. Foram realizadas as seguintes avaliações: Severidade da doença, desfolha, índice de área verde, AACPD, massa de 1.000 grãos e produtividade ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4273', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2e9', 'Produção de serapilheira de duas fisionomias do domínio Cerrado, Gurupi, Tocantins', 'Rômullo Quirino de Souza Ferreira; Marilia Oliveira Camargo; Priscila Bezerra de Souza; Rubens Ribeiro da Silva; Paulo Ricardo Teixeira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se verificar a produção de serapilheira de duas fisionomias do domínio Cerrado, sendo uma fisionomia de cerrado sensu stricto (s.s) e outra de mata ciliar, ambas as áreas estão localizadas na Fazenda Experimental da Universidade Federal do Tocantins, Campus de Gurupi-TO. Foram instalados aleatoriamente em cada uma das fisionomias estudadas dez coletores de 1 x 1 m, os quais foram monitorados mensalmente durante o período maio de 2012 a abril de 2013. A produção média de serapilheira total mostrou variação apenas no mês de outubro de 2012 e fevereiro de 2013 com uma produção anual de 1829,31 kg ha-1 na fisionomia de mata ciliar e de 1349,01 kg ha-1 na fisionomia de cerrado s.s. A fração mais representativa da serapilheira total encontrada nas duas fisionomias estudadas foi composta por folhas que perfazem 63,6% do total de material depositado nos coletores seguido pelas frações material lenhoso, flor e propágulo respectivamente.Leaflitter production in two Cerrado types, Gurup', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4283', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2ee', 'Doses de esterco de galinha e água disponível sob o desenvolvimento inicial do milho', 'Francisco Marto de Souza; Ellen Caroline Santos Lima; Francisco Vanies da Silva Sá; Emanoela Pereira de Paiva; Jonathan Estivens Soares Araújo; Lauter Silva Souto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se estudar o desenvolvimento inicial de plantas de milho sob níveis de irrigação e doses de esterco de galinha. O experimento foi conduzido em condições de túnel plástico da Universidade Federal de Campina Grande, Campus de Pombal, Paraíba, no período de Dezembro de 2014 a janeiro de 2015. O arranjo dos tratamentos constituiu um fatorial 5 x 2, correspondentes a cinco doses de cama de frango e dois níveis de água disponível (AD) de 50 e 100% da CC, mantido após as irrigações do solo, com 10 tratamentos e quatro repetições, totalizando as 40 unidades experimentais. O ensaio foi realizado em unidades experimentais compostas por vasos de 18 dm3 de capacidade, semeando manualmente quatro sementes por vaso. As plantas foram conduzidas por 20 dias após a semeadura, onde foram avaliadas quanto a emergência, o crescimento inicial e o acúmulo de massa seca. As doses de 8,4 e 8,5 t ha-1 promovem o maior crescimento das plantas de milho na fase inicial de crescimento. Não houve influênc', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4667', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2ef', 'Potencial alelopático do extrato aquoso de aveia preta e azevém na germinação e crescimento inicial do capim-sudão', 'Michele da Silva Santos; Helder Morais Mendes Barros; Márcio Cavalli; Karina Xavier Leite Barosi; Mara Karinne Lopes Veriato Barros', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A pecuária brasileira é sustentada em pastagens, pela sua praticidade e economia. Entre as espécies anuais de inverno mais utilizadas para pastejo na Região Sul do Brasil estão à aveia preta e o azevém, isolados ou em misturas, em função da facilidade na aquisição de sementes e em relação ao ciclo de produção das espécies. Entre as espécies de verão o Capim-Sudão vem se destacando, usado como alternativa para diminuir as dificuldades encontradas em obter forragem na época seca do ano, por facilidade de cultivo, rusticidade, tolerância à seca, rapidez no estabelecimento e crescimento, e facilidade de manejo sob corte e ou pelo pastejo direto. O presente estudo objetivou-se verificar o potencial alelopático do extrato aquoso em diferentes concentrações da aveia preta e azevém sobre a germinação e crescimento inicial do capim-Sudão. O experimento foi realizado na safra 2013/14, na Universidade do Oeste de Santa Catarina (UNOESC), campus de São José do Cedro, Santa Catarina, em estufa. Par', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4675', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2f4', 'Caracterização do comércio de plantas medicinais por raizeiros em Mossoró, Rio Grande do Norte', 'Maria de Fatima Barbosa Coelho; Narjara Walessa Nogueira; Caio César Pereira Leal; Rômulo Magno Oliveira de Freitas; Fabrícia Nascimento de Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As plantas medicinais são, em muitos casos, a única alternativa possível para boa parte da população brasileira que as obtém geralmente do próprio quintal ou de raizeiros. O objetivo no presente estudo foi caracterizar o comércio de plantas medicinais por raizeiros em Mossoró, Rio Grande do Norte. Foram usadas as técnicas de observação direta e participante e aplicadas entrevistas semiestruturadas. A comercialização de plantas e produtos medicinais é considerada a principal fonte de renda dos raizeiros entrevistados. Foram citadas 86 plantas de uso medicinais entre os raizeiros, sendo Linum usitatissimum L. (86%) a mais citada, seguida de Plectranthus barbatus L (71%), Pterodon emarginatus Vogel (71%) e Bauhinia forficata Link. (71%). As plantas são procuradas para 67 tipos de enfermidades, como anemia, artrite e vermes. A gripe e inflamação foram as doenças mais citadas. As plantas são armazenadas no próprio estabelecimento por períodos longos comprometendo sua eficácia e não são cult', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3948', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2f6', 'As percepções de agricultores familiares sobre transição agroecológica em uma cooperativa agropecuária no Rio Grande do Sul', 'Joice Zagna Valent', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se descrever as percepções dos agricultores familiares de uma cooperativa agropecuária do Rio Grande do Sul sobre as implicações causadas pela mudança de sistema produtivo: da agricultura convencional para a produção agroecológica de alimentos. Para embasar o trabalho foram usadas as teorias da mudança, agroecologia, cooperativismo e agricultura familiar. O estudo classifica-se como uma pesquisa exploratória e descritiva, com tratamento qualitativo dos dados, por meio da análise de conteúdo. Foram realizadas entrevistas com os 39 agricultores. Observa-se que nas percepções individuais os assuntos mais referenciados foram: conhecimento, comunicação e planejamento; resistência e mudança; saúde e renda. O estudo demonstrou que a mudança de sistema produtivo é lenta, porém importante para os agricultores. Contudo, o comprometimento de todos na transição agroecológica foi essencial para o bom desempenho organizacional.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4186', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2fb', 'Diversidade florística e índices arbóreos de escolas no município de Formoso do Araguaia, Tocantins', 'André Ferreira dos Santos; Patrícia Aparecida Souza; Lucicléia Mendes Oliveira; Gildeane Costa; Kaio Cesar Cardoso de Lima Fonseca Alves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A arborização nas escolas exerce papel importante na melhoria desses ambientes, tornando-os mais atrativos e agradáveis para a comunidade educacional e serve como exemplo e fonte de aprendizagem contínua. Assim, objetivou-se fazer o levantamento das espécies e índices arbóreos em nove escolas no município de Formoso do Araguaia, Tocantins. O referido estudo foi realizado em nove escolas públicas do município, desconsiderando-se as escolas particulares. Para saber o número de alunos existentes, cada escola forneceu a relação dos matriculados no período. Fez-se o senso e a identificação da vegetação arbórea presente nos pátios das nove unidades. Os dados de altura foram levantados com auxílio de um clinômetro, com uma trena coletou-se o diâmetro de copa e o tamanho da área de cada pátio escolar e através do Microsoft Excel fez-se os cálculos dos índices de Densidade Arbórea (IDA), Sombreamento Arbóreo (ISA) e de Área Verde (IAVE). Nas escolas foram encontrados 158 indivíduos pertencentes', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4353', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2fd', 'Germinação e crescimento inicial de variedades de feijão caupi submetidas a diferentes concentrações salinas', 'José Aliçandro Bezerra da Silva; Tales Xavier Seabra; Josenara Daiane de Souza Costa; Russaika Lírio Nascimento; Daniela Siqueira Coelho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A utilização de variedades tolerantes ao estresse salino tem sido essencial para o estabelecimento de culturas comerciais em áreas salinas. O objetivou-se avaliar a germinação e o crescimento inicial de plântulas de quatro variedades de feijão caupi submetidas a diferentes níveis de estresse salino. As sementes das cultivares BRS Tapaihum, BRS Pujante, BRS Acauã e BRS Marataoã foram semeadas em espumas, dispostas em bandejas e umedecidas com as seguintes concentrações de NaCl: 0, 50, 100, 150 e 200 mM. Foram determinadas as variáveis: percentual de germinação, índice de velocidade de emergência, tempo médio, frequência relativa de germinação, comprimento da parte aérea e teor de água das plântulas. As variedades de feijão caupi apresentaram perda na capacidade germinativa a partir da concentração de 50 mM de NaCl. Também foi verificado que a incidência da salinidade promoveu uma diminuição da velocidade com que as variedades realizaram seus eventos bioquímicos, fisiológicos, morfogênic', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4419', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2ff', 'Composição e estrutura da vegetação de caatinga no sul do Piauí, Brasil', 'Joxleide Mendes da Costa Pires Coutinho; Leovandes Soares da Silva; Allyson Rocha Alves; Mailson Pereira de Souza; Felipe Silva Amorim', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Visando contribuir para o conhecimento mais profundo a respeito da vegetação do sul do Piauí, e em especial às áreas de tensão ecológica, o presente trabalho objetivou inventariar, avaliando qualitativamente, o componente lenhoso de um trecho de Caatinga, no município de Bom Jesus, Piauí, Brasil. Para realização do levantamento foram alocadas 10 parcelas de 50x20 m (1000 m²), totalizando 1 ha de área amostrada, dispostas de forma contíguas para minimizar os possíveis efeitos de borda da área. Foram amostrados os indivíduos lenhosos vivos com diâmetro à altura do peito (DAP) ≥ 5 cm, independente da altura. No levantamento foram encontradas 11 famílias, 25 gêneros e 27 espécies. Destas, as que se destacaram com os maiores valores de IVI foram: Cenostigma macrophyllum Tul., Combretum duarteanum Cambess., Erythroxylum laetevirens O.E.Schulz, Campomanesia pubescens (Mart. ex DC.) O. Berg., e Licania rigida Benth. O índice de diversidade de Shannon-Wiener (H’) foi de 2,7 nats.ind-1. Para tod', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4588', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a30b', 'Emergência e crescimento de alface (Lactuca sativa L.) submetida a substratos orgânicos', 'Lucas Henrique Teixeira Garcete; Adriana Strieder Philippsen; Paulo Alfredo Feitoza Bohm; Franciele Mara Lucca Zanardo Bohm; Débora Larissa de Oliveira; Paula Bonomo Bertola', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A agricultura orgânica se destaca como modo de produção que consiste em um sistema sustentável. Um dos desafios desse método de cultivo é a produção de alimentos com qualidade em quantidades suficientes sem comprometer o meio ambiente. Objetivou-se analisar o efeito de substratos orgânicos na germinação e crescimento inicial de alface. O experimento foi conduzido em delineamento inteiramente casualizado com quatro tratamentos (substratos) e duas repetições. Foram testados os substratos: composto de Sibipiruna, substrato comercial, composto de Sibipiruna com chorume e substrato comercial com chorume. O chorume foi obtido exclusivamente da decomposição de vegetais. Foi avaliado o efeito dos substratos pelo percentual de germinação, massa fresca, massa seca e comprimento da radícula. Pôde-se considerar que houve diferença significativa entre os tratamentos. As sementes, quando germinadas em substrato de Sibipiruna com chorume, apresentaram maior massa seca e comprimento de radícula. Com r', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4859', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a30e', 'Crescimento inicial do milho sob doses de esterco caprino e disponibilidade de água no solo', 'Francisco Marto de Souza; Ellen Caroline Santos Lima; Francisco Vanies da Silva Sá; Emanoela Pereira de Paiva; Jonathan Estivens Soares Araújo; Lauter Silva Souto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se estudar a emergência e o crescimento inicial de plantas de milho adubadas com esterco caprino sob dois regimes de disponibilidade de água no solo. O arranjo dos tratamentos constituiu um fatorial 4 x 2, correspondentes a quatro doses de esterco caprino (0, 4, 8 e 12 t ha-1) e dois níveis de água disponível de 50 e 100% da capacidade de campo, mantido após as irrigações do solo, com 8 tratamentos e quatro repetições, totalizando as 32 unidades experimentais. O ensaio foi realizado em unidades experimentais compostas por vasos de 18 dm3 de capacidade, semeando manualmente quatro sementes por vaso. As plantas foram conduzidas por 20 dias após a semeadura, sendo avaliadas quanto à emergência, o crescimento inicial e o acúmulo de massa seca. A redução de 50% de água no solo não exerce impactos negativo sobre a emergência e crescimento inicial das plantas de milho AG1051. A dose de esterco caprino de 12 t ha-1 promoveu o maior crescimento e acúmulo de massa seca das plantas de m', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4964', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a311', 'Elaboração e caracterização da farinha do fruto da castanhola (Terminalia catappa Linn)', 'Luciana Márcia Andrade da Silva; Edilayane da Nóbrega Santos; Mônica Tejo Cavalcanti; Erick dos Anjos Bezerra', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A ciência e tecnologia de alimentos vem se destacando com suas novas propostas para o mercado. A vida atual é marcada pela busca de alimentos cada vez mais saudáveis, pois os consumidores estão buscando por uma alimentação que proporcione, além dos nutrientes básicos, algum benefício à saúde. Farinhas obtidas a partir da desidratação de frutos não convencionais estão sendo utilizadas na formulação de uma variedade de produtos a partir da substituição parcial de farináceos tradicionais. Sendo assim, objetivou-se caracterizar a farinha proveniente da polpa do fruto da castanhola. Os parâmetros analisados foram umidade 2,15% (± 0,15); cinzas 8,03% (± 0,06), proteínas 16,70% (± 0,2), lipídeos 6,30% (± 0,07), carboidratos 66,80%, pH 3,83 (± 0,02); acidez 7,40% ác. cítrico (± 0,06), Aw 0,24 (± 0,01) e Valor Energético Total 390,70 Kcal.Os resultados mostraram-se satisfatórios, sendo estes dentro dos valores estabelecidos para farinhas. Para os macronutrientes determinados, os carboidratos mo', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5337', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a312', 'Produção de feijão-caupi e gergelim consorciado com mamoneira no Semiárido paraibano', 'Rodolfo Rodrigo de Almeida Lacerda; José Raimundo de Sousa Júnior; Anielson dos Santos Souza; Guilherme de Freitas Furtado; Jônatas Raulino Marques de Sousa; Lúcia Helena Garófalo Chaves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar os componentes de produção do feijão-caupi e gergelim, consorciado com a mamoneira no semiárido paraibano. O experimento foi desenvolvido no período de março a novembro de 2011 em condições de campo em Pombal, Paraíba. Realizou-se sob delineamento experimental em blocos ao acaso com três sistemas de cultivo em dois ensaios experimentais: feijão-caupi (cv. BRS Novaera) e gergelim (cv. BRS Seda) em monocultivo, consórcio com mamona cv. IAC 2028 e consórcio com mamona cv. BRS Nordestina, com 4 repetições, totalizando 12 parcelas experimentais em cada ensaio. O consórcio com a mamoneira reduz os componentes de produção e produção do feijão-caupi e gergelim, sendo a cv. BRS Nordestina mais competitiva. Considerando as variáveis estudadas, a melhor opção para cultivo consorciado do feijão-caupi ou gergelim na região é a cv. IAC 2028. Production of cowpea and sesame intercropped with castor bean in semiarid region of ParaibaAbstract: The objective was to evaluate yield co', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4890', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a314', 'Produtividade da água na bataticultura de Ibicoara na Chapada Diamantina, Bahia', 'Murillo Anderson Gonçalves Barbosa; Vital Pedro da Silva Paz; Lucylia Suzart Alves; Karoline Santos Gonçalves; Elizana Karla Andrade Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As altas necessidades hídricas na bataticultura, associada a elevados custos de produção, altos riscos característicos da atividade e perspectiva de retorno financeiro compensador fazem com que a irrigação seja prática indispensável para a obtenção de produtividade. Objetivou-se realizar uma análise da produtividade da água no cultivo irrigado de batata. Os dados foram levantados em áreas de cultivo comercial localizada na região da Chapada Diamantina, Bahia. Para a determinação da produtividade física da água, utilizaram-se dados de produtividade da cultura, do volume de água proveniente da precipitação adicionado ao aplicado por irrigação e da evapotranspiração da cultura nas safras 2013/2014 e 2015. A produtividade física média da água para a cultura da batata irrigada por pivô central, na região da Chapada Diamantina, BA foi de 7,22 kg m-3 (safra 2013/2014) e 9,12 kg m-3 (safra 2015). A produtividade econômica da água teve um incremento de produtividade da primeira para segunda saf', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4045', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a315', 'Comportamento hidráulico de sistema de irrigação por gotejamento em função da pressão de serviço adotada', 'Abel Henrique Santos Gomes; Mayra Gislayne Melo de Lima; José Dantas Neto; Denise de Jesus Lemos Ferreira; Gleyka Nobrega Vasconcelos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A irrigação é um processo artificial de aplicação de água no solo visando propiciar às culturas as condições ideais para seu desenvolvimento. Nesse sentido, este trabalho teve por objetivo avaliar um sistema de irrigação localizada por gotejamento, trabalhando sob cinco diferentes pressões de serviço. O experimento foi conduzido em uma área pertencente ao Laboratório de Engenharia de Irrigação e Drenagem (LEID) da Universidade Federal de Campina Grande (UFCG), localizado no município de Campina Grande, Paraíba. Para análise do desempenho do sistema foram analisados os seguintes coeficientes: Coeficiente de Uniformidade de Distribuição (CUD), Coeficiente de Uniformidade Estatística (Us), Coeficiente de Variação de fabricação (CVf) e Eficiência de aplicação (Ea), para as pressões de 70, 100, 150, 200 e 250 kPa, respectivamente. Para os coeficientes analisados o tratamento utilizando a pressão de serviço de 250 kPa apresentou os melhores resultados. Os valores de CUD, para as cinco pressõ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4047', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a317', 'Fitossociologia de plantas espontâneas sob cultivo agroecológico na bananeira no Sertão Paraibano', 'Marilia Hortência Batista Silva Rodrigues; Danielle Maria do Nascimento; Francisco Edu de Andrade; Oscar Mariano Hafle; Ednaldo Barbosa Pereira Junior', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Plantas são organismos sésseis e, portanto, refletem as condições locais. Elas apresentam geralmente maiores níveis de plasticidade fenotípica comparado aos animais, o que significa que efeitos de diversos estressores podem ser mais aparentes e, potencialmente, mais fáceis de serem medidos e quantificados. Este trabalho objetivou realizar um levantamento fitossociológico das espécies de plantas espontâneas presentes no cultivo de diferentes genótipos de banana sob manejo agroecológico no Alto Sertão Paraibano. Foi realizado em uma área experimental de 1.512m2. O espaçamento entre plantas foi de 3x3 m. Para a identificação e quantificação de plantas espontâneas, foi utilizado o método do quadrado inventário. Foram calculados: frequência, frequência relativa, densidade, densidade relativa, abundância, abundância relativa e o índice de importância relativa. Foram identificadas um total de 93 indivíduos correspondentes a 21 espécies, distribuídas em 11 famílias. A área em estudo apresentou', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4221', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a318', 'Avaliação das condições higiênico-sanitárias na comercialização de frutas e hortaliças no município de Manhuaçu, Minas Gerais', 'Dilson Fagundes Ribeiro; Rosane da Silva Rodrigues', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Em feiras livres e supermercados uma ampla variedade de produtos alimentícios processados e in natura são comercializados, entre eles destacam-se frutas e hortaliças. Esses locais têm sido objeto de estudo devido as frequentes más condições higiênico-sanitárias das bancadas, dos utensílios, dos equipamentos e dos manipuladores. O objetivo deste trabalho foi avaliar as condições higiênico-sanitárias da comercialização de frutas e hortaliças em feira livre e supermercados no município de Manhuaçu (MG), tendo como base as recomendações da RDC MS/Anvisa n° 216 de 2004 e a RDC MS/Anvisa n° 275 de 2002. Foi elaborado um questionário estruturado com questões abertas para entrevista com os manipuladores e questões fechadas (checklist) para observações de condições pontuais de higiene nos locais de venda. Foi verificado que tanto na feira livre como nos supermercados haviam diversas inadequações relacionadas às condições higiênico-sanitárias. Portanto, pode-se concluir que nenhum dos estabeleci', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4243', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a319', 'Efeitos da aplicação de bioestimulantes em sementes de algodão', 'Beliza Queiroz Vieira Machado; Adílio de Sá Junior; Gabriel Fernandes Rezende; Larissa Barbosa de Sousa; Regina Maria Quintão Lana', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No Brasil a cultura do algodoeiro é uma das que mais utiliza tecnologia, surgindo a cada ano novas opções que auxiliam na produção, sendo o uso de bioestimulantes uma delas. O objetivo do presente trabalho foi avaliar o efeito do tratamento de sementes de algodoeiro com doses de biorreguladores na germinação e vigor das sementes. O experimento foi conduzido no Laboratório de Análise de Sementes da Universidade Federal de Uberlândia, em delineamento de blocos casualizados, com quatro repetições. Foram realizados cinco tratamentos, sendo eles compostos por 2; 4 e 6 mL kg de sementes-1 do bioestimulante registrado como adubo foliar, 6 mL kg de sementes-1 do bioestimulante regulador de crescimento e 6 mL kg de sementes-1 de água destilada. Avaliou-se a porcentagem de germinação, massa verde de raízes, parte aérea e total, massa seca de raízes, parte aérea e total e comprimento de raiz, parte aérea e total. O produto registrado como adubo foliar na dose de 6 mL kg de sementes-1, apresenta m', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4299', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a323', 'Qualidade de sementes de Lolium multiflorum tetraploide comercializadas em Santa Catarina', 'Ricardo Miotto Ternus; Ana Carolina Weiss; Géri Eduardo Meneghello; Jerffeson Araújo Cavalcante; Paula da Silva Folquini; Jonas Bloemer', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Na região Sul do Brasil, no período do inverno o azevém (Lolium multiflorum Lam) se torna fundamental para a formação de pastagens. No entanto, o uso e a comercialização de sementes de azevém tetraploide têm crescido em relação aos diploides, devido, principalmente, a qualidade superior de suas sementes. O objetivo do trabalho foi avaliar a qualidade das sementes de azevém tetraploide, comercializadas no Estado de Santa Catarina. Foram utilizados seis lotes de sementes de azevém tetraploide da cultivar Barjumbo, oriundos de diferentes estabelecimentos comerciais do Estado de Santa Catarina. Cada lote de semente foi obtido a partir de coleta oficial. Buscaram-se lotes de sementes da categoria certificada, sendo dois lotes de cada país produtor (Argentina, Brasil e Uruguai). Avaliou-se a qualidade física e fisiológica a partir dos testes de pureza física, massa de mil sementes, teste de germinação, primeira contagem de germinação, comprimento da parte aérea e da raiz e massa seca da área', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4630', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a326', 'Irrigação com águas salinas e adubação nitrogenada na produção de mudas mamoeiro “Formosa”', 'Jonathan Estievns Soares Araújo; Sabrina Gomes de Oliveira; Reginaldo Gomes Nobre; Leandro de Pádua Souza; Luana Lucas de Sá Almeida Veloso; Francisco Wesley Alves Pinheiro', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A ocorrência de longos períodos de estiagem e a irregularidade anual das precipitações no Semiárido do Nordeste brasileiro torna a prática da irrigação imprescindível para garantir a produção agrícola com segurança, no entanto, as fontes hídricas disponíveis nem sempre são de boa qualidade. Desta forma, objetivou-se avaliar os efeitos da irrigação com águas de distintos níveis salinos associado a doses de nitrogênio sobre o crescimento de mudas de mamoeiro ''Formosa'' em condições de semiárido nordestino. O experimento foi conduzido em sacolas plásticas sob condições de ambiente protegido no Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal da Campina Grande, campus Pombal- PB. Utilizou-se o delineamento experimental de blocos casualizados, em esquema fatorial 5 x 4, com 4 repetições, sendo os tratamentos compostos de cinco níveis de condutividade elétrica da água – CEa (0,3; 1,1; 1,9; 2,7 e 3,5 dS m-1) e quatro doses de nitrogênio (70, 100, 130 e 160% de N recomendad', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4754', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a328', 'Avaliação das principais causas de perdas pós-colheita de hortaliças comercializadas em Santarém, Pará', 'Antonia Mirian Nogueira de Moura Guerra; Thaís Silva Vieira; Aline Carla de Medeiros; Júlia Batista Azevedo Ferreira; Paula Raniele Freitas Tavares; Ana Cecília Moura Costa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As hortaliças estão sujeitas a diversos tipos de danos após a colheita, ocasionados por condições inadequadas de manuseio, armazenagem, doenças e injúrias mecânicas. Este trabalho teve como objetivo levantar informações sobre as principais causas de perdas pós-colheita em pimentões, batatas e cebolas comercializadas nas feiras e supermercados de Santarém, Pará. O trabalho foi conduzido no comércio varejista, supermercados, Feira da Cohab, Feira do Aeroporto Velho e Mercadão 2000. Os danos nas hortaliças foram avaliados e classificados em: danos fisiológicos, microbiológicos e mecânicos. Em todos os locais avaliados todas as hortaliças apresentaram algum dano, que foi atribuído como responsáveis pelas perdas de forma direta ou indireta. Nas cebolas os principais danos foram: talo grosso, bulbos mal formados, flácidos, descoloridos e brotados. Todos os pimentões avaliados apresentaram formato retangular e cor verde, os principais danos encontrados foram: frutos amassados, apodrecidos, qu', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4809', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a329', 'Infestação do ácaro Varroa destructor em colônias de abelhas africanizadas (Apis mellifera L.) no Semiárido potiguar, Nordeste do Brasil', 'João Paulo de Holanda Neto; Daniel Santiago Pereira; Guilherme Sampaio Queiroz; Hinkley Alcântara de Castro; Eduardo Alves de Souza; Stephano Bismark Lopes Cavalcante Moreira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho teve como objetivo analisar os índices de infestação pelo ácaro Varroa. destructor em colônias de abelhas africanizadas (Apis mellifera) de apiários dos municípios de Encanto e de Marcelino Vieira, estado do Rio Grande do Norte. A pesquisa foi conduzida no período de setembro a dezembro de 2014, sendo coletadas em média de 100 a 200 abelhas adultas (nutrizes) retiradas dos quadros centrais do ninho com crias de cada colmeia, aprisionadas em recipientes contendo 100 mL de álcool a 70% e encaminhadas para laboratório do Instituto Federal do Rio Grande do Norte (IFRN), para a contagem das abelhas e dos ácaros. Os resultados apresentaram ocorrência do ácaro V. destructor em todos apiários e em todas colmeias analisados, obtendo uma infestação média de 7,24% em Encanto e de 5,25% em Marcelino Vieira, níveis de infestação baixos (<15%), portanto, não acarretando risco às colônias.Varroa destructor mite infestation in colonies of Africanized honey bees (Apis mellifera L.) ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4845', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a32c', 'Efeitos da escassez hídrica na economia do perímetro irrigado de São Gonçalo, Paraíba', 'Francisco Edu Andrade; Caio Braga Ferreira; Eliezer da Cunha Siqueira; Maria Candida de Almeida Mariz Dantas; Francisco Guimarães Lopes; Semirames do Nascimento Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A disponibilidade e usos da água na região Nordeste do Brasil, particularmente na região semiárida, continuam a ser uma questão importante no que concerne ao seu desenvolvimento. A população sofre com graves problemas acarretados pela escassez de água, que inviabilizam a produção agrícola e, consequentemente, a sobrevivência em condições dignas, gerando situações de fome e miséria. Objetivou-se identificar os efeitos da escassez hídrica na economia do perímetro irrigado de São Gonçalo no município de Sousa, Paraíba no período de 2012 a 2016. O trabalho foi desenvolvido através da aplicação de questionários com prévio consentimento da população entrevistada residente nos três núcleos habitacionais e no distrito de São Gonçalo. Também foram realizadas visitas ao Departamento Nacional de Obras Contra as Secas e à Agência Executiva de Gestão das Águas do Estado da Paraíba, para coleta de dados sobre a economia do perímetro, informações sobre produção e volumes do açude São Gonçalo. Ocorrer', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5075', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a32f', 'Adubação orgânica e águas de diferentes níveis salinos no cultivo do algodoeiro de fibra colorida', 'Hans Raj Gheyi; Geovani Soares de Lima; Reginaldo Gomes Nobre; Leandro de Pádua Souza; Anderson Bruno Anacleto de Andrade; Lauriane Almeida dos Anjos Soares', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No semiárido a ocorrência de longos períodos de estiagem vem tornado a irrigação uma pratica indispensável para exploração agrícola. Desta forma objetivou-se, com esta pesquisa, avaliar o crescimento e a produção de do algodoeiro cv. BRS Jady irrigado com águas de distintos níveis de salinidades e doses de matéria orgânica. O experimento foi conduzido utilizando-se um Neossolo Regolítico Eutrófico de textura franco arenosa no município de Campina Grande-PB. Adotou-se o delineamento experimental de blocos ao acaso, em esquema fatorial 4 x 4, com três repetições, cujos os tratamentos resultaram da combinação de quatro níveis de condutividade elétrica da água (CEa) (1,7; 3,4; 5,1 e 6,8 dS m-1) e quatro doses de matéria orgânica (0; 2,5; 3,5 e 4,5% em base do volume do solo). A irrigação com água salina de CE a partir 1,7 dS m-1 afetou negativamente o crescimento e a produção do algodoeiro cv. BRS Jady, provocando reduções no diâmetro de caule, altura de planta, área foliar, fitomassa seca', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5276', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a330', 'Florística, fitossociologia e estrutura diamétrica de um remanescente florestal no município de Gurupi, Tocantins', 'Priscila Bezerra de Souza; Rômullo Quirino de Souza Ferreira; Marcos Alberto Francisco de Carvalho; Paulo Abdala Bittar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se conhecer a composição florística e fitossociológica da formação florestal cerradão, domínio do Cerrado, Gurupi no estado de Tocantins. Foram demarcadas 2 parcelas de 20x50m2 cada nas quais foram registrados todos os indivíduos arbustivo-arbóreos com circunferência do tronco ≥ a 15 cm, na altura de 1.30m do solo. Os dados coletados foram analisados utilizando os softwares Microsoft Office Excel e Fitopac versão 2.1.2. Foi realizada análise dos valores absolutos e relativos de densidade, frequência, dominância e valor de Importância (VI), Índice de diversidade de Shannon (H’) e equabilidade de Pielou (J’). Foram amostrados 142 indivíduos, destes 133 indivíduos vivos e 9 mortos em pé, distribuídos em 26 espécies e 17 famílias, além do grupo das mortas e uma família indeterminada. A densidade total foi de 710 plantas/hectare-1, com área basal total de 6,787 m²/ha-1. A espécie mais abundante foi Tapirira guianensis (37 Ind. 26 %.). Os indivíduos das espécies Copaifera langsdorf', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3797', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a333', 'Produtividade de tomate orgânico cultivado em diferentes ambientes e níveis de insumos', 'Sebastião Elviro Araújo Neto; Antônio Carlos Simões; Regina Lúcia Félix Ferreira; Gisley Karoline Emerick Bitancourt Alves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A importância alimentar do tomate orgânico aliado a sua baixa produção na Amazônia e a necessidade de baixo uso de insumos para seu cultivo ecológico o objetivo deste trabalho foi avaliar a produtividade de cultivares de tomate orgânico cultivado em campo e ambiente protegido com alto e baixo nível de insumos. Os experimentos foram conduzidos em ambiente protegido e campo, ambos no delineamento em blocos casualizados completos, em esquema de parcelas subdivididas 2 x 3, sendo a parcela principal composta por dois níveis de insumos e a subparcela pelas cultivares copa (Santa Kruz Kada, IPA 6 e Santa Clara), com cinco repetições de cinco plantas cada. As variáveis avaliadas foram: massa média de frutos total e comercial (g fruto-1), número de frutos total e comercial por planta, produtividade total e comercial de frutos (kg ha-1). A cultivar IPA 6 em cultivo protegido exigiu maior uso de insumos para aumentar a massa média de fruto total e comercial, produtividade total e comercial, em c', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3964', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a334', 'Redução da captação de água e estimativa de tempo para sangramento no açude Sumé no Estado da Paraíba', 'Jean Pereira Guimarães; Mayra Gislayne Melo de Lima; José Dantas Neto; Dalva Damiana Estevam da Silva; Samuel Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O açude Sumé, nos últimos anos, teve seu volume de água reduzido drasticamente devido a problemas de planejamento e gestão dos recursos hídricos em sua bacia hidrográfica. Assim, para se determinar medidas na melhoria do escoamento hídrico até ao açude e aumento do seu volume armazenado. Objetivou-se realizar um estudo de redução da captação de água do açude e estimando o tempo necessário para o sangramento. Para isso, foi realizada uma simulação das entradas de água no reservatório através do escoamento na bacia e das saídas através da evaporação e abastecimento urbano. Foi utilizado o coeficiente de escoamento para a situação atual da bacia (5%) e com aumento de 1% no mesmo. Observou-se que a redução semanal do abastecimento de água para a cidade de Sumé não é suficiente para o aumento do volume hídrico no açude, sendo a economia anual equivalente a 2% do volume atual. Com o escoamento na bacia de 5%, são necessários 34 anos para ocorrer o sangramento. Porém, se medidas de melhorias ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4102', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a339', 'Avaliação do bagaço de cana natural e modificado como potencial sorvente de óleo vegetal', 'Vanessa Soares dos Santos; Viviane Vasques da Silva Guilarduci; Patrícia Benedini Martelli; William Graciliano Corrêa; Honória Fátima Gorgulho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O óleo e a gordura vegetal residual, utilizados para a preparação de alimentos representam um perigoso poluente para as águas de córregos e rios. Um dos métodos mais utilizados nas últimas décadas para limpeza da água oleosa é a aplicação de biossorventes, pois apresentam facilidade para remoção e recuperação do óleo. Neste sentido, o objetivo deste trabalho foi determinar a influência das modificações do bagaço de cana com anidrido acético (acetilação) e com 3-aminopropiltrietoxisilano (silanização) sob a sorção de óleo vegetal. A modificação das fibras foi avaliada pelas técnicas de espectroscopia no infravermelho com transformada de Fourier (FTIR), análise termogravimétrica (TG), difração de raios X, microscopia eletrônica de varredura (MEV) e análise de área superficial e porosidade. Os resultados obtidos indicaram maior sorção de óleo vegetal para o bagaço de cana modificado com anidrido acético (BCA), 667 mg.g-1, seguido pelo bagaço de cana sem modificação (BCN) com sorção de 576', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4172', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a33f', 'Teor e acúmulo de micronutrientes em gérbera de vaso em função de fontes e doses de potássio', 'Fernanda Ludwig; Guilherme Amaral Ferreira; Amaralina Celoto Guerrero; Dirceu Maximino Fernandes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Estudos sobre absorção de nutrientes através da análise mineral em determinados estádios fenológicos e órgãos amostrados, colaboram para eficiência da nutrição das espécies, predizendo os nutrientes mais absorvidos e também a época de maior exigência nutricional. O objetivo desse trabalho foi avaliar o teor e acúmulo de micronutrientes em gérbera nos períodos vegetativo e reprodutivo, conduzidos com o uso de concentrações e fontes de potássio na solução nutritiva. O experimento foi conduzido em casa de vegetação do DRN/Ciência do Solo, da Faculdade de Ciências Agronômicas da UNESP, Botucatu (SP). O delineamento experimental adotado foi o de blocos casualizados, em esquema fatorial 2x5 (duas fontes e cinco doses de potássio), quatro repetições e cinco plantas por parcela. As fontes utilizadas foram o cloreto e o silicato, aplicados nas doses de 0, 50, 100, 150 e 200 mg L-1 de potássio. A cultivar de gérbera utilizada foi a Red. De forma geral o silicato de potássio promoveu maior teor e', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4461', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a340', 'Analysis of the correlation between different forms of access to water and cases of gastroenteritis hospitalization in the territory of Médio Piranhas, Paraíba State, Brazil', 'Virgínia de Fátima Bezerra Nogueira; Jéssica de Andrade Gomes Silva; Kevison Romulo da Silva França; Sayonara Costa de Araújo; José Adalberto da Silva Filho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Drinking water has a direct influence on people''s well-being, since this resource can transmit various diseases. This research proposes the diagnosis of access to water in the territory of Médio Piranhas, located in semiarid portion of Paraíba State, Brazil. The premise is based on the number of gastroenteritis hospitalization accounted for the Department of Health System Information. The authors selected the municipalities and collected secondary data from the Brazilian Institute of Geography and Statistics. The paper became evident the relationship between the form of access to water and the cases of gastroenteritis hospitalization. The results indicated that 71,75% of residences in the territory receive a water supply service. It was also observed 2.725 cases of gastroenteritis hospitalizations between 2010 and 2015, which provided a correlation of approximately 39%, showing that more investments in infrastructure need to be made in order to improve the health and well-being of the ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4469', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a343', 'Riscos e acidentes entre trabalhadores rurais de usina na região da mata norte do estado de Pernambuco', 'Carla Heloisa de Alencar Figueiredo; Henrique Miguel de Lima Silva; Symara Abrantes Albuquerque de Oliveira Cabral; Cicero Fabiano da Silva; Elinalva Francisca de Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A ação repetitiva e o esforço físico podem provocam acidentes como os cortes, quedas, torções, causarem problemas nas colunas e pés, além de cãibras e tendinites. Diante deste cenário, o presente estudo  objetivou analisar os riscos  que ocasionam  acidentes de trabalho numa área de usina de açúcar e álcool na Zona da Mata Norte do Estado de Pernambuco.  Foram analisados através de pesquisa de campo de caráter quantitativa, por amostragem com aplicação de um questionário, com aspectos investigativos, os tipos de acidentes com maiores frequências, gravidades e quantos dias que este acidente afastou o trabalhador de sua atividade laboral, para assim, compreender e prevenir esses riscos que se acentuam nos canaviais,. Os trabalhadores recebem os EPI’s, mas não os usam corretamente, utilizando pedra de esmeril para amolar o facão de forma insegura, causando ferimento na mão, dependendo da gravidade o trabalhador pode ficar em media de 7 a 10 dias afastado. É organizada uma força tarefa no ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4510', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a344', 'Acúmulo e translocação de cobre e zinco em plantas de Crambe abyssinica', 'Ana Carolina Feitos de Vasconcelos; Gilvanise Alves Tito; Lúcia Helena Garófalo Chaves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Crambe (Crambe abyssinica) é uma cultura promissora para a produção de biodiesel. No entanto, não há muita informação disponível sobre as técnicas e pesquisas sobre o melhor desempenho em diferentes regiões para explorar o seu potencial. Objetivou-se avaliar o efeito de cobre e zinco no acúmulo e distribuição destes elementos nesta planta. O estudo foi realizado em casa de vegetação e constou de dois experimentos independentes, em delineamento experimental inteiramente casualizado, com três repetições. Em um deles, os tratamentos consistiram em cinco doses de cobre, ou seja, 0, 10, 15, 20 e 25 mg kg-1 e no outro , cinco doses de zinco, 0, 20, 30, 40 e 50 mg kg-1. Após 100 dias de germinação as plantas foram colhidas e avaliadas os níveis de cobre e zinco em tecidos de plantas. Os dados foram submetidos à análise de variância e comparação de médias pelo teste de Tukey a 1 e 5% de significância. Os teores de cobre e zinco aumentaram significativamente na fitomassa do crambe em função da ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4539', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a347', 'Qualidade da carcaça bovina comercializada no município de Assunção, Paraíba', 'Wellinghton Alves Guedes; Elisândra Costa Almeida; Josineide de Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se estudar a qualidade da carcaça bovina comercializada no município de Assunção na região do Cariri paraibano, onde se verificou os fatores que influenciam a qualidade da carne, desde as condições antes, durante e depois do abate, bem como a comercialização, e a higiene-sanitária, através dos procedimentos metodológicos: entrevistas com os comerciantes, visitas aos abatedouros e pontos comerciais, além de análise microbiológica das carnes, fazendo a comparação da carne comercializada na feira livre e no açougue. Os resultados obtidos apontaram que vários motivos levam os consumidores a adquirir a carne nesses pontos comerciais, como forma de pagamento, preço, conhecimento da origem e abate do animal, qualidade, falta de opção, entre outros, havendo destaque para o preço na feira livre (29%) e a forma de pagamento no açougue (27%). Na entrevista com os consumidores, a carne foi classificada como boa, regular e ruim; sendo que 60% dos consumidores (açougue) e 42% (feira livre)', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4554', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a34a', 'Avaliação sensorial, microbiologia e físico-química de suco artificial de laranja adicionado de diferentes agentes adoçantes', 'Franciely Kelly Pereira; Iago Felipe da Silva Leite; Fernanda Gomes de Farias; Bruna Maria Alves Alixandre; Thauan da Costa Moura', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Diante do aumento do consumo de adoçantes por vários fatores e a procura por uma dieta mais saudável,  para a redução dos riscos de doenças como, diabetes, obesidade, entre outras, este trabalho teve como objetivo avaliar a diferença da doçura e aceitação dos diferentes agentes adoçantes em sucos artificiais. Foram formulados sucos em pó sabor laranja e adicionado os diferentes agentes adoçantes (sacarose, demerara, stevia pura, sacarina sódica + ciclamato de sódio e sacarina sódica + ciclamato de sódio + stevia). Realizou-se analises de pH e de sólidos solúveis totais (ºBrix) para as diferentes formulações, ocorrendo variações, além das análises microbiológicas para coliformes totais e Salmonella sp/25g, resultando em ausência para ambos Os resultados apontam que as amostras estão próprias para consumo segundo a legislação virgente. A análise foi aplicada no laboratório de análise sensorial da Universidade Federal de Campina Grande e avaliada por 93 provadores. Aplicou-se uma ficha se', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4626', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a34d', 'Fitomassa e produção de algodoeiro cv. BRS Jady cultivado com águas salinas e doses de esterco bovino', 'Hans Raj Gheyi; Geovani Soares de Lima; Reginaldo Gomes Nobre; Leandro de Pádua Souza; Anderson Bruno Anacleto de Andrade; Lauriane Almeida dos Anjos Soares', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A produção de algodoeiro de fibra naturalmente colorido, na região semiárida do nordeste brasileiro, onde as águas nem sempre são de boa qualidade, está na dependência do uso de técnicas que viabilizem o manejo do solo e da água com teor elevado de sais. Diante do exposto, objetivou-se avaliar fitomassa e produção do algodoeiro cv. BRS Jady submetido a níveis crescentes de salinidade da água de irrigação e doses de esterco bovino. O experimento foi conduzido em ambiente protegido em um Neossolo Regolítico Eutrófico de textura franco-arenosa no município de Campina Grande, Paraíba. Usou-se o delineamento experimental de blocos ao acaso, em esquema fatorial 4 x 4, com três repetições, sendo os tratamentos compostos de quatro níveis de condutividade elétrica da água (CEa) (1,7; 3,4; 5,1 e 6,8 dS m-1) e quatro doses de esterco bovino (0; 2,5; 3,5 e 4,5% em base do volume do solo). Níveis crescentes de salinidade da água de irrigação com CEa superior a 1,7 dS m-1 reduziu a formação de fitom', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5277', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a350', 'Avaliação de diferentes hipsômetros na estimativa da altura total', 'Marya Eduarda Feliciano; Paula Carolina Gomides Vitor; Andressa Ribeiro; Antonio Carlos Ferraz Filho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se neste trabalho avaliar a acurácia de diferentes hipsômetros: Blume Leiss [BL], Suunto [ST], Relascópio [RL], Vertex [VX], Haga [HG] e TruPulse [TP] para a medição de altura. Os dados foram coletados em varas telescópicas (A, B e C com 4,45; 10,75 e 7,8 m, respectivamente) por treze observadores. As alturas medidas foram avaliadas por meio de uma análise de variância em um delineamento em blocos casualizados, e as médias comparadas pelo teste de Tukey. Também foi utilizado o Teste t (99% de significância) para comparar a igualdade entre a altura total real de cada vara e as alturas medidas com os hipsômetros. Os resultados mostraram que apenas o RL foi diferente dos demais hipsômetros quando avaliados conjuntamente. Os hipsômetros VX, HG e BL apresentaram os melhores resultados em todas as análises, apresentando alta semelhança à altura real.Assessing different hypsometers to estimate total heightAbstract: This study aimed to assess the accuracy of different hypsometers: Bl', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3741', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a351', 'Construção e resgate do saber sobre a agroecologia através de metodologias de intervenção no processo pedagógico', 'Cleberton Correia Santos; Jéssica Oliveira Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Na busca de um desenvolvimento sustentável, a Agroecologia é uma ciência que articular todos os recursos presentes no ambiente. Porém, muitos ainda desconhecem a mesma, sendo de suma importância sua difusão através de concepções pedagógicas. Desta forma, objetivou-se com este trabalho articular o diálogo de saberes e práticas com estudantes do ensino médio sobre a temática “sustentabilidade e desenvolvimento local”. O trabalho foi realizado com alunos de escola pública (Escola Estadual Professora Eufrosina Pinto) no ano de 2013 por acadêmicos do curso de Tecnologia em Agroecologia da Universidade Estadual de Mato Grosso do Sul (UEMS)/Unidade Universitária de Glória de Dourados. As metodologias utilizadas foram baseadas nas concepções pedagógicas piagetianas (Jean Piaget) norteadas pelo construtivismo e fundamentos teóricos, e freirianas (Paulo Freire), aprimorados a partir da educação popular emancipadora. Os relatos foram anotados m um caderno, seguido da observação participante. A ma', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3944', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a353', 'Percepção entomológica de alunos do ensino médio em escolas da cidade de Patos, Paraíba, Brasil', 'William de Sousa Santos; Rozileudo da Silva Guedes; Felipe Silva de Medeiros; Walleska Pereira de Medeiros; Átila Bruno de Moraes Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os insetos são responsáveis por importantes atividades para o homem e os ecossistemas. No entanto, eles geralmente são associados principalmente aos danos ou prejuízos causados ao homem. O objetivo desse estudo foi analisar a percepção entomológica de alunos do ensino médio da cidade de Patos, Paraíba. Para isso foram aplicados questionários semiestruturados contendo questões sobre os insetos, durante o mês de agosto de 2012. Foram entrevistados 316 alunos, sendo 190 de escolas particulares e 126 de públicas. Do total de entrevistados 62,4% foram do sexo feminino e 37,5% masculino. 56,3% responderam acertadamente que os insetos pertencem ao filo Arthropoda, 37% que possuem 3 pares de pernas e 78,2% que podem ser reconhecidos pelo número de pernas, pela presença de antenas e de olhos. Para 82,6% dos entrevistados os insetos possuem importância positiva e negativa. Alimento para outros seres vivos e transmissão de doenças as mais assinaladas com 20,3% e 25,8% respectivamente. Dos animais', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3975', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a354', 'El Niño/La Niña e sua influência no número de dias com chuva em Bom Jesus – Piauí, Brasil', 'Virgínia Mirtes de Alcântara Silva; Francisco de Assis da Costa Neto; José Ivaldo Barbosa de Brito; Raimundo Mainar Medeiros; Valneli da Silva Melo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Em Bom Jesus, as características da variabilidade temporal da precipitação são provenientes de diversos sistemas meteorológicos atuantes. É comum a ausência de chuvas durante períodos prolongados, ocasionando graves problemas para a sociedade, agropecuários e nos ecossistemas naturais. Objetiva-se analisar a relação entre o número de dias com chuva e a precipitação no município em estudo compreendido entre o período de 1960-2014 e suas influencias entre os fenômenos Niño(a), utilizou-se dos dados diários de precipitações dos anos de 1960 a 2014 fornecido pela Superintendência do Desenvolvimento do Nordeste (SUDENE) e pela Empresa de extensão rural do Estado do Piauí (EMTERPI). A utilização do pacote estatística em planilhas eletrônicas para elaboração de gráficos com a variabilidade mensal dos dias com ocorrências de chuvas (DCC). Além dos dados citados, foram usados os dados de intensidade do fenômeno ENOS, obtidos do Serviço Climatológico Nacional dos Estados Unidos - NOAA referente ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3993', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a355', 'Combinação de métodos paramétricos e não-paramétricos para estudo da estabilidade de cultivares de soja no Cerrado Tocantinense', 'Alex Sandro Dario; Helio Bandeira Barros; Lucas Antonio Lampert Vicentino; Rodrigo Ribeiro Fidelis; Aristoteles Capone', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com esse estudo avaliar a viabilidade da combinação de métodos paramétrico e não-paramétricos para inferir acerca da estabilidade de cultivares de soja no cerrado tocantinense. Para isso utilizou-se os dados de ensaios de competição conduzidos em quatro ambientes nas safras de 2009/10 e 2010/11 e na entressafra de 2010. Utilizou-se o delineamento em blocos casualizados com quatro repetições. As estimativas de estabilidade foram obtidas pelo método paramétrico sugerido por Livorenti e Matsuoka e pelos métodos não-paramétricos propostos por Huenh e Fox. Pelo método paramétrico, os cultivares M8766, M9056, P98Y70RR, M9144RR, JulianaRR e BRS8560RR acumularam o maior número de sinais positivos nos ambientes avaliados, sendo que os dois últimos apresentaram sinal negativo em um ambiente. Pela metodologia não-paramétrica foram discriminados como produtivos e estáveis apenas os quatro primeiros cultivares. Neste sentido, houve concordância na discriminação de cultivares produtivos', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4011', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a357', 'Uso eficiente da água de chuva armazenada em cisterna para produção de hortaliças no Semiárido pernambucano', 'Elvis Pantaleão Ferreira; Fernando Cartaxo Rolim Neto; Luiza Teixeira de Lima Brito; Nilton de Brito Cavalcanti; Tarcizio Nascimento', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O Semiárido brasileiro requer uma particular atenção, dada à irregularidade das precipitações pluviométricas que ocorrem na a região. A cisterna tipo Calçadão do programa Uma Terra e Duas Águas – P1+2 assegura melhoria na dieta alimentar das famílias rurais, por permitir a inserção de alimentação. Com o presente trabalho objetivou-se avaliar o uso eficiente da água empregada sob diferentes lâminas durante todo o ano de 2014, visando a produção de hortaliças no Semiárido pernambucano, com água de chuva armazenada em cisterna do P1+2. Para tanto, foram construídos dois canteiros, denominados 1 e 2, cada um com área de 4 m2, para produção de hortaliças, sendo aplicadas, respectivamente, lâminas de 8 mm dia-1 e 4 mm dia-1, durante todo o ano. Á água foi aplicada de forma manual, utilizando-se regador plástico. A melhor relação água/produção foi obtida com a aplicação de uma lâmina de 4 mm dia-1, suficiente para proporcionar o consumo diário de 33,71 gramas de hortaliças na alimentação de u', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4035', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a35c', 'População de plantas e desempenho produtivo de híbridos de milho oriundos de sementes com diferentes níveis de vigor', 'Sandro de Oliveira; Lilian Madruga Tunes; Géri Eduardo Meneghello; Jerffeson Araújo Cavalcante; Danilo Henrique Rodrigues da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As relações entre o vigor e desempenho de sementes são bastante contraditórias. Para espécies produtoras de grãos e hortaliças, os efeitos do vigor da semente podem ser expressos na emergência, no crescimento inicial, e no desenvolvimento, com impactos na produtividade final. No entanto, o dimensionamento desta persistência pode não ser evidente em todas as fases, sendo mais comum na emergência. Assim, objetivou-se avaliar os efeitos do vigor de sementes de milho no estabelecimento e desempenho produtivo dos híbridos 502 e 810. O experimento foi conduzido na Fazenda Rancho Alegre, em Itiquira, Mato Grosso (520 m de altitude). Empregou-se o delineamento em blocos ao acaso, em esquema fatorial 2×3, sendo dois híbridos de milho (BM502 e BM810) e três níveis de vigor (alto, médio e baixo), com quatro repetições. A semeadura foi realizada com semeadora manual a 2,5 cm de profundidade e com espaçamento de 0,5 metros entre linhas. As parcelas foram constituídas por 6 linhas de 5 m, sendo que ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4173', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a362', 'Seleção de cultivares de cana-de-açúcar para a Zona da Mata Norte de Pernambuco III: Final de safra', 'Aurélia Pietrina da Costa Albuquerque; Patricio Borges Maracajá; Djalma Euzébio Simões Neto; Gerson Quirino Bastos; Lauter Silva Souto; João de Andrade Dutra Filho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Sendo os cultivares melhorados a base de sustentação e desenvolvimento do setor sucroeneregético no Brasil, objetivou-se com este trabalho avaliar o desempenho agroindustrial de 26 cultivares de cana-de-açúcar na microrregião canavieira da Mata Norte de Pernambuco. O experimento foi conduzido na área agrícola da Usina Olho D’água, onde foi utilizado o delineamento experimental em blocos casualizados com quatro repetições. As variáveis analisadas foram: toneladas de pol por hectare, toneladas de cana por hectare, fibra, pol % corrigida, pureza, teor de sólidos solúveis e açúcar total recuperável. Realizou-se a análise de variância conjunta dos experimentos e estimativa de parâmetros genéticos, as médias foram agrupadas pelo teste de Scott e Knott ao nível de 5% de probabilidade. Realizou-se ainda a rentabilidade econômica bruta de cada cultivar.  Constatou-se que a seleção de cultivares superiores deve ser baseada nas variáveis TPH e TCH. Como opções de cultivo comercial para a terceira', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4266', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a36b', 'Qualidade de águas residuárias e salobra utilizadas no cultivo hidropônico de três cultivares de alface crespa', 'Márcia Rejane de Queiroz Almeida Azevedo; Carlos Alberto Vieira de Azevedo; Antônio Fernandes Monteiro Filho; Josilda de França Xavier; José Emídio de Albuquerque Júnior', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O reúso de efluentes tratados não é uma prática nova, no entanto, há um interesse crescente em relação à necessidade de sua reutilização. Objetivou-se avaliar a caraterização das águas residuárias domestica e do reator UASB e água salobra de poço para o cultivo hidropônico de alface crespa. O experimento foi conduzido em ambiente protegido com sistema hidropônico. Delineamento experimental foi em blocos casualizados com esquema fatorial 7 x 3, três repetições sendo, 7 soluções hidropônicase três cultivares de alface. A parcela experimental, S1=solução de Furlani; S2=água residuária domestica; S3=água residuária domestica otimizada; S4=água de poço; S5=água de poço otimizada; S6=água residuária (UASB) e S7=água residuária (UASB) otimizada, subparcela três cultivares de alface. O pH das águas residuárias foram de 7,7 e 7,4 (Poço); 7,4 e 8,0 (Esgoto bruto) e, 7,2 e 8,2 (Extrabes). A (CE) foram 0,957 e 1,002 (Poço); 2,133 e 2,368 (Esgoto bruto) e (Extrabes) 2,502 e 2,4 09 dS m-1. O uso de ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4569', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce75', 'Biofertilizante como bioestimulante na germina??o de feij?o de porco', 'Lima, Juliana Ferreira de; Costa, Jefferson Santos Alves da; Monteiro, Shirley Santos; Santos, Dualyson da Silva; Monteiro, Sh?nia Santos', 'Editora Verde', 'Agriculture', 'Agriculture', 'O biofertilizante surge como uma alternativa para substitui??o do uso de estimulante sint?tico por agricultores familiares em sementes de feij?o de porco. Esses s?o utilizados em cultivares agr?colas proporcionando maior vigor das pl?ntulas. Neste contexto, objetivou-se avaliar as concentra??es de biofertilizantes como bioestimulante na germina??o de feij?o de porco O delineamento experimental adotado foi o inteiramente casualizado, em esquema fatorial 2 x 5, referente a dois tipos de biofertilizantes (a base de esterco bovino e a base de res?duo de frutas) e cinco concentra??es de biofertilizantes (0; 25%; 50%; 75% e 100%) em imers?o por 10 minutos. Avaliou-se o ?ndice de velocidade de germina??o, germina??o total, comprimento de raiz prim?ria e hipoc?tilo, largura e comprimento de cotil?dones e mat?ria fresca e seca da raiz, hipoc?tilo e cotil?dones. O uso do biofertilizante a base de res?duo de frutas estimulou o ?ndice de velocidade de germina??o, germina??o, raiz prim?ria, mat?ria', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce75', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce77', 'Can higher CO2 concentrations affect yield and quality parameters in lettuce and sugar beet crops?', 'Velasquez-Vasconez, Pedro Alexander; Eraso, Hugo Ruiz; Velasquez-Vasconez, Maria; Cardenas, Cristian; Skarsgard, Oyvin Nyheim', 'Editora Verde', 'Agriculture', 'Agriculture', 'It has been suggested that the increase in CO2 levels in the coming decades will have positive consequences on the nutritional content and yield of agricultural crops. However, the effects of the increase in CO2 concentrations remain little known in Andean region. This study evaluated the effect of increased CO2 on the protein content and growth of sugar beet and lettuce plants in the Andean region of Colombia. We used a Randomized Complete Block Design, strip 1 was open field, strip 2 was low tunnel with ambient CO2 and strip 3 was low tunnel with 1000 ppm CO2. The sugar beet experiment three harvest periods were evaluated. The results indicated that CO2 fertilization did not have a significant effect on the yield and head diameter of the lettuce. However, biomass production tended to increase in the first sugar beet harvest but decreased significantly in the last two harvests, probably due to a negative effect caused by acclimatization to CO2 enrichment. The protein content was not a', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce77', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce7a', 'Conhecimento popular sobre plantas medicinais em comunidades rurais do Munic?pio de Laranjeiras do Sul, Paran?', 'Glowka, Karen Karoline de Oliveira; Marques, Siomara Aparecida; Moura, Gabriela Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'Esta pesquisa teve como objetivo resgatar o saber popular sobre as plantas medicinais utilizadas para a promo??o da sa?de e da agroecologia no munic?pio de Laranjeiras do Sul ? Paran?. Foi realizado um estudo etnobot?nico de abordagem quantitativa, seguindo o m?todo descritivo, a partir de uma pesquisa de campo com agricultores das comunidades Passo Liso, Rio do Tigre e Rio Verde, situadas nesse munic?pio, entre os meses de novembro de 2018 ? janeiro de 2019, por meio de visitas pr?-agendadas e acompanhadas pelo Agente Comunit?rio de Sa?de (ACS) da respectiva comunidade. Os dados foram obtidos com dezesseis fam?lias na comunidade de Passo Liso, dezenove fam?lias na comunidade Rio Verde e quinze fam?lias na comunidade Rio do Tigre, totalizando 50 fam?lias de agricultores, indicados aleatoriamente pelo ACS da micro?rea correspondente ? Unidade de Sa?de do SUS. Os resultados mostraram que 100% dos agricultores utilizam plantas medicinais para tratar sintomas de doen?as, e possuem essas pl', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce7a', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce7c', 'Din?mica socioecon?mica da folha de ?bijao?, uma embalagem artesanal e respons?vel, marcada pela sustentabilidade', 'Medina Rojas, Iv?n Dar?o; Higuera Mora, Nubia Carolina; Mart?nez Izquierdo, Juan Felipe; Rodr?guez Rodr?guez, Mayra Alejandra', 'Editora Verde', 'Agriculture', 'Agriculture', 'A cadeia de valor atua como um catalisador para as rela??es entre os agentes que interagem a fim de perseguir objetivos comuns. Dentro do presente estudo, se realiza uma aproxima??o a um elo na produ??o do ?bocadillo vele?o?, que recebeu recentemente a denomina??o de origem e por isso, a prote??o contra imita??es ou produtos similares que s?o elaborados fora do ambiente que inclui a ?rea geogr?fica de interesse: os munic?pios de V?lez, Barbosa, Moniquir?, Puente Nacional e Guavat?, onde est?o localizados produtores de goiaba, e processadores de folhas de ?bijao? (Calathea lutea (Aubl.) E. Mey. ex Schult.), embalagem do produto, tema central deste artigo, e ?bocadillo vele?o? como produto final. O estudo contempla uma amostra de 16 propriedades onde o ?bijao? ? produzido, localizadas no munic?pio de Moniquir? (Boyac?, Col?mbia), e que possuem ou tiveram algum tipo de rela??o com a ?Associa??o dos Bijaeros da Prov?ncia de Ricaurte? (ASOBIJAO), associa??o que re?ne os produtores da folha,', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce7c', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce80', 'Caracteriza??o biom?trica e supera??o de dorm?ncia de sementes de Pithecellobium diversifolium Benth.', 'Pereira, Dalbert de Freitas; Veloso, C?ssio Laurentino; Oliveira, Jailson de; Marques, F?bio Jos?; Nascimento, Denisson Lima do; Lima, Cosmo Rufino de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Pithecellobium diversifolium Benth. ? um arbusto nativo com vasta ocorr?ncia nos estados do Nordeste brasileiro. O crescente interesse na propaga??o e no cultivo de esp?cies florestais nativas demanda informa??es b?sicas sobre as caracter?sticas biom?trica e germinativas das suas sementes para sua propaga??o. Com isso, o objetivo do trabalho foi caracterizar as sementes e avaliar o processo germinativo de P. diversifolium submetidos a m?todos de supera??o de dorm?ncia. O experimento foi conduzido no Laborat?rio de Produ??o Vegetal do Instituto Federal de Alagoas, localizado no munic?pio de Piranhas-AL, onde foram coletadas as sementes. Foi realizada a caracteriza??o f?sica das sementes, determinando-se o teor de ?gua, o peso de 1.000 sementes, e o comprimento, largura e espessura das sementes. Foram utilizados cinco tratamentos para supera??o de dorm?ncia: (T1) intactas; (T2) escarifica??o mec?nica com lixa d??gua n? 80; (T3) fragmenta??o do tegumento; (T4) imers?o em ?gua a 90 ?C por ', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce80', NULL, 'English', 'published', false, false, 'open', 'pdf')
