INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce86', 'Suplementa??o com Salvinia auriculata reduz os efeitos delet?rios do estresse h?drico em pl?ntulas de girassol', 'Ferreira, Gabriela de Sousa; Brito, Paulo Ov?dio Batista de; Souza, Janacinta Nogueira de; Gondim, Franklin Arag?o; Matias, L?gia Queiroz; Arruda, Julyanne Fonteles de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A baixa disponibilidade h?drica em regi?es semi?ridas afeta o desenvolvimento e a produtividade das culturas agr?colas. O trabalho analisou os efeitos da aplica??o da Salvinia auriculata como suplemento no crescimento e nas atividades das enzimas antioxidativas: super?xido dismutase, catalase, peroxidase do ascorbato e peroxidase do guaiacol em folhas e ra?zes de pl?ntulas de girassol submetidas ?s condi??es de estresse h?drico. O delineamento experimental foi inteiramente casualizado, disposto em arranjo fatorial 2x3, sendo dois sistemas de irriga??o (irrigadas e n?o irrigadas) x tr?s substratos (areia; areia + h?mus comercial 80 kg N ha-1; areia + Salvinia auriculata 120 kg N ha-1), com oito repeti??es. A suplementa??o com Salvinia auriculata proporcionou maiores incrementos na altura, n?mero de folhas e massa fresca total. Al?m disso, houve aumentos nas atividades das enzimas antioxidativas em folhas e ra?zes de pl?ntulas de girassol, deduzindo-se que a suplementa??o com a macr?fita', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce86', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce87', 'Lanthanum in vitro control of Alternaria solani and induction resistance mechanism against blight tomato plant', 'Oliveira, Juliana Santos Batista; Cesnik, Sergio Augusto; Schwan-Estrada, K?tia Regina Freitas; Solino, Ant?nio Jussi? da Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'Rare earth elements have been tested in control of plant diseases. Lanthanum (La) was tested in the control of Alternaria solani (in vitro) and tomato early blight (in vivo) using the concentration 0; 0.1; 0.2; 0.4 and 0.8 g L-1. In vitro, the concentration were diluted in V8 culture medium and evaluated for mycelial growth rate index (MGRI) and pathogen sporulation. In vivo, 24 hours after the application of concentration was inoculate the pathogen and 24 hours after the inoculation, leaflets were collected for quantification, the specific catalytic activity and guaiacol peroxidase. The severity of tomato early blight were also analyzed. As 0.27 and 0.28 g L-1 reduces 28% and 50% the MGRI and the sporulation, respectively. Peroxidase and catalase activity was increased by 298% and 151% in tomato treated with 0.5 and 0.4 g L-1de La, respectively. In vivo reduces AUDPC 70% when was applied 0.27 g L-1 La. Lanthanum can be used as resistance inducer in controlling tomato early blight.', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce87', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce8d', 'Estrat?gias de comercializa??o do ?Fub? da Paix?o? produzido no Polo da Borborema, Para?ba', 'Brito, Al?cia Nayana dos Santos Lima de; Santos, Isleno Michel de Sousa; Silva, Patr?cia Ferreira da; Laurentino, Laysa Gabryella de Souza', 'Editora Verde', 'Agriculture', 'Agriculture', 'As estrat?gias de marketing s?o fundamentais em qualquer empreendimento e trata-se de todas as a??es que ser?o utilizadas para divulgar uma marca, produto ou servi?o e, consequentemente, atrair mais clientes. O objetivo deste trabalho foi analisar estrat?gias de comercializa??o do fub? da paix?o produzido com sementes crioulas. Utilizou-se como m?todo a pesquisa de campo, onde a coleta de dados foi realizada atrav?s de visitas e aplica??o de entrevistas semiestruturadas aos agricultores(as)/feirantes da Feira Agroecol?gica do mun?cipio de Rem?gio, Para?ba. Os produtos derivados do milho livre de transg?nico est?o atraindo diversos consumidores conscientes e sua comercializa??o estimula a amplia??o do plantio de milho no territ?rio da Borborema. Por?m, ainda se restringe apenas as cidades circunvizinhas ao Polo da Borborema envolvidas nessa atividade, necessitando da ado??o de estrat?gias que amplie as oportunidades de gera??o de renda das fam?lias agricultoras, como maiores investiment', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce8d', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce93', 'Moscas-das-frutas (Diptera: Tephritidae) associadas com mangueiras no Serid? Oriental da Para?ba', 'Alves, Emanoel da Costa; Dantas, Jair Ferreira; Macedo, Luciano Pacelli Medeiros de; Araujo, Elton Lucio; Freire, Jos? Luc?nio de Oliveira', 'Editora Verde', 'Agriculture', 'Agriculture', 'As moscas-das-frutas s?o respons?veis por causarem danos ? cultura da mangueira (Mangifera indica L. - Anacardiaceae) com preju?zos socioecon?micos. Assim, objetivou-se com esse trabalho relatar as esp?cies de moscas-das-frutas, seus ?ndices faun?sticos e flutua??o populacional em mangueiras das variedades Espada e Maranh?o, na regi?o Serid? Oriental do estado da Para?ba. O trabalho foi desenvolvido em um pomar de mangueira das variedades Espada e Maranh?o, n?o tecnificado, na comunidade V?rzea Verde, munic?pio de Frei Martinho, Para?ba, Brasil. As moscas-das-frutas foram coletadas com o aux?lio de armadilhas McPhail, utilizado prote?na hidrolisada ? 5%, como atrativo alimentar. Foram calculados os ?ndices faun?sticos (domin?ncia, abund?ncia, frequ?ncia e const?ncia). A flutua??o populacional foi estabelecida atrav?s do ?ndice de Mosca/Armadilha/Dia, correlacionando-a com as vari?veis clim?ticas, temperatura e precipita??o pluvial. Foram capturados 1.364 exemplares de moscas-das-frutas', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce93', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce96', 'Qualidade de produtos comerciais ? base de frutas', 'Silva, Amanda Kelly da; Souza, Diego Gadelha; Santana Neto, Deocleciano Cassiano de; Santos, Adriana Ferreira dos; Gomes, Jaqueline de Sousa; Martins, Fl?via de Brito', 'Editora Verde', 'Agriculture', 'Agriculture', 'O processamento de frutos in natura em produtos derivados proporcionam a conserva??o e o consumo fora do per?odo de safra, no entanto, ? importante que estes produtos cheguem ao mercado consumidor atendendo e garantindo a sua qualidade f?sico-qu?mica e funcional. Desta forma, o objetivo deste trabalho foi avaliar caracter?sticas f?sico-qu?micas e quantifica??o de compostos bioativos em amostras comerciais de doces em massa de goiaba e banana, polpas de acerola e goiaba. Os produtos adquiridos foram representados por quatro marcas comerciais, provenientes dos mercados locais de Pombal e Patos na Para?ba. Foram realizadas as determina??es de s?lidos sol?veis, acidez titul?vel, pH, ratio, teor de ?gua, res?duo mineral fixo, ?cido asc?rbico, clorofila, carotenoides, flavonoides, antocianinas e polifen?is extra?veis totais. Para o teor de cinzas, a amostra A de doce de goiaba se destacou entre as demais, indicando maior quantidade de res?duo inorg?nico.As amostras A, B e C de doce de goiaba', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce96', NULL, 'English', 'published', false, false, 'open', 'pdf')
