INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce9c', 'Exposi??o ocupacional aos agrot?xicos pelos agricultores da regi?o de Coruripe, Alagoas', 'Bento, Antonio Jos?; Andrade, Anderson Bruno Anacleto de; Moura, Maria Aline Barros Fidelis de; Santana, Antonio Euzebio Goulart; Goulart, Henrique Fonseca; Santos, Jakeline Maria dos', 'Editora Verde', 'Agriculture', 'Agriculture', 'As intoxica??es por agrot?xicos resultam da exposi??o ocupacional dos trabalhadores rurais, principalmente nas ?reas agr?colas. Para reduzir esses problemas ? necess?rio o uso de estrat?gias de monitoramento e controle do manejo racional dos produtos qu?micos utilizados. O objetivou-se com o trabalho avaliar o perfil ocupacional dos trabalhadores rurais por meio de entrevistas e exames toxicol?gicos. O estudo caracteriza-se por uma pesquisa aplicada, de caracter?stica explorat?ria, com procedimento de levantamento a partir de uma amostra com 50 agricultores. Observou-se maioria dos fatores de riscos aos trabalhadores est? intrinsecamente relacionada, pois quando s?o verificadas as correla??es causais da exposi??o e intoxica??o dos agricultores, verificamos que a baixa escolaridade associada ? car?ncia t?cnica de instru??o do uso racional dos agrot?xicos, o tempo prolongado de exposi??o e o n?o uso de EPIs, contribuem para o perfil toxicol?gico dos trabalhadores rurais. Em rela??o ?s an', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce9c', NULL, 'English', 'published', false, false, 'open', 'pdf')
