INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ceaf', 'Substratos para propaga??o r?pida de mandioca tipo mesa', 'Lopes, Khayran; Melo J?nior, Arsenio Pessoa de; Ara?jo, Wh?llyson Pereira; Alves, Aaron de Sousa', 'Editora Verde', 'Agriculture', 'Agriculture', 'Presente em todas as regi?es, a mandioca, tem import?ncia fundamental na alimenta??o humana e animal, seja como mat?ria-prima para a obten??o de produtos industriais e/ou na gera??o de emprego e renda no campo. Em meio ? relev?ncia desta cultura para o atual cen?rio econ?mico nacional, objetivou-se com este estudo avaliar os efeitos de diferentes composi??es de substratos sobre o desenvolvimento de estruturas vegetativas de mandioca do tipo mesa mediante a adapta??o da t?cnica de propaga??o r?pida, como alternativa ? oferta de mudas de melhor qualidade para comunidades tradicionais inseridas no semi?rido piauiense. O experimento foi desenvolvido em ambiente protegido no Instituto Federal do Piau?, Campus Oeiras. Obedecendo ao delineamento em blocos casualizados, sendo testadas 12 composi??es de substratos formulados a partir da mistura de areia lavada, solo e esterco bovino. A mistura de substratos Solo + Areia lavada + Esterco bovino (1:1:2) e Areia lavada + Esterco bovino (1:2) s?o e', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ceaf', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67dab468677d8be0233b3777', 'A influência dos estímulos sensoriais e psicomotores no desenvolvimento da alfabetização: contribuições para a aprendizagem infantil', 'Moura, Francyely dos Santos; Soares, Andreza Tainá de Sá; Nascimento, Márcia Luciana Gurgel Assunção do; Maia, Ana Cristina Alves Lins; Paiva, Jerdmiler Gomes de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O artigo em testilha discute a importância dos estímulos sensórias e da psicomotricidade, no processo de alfabetização, como agente motivador do ensino na educação infantil.&nbsp; Essa temática que relaciona a importância de uma prática que une movimento corporal, sensório, motor, raciocínio logico e cognitivo comportamental das crianças na educação infantil, como objetivo principal temos o interesse de entender a concepção docente de alguns renomados autores, sobre a importância da psicomotricidade no ensino infantil, e na sua posteridade como agente motivador do ensino, assim como entender quais as vantagens dos estímulos sensoriais na efetivação do conhecimento dentro e fora da sala de aula. A metodologia de elaboração do artigo é baseada na abordagem de referência bibliográfica. A psicomotricidade está diretamente ligada aos estímulos sensórias e a toda a parte dos movimentos ligados a mente e aos sentidos, se configura como sendo uma nova metodologia de ensino que envolve moviment', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11251', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4bab', 'BIBLIOMETRIA DOS ESTUDOS SOBRE O USO DA INTELIGÊNCIA ARTIFICIAL PELO JUDICIÁRIO BRASILEIRO E SUA CORRELAÇÃO COM A AGENDA 2030', 'Marques, Jacyara Farias Souza; Gadelha, Daênio Pinto Nóbrega; Bernardo, Marília Elias', 'Editora Verde', 'Agriculture', 'Agriculture', 'O estudo buscou analisar a tendência dos estudos acerca do uso da Inteligência Artificial pelo Poder Judiciário brasileiro de uma perspectiva da consecução dos Objetivos de Desenvolvimento Sustentável (ODS) da Agenda 2030 e, assim, identificar os avanços e desafios científicos associados à aplicação da IA no sistema de justiça, ou seja, buscou-se compreender como essas iniciativas tecnológicas contribuem ou limitam o alcance dos ODS. Para tanto, adotou-se como metodologia a bibliometria, tendo sido utilizada a Lei de Zipf para identificar a frequência de termos-chave nos artigos publicados entre 2018 e 2024 que se encontram indexados na plataforma Periódicos CAPES. Os dados coletados foram analisados considerando o quantitativo de publicações por ano do período selecionado, os pontos positivos e as principais preocupações identificadas nos estudos mapeados quanto ao uso da IA pelo Poder Judiciário brasileiro e, por fim, a partir dessas análises, estruturou-se a correlação entre cada es', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11299', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4bad', 'ANÁLISE DAS NOVAS DIRETRIZES DA POLÍTICA NACIONAL DE DESENVOLVIMENTO REGIONAL (PNDR) E SEUS EFEITOS NA GESTÃO SOCIOAMBIENTAL E SUSTENTABILIDADE', 'Fernandes, Thais de Morais Beltrão; Soares, Jardel de Freitas; Filho, Miguel Emídio Estrela', 'Editora Verde', 'Agriculture', 'Agriculture', 'A Política Nacional de Desenvolvimento Regional (PNDR), especialmente após sua atualização pelo Decreto nº 11.962/2024, representa um marco no enfrentamento das desigualdades regionais no Brasil, incorporando a sustentabilidade como eixo estratégico. Este estudo tem como objetivo analisar como a PNDR, em sua versão mais recente, integra práticas de gestão socioambiental para promover coesão territorial, crescimento econômico sustentável e inclusão social. A metodologia adotou abordagem qualitativa, exploratória e descritiva, baseada em análise bibliográfica e documental. Utilizou-se a técnica de análise de conteúdo para interpretar os dados sob uma perspectiva interdisciplinar. O referencial teórico baseia-se na convergência entre as teorias de desenvolvimento sustentável, local e territorial, destacando a governança multissetorial como elemento essencial para articular ações entre diferentes níveis de governo, setor privado e sociedade civil. A discussão destaca grandes avanços, como ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11301', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4bae', 'EVASÃO NAS UNIVERSIDADES FEDERAIS: O ESTADO DA ARTE DOS ARTIGOS PUBLICADOS NO BRASIL ENTRE OS ANOS DE 2015 E 2024', 'Pederneiras, Marcleide Maria Macêdo; Silva, André Leite; Roque, Enéias Andrade Rocha', 'Editora Verde', 'Agriculture', 'Agriculture', 'A evasão é um fenômeno multifatorial e complexo que impacta os processos formativos em seus diversos níveis. Com a expansão do ensino superior no Brasil, essa temática ganhou bastante relevância no âmbito acadêmico, passando a ser objeto de diversas pesquisas. Nesse trabalho, objetivou-se realizar um levantamento dos artigos científicos produzidos no Brasil sobre a evasão nas universidades federais ao longo do decênio 2015-2024, buscando-se identificar suas principais tendências e lacunas. Essa pesquisa bibliográfica foi realizada na base de dados do Periódicos Capes. Dos principais achados pode-se destacar que praticamente metade dos estudos analisados, abordam a temática da evasão com enfoque nas suas causas, determinantes e condicionantes. Entre as lacunas, pode-se destacar a escassez de estudos dos impactos da pandemia do Covid-19 sobre a evasão; estudos que indiquem os impactos da evasão sobre o orçamento dessas instituições de ensino superior, entre outros.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11302', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4bb1', 'REGULAÇÃO MÉDICA DAS URGÊNCIAS NO SUS: UM INSTRUMENTO DE GESTÃO PARA A EFICIÊNCIA E EQUIDADE', 'Soares, Jardel de Freitas; Brito, Geyse Karla Leite; Oliveira, Tomazia Rakielle Estrela de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O tema abordado neste estudo é a regulação médica das urgências no Sistema Único de Saúde (SUS) do Brasil, visando sua importância como instrumento de gestão para eficiência e equidade no acesso aos serviços de saúde. O objetivo é analisar como a regulação médica contribui para otimizar o fluxo de atendimento, priorizar a triagem e garantir o encaminhamento adequado dos pacientes em situação de urgência. A metodologia empregada baseou-se em uma revisão bibliográfica que explorou estudos e diretrizes sobre práticas e desafios da regulação no SUS. Os resultados revelaram que, apesar de avanços, a regulação enfrenta desafios estruturais, como escassez de recursos e resistência à mudança entre os profissionais. A conclusão destaca a regulação médica como essencial para um sistema de saúde equitativo e eficaz, promovendo acesso justo para toda a população.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11305', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1b6', 'POLÍTICAS PÚBLICAS E DESENVOLVIMENTO', 'Albuquerque, Amanda Cavalcante de', 'Editora Verde', 'Agriculture', 'Agriculture', '&nbsp;
Quanto ao fato do processo de desenvolvimento o mesmo contou com uma forte ação por meio do Estado através de uma consolidação e permanência por parte deste, tais ações trouxeram tanto a curto como em longo prazo diversas influências e consequências, para diversos setores da economia, da sociedade. Ademais, compreende-se que as constituições buscam se estruturar com base em projetos de desenvolvimento, com o intuito de estabelecer direitos e deveres para os seus cidadãos, baseando tais direitos, nos próprios projetos de desenvolvimento, utilizando para tanto de políticas públicas para que esses fatos sejam concretizados, quando se trata do Brasil a Carta Magna vigente preconiza alguns objetivos fundamentais que devem ser respeitados, dentre eles se destacam: construir uma sociedade livre, justa e solidária; garantir o desenvolvimento nacional; erradicar a pobreza e a marginalização e reduzir as desigualdades sociais e regionais. Ainda ao que tange, a essa promoção do desenvolvim', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11897', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1b7', 'A INFLUÊNCIA DO DIREITO ROMANO NO CÓDIGO CIVIL BRASILEIRO', 'Alves, Milla Eduarda Lima de Sousa; Silva, Aline Soares da', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este artigo propõe uma análise sobre como os princípios e institutos do antigo Direito Romano estão profundamente enraizados na construção dogmática do Código Civil Brasileiro de 2002. O estudo se justifica pela necessidade de entender que o nosso Direito Civil não surgiu do nada, mas é um legado vivo da tradição civil law. Adotamos uma abordagem qualitativa, cruzando o método histórico (para entender a trajetória dos conceitos) com o método comparativo (para colocar lado a lado os institutos romanos clássicos e os dispositivos atuais). A pesquisa baseou-se na leitura crítica de obras fundamentais e de autores contemporâneos do Direito Civil. Os resultados mostram que o sistema brasileiro é estruturalmente romanista, embora modernizado. Na propriedade, mantemos a estrutura romana, mas o absolutismo antigo foi superado, sendo hoje filtrado pela função social. Nas obrigações, o vínculo entre as partes persiste, mas a responsabilidade migrou da punição física para ser exclusivamente patri', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11905', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1b9', 'A EVOLUÇÃO DO PROCESSO DE EXECUÇÃO A PARTIR DA TRADIÇÃO ROMANA E SUA INFLUÊNCIA NA HISTÓRIA DO DIREITO', 'Silva, Samara de Oliveira', 'Editora Verde', 'Agriculture', 'Agriculture', 'A formulação e construção do processo de execução na maior parte dos países jurídicos ocidentais, a exemplo do Brasil, está intrinsecamente interligada à trajetória do Direito Romano. Isso ocorre porque a estruturação jurídica desenvolvida pela tradição romana forneceu a base estrutural para os sistemas jurídicos posteriores, inclusive no que se refere aos atos processuais. Assim, a perspectiva histórica acerca do modelo executório romano e sua influência na formação do Direito, especialmente a partir das contribuições de Thomas Marly, Março Félix Jobim, Rodrigo Freitas Palma e Antônio Carlos Wolkmer, revela-se de grande relevância para a compreensão dos institutos ainda hoje aplicáveis no ordenamento jurídico brasileiro. Evidencia-se o papel romano na transformação da autotutela em jurisdição institucionalizada, com o desenvolvimento de mecanismos rituais, formular e cognitórios, que moldaram os pensamentos português e, por consequência, brasileiro. METODOLOGIA: A pesquisa foi desenvo', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11907', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1bb', 'A RETÓRICA CICERONIANA E OS FUNDAMENTOS DA JUSTIÇA FISCAL: UMA ANÁLISE DA INFLUÊNCIA CLÁSSICA NO DIREITO TRIBUTÁRIO CONTEMPORÂNEO', 'Raicca Letícia Fernandes; Mikaelly Silva Santos; Brasil, Iorrana Iracy Amorim Leite', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente trabalho resulta de um estudo acadêmico no que se demonstrou a importância do Direito Romano, em especial, dos textos de Marco Túlio Cícero, na formação do Direito Tributário contemporâneo. A metodologia adotada pelo artigo é dedutiva, com ênfase na pesquisa bibliográfica-documental, realizada a partir da análise de livros, artigos científicos e documentos históricos relacionados ao tema. Preliminarmente, Cícero é apresentado, de modo que sua obra é analisada. Na sequência, conceitua-se, em breve histórico, o desenvolvimento e a evolução do Direito Tributário, a partir de Roma. Posteriormente, demonstra-se a relação entre Cícero e a formação do Direito Fiscal vigente na sociedade contemporânea e, nessa perspectiva, é comprovada a relevância da retórica ciceroniana para debates fiscais e a presença de princípios clássicos na formação do conceito de justiça fiscal atual. Por fim, considera-se, finalmente, a herança ciceroniana como pilar da compreensão ética e teórica do siste', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11909', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1bf', 'ANÁLISE DA APLICAÇÃO DE PRINCÍPIOS ROMANOS NA INTERPRETAÇÃO JUDICIAL DO DIREITO PRIVADO BRASILEIRO', 'Nascimento, Rian Gomes do; Silva, Camilly Vitória de Melo; Gonzaga, Letycia Hellen Pereira', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente artigo analisa a aplicação de princípios originários do Direito Romano, que ainda persistem na interpretação judicial contemporânea brasileira, como exemplo estão a culpa, a autonomia privada e o instituto da propriedade privada, na interpretação judicial do Direito Privado brasileiro contemporâneo. O objetivo geral deste artigo se pauta na lubricidade de avaliar que o judiciário brasileiro e como o direito privado ainda se molda aos princípios e funcionamentos do Direito Romano, também se analisará a incorporação desses princípios no texto legal e a sua concretização por meio de situações do cotidiano jurídico. Este artigo conseguiu concluir que embora adaptados à realidade brasileira, os princípios romanos permanecem como vetores hermenêuticos e teleológicos centrais para a aplicação do Direito Privado.', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11913', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1c1', 'DESAFIOS E IMPACTOS DA PARTICIPAÇÃO FEMININA NO JUDICIÁRIO: UMA ANÁLISE DO QUINTO CONSTITUCIONAL E A DESIGUALDADE DE GÊNERO NOS TRIBUNAIS', 'Pordeus, Mikaelly Andrade; Silva, Mariana Vieira Júlio da', 'Editora Verde', 'Agriculture', 'Agriculture', 'O artigo científico a seguir busca analisar a reforma feita no Quinto Constitucional (Art.94 da CF/88) que assegura a paridade de gênero como medida para garantir que metade das vagas sejam direcionadas a advogadas, expondo os obstáculos enfrentados pelas mulheres até conseguirem ocupar o Judiciário e evidenciando os ordenamentos jurídicos que pretendem alcançar a igualdade e o reconhecimento das atribuições dentro da sociedade entre os gêneros. Portanto, através de pesquisas bibliográficas e exploratórias de abordagem qualitativa em razão de pesquisas online e legislação, o artigo busca evidenciar que ainda com uma legislação igualitária, percebe-se que a mulher brasileira continua a ser alvo de tratamentos discriminatórios no âmbito profissional e que estudos voltados para sua invisibilidade em cargos superiores são escassos, sendo indispensável sua representatividade nos Tribunais de Justiça. Dessa forma, tem-se o objetivo de mostrar o papel da educação para os direitos humanos e a ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11915', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1c9', 'A INCLUSÃO DE ALUNOS COM TRANSTORNO DO ESPECTRO AUTISTA (TEA) NAS AULA DE EDUCAÇÃO FÍSICA', 'Herculano, Cosmo Matheus Cassiano Dantas; Brito, Wallsson Vinicius Paulino de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este artigo tem como objetivo analisar os desafios e as possibilidades de inclusão de alunos com Transtorno do Espectro Autista (TEA) nas aulas de Educação Física no contexto escolar. A partir de uma abordagem qualitativa e de revisão bibliográfica, discute-se o papel do professor e da gestão escolar na construção de práticas pedagógicas inclusivas que respeitem as particularidades dos estudantes com autismo. Também são abordadas as políticas públicas que amparam a inclusão, como a Lei Brasileira de Inclusão (Lei nº 13.146/2015) e a Política Nacional de Proteção dos Direitos da Pessoa com TEA (Lei nº 12.764/2012). Os resultados da análise indicam que, embora o marco legal seja avançado, ainda há barreiras significativas relacionadas à formação docente, adaptação curricular e falta de recursos pedagógicos. Conclui--se que a efetivação da inclusão depende de uma atuação conjunta entre professores, gestores, famílias e equipe de apoio, para garantir que a Educação Física seja um espaço de', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11923', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1cc', 'O LEGADO FUNDACIONAL DO DIREITO ROMANO: ANÁLISE DA SUA IMPORTÂNCIA PARA AS CIÊNCIAS JURÍDICAS CONTEMPORÂNEAS', 'Araújo, Emanuela Alcindo Batista de; Rosas, Margysa Thaymmara Bezerra; Silva, Lara Ryane Ferreira da; Ribeiro, Bianca Neris dos Santos', 'Editora Verde', 'Agriculture', 'Agriculture', 'Este artigo objetiva demonstrar a importância estrutural e conceitual do Direito Romano como base indispensável para a formação das Ciências Jurídicas contemporâneas. A metodologia utilizada é a revisão bibliográfica de autores clássicos do Direito Romano e de jusfilósofos modernos. A pesquisa, portanto, utiliza como aporte teórico as obras de Amaral e Alves buscando compreender qual o alcance de sua contribuição às Ciências Jurídicas Contemporâneas considerando que, importantes autores nacionais reproduzem as ideias dose autores em seus trabalhos doutrinários. Ante todo o exposto, é possível concluir, que há grandes institutos existentes na legislação&nbsp; vigente&nbsp; e&nbsp; exercem&nbsp; uma&nbsp; plenitude&nbsp; no&nbsp; campo&nbsp; da&nbsp; eficácia,&nbsp; como&nbsp; os&nbsp; direito obrigacionais,&nbsp; a&nbsp; concepção&nbsp; de&nbsp; capacidade&nbsp; da&nbsp; pessoa&nbsp; civil,&nbsp; os&nbsp; bens,&nbsp; obrigação&nbsp; e as finalidades da pena, são todos oriundos das const', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11926', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6970acf7bd789e57df2cb1cd', 'O CONCEITO DE PESSOA E CAPACIDADE NO DIREITO ROMANO E SUA EVOLUÇÃO ATÉ O DIREITO BRASILEIRO ATUAL', 'Alves, Gabriela da Silva; Oliveira, Andressa Fernandes de; Almeida Júnior, Joailson Medeiros de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente estudo analisa a relevância e a influência do Direito Romano na formação do Direito Civil brasileiro, com foco nos institutos da pessoa e da capacidade. A pesquisa, de natureza exploratória, fundamenta-se em fontes históricas, legislação comparada e doutrina especializada, buscando identificar como conceitos estruturantes do sistema romano permanecem presentes no ordenamento jurídico contemporâneo. Verifica-se que o Direito Romano exerceu papel essencial no desenvolvimento da personalidade jurídica e da capacidade civil, uma vez que, em Roma, a noção de pessoa estava condicionada ao preenchimento de determinados status jurídicos, refletindo uma organização social rigidamente hierarquizada. A partir dessa estrutura excludente, observa-se um longo processo de transformação teórica e normativa, culminando no modelo brasileiro atual, que reconhece personalidade jurídica a todos os indivíduos desde o nascimento com vida e orienta a interpretação das normas pelos princípios consti', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11927', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('690c5c78e36ca628435fc99e', 'I Simpósio Paraibano de Ciência Animal (Produtos Agropecuários e Saúde Publica 79-86 p)', 'Sousa, Francisco de Assys Romero da Mota; Maracaja, Patricio Borges; Mascarenhas, Nágela Maria Henrique; Gurjão, Thyago Araujo', 'Editora Verde', 'Agriculture', 'Agriculture', 'I Simpósio Paraibano de Ciência Anima Produtos Agropecuários e Saúde Publica', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11713', NULL, 'English', 'published', false, false, 'open', 'pdf')
