INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('68d27a7db3b40a20d617ee57', 'Percepções locais Comportamento de consumo e a visão de consumidores sobre o mel de abelha no território do Cariri Paraibano', 'Mesquita de Sena, Maria Nayara', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11560', NULL, 'English', 'published', false, false, 'open', 'pdf')
