INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6878b64e0868163a2f74de65', 'Avanços na pavimentação asfáltica: materiais, técnicas e sustentabilidade', 'Batista, José de Carlos; Linhares, Paulo Robson Parente; Silva, Cleber Santana de Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pavimentação asfáltica é um elemento essencial para a infraestrutura de transporte, desempenhando um papel central no desenvolvimento econômico e social. Este artigo, baseado em uma revisão bibliográfica, analisa os avanços recentes em materiais e técnicas de pavimentação com foco na sustentabilidade. O objetivo principal foi identificar inovações que aumentem a durabilidade, reduzam os custos e minimizem os impactos ambientais. A pesquisa incluiu estudos sobre o uso de resíduos reciclados, como plásticos, pneus e resíduos de construção civil, bem como a aplicação de tecnologias como pavimentação a frio, misturas asfálticas mornas e compactação inteligente. Os resultados apontaram para benefícios significativos, como a maior eficiência dos processos, redução de emissões de gases de efeito estufa e integração de práticas sustentáveis no setor. Concluiu-se que as inovações analisadas têm potencial para transformar o setor de pavimentação, mas sua adoção depende de investimentos em pesq', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11414', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6878b64e0868163a2f74de66', 'Georrefenciamento de imóveis rurais com uso de drone e RTK', 'Batista, José de Carlos; Linhares, Paulo Robson Parente; Silva, Cleber Santana de Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente estudo destaca a relevância do georrefenciamento de imóveis rurais com uso de drone e RTK, mas observa que essa tecnologia ainda não é aproveitada em sua totalidade. O georreferenciamento de imóveis rurais é um requisito legal no Brasil, regulamentado pelo INCRA, e tem como finalidade assegurar a delimitação precisa das propriedades, promovendo segurança jurídica, planejamento territorial e políticas públicas efetivas. Embora haja um foco na análise da variabilidade espacial utilizando métodos geoestatísticos e técnicas de interpolação, observa-se uma tendência em optar pela integração pontual, que utiliza métodos multivariados. Dessa forma, o objetivo geral do artigo é analisar o georreferenciamento de imóveis rurais utilizando drones equipados com tecnologia RTK, buscando à obtenção de dados espaciais precisos, em conformidade com as normas técnicas do INCRA, para fins de regularização fundiária, cadastro e gestão territorial. A metodologia utilizada é uma revisão bibliogr', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11415', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e2', 'Produção de fermentado alcoólico de laranja', 'José Crisóstomo da Silva Neto; Saulo Soares da Silva; Adriana da Silva Santos; Janine Patricia Melo Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho tem como objetivo produzir um fermentado alcoólico proveniente do suco de laranja (Citrus sinensis), segundo processo adaptado das metodologias já existentes para obtenção de outros fermentados de fruta. O processo produtivo do fermentado de laranja e as analises referentes ao mesmo foram conduzidos no Laboratório de Operações Unitárias e Fenômeno de Transporte do Centro de Ciências e Tecnologia Agroalimentar da Universidade de Campina Grande – Campus Pombal - Pb. Com relação às etapas da adição dos insumos na confecção do fermentado, as mesmas não foram feitas na ordem descrita pela maioria das literaturas que se trabalham com fermentados alcoólicos, onde a ordem seguida foi: Extração do mosto, Preparação do Mosto: Sulfitação, Inoculação do Microrganismo e Nutrientes, Determinação do °Brix, Chaptalização, Fermentação Alcoólica, Decantação e Trasfegas, Clarificação, Filtração e o Envase. Constata-se pelo presente trabalho que o fermentado de laranja, mostrou-se aceitável ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3561', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e4', 'Utilização de medicamentos fitoterápicos e plantas medicinais em diferentes segmentos da sociedade', 'Kevia Katiucia Santos Bezerra; Vicente Maia Pinto Junior; Patricio Borges Maracajá; Claudia Sarmento Gadelha; Débora S. S. Martins', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A utilização de plantas medicinais como medicina alternativa é uma pratica milenar, no entanto, a inserção de fitoterápicos é recente, porém, tem sido incentivado a sua prescrição pelo SUS.  A Organização Mundial de Saúde,  leva em consideração a cultura e a biodiversidade existentes no Brasil, tendo em vista a complexidade que envolve a fitoterapia, a Política Nacional de Planta Medicinal e Fitoterápico. Esta pesquisa teve como principal objetivo avaliar o uso de fitoterápicos e de plantas medicinais na saúde básica do município de Sousa-PB. Para isso foram aplicados formulários com pacientes/usuários e profissionais de saúde (Médicos e Enfermeiros), a respeito do uso, indicações, contra indicações dentre outros. A pesquisa foi realizada entre os meses de julho a outubro de 2014. Em relação ao faixa etária 90% dos entrevistados possuem idade entre 22 e 59 anos, com relação à renda dos usuários 40% dos mesmos possuem uma renda de menos de R$ 1.000,00, já à indicação do uso de plantas m', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3564', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e5', 'Resíduos de agrotóxicos em alimentos: preocupação ambiental e de saúde para população paraibana', 'Raquel Patrícia Ataíde Lima; Luara Lourenço Ismael; Elisângela M. Rodrigues Rocha; Luciano Alberto Lins Filho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O monitoramento de resíduos de agrotóxicos em alimentos vem assumindo grande importância para o alcance à segurança alimentar dos consumidores. A Paraíba é hoje um grande consumidor de legumes, verduras e frutas no Brasil, detentora de grandes áreas de diversas monoculturas. O presente trabalho visou investigar os resíduos de agrotóxicos em alimentos comercializados no Estado da Paraíba e seus impactos negativos a saúde humana. A partir de visitas feitas em parceria com a Agência Estadual de Vigilância Sanitária (AGEVISA-PB), foram coletadas 100 amostras de 15 diferentes culturas durante os anos de 2011, 2012 e 2013 em vários supermercados da Paraíba e encaminhadas a laboratórios credenciados, onde foram investigados aproximadamente 234 diferentes ingredientes ativos de agrotóxicos em alimentos. Verificou-se que de 100 amostras de alimentos analisadas, 55 % possuem resíduos de agrotóxicos. Através da identificação dos possíveis riscos a saúde humana e ao meio ambiente, resultantes de n', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3459', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e6', 'Elaboração e caracterização de doce de coco adicionado de diferentes concentrações de rapadura', 'Luan Pedro Melo Azerêdo; Heloisa Maria Almeida Do Nascimento; Ricardo Targino Moreira; Emmanuel Moreira Pereira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A rapadura é o produto sólido obtido da concentração do caldo da cana-de-açúcar, muito procurada pelos consumidores, sendo sua utilização na elaboração de doces uma boa alternativa econômica para seu aproveitamento. Este trabalho teve como objetivo avaliar a qualidade microbiológica e sensorial de três formulações de doce de coco. Os resultados mostram que a formulação mais aceita foi obtida a partir da concentração média de rapadura, contribuindo para o desenvolvimento do doce a base de rapadura por meio de procedimentos simples e de fácil aplicação pelos produtores.Preparation and characterization of doce de coco added to different concentrations of sugar cane productsAbstract: The brown sugar is the solid product obtained by concentration of the juice of cane sugar, very popular with consumers, and is used to manufacture candy good economic alternatives for their utilization. This study aimed to evaluate the microbiological and sensory quality of three sweet coconut formulations. Th', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3585', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e9', 'A perspective for rural development based on the dairy-farming production system in Iporá and surroundings, Goiás State', 'Marisa Marques Silva; Paulo Alexandre Perdomo Salviano; Alcido Elenor Wander; Kaique Moreira Dias; Eduardo Rodrigues de Carvalho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'The objective of this study was to characterize the dairy-farming production system in Iporá and adjacent municipalities. In the present work 257 interviews were conducted from April to November 2013 in several locations. Mean milk production per farm was 207.9 liters/day and dairy cow yield was 7.8 liters/day. The indicators of pasture degradation was high (n=111/63.8%). Natural breeding was more frequent (n=155/82.4%) than artificial insemination (n=33/17.6%). Milking cows manually was more frequent (n=146/82.9%) than mechanical milking (n=30/17.1%). The most predominant milking construction was the roofless shed with packed earth floor (n=98/63.2%). Milk quality may be reduced due to certain procedures adopted during milking (48 herdsmen dry the saliva of the calf on the teat surface with the cow tail, 63 herdsmen remove the saliva of the calf on the teat surface by hand and dry it on the cow coat, and 67 herdsmen remove the saliva of the calf on the teat surface by hand and dry it ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3494', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1eb', 'Qualidade pós-colheita de beterraba submetida à adubação com biofertilizante fermentado', 'José Ricardo Tavares de Albuquerque; Anderson dos Santos Formiga; Thayse Cavalcante da Rocha; Ancélio Ricardo de Oliveira Gondim; Franciscleudo Bezerra da Costa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O cultivo de beterraba com biofertilizante consiste em uma alternativa potencial para produção em escala familiar, sendo necessário, contudo avaliar a qualidade de produção. Assim objetivou-se avaliar a qualidade pós-colheita de beterraba submetida á adubação com biofertilizante fermentado. O experimento foi realizado na área experimental do Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, Câmpus de Pombal-PB, durante o período de setembro a dezembro de 2013, em solo classificado como Argissolo Vermelho-Amarelo Câmbico. O delineamento experimental utilizado foi o inteiramente casualizado. Os tratamentos corresponderam à aplicação de dois tempos (20 e 40 dias de fermentação do biofertilizante) com três repetições. Foram utilizados seis tubérculos por parcela, selecionados conforme uniformidade de tamanho. Os tempos de fermentação do biofertilizante não influenciaram nas características físicas e químicas avaliadas, a exceção do teor de vitamina C ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3652', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1ee', 'Produção e avaliação da qualidade das barras de cereais elaborada com farinha de facheiro', 'D. S. Severo; G. S. Alves; J. N. V. Deodato; C. C. M. Silva; A. S. Araújo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As cactáceas constituem um importante elemento da paisagem, apresentando caules suculentos, cobertos por espinhos de diversas formas, tamanhos e dimensões, junto a outras espécies de cactáceas, formam a paisagem típica da região semiárida do Brasil. O facheiro é uma cactácea xerófila, robusta, pouco ramificada, de cor verde-escura, armada de espinhos agudos; com flores grandes isoladas e altas. A proposta do trabalho foi elaborar barras de cereais com farinhas da casca e da polpa do facheiro e determinar as características microbiológicas e físico-químicas. Foram preparadas quatro formulações (5, 10, 15 e 20%) de cada farinha, variando-se a quantidade adicionada à formulação básica das barras de cereais. Os resultados das análises microbiológicas atenderam aos padrões exigidos pela legislação vigente, apresentando resultados negativos para coliforme a 45° C e Salmonella sp. Nos resultados físico-químicos apresentaram baixos valores de umidade e cinzas, elevado teores de lipídeos e sóli', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3699', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f0', 'A educação cooperativista na formação de catadores de resíduos sólidos em Iguatu, Ceará', 'A. K. Feitosa; G. D. Silva; G. H. P. Landim; K. B. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A presente pesquisa teve por objetivo conhecer a percepção dos catadores de resíduos sólidos atuantes no município de Iguatu, CE, sobre a realidade de trabalho e contribuição da educação cooperativista na formação profissional. Para a coleta dos dados foi utilizada a técnica de entrevista de grupo focal, com a participação de 10 (dez) catadores de resíduos sólidos que atuam no lixão do referido município, em que foi possível a interação dos participantes, discussão e manifestação de suas opiniões. A análise de dados se deu sob a temática de Bardin (2011), por meio da análise de discurso de conteúdo. Como resultado, foi possível constatar a importância da educação cooperativista como um processo permanente de base na formação e capacitação profissional dos catadores de recicláveis. Além disso, observou-se a necessidade do fortalecimento da organização dos catadores, via a formação de uma cooperativa, possibilitando avanço, por meio de melhores condições de trabalho, vida, renda, valoriz', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3639', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f2', 'Uso popular de plantas medicinais por mulheres da comunidade quilombola de Furadinho em Vitória da Conquista, Bahia, Brasil', 'L. R. Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho realizar um levantamento do uso popular de plantas medicinais por mulheres da Comunidade Quilombola de Furadinho em Vitória da Conquista-Bahia. O trabalho foi realizado na comunidade Quilombola de Furadinho, visando identificar as principais plantas utilizadas com fins medicinais, as formas de obtenção, sua indicação medicinal, a parte da planta utilizada, as formas de preparo, bem como as formas de obtenção e transmissão deste conhecimento. Para a realização dessa pesquisa foram entrevistadas 14mulheres com idades variadas, moradoras dessa comunidade, através de questionários semi estruturados, e análise descritiva. Constatou-se um vasto conhecimento relacionado ao uso de plantas medicinais entre as entrevistadas, o qual foi adquirido de forma oral através de pais e avós. As plantas medicinais utilizadas são em sua maioria cultivadas em quintais, sendo as folhas a parte mais utilizada nas preparações medicamentosas, e a principal forma de preparo são os ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3408', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f3', 'Obtenção de corante do repolho roxo (Brassica oleracea) por dois métodos de extração', 'D. S. Severo; J. N. V. Deodato; J. C. Almeida; A. S. Araújo; M. A. S. Cordeiro', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O repolho é uma hortaliça folhosa, com grande versatilidade, não somente pelo seu valor nutritivo. Além de colorir a mistura, destaca-se pelo elevado teor de antocianinas e compostos fenólicos, contribuindo para a prevenção de doenças cardiovasculares, bem como de alguns tipos de câncer. As antocianinas são largamente encontradas na natureza e responsáveis pela maioria das colorações azuis, violeta e vermelhas de flores e frutos, sendo sua principal utilização como corante natural na indústria. O presente trabalho tem como objetivo a obtenção de um corante, antocianina, de repolho roxo (Brassica oleracea) por dois métodos distintos de extração. No corrente estudo, o extrato foi obtido por meio de procedimento alcoólico e aquoso. As características avaliadas foram: pH; acidez total titulável; Teor de sólidos solúveis (°Brix); umidade; cinzas; proteínas; extração e quantificação de antocianinas totais; Vitamina C. O resultado encontrado para antocianina no repolho roxo in natura foi de 6', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3909', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1f8', 'Floração e morfologia floral de variedades de melancieira em Juazeiro-BA', 'P. M. Duarte; G. B. S. Silva; Í. L. S. Gomes; N. C. da Silva; K. M. M. de Siqueira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A melancieira apresenta comumente flores masculinas e femininas na mesma planta, necessitando assim dos serviços de polinização para a transferência dos grãos de pólen e consequente produção de frutos. A atratividade aos polinizadores está na dependência dos recursos florais oferecidos como recompensa durante as visitas, e como consequência a planta é beneficiada com a polinização. O objetivo desse trabalho foi registrar aspectos relevantes da floração incluindo a razão sexual e a descrição da morfologia floral de variedades de melancieira. As variedades demelancieira utilizadas foram, Congo, Elisa, Crimson super e Charleston super, em cultivo orgânico, com irrigação por gotejamento. Foram avaliados quatro tratamentos e quatro repetições, utilizando o delineamento experimental inteiramente casualizado. Para todas as variedades analisadas, foi registrada a emissão inicial de flores masculinas. Não foi registrada diferença significativa na emissão de flores femininas entre as variedades,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3431', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1fa', 'Produção orgânica: predileção de consumo e potencialidades do seguimento em Fortaleza – CE', 'A. F. Lima; C. S. P. Oliveira; T. P. P. Andre; W. P. P. Andre; E. C. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho objetivou investigar o perfil de consumidores de produtos orgânicos, bem como sua forma de aquisição e quais as preferências que influenciam no momento de decidir sobre a compra. O presente estudo foi desenvolvido durante a VIII FECEAF – Feira Cearense da Agricultura Familiar – em Fortaleza, Ceará, durante julho de 2015, totalizando 100 sujeitos amostrais. Foram respondidas questões objetivas referentes ao perfil do consumidor, onde os indivíduos do sexo feminino (51%), à faixa etária entre 21 a 30 (39%) e o ensino médio (48%) desse público obtiveram maior representatividade. Observou-se ainda o pouco conhecimento acerca dos produtos orgânicos entre os entrevistados (61%), tendo a televisão como principal fonte de informação a respeito do tema (34%). No que diz respeito aos hábitos de consumo e a forma de aquisição desse tipo de produto, 54% dos respondentes o escolhem por apresentar uma melhor qualidade quando comparados aos convencionais, 43% o consomem todos os dias e ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3614', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1fb', 'Comportamento higiênico em colmeias de Apis mellifera L. africanizadas no Sertão da Paraíba', 'F. A. Olinto; D. C. Silveira; P. B. Maracajá; D. C. Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A apicultura é uma das poucas atividades agropecuárias que atende aos três requisitos da sustentabilidade: o econômico, o social e o ecológico. Sendo assim, fornece renda para o apicultor, ocupa mão de obra familiar ou contratada e contribui para a preservação da flora nativa. A sanidade pode afetar o desenvolvimento da apicultura, pois a Apis mellifera como qualquer outro organismo vivo, é susceptível a doenças causadas por bactérias, vírus, fungos e outros parasitas e as desordens metabólicas, nutricionais e hormonais, além de intoxicações diversas. Assim, em virtude da necessidade de estudos a respeito da sanidade apícola, objetiva-se estudar o comportamento higiênico em colônias de abelhas Apis mellifera em apiários localizados no Sertão do Estado da Paraíba. A pesquisa foi realizada no período de março, abril e maio de 2014, em cinco apiários localizados nos municípios de Condado, Pombal, Jericó, São Bentinho e São Domingos, ambos situados na Mesorregião do Sertão do Estado da Par', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3627', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1ff', 'Prospecção e isolamento de actinomicetos com potencial para promoção de crescimento em rúcula (Eruca sativa L.)', 'João Manoel da Silva; Tania Marta Carvalho dos Santos; Ana Lígia Silva de Melo; Antônio Moreira Neto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Actinomicetos são bactérias Gram negativas, encontradas em compostagens, e ambientes extremos. Objetivou-se por meio deste estudo, a bioprospecção de actinomicetos isolados de compostagem e inoculados em sementes de rúcula. O isolamento foi feito em três composteiras, sendo: Cana, Resíduo doméstico e Fibra de coco. O delineamento experimental foi inteiramente casualizado, constituído de sete tratamentos. Os resultados obtidos foram submetidos à análise estatística pelo teste de Scott Knott a 0,05% de probabilidade. Para altura de planta, os tratamentos diferiram estatisticamente entre si, sendo T7 com os menores valores. Para o número de folhas, as médias diferiram entre si, sendo a T7 com o menor valor. O diâmetro do coleto diferiu apenas para T7 e T2. O comprimento radicular diferiu apenas para o T3 e T7, com os menores valores. Para a fitomassa, o T3, apresentou os melhores resultados. Para a matéria seca, houve diferença apenas para T6 e T7. Os actinomicetos apresentaram um bom pot', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3317', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a204', 'Resíduo de sisal incorporado à substrato comercial na formação de mudas de jiló e brócolis', 'É. S. Rios; A. C. Oliveira; M. J. R. Silva; D. A. Souza; N. T. Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar o efeito da incorporação de resíduo de sisal ao substrato comercial sobre a emergência e a qualidade de mudas de jiló e brócolis. Os experimentos foram realizados em casa de vegetação com sombrite 50% no Departamento de Tecnologia e Ciências Sociais da UNEB, em Juazeiro, BA, utilizando-se sementes comerciais de jiló e brócolis. Nas duas espécies, os tratamentos consistiram na incorporação de diferentes porcentagens de resíduo de sisal (RSL) ao substrato comercial Tropstrato®. Foi incorporado: 0, 10, 20, 30, 40, 50, 60 e 80% do RSL ao substrato comercial. Determinou-se o índice de velocidade e a porcentagem de emergência das plântulas, e aos 26 dias após a semeadura foram determinadas as seguintes características: comprimento de raiz e da parte aérea, diâmetro do colo, número de folhas, volume de raízes e massa seca da parte aérea e de raízes. O resíduo de sisal pode ser incorporado ao substrato comercial Tropstrato® na formação de mudas de jiló e bróc', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3400', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a207', 'Caracterização de um solo salinizado em área irrigada da região Semiárida', 'R. V. Santos; A. F. M. Vital; J. A. Lopes; T. Muraoka', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A expansão das áreas irrigadas no semiárido acarreta sérios problemas de degradação dos solos, principalmente de salinização, reduzindo a capacidade produtiva das culturas. A compreensão de aspectos pedológicos é fundamental durante o manejo dessas áreas.  Objetivou-se com esse trabalho a caracterização do solo de uma área irrigada visando a preservação da qualidade dos solos nos perímetros irrigados. Foi selecionado um perfil representativo da área do Capoeira, no município de São José do Bonfim, mesorregião do Sertão Paraibano, microrregião de Patos, Bacia Hidrográfica do Rio Piranhas, Semiárido do Estado da Paraíba, Bioma Caatinga. O perfil na profundidade de 118 cm foi descrito em campo, em seguida, foram coletadas amostras para a realização das análises morfológicas, físicas, químicas e mineralógicas de cada horizonte. O solo foi classificado como CAMBISSOLO HÁPLICO Sálico sódico, com sequência de horizonte Ap, AB, Bi, BC e 2Ccom predominância de textura franco arenosa. A análise ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3456', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a20e', 'Desenvolvimento e caracterização de salgadinho produzido a partir de gritz de milho nixtamalizado', 'L. A. M. Pinto; G. A. P. Mateus; A. K. Hirata; M. M. Pinto; F. O. Tavares', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Neste trabalho, buscou-se o enriquecimento nutricional de salgadinhos produzidos a partir da extrusão do gritz de milho, para tanto, duas diferentes formulações foram testadas. A primeira formulação consistiu em utilizar o gritz de milho aplicando-se o processo de nixtamalização; processo este conhecido pelo tratamento do gritz alcalinamente, utilizando o hidróxido de cálcio como agente de tratamento, enquanto que a segunda formulação, foi desenvolvida com gritz sem tratamento. Para a caracterização dos salgadinhos foram realizadas análises da composição centesimal e mineral, cor, textura e índice de expansão. Em relação à composição centesimal e concentração de cálcio, a amostra nixtamalizada apresentou diferença significativa para os parâmetros de cinzas, fibras e cálcio. Os valores obtidos para cinzas, foram de 0,44%±0,02 para os salgadinhos tratados e de 0,24%±0,08 para os não tratados. Para o teor de fibra os valores alcançados foram de 0,83%±0,16 e 0,40%±0,03, para os salgadinhos', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3396', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a213', 'Análise microbiológica de frutas minimamente processadas servidas em uma Unidade de Alimentação e Nutrição', 'A. C. F. Sampaio; M. S. Moraes; C. G. C. Lisbôa; D. J. G. Quirino; A. D. F. Lins', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Produtos minimamente processados têm sido descrito como produtos manipulados, preparados, embalados e distribuídos, que passam por procedimentos como seleção, limpeza, lavagem, descascamento e corte que não comprometem suas características organolépticas e agreguem valor aos mesmos. Alguns desses procedimentos podem proporcionar lesões que resultam em aceleração da respiração, produção de etileno, senescência, amadurecimento, deterioração e uma contaminação microbiológica. Partindo desse pressuposto, esse trabalho tem como objetivo verificar as condições microbiológicas de mamão, melão, abacaxi e melancia minimamente processados, provenientes de uma Unidade de Alimentação e Nutrição de um município da Região do Cariri do Estado do Ceará. As análises de coliformes totais, termotolerantes e detecção de Salmonella sp, foram realizadas segundo os padrões e metodologias da Americam Public Health Association. Através dos resultados deste trabalho baseados na RDC Nº 12, de 2 de Janeiro de 200', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3305', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a214', 'Arborização em canteiros centrais na cidade de Patos, Paraíba', 'P. C. Souto; J. N. Lucena; J. D. Z. Camaño; L. S. Souto; J. S. Souto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A arborização de canteiros nas cidades é uma prática que embeleza e permiti reduzir efeitos antropogênicos. O trabalho objetivou quantificar e avaliar a qualidade das árvores localizadas em canteiros centrais da cidade de Patos-PB e o risco que elas representam para a população. Foi realizado o levantamento florístico em 1.391,95 m de canteiros centrais, registrando informações dendrométricas e qualitativas quanto aos aspectos das condições existentes no meio. Foram registrados 166 indivíduos representados em 14 espécies, sendo 71,4% exóticas com destaque para Azadirachta indica e Prosopis juliflora. A maioria das árvores são adultas e medem mais de 10 cm de DAP com altura variando entre 1,6-7,21 m. Em relação à avaliação do risco, não registrou-se indivíduos em conflito com as redes elétricas e sim a presença de galhos ocos nos níveis médio e leve. Na maioria dos indivíduos o sistema radicular apresenta-se subterrâneo, mas, observou-se que 70,1% não apresentam neilóides em superfície,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3761', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a215', 'Comportamento cinético do fermentado alcoólico de banana prata (musa ssp) frente a diferentes parâmetros', 'M. T. Leite Filho; M. E. R. M. C. Mata; E. M. Pereira; E. R. Florentino; B. B. M. Pereira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Dentre as frutas fermentescíveis que podem ser utilizadas na elaboração de bebidas fermentadas (bebidas alcoólicas), a banana se destaca devido a sua abundância e concentração relativamente elevada de açúcares. O trabalho teve por objetivo desenvolver e avaliar o rendimento e a qualidade físico-química de um novo produto: o fermentado alcoólico de banana. Foi elaborado um protótipo do produto, utilizando a variedade de banana prata, cuja fruta foi comprada no mercado local da cidade de Campinha Grande - PB. Foi feito um tratamento térmico a 120°C por 15 min. O teor de sólidos solúveis do caldo foi de 12,5 °Brix e estes foram inoculados com levedura do gênero (Saccharomyces cerevisiae) em frascos de Erlenmeyer, à temperatura ambiente. Após 9 h, a fermentação cessou. As análises físico-químicas foram realizadas a cada 1 h. O teor alcoólico final obtido foi de 3,75°GL, o pH final foi de 4,1, os sólidos solúveis °brix ficaram em torno de 3,4 os açúcares redutores totais ficaram em torno de', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3740', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a216', 'Evapotranspiração da cultura da cebola', 'E. C. S. Cavalcante; G. M. Oliveira; M. N. Daamen; M. W. Silva; M. M. V. B. R. Leitão', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A determinação da quantidade de água necessária para as culturas é um dos principais fatores para o correto planejamento, dimensionamento e manejo de qualquer sistema de irrigação. O presente trabalho teve como objetivo, comparar medida da evapotranspiração da cultura (ETc) da cebola com estimativa obtida a partir da evapotranspiração de referência (ETo) determinada por diferentes métodos e Kc proposto na literatura. O experimento foi conduzido no campo experimental do Departamento de Tecnologia e Ciências Sociais da Universidade do Estado da Bahia - UNEB, em Juazeiro, no período de junho a setembro de 2011. As medidas da ETc foram obtidas em evapotranspirômetros e as estimativas, a partir de ETo determinada pelos métodos: Penman-Monteith (padrão FAO), Penman-Monteith modificado por Villa Nova et al. (2004), Hargreaves & Samani, Makkink e Jensen & Haise e Kc proposto por Marouelli et al. (2005), para a cultura da cebola. É fundamental a avaliação de métodos de estimativa da evapotransp', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3437', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a218', 'Produção de briquetes a partir de espécies florestais', 'R. M. C. Costa; C. H. A. Borges; M. X. Ribeiro; F. S. Amorim; T. P. Protásio', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O setor madeireiro do Brasil produz uma grande quantidade de resíduos, causando danos ao meio ambiente. Diante desse cenário, objetivou-se produzir e avaliar briquetes a partir de serragem de madeira produzida por uma marcenaria localizada no extremo sul do Piauí, visando seu uso tecnológico como fonte energética. Os resíduos utilizados no trabalho são das espécies de Ipê roxo (Tabebuia impetiginosa M.), Pinus sp. L. e Violeta (Daugerbia cearensis D.). A serragem foi coletada em uma marcenaria localizada no município de Corrente-PI. Utilizou-se uma prensa hidráulica de 15 Ton, adaptada. Os briquetes foram avaliados em relação à densidade aparente, densidade a granel, análise química imediata, PCS, PCI, e ICOM. Os briquetes apresentaram densidade aparente média 1,229 g/cm³ (Pinus sp.), 1,225 g/cm³ (Violeta) e 1,139 g/cm³ para o Ipê roxo. Os briquetes da espécie Ipê roxo obteve o maior ICOM, com 0,3961. Observou-se pouca diferença nas dimensões, densidade e ICOM dos briquetes, quando uti', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3779', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a219', 'Elaboração e caracterização físico-química e microbiológica da farinha da palma (Opuntia fícusindica Mill) em diferentes temperaturas', 'D. S. Severo; G. S. Alves; J. N. V. Deodato; C. C. M. Silva; A. S. Araújo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A Palma forrageira (Opuntia fícusindica Mill) é uma cactácea originária do México, porém bastante cultivada na região semiárida do nordeste. Na alimentação humana, geralmente, são usados em preparações culinárias os brotos de palma, os frutos in natura ou processados. Uma das maneiras de diversificar o uso da palma forrageira seriam a secagem e sua transformação em farinhas para incorporação em diversos produtos. Desta forma o objetivo deste trabalho foi avaliar a qualidade físico-química e microbiológica da farinha. As amostras foram coletadas na zona rural e transportadas para o laboratório do Centro Vocacional e Tecnológico /UFCG – Campus Pombal – PB, as mesmas foram desidratadas até a total retirada da umidade em estufa de circulação de ar nas seguintes temperaturas: 70, 80 e 90 °C, posteriormente passaram por um liquidificador industrial, em seguida por um moinho de facas para a obtenção da farinha. Após a obtenção foram realizadas as análises microbiológicas e analises físico-quí', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3793', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a21a', 'Produção de mudas de maracujazeiro amarelo com diferentes tipos de enxertia e uso da câmara úmida', 'K. G. V. Garcia; R. M. da Silva; A. V. M. de Aguiar; E. de A. Cardoso; V. Mendonça', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi avaliar a combinação de três formas de realização da enxertia pelo método de garfagem e uso da proteção da enxertia com câmara úmida na a produção de mudas de maracujazeiro. O delineamento experimental adotado foi o de blocos ao acaso em esquema fatorial (3x2), com seis repetições, sendo cada parcela constituída de nove plantas, os fatores formaram as combinações de três formas de realização da enxertia pelo método de garfagem (fenda cheia, fenda lateral e fenda simples) e utilização e não do uso da proteção da enxertia com câmara úmida. Para produção das mudas dos portaenxertos e enxertos foram utilizadas sementes das cultivares FB 100 e redondo amarelo respectivamente. As enxertias foram realizadas aos 70 dias após a semeadura. Aos 21 dias após as enxertias foi avaliada a porcentagem de pegamento e a cada 14 dias após a enxertia avaliou-se a sobrevivência de plantas que permaneceram vivas, aos 56 dias avaliou-se o número de folhas, diâmetro do enxerto e ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3824', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a21c', 'Estimação da área foliar da “jitirana” (Merremia aegyptia (l.) Urban), através de modelos de regressão para Mossoró - RN', 'J. P. Assis; R. P. Souza; M. F. S. Pereira; A. M. B. Almeida; P. C. F. Linhares', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A mensuração da área foliar é requerida em vários estudos agronômicos, ecológicos e biológicos de uma maneira geral. O objetivo deste trabalho foi obter equações de regressões lineares e não lineares que estimem a área foliar real da espécie jitirana, em função das dimensões do comprimento ao longo da nervura principal (C) e largura máxima (L). Para isso 200 limbos foliares foram coletados em ecossistemas de ocorrência natural desta espécie vegetal, na região de Mossoró, no Estado do Rio Grande do Norte, limpas e acondicionadas em caixa de isopor e medidas imediatamente, inclusive sua área real através do Integrador de Área foliar. Considerando a parcimônia do modelo, o coeficiente de determinação e a significância do teste F da análise de variância a 3 % de probabilidade, as melhores equações para estimação da área foliar da jitirana em ordem de importância foram: modelo linear simples passando pela origem em função do produto do comprimento com a largura da folha; linear simples em f', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3872', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a220', 'Modelagem matemática da desidratação osmo-convectiva da palma forrageira (Opuntia fícus-indica Mill) utilizando soluções mistas', 'E. T. Silva; R. P. Gusmão; T. A. S. Gusmão; E. C. O. Silva; J. D. Lopes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se nesse estudo avaliar a influência de pré-tratamentos osmóticos utilizando secagem convectiva complementar no processo de perda de água, ganho de sólidos e nos parâmetros de qualidade (cor, atividade de água e textura) de cladódios de palma forrageira. O Cladódio foi submetido à desidratação osmótica utilizando soluções mistas contendo 5% de NaCl e concentrações de sacarose de 50 e 60 °Brix, em diferentes proporções palma/solução (1:1, 1:4 e 1:10) a 40°C. Posteriormente foi realizada secagem convectiva a 50 e 60 °C. Foram utilizados, para ajuste aos dados experimentais da secagem, os modelos matemáticos de Page, Henderson & Pabis, Cavancanti Mata, Exponencial de Dois Termos e Midilli. O cladódio de palma in natura e desidratado foi caracterizado quanto aos parâmetros de cor, atividade de água e textura. O aumento da perda de massa foi proporcional ao aumento da proporção cladódio/solução utilizada na desidratação osmótica e o ganho de sólidos foi maior para a concentração d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3489', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a224', 'Biometria, caracterização física e rendimento lipídico do fruto de Licania rigida Benth adquiridos no município de Pombal-PB', 'A. dos S. Araújo; A. E. F. Marque; G. S. Alves; T. N. Albuquerque; T. S. S. Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Resumo: Licânia rigida Benth, popularmente oiticica, é uma vegetação típica no sertão nordestino. Destaca-se pelo alto teor de óleos em seus frutos e boa produtividade mesmo em épocas de seca, sendo capaz de promover desenvolvimento social e econômico para a região, pela utilização industrial de tintas, vernizes, sabão, lonas e esmaltes finos. Portanto, objetiva-se no presente estudo determinar a biometria, parâmetros físicos e rendimento lipídico do fruto da oiticica. Os frutos foram colhidos, selecionados, sanitizados. Em seguida, utilizou-se um paquímetro para a realização da biometria dos frutos e então sofreram separação em exocarpo-mesocarpo, endocarpo e amêndoas. As amostras foram trituradas e armazenadas ate procedidas as análises. Para a determinação do pH e condutividade, utilizou-se cerca de 5g de cada amostra, acrescidos de 50mL de água destilada e homogeneização, por conseguintemente foi utilizado o peagâmetro digital e condutivímetro, respectivamente. Para a acidez total ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3961', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a227', 'Desenvolvimento de Cerveja Artesanal com Acerola (Malpighia emarginata DC) e Abacaxi (Ananas comosus L. Merril)', 'L. I. F. Pinto; E. C. Santos Junior; R. A. Zambelli; D. F. Pontes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A cerveja é a bebida alcoólica mais consumida no mundo. Estando bem relacionado com festividades e comemorações, porém essa bebida contém uma variedade de compostos bioativos, vitaminas e minerais, capazes de promover benefícios quando a sua ingestão é feita de maneira moderada. O mercado está a cada dia buscando produtos diferenciados e até exclusivos, surge assim o campo das cervejas artesanais. O objetivo deste trabalho foi desenvolver uma cerveja artesanal com acerola e abacaxi, trazendo uma nova alternativa ao nicho de mercado, além da associação ao aumento de suas características funcionais. O experimento foi conduzido no Laboratório de Cereais, Universidade Federal do Ceará – UFC, onde a cerveja foi produzida em escala laboratorial passando pelos processos de moagem do malte, mosturação, cozimento, decantação, filtração, fermentação, envase, maturação e primming, sendo adicionada a polpa de fruta em percentagem definidas por DIC, pasteurização e armazenamento. As amostras foram ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3416', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a22d', 'Desenvolvimento de espécies de pimentas sobre efeito de doses urina de vaca', 'M. K. L. V. Barros; H. M. M. Barros; D. L. Oliveira; M. da S. Santos; L. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A crescente demanda do mercado de pimentas tem impulsionado o aumento da área cultivada no Brasil anualmente, no Nordeste brasileiro esse cultivo vem sendo feito não apenas em hortas caseiras para o consumo doméstico, como também em áreas comerciais que abastecem o mercado local e externo. Diante disso objetivou-se verificar os efeitos da utilização da adubação orgânica no cultivo de espécies de pimenta no intuito de possibilitar aos agricultores desenvolverem sua produção utilizando-se de práticas onde produtos alternativos e de baixo custo econômico e ambiental disponíveis em suas propriedades como é o caso da urina de vaca que pode ser utilizados como fertilizante além de possuir outras propriedades favoráveis a este cultivo. Foram usadas as espécies Cambuci, Dedo-de-moça, Bode Amarela e as proporções de urina de vaca utilizadas nas pulverizações foram de 1 a 5%. As variáveis analisadas foram à altura, diâmetro do caule e matéria seca do caule das plantas após a semeadura. A dosagem', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4676', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a22f', 'Análise dos determinantes de adoecimento e mortalidade dos agricultores da 9ª Região Geoadministrativa do Estado da Paraíba', 'Symara Abrantes Albuquerque de Oliveira Cabral; Henrique Miguel de Lima Silva; Patrício Borges Maracajá; Sayonara Abrantes de Oliveira Uchoa; Maria Carmem Batista de Alencar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Entendendo que a saúde deve ser constituída como um conceito que vai além da ausência de doença, abrangendo aos aspectos biopsicossociais, e atrelado ao determinante de que a atividade rural traz consigo aspectos insalubres que podem vir a constituir em agravamento à saúde do agricultor, com possibilidade ainda de culminar em óbito. Diante de tais pressupostos é que o presente trabalho busca o conhecimento dos determinantes de adoecimento e mortalidade dos agricultores da 9ª Região Geoadministrativa do Estado da Paraíba, contribuindo para que, de posse de tais informações, estas possam ser utilizadas como base para o planejamento de ações de saúde direcionadas a esta população, bem como para subsidiar outros trabalhos do mesmo tipo em outras regiões, fortalecendo assim a prevenção de agravos e promoção à saúde do agricultor. Para tal realizou-se uma  pesquisa exploratória, descritiva, retrospectiva, documental, com abordagem quantitativa dos dados, com vistas a contemplar os objetivos ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3490', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a231', 'Condutividade elétrica, pH e a relação adsorção de sódio nas águas de poços do município de Pombal-PB', 'Patrício Borges Maracajá; Diego Lima Crispim; Manoel Moisés Ferreira de Queiroz; Ricardo Ricelli Pereira de Almeida; Alan Del Carlos Gomes Chaves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No meio rural, os poços rasos e nascentes são as principais fontes de abastecimento de água e bastantes susceptíveis à contaminação. Este trabalho objetivou monitorar a condutividade elétrica e o pH e quantificar relação de adsorção de sódio (RAS) nas águas dos poços das comunidades Bezerro e Várzea comprida dos Oliveiras, no município de Pombal -PB. A pesquisa foi desenvolvida em quatro etapas, sendo a primeira delas um reconhecimento da área de estudo. Na segunda etapa, foi feito um reconhecimento através de visitas in loco por parte dos produtores na comunidade, na qual foi feito também levantamento dos poços artesianos existentes na comunidade Várzea Comprida dos Oliveiras e da comunidade Bezerro e levantamento das culturas agrícolas desenvolvidas na região e os agrotóxicos utilizados. A terceira etapa foi realizada através do georreferenciamento e definição dos poços tubulares e na quarta etapa foi feito o monitoramento das águas subterrâneas dos poços estudados. Houve uma redução', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3222', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a235', 'Diagnóstico da degradação ambiental na área do lixão de Pombal - PB', 'José Cleidimário Araújo Leite; Pollyana Bezerra de Azevedo; Franciédna Maria da Silva; Woslley Sidney Nogueira de Oliveira; Paloma Mara de Lima Ferreira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os lixões urbanos são práticas antigas e constantes nas cidades brasileiras, nas quais os resíduos sólidos são depositados em locais inadequados e sem qualquer tratamento, o que vem a ocasionar impactos para a população, a saúde pública e o meio ecológico. Neste trabalho teve- se como objetivo elaborar um diagnóstico qualitativo da degradação ambiental na área do lixão de Pombal-PB. A metodologia teve por base a realização de visitas de campo, entrevistas aos gestores do município, catadores da área do lixão e moradores no entorno da área em estudo. Fez-se a identificação dos impactos ambientais utilizando-se os métodos Ad Hoc e Check Lists, e proposição de medidas voltadas à recuperação da área. De acordo com os resultados, observou-se que os principais impactos diagnosticados foram: a contaminação do solo, dos recursos hídricos, do ar atmosférico; o aumento dos processos erosivos; redução ou perda total da fauna e flora; riscos aos catadores e impacto na saúde pública. Os fatores mai', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3294', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a236', 'Diagnóstico da poluição ambiental em área de preservação no município de Lagoa Seca - Paraíba', 'Jean Pereira Guimarães; Maria Sallydelândia Sobral Farias; Júlia Soares Pereira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A água é um recurso natural renovável finito, no entanto sua qualidade vem se agravando decorrente da crescente população e à falta de políticas públicas para a preservação deste recurso. Nesse sentido, este trabalho teve por objetivo diagnosticar a Área de Preservação Ambiental (APA) do Posto de Fomento, localizado no Centro de Ciências Agrárias e Ambientais – CCAA, da Universidade Estadual da Paraíba Campus II, onde funciona também a Escola Agrícola Assis Chateaubriand, caracterizado pelos experimentos práticos realizados pelos estudantes técnicos e graduandos, que fica em torno de duas comunidades rurais, Vila Florestal e Ipuarana no município de Lagoa Seca - Paraíba. Foram avaliados os problemas de degradação da área (resíduos sólidos, desmatamento, invasão e retirada de riquezas dentro da área) e qualidade da água de uma fonte dentro da reserva. Assim, constatou-se que em muitos pontos da área há elevado grau de degradação, através da exploração dos recursos naturais e lançamento ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2791', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a239', 'Eficiência na remoção de coliformes em águas cinza através da fitorremediação', 'S Nicola; Aline C. Ferreira; Jórgerson P. G. Pereira; Verena S. Baracuhy; Viviane F. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O semiárido é caracterizado pelas irregularidades pluviais e o tratamento de águas cinza para reuso na agricultura com tecnologia ecológica é uma forma de conviver com a seca nessas regiões. Nesse contexto, a pesquisa foi realizada no distrito de Ribeira no município de Cabaceiras/PB objetivando-se avaliar a eficiência da remoção dos coliformes totais e fecais do efluente tratado nas unidades de produção agrícola através da fitorremediação. Foram realizados dois tratamentos com e sem fitorremediação, a cultura utilizada foi o capim roxo. As águas cinza eram provenientes de uma lavanderia pública. Foram coletadas amostras mensais e analisadas os coliformes total e fecal (Escherichia coli). No tratamento sem fitorremediação, os coliformes totais variaram de 1,583 x 103 a 2,0224 x 103 (UFC/100 mL) e quando o tratamento tinha o auxílio do capim roxo, ou seja, com fitorremediação os coliformes totais oscilaram de 1,354 x 103 a 2,0224 x 103 (UFC/100 mL). Ocorreu uma redução significativa de ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3330', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a23a', 'Potencial toxicológico frente Artemia Salina em plantas condimentares comercializadas no município de Campina Grande-PB', 'Ana Paula Trindade Rocha; Emmanuel Moreira Pereira; Ana Nery Alves Martins; Francisco de Assis Mendes; Manoel Tolentino Leite Filho', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O conhecimento do potencial toxicológico das plantas é um fator primordial para estipular o limite consumível. Objetivou-se nesse trabalho avaliar o potencial toxicológico de plantas condimentares frente Artemia salina, expostas às concentrações dos extratos das plantas erva-doce (Pimpinella anisum L.), pimenta malagueta (Capsicum frutescens), endro (Anethum graveolens L.) e alecrim (Rosmarinus officinalis L.). O trabalho foi desenvolvido no Laboratório de Engenharia de Alimentos - LEA pertencente ao Centro de Tecnologia e Recursos Naturais da Universidade Federal de Campina Grande-PB. A erva doce apresentou uma baixa toxicidade, atingindo uma DL50 de 428ppm do extrato. Já a pimenta malagueta exibiu um comportamento similar, atingindo o seu potencial toxicológico máximo na terceira diluição com DL50 716,1ppm. Para o endro, observou-se uma baixa taxa de mortalidade, consequentemente foi considerada não toxica, apresentando a DL50, com 2.624,5ppm. O alecrim apresentou baixos percentuais ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3327', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a23d', 'Efeito da estocagem de massas congeladas nos parâmetros colorimétricos de pães tipo forma adicionados de ingredientes funcionais', 'Lucicléia Barros de Vasconcelos Torres; Rafael Audino Zambelli; Gerla Castello Branco Chinelate; Luan Ícaro Freitas Pinto; Dorasílvia Ferreira Pontes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente teve como objetivo estudar o efeito da estocagem congelada de massas por até 60 dias nos parâmetros colorimétricos de pães tipo forma. Foram desenvolvidas 7 formulações de pães tipo forma, uma padrão, sema adição de ingredientes funcionais e as  contendo as combinações dos ingredientes açaí em pó/polidextrose, brócolis em pó/polidextrose e tomate em pó/polidextrose nas proporções de 5% e 10% cada. Através de análise de cor instrumental foram avaliados os parâmetros de luminosidade (L), cromaticidades a* e b*, o croma (C*) e o ângulo de tonalidade (h°) do miolo dos pães nos tempos 0, 15, 30, 45 e 60 dias. Para a formulação padrão, a luminosidade apresentou redução de  77,38 a 69,43, houve redução na cromaticidade a* e ângulo de tonalidade, já a cromaticidade b* e croma apresentaram elevação em função do tempo de estocagem. Para as formulações contendo ingredientes funcionais, o comportamento foi semelhante, os pães tiveram menor luminosidade quando comparada à padrão, à medid', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3342', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a23e', 'Análise histológica do impacto da isotretinoína na ossificação endocondral em ratos Wistar', 'Thiago de Oliveira Assis; Flávio Silva Sento Sé Paccelli; Tharcia Kiara Beserra de Oliveira; Huggo Luãn Barros Medeiros; Marina Suênia de Araújo Vilar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A isotretinoína é uma droga de ação teratogênica, utilizada no tratamento da acne vulgar por causar a redução no tamanho das glândulas sebáceas e ainda normalizando a queratina na abertura do folículo piloso. Relatos indicam que o uso desse fármaco está envolvido com malformações ósseas. Objetivou-se nessa pesquisa analisar as conseqüências do uso da isotretinoína sobre o processo de ossificação endocondral, de jovens ratos Wistar machos submetidos à ingestão oral de uma dose de 8mg/kg/dia dessa medicação, do 17º ao 30º dia de vida. A amostra composta por 20 espécimes foi distribuída entre o Grupo Controle (recebendo apenas óleo vegetal, com n=10) e o Grupo Experimento (recebendo a isotretinoína diluída em óleo vegetal, com n=10). Ao fim da administração os animais foram eutanasiados e os fêmures foram coletados, dissecados e realizados cortes para a confecção das lâminas histológicas coradas pela técnica da Hematoxilina-Eosina. A análise microscópica do material permitiu verificar uma', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2650', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a23f', 'Desempenho de híbridos de milho e da forrageira Brachiaria brizantha em cultivo consorciado', 'Priscila Barcello Maia; Iurhy da Silva Rezende; Flavio Heiji Tsumura', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O estudo teve como objetivo avaliar o desempenho de híbridos simples de milho em consórcio com a forrageira (Brachiaria brizantha). O experimento foi conduzido no município de Cassilândia-MS utilizando delineamento experimental de blocos casualizados, com cinco repetições. Os tratamentos foram compostos por seis híbridos simples de milho: DKB390, BMX944, DKB399, P30F35H, P3862H e BM810. O milho foi plantado com semeadora mecanizada, no espaçamento de 0,90 m entrelinhas. A forrageira foi semeada a lanço aos 48 dias após semeadura do milho. Foram avaliados os parâmetros de componentes de produção dos híbridos de milho e da forrageira aos 117 dias após a semeadura do milho. Pelos resultados observados, o híbrido DKB399 apresentou melhor rendimento no cultivo em consórcio, sendo o mais indicado para o município de Cassilândia-MS.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2527', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a245', 'Análise de coliformes e verificação das Boas Práticas de Fabricação de carne moída comercializada na cidade de Campina Grande-PB', 'Alfredina dos Santos Araújo; Ana Paula Trindade Rocha; Renata Rodrigues de Lima Silva; Deyzi Santos Gouveia', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A indústria de alimentos é um ramo que se desenvolve ao longo dos anos e, com isso, a exigência por produtos microbiologicamente seguros é cada vez maior, visando evitar prejuízos financeiros e garantir a segurança alimentar ao consumidor. Nesse ramo, existem práticas que são adotadas a fim de garantir a qualidade sanitária e a conformidade dos produtos alimentícios com os regulamentos técnicos vigentes, buscando sempre métodos eficazes de prevenção contra a deterioração de alimentos e aumento de vida de prateleira. No setor de carnes, o controle do desenvolvimento microbiano é de grande importância, visto que este é um alimento que possui características favoráveis à proliferação de microrganismos. Foram avaliadas amostras de carne moída comercializadas em três redes de distribuição distintas. Em todas as amostras avaliadas, foi determinada a presença de coliformes totais, bem como valores superiores a 14% de inconformidade nos itens relacionados às Boas Práticas de Fabricação.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3380', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a246', 'O consumo de alimentos orgânicos na cidade de Manaus (AM): o comércio de produtos e a sustentabilidade do setor', 'Sinaida Maria Vasconcelos de Castro; Paula de Fátima da Cruz Lima; Maria de Valdivia Costa Norat Gomes; Aline Maria Meiguins de Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A produção de alimentos orgânicos proporciona a oferta de produtos saudáveis; o uso sustentável da água e do solo; a integridade cultural das comunidades rurais; a sustentabilidade econômica e ecológica; e a eliminação do uso de organismos geneticamente modificados em qualquer fase do processo de produção, processamento, armazenamento, distribuição e comercialização. Considerando a importância ecológica da região Amazônica, foi avaliado o mercado de consumo de produtos alimentícios orgânicos em Manaus-Amazonas e caracterizado seu perfil de consumo, potencialidade e limitações. A pesquisa foi realizada junto a Associação de Produtores Orgânicos do Amazonas. Os resultados indicaram os consumidores são em sua maioria do sexo feminino, com faixa etária entre 30 a 40 anos, nível de escolaridade superior completo, em sua maioria, com uma renda superior a 4 salários mínimos. São clientes e consumidores fiéis, porém não avaliam com critério o alimento que estão adquirindo. Os produtores encont', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3131', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a24a', 'Elaboração e qualidade de geleia e compota de abacaxi “pérola"', 'Emmanuel Moreira Pereira; Manoel Tolentino Leite Filho; Bárbara Bruna Maniçoba Pereira; Paticio Borges Maracajá; Yvana Maria Gomes dos Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O abacaxi é uma fruta largamente consumida no país sendo na forma processada ou in natura. Objetivou-se neste trabalho elaborar uma formulação de geleia e compota de abacaxi tipo “pérola” e sua composição físico-química. Objetivou-se elaborar geleia e compota de abacaxi “perola” e a sua composição físico-química. O experimento foi conduzido no Laboratório de Pesquisa e Desenvolvimento de Produtos Frutohortícolas – PDFRUTHO, Campus Bananeiras – Bananeiras/PB, pertencente à Universidade Federal da Paraíba. As etapas utilizadas na elaboração da compota foram: seleção, lavagem e sanitização, extração da polpa, formulação, concentração, envase, resfriamento e rotulagem. Para os parâmetros químicos avaliados foram pH, vitamina C, sólidos solúveis (SS),  acidez titulável (AT) e a condutividade elétrica. A geleia obtida apresentou valor de pH3,94, o teor de acidez titulável  foi de 0,24 ( em ácido cítrico) de sólidos solúveis totais (SS) de 37,94°Brix, de vitamina C de 1,84 mg/100 g e condutiv', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3440', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a24c', 'Produção de mudas de cultivares de alface utilizando duas espumas fenólicas em Altamira, Pará', 'Djair Alves Moreira; Pedro Vitoriano de Araujo Junior; Alzirio Lino Couto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O sucesso de qualquer produção comercial de hortaliças inicia-se com a produção de mudas. A espuma fenólica tem se mostrado um interessante e prático substrato para este processo. A utilização deste produto depende de uma lavagem precedente para reduzir a acidez. Porém, já é possível encontrar à venda espumas fenólicas com pH próximo. Por isso o objetivo deste trabalho foi avaliar a produção de mudas de cultivares de alface utilizando duas espumas fenólicas em Altamira, Pará. O delineamento constou de um esquema fatorial 2 (substratos) x 6 (cultivares). Os dois substratos foram as espumas fenólicas Green Up®, com pH 6.0 (± 0.5)., e a outra com pH 2.6 (± 0.5). As cultivares avaliadas foram: Alcione, Amanda, Lucy Brown, Caipira, Multiblond 3 e Solaris. Foi avaliada porcentagem de germinação, índice de velocidade de emergência, altura da planta e número de folhas. Houve diferença significativa para altura da planta em função dos substratos testados. A porcentagem de germinação mais elevad', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3072', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a24e', 'Análise sensorial da água de coco anão verde processada e comercializada no sertão paraibano e cearense', 'Mônica Tejo Cavalcanti; Antonio Vitor Machado; Cícera Gomes Cavalcante de Lisbôa; Suziane Alves Josino Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O Brasil, atualmente, possui uma grande tendência de crescimento do cultivo do coqueiro anão verde, onde o principal objetivo deste se da para a produção da água de coco, sua cultura esta distribuída em todo o território nacional, destacadamente na região Nordeste onde se concentram os maiores plantios do país. A água de coco é um produto natural que vem ganhando espaço no mercado como uma bebida de vasto potencial comercial, pois além de ser um produto natural é praticamente livre de contaminações, possui baixo teor calórico, considerável valor nutricional e apresenta aroma e sabor suaves e agradáveis. Neste contexto se faz necessário a avaliação da qualidade sensorial da água de coco industrializada e comercializada de forma a garantir a qualidade do produto para o consumidor. Com isso este trabalho objetivou avaliar sensorialmente á água de coco anão verde, produzidas comercialmente e envasadas, por indústrias do Sertão Paraibano e do Ceará. As amostras de água de coco proveniente d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3466', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a257', 'Diagnóstico e desenvolvimento inicial de mamoneira em solos de áreas degradadas', 'Girlânio Holanda Silva; Adriana Fátima Meira Vital; Rivaldo Vital Santos; Kely Silva do Ó', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A degradação do solo no semiárido também ocorre pelo desmatamento da Caatinga e pela remoção da camada superficial do solo, cujo destino é a indústria de cerâmica ou olarias. O presente trabalho objetivou avaliar o crescimento da mamoneira em solos degradados. Os tratamentos consistiram de solos degradados: subsolo degradado-1, subsolo degradado-2 e área desmatada; quatro doses de fósforo (0, 100, 200, 300 mgkg-1 P), com três repetições. As testemunhas absolutas, sem fósforo, corresponderam ao solo salinizado não corrigido, solo-1 não degradado, solo-2 não degradado e solo de caatinga não desmatada. O solo degradado por sais, o subsolo-2, recebeu correção com gesso agrícola, foi incubado e lavado. Os resultados demonstraram que a análise do subsolo degradado revelou alta salinidade e baixos teores de fósforo e matéria orgânica, o subsolo degradado salino exige correção com gesso para tornar possível o cultivo da mamona em caatinga desmatada e subsolos degradados. As doses de fósforo nã', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2809', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a258', 'Efeitos de farelo alimentar fibroso produzido a partir da linhaça em indivíduos com constipação intestinal', 'Andressa L. Nóbrega; Vicente Maia Pinto Junior; Fernanda S. Lopes; Jéssica S. Oliveira; Débora S. S. Martins', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A preocupação com o bem estar e a melhora da qualidade de vida tem levado as pessoas a consumirem alimentos mais saudáveis os chamados alimentos funcionais, no qual se destaca os que contêm fibra alimentar. Devido às propriedades fibrosas que a linhaça constitui, o presente trabalho teve por objetivo avaliar a eficácia da ingestão de um farelo alimentar rico em fibras, em indivíduos sedentários e não sedentários com constipação intestinal. O presente estudo apresentou caráter laboratorial e experimental com abordagem quantitativa utilizando-se o método da estatística descritiva. O farelo foi produzido à base da semente de linhaça, com adição de outros ingredientes fibrosos, foi embalado e rotulado, e em seguida distribuído para o consumo. De acordo com os dados obtidos, na análise da composição nutricional do farelo fibroso evidenciou-se um teor apreciável de fibra alimentar. Para a avaliação das características organolépticas do farelo foi observado uma maior aprovação para o sabor, t', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3556', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a259', 'Desempenho de genótipos de batata-doce submetidos ao efeito da calagem em Rio Largo-Alagoas', 'Jackson da Silva; Kleyton Danilo da Silva Costa; Paulo Vanderlei Ferreira; Islan Diego Espindula de Carvalho; Alysson Jalles da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo desse trabalho foi avaliar o desempenho de genótipos de batata-doce submetidos ao efeito da calagem em Rio Largo-AL. O delineamento experimental utilizado foi o de blocos casualizados no esquema fatorial (7 x 2),  com sete genótipos de batata-doce e dois tipos de correção do solo, em três repetições. As variáveis avaliadas foram: Número de Raízes Comerciais (NRC); Número Total de Raízes (NTR); Comprimento de Raízes Comerciais (CRC); Diâmetro de Raízes Comerciais (DRC); Rendimento de Raízes Comerciais (RRC); Rendimento Total de Raízes (RTR) e Peso Médio de Raízes Comerciais (PMRC). Dentre os genótipos de batata-doce avaliados no experimento, o Clone-06 apresentou o melhor desempenho, superando todos os genótipos avaliados, inclusive as testemunhas, Rainha de Penedo e Sergipana, tanto em produtividade, com rendimento médio de 15,79 t.ha-1de raízes comerciais, quanto em qualidade, apresentando dimensões de raízes comerciais dentro dos padrões de comercialização como Extra A. O ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2805', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a25a', 'Bioproscpecção de linhagens de Trichoderma spp. na degradação de resíduos lignocelulósicos de sabugo de milho.', 'Marcos Giongo; Damiana Beatriz Silva; Aloísio Freitas Chagas Junior; Aquiles Rhuan Bandeira Neres Pinheiro; Lílian França Chagas', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', '- O Brasil é um grande produtor agrícola, e nos últimos anos a área plantada teve grande crescimento o que determina diretamente na quantidade de resíduos agroindustriais gerados. O etanol é um biocombustível de larga utilização e pode ser obtido de matérias primas que contenham açúcares ou polímeros de açúcares como os materias lignocelulósicos após passarem por processo de hidrólise enzimática. Os 70 isolados disponívies foram submetidas a identificação prévia por microcultivo em lamínula, teste de solubilização de carboximetilcelulose (CMC) em placa e avaliadas na degradação de sabugo de milho para produção enzimática. Das 70 estirpes, 66 tem fortes características morfológicas do gênero trichoderma segundo teste de microcultivo em lamínula e os isolados UFTJCO85 e UFTMG15 apresentaram as maiores atividades enzimáticas com 1,34 UI.mL-1 para FPase e 0,81 UI.mL-1 para CMCase, sem tratamento prévio no substrato.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2775', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a261', 'Avaliação da estimativa de fixação de carbono em sistemas agroflorestais na região amazônica', 'I. P. Dias; J. F. Almeida; M. M. Tourinho; B. C. Costa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho é identificar, descrever e analisar a literatura técnico-científica nacional sobre a estimativa de carbono em Sistemas Agroflorestais (SAFs), na região amazônica. Foi realizada uma revisão bibliográfica nas bases de dados dos portais eletrônicos mais significativos que tratam sobre o tema, postados entre os anos de 1998 e 2015. Conclui-se que, ainda há poucos estudos realizados sobre SAFs com fixação de carbono e são poucos os estudos apresentados sobre espécies nativas da Amazônia. Da mesma forma que apresentam poucas diferenças nas metodologias encontradas.Carbon fixation estimated assessment in agroforestry systems in the Amazon regionAbstract: The objective of this work is to identify, describe and analyze the national scientific and technical publications to be carried on carbon fixation in Amazon Agroforestry Systems (AFS). We performed a list of online databases literature review of the most significant portal for digital collections of electronic paper', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3411', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a264', 'Comportamento dos preços de milho e feijão caupi no mercado do estado do Ceará', 'A. M. Sousa; D. B. Nogueira; V. B. Silva; J. I. Pinheiro; A. M. Barroso Neto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A agricultura de subsistência (geralmente milho e feijão caupi) é a atividade econômica mais importante na Região Nordeste, sendo a baixa disponibilidade de água o principal obstáculo para a produção agrícola. O estudo dos preços dessas culturas torna-se importante ferramenta de tomada de decisão por parte de produtores, sendo a análise de sazonalidade a metodologia mais empregada no âmbito de análise de preços. O presente trabalho teve como objetivo analisar a sazonalidade dos preços do milho e feijão caupi produzidas no Estado do Ceará. Foi analisado o período de janeiro de 2005 à dezembro de 2014. A determinação dos índices estacionais de preços para a realização da análise de sazonalidade foi realizada através do método da média aritmética móvel centrada em 12 meses. O índice foi utilizado com a base em dezembro de 2014. Com a série de preços deflacionados calculou-se a média móvel centrada para cada mês a partir mês de julho de 2005 até o mês de junho de 2014. Com as médias determ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3399', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a269', 'Iogurte adicionado de polpa de abacaxi, base mel: Elaboração, perfil microbiológico e físico-químico', 'E. V. Silva; E. E. V. Silva; Y. F. Paiva; J. N. V. Deodato; A. S. Araújo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os produtos lácteos, são fonte importante para se obter nutrientes necessários para um bom funcionamento do organismo humano. Com o mercado consumidor em alta, sentiu-se a necessidade de adicionar ingredientes que auxiliam tanto na aceitação do produto final, quanto o tornando uma refeição mais nutritiva. Objetivou-se a elaboração de iogurte natural que uniu as propriedades nutritivas do abacaxi e do mel de abelha. As três formulações do produto (A,B e C) foram submetidas à análises microbiológicas (Coliformes à 35ºC e 45ºC, Salmonella sp/25g., Staphylococcus spp., Contagem total de bactérias aeróbias Mesófilas (CTM) e Psicotróficas) seguindo metodologia descrita por Silva (2010) e à análises físico-químicas (Umidade, Cinzas, Sólidos Solúveis (ºBrix), pH, Acidez e Proteínas) utilizando metodologia do Instituto Adolfo Lutz (2008). As três formulações apresentaram ausência emtodos os parâmetros microbiológicos analisados, exceto para CTM, apresentando valores de 1x 10 e 1,5x 10UFC/g, est', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3908', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a26a', 'Saúde, meio ambiente e segurança do trabalho associado ao uso de agrotóxicos', 'H. R. M. Garcia; J. Augusto; L. L. Ismael; W. A. Martins', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O trabalhador rural está exposto a diferentes situações de riscos durante o desenvolvimento de suas atividades no campo. Uma delas refere-se ao manuseio e aplicação incorreta de agrotóxicos, o que acaba por provocar sérios danos á saúde, não apenas do próprio agricultor mais da população local por consumir alimentos contaminados e ao ambiente. Para isto, o objetivo geral dessa pesquisa foi realizar um levantamento bibliográfico acerca dos riscos advindos das atividades agrícolas quanto ao uso de agrotóxicos. Os resultados evidenciaram que grande parte dos acidentes de trabalho, estão associados à utilização incorreta dos EPIs, além da falta de informação e treinamento dos agricultores para desenvolver tais atividades. Nesse contexto, medidas de caráter preventivo e corretivo deverão ser tomadas para a redução do uso e exposição aos agrotóxicos, para isso, devem ser implementadas no ambiente de trabalho ações socioeconômicas, políticas e ambientais.Health, environment and safety associa', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3731', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a26e', 'Avaliação da qualidade microbiológica da água do açude Engenheiro Ávidos, Cajazeiras-PB', 'A. E. F. Marques; A. dos S. Araújo; E. A. Sousa Filho; A. C. B. Vieira; T. S. S. Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A água é um recurso renovável de extrema importância para sobrevivência e manutenção das espécies, assim como preservação da fauna e flora. Nos últimos anos o homem vem modificando o ecossistema, através do desmatamento e crescimento dos centros urbanos que causam diferentes tipos de poluição, causando um grande desperdício e contaminação da água. Nesse contexto, é essencial conhecer a qualidade da água que é consumida em uma cidade. Por isto, neste trabalho, objetivou-se realizar uma avaliação da qualidade bacteriológica da água do açude Engenheiro Ávidos que abastece a cidade de Cajazeiras - PB. O trabalho foi realizado através de estudo aplicado do tipo exploratório quantitativo, no qual foi analisada a presença de bactérias heterotróficas a partir de contaminação fecal, ou seja, esgotos não tratados. Foram coletadas três amostras em diferentes pontos do açude, sendo estes: entrada do açude, proximidade das habitações e paredão. Após análise foi possível identificar que o açude Enge', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3960', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a271', 'Análises físicas, composição centesimal e nutricional de minimilho (Zea mays, L.) orgânico de diferentes variedades', 'A. S. O. D. Lima; L. F. Oliveira; V. R. Tolentino; A. R. Melo; C. S. V. Branco', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Atualmente os produtos orgânicos vêm roubando a cena dos produtos tradicionais, por serem saudáveis, livres de agrotóxicos e por gerarem menor impacto no meio ambiente. O minimilho (Zea mays, L.) também conhecido como “babycorn”, uma espiga imatura ainda não fertilizada (espiguetas), é uma hortaliça, produto considerado fino que vem ganhando importância no mercado de conservas no Brasil. Esta pesquisa se propôs avaliar a qualidade de minimilho orgânico in natura de diferentes variedades e determinar a composição centesimal e nutricional.Utilizou-se como metodologias analíticas as determinações de rendimento, peso médio, diâmetro e comprimento das espiguetas, além de pH, sólidos solúveis, acidez  titulável, umidade, cinzas, lipídeos,  proteínas, carboidratos e valor energético total. Com os resultados obtidos concluiu-se que as variedades que apresentaram maior rendimento foram Pipoca (48,75%), Eldorado (42,06%)e Branco (40,50%), sendo mais recomendadas para o beneficiamento e que o min', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3589', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a273', 'Desempenho agronômico de consórcios entre rabanete e alface no Oeste goiano', 'H. A. Carneiro; A. F. Lima Junior; T. P. Paim; A. M. Custódio; E. M. Alves', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os consórcios feitos de forma adequada podem resultar em inúmeros benefícios ao agroecossistema e ao produtor. O objetivo foi avaliar aspectos fitotécnicos do rabanete e alface cultivados em consórcio no oeste goiano. Foram testados 4 consórcios (com 8 plantas de alface e 20, 40, 60 e 80 plantas de rabanete, respectivamente, C I, C II, C III e C IV) em relação ao monocultivo de alface (16 plantas) e de rabanete (80 plantas) por metro quadrado. O delineamento foi em blocos casualizados, com quatro repetições. Avaliou o diâmetro, comprimento e massa média das raízes do rabanete; o diâmetro médio do coleto, número de folhas e massa média da parte aérea das plantas de alface e a produtividade de ambas as culturas. Calculou-se o índice de equivalência de área (IEA). O consórcio não afetou o tamanho e peso médio das raízes do rabanete, entretanto, a produtividade do C I (0,46 kg.m-2) foi inferior ao C III (1,97 kg.m-2), C IV (2,25 kg.m-2) e ao monocultivo (2,05 kg.m-2). Para a cultura da alf', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3828', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a276', 'Caracterização morfobiométrica de frutos e sementes e superação da dormência em coronha (Acacia farnesiana)', 'F. J. C. Moreira; M. L. S. Mesquista; M. C. Vasconcelos; M. C. M. R. Souza; L. G. Pinheiro Neto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O trabalho tem por objetivo caracterizar morfobiometricamente frutos e sementes de Acacia farnesiana além de avaliar diferentes métodos de superação da sua dormência. O trabalho foi desenvolvido no período de setembro 2014 a janeiro de 2015. As vagens foram coletadas de plantas nativas, no distrito Madeira, Sobral-CE. Para a biometria, utilizou-se 50 vagens, onde foi mensurado: comprimento, diâmetro, peso e número de sementes por vagem. Posteriormente feito o mesmo com as sementes, comprimento, largura e peso. Para a superação da dormência, utilizou-se nove tratamentos, dispostos em DIC, sendo (sementes sem escarificação, imersão em água a 80 ºC por 10, 20, 30 e 40 minutos, na imersão em H2SO4 concentrado por 10, 15, 20 e 25 minutos), com quatro repetições de 16 sementes cada. A avaliação de porcentagem de germinação - (%GER), realizou a contagem diária de plântulas emergidas, número de folhas (NF); altura da planta (AP); comprimento da raiz (CR); peso seco parte aérea (PSPA). Verifico', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3612', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a27b', 'Performance econômica e ambiental de agricultura agroflorestal e convencional  no município de Nova Olinda-CE', 'T. T. Silva; S. M. Silva; I. A. Bakke; M. A. Drumond', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Inúmeras experiências agrícolas alternativas surgiram no sertão nordestino. Com bons resultados, essas experiências agroflorestais expandiram-se para outras áreas, como, por exemplo, a Chapada do Araripe, no Ceará, Brasil. Este estudo teve como objetivo comparar os benefícios econômicos e ambientais de um sistema agroflorestal (SAF) em relação à agricultura convencional, no município de Nova Olinda-CE. A pesquisa foi realizada em uma propriedade que desenvolve o SAF comparando com uma que emprega a agricultura convencional. Utilizou-se, no estudo, a análise descritiva. Nos aspectos econômicos, foram avaliados: Valor Bruto de Produção (VBP), Custos na produção (CP), Lucro Bruto (LB) e Relação Benefício/Custo (B/C). Na performance ambiental,  utilizaram-se os parâmetros do Guia do Meio Ambiente para o Produtor Rural, elaborado pelo Banco do Nordeste. Para o teor de fertilidade do solo, foram colhidas amostras de solos de acordo com a metodologia da Embrapa Os resultados mostraram que o S', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3817', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a280', 'A produção de vôngole e seu potencial para o desenvolvimento de novos produtos a base de pescado', 'Gesilene Mendonça Oliveira; Mayla Monique dos Santos Leite', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A dificuldade em suprir a demanda de proteína de origem animal de excelente valor biológico para a população humana é uma das maiores preocupações do nosso século. De acordo com a FAO, a atividade pesqueira (pesca extrativa e aquicultura), será uma das principais atividades responsáveis pela segurança alimentar do planeta, com previsões de produção de proteína de origem animal para a próxima década maior do que o setor de animais de abate (carnes bovinas, suínas e aves). A utilização de recursos pesqueiros subutilizados com potencial para explotação poderá assegurar a manutenção da oferta primária de matéria prima no mercado interno local e/ou regional, e inibir oscilação de preços, como a prática da mariscagem. Neste contexto, o presente artigo de revisão tem por objetivo evidenciar o potencial da Anomalocardia brasiliana para explotação e processamento contribuindo para o fortalecimento desta cadeia produtiva no segmento artesanal e diversificação de produtos no mercado brasileiro.Th', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3374', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a282', 'Capacidade antioxidante de frutas e hortaliças', 'Marcela Cristina Machado Raposo; Elga Batista da Silva; Vanessa de Oliveira dos Santos; Michele Matias da Conceição', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A definição de alimentos funcionais ainda é controversa na literatura, são definidos como aqueles que apresentam concentrações de um ou mais ingredientes modificados ou manipulados para melhorar sua contribuição para dieta saudável. Esses alimentos apresentam ainda nutrientes em quantidades apreciáveis, como é o caso das frutas e hortaliças que apresentam em sua composição compostos antioxidantes capazes de combater os radicais livres. Objetivou-se com essa revisão bibliográfica discutir os benefícios dos compostos com atividade antioxidantes presentes em frutas e hortaliças. Este estudo se utilizou da revisão de literatura para buscar evidencias sobre o tema abordado. Os carotenoides formam uma classe de pigmentos presentes nos vegetais, além das propriedades biológicas envolvendo sua atividade antioxidante, destacarmos a função antioxidante dos compostos fenólicos e das vitaminas A, C e E. As vitaminas são substâncias orgânicas presentes em muitos alimentos em pequenas quantidades e ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3636', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a283', 'Avaliação de genótipos de feijão-caupi para produção de grãos verdes em Gurupi, Tocantins', 'Ildon Rodrigues do Nascimento; Tiago Alves Ferreira; Danilo Pereira Ramos; Anatercia Ferreira Alves; Rodrigo Ribeiro Fidelis', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O feijão-caupi, também conhecido como feijão-de-corda, é um dos componentes mais importantes da dieta alimentar de povos das regiões tropicais e subtropicais do mundo, sendo a principal fonte de proteína para os agricultores familiares das regiões norte e nordeste do Brasil. Com objetivo de avaliar o potencial de genótipos de feijão-caupi para produção de grãos verdes nas condições de Gurupi-TO, foi conduzido um experimento na estação experimental da Universidade Federal do Tocantins, Campus Universitário de Gurupi, no período de março a maio de 2013. Os tratamentos constituíram-se de vinte genótipos de feijão-caupi, sendo dezesseis linhagens e quatro cultivares. Utilizou-se o delineamento experimental em blocos ao acaso com quatro repetições. A parcela experimental foi representada por quatro linhas de cinco metros de comprimento, com espaçamento de 0,5 m entre linhas, sendo as duas linhas centrais a área útil. Foram avaliados comprimento de vagem, peso de vagem, peso de grãos por vag', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3640', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a284', 'Relato de ocorrência da ferrugem da teca, causada por Olivea neotectonae no Estado de Goiás', 'M. C. S. Virtuoso; G. R. Santos; J. M. I. Jesus; M. L. S. Marques; V. S. Marques', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A Teca (Tectona grandis) é uma planta originaria da Ásia e vêm sendo cultivada principalmente nas regiões Norte e Centro Oeste do Brasil. Porém algumas doenças podem provocar danos à produtividade e crescimento desta espécie, dentre estas fitopatologias está à ferrugem. Este trabalho objetivou-se a relatar a ocorrência do fungo Olivea neotectonae, causador da ferrugem na teca, pela primeira vez no Estado de Goiás. Em maio de 2013, foram observadas folhas da teca com sintomas de necroses que posteriormente provocavam desfolha precoce das plantas. Para avaliação inicial, folhas de teca foram coletadas em plantas localizadas na área do Instituto Federal Goiano Câmpus Ceres-GO. Em seguida, estas foram levadas ao laboratório de Microbiologia do Departamento de Ciências Agrárias. Na observação em microscópio óptico, foram visualizadas e medidas as estruturas fúngicas. Diante dos resultados obtidos no presente trabalho, pode-se concluir que o fungo causador de necroses em plantas observadas n', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3689', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a286', 'Avaliação gravimétrica dos resíduos de serviços de saúde no município de Rondonópolis (MT) Brasil', 'D. A. S. Santos; P. M. Souza; R. A. Olinda; R. X. Oliveira; M. S. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O resíduo de serviço de saúde (RSS) é resíduo proveniente de atividades exercidas em estabelecimentos diferenciados (seja biológico, químico, perfurocortantes e comum produzidos dentro desses locais), que vem aumentando diariamente e que exigem, na maioria das vezes, cuidados especiais desde sua geração a sua disposição final.  Este estudo objetivou analisar o gerenciamento dos RSS a partir da avaliação gravimétrica de resíduos de uma instituição hospitalar de Rondonópolis (MT) Brasil. Como metodologia foi realizada uma pesquisa exploratória, descritiva, quantitativa, observacional e longitudinal. Baseada nos Planos de Gerenciamento de RSS entre os anos de 2010 e 2014, foi possível fazer uma análise gravimétrica dos RSS por leito ocupado por dia, com os seguintes resultados: 1,57Kg em 2010; 1,70Kg em 2011; 1,57Kg em 2012; 1,86Kg em 2013 e 1,98Kg. (leito.ocupado.dia)-1 em 2014; com uma taxa média de 1,73Kg .(leito.ocupado.dia)-1 nos cinco anos analisados. Foram sugeridas propostas de me', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3785', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a291', 'Avaliação de restaurante universitário por meio do regulamento técnico de boas práticas para serviços de alimentação', 'Ana Paula Trindade Rocha; Deyzi Santos Gouveia; Analha Dyalla Feitosa Lins; Rebeca Morais Silva Santos; Willame Mendes da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Diante dos desconfortos ocorridos no Restaurante Universitário da Universidade Federal de Campina Grande Campus I, relacionados à qualidade das refeições servidas diariamente, notou-se a necessidade da implantação de um programa de verificação e atualização das boas práticas de manipulação de alimentos. Objetivou-se a avaliação das práticas de manipulação alimentar e das condições das instalações higiênico-sanitárias do restaurante, com posterior treinamento dos funcionários, para melhoramento da qualidade e segurança dos alimentos servidos. A verificação deu-se pela aplicação do check-list disposto na resolução RDC nº 216/2004 da ANVISA. O Restaurante Universitário apresentou dos 123 questionamentos realizados, 37,3% de conformidades, 43% de não conformidades, e os demais quesitos foram preenchidos com a opção NA (Não se aplica) ou não puderam ser preenchidos por falta de acesso às informações necessárias. Conforme a classificação pela Categorização dos Serviços de Alimentação da ANVI', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3417', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a294', 'Efeito residual da jitirana, flor-de-seda e mata-pasto no cultivo da rúcula em sucessão a beterraba', 'Sérgio Luiz Silva de Morais; Paulo César Ferreira Linhares; João Liberalino Filho; Ana Paula Morais Neves; Alany Moisa Bezerra Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O efeito residual da adubação anterior em cultivos subsequente é de suma importância, uma vez que a fertilização do solo em uma atividade tão intensa, como a olericultura, aumentaria o custo de produção sempre que fosse implantada uma nova cultura. Este trabalho foi conduzido na Fazenda Experimental Rafael Fernandes, localizada no distrito de Alagoinha, zona rural de Mossoró-RN, no período de novembro a dezembro de 2011. Objetivou-se avaliar o efeito residual da jitirana, flor-de-seda e mata-pasto no cultivo da rúcula em sucessão a beterraba. A beterraba foi plantada em parcelas de 1,2 x 1,2 m e adubado com espécies espontâneas, nas quantidades: 0,6; 1,2; 1,8; 2,4 e 3,0 kg m-2 de canteiro. Após a retirada da beterraba, semearam-se sementes de rúcula nas parcelas referente aos tratamentos acima citados. O delineamento experimental foi em blocos casualizados com três repetições, no esquema fatorial 5 x 3, sendo cinco quantidades e três tipos de adubos verdes (jitirana; flor-de-seda e mat', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3428', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a297', 'Atividade fotossintética da beterraba submetidas a adubação mineral e esterco bovino', 'Francisco Hevilásio Freire Pereira; Ancélio Ricardo de Oliveira Gondim; Marcos Eric Barbosa Brito; Renato Pereira Lira; José Lucas Guilherme Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho foi desenvolvido com o objetivo avaliar os efeitos da adubação mineral e esterco bovino sobre as trocas gasosas em plantas de beterraba. O experimento foi conduzido em condições de campo, com delineamento em blocos casualizados, no esquema fatorial 5 x 2, com três repetições. Os tratamentos serão constituídos por cinco doses de esterco bovino (2,0; 4,0; 6,0; 8,0; e 10,0 kg m-2), na presença e ausência de adubo mineral. Foram avaliados os seguintes parâmetros: fotossíntese liquida (A), a condutância estomática (gs), a transpiração (E) e a concentração intercelular de CO2 (Ci), eficiência instantânea do uso da água (A/E), eficiência de carboxilação (A/Ci). As plantas de beterraba cultivadas na presença da adubação mineral e com a maior dose de esterco revelaram valores maiores para condutância estomática. O tratamento de 10,0 kg m-2 de esterco apresentou maior taxa de fotossíntese. Os valores de transpiração e concentração intercelular de CO2 na beterraba foram influe', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3438', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a298', 'Diagnóstico do potencial de contaminação de águas subterrâneas por agrotóxicos aplicados na agricultura do entorno do reservatório São Gonçalo - PB', 'Ricardo Lins Vale; Patrício Borges Maracajá; Elysson Marcks Gonçalves Andrade; Janine Patrícia Melo Oliveira; Saulo Soares da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A importância dos agrotóxicos para o modelo de desenvolvimento agrícola vigente é indiscutível, uma vez que constituem parte dos insumos básicos. Entretanto, é muito importante que sejam utilizados adequadamente para a preservação não só dos produtos cultivados, mas também dos próprios recursos naturais, principalmente o solo e a água, além da saúde dos agricultores e consumidores. Este trabalho foi realizado na região do entorno do Reservatório São Gonçalo - PB e tem como objetivo diagnosticar o potencial de contaminação de águas subterrâneas por agrotóxicos aplicados na agricultura irrigada da região, baseado nos métodos Método Screening da Agência de Proteção Ambiental Americana (Environmental Protection Agency, EPA) e o Índice de Vulnerabilidade de Águas Subterrâneas (Groundwater Ubiquity Score, GUS). Por meio da comparação entre os métodos observou-se que 35,3% dos princípios ativos utilizados nas lavouras da área de estudo apresentam alto potencial de contaminação para as águas s', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3362', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a299', 'Análises físicas das águas subterrâneas de poços localizados nas comunidades Várzea Comprida dos Oliveiras e Bezerro no município de Pombal-PB', 'Elton Pereira da Silva; Francisco Tales da Silva; Diêgo Lima Crispim; Alan Dél Carlos Gomes Chaves; Ricardo Ricelli Pereira de Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As águas subterrâneas são aquelas que se infiltram através da superfície do terreno e enchem os espaços vazios dos interstícios das rochas. A irrigação é uma prática agrícola que visa principalmente atender as necessidades hídricas das culturas no momento adequado.  A água utilizada na irrigação das hortaliças é derivada de poços tubulares e do rio Piranhas. O trabalho teve como objetivo avaliar os parâmetros físicos da água dos poços das comunidades Bezerro e Várzea Comprida dos Oliveiras. A pesquisa foi desenvolvida no município de Pombal-PB, por meio de visitas feitas nas comunidades, as quais trabalham com a produção de hortaliças irrigada com água subterrânea. Foram coletadas 18 amostras de água nas comunidades citadas e realizadas as seguintes análises físicas: Turbidez, temperatura e cor. Os poços apresentaram redução nos valores de Turbidez a partir de fevereiro, pois as chuvas conseguiram diluir os materiais presentes na água dos poços. Os valores obtidos para cor estão dentro', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3249', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a29a', 'Viabilidade da incorporação do mel de abelha em sachê na alimentação escolar de uma instituição de Ensino de São Domingos-PB', 'Debora Cristina Coelho; Walnara Arnaud Moura Formiga; Patrício Borges Maracajá; Antônio Vitor Machado; Bárbara Bruna Maniçoba Pereira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A alimentação escolar deve oferecer alimentos naturais e de boa qualidade para garantir o aprendizado e melhorar a qualidade de vida dos alunos na escola. No Brasil o Programa Nacional de Alimentação Escolar-PNAE precisa ter em sua execução alimentos naturais e com muitos benefícios para seus comensais, dentre os muitos alimentos com a referida qualidade, encontramos o mel de abelha, um alimento natural, que se constitui de uma solução supersaturada de glicose e frutose, além de ser rico em micronutrientes essenciais ao organismo humano, por sua constituição, o referido alimento fornece aos indivíduos que o consomem propriedades antibacterianas, anti-inflamatórias, energéticas, antioxidantes, entre outras. Neste contexto este trabalho objetivou avaliar o nível de aceitabilidade do mel de abelha embalado em sachês introduzido na alimentação escolar do município de São Domingos-PB. O estudo teve um caráter descritivo, exploratório e quantitativo. A pesquisa foi realizada numa escola de e', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3467', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a29b', 'O uso de agrotóxicos pelos agricultores da comunidade Baixa do Juá, Santana de Mangueira - PB', 'Natanaelma C. da Silva; Jocimario Alves Pereira; Joelma F. V. de Jesus', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os agrotóxicos foram introduzidos no Brasil na década de 60, na época o governo criou um plano nacional de defensivos agrícolas, baseado e argumentado pela “Revolução Verde”, onde as práticas modernas se expandem, uso de máquinas, sementes geneticamente modificadas aparecem e o uso de defensivos químicos (agrotóxicos) se populariza.  Com políticas publicas favoráveis a esse setor, hoje o país passou a ser apontado em varias pesquisas como maior consumidor de insumos químicos. Desta forma interiorizando no Brasil novas tecnologias de manejo e práticas agrícolas como uso de agrotóxicos. Este trabalho objetiva investigar o uso de defensivos químicos na produção agrícola da comunidade Baixa do Juá município de Santana de Mangueira - PB, avaliando as possíveis consequências dessa prática no âmbito pessoal e profissional. O trabalho constou de pesquisa quantitativa e qualitativa, com pesquisa documental, pesquisa de campo, entrevistas e questionários, junto aos produtores associado à ASPROBA', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3149', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a2', 'Diagnóstico do uso de ferramentas de gestão por proprietários rurais de Uberlândia - MG.', 'Leôncio Campos Gouveia; Fernando Caixeta Lisboa; Washington Ribeiro do Nascimento; Matheus Henrique Medeiros; Jéssica Laura Miranda Peixoto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O produtor rural deve se adequar, na tentativa de tornar-se consciente da gestão de sua propriedade rural, pois um melhor gerenciamento resulta em maior lucratividade e em menor custo de produção. Sendo assim, o objetivo deste trabalho foi realizar um diagnóstico do uso de ferramentas de gestão por produtores rurais do município de Uberlândia – MG.  Para tanto, realizou-se a aplicação de formulários estruturados a 23 produtores rurais da referida localidade, através de pesquisa de campo, obtendo-se assim, panoramas quanto ao uso destas ferramentas. Os resultados indicam a necessidade de aprimoramento e do uso das ferramentas de gestão utilizada pelos proprietários rurais entrevistados. Detectou-se, ainda, a necessidade de abertura de um curso para esclarecimento do uso dessas ferramentas.', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3287', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a4', 'Análise microbiológica e bromatológica da água em bebedouros de escolas públicas em Belém do Brejo do Cruz-PB', 'Andressa L. Nóbrega; Jéssica de S. Oliveira; Franklis B. F. Santana; Débora S. S. Martins', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A água é um recurso essencial à sobrevivência de todos os seres vivos e o seu fornecimento em quantidade e qualidade é fundamental para a perfeita manutenção da vida humana. O presente trabalho teve como objetivo realizar a análise microbiológica e bromatológica da água em bebedouros de escolas públicas na cidade de Belém do Brejo do Cruz – PB. Para as análises físico-químicas foram coletadas 100 ml de cada amostra e distribuídas entre as seguintes análises: cor, turbidez e pH, enquanto para a análise microbiológica foi utilizada kit Colilert® (técnica de substrato cromogênio). Foi constatado que para a análise microbiológica as amostra E1, E3, E4 e E5 os resultados foram insatisfatório, pois a portaria vigente estabelece que para a água tratada não se admite a presença de coliformes totais e Escherichia coli em amostra de 100 ml. Para a amostra E2 foi observado resultado satisfatório, fator importante para o ambiente escolar. A amostra E6, não se aplica a análise em virtude da água nã', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3555', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2a9', 'Desenvolvimento de porta-enxerto de goiabeira sob irrigação com água salinizadas e doses de nitrogênio', 'Israel Almeida da Silva; Fablo Fernandes de Sousa; Reginaldo Gomes Nobre; Leandro de Pádua Souza; Evandro Manoel da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os efeitos dos sais nos solos, causando variações na estrutura, permeabilidade e aeração do solo, afetam indiretamente o crescimento das plantas. Desta forma o incremento da dosagem de nitrogênio, como fator isolado, pode promover melhor eficiência na produção de mudas. Neste sentido, objetivou-se com este trabalho, analisar a influência da salinidade da água de irrigação associada a doses crescentes de nitrogênio sobre o desenvolvimento de porta-enxerto de goiabeira de genótipo ‘Crioula’. O experimento foi conduzido em tubetes sob condições de ambiente protegido no CCTA/UFCG. Utilizou-se o delineamento experimental em blocos casualizados, com os tratamentos dispostos em esquema fatorial 5 x 4, correspondentes a  cinco níveis de condutividade elétrica da água – CEa (0,3; 1,1; 1,9; 2,7 e 3,5 dS m-1) e quatro doses de nitrogênio (70, 100, 130 e 160% de N da dose recomendada para cultivo de mudas de goiabeira cv. Paluma) com 4 repetições e 5 plantas por parcela. Não houve interação signif', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3717', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2ae', 'Efeito de Humoativo comercial na produtividade da couve-flor no Estado de Santa Catarina', 'José Alfredo da Fonseca; Ana Lúcia Hanisch', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O Humoativo comercial é um substrato registrado como produto orgânico, proveniente do tratamento anaeróbico dos resíduos de celulose em lagoas de decantação e posterior compostagem aeróbica, com alta concentração em nutrientes. O objetivo deste experimento foi avaliar, a campo, o efeito da aplicação de doses de Humoativo sobre a produtividade e a absorção de metais pesados por plantas de couve-flor. Foi utilizado delineamento em blocos inteiramente casualizados, com três repetições e sete tratamentos que corresponderam às doses de Humoativo de 17, 34, 51, 68, 85 e 102 t.ha-1, em base seca. O uso do produto como fertilizante para a cultura da couve-flor proporcionou aumentos crescentes das produtividades com o aumento das doses aplicadas. Não houve efeito dos tratamentos sobre os teores de macro e micronutrientes analisados nos tecidos foliares da couve-flor.Effects of Humoativo commercial in cauliflower productivity in Santa Catarina StateAbstract:  Humoativo commercial is a substrate ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2634', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2af', 'Indicadores de sustentabilidade e influência de sistemas agroflorestal e convencional sobre a qualidade do solo e do café arábica em Piumhi-MG', 'M. V. M. Vieira; A. V. Silva; O. D. Giunti; C. F. Gris', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com esse trabalho a comparação dos teores nutricionais dos solos de uma área constituída por um SAF (Sistema Agroflorestal), que tem o cafeeiro como um dos seus principais elementos constituinte, com os de uma área com o café em monocultivo convencional e a confrontação dos teores nutricionais do solo do SAF antes e três anos após sua implantação, bem como a seleção e aplicação de indicadores de sustentabilidade para avaliar e contrastar parâmetros relacionados à qualidade do solo e do cafeeiro nos dois sistemas avaliados. Na comparação entre análises de solo de amostras retiradas da linha e entrelinha do café convencional e do SAF, os valores de pH, P, K, Ca, Mg e MO apresentaram-se mais elevados nas amostras de solo retiradas na entrelinha do cafeeiro convencional e na linha de plantio do SAF, na profundidade de 0-20 cm. . Nas comparações entre análise da área total do SAF retirada em período anterior à sua implantação com análises atuais das linhas e entrelinhas do SAF,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3329', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2b0', 'Análise geoespacial do processo de desmatamento da Caatinga no município de Catolé do Rocha – PB', 'J. S. Almeida; W. F. Mello; A. B. A. Andrade; R. A. Oliveira; W. F. Melo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se analisar o processo de desmatamento no município de Catolé do Rocha-PB. Com o presente trabalho estabelecemos uma análise multitemporal das mudanças no uso e ocupação do solo no município de Catolé do Rocha entre os anos de 2005 e 2013. Foram utilizadas imagens do sensor TM Landsat-7, ano 2005 Bandas 3, 4, 5, ponto 216 e órbita 064, e Landsat-8 Banda 8, ponto 216, órbita 064, (georreferenciada). No ano de 2013 as imagens foram corrigidas no Regeemy 0.2.43, e processadas, filtradas e classificadas no SPRING 5.2, a classificação foi efetuada pelo método pixel a pixel, foi obtido 9 amostras para cada classe, com desempenho médio acima de 90%. A imagem resultante da sobreposição dos planos de informação foi obtida por cruzamento usando lógica booleana, no ambiente de programação em LEGAL. A vegetação manteve os níveis degradação principalmente sobtre as regiões de classes (Caatinga Estépica Florestada Mantida e Caatinga Estépica Arborizada Mantida), representando respectivamen', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3924', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2b2', 'Propriedades mecânicas de tijolos fabricados com solo e água residuária de mandioca', 'R. C. dos Santos; N. C. de Araújo; J. da S. Buriti; A. P. Ramos; A. J. P. Queiroz', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A vantagem do processo de fabricação de tijolos com manipueira é ser ecologicamente correto, pois não consome água, nem há necessidade de ir ao forno, economizando recursos naturais e fazendo uso de um efluente altamente poluente. Assim, este trabalho objetivou analisar as propriedades mecânicas de tijolos fabricados com solo associado à manipueira como alternativa sustentável. Foram avaliados os parâmetros absorção de água e resistência à flexão. Em conformidade com os resultados, observou-se que as massas cerâmicas apresentaram valores de absorção de água da ordem de 10 a 13 %, valores aceitáveis para fabricação de blocos cerâmicos e valores de resistência a flexão adequados para fabricação de tijolos maciços, tanto, os corpos de prova com queima quanto os corpos de provas sem queima. Assim, conclui-se que a troca da água pela adição da manipueira na massa cerâmica não interfere nas propriedades mecânicas e esta pode ser adicionada a massa cerâmica para fabricação de tijolos ecológic', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3427', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2b7', 'Efeito da adubação orgânica e mineral no crescimento de plantas de orégano cultivadas em ambiente protegido', 'Girlene Santos de Souza; Anacleto Ranulfo dos Santos; Vanuze Costa de Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O orégano é uma das plantas aromáticas e condimentares mais utilizadas no Brasil e a maior parte do produto consumido é proveniente de importação, mesmo o País apresentando condições de clima e solo favoráveis para o cultivo desta erva.  Este trabalho teve como objetivo avaliar o efeito da adubação orgânica e mineral em plantas de orégano cultivado sob malha colorida. Foi adotado o esquema fatorial 4x4 (sendo quatro ambientes de luz modificada e quatro fontes de nutrientes: Latossolo Amarelo, esterco bovino, composto orgânico e NPK), adotou-se o DIC com seis repetições. Avaliaram-se as seguintes características de crescimento: altura das plantas, produção de massa seca e razão de peso foliar. Constatou-se que as plantas adubadas com esterco bovino obtiveram maior altura e maior produção de massa seca; e as plantas cultivadas no ambiente protegido pela malha azul tiveram maior altura, massa seca de raiz e massa seca total.Effect of organic and mineral fertilizers in growth of oregano''s ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3176', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2b8', 'Arranjos agroflorestais no contexto da agroecologia: O caso dos agricultores da região do Médio Maracá no município do Mazagão, Amapá', 'Hilaíres Lima Maciel; Daniel Santos de Assis; Gilberto Ken-Iti Yokomizo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se identificar localmente os diferentes arranjos, práticas e manejos agroflorestais, desenvolvidos pelos agricultores da região do Médio Maracá no município do Mazagão. Para a pesquisa foram adotadas observações diretas desenvolvida em duas etapas: a primeira constou de pesquisa e revisão bibliográficas. A segunda etapa da pesquisa foi realizada em campo. Identificou-se que as tipologias Quintal Florestal possuem área média 0,5 ha e a agrossilvicultura com área média de 5,5 ha. Quanto às espécies utilizadas o açaizeiro (Euterpe oleracea), o cupuaçuzeiro (Theobroma Grandiflorum), e a bacabeira (Oenocarpus bacaba), apresentaram maior frequência na composição dos sistemas pesquisados. Entre os lotes constatou-se uma média de 10 de espécies frutíferas por lote, quanto às essências florestais a média variou de 10 a 15 espécies. Nesta perspectiva, resgatar práticas e manejos tradicionais baseadas empiricamente nos princípios dos sistemas agroflorestais, se reveste de grande importâ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3384', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2bd', 'Influência da cobertura morta em mini melancia ‘Sugar baby’ no início da frutificação', 'Uirá do Amaral; Isabella Borges Silva; Silvio Luís Carvalho; André Dorneles Oliveira; Valdineia Maria dos Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com este trabalho avaliar a influência de diferentes tipos de cobertura morta no cultivo de mini melancia ‘Sugar baby’ no início da frutificação. O experimento foi conduzido no campus da Faculdade de Filosofia e Ciências Humanas de Goiatuba-GO, de fevereiro a abril de 2015. O delineamento experimental utilizado foi de blocos casualizados com quatro tratamentos e cinco repetições, com seis plantas úteis por parcela. Os tratamentos utilizados foram: testemunha (sem cobertura morta); casca de arroz; serragem e resíduo de silagem de milho. As plantas foram avaliadas aos 44 dias após o plantio, na fase reprodutiva, no entanto, os frutos ainda não estavam maduros e a ocorrência de plantas espontâneas foi realizada quinzenalmente, sendo identificadas todas as plantas daninhas presentes na parcela. Foram analisadas as seguintes variáveis: número de frutos; peso de frutos (g); massa fresca de raízes (g); massa fresca da parte aérea (g); massa seca de raízes (g); massa seca da parte', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4013', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c2', 'Superação de dormência em sementes de pau de balsa (Ochroma pyramidale)', 'Cristiane Deuner; Géri Eduardo Meneghello; Ana Paula Ferreira de Almeida; Daiane Gobes de Jesus Santos; Fernanda da Motta Xavier', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O pau de balsa (Ochroma pyramidale) vem se constituindo como umas das principais espécies arbóreas no ramo de reflorestamento, devido ao seu ponto de corte rápido, que varia entre cinco e sete anos. Entretanto, as sementes desta espécie apresentam dormência devido à impermeabilidade do tegumento, dificultando a sua germinação e assim a produção de mudas. O objetivo do trabalho foi avaliar a eficiência de métodos de superação de dormência em sementes de pau de balsa. O experimento foi conduzido na Empresa de Pesquisa, Assistência e Extensão Rural (EMPAER), localizada na cidade de Guarantã do Norte, MT. Para superar a dormência as sementes foram submetidas aos seguintes tratamentos:  1) choque térmico por 10 minutos, 2) choque térmico por 15 minutos, 3) choque térmico por 20 minutos, 4) choque térmico por 25 minutos, 5) acetona por 15 minutos e 6) hipoclorito de sódio por 15 minutos. Para avaliar o efeito dos tratamentos, foram analisadas as variáveis emergência de plântulas, índice de v', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4191', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c4', 'Padrões físico-químico e microbiológicos do leite cru comercializado em município no interior da Paraíba', 'Rafael Ferreira Lima; Alex Sandro de Lima; Ailton do Nascimento Targino; Mayra Vieira Pereira Targino; Everton Vieira da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O leite é um produto de grande importância na alimentação humana, devido ao seu elevado valor nutritivo. Como fonte de proteínas, lipídios, carboidratos, minerais e vitaminas, o leite torna-se também um excelente meio para o crescimento de vários grupos de microrganismos desejáveis e indesejáveis. O presente trabalho teve como objetivo analisar a qualidade do leite quanto aos aspectos físico-químicos e microbiológicos comercializados a domicílio na cidade de Água Branca - PB. O estudo apresentou caráter experimental com abordagens quantitativas utilizando-se o método da estatística descritiva. As amostras foram coletadas de vendedores autônomos de bairros distintos do município da cidade de Água Branca - PB. Depois da coleta das amostras, as mesmas seguiram para o laboratório de Tecnologia do Leite da Universidade Federal de Campina Grande (UFCG), Campus / Patos - PB. Foi verificado neste estudo que a Densidade relativa apresentou variações para as amostras A1 e A5. Para a análise de G', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4223', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c5', 'Análise biométrica de frutos e sementes de Bauhinia forficata L.', 'Adriana Dias Cardoso; Otoniel Magalhães Morais; Bruna Aparecida Madureira de Souza; Fabrício Vieira Dutra; Arlete da Silva Bandeira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Estudos relacionados aos aspectos biométricos de frutos e sementes são importantes devido à necessidade na identificação e diferenciação da espécie. A partir da caracterização biométrica de frutos é possível obter informações para a conservação e exploração da espécie, e constitui um instrumento fundamental para detectar a variabilidade entre indivíduos em uma determinada área. Dessa forma, objetivou-se caracterizar biometricamente frutos e sementes de Bauhinia forficata L. de plantas provenientes do município de Vitória da Conquista, BA. Para isso foram selecionados aleatoriamente 30 frutos e 100 sementes, os quais foram medidos com o auxílio de um paquímetro digital (0,01mm), determinando-se comprimento e diâmetro de frutos e sementes. Os frutos de Bauhinia forficata L, provenientes do município de Vitória da Conquista, apresentaram variação nas suas dimensões biométricas e na massa fresca do fruto indicando potencial de seleção da espécie estudada. Biometric analysis of fruits and s', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4231', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2c8', 'Variação temporal de nutrientes N P K na serapilheira de duas fisionomias do domínio cerrado, Gurupi - TO', 'Rômullo Quirino de Souza Ferreira; Marília Oliveira Camargo; Rodrigo de Castro Tavares; Priscila Bezerra de Souza; Paulo Ricardo Teixeira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'objetivou-se avaliar o retorno de macronutrientes (N, P, K) produzido em duas fisionomias do domínio Cerrado, sendo, uma fisionomia de cerrado sensu stricto (s.s) e outra de mata ciliar, ambas as áreas localizadas na Fazenda Experimental da Universidade Federal do Tocantins, Campus de Gurupi - TO. As amostras foram submetidas a análise de rotina para os macronutrientes N, P e K. Os maiores valores de precipitação foram registrados no período de novembro de 2012 a abril de 2013. Os maiores teores de nutrientes na fisionomia cerrado sensu stricto foram depositadas no final da estação seca.  Os menores teores de nutrientes foram encontrados no início da estação chuvosa. Na fisionomia de mata ciliar os teores de nutrientes nitrogênio e fósforo ocorreram de forma variável. A folha foi a fração que apresentou maior teor de nutrientes devido à grande deposição de serapilheira que ela apresentou durante o período de estudo.N P K nutrientes time variation of leaflitter from two cerrado biome ph', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4256', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2cd', 'Utilização de soluções numéricas e analíticas na descrição da secagem do eixo central de jaca', 'Hyago Costa Sousa; Nathan José Pereira da Silva; Emmanuel Moreira Pereira; Carlos Roberto Marinho da Silva Filho; Weysser Felipe Cândido de Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se descrever o processo de secagem do eixo central de jaca por modelos matemáticos e determinar qual modelo matemático apresentou os melhores ajustes para as características avaliadas. Foi estudado a secagem do eixo central de jaca em estufa com circulação e renovação de ar em quatro temperaturas diferentes 50, 60 70 e 80 °C utilizando modelos matemáticos para a descrição da quantidade de água no eixo central de jaca, foram utilizados frutos adquiridos no pomar do Centro de Ciências Humanas, Sociais e Agrarias, Bananeiras-PB pertencente a Universidade Federal da Paraíba. De acordo com a análise de dados o modelo de Page foi o que apresentou os melhores coeficientes de determinação e os melhores ajustes aos dados experimentais.Use of numerical and analytical solutions in the description of the drying of the central axis of jackfruitAbstract: This study aimed to describe the process of drying the central axis of jackfruit by mathematical models and determine which mathematical ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4314', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2cf', 'Mapeamento da deposição irregular dos resíduos provenientes da construção civil na cidade de Mossoró-RN', 'Frnacisco de Assis de Oliveira; Leonardo Vieira de Sousa; Luan Alves Lima; Ellen Ramona de Almeida Correia Brito; Giordanio Bruno Silva Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A construção civil tem sido considerada uma das mais importantes atividades para o desenvolvimento da sociedade, porém é uma atividade que causa impactos ambientais, pois utiliza recursos naturais, modifica o meio ambiente e gera um grande volume de resíduos. Nota-se que as atividades ligadas à construção civil no município de Mossoró-RN, são responsáveis por gerar uma quantidade considerável de resíduos de construção civil (RCC), que na maioria das vezes, são depositados em locais irregulares, por não haver na cidade um local específico para esse fim. Esses resíduos constituem um grave problema, tanto para o meio ambiente quanto para qualidade de vida da população. A pesquisa foi realizada com o objetivo de mapear áreas de depósito irregular de resíduos provenientes da construção civil na cidade de Mossoró-RN. Foi realizada a demarcação dos pontos de acordo com a localização do despejo dos resíduos, com a finalidade de identificar e indicar sua localização dentro da zona urbana de Mos', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4345', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d3', 'Componentes de produtividade e teor de óleo de cultivares de mamona no Semiárido paraibano', 'Rodolfo Rodrigo de Almeida Lacerda; Anielson dos Santos Souza; Wendell de Almeida Lacerda; Ivislanne de Sousa Queiroga Lacerda; Guilherme de Freitas Furtado', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A cultura da mamona (Ricinus communis L.) se apresenta como alternativa de relevante importância econômica e social para o extenso semiárido brasileiro, pois, em virtude das suas características, é capaz de produzir satisfatoriamente até sob condições de baixa precipitação pluvial. Porém, a falta de cultivares adaptadas a cada região de cultivo tem dificultado o estabelecimento dessa cultura em novas áreas. Sendo assim, o presente trabalho tem como objetivo identificar cultivares de mamona que se adaptem as condições edafoclimáticas Locais. O experimento foi conduzido no Sítio Monte Alegre zona rural do município de Pombal - PB, o delineamento experimental foi o de blocos ao acaso com sete tratamentos compostos pelos cultivares BRS Nordestina; BRS Paraguaçu; BRS Energia; AL Guarany-2002; IAC 2028; IAC Guarany e IAC 80, com quatro repetições, foram avaliadas as características de produção, produtividade e teor de óleo nas sementes. Dos resultados registrou-se maior produção de grão por ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4382', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d4', 'Variabilidade espacial dos atributos químicos em terra preta de índio cultivada na região de Novo Aripuanã, AM', 'José Maurício da Cunha; Milton César Costa Campos; Selma Ferreira Viana; Antonio Francisco de Mendonça Júnior; William Barros do Nascimento', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Terras Pretas de Índio são solos de uma fertilidade notoriamente superior à grande maioria dos solos típicos da região Amazônica. Apresentam em sua composição fragmentos de cerâmica e artefatos indígenas incorporados a matriz dos horizontes superficiais, dispõem de alta estabilidade e persistência mantendo sua fertilidade mesmo depois de vários anos. Nesse sentido, o presente trabalho tem como objetivo avaliar a variabilidade espacial dos atributos químicos do solo em área de Terra Preta de Índio sob cultivo de feijão em Novo Aripuanã, AM. Foi realizado o mapeamento de uma malha de 20,0 x 72,0 m, com espaçamento regular de 5,0 x 4,0 m, nas profundidades de amostragem 0,0 - 0,05, 0,05 - 0,10 e 0,10 - 0,20 m, totalizando 90 pontos. Foram realizadas análises químicas como: pH em água, fósforo (P), concentração de alumínio (Al), e acidez potencial (H+Al). Os dados foram analisados utilizando-se técnicas estatísticas descritivas e de geoestatística. Os químicos estudados apresentaram estrut', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4385', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d6', 'Condições higiênico-sanitárias de sorvetes do tipo italiano (soft), comercializados em Pombal, Paraíba', 'Yaroslávia Ferreira Paiva; Alfredina dos Santos Araújo; Everton Vieira da Silva; Thamyres César de Albuquerque Sousa; Plínio Tércio Medeiros de Azevedo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No mercado alimentício novas tecnologias são lançadas em busca de maior praticidade para população, um exemplo é a máquina de sorvete italiano (soft) que pode ser inserida em locais com grandes fluxos de pessoas, ocupando espaços pequenos e servindo os produtos com uma maior rapidez. No entanto, a forma como são comercializados pode representar riscos à saúde do consumidor, portanto, objetivou-se avaliar as condições higiênico-sanitárias desses produtos, comercializados em Pombal, Paraíba. Foram coletadas amostras de sorvetes do tipo italiano, sabor “misto”, diariamente durante cinco dias, em três diferentes estabelecimentos, sendo submetidos a análises de Coliformes a 35º e 45ºC, Escherichia coli, Salmonella sp, Staphylococcus spp, Contagem total de Bactérias aeróbias Mesófilas e Psicrotróficas. Os resultados obtidos para coliformes a 45ºC nos três pontos de venda SP1, SP2 e SP3 tiveram valores médios de 0,72 NMP/g, 1,3 NMP/g e 9,8 NMP/g, respectivamente. Para Staphylococcus spp. os r', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4389', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2d7', 'Qualidade de biodiesel de soja, mamona e blendas durante armazenamento', 'Eduardo H. S. Vasconcelos; Antonio Gouveia de Souza; Guiseppe C. Vasconcelos; Everton Vieira da Silva; Marco Aurélio R. Melo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se monitorar o armazenamento dos biodieseis provenientes da transesterificação homogênea alcalina do óleo de soja e mamona via rota metílica, avaliando a indução oxidativa pela norma EN14112 e pelo método PetroOxy durante o período de 120 dias, também observou-se o comportamento dos biodieseis inseridos em blendas nas proporções de 20, 30, 40 e 50% v/v de biodiesel de mamona ao biodiesel de soja denominadas de M20, M30, M40 e M50 (em recipientes de aço-carbono fechado). Conforme análises físico-químicas, as especificações para ambos biodiesel e blendas satisfizeram as exigências dos limites permitidos pelo Regulamento Técnico nº 14/2012 da Agência Nacional do Petróleo, Gás Natural e Biocombustíveis. Exceção das análises de estabilidade oxidativa (M0, M20, M30 e M40), do índice de acidez após 60 dias (M50), após 90 dias (M40 e M50), após 120 dias (M100) e da viscosidade cinemática (M40, M50 e M100) que apresentaram valores fora dos limites estabelecidos pela norma. As propried', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4099', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2da', 'Avaliação física e físico-química de frutos de juazeiro (Zizyphus joazeiro Mart.) em diferentes estádios de maturação', 'Ana Marinho do Nascimento; Mahyara de Melo Santiago; Rafaela Rodrigues do Vale Costa; Franciscleudo Bezerra da Costa; Jéssica Leite da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar as características físicas e físico-químicas dos frutos de juazeiro colhidos em cinco estádios de maturação. Os frutos foram colhidos no Centro de Ciências e Tecnologia Agroalimentar (CCTA) da Universidade Federal de Campina Grande (UFCG), Campus Pombal, foram acondicionados em sacos plásticos e transportados ao laboratório de Análise de Alimentos do CCTA. Os frutos foram classificados em cinco estádios de maturação, selecionados quanto à coloração da casca do fruto. Avaliou-se a massa fresca dos frutos, polpas e sementes; espessura longitudinal e transversal do fruto e polpa, rendimento da polpa e semente. Após o processamento da polpa com a casca, foram avaliadas as seguintes características físico-químicas: umidade, cinzas, pH, sólidos solúveis totais, acidez total titulável e vitamina C. Os frutos do IV estádio de maturação se destacaram em relação aos demais nos atributos físicos, apresentando elevado rendimento (80,16%), tornando o processamento industrial, n', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4743', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2e0', 'Quintais agroflorestais na percepção dos moradores do reassentamento Mariana, Tocantins', 'Priscila Bezerra Souza; Ícaro Gonçalves Santos; Conceição Aparecida Previero', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A usina hidrelétrica Luís Eduardo Magalhães é a primeira usina hidrelétrica do estado do Tocantins, a mesma foi responsável pelo enchimento do reservatório na região central do estado, ocasionando a desapropriação e a realocação das comunidades ribeirinhas do rio Tocantins para reassentamentos, o que gerou diversas mudanças espaciais. Dentro do processo de adaptação dos assentados, uma das características que se deve levar em consideração é a forma como interagem com o meio ambiente. O uso da terra de forma sustentável é uma realidade histórica na agricultura familiar, a forma como manejam os agroecossistemas como os quintais agroflorestais é de fundamental importância na conservação dos recursos naturais. Dessa forma, o presente trabalho objetivou realizar uma análise comparativa dos benefícios gerados na manutenção dos quintais agroflorestais, bem como do comportamento ambiental dos reassentados do reassentamento Mariana. Utilizou-se como ferramenta metodológica a observação/etnograf', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3830', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2e3', 'Avaliação de hipsômetros e operadores na mensuração de árvores de Eucalyptus urograndis de tamanhos diferentes', 'Paula Carolina Gomides Vitor; Antonio Carlos Ferraz Filho; Rafaella Carvalho Mayrinck; Ximena Mendes de Oliveira; Gabriela Cristina Costa Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A mensuração da altura de forma acurada é extremamente importante na ciência florestal, pois, influencia diretamente na predição do volume individual das árvores, bem como na volumetria de um povoamento e em todo o sistema de prognose. Por ser feita de forma indireta, é sujeita a erros, que devem ser minimizados. Assim, deve se usar o hipsômetro que proporcione menor erro, além de um operador treinado para o procedimento. Nesse estudo objetivou-se testar a acurácia do hipsômetro e operador em relação a árvores de Eucalyptus urograndis de tamanhos diferentes. Os dados foram coletados em um plantio de Eucalyptus urograndis em Turmalina, MG. Três árvores foram selecionadas, classificadas em pequena (12,1 m), média (18,9 m) e grande (25,2 m). Seis operadores mediram cada uma das árvores usando 4 hipsômetros (Prancheta dendrométrica, Clinômetro digital, Suunto e Vertex) 5 vezes. Posteriormente, realizou-se o abate das árvores e a obtenção da altura real com uma trena. Para analisar os dados', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3976', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2e6', 'Agricultores familiares do Sul da Amazônia: Desafios e estratégias para inovação agroecológica de sistemas de produção', 'Maria Aico Watanabe; Lucimar Santiago de Abreu', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A importância agroecológica e ambiental da Amazônia para o equilíbrio do clima e biodiversidade é mundialmente reconhecida. Porém, pouco se discute os usos dos recursos naturais pela população regional ou a conservação ambiental, a agro biodiversidade e a segurança alimentar. Entre o final de 2007 e 2016 foram conduzidas pesquisas sobre a produção agroflorestal de produtores ecológicos de Ouro Preto do Oeste, Rondônia, sul da Amazônia. Inicialmente foram entrevistados 29 agricultores de base ecológica; depois, com visitas e contatos com produtores e agentes locais, acompanhou-se a experiência e atualizaram-se os dados da pesquisa. Assim objetivou-se com este trabalho avaliar as potencialidades da diversificação agroecológica das atividades pela comparação do que cultivavam e criavam e o que poderiam cultivar e criar conforme as espécies existentes e as espécies já pesquisadas para região, analisando os desafios para a produção oriunda dessas atividades. A comparação mostra que apesar d', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4202', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2ea', 'Aspectos físicos e químicos de frutos de Quipá (Tacinga inamoena)', 'Anderson dos Santos Formiga; Yasmin Lima Brasil; Emmanuel Moreira Pereira; Franciscleudo Bezerra da Costa; Marcio Santos da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi disponibilizar informações sobre os aspectos tecnológicos e nutricionais dos frutos do quipá buscando aplicações para o mesmo na alimentação humana. O quipá é uma planta nativa da região Nordeste, seus frutos, ao contrário do figo-da-índia não é valorizado. Os frutos foram colhidos, acondicionados e conduzidos ao laboratório de Análise de Alimentos, CCTA/UFCG, Pombal-PB. Em seguida foram divididos em quatro lotes e submetidos à extração da polpa. Foram avaliadas as características físicas, físico-químicas e químicas dos frutos do quipá. Os frutos são pequenos, a casca representa mais da metade do peso do fruto e com as sementes dificultam a aceitabilidade dos frutos pelo consumidor. A polpa compõe pouco mais de 20% do peso do fruto, possui pH ácido, com baixa concentração de ácido cítrico e sólidos solúveis inferiores aos frutos de figo-da-índia e do mandacaru, comuns ao semiárido; as concentrações de vitamina C e compostos fenólicos na polpa foram considerad', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4559', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2ec', 'Influência da adubação orgânica no desenvolvimento do feijão-vagem em diferentes níveis de água de irrigação', 'Maila Vieira Dantas; Bárbara Genilze Figueiredo Lima Santos; Ivando Comandante de Macedo Silva; Tiago Silva Lima; Joseano Graciliano da Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A cultura do feijão-vagem possui ampla adaptação edafoclimática, podendo ser cultivado durante todo o ano em grande parte dos estados brasileiros, entretanto, fatores como o manejo do solo, sendo este fundamental para obtenção de maior sucesso de produção e o volume inadequado da água de irrigação limita sua produção principalmente nas regiões semiáridas. Com isso, o presente trabalho objetivou avaliar a influência de fontes de adubação orgânica no desenvolvimento do feijão-vagem cv. ‘Macarrão’ submetido a diferentes níveis de água de irrigação. Os tratamentos avaliados foram: duas fontes de adubação orgânica (esterco caprino e bovino) mais a testemunha (sem adubação) e quatro níveis de água de irrigação (40%; 60%; 80% e 100% da capacidade de campo). Foi adotado o delineamento experimental em blocos casualisados, com arranjo fatorial 3 x 4, sendo o primeiro fator as fontes de adubação orgânica mais a ausência da mesma e o segundo fator os quatro níveis de água de irrigação, com quatro ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4601', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2f0', 'Caracterização físico-química de blend de abacaxi com acerola obtido pelo método de liofilização', 'Ana Paula Trindade Rocha; Maria José Silveira da Silva; Marcela Nobre de Oliveira; Dyego da Costa Santos; Alfredina dos Santos Araújo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se caracterizar blend de abacaxi com acerola liofilizado quanto à composição físico-química. O estudo foi conduzido no Laboratório de Armazenamento e Processamento de Produtos Agrícolas da Universidade Federal de Campina Grande, Campina Grande, Paraíba. As polpas foram homogeneizadas em liquidificador durante 1 min e filtrado em peneira com malha de 2,5 mm, as amostras foram liofilizadas em liofilizador de bancada (Terroni, LS 3000), onde foi desidratada na temperatura de -50 °C por 76 h. A amostra in natura e a liofilizada foram submetidas às analises físico-químicas. Onde foi obtido um teor de água de 92% da amostra in natura e, após o processo de liofilização houve uma redução de 70%. A atividade de água (aw) foi inferior a 0,30 após a desidratação. Observou-se que houve um amento significativo nos teores de sólidos totais, acidez total titulável e sólidos solúveis totais. No tocante a relação SST/ATT houve um decréscimo de 8,37% e, com relação ao pH não houve diferença si', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4786', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2f2', 'Estratégias de irrigação com águas salinas e adubação nitrogenada no cultivo da mamoneira', 'Felipe Luênio de Azevedo; Hans Raj Gheyi; Jutahy Jorge Elias; Geovani Soares de Lima; Reginaldo Gomes Nobre; Lauriane Almeida dos Anjos Soares', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar a concentração de potássio, sódio e a produção na mamoneira cv. BRS Energia, em função da irrigação com águas salinizadas e adubação nitrogenada nas diferentes fases fenológicas, em experimento conduzido em lisímetros de drenagem sob condições de campo no Centro de Ciências e Tecnologias Agroalimentar da Universidade Federal de Campina Grande. O delineamento experimental utilizado foi o de blocos casualizados, arranjados em esquema fatorial 5x2x2, constituídos pela combinação de cinco níveis de condutividade elétrica da água de irrigação - CEa (0,3; 1,2; 2,1; 3,0 e 3,9 dS m-1), duas doses de nitrogênio-DN (100 e 160 mg  kg-1 de solo) e duas fases fenológicas (vegetativa e formação da produção - floração e frutificação). A concentração de potássio e sódio nas folhas, caule e raízes da cv. BRS Energia foram mensuradas aos 120 dias após o semeio. O aumento dos níveis de salinidade da água elevou a concentração de sódio nas folhas, caule e raízes, sendo o efeito variáv', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4989', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2f7', 'Produção de fitomassa de Sálvia officinalis L. cultivada sob malhas coloridas e doses de esterco avícola', 'Uasley Caldas de Oliveira; Girlene Santos de Souza; Anacleto Ranulfo dos Santos; Mariana Nogueira Bezerra; Janderson Carmo Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito da qualidade de luz na produção de fitomassa de plantas de Sálvia Oficcinalis L. cultivada sob malhas coloridas e doses de esterco avícola. O experimento foi conduzido em área experimental da Universidade Federal do Recôncavo da Bahia, onde as plantas foram dispostas em diferentes ambientes de luz e cinco doses de esterco avícola  (0; 60; 120; 180 e 240 Kg ha-1). Aos 90 dias foram aferidas medidas não lineares: área foliar e peso de matéria seca e medidas lineares: número de folhas e altura das plantas. Houve uma interação significativa entre os ambientes de luz e as doses de esterco utilizadas para as variáveis área foliar (AF) e razão de massa foliar (RMF), encontrando os maiores valores de RMF com incremento de 72% e AF com 66% nas plantas submetidas as maiores doses de esterco. Analisando o efeito isolado dos ambientes de luz a malha vermelha teve destaque em todas as variáveis com exceção do número de folhas que não foram significativos. O uso de malh', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4213', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2f9', 'Ocorrência fúngica em goiaba ‘paluma’ submetida a impacto e transportada em dois tipos de embalagens', 'Tiago Augusto Cardoso de Lima; Railene Hérica Carlos Rocha Araújo; Francisco de Assis de Souza; Maciel dos Santos Freire; Márcia Aparecida Cerzar', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'No Nordeste, é comum a utilização de embalagens inadequadas para transporte de frutos,acarretando injúrias que servem como porta de entrada de patógenos. Objetivou-se avaliar a incidência de podridão, severidade e ocorrência fúngica em goiaba ‘Paluma’ transportada em dois tipos de embalagens. Frutos foram colhidos na Fazenda Mocó, Aparecida, Paraíba, no estádio de maturação “de vez”, e submetidos aos tratamentos por impacto através de queda à altura de 85cm sob piso industrial, caracterizando os tratamentos: T1, frutos submetidos a impacto, embalagem em caixa plástica de polietileno; T2, frutos submetidos a impacto, embalagem em caixa de papelão; T3, frutos sem impacto, embalagem em caixa plástica de polietileno; T4, frutos sem impacto, embalagem em caixa de papelão; T5, testemunha, frutos sem injúria mecânica. As amostras foram transportados por 45 km, até o Laboratório de Fitopatologia da Universidade Federal de Campina Grande, Campus Pombal. Os resultados de severidade mostraram que', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4296', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2fc', 'Níveis de sódio na alimentação de codornas japonesas na fase de postura', 'Felipe Barreto Petrucci; Danilo de Vargas Gonçalves Vieira; José Geraldo de Vargas Júnior; Bruno Andreatta Scottá; Júlio Francisco Valiati Marin; Talita Pinheiro Bonaparte', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o efeito de diferentes níveis de sódio na dieta de codornas japonesas na fase de postura. Foram utilizadas 360 codornas japonesas, com idade inicial de 120 dias, distribuídas em delineamento em blocos ao acaso, com seis tratamentos de acordo com o nível de sódio nas dietas, seis repetições e 10 aves por unidade experimental. Para formação das dietas experimentais foram adicionados à dieta basal 0,000%; 0,126%, 0,252%, 0,378%, 0,504% e 0,630% de sal comum em substituição ao material inerte, de forma a obter os níveis de 0,05%; 0,10%; 0,15%; 0,20%, 0,25% e 0,30% de sódio que constituíram os tratamentos, as dietas foram isoproteicas, isocalóricas e isocálcicas. O período experimental foi de 84 dias divididos em quatro períodos de 21 dias. Os parâmetros avaliados foram consumo de ração, taxa de postura, peso médio de ovos, massa de ovos, peso final e conversão alimentar por massa de ovos. Foi observado efeito quadrático para consumo de ração, taxa de postura, massa de ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4391', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a2fe', 'Qualidade pós-colheita em brotos de palma de diferentes cultivares', 'Daniel Pereira Lima; Nathan José Pereira da Silva; Emmanuel Moreira Pereira; Welliton Barros de Magalhães; Ricardo da Silva Henrique', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A palma pertencente à família das cactáceas, sendo de origem mexicana. No Nordeste brasileiro, o broto de palma faz parte da dieta alimentar da população de alguns municípios. Com isso objetivou-se avaliar a qualidade pós-colheita dos brotos de palma proveniente de diferentes cultivares. O trabalho foi desenvolvido no Centro de Ciências e Humanas Sociais e Agrárias, Bananeiras, Paraíba, pertencente à Universidade Federal da Paraíba. Foram utilizados brotos das cultivares Gigante (Opuntia ficus indica Mill.), Redonda (Opuntia ficus indica L.), Orelha de Elefante (Opuntia tuna (L.) Mill.) e Miúda (Nopalea cochenillifera (L.) Salm-Dyck). Os brotos foram colhidos em propriedades rurais às 6:00 horas e transportados ao laboratório, onde foram eliminados os acúleos e lavados. Realizou-se as análises em triplicata dos teores de ácido ascórbico (AA), de acidez titulável (AT) e de sólidos solúveis (SS), pH, umidade e condutividade elétrica. Os brotos de palma da variedade Gigante foram os que a', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4454', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a300', 'Composição da comunidade fitoplanctônica no estuário do rio Apodi-Mossoró, Semiárido brasileiro', 'Rogério Taygra Vasconcelos Fernandes; Rodrigo Fernandes; José Luís Costa Novaes; Rodrigo Silva da Costa; Jônnata Fernandes de Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se caracterizar a estrutura da comunidade fitoplanctônica bem como as principais variáveis abióticas do estuário do rio Apodi-Mossoró, Rio Grande do Norte, Brasil. Foram realizadas coletas mensais durante as marés altas de sizígia e análises de variáveis abióticas e bióticas de julho de2004 aagosto de 2005 em três pontos (foz, estuário médio e estuário superior). Foram calculadas as médias para cada estação de coleta e período sazonal, além dos atributos de comunidade: riqueza, diversidade e equitabilidade. Para a identificação dos principais fatores responsáveis pela variância dos dados foi realizada a Análise de Componentes Principais, as variações na abundância fitoplanctônica, por sua vez, foram avaliadas usando a Análise de Correspondência e a Análise de Correspondência Canônica. O estuário do rio Apodi-Mossoró é um ecossistema tropical e estável termicamente, influenciado pela sazonalidade dos períodos de estiagem e chuvas. Seu regime de salinidade predominante é o euha', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4592', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a304', 'Bioatividade dos extratos aquosos de folhas de pimenta malagueta e eucalipto sobre Zabrotes subfasciatus em grãos de fava', 'Lúcia da Silva Fontes; Aline Amanda Sampaio; Douglas Rafael e Silva Barbosa; Vânia Maria Gomes da Costa Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os extratos vegetais atualmente representam uma alternativa importante no controle de insetos-praga. Objetivou-se com este trabalho analisar os efeitos de extratos aquosos de folhas de pimenta malagueta (Capsicum frutescens) e eucalipto (Eucalyptus sp.) sobre Zabrotes subfasciatus em fava. Foram realizados dois bioensaios no laboratório de Entomologia, Departamento de Biologia, Centro de Ciências da Natureza da Universidade Federal do Piauí, em delineamento experimental inteiramente casualizado, totalizando cinco tratamentos [0% (testemunha), 30%, 60%, 80% e 100 %], cada um com quatro repetições, onde os parâmetros, número de insetos mortos, número de ovos e emergência de adultos foram avaliados. O extrato aquoso de folhas de pimenta malagueta não foi eficiente contra o caruncho Z. subfasciatus, pois, houve mortalidade média de 20% dos insetos nas concentrações de 80 e 100%, e com o aumento da concentração teve-se um estímulo a oviposição e emergência destes. O extrato aquoso de folhas', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4695', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a306', 'Taxa respiratória de frutos de juazeiro (Ziziphus joazeiro Mart.) armazenado sob temperatura ambiente', 'Ana Marinho do Nascimento; Kalinne Passos dos Santos; Franciscleudo Bezerra da Costa; Jéssica Leite da Silva; Francimalba Francilda de Sousa', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O juazeiro é uma planta bastante conhecida dos sertanejos, que além de servir de sombra e arborização de ruas, seus frutos são amplamente consumidos por animais. Algumas pesquisas são direcionadas a essa cultura, no entanto, não existem pesquisas no que diz respeito à natureza respiratória dos frutos. Assim, esta pesquisa teve por objetivo avaliar a taxa respiratória de frutos de juazeiro colhidos de plantas localizadas no município de Queimadas, Paraíba, armazenados à temperatura ambiente controlada (23±1 °C e 55±2% UR) por quatro dias. A taxa respiratória foi determinada por meio da metodologia descrita por Crispim et al. (1994) com adaptações, também foi estimada a massa fresca do fruto e a perda de massa durante o período de armazenamento . Os resultados demonstraram redução de massa fresca do fruto, aumento de perda de massa, bem como, picos climatéricos no terceiro dia de armazenamento, podendo assim, serem considerados frutos de natureza climatérica. Respiratory rate of juazeiro', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4740', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a309', 'Staphylococcus aureus e Salmonella sp. em queijos de coalho artesanais produzidos em São Rafael, Rio Grande do Norte', 'Tarciara Magley da Fonseca Pereira; José Aldenor de Sousa; Lara Barbosa de Souza; Karoline Mikaelle de Paiva Soares; Vilson Alves de Góis', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O queijo de coalho artesanal é produto de origem animal muito consumido principalmente na região Nordeste do Brasil. É comumente fabricado com leite cru, não pasteurizado, como matéria prima, sem a utilização de boas práticas higiênicas, podendo veicular micro-organismos patogênicos ao consumidor. Assim, objetivou-se avaliar a presença de Salmonella sp. e quantificar Staphyloccocus aureus em queijos de coalho produzidos artesanalmente no município de São Rafael Rio Grande do Norte.Foram realizadas coletas em triplicata em sete queijarias artesanais do município, e, em seguida, os queijos foram transportados imediatamente em caixas isotérmicas, ao Laborátório de Biotecnologia Industrial da Universidade Federal Rural do Semi-Árido, onde foram submetidos à análise microbiológica de forma asséptica, conforme metodologia recomendada pela Instrução Normativa nº 62, de 26 de agosto de 2003, do Ministério da Agricultura, Pecuária e Abastecimento. Todas as amostras apresentaram elevadas contage', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4829', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a30c', 'Chemical attributes of soil in agroforestry system of gliricidia intercropped with spineless cactus', 'Aldrin Martin Pérez-Marin; Maria Iza de Arruda Sarmento; Patricio Borges Maracajá; Aline Carla de Medeiros; Ednaldo Barbosa Pereira Junior; José Cezario de Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'In this study, we aimed to assess the chemical attributes of a soil fertilized with organic matter, in an agroforestry system. The experiment was carried out at the Miguel Arraes agricultural experiment station of the National Semiarid Institute (INSA), located in Campina Grande, Paraíba, Brazil. Experimental design consisted of a randomized block with four replications. We applied four treatments of organic fertilization: (HS) Humic Substances; (SW) Seaweeds; (B) Bokashi; and (C) control treatment, without fertilization. Soil samples were collected at 0-20 cm depth, placed in plastic bags and taken to laboratory for the following chemical analysis: pH, potassium (K+), sodium (Na+), phosphorus (P), calcium (Ca2+), magnesium (Mg2+), soil organic matter (SOM), sum of bases (SB), cation exchange capacity (CEC), base saturation (V%) and Soil Quality Index (SQI). Organic fertilizers applied to the soil did not affected pH, P, K+, Na+, Al3+ and CEC. Humic substances treatment increased the a', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4921', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a30d', 'Modelos matemáticos na predição do comportamento higroscópico para pó do mix de batata yacon e suco de lima', 'Renato Costa Silva; Emanuel Neto Alves de Oliveira; Rossana Maria Feitosa Figueiredo; Regilane Marques Feitosa; Alexandre José Melo Queiroz; Lumara Tatiely Santos Amadeu', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A batata yacon tornou-se popular devido aos inúmeros benefícios que proporciona à saúde, porém seu tempo de vida útil é curto, aliado ao escurecimento enzimático, comum em alimentos ricos em compostos fenólicos, que reduz e restringe o seu consumo. Em virtude de ser um produto de alto valor, e com o intuito de se evitar o seu desperdício, justifica-se o estudo de meios de conservação do mesmo. A secagem seguida por transformação do produto em pó se apresenta como uma alternativa conveniente, segura e capaz de proporcionar longa vida útil ao material processado. Diante do exposto, objetivou-se verificar o comportamento higroscópico do pó obtido pela liofilização do mix de batata yacon e suco de lima ácida Tahiti nas temperaturas de 20, 30 e 40 ºC. Elaborou-se um mix de batata yacon com suco de lima ácida Tahiti, aproveitando a propriedade deste suco de atuar na inativação enzimática da enzima polifenoloxidase, além de ser fonte de vitamina C. O mix com maltodextrina foi seco por liofili', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4933', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a310', 'Aspectos fisiológicos e crescimento do algodoeiro ‘BRS topázio’ cultivado com águas salinas e adubação potássica', 'André Alisson Rodrigues da Silva; Jessica Dayanne Capitulino; Héraclito Marques do Nascimento; Geovani Soares de Lima; Rual Araújo Nobrega; Lauriane Almeida dos Anjos Soares', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar os índices fisiológicos e o crescimento do algodoeiro colorido cv. BRS Topázio submetido à irrigação com águas de diferentes níveis de salinidades e adubação com doses de potássio. O experimento foi conduzido em vasos sob condições de casa de vegetação, utilizando-se um Neossolo Regolítico Eutrófico de textura franco-arenoso não salino. Utilizaram-se o delineamento de blocos casualizados, com 4 repetições, cujos tratamentos foram distribuídos em esquema fatorial 4 x 4, sendo quatro níveis de condutividade elétrica da água de irrigação (CEa) (1,5; 3,0; 4,5 e 6,0 dS m-1) e quatro doses de potássio (50; 75; 100 e 125% da recomendação), sendo a dose de 100% correspondente a 150 mg K2O por kg-1 de solo. Avaliaram-se os efeitos dos tratamentos sobre a concentração interna de CO2 (Ci), transpiração (E), condutância estomática (gs), taxa de assimilação de CO2 (A), eficiência no uso da água (EiUA) e a eficiência instantânea da carboxilação (EICi), fitomassa seca das folhas ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5279', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a313', 'Consumo e digestibilidade de dietas contendo feno de jitirana para ovinos em terminação', 'Ariadne de Barros Carvalho; Ana Valéria Mello de Souza Marques; Francisco Jocélio Cavalcante Souza; Daniel Cézar da Silva; Desirée Coelho de Mello Seal', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A jitirana é encontrada em abundância na região semiárida do Nordeste brasileiro, conferindo durante o período chuvoso elevada produção de fitomassa e satisfatório teor de nutrientes, o que a credencia como alimento alternativo para ruminantes. Dessa forma, avaliou-se o efeito da substituição de 0; 25; 50 e 75% do feno de capim-tifton 85 pelo feno de jitirana (FJ) sobre o consumo e digestibilidade em dietas para ovinos, distribuídos em delineamento de quadrado latino 4 x 4 duplo, com oito ovinos. O consumo de matéria seca (CMS) e nutrientes foram influenciados (P<0,05) pela inclusão do FJ à dieta, com exceção do consumo fibra em detergente neutro (CFDN) em g por animal por dia, com média 682,76 ± 125,13. O CMS elevou-se linearmente (P<0,05) em 6,33 g por unidade percentual do FJ acrescido. Houve efeito linear positivo (P<0,05) para consumo de proteína bruta (CPB) e CFDN, com elevação de 1,11 g por animal por dia e 0,02% do peso corporal, respectivamente, por unidade percentual de FJ in', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3987', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a31c', 'Atividade antimicrobiana e análise fitoquímica preliminar do extrato vegetal de alho no controle de fungos fitopatogênicos', 'Gessiel Newton Scheidt; Antônio Carlos Costa Ramos; Layssah Passos Soares; Nadine Cunha Costa; Aloisio Freitas Chagas Junior', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As potencialidades de utilização de métodos alternativos no controle de doenças de plantas são incessantemente estudadas e avaliadas por vários pesquisadores no mundo inteiro, com o objetivo de minimizar o impacto ambiental através da utilização de produtos naturais. Este trabalho teve como objetivo traçar o perfil fitoquímico preliminar verificando a atividade antimicrobiana in vitro do extrato hidroalcóolico de Allium sativum L. contra Bipolaris spp., Curvularia lunata e Fusarium subglutinans através do mecanismo de pulverização na Torre de Potter. Observou-se na análise fitoquímica a presença de taninos hidrolisáveis, saponinas e flavonóides. O extrato possuiu atividade antimicrobiana sobre todos os fungos fitopatogênicos testados, com destaque para os fungos Curvularia lunata e Fusarium subglutinans nas concentrações de 40 a 50%, no entanto, o fungo Bipolaris spp. mostrou-se mais resistente com sensibilidade apenas na concentração máxima de 50%.Antimicrobial activity and analysis p', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4406', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a31f', 'Produção e teor de nitrato em rúcula sob adubação orgânica com cama de frango e esterco bovino', 'Geovani Soares da Silva Júnior; Renan Cesar Dias da Silva; Camila Santos Silva; Gláucia de Mello Pelá; Adilson Pelá', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O nitrogênio é um dos nutrientes mais exigidos pelas plantas. Também é normalmente encontrado em grandes quantidades nos adubos orgânicos. Se absorvido em excesso, pode se acumular no vacúolo das células das plantas como nitrato, e levar à metamioglobina tóxica e à formação de nitrosaminas. Este trabalho objetivou-se avaliar a adubação com cama de frango e esterco bovino de curral na produtividade, teores de N total e nítrico na parte aérea da cultura da rúcula. O delineamento experimental foi em blocos casualizados, em esquema fatorial 2x5, com quatro repetições. Foram testados dois adubos orgânicos (cama de frango e esterco bovino), e cinco doses (0, 10, 20, 30 e 40 t ha-1). O experimento foi implantado em condições de campo, em um Latossolo Vermelho-Amarelo Distrófico. A parcela experimental foi constituída por quatro linhas, espaçadas de 0,25 m, e com 1 m de comprimento. Aos 40 dias após o transplante das mudas, foram avaliados a altura de plantas (usando-se uma régua, a partir do ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4476', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a320', 'Diagnóstico ambiental qualitativo no “lixão” da cidade de Pombal, Paraíba', 'Fernanda Carolina Monteiro Ismael; Camilo Allyson Simões de Farias; José Cleidimário Araújo Leite; Naiara Angelo Gomes; Ana Paula Oliveira Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A destinação ambientalmente inadequada de resíduos sólidos urbanos provoca diversos impactos negativos no meio ambiente, especialmente nos componentes ambientais: solo, água e ar atmosférico. Neste sentido, para que esses efeitos adversos sejam identificados, é necessário conhecer as características do ambiente na área em questão. Neste estudo, objetivou-se a elaboração de um diagnóstico ambiental qualitativo dos meios físico, biótico e antrópico da área do lixão da cidade de Pombal, Estado da Paraíba. A metodologia utilizada teve por base consultas a órgãos públicos, pesquisas bibliográficas, visitas de campo e fotodocumentação. De acordo com os resultados, verificou-se a ocorrência de várias alterações ambientais adversas significativas nos meios físico, biótico e antrópico, típicas da destinação ambientalmente inadequada de resíduos sólidos em “depósitos” a céu aberto, o que tem resultado em uma degradação ambiental local e acarretado danos sociais, sanitários e ecológicos para o mu', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4560', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a324', 'Produção, aspectos nutricionais e fisiológicos de alface sob adubação foliar com Spirulina platensis', 'Josinaldo Lopes Araújo; Wellinghton Alves Guedes; Railene Hérica Carlos Rocha; Débora Samara Oliveira e Silva; José Franciraldo de Lima; Jackson Silva Nóbrega', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar a influência de concentrações do fertilizante orgânico a base de Spirulina platensis sobre a produção, crescimento, teores de N, P, K e sódio e sobre as trocas gasosas de alface cv. Elba em condições de campo. Utilizou-se o delineamento de blocos ao acaso, com seis tratamentos, constituídos das concentrações do fertilizante (0; 1,5; 3,0; 4,5; 6,0 e 7,5%) com seis repetições. No ponto de colheita da cultura foram avaliadas variáveis de produção e crescimento, os teores de nitrogênio, fósforo, potássio e sódio, bem como, as trocas gasosas das plantas com o medidor de gás infravermelho (IRGA). Os resultados obtidos mostraram que as concentrações do fertilizante, não afetaram a produção, o crescimento, os teores de nutrientes avaliados, assim como não influenciaram as trocas gasosas das plantas.Production, mineral nutrition and physiological aspects of lettuce under foliar fertilization with Spirulina platensis Abstract: The objective of this study was to evaluate the ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4722', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a327', 'Consciência ambiental e percepção sobre os resíduos sólidos pelos residentes da Cidade de Coremas, Paraíba', 'Gabriel Carlos Moura Pessôa; Daniel Jackson Andrade de Sousa; Alan Dél Carlos Gomes Chaves; Ricardo Ricelli Pereira de Almeida; Carlos Sergio Araújo dos Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Resíduos sólidos são todos os restos sólidos ou semi-sólidos das atividades humanas ou não-humanas, que embora possam não apresentar utilidade para a atividade fim de onde foram gerados, podem virar insumos para outras utilizações. Objetivou-se avaliar o comportamento da população à respeito das atitudes e percepção com relação aos resíduos sólidos na cidade de Coremas, Paraíba. Os dados referentes a atitudes e percepção dos atores sociais foram coletados na cidade de Coremas por meio de questionários, previamente estruturados com perguntas de múltipla escolha a fim de conhecer o perfil dos entrevistados através das seguintes variáveis: sexo, faixa etária, escolaridade, estado civil e renda. Foi realizada uma análise descritiva para verificar a percepção dos residentes no município segundo as variáveis relacionadas aos resíduos sólidos. A relação entre variáveis socioeconômicas e o comportamento ambiental referente aos resíduos sólidos dos moradores da cidade de Coremas foi verificada ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4808', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a32a', 'Levantamento etnobotânico de espécies arbóreas no assentamento Tabuleiro Grande, Apodi, Rio Grande do Norte', 'Alan Cauê Holanda; Rejane Tavares Botrel; Mônica Costa Cordeiro', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se realizar um levantamento etnobotânico no Projeto de Assentamento Tabuleiro Grande, localizado em Apodi, Rio Grande do Norte, contribuindo para o resgate do conhecimento popular discutindo as implicações do uso da vegetação arbórea na conservação dos recursos florestais. A condução do estudo foi por meio da observação direta e entrevistas semiestruturadas (21 entrevistas). Para análise dos dados foram feitas abordagens qualitativas (acesso a informações subjetivas) e quantitativas (Valor de Uso; índices de diversidade de Shannon e de equabilidade de Pielou). Foram mencionadas no levantamento 57 espécies arbóreas, entre nativas e exóticas, distribuídas em 26 famílias e enquadradas nas seguintes categorias de uso: Madeira (móveis e construção), Medicina/Higiene, Apicultura, Lenha, Veterinária Popular, Forragem, Alimentação Humana e Outros. Com os resultados obtidos, conclui-se que a comunidade estudada possui conhecimento sobre um grande número de espécies arbóreas. No entant', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4925', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a32b', 'Biometria e características físico-químicas da fruta-pão (Artocarpus altilis)', 'Mônica Tejo Cavalcanti; João Vitor Fonseca Feitoza; Erick dos Anjos Bezerra', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A espécie Artocarpus altilis produz frutos popularmente conhecidos como fruta-pão. São climatéricos e contribuem com quantidades consideráveis de energia e fornecer os principais nutrientes da dieta. Podem ser consumidos cozidos, fritos ou torrados e em processos tecnológicos tendo potencial para ser empregados em biscoitos e comercializados como farinha. Na literatura são poucos os trabalhos que relatem as características desses frutos, principalmente da região Nordeste. Desta forma, objetivou-se avaliar a biometria e as características físico-químicas da fruta-pão coletada no município de Santa Rita, Paraíba, Brasil. Foram selecionados 30 frutos firmes em 3 estádios de maturação, com pedúnculo, casca verde e amarelada, látex presente e livres de lesões. Os frutos apresentaram em média diâmetro externo transversal e diâmetro externo longitudinal de 15,98 (± 0,12) e 13,11 (± 0,13) cm, respectivamente, bem como massa média de 1,52 (± 0,06) Kg e firmeza de 66,80 (± 1,13) N. Quanto a comp', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5027', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a32d', 'Temporal analysis of water volume at Capoeira Reservoir Mãe d’Água, Paraíba, Brazil', 'Denize Monteiro dos Anjos; Ivonete Alves Bakke; Danilo de Medeiros Arcanjo Soares; Ewerton Medeiros Simões; Talytta Menezes Ramos; Ana Claudia Caetano Pinheiro Leite', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'The “Polígono das Secas” is a region in the Northeast of Brazil that stands out by its low precipitation, high temperatures, and dry climate. Geoprocessing and the remote sensing techniques used in this research demonstrate the effectiveness for the monitoring of environmental resources. The objective of this work was to use the normalized difference water index (NDWI) in a comparative analysis of the reduction of the water surface area of the dry periods, November 2009 and December 2016, of the Capoeira Reservoir using images from the Landsat 5 TM satellite and Landsat 8 OLI, respectively. The results showed high values of NDWI in 2009, corresponding to La Niña period, with high precipitation and overflow of reservoirs. NDWI values in 2016 were low due to the low precipitations typical of El Niño periods. NDWI can be used to detect and monitor the presence of water and is an excellent tool to assist water monitoring agencies through the monitoring of rivers, lakes, and reservoirs in r', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5115', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a337', 'Caracterização botânica-agronômica e do óleo essencial de acessos de manjericão', 'Aloísio Freitas Chagas Júnior; Henrique Guilhon de Castro; Dione Pereira Cardoso; Lillian França Borges Chagas; Ronice Alves Veloso', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se realizar a caracterização de quatro acessos e duas cultivares de manjericão por características fitoquímicas do óleo essencial e botânico-agronômicas em diferentes épocas de colheita. O experimento foi instalado utilizando-se um delineamento inteiramente casualizado em esquema de parcela subdivida, com quatro repetições. As parcelas consistiram de quatro acessos e duas cultivares de manjericão e as subparcelas por cinco épocas de amostragem. A análise de agrupamento por meio do método Tocher, utilizando as características botânico-agronômicas e fitoquímicas do óleo essencial, promoveu o agrupamento dos acessos silvestres no mesmo grupo evidenciando similaridade entre eles. Os acessos coletados na mesma região formaram grupo conjuntos. Observou-se variação na constituição dos grupos pelos acessos nas diferentes épocas de avaliação por características botânico-agronômicas. A divergência genética entre acessos e cultivares de manjericão, avaliada por características botânico-', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4130', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a33c', 'Aspectos socioeconômicos e ambientais do reuso de águas residuárias em uma comunidade rural localizada no município de Apodi-RN', 'Luara Lourenço Ismael; Gleydson de Freitas Silva; Francisco Aires Sizenando Filho; Maria Alcilene Morais; Anderson Alves Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A utilização da água residuária na produção agrícola é uma alternativa sustentável do ponto de vista ambiental e, sobretudo econômica para a realidade da região Semiárida do Brasil. Este trabalho teve por objetivo caracterizar o perfil socioeconômico analisando o nível de satisfação de uma comunidade rural em relação ao reuso e seus benefícios sociais e ambientais. A pesquisa foi realizada no Projeto de Assentamento Milagre, localizado no município de Apodi no Estado do Rio Grande do Norte. A metodologia de análise foi por meio de aplicação de questionários com as famílias que correspondem um total de 26 casas. O período de aplicação dos questionários se deu no mês de junho de 2013. Constatou-se quanto aos aspectos socioeconômicos que as crianças de 0-3 anos de idade não dispõem de nenhum acompanhamento escolar. O estado civil dos chefes da família correspondia a 12% casados, 10% assumem uma união consensual e 1% dos assentados são viúvos. A maioria das famílias entrevistadas residem n', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4306', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a33d', 'Qualidade físico-química e toxicológica de farinha obtida do eixo central de jaca', 'Hyago Costa Sousa; Nathan José Pereira da Silva; Emmanuel Moreira Pereira; Carlos Roberto Marinho da Silva Filho; Agda Letícia Barbosa de Macêdo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A produção de farinha do eixo central de jaca se apresenta como uma alternativa viável para o aproveitamento dessa parte do fruto e sua utilização na indústria. O projeto foi desenvolvido no Centro de Ciências Humanas, Sociais e Agrárias, Bananeiras-PB pertencente a Universidade Federal da Paraíba. Os frutos foram adquiridos no pomar do CCHSA. As farinhas foram obtidas a partir da secagem do eixo central em quatro diferentes temperaturas 50, 60, 70 e 80 °C. Foi determinada a potencialidade toxicológica frente Artemia Salina do eixo central e de suas respectivas farinhas bem como sua caracterização físico-química. O eixo central de jaca não apresentou toxicidade assim como as farinhas obtidas a 50, 60 e 70 °C. A farinha do eixo central obtida a temperatura de 50 °C apresentou os melhores resultados nas análises físico-químicas.Physicochemical and toxicological quality of flour obtained from the central axis of jackfruitAbstract The production of flour from the central axis of jackfruit ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4315', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a341', 'Espacialização da cobertura do serviço de saneamento básico e do índice de desenvolvimento humano dos municípios do Marajó, Pará', 'Artur Sales de Abreu Vieira; Rodrigo Silvano Silva Rodrigues; Rafaela Nazareth Pinheiro de Oliveira Silveira; Diêgo Lima Crispim; Lindemberg Lima Fernandes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O acesso aos serviços de saneamento básico tem causado preocupação, principalmente nos estados das regiões Norte e Nordeste e, mais especificamente em municípios com orçamento limitado, de pequeno porte e distante das capitais, onde abrigam populações em situações de vulnerabilidade social. Neste contexto, objetivou-se analisar a situação de alguns serviços do saneamento ambiental e do índice de desenvolvimento humano municipal dos municípios da mesorregião geográfica do Marajó, estado do Pará. Para tanto, foi levantado algumas informações por meio de dados secundários dos municípios que compõe a mesorregião em estudo, com ênfase em alguns serviços de saneamento e do IDHM. Os resultados demonstraram que o índice de atendimento do serviço de coleta de esgoto doméstico deixa extremamente a desejar, em particular com relação à coleta e ao tratamento do esgoto sanitário. Quanto à forma de destinação dos resíduos sólidos, verificou-se que alguns municípios ainda adotam uma maneira inapropri', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4507', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a345', 'Crescimento e absorção de macronutrientes na cultura da melancia no estado de Pernambuco', 'Thiago Alves Pimenta; Patricio Borges Maracajá; Aline Carla de Medeiros; Tiago Silva Lima; Raimunda Ariádna Gomes de Souza; Pedro Aguiar Neto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se avaliar o crescimento e acúmulo de macronutrientes por cultivares de melancia no estado de Pernambuco. O trabalho foi conduzido na estação experimental Bebedouro (Petrolina-PE) pertencente à EMBRAPA Semiárido, no período de setembro a dezembro de 2009. O solo da área experimental foi classificado como argilosolo vermelho-amarelo eutrófico (EMBRAPA, 1999). O delineamento utilizado foi em blocos casualizados completos, com quatro repetições em esquema fatorial 2x5. Os tratamentos resultaram da combinação de duas cultivares de melancia (Quetzale e Shadow) e cinco épocas de coletas: 15, 25, 35, 45 e 55 dias após o transplantio.  Em cada coleta foram utilizadas três plantas por repetição. A unidade experimental para o experimento foi constituída por três fileiras de plantas de 10,5 m de comprimento, com espaçamento de 2,0 x0,50m perfazendo um total de 63,0 m2. As coletas de plantas foram realizadas na fileira central. As cultivares Quetzale e Shadow apresentaram crescimento ini', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4540', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a348', 'Inventário preliminar da entomofauna em área de policultivo e monocultivo de frutíferas no município de Ipanguaçu, RN', 'Ewerton Marinho Costa; Adriano Soares Carvalho; Áleny Raiane Fonsêca Pinheiro; Rayane Dantas Pinheiro; Antônio Francisco de Mendonça Junior', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar a diversidade de insetos em área de policultivo e monocultivo agroecológico de frutíferas no município de Ipanguaçu, Rio Grande do Norte. O levantamento foi realizado na fazenda escola do Instituto Federal do Rio Grande do Norte (IFRN), Campus Ipanguaçu, no período de junho à agosto de 2012, em duas áreas distintas (0,8 ha cada): Área 1 (5°32''14.86"S e 36°52''19.81"W) - Pomar agroecológico (policultivo com goiaba, acerola, graviola, limão, manga e banana) e Área 2 (5°32''1.55"S 36°53''2.21"W) - monocultivo agroecológico de banana. Foram identificadas ao final do levantamento nove ordens na área de policultivo agroecológico de frutíferas: Hymenoptera, Diptera, Coleoptera, Orthoptera, Blattodea, Hemiptera, Lepidoptera, Odonata e Dermaptera e quatro na área com monocultivo agroecológico de banana: Hymenoptera, Diptera, Coleoptera e Orthoptera. O resultado obtido no presente trabalho indica que, mesmo sob o mesmo sistema de manejo, em áreas cultivadas com ma', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4605', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a349', 'Climatologia da pluviometria do município de Teresina, Piauí, Brasil', 'Raimundo Mainar de Medeiros; Hudson Ellen Alencar Menezes; José Lucas Guilherme Santos', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'As variações nas precipitações refletem claramente a dinâmica atmosférica da região, marcada pela intensa variabilidade, onde se observa a atuação da Zona de Convergência Intertropical (ZCIT) com sua atuação entre os meses de janeiro a março, sendo esse período mais chuvoso. As variabilidades espaço temporal no comportamento das chuvas tem sido analisadas e diagnosticadas por vários autores no Nordeste do Brasil (NEB), portanto objetivou-se diagnosticar a variabilidade dos índices pluviométricos em Teresina no Estado do Piauí no período de 1913 a 2010. A análise do comportamento da precipitação nas cidades de grande e médio porte é de extrema importância para o gerenciamento dos recursos hídricos, uma vez que se trata de áreas densamente urbanizadas. Muitas vezes, sem uma estruturação urbana adequada, estas cidades se encaixam perfeitamente nesse contexto. Foram utilizados dados mensais observados e anuais de precipitação pluviométrica no período de 1913 a 2010, com 97 anos de observaç', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4609', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a34b', 'Modelling of the canopy photosynthesis in intercropping with lettuce, rocket, radish, coriander and red beet', 'Caciana Cavalcanti Costa; José Wilson da Silva Barbosa; Laíza Gomes de Paiva; Jerfferson Araujo Cavalcante; Kilson Pinheiro Lopes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'In the past years, many combinations of plants in intercropping have been demonstrating agronomic viability due to the increase of production per unity of area and greater use of natural resources. However, the knowledge and the proper choice of crops that will be part of the system are necessary to reach achievement, so that there is mutual interaction between them. The study had the purpose of evaluate the productivity of lettuce (Elba) intercropped with coriander (Verdão), rocket (Cultivada), beet (Early Wonder) or radish (Crimson Gigante). The experiment was conducted in the experimental area of the CCTA/UFCG, Pombal/PB, from September 2013 to July 2014. Nine treatments were assessed (4 intercropping and 5 monocultures), installed in randomized blocks with four replications. The amalgamation of lettuce with crops of coriander, rocket, radish or beet did not affected negatively its profitability. The intercropping of lettuce and beet presented the greater productive efficiency and e', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4631', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a352', 'Biomass and nutrient accumulation of leguminous green manure species in the Jaguaribe-Apodi region, Ceará, Brazil', 'Ismail Soares; Natanael Santiago Pereira; Fábio Rodrigues de Miranda', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'The ability of leguminous green manure to incorporate significant amounts of nutrientes into the soil makes them excellent alternatives for the region agriculture systems. This study aimed to evaluate the potential use of six leguminous species (Crotalaria juncea, Canavalia ensiformes, Cajanus cajan, Crotalaria spectabilis, Dolichos lab lab and  Mucuna deeringiana) as green manure in an area of the Jaguaribe-Apodi agricultural region, CE, Brazil. The experiments were carried out under field conditions in a randomized block design with five replications. Sampling of biomass of shoots was carried out 78 days after sowing on each plot. It was determined the total biomass and nutrients accumulation in the plants that grew in the plots (leguminous and weeds). We concluded that the use of Crotalaria juncea showed up as the most promising treatment in terms of biomass production and nutrient accumulation.Biomassa e acúmulo de nutrients por espécies de leguminosas utilizadas como adubo verde n', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3945', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a356', 'Avaliação da cinética de secagem da carambola em secador convectivo', 'Aline Pacheco Albuquerque; Emmanuel Moreira Pereira; Francisco de Assis Mendes; Hofsky Vieira Alexandre; Daniela Dantas de Farias Leite', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A carambola (Averrhoa carambola L.) é tida como uma das frutas de grande potencial, por ser fonte de compostos essenciais para a nutrição dos seres humanos. A grande parte das perdas pós-colheita de frutas deve-se ao despreparo das pessoas do ramo da agroindústria e consumidores. A secagem é o processo comercial mais utilizado para preservar e aumentar a vida útil do produto alimentício convertendo-os em produtos mais estáveis. Diante disso, o objetivo desse trabalho foi de obter curvas de secagem de carambola em um secador convectivo e, a partir dessas curvas, obter dados de taxa de secagem. As carambolas foram lavadas, higienizadas, minimamente processadas em fatias de 1 cm de espessura e colocadas imediatamente nas bandejas para secagem. Utilizou-se um secador convectivo para o experimento, nas temperaturas de 60, 70 e 80 °C e velocidade do ar de secagem de 1,5 m s-1. As pesagens foram realizadas até que as variações de massa fossem insignificantes e, em seguida, as amostras foram c', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4026', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a35a', 'Comportamento dos teores de sais em perfil de solo com vegetação nativa e cultura irrigadas', 'José Geraldo de Araújo Ferreira Filho; Kyonelly Queila Duarte Brito; Soahd Arruda Rached Farias; Felipe Guedes Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A salinização do solo é um problema que vem crescendo em todo o mundo; principalmente nas regiões áridas e semiáridas, tendo um agravante maior devido a baixa precipitação e a elevada evaporação. Nestas condições nem sempre as aguas utilizadas são de boa qualidade afetando a capacidade das plantas de expressar seu máximo potencial produtivo. Diante disto, objetivou-se com o presente estudo avaliar o comportamento dos sais no solo sob condições naturais e irrigadas por águas residuárias da cidade de Campina Grande, PB durante o período de maio a julho de 2014. A pesquisa em campo foi realizada na propriedade Cajá que são abastecidas pelas águas do rio Bodocongó, destinada à produção de capim Mombaça, capim Tifton, Sorgo e Milho irrigados através de sistemas de irrigação como pivô, aspersão fixa, e inundação. Foram coletados três pontos distintos de amostras de solo nas profundidade de 10 cm, 30 cm, 60 cm, 75 cm, 90 cm. Sendo o primeiro na área irrigada por superficial o segundo área nat', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4049', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a35d', 'Influência da cor do tegumento e da temperatura na germinação e vigor de sementes de Crotalaria ochroleuca L.', 'Adailza Guilherme da Silva; Gilvaneide Alves de Azeredo; Fillipe Silveira Marini; Emmanuel Moreira Pereira; Vênia Camelo de Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A crotalária é uma leguminosa originária da Índia e Ásia Tropical com ampla adaptação as regiões tropicais. No Brasil, foi introduzida inicialmente para a produção de fibras, mas se difundiu como planta condicionadora do solo. Atualmente, é utilizada como planta para cobertura do solo e adubo verde, contribuindo para o incremento da fertilidade e redução da erosão do solo. O objetivo do trabalho foi avaliar a influência da cor do tegumento e da temperatura na germinação e vigor de sementes de Crotalaria ochroleuca L. As sementes foram separadas de acordo com a cor do tegumento. Foram classificadas em quatro cores: vermelha, rósea, bege-claro, cinza e a testemunha (sementes de todas as cores), constituindo, assim, os cinco tratamentos. O ensaio foi conduzido em laboratório e em casa de vegetação. No laboratório foi avaliada a germinação das sementes e o índice de velocidade de germinação, sendo então calculado o tempo médio de germinação. Na casa de vegetação, foi realizada a emergência', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4180', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a35e', 'Uso de Plantas com Fins Medicinais no Município de Barra – BA', 'Debora Cristina Coelho; Antonia Mirian Nogueira de Moura Guerra; Aline Carla de Medeiros; Priscila Santos Silva; Deyse Silva dos Santos; Hélen Tamares Santos de Sá', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho foi realizado no Assentamento de Reforma Agrária Sítio Novo, Barra–BA, objetivando conhecer as espécies medicinais e suas formas de uso adotadas pela população local. Entre Abril e Maio de 2015 foram realizadas entrevistas com aplicação de questionários estruturados. Todos os entrevistados fazem uso de plantas medicinais e cultivam alguma espécie em suas residências, usam as plantas por tradição familiar e por se tratar de um remédio natural  consomem principalmente quando estão doentes. Foram registradas 258 citações, nas quais foram relatadas a utilização de várias partes vegetais das 41 espécies, em 11 formas de preparo, com diferentes finalidades terapêuticas. As folhas e as cascas foram as partes mais utilizadas e os chás a principal forma de uso. As famílias Lamiaceae, Anacardiaceae, Myrtaceae e Rutaceae foram aquelas com maior representatividade e adoção medicinal. As espécies mais citadas foram a Cymbopogon citratus (Capim Santo – 15,5%), Lantana camara L. (Camará', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4244', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a360', 'Crescimento de plântulas de alface (Lactuca sativa L.) em solo oriundo de um povoamento de Luetzelburgia auriculata (Allemão) Ducke', 'Roberto Ferreira Barroso; Francisco de Assis Pereira Leonardo; César Henrique Alves Borges; Aline Carla de Medeiros; Érika do Nascimento Fernandes Pinto; Jacob Silva Souto', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Esta pesquisa buscou conhecer características alelopáticas e de fertilidade de um solo oriundo de povoamento de Luetzelburgia auriculata (Allemão) Ducke), através da avaliação do crescimento de plantas de alface. Inicialmente, realizou-se a coleta do solo sob o povoamento da L. auriculata (SPL) e de uma área externa a esse povoamento (SAE), na Fazenda Cachoeira de São Porfírio, em Várzea-PB, e encaminhou-se para o Centro de Saúde e Tecnologia Rural da Universidade Federal de Campina Grande, Campus de Patos. Em delineamento inteiramente casualizado, aplicaram-se cinco tratamentos com cinco repetições, colocando-se três sementes de alface por vaso contendo os seguintes tratamentos: T1=100%SAE; T2=100%SPL; T3=75%SPL; T4=50%SPL e T5=25%SPL. Aos 63 dias da semeadura, realizou-se a colheita e mensuraram-se as variáveis: comprimento da parte aérea, da raiz, peso da massa fresca da parte aérea, área foliar e número de folhas de cada indivíduo e a análise química dos substratos. Aplicou-se a AN', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4260', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a363', 'Análise hierárquica dos problemas existentes na produção de mel do Estado da Paraíba', 'Rubênia de Oliveira Costa; Aline Costa Ferreira; Thiago Alves Pimenta; Augusto Henrique Alves Bezerra; Bárbara Bruna Maniçoba Pereira; Anderson Bruno Anacleto de Andrade', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A produção de mel representa uma das atividades produtivas que fornece grandes oportunidades para a agricultura familiar na região nordeste, proporcionando o desenvolvimento econômico e social dos que exercem esta atividade. Porém é uma atividade que representa alguns entraves durante a produção, gerando perdas e produtos impróprios para o consumo. Baseada nisso, esta pesquisa tem o objetivo de analisar os problemas existentes na produção de mel do Estado da Paraíba com a utilização do método de análise hierárquica (AHP). Quanto aos procedimentos metodológicos, inicialmente foi feito um levantamento bibliográfico para identificar os problemas da produção de mel apontados na literatura, em seguida foram feitas entrevistas semiestruturada com especialistas que trabalham na apicultura paraibana e listados os problemas encontrados na produção de mel no estado. Esta lista foi validada pelos entrevistados. Para a hierarquização dos problemas utilizou-se o método de análise hierárquica (AHP).', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4274', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a364', 'Doses de fósforo e potássio no desenvolvimento da cultura de Crambe abyssinica', 'Lucia Helena Garófalo Chaves; Ramara Sena Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A cultura do crambe (Crambe abyssinica) é uma alternativa para produção de biodisel recebendo este enfoque por sua rusticidade, precocidade, alto teor de óleo e adaptabilidade. Os nutrientes minerais possuem funções essenciais e específicas no metabolismo das plantas. A aplicação de fertilizantes minerais é feita para repor sua perda, pois a cada ciclo as plantas extraem nutrientes dos solos. O manejo adequado do uso de fertilizantes no cultivo do crambe é pouco conhecido, não havendo recomendações específicas para a adubação. Portanto, objetivou-se estudar os efeitos da adubação mineral relativa aos elementos fósforo e potássio, no crescimento e na produção do crambe. O experimento foi instalado em casa de vegetação, com delineamento inteiramente casualizado em esquema fatorial 4 x 4 + 1, com três repetições, totalizando 51 unidades experimentais. As doses de fósforo e potássio utilizadas foram 50; 75; 100 e 125 kg ha-1. Aos 60 dias após o semeio (DAS) foram analisadas altura das plan', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4298', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a365', 'Influência da população de plantas sob o crescimento e produção orgânica de alface no Sertão paraibano', 'Caciana Cavalcanti Costa; Ivando Comandante de Macedo Silva; Maíla Vieira Dantas; José Junior Araújo Sarmento; Kilson Pinheiro Lopes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O grau de interferência entre plantas em função da densidade é um dos fatores que afeta a quantidade e qualidade das mesmas, pois quanto maior a densidade de plantas, mais elevada será a concorrência pelos recursos do ambiente. O presente trabalho objetiva avaliar o efeito da competição intraespecífica dos diferentes espaçamentos sobre o crescimento e produção da alface Cristina. O experimento foi conduzido em área experimental do Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, em Pombal, PB. O trabalho foi realizado em blocos casualisados, compostos por quatro espaçamentos: 0,25 x 0,30; 0,25 x 0,25; 0,20 x 0,25 e 0,20 x 0,20 m, totalizando um número de: 100.000; 120.000; 150.000 e 187.000 plantas por hectare, respectivamente, com cinco repetições. Tendo como base a recomendação da adubação do estado do Pernambuco, foi aplicada a dose de 130 Kg ha-1 doN indicado para alface tendo como fonte o esterco caprino. A adubação orgânica foi incorporada ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4413', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a367', 'Produção e avaliação de briquetes de capim elefante (Pennisetum purpureum Schum.) cultivados com doses de nitrogênio', 'Juscileia de Souza Lima; César Henrique Alves Borges; Maílson Pereira de Souza; Yara Karolynne Lopes Abreu; Felipe Silva Amorim; Marcelo Xisto Ribeiro', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A produção de briquetes surge como uma forma alternativa no reaproveitamento de resíduos lignocelulósicos, concentrando a energia disponível na biomassa, visando a problemática do armazenamento de resíduos, produzindo biocombustível. O objetivo desse trabalho foi produzir briquetes utilizando resíduo de capim elefante (Pennisetum purpureum Schum.) cultivar Carajás, adubado com diferentes doses de nitrogênio avaliando quanto à descompressão, índice de combustão (ICOM), massa, volume, densidade, altura e diâmetro. O capim elefante recebeu dosagens de 200 e 400 kg de N/ha. A coleta foi realizada em diferentes épocas: 60, 75 e 90 dias. Após a coleta, o material foi armazenado em sacos de fibra e deixado para climatizar com temperatura e umidade controlada (20ºC e 60%). O material foi triturado com o auxílio de um moinho. Posteriormente, para cada briquete produzido pesou-se 40 g de biomassa, na qual foi compactada em uma prensa hidráulica de 15 Toneladas.  A pressão utilizada foi de aproxi', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4468', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a368', 'Adubação verde com espécies espontâneas da caatinga no cultivo do rabanete em sucessão a rúcula', 'Janilson Pinheiro de Assis; Paulo César Ferreira Linhares; Whenia Benevides Ramalho; Alany Moisa Bezerra de Almeida; Lauvia Moesia Morais Cunha', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O rabanete é uma planta de ciclo curto e o ambiente exerce grande interferência na qualidade de suas raízes O efeito residual da adubação anterior em cultivos subsequente é de suma importância, uma vez que a fertilização do solo em uma atividade tão intensa, como a olericultura, aumentaria o custo de produção sempre que fosse implantada uma nova cultura. Este trabalho foi conduzido na fazenda experimental Rafael Fernandes, pertencente à Universidade Federal Rural do Semi-Árido, Mossoró-RN, no período de julho a novembro de 2010. Objetivou-se avaliar a adubação verde com espécies espontâneas da caatinga no cultivo do rabanete em sucessão ao cultivo da rúcula. O rabanete assim como a rúcula foi plantado em parcelas de 1,2 x 1,2 m sendo avaliado o efeito residual das espécies espontâneas da caatinga (Jitirana, flor-de-seda e mata-pasto) nas quantidades (0; 6,0; 12,0; 18,0; 24,0 e 30,0 t ha-1). Após a retirada do primeiro cultivo, semearam-se sementes de rabanete nas parcelas referente aos', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4498', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4379cbb2c2c1af309d', 'Produtividade de tomate cereja em sistema orgânico em função do uso de calcário, esterco e mulching', 'Antonia Gorete Galdino (UFCA UNIVERSIDADE FEDERAL DO CARIRI); Maria Ferreira Costa (UFCA); Wíctor Állyson Rodrigues (UFCA); Felipe Thomaz Camara (UFCA); Pedro Vinícius Silva (UFFCA)', 'Editora Verde', 'Agriculture', 'Agriculture', 'O desenvolvimento de técnicas que proporcionem maiores produtividades é necessário para atender a crescente demanda por orgânicos. Portanto, objetivou-se avaliar a produtividade de tomate cereja em função do uso de mulching, calcário e esterco bovino em sistema orgânico. A pesquisa foi realizada no Centro de Ciências Agrárias e da Biodiversidade da Universidade Federal do Cariri, Crato-Ceará. Foram avaliados o comprimento e o diâmetro dos frutos, o número de frutos por planta, a massa por fruto, massa de frutos por planta e a produtividade. Os resultados evidenciaram efeito positivo do uso do calcário para elevação da saturação por bases a 80%, enquanto que o mulching não teve efeito significativo. Quanto à adubação orgânica com esterco bovino, apresentou resposta linear até a dose de 5 L por cova, com valores crescentes de produtividade. Conclui-se que o uso de calcário e esterco bovino beneficiam o desenvolvimento e produtividade do tomate cereja, enquanto o uso de mulching não melho', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4655', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64746a4479cbb2c2c1af30c9', 'Caracterização fenológica de cultivares de videira utilizada na fabricação de vinho no Rio Grande do Norte, Brasil', 'Luana Mendes de Oliveira (Universidade Federal Rural do Semi-Árido); Wilma Freitas Celedônio (Universidade Federal Rural do Semi-Árido); Vander Mendonça (Universidade Federal Rural do Semi-Árido); Ali', 'Editora Verde', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/5454', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce76', 'Substrato a base de rejeito de minera??o de cobre na produ??o de ip?-branco', 'Oliveira, Fernando Kidelmar Dantas de; Costa, Jos? Ronaldo Medeiros; Oliveira, ?ngelo Kidelman Dantas de; Gomes Tabosa, Louis Dostoievsky; Arruda, Anna Gabriela Rocha; Costa, Denilson da Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'Um dos principais metais explorados no mundo ? o cobre (Cu), um elemento nativo, que dificilmente ? encontrado puro na natureza. A lavra e beneficiamento do cobre geram debates ambientais devido ? forma??o de agentes poluidores nas ?reas de concentra??o, fundi??o e refino, al?m dos impactos negativos na vegeta??o e topografia da ?rea minerada. Este trabalho teve como objetivo investigar o desempenho morfom?trico inicial do ip?-branco (Tabebuia roseo-alba (Ridl.) Sandwith) em substrato composto por rejeito de minera??o de cobre e percentuais crescentes de mat?ria org?nica, bem como, avaliar seu potencial fitorremediador e o ?ndice de Qualidade de Dickson (IQD). O delineamento experimental foi o inteiramente casualizado, onde se coletou dados morfom?tricos dos tratamentos referentes ? altura, di?metro do caule e n?mero de folhas da esp?cie vegetal que posteriormente foram submetidos ? an?lise estat?stica e ao IQD, al?m dos c?lculos relacionados ao ?ndice e fator de transloca??o do cobre ', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce76', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce78', 'An?lise agroecon?mica do arranjo de plantas no cultivo de mel?o em Nova Mutum, Mato Grosso', 'Dipple, Fernanda Louren?o; Toledo, Claudia Aparecida de Lima; Rocha, Rafael Rosa; Begnini, Renata Lunardi; Junior, Santino Seabra; Trento, Daiane Andreia', 'Editora Verde', 'Agriculture', 'Agriculture', 'O espa?amento ? uma estrat?gia que pode ser utilizada para aumentar a produ??o e a rentabilidade do meloeiro (Cucumis melo L.), sem interferir negativamente na qualidade dos frutos. Por?m, s?o escassos os trabalhos publicados avaliando espa?amentos na rentabilidade da cultura na regi?o Centro-Oeste, principalmente em Mato Grosso. Desse modo, o objetivo do trabalho foi determinar as respostas da produ??o, qualidade e estimar os custos de produ??o e rentabilidade do meloeiro em diferentes densidades de plantio em Nova Mutum, MT. Foram avaliados cinco espa?amentos (0,2, 0,3, 0,4, 0,5 e 0,6 m) entre plantas e 3 m entre linhas, cultivado sob mulching em delineamento em blocos ao acaso. Realizaram-se avalia??es para determina??o de produtividade total e comercial, massa de frutos comerciais, largura e comprimento de frutos, teor de s?lidos sol?veis totais, pH, acidez titulavel total, ?ndice de matura??o de fruto e indicadores econ?micos. As plantas cultivadas no espa?amento 0,2 m obtiveram m', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce78', NULL, 'English', 'published', false, false, 'open', 'pdf')
