INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce79', 'Din?mica de nidifica??o de Apis mellifera na Caatinga pernambucana: Chuvas e floradas ap?colas influenciam no processo?', 'Cavalcante, Marcelo Casimiro; S?, Marileide de Souza; Oliveira, Pedro de Assis de; Melo, H?lio Fernandes de; Melo, Andr? Laur?nio de', 'Editora Verde', 'Agriculture', 'Agriculture', 'O comportamento de Apis mellifera em ?reas urbanas tem causado acidentes com seres humanos e animais dom?sticos. A??es que visem minimizar o problema, como a captura, s?o essenciais. Assim, o presente trabalho buscou compreender a din?mica de nidifica??o e a varia??o anual das ocorr?ncias de enxames e col?nias, as suas rela??es com a precipita??o pluviom?trica e a flora??o ap?cola. O trabalho foi realizado no Sert?o Pernambucano, em Serra Talhada, principalmente, e em cidades vizinhas. As ocorr?ncias foram registradas no per?odo de 2014 a 2015. Col?nias e enxames foram capturados e levados para o api?rio da Unidade Acad?mica de Serra Talhada, ou doados para uma comunidade de assentados. Dados pluviom?tricos foram coletados, e o levantamento do pasto ap?cola em Serra Talhada, atrav?s de transectos aleat?rios de 1.500m a partir do referido api?rio. Foram registradas 115 ocorr?ncias, sendo 65% em ?reas urbanas e 35% em ?reas rurais. Desse total, 76% foram de col?nias nidificadas e 24% de ', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce79', NULL, 'English', 'published', false, false, 'open', 'pdf')
