INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce7b', 'Produ??o org?nica na renda bruta agropecu?ria: Estudo baseado nos dados do censo agropecu?rio de 2017', 'Gomes, Eliane Gon?alves; Souza, Geraldo da Silva e; Gazzola, Rosaura', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo do trabalho ? estudar a presen?a da agricultura e/ou pecu?ria org?nica na renda dos estabelecimentos agropecu?rios recenseados em 2017. A an?lise est? baseada nos dados agregados em escala municipal. Caracteriza-se regionalmente a presen?a da produ??o org?nica por meio de tabelas de conting?ncia, via qui-quadrado e an?lise de covari?ncia, tomando-se como vari?veis contextuais: regi?es, classes de renda, ?rea, assist?ncia t?cnica, cooperativismo, alfabetiza??o, cr?dito e ?rea. Ajusta-se, tamb?m, uma fronteira de produ??o estoc?stica que identifica, em n?vel do munic?pio, o efeito de fatores que afetam diretamente a produ??o (renda bruta) e a componente de inefici?ncia t?cnica. O n?mero de estabelecimentos que praticam agricultura e/ou pecu?ria org?nica diminuiu de 90.498 (em 2006) para 64.690 (em 2017). A predomin?ncia de agricultura org?nica est? no Sudeste e a menor propor??o est? no Centro-Oeste. A classe de renda bruta predominante para os estabelecimentos que praticam pe', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce7b', NULL, 'English', 'published', false, false, 'open', 'pdf')
