INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce7d', 'Economia no cultivo protegido de alface org?nica com o uso de mudas desenvolvidas', 'Ara?jo Neto, Sebasti?o Elviro de; Souza, Lu?s Gustavo de Souza e; Tomio, Denis Borges; Ferreira, Regina L?cia Felix', 'Editora Verde', 'Agriculture', 'Agriculture', 'O objetivo deste trabalho foi realizar an?lise econ?mica do uso de ambientes protegidos e diferentes volumes de recipientes no cultivo de alface em sistema de produ??o org?nica. Os experimentos foram realizados em dois ambientes protegidos: estufa coberta com polietileno e aberta nas laterais e estufa coberta com polietileno fechada nas laterais com tela anti-inseto em ambos, o delineamento experimental foi em blocos casualizados com cinco tratamentos (volumes de recipientes): 70, 160, 250, 340 e 430 cm?. Para avaliar a an?lise econ?mica, utilizaram-se a produtividade e os custos para cada m? de cultivo e considerado o pre?o local para os respectivos produtos e insumos no ?ltimo trimestre de 2017, considerando 3% de custo de administra??o, 6% de custo de oportunidade, deprecia??o da infraestrutura e custos da terra. Houve lucro acima da remunera??o m?nima (6% a.a.), em todos os tratamentos, exceto aquele com recipiente de 70 cm? em estufa com tela anti-inseto, em estufa sem tela anti-i', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce7d', NULL, 'English', 'published', false, false, 'open', 'pdf')
