INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce7e', 'Supera??o de dorm?ncia em sementes da Cassia grandis L. f. (Fabaceae)', 'Nascimento, Sandro Ferreira do; Nascimento, Ednaldo Vieira do; Farias, Ivina Beatriz Menezes; Lucena, Eliseu Marl?nio Pereira de; Sousa, Let?cia Holanda de; Bonilla, Oriel Herrera', 'Editora Verde', 'Agriculture', 'Agriculture', 'Estudos sobre tecnologia de sementes fundamentam-se na an?lise de temperaturas e m?todos pr?-germinativos; ? preciso aprimorar os que se mostram mais eficientes, otimizando tempo e recursos. A dorm?ncia ? um processo de distribui??o da germina??o das sementes no tempo e no espa?o. A Cassia grandis L. f., esp?cie arb?rea, pertencente ? fam?lia Fabaceae, possui import?ncia ambiental e socioecon?mica. O objetivo deste trabalho foi superar a dorm?ncia de sementes de C. grandis, atrav?s de diferentes m?todos. As sementes foram submetidas aos tratamentos de escarifica??o mec?nica, qu?mica e testemunha; germinadas nas temperaturas de 25 e de 30 ?C. O delineamento experimental adotado, foi do tipo inteiramente casualizado, com quatro repeti??es, fatorial 3x2 e 24 parcelas. Avaliou-se: porcentagem e ?ndice de velocidade de germina??o, comprimento e massa fresca e seca de rad?cula, hipoc?tilo e pl?ntula. As sementes de C. grandis possuem dorm?ncia f?sica, sendo os m?todos mais eficientes de supe', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce7e', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce83', 'Larva de Rhynchophorus palmarum L. (Coleoptera: Curculionidae): Efecto de la dieta en la s?ntesis de ?cidos grasos esenciales', 'Maceda Santiva?ez, Julio Cesar; Cha?i Paucar, Larry Oscar', 'Editora Verde', 'Agriculture', 'Agriculture', 'Los insectos son fuente importante de prote?nas, vitaminas, amino?cidos, minerales y l?pidos. En ese contexto el presente estudio, evalu? el perfil de ?cidos grasos esenciales del aceite de larva de Rhynchophorus palmarum (Coleoptera: Curculionidae) sometida a tres dietas de tejidos vegetales: Mauritia flexuosa (Arecaceae), Oenocarpus bataua (Arecaceae) y Jacaratia digitata (Caricaceae). Fueron capturados cinco individuos adultos, 2 machos y 3 hembras para su reproducci?n en cautiverio. Las larvas eclosionadas se sometieron a las tres dietas por 45 d?as. Despu?s de este periodo se efectu? la extracci?n y se determin? el perfil de ?cidos grasos del aceite. Siendo el ?cido graso monoinsaturado oleico (18:1) y el ?cido graso saturado palm?tico (16:0), los que se encuentran en mayor abundancia para las tres dietas. Respecto a los ?cidos grasos esenciales, fueron detectados los ?cidos grasos linoleico (18:2) y alpha linol?nico (18:3) en concentraciones de 1,96 ? 0,028 y 1,14 ? 0,007%, para ', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce83', NULL, 'English', 'published', false, false, 'open', 'pdf')
