INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce84', 'Irriga??o com ?gua salina e uso de biofertilizante bovino no crescimento e nas trocas gasosas de feij?o-de-corda', 'Cruz Filho, Elizeu Matos da; Santos, Max Ferreira dos; Sousa, Geocleber Gomes de; Barbosa, Andreza Silva; Ribeiro, Rute Maria Rocha; Magalh?es, Clarissa Lima', 'Editora Verde', 'Agriculture', 'Agriculture', 'O biofertilizante pode atenuar o efeito do estresse salino no crescimento inicial e na fisiologia do feij?o-caupi (Vigna unguiculata). O objetivo deste trabalho foi avaliar o efeito do biofertilizante bovino no crescimento inicial e trocas gasosas de plantas de feij?o-caupi irrigadas com ?gua salina. O experimento foi conduzido em condi??o de campo na Horta Did?tica do campus da Liberdade na Universidade da Integra??o Internacional da Lusofonia Afro-Brasileira, Reden??o, Cear?. A cultivar ?BRS Tumucumaque? foi utilizada no experimento, sendo semeada em vasos pl?sticos de 8 litros, em delineamento de blocos ao acaso sob esquema fatorial 5x2, com quatro repeti??es, sendo o primeiro fator composto por cinco concentra??es de biofertilizantes (5, 10, 15, 20 e 25% do volume do vaso e o segundo fator composto pela condutividade el?trica da ?gua de irriga??o (CEa: 0,5 e 5,0 dS m-1). A ?rea foliar, n?mero de folhas, di?metro do caule, altura das plantas, condut?ncia estom?tica, taxa de fotoss?n', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce84', NULL, 'English', 'published', false, false, 'open', 'pdf')
