INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce88', 'Releitura de p?o de queijo: Vers?o vegetariana com farinha de oliveira', 'Menezes, Rafaella C?mara Rocha; Santos, Carolina Dias dos; Dal Bosco, Simone Morelo', 'Editora Verde', 'Agriculture', 'Agriculture', 'A oliveira (Olea europaea L.) ? composta por folhas que podem ser consumidas, mas costumam ser descartadas pela colheita mecanizada. Uma alternativa para viabilizar o descarte das folhas de oliveiras, ? elaborar a farinha de folha de oliveira (FFO) realizando o aproveitamento. Com isso, o objetivo desta pesquisa foi elaborar um p?o de queijo vegetariano adicionado de farinha da folha de oliveira a fim de viabilizar uma nova alternativa de aproveitamento tecnol?gico desse res?duo. Foram desenvolvidas cinco formula??es de p?es de queijo, alterando-se a quantidade de farinha das folhas de oliveira adicionada (0,95 ? 2,85%) e submetidas a avalia??o das caracter?sticas sensoriais pelo m?todo de An?lise Descritiva Quantitativa. Os resultados demonstraram que, dentre os quinze atributos avaliados, os sabores herb?ceo, amargo e de queijo juntamente com o aroma herb?ceo apresentaram diferen?a significativa. Entre os atributos analisados, a FFO contribuiu para o maior sabor amargo dos p?es de qu', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce88', NULL, 'English', 'published', false, false, 'open', 'pdf')
