INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce92', 'Taxa de decomposi??o foliar de esp?cies utilizadas em sistemas agroflorestais', 'Rode, Rafael; Leal de Sousa, Iara Rayana; Pauletto, Daniela; Lopes, Lucas S?rgio de Sousa; Peleja, Vanessa Le?o; Freitas, Bruna Bandeira de', 'Editora Verde', 'Agriculture', 'Agriculture', 'Os sistemas agroflorestais (SAFs) promovem a sustentabilidade do agroecossistema atrav?s das intera??es energ?ticas e da ciclagem de nutrientes por meio da produ??o e decomposi??o de biomassa sobre o solo. O objetivo deste trabalho foi avaliar a decomposi??o foliar de esp?cies utilizadas na aduba??o verde e de interesse econ?mico em sistemas agroflorestais. O estudo foi realizado no SAF experimental da Universidade Federal do Oeste do Par? (UFOPA). Analisou-se a decomposi??o foliar de seis esp?cies, sendo cacau (Theobroma cacao L.), cumaru (Dipteryx odorata (Aubl.) Forsyth) e pimenta-do-reino (Piper nigrum L.) consideradas de interesse econ?mico e feij?o-de-porco (Canavalia ensiformis (L.) DC.), gliric?dia (Gliricidia sepium (Jacq.) Walp.) e guand? (Cajanus cajan (L.) Huth) consideradas esp?cies de aduba??o verde. Para acompanhar a decomposi??o, utilizou-se o m?todo de litter bags com o experimento alocado nos per?odos mais chuvoso e menos chuvoso. Os dados de massa foliar remanescente', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce92', NULL, 'English', 'published', false, false, 'open', 'pdf')
