INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce99', 'Diagn?stico ambiental em trechos do alto Rio Paje?, Itapetim, Pernambuco: contribui??es educativas ao desenvolvimento sustent?vel', 'Sousa R?go, Veneziano Guedes de; Almeida, Severina Val?ria Gon?alves de; Medeiros, Felipe Silva de; Farias, Soahd Arruda Rached; Oliveira, Davi Argemiro Henrique Cardoso de; Lima, Joedla Rodrigues de', 'Editora Verde', 'Agriculture', 'Agriculture', 'A deteriora??o ambiental amea?a ? biodiversidade, os recursos naturais, o bem-estar populacional e consequentemente os servi?os que os ecossistemas podem oferecer. O presente trabalho teve por objetivo avaliar o grau de deteriora??o ambiental em trechos do alto Rio Paje? no munic?pio de Itapetim, Pernambuco, sugerindo medidas corretivas ? ambi?ncia deteriorada. A coleta de dados foi realizada por meio de visitas ?in loco? e entrevistas aos produtores rurais utilizando-se o question?rio do Diagn?stico Ambiental (Fator ambiental + Fator prioridade). A deteriora??o ambiental foi de 13% devido o uso ecologicamente inadequado dos recursos naturais. As principais prioridades relatadas foram baixa produtividade, falta de assist?ncia m?dica e odontol?gica e problemas relacionados ? disponibilidade de ?gua. Como progn?stico geral ? sugerido o incentivo de pol?ticas p?blicas voltadas para as associa??es rurais como forma de inserir pr?ticas adequadas de manejo de bacia hidrogr?fica e a??es de ed', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce99', NULL, 'English', 'published', false, false, 'open', 'pdf')
