INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce9f', 'Efeito do extrato de tiririca no enraizamento de estacas de lim?o-Tahiti', 'Costa, Antonio Cesar; Fernandes, Guilherme Henrique; Abes, Sara da Silva; Santos, Jo?o Paulo Gomes dos; Bardiviesso, Di?genes Martins; Rodrigues, Daniel Henrique Santana', 'Editora Verde', 'Agriculture', 'Agriculture', 'O tratamento de estacas com extrato de tiririca (Cyperus rotundus L.) tem sido recomendado como alternativa para estimular o enraizamento de v?rias esp?cies, devido sua efici?ncia e baixo custo, contudo, pesquisas envolvendo m?todos alternativos para estimular o enraizamento de estacas de lim?o-Tahiti (Citrus latif?lia Tanaka) s?o escassas. Portanto, o objetivo foi avaliar os efeitos de uma t?cnica alternativa de propaga??o de mudas de estacas de lim?o-Tahiti por meio de enraizamento, com o uso de extrato de tiririca. O delineamento experimental utilizado foi de blocos ao acaso, com cinco tratamentos e quatro repeti??es. Os tratamentos foram compostos por testemunha (estacas tratadas com ?gua destilada) e tratamento de estacas com quatro extratos de tiririca, nas concentra??es de: 75 g/L (25%), 150 g/L (50%), 225 g/L (75%) e 300 g/L (100%). Cada unidade experimental foi constitu?da por seis estacas. As avalia??es foram realizadas 90 dias ap?s o plantio, sendo mensurados os seguintes pa', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce9f', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1cea0', 'Conhecimento de plantas aliment?cias n?o convencionais em assentamentos rurais', 'Ferreira, Bruna Pereira; Terra, Simone Braga', 'Editora Verde', 'Agriculture', 'Agriculture', 'Plantas aliment?cias n?o convencionais (PANC) refere-se a todas as plantas que possuem uma ou mais partes comest?veis para humanos, sendo espont?neas ou cultivadas, nativas ou ex?ticas, que n?o est?o inclu?das em nosso card?pio cotidiano. Agricultores familiares, ao terem consci?ncia do potencial dessas plantas aliment?cias, podem diversificar sua alimenta??o habitual e cultiv?-las aproveitando ?reas improdutivas ou de baixa fertilidade. Com isso, objetivou-se avaliar o n?vel de conhecimento de agricultores moradores em assentamentos rurais sobre as PANC, identificando as esp?cies presentes nos locais estudados. A pesquisa foi realizada entre mar?o e junho de 2019 em tr?s assentamentos da reforma agr?ria de Santana do Livramento, Rio Grade do Sul, com 15 informantes-chave, utilizando como metodologia a amostragem tipo bola de neve. Perguntas pr?-elaboradas foram respondidas pelos agricultores assentados durante o m?todo da turn? guiada. Como resultados, foram identificadas 20 esp?cies ', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1cea0', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1cea3', 'Uso de agentes aderentes na peletiza??o de sementes de milho crioulo com p? de rocha', 'Melo, Luan Danilo Ferreira de Andrade; Silva, La?s Gonzaga da; Ramos, Marcus Gabriel de Carvalho; Berto, Tha?se dos Santos; Melo Junior, Jo?o Luciano de Andrade; Crisostomo, Nat?lia Marinho Silva', 'Editora Verde', 'Agriculture', 'Agriculture', 'O milho (Zea mays L.) ? um dos gr?os mais plantados no mundo, tendo um papel consider?vel na economia por expressar elevado valor comercial. A peletiza??o de sementes vem se tornando uma tecnologia crescente e pr?spera, pois acrescenta valor ?s sementes e contribui para um mercado cada vez mais rigoroso e competitivo. Dessa forma, o trabalho teve como objetivo avaliar o efeito de diferentes agentes aderentes na peletiza??o e potencial fisiol?gico de sementes de milho crioulo. O trabalho foi conduzido no Laborat?rio de Propaga??o de Plantas pertencente ao Campus de Engenhria e Ci?ncias Agr?rias da Universidade Federal de Alagoas. Como agentes aderentes foram utilizados: ?gua, babosa, cola ? base de acetato de polivinila (PVA), extrato de mandacaru, extrato de palma e goma de mandioca. No revestimento utilizou-se o p? de rocha (MB-4). Os par?metros avaliados foram: teor de ?gua, peso de mil sementes, primeira contagem de germina??o, germina??o, ?ndice de velocidade de germina??o, tempo m', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1cea3', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1cea8', 'Circuitos cortos de comercializaci?n de alimentos agroecol?gicos en Quito, Ecuador: Cooperativa Sur Siendo Redes y Sabores', 'Piedra, Andrea Carolina Castillo', 'Editora Verde', 'Agriculture', 'Agriculture', 'El estudio presenta las relaciones de equidad entre el campo y la ciudad que han creado los consumidores responsables de la cooperativa Sur Siendo Redes y Sabores. La cooperativa ha generado espacios de mercado a productos agroecol?gicos para una poblaci?n de estratos sociales populares que hist?ricamente vive en un ambiente alimentario poco accesible. Mediante el an?lisis socio espacial de los circuitos cortos de comercializaci?n de alimentos agroecol?gicos se identific? que los consumidores responsables de esta cooperativa crearon cinco ferias y una biotienda. Generando comercio justo en la ciudad de Quito con la venta de productos agroecol?gicos de los territorios rurales de Pedro Moncayo.', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1cea8', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ceaa', 'Functionalization of SBA-15 with EDTA and its application in removing Ca2+ and Mg2+ ions from hard water', 'Leite, Ricardo Henrique de Lima; Santos, Franciso Klebson Gomes; Marques, Vanessa da Silva Bezerra; Santos, Andarair Gomes dos', 'Editora Verde', 'Agriculture', 'Agriculture', 'Poor management, changes in drinking parameters and drought subject many parts of the world to survival in the face of shortages of drinking water and the quality of drinking water needs to be assessed for adequate consumption. Hard water can lead to the buildup of mineral deposits in pipes and appliances that use water on a regular basis, affecting the performance and life cycle of these items. In addition, in the presence of soap, fatty acids formed an insoluble precipitate with calcium ions, making foam and cleaning difficult, as well as other problems generated by the high content of Ca2+ and Mg2+ ions present in water. The goal of this paper was to study the removal of Ca2+ and Mg2+ ions using SBA-15, a mesoporous material, functionalized with ethylenediaminetetraacetic acid and compared to its pure matrix. This adsorbent was tested in Ca2+ and Mg2+ ions solution with concentration of 250 mg.L-1 and pH = 9, varying the temperature in 25?C and 50?C. Mesoporous materials were synthe', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ceaa', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ceac', 'Pl?ntulas de gergelim cv. BRS seda sob aplica??o de ?gua salinizada', 'Tavares, Austro Jos? Faustino; Andrade, Kyonelly Queila Duarte Brito; Nascimento, Ronaldo do; Sobrinho, Thiago Galv?o; Cord?o, Mailson Araujo', 'Editora Verde', 'Agriculture', 'Agriculture', 'O gergelim ? uma importante cultura oleaginosa e aliment?cia, bem adaptada ?s condi??es da regi?o semi?rida, na qual o problema da salinidade ? comum. Assim, objetivou-se com este estudo avaliar a germina??o e o crescimento das pl?ntulas de gergelim submetidas ao estresse salino. Os tratamentos foram arranjados em delineamento inteiramente casualizado, aplicando cinco tratamentos, sendo os n?veis de sais correspondente ?s condutividades el?tricas da ?gua (0,6; 1,2; 1,8; 2,4 e 3,0 dS m-1) na cultivar de gergelim BRS seda, distribu?dos em quatro repeti??es, totalizando 20 unidades experimentais. As vari?veis analisadas foram ? porcentagem, a primeira contagem, o ?ndice de velocidade, o tempo m?dio de germina??o, e as vari?veis de crescimento das pl?ntulas: comprimento total da pl?ntula, do hipoc?tilo, da rad?cula prim?ria, vigor e a massa fresca total da parte ?rea e da rad?cula prim?ria. Os resultados obtidos denotam que o aumento da salinidade na ?gua ocasiona redu??o na germina??o e n', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ceac', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ceae', 'Microbiologia da ?gua de po?os semiartesianos da zona rural de Aparecida D?Oeste, S?o Paulo', 'Frias, Danila Fernanda Rodrigues; Oliveira, Luciano Ricardo de; Kozusny-Andreani, Dora In?s; Correa, Glauder; Am?rico-Pinheiro, Juliana Heloisa Pin?', 'Editora Verde', 'Agriculture', 'Agriculture', 'A qualidade e inocuidade da ?gua s?o fatores importantes para a sa?de p?blica, pois a mesma pode servir como veiculadora de pat?genos que causam diversas enfermidades nos seres humanos e animais. O objetivo da pesquisa foi avaliar a qualidade microbiol?gica da ?gua de po?os semiartesianos da zona rural de Aparecida D?Oeste, S?o Paulo, verificando os principais fatores associados ? sua contamina??o. O estudo foi realizado em 50 propriedades rurais. As amostras foram coletadas em frasco de vidro com tampa est?ril de 1000 mL est?ril, na v?lvula de sa?da do po?o, ap?s pr?vio bombeamento de 10 minutos. As amostras foram submetidas ? determina??o do n?mero mais prov?vel de coliformes totais, coliformes termotolerantes e contagem de microrganismos mes?filos. Para contagem de mes?filos e verifica??o da presen?a de coliformes totais e termotolerantes, utilizou-se ?gar Triptone Soja, Caldo Lauril Sulfato, Caldo Verde Brilhante e ?gar de Levine. As col?nias que n?o foram identificadas como Escher', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ceae', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1b7', 'Características morfométricas e rendimento da palma forrageira ‘Gigante’ sob diferentes adubações e configurações de plantio', 'E. S. Souza; M. C. Padilha Junior; S. L. R. Donato; P. E. R. Donato; J. A. Silva', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Objetivou-se com o presente trabalho avaliar as características morfométricas e de rendimento da palma forrageira ''Gigante'' submetida a diferentes tipos de adubação orgânica, química e organomineral e configurações de plantio. O experimento foi instalado em LATOSSOLO Vermelho-Amarelo distrófico, num delineamento em blocos casualizados, em esquema de parcelas subdivididas, com três repetições. As parcelas constituídas por duas configurações de plantio: 1) 24.0000 plantas ha-1, dispostas em fileira tripla, no espaçamento 3,00 x 1,00 x 0,25 m; 2) 26.666 plantas ha-1, dispostas em fileira quádrupla, no espaçamento 3,00 x 1,00 x 0,25 m; as subparcelas compostas por 12 tipos de adubação orgânica, química e organomineral. Aos 650 DAP mensuraram-se altura da planta, número, comprimento, largura e índice de área de cladódios, produção de matéria verde e seca e teor de matéria seca. As características morfométricas, o teor de matéria seca e a produção de massa verde e matéria seca foram influenc', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3710', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1b8', 'Efeito de diferentes tratamentos de polinização em berinjela em casa de vegetação', 'M. A. Silva; M. Hrncir; F. A. Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho objetivou avaliar a influência de diferentes tipos de polinização na quantidade e qualidade de berinjela (Solanum melongena) cultivada em casa de vegetação. A pesquisa foi realizada em uma casa de vegetação localizada na Universidade Federal Rural do Semiárido (UFERSA), Mossoró/RN. Foram utilizadas duas colônias de Scaptotrigona sp. Para verificar os requerimentos de polinização foram realizados quatro tratamentos: polinização livre, autopolinização, polinização manual por vibração e polinização cruzada manual, comparando a quantidade e qualidade dos frutos obtidos de cada tratamento, como peso, comprimento, circunferência e número de sementes produzidas. O tratamento de polinização cruzada manual (PCM) apresentou os maiores valores em relação a número de frutos produzidos (26,67%) e com maior número de sementes (1º corte: 3,2 ± 10,12; 2º corte: 26,7 ± 27,91; 3º corte: 103,4 ± 21,79) quando comparados com os demais tratamentos, entretanto o peso, comprimento e circu', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3771', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1b9', 'Influência da profundidade e posição de semeadura na emergência de Acacia polyphylla DC.', 'L. M. Oliveira; A. C. F. Portella; E. M. C. Batista; P. B. Souza; A. J. Rodrigues', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A Acacia polyphylla DC. é uma leguminosa, pertencente à família Fabaceae, conhecida principalmente por monjoleiro, cuja árvore apresenta porte médio e rápido crescimento, a mesma enquadra-se em estágios iniciais da sucessão secundária com grande potencial para o uso na recuperação de áreas degradadas do Bioma Cerrado. Assim, objetivou-se avaliar a influência de diferentes posições e de profundidades de semeadura na emergência e crescimento inicial de plântulas de Acacia polyphylla DC. O experimento foi realizado em delineamento inteiramente casualisado, com quatro repetições de 25 sementes, dispostos em esquema fatorial 3 x 5 (posições e profundidades de semeadura). Os tratamentos consistiram em diferentes posições das sementes no substrato: hilo voltado para cima, hilo voltado para baixo e sementes na horizontal, nas profundidades de 1, 2, 3, 4 e 5 cm. Determinou-se a porcentagem de emergência, índice de velocidade de emergência, bem como o comprimento e a massa seca da parte aérea e ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3812', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1bc', 'Diagnóstico ambiental no córrego Bacaba, Talismã - TO', 'A. R. Mota; M. O. Camargo; P. B. Souza; A. F. Santos; P. A. Souza', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente estudo teve como objetivo avaliar os aspectos e impactos ambientais na mata ciliar do córrego Bacaba, localizada no município de Talismã -TO. O diagnóstico foi feito através de visita in loco e com registro fotográfico das características da degradação, para analise quantitativa dos impactos utilizou-se uma matriz de aspectos e impactos. Os principais problemas encontrados foram à inexistência da mata ciliar nas duas margens do córrego, o transporte de sedimentos do solo para a calha, a compactação da camada superficial do solo, afugentamento da fauna local, surgimento de ravinas e voçorocas de erosão e afugentamento da fauna local. As causas desses impactos são devido à intensificação da agropecuária juntamente com manejo inadequado do solo necessitando de medidas mitigatórias urgentes como isolamento da área e plantio de mudas nativas onde a área foi degradada.Environmental diagnosis stream Bacaba, Talisman - TOAbstract: This study aimed to assess the environmental aspects', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3893', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1c3', 'Gerenciamento de resíduos sólidos urbanos: um estudo de caso em uma escola estadual de ensino médio em Pombal-PB', 'E. P. Sousa; J. C. F. Sales; S. O. Andrade; J. D. Fernandes; D. L. Crispim', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Diversas cidades brasileiras apresentam dificuldades relacionadas à gestão de resíduos sólidos, em especial na coleta, transporte, tratamento e no destino final de resíduos. A deficiência na gestão dos resíduos sólidos permite que práticas inadequadas de disposição final sejam comuns, como a disposição em lugar impróprio. O estudo objetivou verificar o nível de conhecimento dos discentes da Escola E.M.M.V.F. em Pombal, PB, sobre o gerenciamento dos resíduos sólidos urbanos. A pesquisa foi realizada por meio de questionários semiestruturados com perguntas relacionadas ao gerenciamento desta problemática pela população. Os resultados revelaram que 67% dos participantes desta pesquisa não separam o resíduo úmido do resíduo seco, enquanto apenas 33% realizam a separação. Quanto ao destino final do resíduo gerado nas residências, 88% dos moradores expuseram que é depositado em vazadouro a céu aberto (lixão). Para amenizar o cenário que cerca a gestão dos resíduos sólidos urbanos é fundament', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3947', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1c4', 'Percepção ambiental do corpo docente e discente da modalidade EJA de uma escola estadual no município de Pombal-PB', 'E. P. Sousa; S. O. Andrade; A. V. M. Francelino; D. L. Crispim; A. G. Lima', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A educação é um processo que abrange dimensões humanas, técnicas e político-social e seu desafio consiste em construir uma dinâmica articulada nos contextos políticos e sociais. Dentro deste contexto está a Educação Ambiental cujo intuito é explanar aos alunos a importância do meio ambiente que estamos inseridos e desenvolver práticas sustentáveis. Portanto, a presente pesquisa objetivou investigar o nível de percepção ambiental dos professores e alunos da modalidade EJA (Educação de jovens e adultos) da Escola Estadual de Ensino Médio Monsenhor Vicente Freitas, município de Pombal-PB e suas relações com o meio ambiente. O trabalho foi desenvolvido no período de julho a novembro de 2015. Foram aplicados questionários com os professores e alunos que se enquadram na modalidade em estudo. Os alunos apresentaram boa noção em relação ao conceito de meio ambiente e dos seus elementos. Em virtude da grave crise hídrica vivida na região Nordeste brasileira, o tema de maior interesse observado,', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3974', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1ca', 'Aspectos fisiológicos do feijão-caupi e crescimento de tiririca (Cyperus rotundus L.) sob competição em solo compactado', 'U. C. M. Pessôa; A. S. Souza; E. N. Silva Terceiro; A. A. Soares Filho; T. A. Pimenta', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Vários fatores estão envolvidos na interferência das plantas daninhas sobre as culturas e os aspectos fisiológicos ainda são pouco estudados. Assim, objetivou-se avaliar a interferência de diferentes populações de Cyperus rotundus L. e da compactação do solo nos caracteres fisiológicos do feijão-caupi [Vigna unguiculata (L.) Walp] e na fenologia de C. rotundus. O experimento foi realizado em casa de vegetação no Centro de Ciências e Tecnologia Agroalimentar da Universidade Federal de Campina Grande, CCTA/UFCG, Campus de Pombal-PB. As unidades experimentais foram compostas por vasos com capacidade de 6 litros. Utilizou-se o delineamento inteiramente casualizado com tratamentos distribuídos em esquema fatorial 3 x 2, sendo os fatores três populações de C. rotundus (0, 2 e 3 tubérculos por vaso) e dois níveis de compactação (solo sem compactação e solo com subsuperfície compactada artificialmente), com quatro repetições. Foram coletados os dados de: taxa de assimilação de CO2 (µmol m-2 s-', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4069', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1cb', 'Propriedades funcionais da semente do sorgo (Sorghum bicolor (L.) Moench) in natura e germinado', 'M. C. Gonçalves; M. T. Cavalcanti; D. D. F. Leite; A. S. Silva; M. C. B. M. Almeida', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A utilização de sementes germinadas na elaboração de produtos alimentícios com boa qualidade nutricional é uma possibilidade e o sorgo pode se apresentar como alternativa ao consumo dos cereais convencionais. O objetivo deste estudo foi de observar as alterações nos parâmetros físico-químicos da semente de sorgo antes e após o processo de germinação, assim como avaliar as propriedades funcionais indicando suas possíveis utilizações como ingrediente alimentar. As sementes germinadas apresentaram um aumento no teor proteico, passando de 4,32 para 7,20%, além da diminuição no teor de amido e consequente aumento no teor de açúcares redutores. A partir das propriedades funcionais avaliadas, a semente de sorgo germinada apresentou uma boa capacidade de absorção de óleo, podendo ser utilizado como ingrediente para auxiliar na textura e suculência de produtos. A germinação garantiu boa capacidade de formação de espuma e sua estabilidade, podendo ser utilizado como ingrediente em produtos alime', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4076', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d2', 'Desempenho econômico do consórcio de coentro com beterraba, adubados com doses de jitirana, combinada com esterco bovino', 'W. B. Ramalho; P. B. Maracajá; A. M. B. Almeida; P. C. F. Linhares; A. P. Morais', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A análise econômica ajuda a interpretar os resultados obtidos nos diferentes sistemas de cultivo e deve ser empregada indicando o que e como plantar, de maneira a gerar lucro ao produtor. A utilização da mistura de adubos orgânicos constitui-se em alternativa para os agricultores que produzem em sistema agroecológico, pois contribui para a redução dos custos de produção e maior eficiência no uso dos insumos disponíveis na área. Diante do exposto, objetivou-se avaliar o desempenho econômico do consórcio de coentro com beterraba, adubados com doses de jitirana, combinada com esterco bovino. O experimento foi conduzido na Fazenda Experimental Rafael Fernandes, distrito de Alagoinha, zona rural de Mossoró – RN, no período de setembro a dezembro de 2014. O delineamento experimental utilizado foi de blocos completos casualizados com os tratamentos arranjados em esquema fatorial 2 x 5, com três repetições. O primeiro fator foi constituído pelo cultivo solteiro e consorciado do coentro e da be', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4497', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d3', 'Acúmulo, deposição e decomposição de serrapilheira sob a dinâmica vegetacional da Caatinga em Unidade de Conservação', 'P. C. Souto; W. S. Santos; T. S. Lima; I. G. N. Henriques; J. S. Souto; Í. G. N. Henriques', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A ciclagem de nutrientes é essencial para a manutenção da produtividade dos ecossistemas florestais, principalmente sobre solos de baixa fertilidade e fortemente intemperizados. Apesar da existência de trabalhos de acúmulo e deposição de serrapilheira da vegetação da Caatinga, ainda falta muito para o conhecimento da dinâmica desse bioma. O presente trabalho teve por objetivo, avaliar o acúmulo, deposição e decomposição de serrapilheira, a fim de obter informações sobre a dinâmica das espécies vegetais de uma Reserva Particular do Patrimônio Natural no bioma Caatinga, no Estado da Paraíba, para propiciar futuros estudos no tocante a ciclagem de nutrientes e, avaliar a interferência da precipitação pluviométrica na sazonalidade destes eventos. Para se obter a produção de serrapilheira 20 coletores de 1,0 m x 1,0 m, com fundo da tela de náilon. Coletada mensalmente, a serrapilheira foi separada nas frações folhas, galhos, material reprodutivo e miscelânea, sendo as frações secas em estuf', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4523', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d6', 'Ora-pro-nóbis em uso alimentar humano: percepção sensorial', 'Luciany Braga de Paiva Gomes; Laís Ferreira; Carla Regina Amorim dos Anjos Queiroz; Reginaldo Rodrigues de Andrade; Cláudia Maria Tomás Melo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O governo brasileiro incentiva o consumo de hortaliças não convencionais, como forma de aproveitamento da biodiversidade brasileira e suprimento de necessidades nutricionais de forma viável a população, principalmente a de baixa renda. A Ora-pro-nóbis (Pereskia aculeata Miller) é uma hortaliça nativa brasileira que se propaga facilmente, cujo cultivo apresenta baixa incidência de doenças e de demanda hídrica. É viável para o cultivo doméstico, como fonte nutricional alternativa e de baixo custo, sendo uma hortaliça recomendada para o consumo diário na alimentação, nas formas crua e/ou processada. Neste trabalho, buscou-se ampliar o uso o e cultivo da Ora-pro-nóbis, com a produção e distribuição de mudas em um evento tradicional na Zona Rural de Uberlândia, a Semana da Família Rural, em sua 26ª edição, no Instituto Federal do Triângulo Mineiro – Campus Uberlândia. Durante o evento foram distribuídas amostras de alimentos processados com folhas de Ora-pro-nóbis in natura ou previamente s', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3393', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d7', 'Análise da adequação de eventos de precipitação extrema na Amazônia Ocidental em modelos estáticos: Rondônia', 'Marcos Leando Alves Nunes; Ana Lúcia Denardin da Rosa; Vinicius Alexandre Sikora de Souza; Sandra Ferronatto Francener', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este estudo objetivou estimar a função Intensidade-Duração-Frequência (IDF) de eventos pluviométricos extremos a partir dos dados de precipitação das estações pluviométricas instaladas no estado de Rondônia, de modo que posteriormente tais informações possam ser utilizadas no dimensionamento de obras hidráulicas. Utilizou-se 41 estações pluviométricas com séries históricas acima de 10 anos, disponibilizadas pela Agência Nacional de Águas (ANA). Essas séries passaram inicialmente pelo teste de aderência Kolmogorov-Smirnov (KS), a fim de verificar o ajuste das mesmas as distribuições: Normal, Log-Normal, Exponencial, Gama, Gumbel, Weibull e Logística. O trabalho denotou que o teste de aderência Kolmogorov-Smirnov de forma geral forneceu uma expressiva aceitação na maioria das distribuições estatística testadas. Analysis of fitness for extreme rainfall events in western amazon in static models: state Rondônia ABSTRACT: This study aimed to estimate the Intensity - Duration - Frequency (IDF', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2716', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1d8', 'Características físicas, químicas e físico-químicas dos frutos da murta', 'Érllens Eder Silva; Dyalla Ribeiro de Araujo; Rossana Maria Feitosa de Figueirêdo; Eliseu Marlônio Pereira de Lucena; Josivanda Palmeira Gomes', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O presente trabalho teve como objetivo estudar as características físicas, químicas e físico-químicas dos frutos da murta (Eugenia gracillima Kiaersk.) no estádio de maturação “maduro”. Os frutos de murta foram colhidos em área de vegetação nativa, na propriedade rural da família Lermen, localizada na Serra dos Paus Dóias - Chapada do Araripe, município de Exu, PE. Após a colheita, os frutos foram transportados para o Laboratório de Ecofisiologia Vegetal da Universidade Estadual do Ceará, para a realização das análises físicas, químicas e físico-químicas: coloração da casca; diâmetros longitudinal e transversal; massas fresca, seca e de água e teor de água; sólidos solúveis totais (SST), acidez total titulável (ATT), pH, relação SST/ATT, carboidratos (amido, açúcares solúveis totais, açúcares redutores e açúcares não redutores); vitamina C; pectinas; fenólicos; antocianinas; flavonoides amarelos e carotenoides. Os frutos da murta (Eugenia gracillima Kiaersk.) são relativamente pequenos', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3115', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1db', 'Estudo de caso de três espécies de plantas bioindicadoras de solos salinos', 'Mercia Fonseca Carvalho; Gian Carlo Carvalho; Marcus Metri Corrêa; Soraya Giovanetti El-Deir', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Bioindicadores, de uma maneira geral, são seres vivos de natureza diversa, vegetais ou animais, utilizados para analisar a qualidade de um determinado ambiente. A degradação ambiental do solo pela salinidade é um problema muito antigo e de extensão mundial, geralmente, mais pronunciado nas regiões áridas e semi-áridas. As plantas que se desenvolvem em áreas com elevadas concentrações de sais são chamadas de halófitas, e algumas delas são usadas na recuperar desses solos. O objetivo desse trabalho é analisar três espécies de plantas resistentes ao estresse salino gerar recomendações a respeito das mesmas, disponibilizando uma indicação de espécie que possa recuperar o ambiente salinizado. Foram selecionadas aleatoriamente três espécies de plantas resistentes a salinidade Copernicia prunifera, Atriplex nummularia L. e Gossypium hirsutum L, as mesmas foram analisados por uma planilha com características que identificam um bioindicador ideal e em seguida as espécies foram avaliadas de acor', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2883', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1dd', 'Análise espectral e avaliação de índices de vegetação para o mapeamento da caatinga', 'Bernado Barbosa da Silva; Iede de Brito Chaves; Lucia Helena Garofalo Chaves; Eduardo Rodrigues Viana de Lima; Paulo Roberto Megna Francisco', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'A caatinga é um bioma de grande diversidade que cobre a maior parte da área de clima semiárido brasileiro. Várias técnicas já foram utilizadas com o objetivo de determinar quantitativamente e qualitativamente o estado da vegetação a partir de imagens de satélite, e índices de vegetação foram desenvolvidos para auxiliar no mapeamento da vegetação, otimizando parâmetros de medidas espectrais utilizadas com esse fim. Este trabalho teve como objetivo analisar e avaliar índices espectrais (NDVI, SAVI e EVI) para mapear a vegetação de caatinga. Concluiu-se que o melhor índice que se correlaciona com a cobertura vegetal da caatinga foi o Normalized Difference Vegetation Index (NDVI), para o período seco, e o padrão de resposta espectral do período seco diminuiu os confundimentos de alvos de vegetação da caatinga. Estimou-se que 29,7% da área da bacia do rio Taperoá esteja em processo avançado de desertificação. Spectral analysis and evaluation of vegetation indices for mapping caatinga ABSTRA', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3046', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1df', 'Avaliação da compactação do solo por meio de um ensaio oedometrico', 'Francisco Assis de Oliveira; Joaquim Odilon Pereira; Cícero Luiz Câmara Júnior; Joaquim Amaro Filho; Alex Rogerdan Medeiros', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Este trabalho teve o objetivo de avaliar a compactação do solo por meio de um ensaio oedometrico. O estudo foi desenvolvido na fazenda experimental Rafael Fernandes, da UFERSA localizada em Alagoinha, zona rural do município de Mossoró/RN.O experimento foi conduzido  no período de Março de 2012 à Agosto de 2012. Os parâmetros analisados foram densidade do solo, matéria orgânica, índices de vazios estruturais, índice de compressão. O delineamento experimental utilizado foi em blocos casualizados, com três tratamentos e quatro repetições. Os tratamentos foram representados por três profundidades de solo 0,0-0,05m; 0,05-0,10m e 0,10-0,20m. Os resultados evidenciaram que os valores de Matéria orgânica e densidade do solo variaram inversamente. O ensaio oedometrico revelou que o índice de vazios estrutural do solo e reduzido com o aumento da densidade do solo e com o teor de água para uma mesma pressão aplicada. Para o mesmo teor de água o índice de vazios estrutural diminuiu com o aumento ', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/2895', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e0', 'Alterações físico-químicas de geleias de melão e acerola durante o armazenamento', 'N. O. Araújo; C. A de Paiva; R. M.  A. Ferreira; P. S. L. Silva; E. M. M. Aroucha', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'O processamento de polpa e a fabricação de geleias são produtos de interesse para a região nordeste do Brasil. A baixa precipitação e os altos índices de luminosidade anuais, associado ao desenvolvimento da irrigação localizada na região, atraíram grandes empresas nacionais e internacionais para a produção de variados tipos de frutos, incluindo a acerola e o melão. O objetivo do presente trabalho foi avaliar as características físico-químicas de geleia simples e mista (50% de melão e 50% de acerola) de melão e acerola, por ocasião do preparo e após o armazenamento por 30 dias. Utilizou-se o delineamento inteiramente casualizado. O tempo de armazenamento aumentou o teor de sólidos solúveis (SS) e o pH, mas reduziu a acidez titulável e o teor de ácido ascórbico das geleias. A geleia de melão apresentou o maior teor de SS após o armazenamento. E a geleia de acerola obteve valores superiores de pH, acidez titulável e vitamina C, nas duas épocas de análise. Já a geleia mista apresentou pH i', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3495', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b47542a3f9f03b4a1e1', 'Eficiência econômica de cultivares de coentro consorciado com rabanete adubado com jitirana mais esterco bovino', 'Patrício Borges Maracajá; Jéssyca Duarte de Oliveira; Brenna Rafaella Veríssimo dos Santos; Paulo César Ferreira Linhares; Bárbara Bruna Maniçoba Pereira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Dentre as hortaliças cultivadas em sistema consorciado nas áreas de produção familiar, encontra-se o coentro e o rabanete, espécies de ciclo curto (de 30 a 35 dias para o coentro) e (de 25 a 30 dias para o rabanete). Essas espécies são cultivadas na região de Mossoró/RN em sistema orgânico de produção onde se utiliza esterco bovino como adubo. Assim, um experimento foi conduzido na Fazenda Experimental Rafael Fernandes, Mossoró-RN, no período de agosto a outubro de 2014, com o objetivo de avaliar a eficiência econômica de cultivares de coentro consorciado com rabanete adubado com jitirana mais esterco bovino. O trabalho foi conduzido no delineamento de blocos completos casualizados em esquema fatorial 2 x 5, com três repetições. O primeiro fator foi constituído de duas cultivares de coentro (verdão e tabocas) consorciado com rabanete, cultivar Crimsom gigante e o segundo fator pelas doses de jitirana mais esterco bovino (0,0; 1,0; 2,0; 3,0 e 4,0 kg m-2 de canteiro). Utilizou-se a propo', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3559', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b48542a3f9f03b4a2cb', 'Qualidade físico-química de farinhas de genótipos de berinjela (Solanum melongena L.) submetidas ao cultivo orgânico', 'Emmanuel Moreira Pereira; Rosicleide dos Santos da Silva; José Carlos da Costa; Fernando Luiz Nunes Oliveira; Geíza Alves de Azerêdo', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Atrelado ao valor nutricional vem sendo atribuída à berinjela algumas propriedades funcionais, como a capacidade de diminuir o colesterol plasmático e o efeito hipoglicêmico. Por suas características nutricionais, a farinha de berinjela se destaca como um importante ingrediente alimentar, visto que apresenta, em relação à farinha de trigo, maior teor de proteínas, cinzas e fibra alimentar. Dados sobre os efeitos benéficos da berinjela evidenciam a importância do conhecimento detalhado de sua composição química para especificações nutricionais, adequação de dietas e para a ciência de alimentos. Em vista do manejo diferenciado, o cultivo sustentável demanda cultivares bem adaptadas e que proporcionem o melhor rendimento e elevado padrão de qualidade, o que pode interferir na composição dos frutos e, por conseguinte na farinha elaborada a partir destes. Dessa maneira, objetivou-se avaliar as características físico-químicas das farinhas de berinjela de diferentes genótipos sob o sistema de', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/4307', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('64745b49542a3f9f03b4a332', 'Levantamento etnobotânico das espécies vegetais em quintais de bairro na cidade de Mossoró, Rio Grande do Norte', 'Maria de Fatima Barbosa Coelho; Narjara Walessa Nogueira; Caio César Pereira Leal; Rômulo Magno Oliveira de Freitas; Fabrícia Nascimento de Oliveira', 'GRUPO VERDE DE AGROECOLOGIA E ABELHAS', 'Agriculture', 'Agriculture', 'Os quintais são conhecidos por diferentes denominações em vários lugares e podem ser definidos como uma área de produção localizada perto da casa, onde são cultivadas espécies agrícolas e florestais, com a criação de pequenos animais domésticos. O presente trabalho teve como objetivo realizar um levantamento etnobotânico das espécies vegetais existentes nos quintais do bairro Alto Sumaré em Mossoró, Rio Grande do Norte. A seleção de quinze informantes foi feita usando a técnica de bola de neve e a coleta dos dados foi efetuada com observação direta e participante, turnê guiada, e entrevistas semiestruturadas. Foram observadas 65 espécies pertencentes a 38 famílias botânicas. A família com maior número de espécies foi Lamiaceae e as espécies mais frequentes foram Carica papaya L. e Mangifera indica L. Alocasia macrorrhizos (L.) G. Don e Carica papaya L. foram as espécies mais abundantes. Dos entrevistados, 80% declararam utilizar plantas medicinais para tratamentos de doenças e 24 espéc', 'https://www.gvaa.com.br/revista/index.php/RVADS/article/view/3953', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('647470aa425ec3c088f1ce95', 'Caracteriza??o f?sica, f?sico-qu?mica e centesimal do fruto de jatob?-do-cerrado (Hymenaea stigonocarpa Mart.)', 'Barcelos, Samuel Carneiro de; Souza, Pahlevi Augusto de; Almeida, ?rica Jamily do Nascimento; Batista, Elisabeth Mariano; Lemos, L?cia Mara dos Reis; Silva, Edilene Ferreira da', 'Editora Verde', 'Agriculture', 'Agriculture', 'Dentre as esp?cies nativas do Cerrado est? o jatob?, uma leguminosa arb?rea que possui um fruto, em que sua polpa farin?cea apresenta forte potencial para o enriquecimento de prepara??es. Objetivou-se avaliar as caracter?sticas f?sicas do fruto de jatob?-do-cerrado (Hymenaea stigonocarpa Mart.), e as caracter?sticas f?sico-qu?micas e composi??o centesimal na polpa, semente e casca do fruto. A polpa do jatob? foi homogeneizada e denominada de Farinha da Polpa (FP). As sementes e as cascas do jatob? foram maceradas e reduzidas e, em seguida, foram trituradas em liquidificador industrial, obtendo-se as farinhas denominadas de Farinha da Semente (FS) e Farinha da Casca (FC). Foi avaliado as vari?veis biom?tricas das sementes e dos frutos do jatob?. Os resultados obtidos validam a possibilidade da FP e FS serem utilizadas como ingrediente no enriquecimento proteico de alimentos, por apresentar quantidade expressiva desse componente. Al?m disso, a FP e FC apresentaram potencial de aplica??o ', 'https://agris.fao.org/search/en/records/647470aa425ec3c088f1ce95', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4ba8', 'Exploring stingless bees and meliponiculture in Nepal', 'Kafle, Nischal; Giri, Avishek; Bhattarai, Abhishek; Dhakal, Astha; Shrestha, Aavash', 'Grupo Verde de Agroecologia e Abelhas - Editora Verde', 'Agriculture', 'Agriculture', 'Stingless bees are crucial pollinators with significant cultural and ecological roles. They are essential for the pollination of various plants, contributing to biodiversity and the health of ecosystems. These bees also play a vital role in sustaining agricultural productivity by enhancing crop yields through their pollination services. Meliponiculture, the practice of keeping stingless bees for honey production and pollination, presents a viable livelihood option for rural communities, offering economic benefits and promoting sustainable agricultural practices. Despite their importance, stingless bees have been relatively understudied, and their unique biological traits, nesting behavior, and ecological roles remain underexplored. The lack of research has led to an absence of specific policies addressing their conservation or management in Nepal. This gap in policy and knowledge hampers efforts to protect these essential pollinators and their habitats. Effective conservation strategie', 'https://www.gvaa.com.br/revista/index.php/APB/article/view/10944', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4ba9', 'Castanha-do-brasil com casca: Mercado mundial e taxas de crescimento', 'Araújo Aragão, Adalberto; Gazzola, Rosaura; GONÇALVES GOMES, ELIANE; Cabral de Sousa Dias, José Manuel', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/11040', NULL, 'English', 'published', false, false, 'open', 'pdf')
