INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4baa', 'AMÊNDOA DA CASTANHA-DO-BRASIL (Bertholletia excelsa): COMÉRCIO INTERNACIONAL', 'Cabral de Sousa Dias, JOSE MANUEL; Gazzola, Rosaura; GONÇALVES GOMES, ELIANE', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', '', 'https://www.gvaa.com.br/revista/index.php/REBAGRO/article/view/11324', NULL, 'English', 'published', false, false, 'open', 'pdf')
