INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6800e600e329785f954b4bb2', 'A MOBILIDADE URBANA SOB A PERSPECTIVA DOS DESAFIOS E PERSPECTIVAS DO TRANSPORTE PÚBLICO EM SOUSA', 'Marques, Jacyara Farias Souza; Bezerra Neto, Francisco das Chagas; Lucas, Olenice Galvão', 'Editora Verde', 'Agriculture', 'Agriculture', 'O presente estudo teve como objetivo analisar a implementação da Política Nacional de Mobilidade Urbana e seus impactos na população local, com ênfase na disparidade entre as diretrizes legais e a realidade enfrentada por municípios de menor porte, a exemplo de Sousa, no Estado da Paraíba. Apesar de sua importância regional e de uma população de aproximadamente 68 mil habitantes, o município enfrenta desafios expressivos na oferta e manutenção de um sistema de transporte público eficiente. A pesquisa adotou uma abordagem metodológica indutiva, combinando técnicas qualitativas e quantitativas, por meio da análise de dados estatísticos, revisão bibliográfica e documental, além de uma investigação empírica, que incluiu entrevistas com usuários e gestores do transporte municipal antes do período pandêmico. Nesse contexto, o estudo também buscou estabelecer a relação entre o direito constitucional à locomoção e a necessidade de um transporte público urbano adequado, evidenciando as lacunas ', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11307', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6878b64e0868163a2f74de64', 'A importância do saneamento básico para a saúde pública: uma revisão de literatura', 'Batista, José de Carlos; Linhares, Paulo Robson Parente; Silva, Cleber Santana de Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O saneamento básico é um dos principais determinantes sociais da saúde, influenciando diretamente a qualidade de vida e o desenvolvimento humano. Este artigo tem como objetivo revisar a literatura científica sobre os impactos do saneamento básico na saúde pública, na economia e na sociedade, bem como discutir os desafios relacionados à universalização desses serviços. A metodologia adotada foi uma revisão bibliográfica, utilizando artigos publicados entre 2013 e 2023 em bases como Google Acadêmico, PubMed, SciELO e CAPES. Os resultados demonstram que a ausência de saneamento adequado está associada a altas taxas de morbidade, particularmente em doenças diarreicas e parasitárias, e que o investimento em infraestrutura sanitária gera benefícios econômicos significativos, como a redução de custos com saúde e o aumento da produtividade. Ademais, os serviços de saneamento são cruciais para melhorar o desempenho educacional e promover a equidade de gênero, especialmente em comunidades vulner', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11413', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6878b64e0868163a2f74de67', 'Sustentabilidade Social No Contexto Do Ensino Médio: Potencialidades Práticas Em Educação Ambiental', 'Santos, Ivan Zichtl; Castelhano, Marcos Vitor Costa; Carvalho, Alba Valéria Gomes de; Barbosa, Paulo Estefan Costa; Alves, Larysse Cristina Ferreira; Maranhão, Gabriela Gomes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'RESUMO: No contexto do Ensino Médio – EM, avista-se as introduções e ampliações educativas-ambientais assumem um papel revelante nas estruturações educacionais globais e setoriais, como também na formação de jovens conscientes e críticos perante das necessidades e variáveis que tangem a sustentabilidade socioambiental, instaurando-se como um processo idiossincrático e fundamental de aprendizagem e aperfeiçoamento individual-coletivo. Partindo dos elementos citados, o presente estudo discorre sobre a pertinência da discussão da sustentabilidade social nas contextualizações do EM na atualidade, tendo como plano norteador os saberes e as potencialidades práticas ancoradas nas perspectivas da educação ambiental, levando em consideração as suas diferentes temáticas e aportes teórico-metodológicos. No âmbito de pesquisa, o método de revisão narrativa foi empregado como norte organizativo e captativo nos direcionamentos estruturantes, valendo-se artigos científicos, capítulos de livro e livro', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11494', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('68caab8ef61e5b80b5e8ec88', 'Driving Local Action for the UN 2030 Agenda: Challenges in Rural Selective Waste Collection', 'Aguiar Caires, Taiara; Santos, Geisa Coelho dos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'The demands of industrial sectors have been growing since the Industrial Revolution due to population growth associated with the prevailing consumerist model, requiring increased product generation, which, in turn, results in a high percentage of solid waste. In Brazil, solid waste management (SWM) is precarious and fails to meet the Sustainable Development Goals (SDGs) outlined in the United Nations (UN) Agenda 2030. According to the Agenda, achieving the SDGs requires the implementation of SWM across all social spheres. Thus, the objective of this study was to implement selective waste collection in the community of Baixão dos Honoratos, municipality of São Gabriel, Bahia, contributing locally to achieving the SDGs. Ten families participated in the study, separating recyclable materials into categories at their homes, with weighing conducted every 15 days over a three-month period. On-site visits were conducted to enhance the dissemination of Environmental Education knowledge within ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11237', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('690c5c78e36ca628435fc99d', 'I Simpósio Paraibano de Ciência Animal (Pequeno Animais 43-78p.)', 'Sousa, Francisco de Assys Romero da Mota; Maracaja, Patricio Borges; Mascarenhas, Nágela Maria Henrique; Gurjão, Thyago Araujo', 'Editora Verde', 'Agriculture', 'Agriculture', 'I Simpósio Paraibano de Ciência Animal Pequenos Animais', 'https://www.gvaa.com.br/revista/index.php/CVADS/article/view/11712', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67dab468677d8be0233b3775', 'Estratégias de responsabilidade social em empresas', 'Bezerra Neto, Francisco das Chagas; Marinheiro Neto, Austidio Alves; Soares, Andreza Tainá de Sá; do Nascimento , Márcia Luciana Gurgel Assunção; Paiva, Jerdmiler Gomes de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A importância da diversidade organizacional tem aumentado nos debates acadêmicos e corporativos, impulsionada por elementos como a globalização e a Responsabilidade Social Corporativa (RSC). Esta pesquisa explora a pluralidade no contexto empresarial e sua conexão com a agenda ESG e os Objetivos de Desenvolvimento Sustentável (ODS), enfatizando categorias como gênero, etnia, idade, orientação sexual e adequação física. O estudo fundamenta-se na literatura e em informações empíricas para destacar as vantagens da diversidade, tais como o incremento da inovação, produtividade e envolvimento. Contudo, barreiras como o preconceito, a disparidade salarial e a exclusão continuam presentes, demandando políticas eficazes para fomentar a inclusão. A avaliação mostra que companhias engajadas na diversidade não só consolidam sua imagem, como também estabelecem ambientes de trabalho mais harmoniosos e sustentáveis. A conclusão é que a diversidade é um elemento estratégico crucial para o crescimento', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11249', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('67dab468677d8be0233b3776', 'Análise das vantagens e desvantagens do método qualitativo no estudo do comércio justo, autogestão e sustentabilidade da feira de orgânicos da rede Xique Xique no IFRN - Campus Mossoró-RN', 'Assunção do Nascimento, Márcia Luciana Gurgel; Bezerra Neto, Francisco das Chagas; Marinheiro Neto, Austidio Alves; Soares, Andreza Tainá de Sá; Paiva, Jerdmiler Gomes de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pesquisa em foco aborda a interseção entre comércio justo, autogestão e sustentabilidade na agricultura familiar, com ênfase na Feira de Orgânicos da Rede Xique Xique no IFRN - Campus Mossoró. Esta iniciativa exemplifica novos paradigmas de sustentabilidade e autogestão na agricultura familiar, cruciais em um contexto global onde práticas agrícolas tradicionais enfrentam desafios significativos. A escolha metodológica pela abordagem qualitativa destaca-se pela sua capacidade de explorar aspectos subjetivos e complexos desses temas, proporcionando uma compreensão profunda e contextualizada. No entanto, é crucial também examinar as vantagens e desvantagens dessa metodologia específica, considerando os impactos gerados na análise do comércio justo, autogestão e sustentabilidade na Feira de Orgânicos da Rede Xique Xique.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/11250', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c697', 'IDENTIFICAÇÃO E PONTENCIALIZAÇÃO DOS RECURSOS HÍDRICOS NO ASSENTAMENTO PAULO FREIRE – MOSSORÓ-RN - BRASIL', 'Íris Leite, Alexandro; Fernandes de Brito, Raimundo; Sousa Moura, Olga Nogueira de; da Silva Dias, Nildo; Barbosa de Lira, Raniere', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Com o objetivo de identificar e potencializar os recursos hídricos do projeto de Assentamento Paulo Freire em Mossoró-RN foi realizado uma pesquisa-ação na comunidade no período de janeiro de 2006 à abril de 2007. Na fase exploratória da pesquisa identificou-se, com os diálogos entre as famílias, que a escassez dos recursos hídricos era o principal problema que dificultava o desenvolvimento das atividades agropecuárias. Foram realizadas oficinas para discutir e deliberar estratégias e responsabilidades na resolução do problema caracterizado e, com a sensibilização e as atitudes dos assentados, conseguiu-se potencializar os recursos hídricos do assentamento, efetivando-se a recuperação da barragem de dois açudes do assentamento. Com isso, se proporcionou o armazenamento de água para atender às necessidades da comunidade no período de estiagem, evidenciando-se nos depoimentos dos agricultores e agricultoras as melhorias trazidas, além da satisfação e o despertar de ações coletivas para p', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/373', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c698', 'DIAGNÓSTICO DA APICULTURA NO MUNICÍPIO DE POMBAL-PB', 'Maracajá, Patrício Borges; Santos, Diego Passos dos; Alves, Leonardo de Sousa; Sousa, José da Silva; silva, Antonio Fernandes da; Sousa, João Rodrigues de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A apicultura é uma das atividades mais antigas e importantes do mundo. Esta atividade atravessou o tempo, ganhou o mundo e se tornou uma importante fonte de renda para várias famílias. No presente trabalho procurou-se analisar o estado da apicultura no município de pombal PB. Para tanto, foram visitados no período de Março a Maio de 2006 quatro comunidades onde se pratica a apicultura. Aos cinco apicultores identificados foi aplicado um questionário e realizados registros fotográficos. Esses apicultores praticam a apicultura fixa, possuem poucas colméias, não seguem rigorosamente as práticas apícolas, o único produto é o mel e com baixa produtividade, vendem diretamente aos atravessadores, alguns apiários localizam-se próximos a culturas agrícolas onde se utiliza agrotóxicos. Entretanto, a apicultura no município de Pombal PB, ainda não é considerada uma atividade organizada, nem tão pouco de produção expressiva.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/460', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c699', 'IMPACTOS AMBIENTAIS NAS MARGENS DO RIO PIANCÓ CAUSADOS PELA AGROPECUÁRIA', 'Araujo, Maria Lucia Martins Nóbrega de; Sousa, José da Silva; Almeida, Pedro Gomes de; Reinaldo, Lediam Rodrigues Lopes Ramos; Wanderley, José Alberto calado', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'abc', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/461', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c69a', 'IMPACTOS AMBIENTAIS CAUSADOS PELA AGRICULTURA E A PECUÁRIA NAS PROPRIEDADES SÃO JOÃO E AREIA BRANCA, POMBAL – PB', 'Maracajá, Patricio Borges; Alves, Leonardo de Sousa; Sousa, José da Silva; Almeida, Pedro Gomes de; Reinaldo, Lediam Rodrigues Lopes Ramos; Wanderley, Jose Alberto Calado; Santos, Diego Passo dos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho trata de um diagn&oacute;stico socioecon&ocirc;mico e ambiental, realizado nas propriedades S&atilde;o Jo&atilde;o e Areia Branca, ambas no munic&iacute;pio de Pombal, estado da Para&iacute;ba, cujo objetivo foi avaliar os fatores de risco da deteriora&ccedil;&atilde;o ambiental ocasionada pela explora&ccedil;&atilde;o agropecu&aacute;ria e extrativismo vegetal. Para a coleta de dados, foram aplicados question&aacute;rios junto &agrave; popula&ccedil;&atilde;o das &aacute;reas em estudo. A metodologia utilizada nesta pesquisa n&atilde;o avaliou apenas os aspectos f&iacute;sicos ou biol&oacute;gicos vulner&aacute;veis ao processo de deteriora&ccedil;&atilde;o ambiental mas tamb&eacute;m, considerou o aspecto socioecon&ocirc;mico das popula&ccedil;&otilde;es locais. Um ambiente, que sempre desempenhou sua fun&ccedil;&atilde;o depuradora com efici&ecirc;ncia, encontra-se hoje excessivamente sobrecarregado pelas atividades antr&oacute;picas, sofrendo o risco de exaust&a', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/462', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c69f', 'Gestão Socioambiental: um Estudo sobre as Práticas de uma Empresa do Setor Moveleiro', 'Mendes, Luciano; Tisott, Sirlei Tonello; Rizzo, Marçal Rogério', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo neste artigo foi compreender quais s&atilde;o as pr&aacute;ticas em responsabilidade socioambiental desenvolvida pela Todeschini S.A., que possui sede no estado do Rio Grande do Sul. Essa empresa passou por uma s&eacute;rie de reestrutura&ccedil;&otilde;es que a colocou no patamar de uma empresa socialmente respons&aacute;vel, n&atilde;o apenas pelos programas desenvolvidos, mas pelas mudan&ccedil;as na planta da empresa e na estrutura organizacional adotada. Para tanto, no inicio foi necess&aacute;rio uma discuss&atilde;o sobre o conceito de responsabilidade socioambiental, trazendo as vertentes e tamb&eacute;m a complexidade que tais a&ccedil;&otilde;es v&ecirc;m tomando. Ap&oacute;s esse percurso te&oacute;rico a inten&ccedil;&atilde;o foi desenvolver algumas discuss&otilde;es sobre o m&eacute;todo de pesquisa utilizada, assim como sobre os sujeitos pesquisados e como foi realizada a pesquisa propriamente dita e a analise dos dados. Diante disso, constata-se que a empresa', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/539', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a1', 'ESTUDO SOCIO-ECONOMICO, CULTURAL E DE PERCEPÇÃO AMBIENTAL DAS CONDIÇÕES DE SANEAMENTO EM ARARICÁ - RS', 'Naime, Roberto; Cabral, Adauri Fantinel', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A omiss&atilde;o do poder p&uacute;blico municipal na atribui&ccedil;&atilde;o legal de fiscalizar a ocupa&ccedil;&atilde;o do solo como elemento definidor do desenvolvimento e expans&atilde;o urbana, no exerc&iacute;cio do planejamento p&uacute;blico e do seu dever-poder de pol&iacute;cia, atrav&eacute;s da compet&ecirc;ncia constitucional em legislar em assuntos de interesse local e de proteger o meio ambiente, resulta em danos s&oacute;cio-ambientais muitas vezes irrevers&iacute;veis. Este trabalho investiga a percep&ccedil;&atilde;o ambiental sobre as condi&ccedil;&otilde;es de saneamento destas ocupa&ccedil;&otilde;es desordenadas, discutindo quest&otilde;es vinculadas ao tratamento de esgoto sanit&aacute;rio domiciliar (fossas s&eacute;pticas e sumidouros) geralmente adotadas pelas comunidades e incentivadas pelo pr&oacute;prio poder p&uacute;bico. A conseq&uuml;&ecirc;ncia mais imediata percebida &eacute; a contamina&ccedil;&atilde;o do len&ccedil;ol fre&aacute;tico que &eacute;', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/620', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a2', 'Indice de sustentabilidade em zona ribeirinha na bacia hidrográfica do riozinho do rôla, Rio Branco, Acre', 'Coelho, France Maria Gontijo; Santos, Izaias Fernandes; Dias, Herly Carlos Teixeira; Silva, Elias', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As popula&ccedil;&otilde;es ribeirinhas da Amaz&ocirc;nia Ocidental brasileira se distinguem pela sua maneira diferenciada de lidar com natureza, mas tamb&eacute;m pelo ambiente em que vivem. Conhecer e diferenciar os atores sociais que residem nestas &aacute;reas possibilita formular planos de manejo ambientais mais eficientes. O objetivo deste trabalho foi analisar as propriedades dos ribeirinhos do Riozinho do R&ocirc;la, Rio Branco, Acre, utilizando &Iacute;ndices de Sustentabilidade (IS). Os indicadores utilizados foram retirados de informa&ccedil;&otilde;es coletadas pela aplica&ccedil;&atilde;o de 39 question&aacute;rios, em janeiro de 2008. Os resultados mostram que existe um gradiente negativo de IS econ&ocirc;mico, social e ambiental ao longo deste rio. O IS Ambiental encontrado n&atilde;o refletiu a realidade dessa popula&ccedil;&atilde;o, sendo, portanto, necess&aacute;rio reavaliar os indicadores utilizados ou aprofundar no conhecimento do uso dos recursos naturais por par', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/624', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a3', 'AS PRÁTICAS DE GESTÃO AMBIENTAL E O PLANEJAMENTO ESTRATÉGICO: UM ESTUDO DE CASO EM EMPRESAS DO MUNICÍPIO DE DOURADOS-MS', 'Pereira de Almeida Bogarim, Everton; Soares de Souza, Luciana', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente estudo visa avaliar a import&acirc;ncia da vertente ambiental no planejamento estrat&eacute;gico empresarial, fazendo uso da certifica&ccedil;&atilde;o e das pr&aacute;ticas de gest&atilde;o ambiental como instrumento de trabalho e verificar o patamar em que se insere o planejamento estrat&eacute;gico ambiental das empresas do munic&iacute;pio de Dourados-MS. Para tal, foi desenvolvido um estudo multicaso com base na aplica&ccedil;&atilde;o de question&aacute;rios semi estruturados &agrave; ger&ecirc;ncia de cinco empresas de pequeno, m&eacute;dio e grande porte do munic&iacute;pio. Os dados obtidos foram analisados e constatou-se que a maioria das empresas entrevistadas realiza planejamento estrat&eacute;gico, entretanto essas informa&ccedil;&otilde;es ficam restritas somente no interior das organiza&ccedil;&otilde;es. &Eacute; importante destacar ainda que grande parte das empresas desconhece &nbsp;a certifica&ccedil;&atilde;o ambiental propriamente dita, conhecendo por&ea', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/713', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6a8', 'Resíduos de agrotóxicos e metais pesados em água para consumo humano em Centro Novo-MA', 'Pereira, Dagoberto Calazans Araujo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os agrot&oacute;xicos tamb&eacute;m conhecidos como pesticidas s&atilde;o usados na agricultura a fim de proteger as plantas contra doen&ccedil;as, plantas daninhas e insetos nocivos &agrave; agricultura. Por&eacute;m, deve-se lembrar que esses produtos qu&iacute;micos podem deixar res&iacute;duos nos alimentos, gerando problemas na popula&ccedil;&atilde;o que os consome e no meio ambiente. Este trabalho teve como objetivo analisar amostras de &aacute;gua para consumo humano, coletadas em Centro Novo-MA, em Janeiro de 2006, com a finalidade de verificar a possibilidade de contamina&ccedil;&atilde;o por pesticidas e metais pesados e poss&iacute;veis impactos na sa&uacute;de desta popula&ccedil;&atilde;o. Foram coletadas e analisadas amostras de &aacute;gua para consumo humano, identificadas de acordo com o local de coleta e submetidas &agrave; an&aacute;lise para identifica&ccedil;&atilde;o e quantifica&ccedil;&atilde;o dos princ&iacute;pios ativos dos inseticidas ativos dos inseticidas', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1109', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ac', 'Modelo de composteiras orgânicas na Gestão Ambiental domiciliar.', 'Nicolas, Fernandes Martins', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Nesse trabalho fora realizado um estudo de caso, onde investigamos quais dos modelos de composteiras vigentes det&eacute;m o maior potencial. Diante do estudo percebemos que a composteira de andares (tr&ecirc;s andares) &eacute; um excelente modelo para ser utilizada nas resid&ecirc;ncias. Sendo seu custo baixo e sua atividade de compostagem atinge &oacute;timos resultados para uso dom&eacute;stico.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1176', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ae', 'Do design ao ecodesign: pequena história, conceitos e princípios', 'Naime, Roberto; Hupffer, Haide Maria; Ashton, Elisa', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este trabalho faz uma discuss&atilde;o da inser&ccedil;&atilde;o do design e do ecodesign em par&acirc;metros de desenvolvimento sustent&aacute;vel. Discute o tema a partir de uma resenha hist&oacute;rica sobre a origem do termo design, seus conceitos e princ&iacute;pios e sua evolu&ccedil;&atilde;o at&eacute; a concep&ccedil;&atilde;o moderna de ecodesign, buscando nas refer&ecirc;ncias bibliogr&aacute;ficas mais relevantes sobre o tema, alicer&ccedil;ar uma discuss&atilde;o que atinja os significados mais importantes sobre a inser&ccedil;&atilde;o cotidiana da pr&aacute;tica de design na sociedade contempor&acirc;nea. Discute a necessidade dos materiais retornarem aos ciclos produtivos em uma cadeia de circuito fechado, pois a grande maioria das mat&eacute;rias primas s&atilde;o constitu&iacute;das de recursos naturais n&atilde;o renov&aacute;veis. Com este prop&oacute;sito, os conceitos de design e ecodesign tem muito a auxiliar a altera&ccedil;&atilde;o dos paradigmas em busca de p', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1227', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b1', 'A atuação ambiental das empresas do Vale oo Rio dos Sinos - RS/ Brasil - nos sistemas de gestão ambiental e suas certificações.', 'Krause, Alessandra Tatiana', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente trabalho, de natureza aplicada, objetiva investigar a situa&ccedil;&atilde;o das empresas na &aacute;rea da gest&atilde;o ambiental do Vale do Rio dos Sinos/ RS - Brasil. Para isso, foram escolhidas aleatoriamente empresas de pequeno e de grande porte da regi&atilde;o, sendo enviado por e-mail &agrave;s mesmas, um question&aacute;rio previamente elaborado com quest&otilde;es, que buscavam retratar qualitativamente e quantitativamente a situa&ccedil;&atilde;o da gest&atilde;o ambiental destas. Ap&oacute;s 60 dias, somente duas empresas devolveram os question&aacute;rios respondidos, uma de pequeno e outra de grande porte. Nenhuma delas possu&iacute;a certifica&ccedil;&atilde;o ambiental, a ISO 14.0001. Ambas descreveram as principais dificuldades e facilidades a serem encontradas na implementa&ccedil;&atilde;o de um Sistema de Gest&atilde;o Ambiental. Assim sendo, percebeu-se que esta regi&atilde;o do Vale do Rio dos Sinos est&aacute; num alto patamar de desenvolvimento indus', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1289', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b2', 'INUNDAÇÕES EM CENTROS URBANOS: IMPACTOS AMBIENTAIS GERADOS PELO CRESCIMENTO POPULACIONAL', 'Scherer, Rosângela Bianca; dos Santos, Rosele Clairete', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O crescimento desordenado das cidades tem gerado diversos impactos ambientais, mudan&ccedil;a da paisagem urbana e problemas de infraestrutura. Dentre estes problemas, o mais comumente observado s&atilde;o as enchentes e, em alguns munic&iacute;pios, as enxurradas, cujas conseq&uuml;&ecirc;ncias s&atilde;o, geralmente, muito danosas &agrave; popula&ccedil;&atilde;o, atingindo principalmente &agrave;quelas situadas nas periferias, onde as condi&ccedil;&otilde;es sanit&aacute;rias s&atilde;o prec&aacute;rias. Conforme h&aacute; o crescimento populacional, ocorre o aumento da pavimenta&ccedil;&atilde;o e das constru&ccedil;&otilde;es, o que provoca a impermeabiliza&ccedil;&atilde;o do solo, impedindo o escoamento da &aacute;gua pluvial. No caso da drenagem urbana &eacute; preciso repensar o que vem sendo feito at&eacute; o momento, que n&atilde;o tem surtido efeito, visando o uso de novas alternativas, ecologicamente corretas, com o intuito de promover a sustentabilidade urbana, com o m&i', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1291', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6b8', 'A evolução da agricultura orgânica', 'Santos, José Ozildo dos; Salgado, Alberto Bandeira; Santos, Rosélia Maria de Sousa; Ferreira, Reginaldo Tácio França Vieira; Borges, Maria da Glória Borba; Santos Segundo, Ovidio Angelino dos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Nos &uacute;ltimos anos, a produ&ccedil;&atilde;o org&acirc;nica tem registrado um grande crescimento em v&aacute;rios pa&iacute;ses, principalmente, na Europa, movimentando bilh&otilde;es de d&oacute;lares anualmente em seu mercado, no qual figuram como maiores consumidores a Alemanha, a Holanda, a Su&iacute;&ccedil;a, a Fran&ccedil;a, a Inglaterra, os Estados Unidos e o Jap&atilde;o. &Agrave; semelhan&ccedil;a da agricultura convencional, a org&acirc;nica tamb&eacute;m exige investimentos p&uacute;blicos, principalmente, no que diz respeito &agrave; sua divulga&ccedil;&atilde;o. Atualmente, os pa&iacute;ses que entendem que esse tipo de atividade &eacute; uma estrat&eacute;gia sustent&aacute;vel, passaram a investir economicamente no setor, bem como estatuindo normas para regularem as condi&ccedil;&otilde;es de plantio e disciplinarem a certifica&ccedil;&atilde;o dos produtos. No Brasil, o sistema de cultivo org&acirc;nico, em bases tecnol&oacute;gicas, teve in&iacute;cio, em pequena', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1864', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ba', 'Ingerências socioeconômicas das centrais de tratamento de resíduos: estudo para a região metroplitana de Londrina', 'Zapparoli, Irene Domenes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O sistema de produ&ccedil;&atilde;o intensivo em recursos naturais, energia e grande gerador res&iacute;duo faz a sociedade repensar seu modo atual de produ&ccedil;&atilde;o e consumo. O objetivo &eacute; identificar as quest&otilde;es socioecon&ocirc;micas que envolvem as Centrais de Tratamento de Res&iacute;duos (CTR) na Regi&atilde;o Metropolitana de Londrina (RML), Paran&aacute; - Brasil. A metodologia est&aacute; composta por revis&atilde;o bibliogr&aacute;fica e coleta de dados emp&iacute;ricos. Para os dados emp&iacute;ricos usou-se das t&eacute;cnicas, estudo observacional, entrevistas com autoridades municipais e com 21 empres&aacute;rios da RML e os question&aacute;rios foram respondidos por 119 pessoas, efetuando-se a triangula&ccedil;&atilde;o de dados. Os resultados acenam para a dif&iacute;cil considera&ccedil;&atilde;o das quest&otilde;es socioecon&ocirc;micos na escolha de quem e qual munic&iacute;pio da RML deve sediar a CTR. Londrina concentra as atividades econ&ocirc', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1885', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6bd', 'Ética e responsabilidade social em latícinio do município de Tenente Ananias - RN: Estudo de caso', 'Almeida, Juciê de Sousa; Ferreira, Alcides Almeida; Almeida Neto, Isidro Patrício de; Sousa, Debora Ferraz Moura Alves de UFCG; Feitosa, João Cavalcante; Sousa, Glauber Antonio de; Melo, Wellington Fe', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pesquisa explorou a realidade do Latic&iacute;nio A, empresa de pequeno porte localizada na cidade de Tenente Ananias, no estado do Rio Grande do Norte. Para a realiza&ccedil;&atilde;o do estudo foi tomada como metodologia o estudo de caso, considerada a ferramenta metodol&oacute;gica mais apropriada para a este tipo de trabalho de campo. Para a coleta dos dados foram aplicadas entrevistas n&atilde;o estruturadas junto &agrave; ger&ecirc;ncia do Latic&iacute;nio A, no per&iacute;odo de 01 a 03 de julho de 2012 e a an&aacute;lise desses correlacionou os resultados com a fundamenta&ccedil;&atilde;o te&oacute;rica referente. O objetivo geral foi descrever os princ&iacute;pios &eacute;ticos e as pr&aacute;ticas socialmente respons&aacute;veis da empresa; de modo espec&iacute;fico conhecer os princ&iacute;pios &eacute;ticos que norteiam a organiza&ccedil;&atilde;o, caracterizar os processos de gest&atilde;o e responsabilidade social na empresa e tra&ccedil;ar o perfil das a&ccedil;&otilde', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/1972', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c1', 'Uma síntese crítica sobre aspectos dos Estudos dos Solos', 'Nicolas, Fernandes Martins', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O solo &eacute; um corpo material que recobre a superf&iacute;cie terrestre e as plantas preenche e compartilham o solo com um vasto n&uacute;mero de organismos vivos. Temos desde micr&oacute;bios a pequenos mam&iacute;feros que utilizam o solo, sendo produto de intemperismo sobre um material de origem, cuja transforma&ccedil;&atilde;o se desenvolve ao longo de um tempo, o solo &eacute; crucial para a sobreviv&ecirc;ncia, sendo importante para sobreviv&ecirc;ncia, pois forcene suporte, &aacute;gua e uma variedade de elementos essenciais para o crescimento dos vegetais. O intemperismo &eacute; de fundamental import&acirc;ncia sendo fornecedor dos elementos qu&iacute;micos aos quais as plantas requerem e o tamanho das cargas el&eacute;tricas das part&iacute;culas do solo produzidas por intemperismo afetando a disponibilidade de &iacute;ons, &aacute;gua e oxig&ecirc;nio.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2065', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6c4', 'Programa Compra Direta e a criação de mercados para a agricultura familiar: o caso da EMATER-RN', 'Medeiros, Aline Carla de; Fernandes Júnior, José Vivaldo Machado; Batista, Kennya Cristiane Pereira; Menezes, Edivaldo Rabelo de; Sales Júnior, Francisco Vieira; Borges, Maria da Gloria Borba; Freitas', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Garantir a oferta de alimentos atrav&eacute;s de pol&iacute;ticas p&uacute;blicas que incentivam a produ&ccedil;&atilde;o e comercializa&ccedil;&atilde;o da produ&ccedil;&atilde;o agropecu&aacute;ria, n&atilde;o pode ser encarado como custo, mas como investimento. O Programa de Aquisi&ccedil;&atilde;o de Alimentos (PAA), enquanto pol&iacute;tica p&uacute;blica coloca-se como de fundamental import&acirc;ncia para o desenvolvimento da agricultura familiar. A pesquisa tem como objetivo analisar a contribui&ccedil;&atilde;o do PAA, na modalidade Compra Direta Local da Agricultura Familiar (CDLAF) para o desenvolvimento da agricultura familiar em um munic&iacute;pio da Regi&atilde;o Nordeste do Brasil. Considerando a forma de abordagem do problema, o estudo foi delineado qualitativo e quantitativo; os meios utilizados caracterizam como levantamento e documental; quanto &agrave; finalidade, explorat&oacute;rio, explicativo, estudo de caso e avalia&ccedil;&atilde;o de resultados. Foi poss&iac', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2148', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ca', 'ESTUDO PARA ELABORAÇÃO DE MAPA DE RISCOS AMBIENTAIS PARA O MUNICIPIO DE PRINCESA ISABEL - PB', 'Diniz Ferreira, Lineker Jordan', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A pesquisa foi desenvolvida como atividade da disciplina Gerenciamento de Riscos Ambientais e teve como &nbsp;objetivo &nbsp;identificar &nbsp;os &nbsp;poss&iacute;veis&nbsp; agentes causadores de riscos ambientais em um determinado trecho de uma das principais ruas do munic&iacute;pio de Princesa Isabel-PB. Foram realizadas visitas ao local para identificar e classificar os riscos existentes, ap&oacute;s&nbsp; esta etapa&nbsp;&nbsp; &nbsp;de&nbsp;&nbsp; &nbsp;caracteriza&ccedil;&atilde;o&nbsp;&nbsp; &nbsp;e&nbsp;&nbsp; levantamento, foram desenvolvidas algumas propostas de a&ccedil;&otilde;es com o objetivo de gerar medidas corretivas para os problemas identificados.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2238', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6cd', 'Proposta de recuperação da mata ciliar do açude do bairro Santo Amaro em Pombal - PB', 'Chaves, Alan Del Carlos Gomes; Maracajá, Patrício Borges; Silva, Luderlândio de Andrade; Crispim, Diêgo Lima; Leite, Rodrigo Pereira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Diante de todos os fatores intervenientes com a qualidade dos ambientes naturais, a vegetação ciliar mostra-se como um ambiente dotado de fragilidade, neste caso, a busca por formas de prevenção e até recuperação das áreas que sofreram algum tipo de degradação torna-se de extrema relevância. O presente trabalho descreve as causas que levou à degradação da mata ciliar da área supracitada e suas consequências para o meio. Objetivou-se com isso propor um Plano de Recuperação de Área Degradada, visando à recuperação do manancial na cidade de Pombal - PB, que encontra-se sem nenhuma área de mata ciliar original. Para consecução deste trabalho foram realizados levantamento bibliográfico, pesquisas de campo, que constou de entrevistas a moradores da área de entorno, registros fotográficos, bem como levantamento da fauna e flora da área e do seu entorno, onde observou-se um processo de degradação elevado, em virtude do uso e ocupação desordenado do solo, disposição inadequada de lixo e ativida', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2300', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ce', 'Diagnóstico ambiental do rio Piancó próximo ao perímetro urbano da cidade de Pombal - PB', 'Chaves, Alan Del Carlos Gomes; Maracajá, Patrício Borges; Cajá, Danielle Ferreira; Barbosa, Roberta Chaiene Almeida; Crispim, Diêgo Lima; Leite, Rodrigo Pereira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O processo de ocupa&ccedil;&atilde;o do Brasil caracterizou-se pela falta de planejamento e consequente destrui&ccedil;&atilde;o dos recursos naturais. Este trabalho teve como objetivo diagnosticar os principais impactos ambientais sobre o Rio Pianc&oacute;, na &aacute;rea pr&oacute;xima ao per&iacute;metro urbano da cidade de Pombal, PB, identificando os tipos e fontes de polui&ccedil;&atilde;o, descrevendo os problemas ambientais existentes. Utilizou-se a Metodologia Espont&acirc;nea (Ad Hoc) para avaliar os impactos ambientais de forma simples, objetiva e de maneira dissertativa. Os resultados mostraram que o rio est&aacute; recebendo uma elevada carga org&acirc;nica, devido &agrave; emiss&atilde;o in-natura de efluentes dom&eacute;sticos e sanit&aacute;rios atrav&eacute;s das galerias de drenagem pluviais, contaminando as &aacute;guas superficiais e tamb&eacute;m as reservas h&iacute;dricas subterr&acirc;neas. Os res&iacute;duos s&oacute;lidos e as atividades agropecu&aacute;rias s', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2301', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d0', 'Impactos ambientais no açude do bairro Nova Vida em Pombal - PB', 'Medeiros, Aline Carla de; Chaves, Alan Del Carlos Gomes; Maracajá, Patricio Borges; Ferreira, Aline Costa; Crispim, Diêgo Lima; Leite, Rodrigo Pereira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este trabalho teve como objetivo analisar e diagnosticar os impactos ambientais decorrentes das atividades antrópicas no açude do bairro Nova Vida, no município de Pombal – PB. A verificação e a descrição dos principais impactos ambientais encontrados na área de estudo foram através do “check-list” (lista de checagem) e da Metodologia Espontânea (Ad Hoc). Além disso, para complementar o trabalho realizaram-se estudos do tipo descritivo e bibliográfico. Durante a realização do trabalho de campo, observou-se que não há rede coletora de esgoto sanitário no bairro, sendo os efluentes lançados em direção ao açude. Além disso, verificou-se que açude vem sendo entulhado com a disposição inadequada de resíduos de material de construção e outros tipos de resíduos sólidos. Além de que, constatou-se que a floresta ciliar do curso d’água em estudo foi totalmente devastada devido ao crescimento urbano desordenado. Portanto, a questão da floresta ciliar quanto à coleta de resíduos sólidos, esgoto sa', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2454', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d2', 'Reuso dos resíduos da borracha sintética SBR/EVA, no asfalto ecológico para mitigação dos impactos ambientais', 'Rios, Fábio Remy de Assunção; Barbosa Sobrinho, Ariosvaldo Alves; Morais, Crislene Rodrigues Silva; Silva, Dalva Damiana Estevam da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A gest&atilde;o eficiente dos res&iacute;duos industriais &eacute; de extrema import&acirc;ncia no contexto econ&ocirc;mico, ambiental e social. O grande desafio no &acirc;mbito cient&iacute;fico, &eacute; como destinar de forma racional e como reutilizar os passivos ambientais dos processos industriais. Os pol&iacute;meros sint&eacute;tico possuem grande aplicabilidade, desde fabrica&ccedil;&atilde;o de cal&ccedil;ados a componente aeroespacial, isto tem provocado a gera&ccedil;&atilde;o de indicadores acentuados de res&iacute;duos de dif&iacute;cil degrada&ccedil;&atilde;o, como os termofixos, os elast&ocirc;meros Estireno Butadieno Rubber - SBR e elast&ocirc;meros termopl&aacute;sticos como o Etileno Acetato de Vinila &ndash; EVA. Este trabalho tem como objetivo, aproveitar os res&iacute;duos polim&eacute;ricos da ind&uacute;stria (SBR/EVA), na incorpora&ccedil;&atilde;o ao ligante asf&aacute;ltico CAP50/70, para aplica&ccedil;&atilde;o em pavimentos rodovi&aacute;rios. A metodologi', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2504', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d5', 'UM ESTUDO SOBRE A CONTABILIDADE AMBIENTAL, SUSTENTABILIDADE E O CONSUMO COLABORATIVO.', 'Carneiro, Elian Alves', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo deste estudo foi analisar de que forma a contabilidade ambiental est&aacute; aparelhada para registrar procedimentos de sustentabilidade e de consumo colaborativo. Para tanto foi utilizado o m&eacute;todo dedutivo, sendo examinados livros, artigos, teses, disserta&ccedil;&otilde;es, textos dispon&iacute;veis na internet e legisla&ccedil;&atilde;o vigente. Os resultado demonstraram que a contabilidade ambiental est&aacute; aparelhada para informar &agrave; sociedade os procedimentos que as empresas adotam para manter a sustentabilidade doas riquezas naturais do planeta, bem como registrar as opera&ccedil;&otilde;es de consumo cooperativo.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2564', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6d8', 'Técnicas de geoprocessamento aplicadas aos problemas ambientais que afetam o rio Iaco dentro do limite do município de Sena Madureira-AC', 'Ferreira de Morais, Joselanio Joselanio; Krugerr Pereira, Tais Karina', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O geoprocessamento &eacute; uma importante ferramenta que pode ser aplicado nos estudos dos aspectos f&iacute;sicos e ambientais da Terra, e neste caso espec&iacute;fico em bacias hidrogr&aacute;ficas. Avan&ccedil;os na &aacute;rea da inform&aacute;tica somam para obten&ccedil;&atilde;o de resultados cada vez mais imediatos, como &eacute; o caso dos algoritmos de classifica&ccedil;&atilde;o aqui empregada para obten&ccedil;&atilde;o dos produtos. &nbsp;Com isso ser&aacute; poss&iacute;vel analisar a realidade posta e caracterizar, associando com influ&ecirc;ncias exercidas pela popula&ccedil;&atilde;o sobre o meio natural e alertar sobre a import&acirc;ncia em proteger a biodiversidade para as diferentes classes (assentamentos, unidades de conserva&ccedil;&atilde;o, &aacute;reas particular e terras ind&iacute;genas), que cercam o curso do rio, utilizando as t&eacute;cnicas de an&aacute;lise espacial para gerar subs&iacute;dios qualitativos e quantitativos sobre a realidade produzida pe', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/2669', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6dd', 'A PRODUÇÃO ORGÂNICA GARANTINDO A PROMOÇÃO DA SAÚDE DOS TRABALHADORES DO CAMPO', 'Santos, Adriana Maria dos; Pinto, Érika do Nascimento Fernandes; Marçal, Nelly Alexandre', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Os trabalhadores se expõem diariamente a diversos agentes nocivos à saúde, variando de acordo com a atividade que exercem. No meio rural, a produção de commodites é uma atividade primária que contribui para desastrosos efeitos no organismo humano e até no meio ambiente. Entretanto, cada vez mais é possível eliminar ou minimizar tais riscos. O presente estudo visa apresentar ações concretas simples que o trabalhador rural pode adotar para reduzir a exposição ao risco de sustâncias químicas, fertilizantes e defensivos agrícolas. Mostrando que, adotando uma cultura de produção orgânica é possível melhorar qualidade de vida no trabalho e aumentar a produtividade. A vida no campo pode dá bons resultados em favor da saúde e do meio ambiente se for planejado ações (treinamento, banco de sementes, produção de defensivos e fertilizantes naturais, entre outros) que almejem um futuro saudável para todos.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/3005', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6df', 'AVALIAÇÃO DAS PRÁTICAS DE EDUCAÇÃO AMBIENTAL INSERIDAS EM DUAS ESCOLAS DE ENSINO FUNDAMENTAL II NA CIDADE DE JUAZEIRO DO NORTE-CE', 'Nascimento, Andréa Amaro; Souza, Amay Fernandes Silva; Santana, Willma José de; Gomes, Carlos Mário Ribeiro', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo deste estudo foi avaliar o conhecimento dos alunos de duas escolas p&uacute;blicas de ensino fundamental da cidade de Juazeiro do Norte-CE a respeito das pr&aacute;ticas ambientais. A metodologia utilizada foi um question&aacute;rio semiestruturado com perguntas norteadoras. Os resultados obtidos mostraram que todos os alunos sabem o conceito de meio ambiente, 93% disseram respeit&aacute;-lo, 14% descartam seus res&iacute;duos de forma inadequada. Conhecer e orientar a pr&aacute;tica da educa&ccedil;&atilde;o ambiental nas escolas, &eacute; de suma import&acirc;ncia, uma vez que facilitar&aacute; a integra&ccedil;&atilde;o de novas t&eacute;cnicas de acordo com o conhecimento dos alunos, para que seja poss&iacute;vel a mudan&ccedil;a de pequenos h&aacute;bitos que possam proporcionar uma melhor qualidade de vida.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/3060', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e0', 'UTILIZAÇÃO DE LODO DE ESGOTO NA AGRICULTURA', 'Santos, Mirella dos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A população humana, enquanto parte do ecossistema terrestre, possui comportamentos que agem em sentido contrário à manutenção do equilíbrio do meio ambiente. Os principais fatores que alteram este equilíbrio estão relacionados ao consumo de recursos e energia e à produção de resíduos. O lodo é produzido nas Estações de Tratamento de Esgoto em quantidades significativas e sua destinação final é um sério problema ambiental. Quanto ao gerenciamento deste resíduo, uma das alternativas é a utilização para do mesmo na agricultura. As alterações benéficas nas características físicas, químicas e biológicas do solo, o aumento da produtividade agrícola e os consequentes benefícios socioeconômicos tornam a reciclagem agrícola uma das práticas mais adequada dentre as formas de disposição final do lodo de esgoto. A presente revisão tem como intuito mostrar as vantagens na utilização do lodo de esgoto na agricultura, ou seja, como uma alternativa de fonte nutricional para as plantas e condicionador ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/3167', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e2', 'Agroecologia: preservação ambiental e sustentabilidade', 'Silva, Aldeni Barbosa da; Brito, Janaina Moreira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O intenso processo modernizador da agricultura brasileira acarretou impactos ambientais e transformações sociais em amplas magnitudes. A intensificação no uso de insumos químicos e mecânicos na agricultura acelerou a degradação de solos, a contaminação do meio ambiente e a agressão aos recursos naturais, com reflexo direto na qualidade de vida das populações rurais e urbanas. Nos últimos anos, em oposição ao modelo de agricultura convencional, diversos estilos de agricultura têm sido adotados em diferentes localidades, e são caracterizados pela utilização de tecnologias que respeitem a natureza, mantendo um equilíbrio dinâmico entre os seres vivos e o meio ambiente, imitando ao máximo os sistemas naturais. A partir dos princípios da Agroecologia, que não é um tipo de agricultura alternativa, e se constitui numa ciência que estabelece as bases para a construção de estilos de agriculturas sustentáveis e de estratégias de desenvolvimento rural sustentável, existe um potencial técnico-cien', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/3394', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e4', 'A GESTÃO AMBIENTAL NO DNIT: POSSIBILIDADES DE MELHORIAS MEDIANTE ANÁLISE DO ACÓRDÃO Nº 544/2015 – TCU - PLENÁRIO', 'Caldas, Sidcley Dalmo Teixeira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do estudo aqui apresentado foi analisar como ocorre a Gestão Ambiental no Departamento Nacional de Infraestrutura de Transportes - DNIT em contraste com o Acórdão nº 544/2015 do Tribunal de Contas da União - TCU -  Plenário. De forma mais específica, descrever a estrutura da Gestão Ambiental no DNIT, examinar sua atuação e analisar o Acórdão nº 544/2015 - TCU que trata das práticas de Gestão Ambiental no DNIT. De caráter descritivo e documental, a pesquisa baseou-se em análises de documentos publicados pelo TCU e pelo DNIT. No seu transcorrer, ocorre a caracterização do DNIT, acerca de seus objetivos e de sua configuração administrativa, a descrição da Gestão Ambiental no DNIT e a apresentação dos achados realizados pela auditoria do TCU. Compreende-se a importância deste trabalho considerando que o mesmo concorre para contribuir em melhorias na condução do processo da Gestão Ambiental da autarquia em questão.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/3767', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e6', 'IDENTIFICAÇÃO DE MUNICÍPIOS HOMOGÊNEOS QUANTO A AMEAÇAS AMBIENTAIS NO ESTADO DO RIO DE JANEIRO POR TWO STEP CLUSTER', 'Costa, Giovani Glaucio', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo deste artigo é prosseguir nas análises estatísticas das ameaças ambientais no Estado do Rio de Janeiro promovida pela Defesa Civil. Este estudo se propõe a utilizar a técnica de análise multivariada two step cluster para obtenção de municípios do estado do Rio de Janeiro homogêneos quanto às ameaças ambientais. Com base nos dados do “Mapa de Ameaças Naturais, será montada a base de dados ou o espaço de análise do estudo. Os 92 municípios do Estado do Rio de Janeiro foram agrupados em clusters que seriam semelhantes internamente quanto a prevalências de ameaças ambientais. Os resultados da análise sugeriram três grupos homogêneos de municípios por ameaças ambientais. O cluster 1 agrupa 23,91% dos municípios do Rio de Janeiro, o cluster 2 retém 26,09% das cidades do estado e o cluster 3 aglomera a metade dos municípios (50%). Portanto, há evidências, pelo estudo realizado, que os municípios do Rio de Janeiro têm prevalências diferenciadas de ameaças ambientais. Com o perfil de', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4207', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e7', 'ESTIMAÇÃO DE UM MODELO DISCRIMINANTE PARA DIAGNÓSTICO DO ESTADO DE SAÚDE DE ÁRVORES', 'Costa, Giovani Glaucio', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A avaliação da condição de árvores urbanas é de suma importância para o manejo da arborização de ruas e a gestão da floresta urbana como um todo. Este artigo visa contribuir para o estudo de metodologias que permitam avaliar em que condições se encontram as florestas urbanas, buscando a elaboração de projetos administrativos mais eficientes e fundamentar as ações preventivas de poderes públicos de desenvolvimento de espaços urbanos que proporcionem qualidade de vida às populações de grandes centros urbanos. Um levantamento reuniu de 2013 a 2014, por amostragem não probabilística, 190 árvores de espaços urbanos no estado do Rio de Janeiro. Os pesquisadores teriam que indicar 1 para a presença do item de enfermidade e 0 para a ausência do item de enfermidade. Com a utilização das técnicas multivariadas two step cluster e análise discriminante, formalizou-se o modelo classificatório, que se denominou MODIG-SAR (“Modelo Diagnóstico da Saúde da Árvore”). O MODIG-SAR será uma das contribuiçõ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4208', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e8', 'IMPACTOS SOCIOAMBIENTAIS GERADOS PELAS AGROINDÚSTRIAS FAMILIARES RURAIS NO SEMIÁRIDO NORDESTINO BRASILEIRO', 'Coelho, Luiz Fernando de Oliveira; Valério, Rayan Araújo; Ferreira, Daniela de Matos; Lima, Yasmim Sousa e; Brito, Célia Soares de; Oliveira, Andréa Maria Brandão Mendes de; Andrade, Sanduel Oliveira ', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Para se adaptar as novas tendências do mercado, o pequeno produtor rural sentiu-se obrigado a modificar seu perfil de produção, comercializando o excedente e automatizando a cadeia produtiva e buscando novas alternativas, diversificando a produção e consequentemente, agregando valor ao produto e incrementando a renda familiar. O presente artigo teve por finalidade abordar a problemática dos resíduos gerados pelo setor agroindustrial e foi elaborado mediante um levantamento literário de artigos já existentes. Para este levantamento optou-se pela busca de material bibliográfico nacional e internacional, oriundo de periódicos, livros, anais de eventos, monografias, dissertações, teses e documentos oficiais, durante o período de maio a dezembro de 2015. O setor agroindustrial brasileiro, em 2013, foi responsável pela oferta de 70% dos produtos que compõe a cesta básica, ocupa 80% da mão-de-obra rural, responde por 40% do valor bruto da produção agropecuária nacional e obtém em média três v', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4227', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6e9', 'A IMPORTÂNCIA DA CONCESSÃO DE CRÉDITO PARA O FINANCIAMENTO DE POLÍTICAS SÓCIO-AMBIENTAIS NO CONTEXTO EMPRESARIAL', 'Nascimento, Helton Ferreira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Este artigo tem como objetivo ressaltar a importância de créditos financeiros concedidos através de agências de fomento, bancos públicos e federais para investimentos sócio-empresariais e ambientais, ressaltando o trabalho exercido pela ABDE e suas perspectivas estratégicas. A problemática de pesquisa leva em consideração os seguintes questionamentos: Qual é a probabilidade de um temido evento de ordem ambiental acontecer? O que pode ser feito para lidar com isso? Quem pode ajudar? Quanto à metodologia, esta pesquisa foi estruturada pelo método descritivo-exploratório, caracterizada como pesquisa bibliográfica, elaborada com base em material já publicado, tendo como propósito proporcionar maior familiaridade com o problema, com vistas a torna-lo mais explícito. É possível concluir que as necessidades de mudanças na cadeia de produção renovável é responsabilidade social e empresarial, conduzindo a uma reflexão sobre o reconhecimento da importância do fomento de linhas de créditos para i', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4236', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ec', 'SUSTENTABILIDADE NA AGRICULTURA FAMILIAR: UMA ABORDAGEM SOBRE A FEIRA DA AGRICULTURA FAMILIAR ORGÂNICA NO MUNICÍPIO DE PATOS-PB', 'Ribeiro, Maria das Dores Pereira; Brito, Felipe César da Silva', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Trata-se de um estudo exploratório-descritivo de abordagem quantitativa, que teve por objetivo geral avaliar como os agricultores do município de Patos, Estado da Paraíba, vêm promovendo o processo de transição da agricultura familiar para a agricultura sustentável. No contexto atual, a agricultura familiar vem se mostrando como uma das melhores formas de ocupação do espaço rural, podendo favorecer o cumprimento de exigências sociais, como a geração de emprego e renda, e ambientais, como a conservação da biodiversidade. Entretanto, quando se aborda o termo agricultura sustentável, se está falando de estilos de agricultura de bases ecológicas que atendam a requisitos de solidariedade entre as gerações atuais e destas para com as futuras gerações. A agricultura sustentável tem uma base ecológica, inspirada na agroecologia, sob uma perspectiva social, econômica e cultural. Os dados colhidos através da presente pesquisa revelam que quase todos os agricultores possuem conhecimento sobre o q', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4319', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ed', 'LEVANTAMENTO FLORÍSTICO DE ESPÉCIES ARBÓREAS NA PRAÇA CORONEL JOSÉ VIEIRA EM PARAISÓPOLIS/MG', 'Pasin, Liliana Auxiliadora Avelar Pereira; Pereira Vieira, Jaqueline Gequiele; Gonçalves, Tamires de Cássia', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A arborização urbana melhora a qualidade do ar, o nível de umidade e a temperatura. Assim, esse trabalho teve como objetivo realizar um levantamento das espécies arbóreas da Praça Coronel José Vieira do município de Paraisópolis/MG utilizando o índice de diversidade de Margalef visando verificar a diversidade de espécies e analisar a presença de plantas nativas, exóticas e tóxicas. Com o resultado do índice nota-se que a biodiversidade do local é baixa, sendo assim sugere-se a substituição de plantas exóticas por nativas para atrair a avifauna local.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4323', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afead6a63682f044c6ee', 'DIAGNÓSTICO DA COLETA DE RESIDUOS SÓLIDOS DOMICILIAR NO MUNICÍPIO DE SOURE NA ILHA DO MARAJÓ', 'Castillo, Valentina de Los Angeles; Gonçalves, Edkeyse Dias; Araújo, Eduirbe Castro de; Teixeira, Luiza Girard; Correa, Roberto dos Santos', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O artigo apresenta um diagnostico da coleta de resíduos sólidos domésticos do município de Soure, no Estado do Pará, Brasil. A construção foi realizada baseando-se em informações adquiridas em dados secundários e primários, confrontando com as leis vigentes no Brasil. Foi utilizada como instrumento de avaliação uma matriz por meio do método Delphi. A matriz final possui 3 aspetos de sustentabilidade: política, institucional-gerencial, econômico-financeiro e social, contemplando 17 indicadores. No trabalho foi identificado que o serviço de coleta de lixo necessita de melhorias na gestão, a fim de que se alcance maior eficiência desse serviço. No aspecto político a nota, segundo método Delphi foi 6 de um total máximo de 20 equivalente a um atendimento de 30% das metas, no aspecto institucional-gerencial a nota foi de 30 de um total de 50, equivalendo a 60% das metas a serem alcançadas e no aspecto social 12 de 15, equivalendo a 80% da meta a ser alcançada.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4332', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6f0', 'A IMPORTÂNCIA DO REFLORESTAMENTO NOS PROCESSOS DE RECUPERAÇÃO DAS ÁREAS DEGRADADAS DO SERTÃO PARAIBANO', 'Sousa, Jânio Jacinto de; Sobrinho, Antonio Izidro', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'No sertão paraibano, a exploração predatória dos recursos naturais, a falta de práticas adequadas das atividades agrícolas, aliada as condições climáticas do semiárido com longos períodos de estiagem, tem degradado a cobertura vegetal e acarretado o assoreamento dos rios e reservatórios, pela erosão dos solos. Tais práticas inadequadas também estão assoreando os recursos hídricos e colocando em risco a fauna silvestre e a permanência da população na zona rural. Uma vez que com a superfície exposta o solo é erodido e os nutrientes indispensáveis para a exploração agrícola autossustentável, são exauridos rapidamente comprometendo todo o ecossistema. Uma das soluções apresentadas visando à recuperação das áreas degradadas do sertão paraibano é o reflorestamento, que vem se constituindo numa alternativa importante para a recuperação ambiental. Observada as características gerais da área degradada a ser recuperada, utiliza-se as espécies que melhor se atenda aos pré-requisitos determinados.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4361', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c6fb', 'Tendência de precipitações pluviométricas e avaliação da influência dos ENOS no distrito de Abunã, Rondônia.', 'Silveira, Rafaela Nazareth Pinheiro de Oliveira; Fernandes, Lindemberg Lima; Silva, Maria de Nazaré Alves da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O estudo foi aplicado no distrito de Abunã, por meio da análise de 31 anos de dados da estação pluviométrica Abunã (Código ANA - 965001), localizado em Porto Velho - Rondônia, com o objetivo de avaliar a tendência da série histórica de precipitação pluviométrica e as influências dos eventos climáticos El Niño e La Niña.  No desenvolvimento do estudo foram aplicados os testes não paramétricos de Mann-Kendall, Spearmann e o Estimador Sen, bem como a determinação da estatística descritiva, ambos por meio dos softwares BioEstat 5.3 e XLSTS 2016, e os resultados apresentados em tabelas e gráficos.  De acordo com resultados obtidos, a área apresentou sazonalidade identificada por duas estações distintas uma seca, entre os meses de maio a setembro, e a outra chuvosa, entre os meses de outubro a abril, caracterizando o comportamento hidrológico típico da região amazônica e com influência dos eventos La Niña (88/90) e de El Niño (90/93). Resultando numa tendência de crescimento da precipitação,', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4702', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c709', 'Modelo de otimização na substituição de ônibus no transporte público', 'Emiliano, William Machado; Augusto Lanzer, Edgar; Telhada, José; Machado, Antônio Vitor', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Ao longo do tempo, o desgaste pelo uso de um equipamento tende a elevar cada vez mais os seus custos de operação e manutenção. A partir de um ponto torna-se economicamente interessante substituir o equipamento por um novo, mesmo na ausência de qualquer melhoramento tecnológico significativo. Esta observação genérica se aplica também a equipamentos tais como ônibus de transporte urbano. Pela sua natureza de serviço público, o transporte urbano de passageiros é geralmente regulado pelo poder municipal. Na cidade de Joinville (Santa Catarina) a Lei 3806/1998 determina a substituição de qualquer ônibus urbano que complete dez anos de uso. Neste contexto, este trabalho visa avaliar a racionalidade desta legislação sob a ótica da otimização econômica no uso de recursos privados. Adota-se a hipótese de que o agente privado busca substituir seus ônibus naquela idade (anos de uso) que conduza a minimização do fluxo de custos para a prestação dos serviços de transporte urbano, uma vez que o preç', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/4888', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c714', 'METABÓLICOS SECUNDÁRIOS ASSOCIADOS A ESTRESSE HÍDRICO E SUAS FUNÇÕES NOS TECIDOS VEGETAIS', 'Sousa, Rodrigo Ferreira de; Sousa, Joama Alves de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'As plantas tem papel essencial nas nossas vidas, sendo úteis de varias maneiras desde fonte de alimento e combustível ate o oxigênio que respiramos. Graças a engenharia genética e outros tipos de tecnologia moderna, as plantas hoje podem ser transformadas, por exemplo, resistentes ás doenças, tolerante a solos ricos em sais, resistentes á seca. O estudo da sua fisiologia possibilita o entendimento de reações a atividades metabólicas que proporcionam o manejo e o cultivo de populações de plantas selvagens ou nativas de forma mais adequada. O presente trabalho tem como objetivo realizar um levantamento bibliográfico atual sobre a associação entre metabólitos secundários e estresse hídrico e suas interferências nos tecidos vegetais.  O metabolismo das plantas varia de acordo com sua fisiologia, e pode ser dividido em metabolismo primário e secundário. Os metabólitos primários são frequentemente citados como compostos diretamente ligados à sobrevivência da planta Os metabólitos secundários', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5008', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c715', 'Levantamento pluviométrico da região geoadministrativa de Pombal, Paraíba', 'Sousa, Edigleison Pereira de; Lima, Rafael Rocha de; Sousa, Joama Alves de; Lima, João Paulo Rodrigues de; Sousa, Rodrigo Ferreira de; Sousa, João Filipe Alves de; Araujo, Talita Soares de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A região semiárida brasileira tem por característica o déficit hídrico e a irregularidade na distribuição e quantidade das chuvas e o alto índice de evaporação. Contudo é uma região vulnerável a chuvas intensas e enchentes. O objetivo do estudo foi apresentar e avaliar os índices pluviométricos da região geoadministrativa de Pombal, estado da Paraíba entre os anos de 1999 e 2015 afim de dar subsídio na identificação de padrões pluviométricos, auxiliando na elaboração de planos de combate as secas. A coleta de dados foi utilizando o banco eletrônico de informações da Agência  Executiva de Gestão das Águas do Estado da Paraíba (AESA), Empresa de Assistência Técnica e Extensão Rural da Paraíba (EMATER-PB), Instituto Brasileiro de Geografia e Estatística (IBGE) e Agência Nacional das Águas (ANA). As médias anuais e mensais foram comparadas pelo teste de Tukey. Pombal destacou-se com a maior média pluviométrica da região, enquanto que São Domingos apresentou os menores índices. A região geo', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5009', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c716', 'BIODIGESTORES: ESTADO DA ARTE, SUAS PERSPECTIVAS E DESAFIOS', 'Andrade, Sanduel Oliveira de; Oliveira, Andréa Maria Brandão Mendes de; Coelho, Luiz Fernando de Oliveira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Objetiva-se com esta pesquisa avaliar o uso de biodigestores em seu estado da arte, abrangendo os substratos utilizados e os produtos gerados. O levantamento literário ocorreu no período de julho a agosto de 2017 e consistiu em uma revisão sistemática, utilizando como fonte de dados a literatura científica sobre determinado tema, priorizado as pesquisas mais recentes. São várias as tecnologias que tem sido desenvolvida no intuito de gerar energia, dentre elas os biodigestores, que são capazes de produzir biogás a partir da decomposição de material orgânico em ambientes anaeróbicos. Os principais tipos de biodigestores utilizados são o chinês e o indiano, sendo este último mais viável em termos de custos e eficiência. Foi possível observar que o processo de digestão anaeróbia de compostos orgânicos por meio de biorreatores é uma opção viável, tanto para tratar os resíduos orgânicos oriundos de diversas atividades, bem como para a geração de subprodutos, tais como eletricidade, biogás e ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5037', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c71a', 'Influência do efeito de escala sobre a produção de sedimentos em bacias hidrográficas não instrumentadas no semiárido', 'Maracajá, Patricio Borges; Afonso, João Paulo Sobral Dias; Medeiros, Paulo da Costa; Siqueira, Mariana da Silva de; Ribeiro, George do Nascimento; Alcântara, Hugo Morais de; Medeiros, Aline Carla de; ', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O estudo dos efeitos das alterações de uso e ocupação do solo nos processos hidrológicos tem sido realizado por meio de manipulações experimentais em termos de sua cobertura em bacias hidrográficas. O presente trabalho teve como objetivo analisar o efeito de escala sobre a erosão e a produção de sedimentos por meio de modelagem ambiental para bacias não instrumentadas no semiárido com o intuito de subsidiar estratégias de conservação do solo. As características de uso e ocupação dos solos, tipos de solos, topografia e morfologia foram obtidas por meio da classificação supervisionada de imagens do satélite LANDSAT 5. O modelo SWAT (Soil and Water Assessment Tool) foi utilizado para a simulação dos cenários alternativos de uso e ocupação do solo, possibilitando a análise da influência de práticas conservacionistas em pequenas bacias hidrográficas e o efeito de escala na produção de sedimentos nas bacias analisadas, apresentando-se como uma importante ferramenta para o planejamento ambien', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5273', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c71c', 'DETERMINAÇÃO DA PUREZA DE DOIS LOTES DE SEMENTES DE CAPIM ‘Brachiaria brizantha’ cv. MARANDU', 'da Silva, Rosilene Agra; de Abrantes, Janiny Vieira; Andrade, Samara Raquel Souza Ribeiro; Martins, Debora Janyne Barbosa; dos Santos, Samanda Costa; Carreira, Daniel de Almeida; Moreira, Amanda Rezen', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A determinação da pureza de lotes de sementes de forrageiras é de extrema importância tanto para a determinação do valor cultural de cultivares. O Objetivo deste trabalho foi avaliar a pureza de dois lotes de sementes de capim braquiarão (Brachiaria brizantha cv Marandu). Após a obtenção dos lotes de sementes no comércio local da cidade de Pombal-PB e na cidade de Mossoró-RN, a fim de obter dois lotes distintos.  Procedeu-se a limpeza dos dois lotes de sementes, estes foram divididos quanto as sementes puras e material inerte, para a determinação da pureza, onde esta foi determinada em porcentagem. Os dois lotes de sementes apresentaram baixa porcentagem de pureza física, contudo, aquele lote de Mossoró-RN destacou-se em ralação ao lote de sementes obtido em Pombal-PB.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5291', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c721', 'Avaliação do desenvolvimento do capim Panicum maximum cv. Mombaça submetidos à duas idades de corte e diferentes densidades de plantas', 'Lopes da Silva, Zaqueu; Gadelha, Jéssika Assis Ferreira; Andrade, Samara Raquel Souza Ribeiro; Martins, Debora Janyne Barbosa; Silva, Rosilene Agra da; Lucena, Francisco Tarcísio; Moreira, Amanda Reze', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar o desenvolvimento do capim Panicum maximum, em diferentes épocas de corte e densidades de plantas. O experimento foi constituído por meio do esquema fatorial 3 x 2, com quatro repetições. O fator A com 3 densidades de plantas (404, 547, 582) e o segundo fator de duas épocas de retiradas (20 e 35 dias após a emergência). A quantificação de desenvolvimento em função da época e número de plantas foi obtida por meio de anotação da medida da altura da planta com auxílio da régua, posteriormente, foi feito a soma para obtenção do número total de plantas em cada tratamento. As variáveis serão estudadas pela análise de variância e médias por meio do teste de tukey, a 5% de significância. Os resultados mostraram que tanto para o desenvolvimento, massa seca e massa total, na época 20 os que tiveram melhor desempenho foi a de 582, já para época 35 a que melhor obteve desempenho foi a de 404. No geral a época de retirada que melhor teve desempenho foi a de 35 dia', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5363', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c725', 'Contabilização e evidenciação dos créditos de carbono em uma  empresa do segmento de alimentos', 'Vieira, Allan Sarmento; Mendes, Allan Martinne Gonçalves; Silveira, Raquel Cristina Soares; Júnior, Francisco José da Silva; de Sá Neto, José Abrantes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo principal deste trabalho é evidenciar os ativos e passivos ambientais, e mensurar os créditos de carbono da empresa Nestlé, utilizando um modelo quantitativo parcimonioso para estimar as emissões evitadas de dióxido de carbono (CO2). Inicialmente foi observado nos relatórios de sustentabilidade da empresa estudada, investimentos em produtos, bem como a utilização de embalagens que reduzem a emissão de poluentes e medidas de minimização dos gases que contribuem na formação do efeito estufa. Com relação à contabilização dos créditos de carbonos aptos a negociação na Bolsa de Valores, pode-se afirmar que nos anos exercícios de 2011 e 2012 a empresa possuía milhões de créditos de carbono disponíveis que poderiam ser negociados no mercado de carbono que geraria uma receita adicional. Diante do exposto, pode-se afirmar que a empresa Nestlé evidencia e contabiliza voluntariamente algumas ações ambientais, mas não mensuram nos seus demonstrativos contábeis e deixa de reconhecer seus', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5440', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c727', 'Governança corporativa e desempenho econômico-financeiro: uma análise de sua relação nas empresas listadas nos níveis diferenciados de governança da B3', 'Ventura Júnior, Raul; Ferreira, Jonnas Gonçalves; Alencar, Lucas Vieira Pereira de; Ventura, Ana Flávia Albuquerque', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Governança corporativa consiste num sistema utilizado na proteção e auxílio dos que compõem a alta administração das companhias. Ela busca tomada de decisões sempre interligadas, o que promove melhor desempenho, retorno dos investimentos, credibilidade e maximização de valor da entidade. O presente estudo investigou se há relação entre as boas práticas de governança e o desempenho econômico-financeiro nas companhias listadas nos níveis diferenciados de governança da B3. No período de 2010 a 2013 utilizou-se de 133 companhias que foram divididas em dois grupos: sendo um de governança e outro de não governança, o critério de diferenciação foi saber se em de determinado ano a entidade estava listada em um dos níveis diferenciados, se sim, foi incorporada ao grupo governança, se não, foi considerada como não praticante de governança e incorporada ao grupo não governança. Por se tratar de duas amostras independentes e apresentar uma distribuição normal, optou-se analisar por meio do teste t', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5472', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c729', 'A Relação entre os Níveis de Governança Corporativa e a Rentabilidade das Empresas Listadas na B3', 'Abrantes, Emerson Eder Rolim; Ventura Júnior, Raul; Guilherme, Hiponio Fortes; Ventura, Ana Flávia Albuquerque', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A governança corporativa é um conjunto de práticas utilizadas para minimizar os conflitos de agência visando à maximização do empreendimento e o retorno esperado para os investidores. Dessa forma, esta pesquisa tem como objetivo analisar a relação entre os níveis de governança corporativa e a rentabilidade das empresas listadas na B3 no período de 2016. Para atingir tal objetivo, foram coletados os índices de rentabilidade ROA e ROE de cada empresa da amostra, como também os seus respectivos níveis de governança. Para verificar a existência de diferenças entres as médias dos índices de rentabilidade por nível de governança coorporativa foi utilizado a Análise de Variância (ANOVA) de um fator. Os resultados apontam indícios de que os níveis diferenciados de governança corporativa podem influenciar positivamente o índice ROE e negativamente o índice ROA. Por fim, pode-se concluir que mecanismos de governança mais rígidos podem contribuir positivamente para resguardar os interesses de ret', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5475', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c72a', 'Avaliação das condições higiênico-sanitárias de frigoríficos do sertão paraibano', 'Medeiros Neto, Moisés Sesion de; Dantas, Romildo Pinheiro; da Silva, Everton Vieira; Sousa, Thamyres Cesar de Albuquerque; Paiva, Yaroslávia Ferreira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O mercado de carne está cada vez mais competitivo e complexo no que se refere ao requisito vida útil do produto final, além do rigoroso controle higiênico-sanitário e da demanda por diversificação e agregação de valor aos produtos. O objetivo desse trabalho foi avaliar as condições higiênico-sanitárias da comercialização de carnes em frigoríficos no sertão paraibano; em que foi seguido como recomendações a resolução RDC N°275/2002 da ANVISA. Foi aplicado um questionário estruturado com questões fechadas (check list) aos manipuladores, como também aos donos dos estabelecimentos comerciais, para serem observadas as condições pontuais de higiene nos devidos locais de comercialização. Com isso foi identificado que nos referidos frigoríficos apresentaram diversas inadequações com relação aos aspectos higiênico- sanitários. Devido a isso, pode-se concluir que a grande maioria dos estabelecimentos frigoríficos não atendem a todos os itens avaliados, ressaltando-se com isso a importância do cu', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5477', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c72b', 'A influência do componente geológico ou natural na vulnerabilidade de encostas', 'Maracajá, Patrício Borges; Prado Junior, Leonardo Souza do; Almeida, Thales Hieron Soares de; Farias, Camilo Allyson Simões de; Vasconcelos, Isabelly Cícera Dias de; Paiva, Anna Catarina Costa de; Med', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente artigo tem como objetivo abordar através da literatura pertinente, os fatores que influenciam o componente geológico ou natural na vulnerabilidade das encostas. Isso devido aos processos de instabilizações de encostas e relatos dos fenômenos que ocorrentes associados aos desastres naturais, sobremodo nas áreas urbanas intensamente ocupadas por assentamentos, favelas, vilas e loteamentos. Esta investigação, trata-se de um estudo bibliográfico, onde levantou-se informações em periódicos sobre a temática, realizada no período compreendido entre setembro de 2006 e maio de 2007. Para isto, realizou-se consultas a livros, periódicos e artigos científicos selecionados. Onde foram visto que os movimentos de massas correspondem aos mecanismos de transporte de sedimentos, solos ou rochas que são induzidos pela força gravitacional e pela ação conjunta ou isolada de fatores como a presença de águas superficiais e subterrâneas ou ações antrópicas como desmatamentos, cortes e aterros, ent', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5502', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c72d', 'Percepção ambiental sobre o descarte de fármacos no bairro Célio Miranda, Paragominas-PA', 'Junior, Antonio Pereira; Pereira, Adriana da Silva', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O uso de fármacos para automedicação e a facilidade de aquisição destes, gera um incremento em unidades vencidas ou não utilizadas totalmente em locais inadequados e causam impactos ambientais. O objetivo dessa pesquisa foi verificar a percepção ambiental quanto ao descarte de fármacos vencidos ou não totalmente utilizados e os impactos ambientais que essa ação causa ao meio ambiente, e a prática ou não, da logística reversa, em cinco drogarias e uma farmácia de manipulação localizadas no bairro Célio Miranda, Paragominas-PA. O método empregado foi o indutivo, a amostragem foi probabilística simples (noventa indivíduos amostrados = 10%). Os dados coletados, durante sete dias do mês de setembro de 2017, com aplicação de noventa e seis formulários de caráter misto, para obtenção de dados acerca da percepção ambiental quanto a esse tipo de impacto. A análise dos dados obtidos indicaram que a percepção ambiental dos individuos amostrados, é baixa, devido ao descarte inadequado (72,2%) dos ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5534', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c731', 'Desempenho agronômico da alface sob quantidades e períodos de incorporação da lab-lab', 'Gomes, Marcos Vinicius; Souza, Clara Maria da Costa; Costa, Caciana Cavalcanti; Barbosa, José Wilson da Silva; Nunes, Edivan Silva', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O Lab Lab (Dolichos lablab L.) entre outras espécies constituem-se em importante recurso vegetal para ser utilizado como adubo verde na produção hortaliças, devido a sua composição nutricional e produção de biomassa satisfatória em quantidade, facilidade e tempo reduzido. Este trabalho foi realizado durante o período de janeiro a dezembro de 2016, na horta didática do Departamento de Agrárias e Exatas da Universidade Estadual da Paraíba - Campus IV, Catolé do Rocha – PB, com o objetivo de avaliar o lab lab como adubo verde no cultivo da alface. O delineamento experimental utilizado foi o de blocos completos casualizados com os tratamentos arranjados em esquema fatorial 4 x 4, com quatro repetições. Os tratamentos consistiram na combinação de quatro quantidades de lab lab (5,4; 8,8; 12,2 e 15,6 t ha-1 em base verde) com quatro períodos de incorporação (0, 15, 30 e 45 dias antes do tranplantio). A cultivar de alface plantada foi a Veneranda comercializada pela empresa Feltrin. As caracte', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5607', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c736', 'A ATUAÇÃO DO CONSELHO MUNICIPAL DE MEIO AMBIENTE NO MUNICÍPIO DE MARABÁ-PA', 'Junior, Antonio Pereira; Costa, Savannah; Tavares, Florene; Teixeira, Deisianne; Marquioro, Giovanna', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A criação de órgãos deliberativos é reconhecida como um processo de fundamental importância para a municipalização das questões ambientais, pelo qual é reconhecido o papel de cada órgão frente à organização de um sistema municipal de meio ambiente. O objetivo dessa pesquisa foi a realização de análise qualitativa acerca do funcionamento, estruturação, relação com a sociedade, avanços e impasses do Conselho Municipal do Meio Ambiente- Marabá - PA. O método empregado foi o dedutivo, com pesquisa qualitativa básica e exploratória. Foram realizadas quatro entrevistas informais (três com componentes do COMAM, e uma com um representante da comunidade, além de uma participação na reunião desse Conselho, para verificar in loco, a sistemática de discussão das temáticas propostas. Efetuou-se o levantamento de dados documentais com recorte temporal entre 2008 e 2017. Os dados obtidos indicaram que: (1) há dificuldade de conciliar os ideais entre os diferentes atores e  os interesses institucionai', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5625', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c73b', 'Biodiversidade e a Gestão ambiental', 'Pereira, Emmanuelle; Junior, Antonio Pereira; Jesus, Edmir Pereira', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A biodiversidade é uma prioridade na linha direta de trabalho da gestão ambiental. O objetivo dessa revisão bibliográfica é correlacionar a qualidade dessa gestão em função da conservação da diversidade biológica. O método aplicado foi o dedutivo, pois, partiu-se de duas premissas verdadeiras: (1) a qualidade da gestão ambiental em unidades de conservação; (2) a boa gestão ambiental em UC’s, é um dos fatores que contribui para a conservação da biodiversidade. Essa pesquisa apresenta abrangência qualitativa porque não houve quantificações em relação aos dados obtidos, e natureza empregada foi a observativa, pois não houve ações práticas para serem empregadas na solução de problemas gerados por essas ações. A obtenção de dados foi efetuada em duas bases de pesquisa – Capes periódicos e Scientific Library Online - SCIELO, em periódicos cujas publicações foram similares aos dois objetos dessa pesquisa. O recorte temporal para o levantamento de dados documentais situou-se em 2000 a 2018, em', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5675', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c73d', 'Avaliação microbiológica e sensorial de linguiça frescal bovina com adição de extratos de alecrim e chá verde', 'Chaves, Karina da Silva; Fonseca, Sthelio Braga; Meireles, Bruno Raniere Lins Albuquerque; Clemente, Juliana Nobrega; Barbosa, Thaísa Cidarta Melo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A elevada comercialização de produtos cárneos no Brasil está relacionada às questões culturais e econômicas da população. Nesse grupo de alimentos destacam-se os embutidos, principalmente a linguiça frescal devido ao sabor característico e preço acessível. Dessa forma, objetivou-se avaliar as características microbiológicas e sensórias da linguiça frescal bovina com a adição de extrato de alecrim (Rosmarinus officinalis) e chá verde (Carmellia sinensis). As linguiças foram elaboradas utilizando as formulações F1: sem antioxidante; F2: antioxidante BHT; F3: extrato de alecrim e F4: extrato de chá verde, nas quais foram realizadas análises físico-químicas, microbiológicas e sensoriais. Os resultados da caracterização físico-química da linguiça frescal bovina apresentaram-se dentro dos padrões estabelecidos pela Instrução Normativa Nº 4 do MAPA. As análises microbiológicas de salmonella sp., coliformes a 45ºC e  staphylococus coagulase positivo obtiveram valores de acordo com a Resolução ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5692', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c73f', 'Coliformes totais em corpos hídricos lóticos do Rio Prainha, Paragominas – PA', 'Gonçalves, Andreia; Silveira, Adriana; Junior, Antonio Pereira; Pereira, Lavinia; Cristo, Jaqueline', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O processo desordenado de urbanização, próximo aos cursos d’água, ocasiona diversos problemas para os corpos hídricos, por exemplo, o despejo de efluentes domésticos motivado pela falta de saneamento básico. O objetivo dessa pesquisa foi promover uma análise microbiológica da água do Rio Prainha, no município de Paragominas – PA, bairro Promissão 2, rua Equador, com o intuito de verificar os possíveis fatores contribuintes para ocorrência de microorganismos patogênicos. A amostragem ocorreu no dia vinte e seis de janeiro de 2018, período chuvoso, em dois pontos do rio pratinha, sendo duas de superfície e duas a vinte centímetros de profundidade. O método empregado foi o dedutivo, já a pesquisa apresenta natureza aplicada com abordagem qualiquantitativa e procedimento experimental. A análise dos dados obtidos indicou que há presença de coliformes totais, na água do Rio Prainha, em pelo menos 250 mL das quatro amostras. Isso resulta no desvio dos parâmetros da Portaria 2914:2011 do Minis', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5700', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c740', 'As Feiras Agroecológicas da Cidade de Campina Grande/Paraíba na perspectiva da Sustentabilidade e do Slow Food', 'Silva, Lenice', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Nos últimos anos é visível o crescimento das informações referentes ao uso de grandes quantidades de defensivos agrícolas na produção de alimentos, aumentando a preocupação da sociedade na busca de uma alimentação mais saudável, diante disso destacamos nesse trabalho as ideias do Slow Food, que tem como fundamentos alimentares a sustentabilidade, a qualidade e a valorização dos alimentos consumidos em oposição à disseminação em massa de alimentos industrializados e dos fast-food, com intuito de verificar a afinidade entre as feiras agroecológicas e essa nova filosofia alimentar o presente artigo teve como propósito realizar uma abordagem das feiras agroecológicas da cidade de Campina Grande na perspectiva Slow Food e da sustentabilidade, a partir da observação do gerenciamento de tais feiras, para tanto realizou-se um estudo de caso, de caráter exploratório-descritivo, com abordagem qualitativa, fazendo-se o uso de relatos de agricultores que trabalham com a agroecologia na cidade de C', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5704', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c742', 'A urbanização, a formação de ilhas de calor e o uso de vegetação para o conforto térmico', 'Junior, Antonio Pereira; Sousa, Andrielly; Jesus, Edmir; Santos, Carlos; Ribeiro, Dryelly', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O rápido crescimento urbano tem provocado surgimento de ilhas de calor e alterações no microclima, a vegetação tem características capazes de mitigar esses efeitos negativos. O objetivo desta pesquisa é analisar o comportamento de três variáveis ambientais a partir de dados coletados no Campus VI Universidade do Estado do Pará – UEPA, Paragominas – PA. O método utilizado foi o indutivo, aplicado, quantiqualitativo e experimental. A coleta de dados foi efetuada durante doze horas por trinta dias. O tratamento estatístico dos dados (média e desvio padrão) ocorreu com o uso do software Excel 2010, e a Correlação de Pearson (software BioEstat 5.3). A análise dos dados obtidos indicou tendência de: elevação da temperatura atmosférica (1ºC a 2ºC), umidade relativa do ar (6% a 12%) e velocidade do vento (0,15 m/s a 2,59 m/s). Inversão entre temperatura e umidade relativa atmosférica (r = - 0,94); temperatura e velocidade do vento (r = - 0,55); paridade entre umidade relativa do ar e velocidad', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5723', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c745', 'Tratamentos pré-germinativos em sementes de Schizolobium parahyba (Vell.) Blake', 'Mendonça, Janaína Soares de; Alexandre, Patrícia da Silva; Arruda, Jordana Dantas de; Silva, Edna de Oliveira; de Medeiros, Dayana Silva; de Medeiros, Marcos Barros', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O objetivo do trabalho foi avaliar o efeito de diferentes tratamentos pré-germinativos para superação de dormência em sementes de Schizolobium parayba (Vell.) Blake. A pesquisa foi realizada no Laboratório de Análise de Sementes do CCA/UFPB, no município de Areia-PB. Os tratamentos pré-germinativos foram: T1 = Testemunha (sementes intactas); T2 = Escarificação mecânica com lixa d’água nº 80; T3 = Escarificação mecânica com lixa d’água nº 80, seguida de embebição em água por 12 h; T4 = Escarificação mecânica com lixa d’água nº 80, seguida de embebição em água por 24 h; T5 = Imersão em água na temperatura de 90ºC por 5 minutos; T6 = Imersão em água na temperatura de 100ºC por 5 minutos; T7 = Imersão em água na temperatura de 80ºC por 5 minutos; T8 = Imersão em água na temperatura de 70ºC por 5 minutos; T9 = Imersão em ácido sulfúrico por 10 minutos; e T10 = Imersão em ácido sulfúrico por 20 minutos. De acordo com os resultados para se obter melhor desempenho germinativo recomenda-se a es', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5760', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c748', 'Degradação ambiental no entorno da bacia hidráulica do açude de Sumé-PB', 'Medeiros, Paulo da Costa; Ribeiro, George do Nascimento; Barros, Maikon Rodrigo Gomes de; Alcântara, Hugo Morais de; Medeiros, Aline Carla de; Rocha, Layane Carmem Arruda da', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Imagens de satélite tem sido uma ferramenta importante para estudos de degradação ambiental. Algumas atividades antrópicas e naturais têm contribuído para o avanço de tal modificação na natureza. Este trabalho teve como objetivo principal, identificar as principais atividades que estão causando a degradação e assim elaborar mapas temáticos que mostram a evolução espaço-temporal dessa degradação ambiental para as épocas consideradas secas na região do cariri paraibano, levando em consideração os anos de 1990, 2005, 2008 e 2010. As imagens usadas nesta pesquisa foram adquiridas a partir do catálogo de imagens do INPE; foram utilizadas imagens do satélite Landsat 5 e do Landsat 8 e utilizado o Spring 5.2.7 para fazer o processamento digital das imagens e o módulo Scarta para gerar os mapas. Pelos resultados obtidos observamos que, partindo do ano de 1990, a área de solo exposto teve um acréscimo de 21,17%, cerca de 42,92 km2, até o último ano em estudo (2010), observou-se também, que cerc', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5775', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c749', 'Análise do currículo nas escolas do campo a partir do método quase experimental', 'dos Santos Macedo de Lima, Niedja Raissa; de Sousa, Cleomara Gomes; de Oliveira, Ademir Guilherme; Hipólito, Geisiele Alves; Oliveira, Lucas Lopes', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O presente estudo teve por objetivo a realização de um estudo sobre a análise do currículo nas escolas do campo a partir do método quase experimental. A metodologia empregada constou da pesquisa do tipo qualitativa e quantitativa, do método quase experimental e da utilização dos instrumentos de pré-teste e pós-teste. Para tanto, os procedimentos constaram dos seguintes momentos: pesquisa bibliográfica, realização de aula expositiva sobre o conteúdo da disciplina ciências, aplicação de pré-teste, aula prática ou experimental e pós-teste. Os resultados obtidos evidenciaram a ocorrência de um maior nível de aprendizagem após a realização da aula prática ou experimental. Portanto, concluiu-se que a aprendizagem dos alunos de ciências no ensino fundamental das escolas públicas do campo é mais significativa quando eles manipulam materiais concretos no ambiente escolar.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5776', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798afeed6a63682f044c74e', 'O uso do eugenol como agente antimicrobiano para agroindústria', 'Santos, Camila Lais Alves dos antos; Alencar, Maria Carmem Batista de; Gadelha, Hugo Sarmento; Sousa Neto, Odilon Lucio de; Roberto, Stephanny Batista de Alencar; Sá, João Paulo Natalino de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'O controle de micro-organismos deteriorantes e ou patogênicos veiculados por alimentos é alcançado principalmente por métodos químicos, mas o uso de alguns compostos químicos de origem sintética, vem se tornando indesejáveis por apresentarem alguns fatores limitantes como elevada carcinogenicidade, toxicidade aguda, teratogenicidade, entre outros.O eugenol tem efeito sobre as bactérias gram positivas como em gram negativas, pela possível ação deste composto na desintegração da estrutura da membrana celular microbiana, principalmente a nível da fração lipídica, pela maior interação hidrofóbica do eugenol com os lipídios presente na constituição da membrana celular,  favorecendo a alteração à permeabilidade da membrana citoplasmática, provocando o extravasamento de constituintes citoplasmáticos.', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5791', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c74f', 'A utilização de óleos essenciais na indústria de alimentos', 'Santos, Camila Lais Alves dos; Alencar, Maria Carmem Batista de; Gadelha, Hugo Sarmento; Ribeiro, Samara Raquel Souza; Roberto, Stephanny Batista de Alencar; Sá, João Paulo Natalino de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Physico-chemical and microbiological conservation can be a viable alternative for different segments, such as products of animal origin, vegetable and as sanitizing agents on surfaces that come into contact with food. They evaluated the action of the essential oil extracted from tangerine bark (Citrus reticulata), bitter orange peel (Citrus bigarradia) and sweet orange peel (Citrus sinensis) for the conservation of fish (Megalobrama amblycephala) stored under freezing conditions. According to the results reported by the authors, all the essential oils presented bacteriostatic activity, being the essential oils of Z. officinale, E. caryophyllus and E. cardamomum those that presented greater inhibitory effect on P. aeruginosa, with MIC value of 0 , 25% (v / v). The essential oils of E. caryophyllus and E. cardamomum were used for the second stage, because they had a higher antibacterial effect in the initial tests. Thus we can verify the possibility of the use of essential oils as agents', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5792', NULL, 'English', 'published', false, false, 'open', 'pdf')
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c750', 'Cadeia produtiva do mel: Agroindústria familiar em Rolim de Moura, Rondônia-RO', 'Ribeiro, Sylviane Beck; Silva, Elisangela Aparecida da; Santos, Sheila Becker dos; Jacobsen, Raquel Felberg Helena; Mikos, Aline; Lopes, Fabio Silva do Carmo', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'A apicultura é uma atividade com grande potencial de geração de renda e diversos são os fatores que podem influenciar para que possa ser mais produtiva. O estado de Rondônia apresenta expansão gradativa na produção de mel, favorecido pela vegetação, clima e grande quantidade de agricultores familiares. Dessa forma, o beneficiamento dos produtos por meio de agroindústrias aparece como alternativa para o fortalecimento da renda dos pequenos produtores rurais do estado e, ainda, favorece a economia local. Assim, realizamos um estudo de caso na agroindústria de mel Recanto das Paineiras e analisamos questões relacionadas ao processo de produção, industrialização e comercialização. Os objetivos específicos foram: (i) caracterizar a área de estudo; (ii) identificar os principais gargalos no modelo da cadeia produtiva utilizada pelo produtor, e (iii) propor sugestões que pudessem otimizar a cadeia produtiva na propriedade. A fim de alcançar os objetivos propostos, realizamos revisão bibliográ', 'https://www.gvaa.com.br/revista/index.php/RBGA/article/view/5797', NULL, 'English', 'published', false, false, 'open', 'pdf')
