INSERT INTO public.books (id, title, author_names, publisher_name, faculty, subject, description, file_url, year_published, language, status, is_african, is_zimbabwean, access_model, format)
VALUES ('6798aff1d6a63682f044c754', 'ANÁLISE DA SUSTENTABILIDADE DO DESENVOLVIMENTO SOCIAL NO MUNICÍPIO DE POMBAL-PB', 'Oliveira, Francisco Fabrício Damião de; Sales, Luís Gustavo de Lima; Sousa, Gláucio de Meneses; Figueiredo, Caio Franklin Vieira de', 'Grupo Verde de Agroecologia e Abelhas', 'Agriculture', 'Agriculture', 'Há tempos as comunidades rurais dos municípios brasileiros sofrem com falta de atenção e de assistência por parte dos gestores públicos. Para enfrentamento “esquecimento” e como conseqüência da abertura da participação popular nas discussões sobre políticas públicas voltadas para o campo brasileiro, foram criados os Conselhos Municipais de Desenvolvimento Rural Sustentável (CMDRS), no qual acaba sendo uma forma das comunidades rurais se organizarem e reivindicar seus direitos. O presente trabalho teve por objetivo analisar os índices de deterioração social dos territórios rurais do município de Pombal – PB com o intuito de auxiliar no processo de construção do conhecimento rural local, subsidiando, assim, as discussões no âmbito do Conselho Municipal de Desenvolvimento Rural S